    public sealed class MediaCentreViewModel : INotifyPropertyChanged
    {
        public static MediaCentreViewModel Instance { get; private set; }

        private static readonly string LibraryFilePath = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
            "AtlasAI",
            "media_library.json");

        private static readonly string MediaAgentDraftsFilePath = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
            "AtlasAI",
            "media_agent_drafts.json");

        public static List<string> FindPersistedLibraryTitles(string query, string? typeId = null, int maxResults = 250)
        {
            query = (query ?? "").Trim();
            if (string.IsNullOrWhiteSpace(query)) return new List<string>();

            try
            {
                if (!File.Exists(LibraryFilePath)) return new List<string>();

                var json = File.ReadAllText(LibraryFilePath);
                using var doc = JsonDocument.Parse(json);
                if (!doc.RootElement.TryGetProperty("Items", out var itemsEl) || itemsEl.ValueKind != JsonValueKind.Array)
                    return new List<string>();

                var stopwords = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
                {
                    "a", "an", "and", "the", "me", "my", "all", "every", "please", "in", "on", "at", "to", "for", "of", "from"
                };
                var tokens = Regex.Split(query, "\\s+")
                    .Select(t => (t ?? "").Trim())
                    .Where(t => !string.IsNullOrWhiteSpace(t))
                    .Select(t => t.Trim('\"', '\'', ',', '.', '!', '?', ':', ';', '(', ')', '[', ']', '{', '}'))
                    .Where(t => t.Length >= 3 && !stopwords.Contains(t))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToArray();
                if (tokens.Length == 0) return new List<string>();

                var scored = new List<(string title, int score, int matched)>();
                foreach (var it in itemsEl.EnumerateArray())
                {
                    if (it.ValueKind != JsonValueKind.Object) continue;
                    var itemType = it.TryGetProperty("Type", out var typeEl2) ? (typeEl2.GetString() ?? "") : "";
                    if (!string.IsNullOrWhiteSpace(typeId) &&
                        !string.Equals(itemType, typeId, StringComparison.OrdinalIgnoreCase))
                        continue;

                    var title = it.TryGetProperty("Title", out var titleEl) ? (titleEl.GetString() ?? "") : "";
                    var artist = it.TryGetProperty("Artist", out var artistEl) ? (artistEl.GetString() ?? "") : "";
                    var album = it.TryGetProperty("Album", out var albumEl) ? (albumEl.GetString() ?? "") : "";
                    var path = it.TryGetProperty("FilePath", out var pathEl) ? (pathEl.GetString() ?? "") : "";
                    var displayTitle = (title ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(displayTitle) && !string.IsNullOrWhiteSpace(path))
                        displayTitle = (Path.GetFileNameWithoutExtension(path) ?? "").Trim();

                    var score = 0;
                    var matched = 0;
                    foreach (var t in tokens)
                    {
                        var m = false;
                        if (title.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 12; m = true; }
                        if (album.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 6; m = true; }
                        if (artist.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 6; m = true; }
                        if (path.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 3; m = true; }
                        if (m) matched++;
                    }
                    if (matched <= 0 || score <= 0) continue;
                    if (string.IsNullOrWhiteSpace(displayTitle)) continue;
                    scored.Add((displayTitle, score, matched));
                }

                var ordered = scored
                    .OrderByDescending(s => s.matched)
                    .ThenByDescending(s => s.score)
                    .ThenBy(s => s.title, StringComparer.OrdinalIgnoreCase)
                    .Select(s => s.title)
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(Math.Max(1, maxResults))
                    .ToList();

                if (ordered.Count == 0 && tokens.Contains("marvel", StringComparer.OrdinalIgnoreCase))
                {
                    return FindPersistedByFranchiseKeywords(itemsEl, typeId, maxResults);
                }

                return ordered;
            }
            catch
            {
                return new List<string>();
            }
        }

        private static List<string> FindPersistedByFranchiseKeywords(JsonElement itemsEl, string? typeId, int maxResults)
        {
            try
            {
                var keywords = GetMarvelKeywordPhrases();
                var scored = new List<(string title, int score)>();

                foreach (var it in itemsEl.EnumerateArray())
                {
                    if (it.ValueKind != JsonValueKind.Object) continue;
                    var itemType = it.TryGetProperty("Type", out var typeEl2) ? (typeEl2.GetString() ?? "") : "";
                    if (!string.IsNullOrWhiteSpace(typeId) &&
                        !string.Equals(itemType, typeId, StringComparison.OrdinalIgnoreCase))
                        continue;

                    var title = it.TryGetProperty("Title", out var titleEl) ? (titleEl.GetString() ?? "") : "";
                    if (string.IsNullOrWhiteSpace(title)) continue;
                    var path = it.TryGetProperty("FilePath", out var pathEl) ? (pathEl.GetString() ?? "") : "";

                    var score = ScoreByPhrases(title, path, keywords);
                    if (score <= 0) continue;
                    scored.Add((title.Trim(), score));
                }

                return scored
                    .OrderByDescending(s => s.score)
                    .ThenBy(s => s.title, StringComparer.OrdinalIgnoreCase)
                    .Select(s => s.title)
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(Math.Max(1, maxResults))
                    .ToList();
            }
            catch
            {
                return new List<string>();
            }
        }

