        static MediaCentreViewModel()
        {
            try
            {
                ServerHttp.DefaultRequestHeaders.TryAddWithoutValidation("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/121.0 Safari/537.36");
                ServerHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept", "application/json");
                ServerHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept-Language", "en-US,en;q=0.9");
                ServerImageHttp.DefaultRequestHeaders.TryAddWithoutValidation("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/121.0 Safari/537.36");
                ServerImageHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept", "*/*");
                ServerImageHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept-Language", "en-US,en;q=0.9");
                PreviewHttp.DefaultRequestHeaders.TryAddWithoutValidation("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/121.0 Safari/537.36");
                PreviewHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept", "application/json");
                PreviewHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept-Language", "en-US,en;q=0.9");
                RadioProbeHttp.DefaultRequestHeaders.TryAddWithoutValidation("User-Agent", "AtlasAI/1.0");
                RadioProbeHttp.DefaultRequestHeaders.TryAddWithoutValidation("Accept", "*/*");
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error initializing HTTP headers: {ex.Message}");
            }
        }

