        public sealed class MediaAgentResultItem
        {
            public enum ResultKind { Movie, Music, Local, Info, Error }
            public ResultKind Kind { get; init; } = ResultKind.Info;
            public string Title { get; init; } = "";
            public string Subtitle { get; init; } = "";
            public string MediaTypeId { get; init; } = "";
            public int? Year { get; init; }
            public double? Rating { get; init; }
            public int? Votes { get; init; }
            public string Provider { get; init; } = "";
            public string Overview { get; init; } = "";
            public string Source { get; init; } = "";
            public string LocalPath { get; init; } = "";
            public string ExternalQuery { get; init; } = "";
            public IReadOnlyList<string> Tags { get; init; } = Array.Empty<string>();
            public string LibraryStatusText { get; init; } = "";
            public string DraftCategory { get; init; } = "";
            public bool CanPlay { get; init; }
            public bool CanOpenLocation { get; init; }
            public string SimilarReason { get; init; } = "";
            public string ArtistName { get; init; } = "";
            public int? TmdbId { get; init; }
            public bool CanAddToWatchlistDraft => Kind == ResultKind.Movie;
            public bool CanAddToPlaylistDraft =>
                Kind == ResultKind.Music ||
                string.Equals(MediaTypeId, "music", StringComparison.OrdinalIgnoreCase);
            public bool CanFindTrailer => Kind == ResultKind.Movie;
            public bool CanSearchWeb => Kind == ResultKind.Movie;
            public string YearText => Year.HasValue ? $"({Year.Value})" : "";
            public string RatingText => Rating.HasValue && Rating.Value > 0
                ? "★ " + Rating.Value.ToString("0.0", CultureInfo.InvariantCulture) + "/10"
                : "";
            public string VotesText => Votes.HasValue && Votes.Value > 0
                ? Votes.Value.ToString("N0", CultureInfo.InvariantCulture) + " votes"
                : "";
            public string TagsText => Tags.Count > 0 ? string.Join(", ", Tags.Take(3)) : "";
            public string DraftDisplayName => string.IsNullOrWhiteSpace(ArtistName) ? Title : $"{ArtistName} - {Title}";
            public string ToFallbackLine()
            {
                var sb = new System.Text.StringBuilder();
                if (!string.IsNullOrWhiteSpace(ArtistName)) sb.Append(ArtistName).Append(" — ");
                sb.Append(Title);
                if (Year.HasValue) sb.Append(" (").Append(Year.Value).Append(')');
                if (!string.IsNullOrWhiteSpace(RatingText)) sb.Append(" · ").Append(RatingText);
                if (!string.IsNullOrWhiteSpace(SimilarReason)) sb.Append(" · ").Append(SimilarReason);
                if (!string.IsNullOrWhiteSpace(Provider)) sb.Append(" · ").Append(Provider);
                return sb.ToString();
            }
        }

