        // DEBUG: Log all candidates and shelves built
        private void DebugLogShelfCandidates(List<ShelfCandidate> candidates, string context)
        {
            try
            {
                var msg = $"[ShelfDebug] {context}: Candidates={candidates.Count}\n";
                foreach (var c in candidates)
                {
                    msg += $"  - {c.Title} | {c.ContentType} | {c.CatalogId} | Servers={string.Join(",", c.Servers.Select(s => s.BaseUrl))}\n";
                }
                AppLogger.LogInfo(msg);
            }
            catch { }
        }

        private void DebugLogShelves(List<ServerShelf> shelves, string context)
        {
            try
            {
                var msg = $"[ShelfDebug] {context}: Shelves={shelves.Count}\n";
                foreach (var s in shelves)
                {
                    msg += $"  - {s.Title} | {s.ContentType} | {s.CatalogId} | Items={s.Items.Count}\n";
                }
                AppLogger.LogInfo(msg);
            }
            catch { }
        }

