        public bool IsChatVisible
        {
            get => _isChatVisible;
            set
            {
                if (!SetProperty(ref _isChatVisible, value)) return;
                try
                {
                    var orchestrator = VoiceSystemOrchestrator.Instance;
                    if (_isChatVisible)
                    {
                        // Save current handler before overwriting, so we can restore it later
                        _previousPushToTalkHandler ??= orchestrator.PushToTalkCommandHandler;

                        try
                        {
                            _uiDispatcher.BeginInvoke(() =>
                            {
                                try
                                {
                                    EnsureMediaAiGreeting();
                                }
                                catch
                                {
                                }
                            });
                        }
                        catch
                        {
                        }

                        orchestrator.PushToTalkCommandHandler = (text) =>
                        {
                            _uiDispatcher.BeginInvoke(() =>
                            {
                                try
                                {
                                    MediaAiCommandText = text;
                                }
                                catch
                                {
                                }
                            });
                        };
                    }
                    else if (_previousPushToTalkHandler != null)
                    {
                        // Restore the handler we saved earlier
                        orchestrator.PushToTalkCommandHandler = _previousPushToTalkHandler;
                        _previousPushToTalkHandler = null;
                    }
                }
                catch (OperationCanceledException)
                {
                    // Ignore cancellation
                }
                catch (Exception ex)
                {
                    System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error restoring PushToTalk handler: {ex.Message}");
                }
            }
        }

        private void EnsureMediaAiGreeting()
        {
            if (_mediaAiChat.Count > 0) return;

            var hasProvider = false;
            try
            {
                var provider = AIManager.GetActiveProviderInstance();
                hasProvider = provider != null && provider.IsConfigured;
            }
            catch
            {
            }

            var greeting =
                "Atlas Media Agent ready.\n" +
                "I can search, explain selected media, and produce preview cleanup plans.\n" +
                "Try: find me all marvel movies\n" +
                "Try: show tv breaking bad\n" +
                "Try: clear search\n" +
                "Use quick actions for structured insights.";

            if (!hasProvider)
                greeting += "\nAI provider is not configured, but search commands still work.";

            _mediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = greeting });
        }

