        private void RebuildServerShelves()
        {
            // Debounce: cancel any pending debounce timer and restart it.
            // This collapses rapid successive calls into one actual build.
            try { _serverShelvesDebounCts?.Cancel(); _serverShelvesDebounCts?.Dispose(); } catch { }
            _serverShelvesDebounCts = new CancellationTokenSource();
            var debounceCt = _serverShelvesDebounCts.Token;
            _ = Task.Run(async () =>
            {
                try
                {
                    await Task.Delay(800, debounceCt).ConfigureAwait(false);
                }
                catch (OperationCanceledException)
                {
                    return; // A newer call superseded this one
                }

                // Cancel any in-progress build and start a fresh one
                try { _serverShelvesBuildCts?.Cancel(); _serverShelvesBuildCts?.Dispose(); } catch { }
                _serverShelvesBuildCts = new CancellationTokenSource();
                var ct = _serverShelvesBuildCts.Token;
                await BuildServerShelvesAsync(ct).ConfigureAwait(false);
            });
        }

        private sealed record ShelfCandidate(string ContentType, string CatalogId, string Title, List<(string BaseUrl, string RequestType)> Servers);

        private static bool IsSupportedContentType(string? value)
        {
            var v = (value ?? "").Trim();
            return string.Equals(v, "movie", StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(v, "series", StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(v, "music", StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsBlockedLegacyAiSearchShelf(string? catalogId, string? title)
        {
            var haystack = $"{(catalogId ?? "").Trim()} {(title ?? "").Trim()}".ToLowerInvariant();
            if (string.IsNullOrWhiteSpace(haystack))
                return false;

            return haystack.Contains("ai search movie") ||
                   haystack.Contains("ai search movies") ||
                   haystack.Contains("ai search series") ||
                   haystack.Contains("ai movies") ||
                   haystack.Contains("ai series");
        }

        private static double NormalizeRatingToTen(double raw)
        {
            try
            {
                if (double.IsNaN(raw) || double.IsInfinity(raw)) return 0;
                var v = Math.Abs(raw);
                if (v <= 0) return 0;

                // Common cases:
                // - 0..10 (already)
                // - 0..100 (percent)
                // - 0..1 (fraction)
                if (v > 10 && v <= 100) v = v / 10.0;
                else if (v > 0 && v < 1.0) v = v * 10.0;

                if (v > 10) v = 10;
                return Math.Round(v, 1, MidpointRounding.AwayFromZero);
            }
            catch
            {
                return 0;
            }
        }

        private static bool TryParseRatingString(string? raw, out double value)
        {
            value = 0;
            var s = (raw ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return false;

            // e.g. "7.8/10", "78%", "7,8"
            if (s.EndsWith("%", StringComparison.Ordinal))
                s = s.TrimEnd('%').Trim();

            var slash = s.IndexOf('/');
            if (slash > 0)
                s = s.Substring(0, slash).Trim();

            s = s.Replace(',', '.');

            if (double.TryParse(s, NumberStyles.Float, CultureInfo.InvariantCulture, out var d))
            {
                value = d;
                return true;
            }
            if (double.TryParse(s, out d))
            {
                value = d;
                return true;
            }
            return false;
        }

        private static double ReadNormalizedRating(JsonElement el)
        {
            try
            {
                if (el.ValueKind == JsonValueKind.Number && el.TryGetDouble(out var d))
                    return NormalizeRatingToTen(d);
                if (el.ValueKind == JsonValueKind.String && TryParseRatingString(el.GetString(), out var ds))
                    return NormalizeRatingToTen(ds);
            }
            catch
            {
            }
            return 0;
        }

        private static int ShelfScore(string? catalogId, string? title)
        {
            var id = (catalogId ?? "").Trim().ToLowerInvariant();
            var t = (title ?? "").Trim().ToLowerInvariant();
            if (id == "top" || t.Contains("top") || t.Contains("latest") || t.Contains("new releases")) return 0;
            if (id.Contains("popular") || t.Contains("popular")) return 1;
            if (id.Contains("trending") || t.Contains("trending")) return 2;
            if (id.Contains("featured") || t.Contains("featured")) return 3;
            if (id.Contains("new") || t.Contains("new")) return 4;
            if (id.Contains("discover") || t.Contains("discover")) return 5;
            return 10;
        }

        private async Task<List<MediaItem>> LoadShelfItemsAsync(List<ServerCatalogPageState> states, int targetCount, CancellationToken ct)
        {
            var dedupe = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var results = new List<MediaItem>();
            if (states == null || states.Count == 0) return results;

            var start = DateTime.UtcNow;
            var softDeadlineMs = Math.Clamp(states.Count * 2500, 10000, 20000);
            var maxParallel = 4;
            var activeStates = states
                .Where(s => s != null && s.HasMore && !string.IsNullOrWhiteSpace(s.BaseUrl) && !string.IsNullOrWhiteSpace(s.CatalogId))
                .ToList();

            while (activeStates.Count > 0)
            {
                ct.ThrowIfCancellationRequested();
                var elapsed = (DateTime.UtcNow - start).TotalMilliseconds;
                if (results.Count >= targetCount || elapsed >= softDeadlineMs)
                    break;

                using var semaphore = new SemaphoreSlim(maxParallel);
                var roundTasks = activeStates.Select(async state =>
                {
                    await semaphore.WaitAsync(ct).ConfigureAwait(false);
                    try
                    {
                        return await TryLoadServerCatalogPageAsync(state, ct, searchQuery: null).ConfigureAwait(false);
                    }
                    catch
                    {
                        return (items: new List<MediaItem>(), updated: state with { HasMore = false });
                    }
                    finally
                    {
                        try { semaphore.Release(); } catch { }
                    }
                }).ToList();

                var roundResults = await Task.WhenAll(roundTasks).ConfigureAwait(false);
                var nextStates = new List<ServerCatalogPageState>();
                var addedAny = false;

                foreach (var round in roundResults)
                {
                    foreach (var item in round.items)
                    {
                        if (item == null) continue;
                        var key = BuildServerCatalogDedupeKey(item);
                        if (string.IsNullOrWhiteSpace(key)) continue;
                        if (!dedupe.Add(key)) continue;
                        results.Add(item);
                        addedAny = true;
                        if (results.Count >= targetCount)
                            break;
                    }

                    if (results.Count >= targetCount)
                        break;

                    if (round.updated.HasMore && round.updated.NextSkip > 0)
                        nextStates.Add(round.updated);
                }

                if (results.Count >= targetCount || nextStates.Count == 0 || !addedAny)
                    break;

                activeStates = nextStates;
            }

            return results;
        }

        private async Task BuildServerShelvesAsync(CancellationToken ct)
        {
            try
            {
                if (!IsServersView) return;

                const int shelfPreviewCount = 180;

                var snap = _uiDispatcher.Invoke(() =>
                {
                    var selection = (SelectedAddonServer ?? "").Trim();
                    var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
                    var normalizedSelection = NormalizeAddonServerUrl(selection);

                    Dictionary<string, List<ServerCatalogCatalogOption>> movieOptions;
                    Dictionary<string, List<ServerCatalogCatalogOption>> seriesOptions;
                    Dictionary<string, List<ServerCatalogCatalogOption>> musicOptions;
                    lock (_stateLock)
                    {
                        movieOptions = new Dictionary<string, List<ServerCatalogCatalogOption>>(_serverMovieCatalogOptionsByServer, StringComparer.OrdinalIgnoreCase);
                        seriesOptions = new Dictionary<string, List<ServerCatalogCatalogOption>>(_serverSeriesCatalogOptionsByServer, StringComparer.OrdinalIgnoreCase);
                        musicOptions = new Dictionary<string, List<ServerCatalogCatalogOption>>(_serverMusicCatalogOptionsByServer, StringComparer.OrdinalIgnoreCase);
                    }

                    return (
                        selection,
                        isAllServers,
                        normalizedSelection,
                        movieOptions,
                        seriesOptions,
                        musicOptions,
                        _serverMovieCatalogItems.Take(shelfPreviewCount).ToList(),
                        _serverTvCatalogItems.Take(shelfPreviewCount).ToList(),
                        _serverMusicCatalogItems.Take(shelfPreviewCount).ToList()
                    );
                });

                var isAll = snap.isAllServers;
                var normalizedSelection = (snap.normalizedSelection ?? "").Trim();

                if (_addonServers.Count == 0)
                {
                    await _uiDispatcher.InvokeAsync(() =>
                    {
                        _serverShelves.Clear();
                        ActiveServerShelf = null;
                        OnPropertyChanged(nameof(ServerShelves));
                    });
                    return;
                }

                static ServerShelf? CreateSnapshotShelf(string title, string contentType, string catalogId, List<MediaItem> items, int previewCount)
                {
                    if (items == null || items.Count == 0)
                        return null;

                    var shelf = new ServerShelf { ContentType = contentType, CatalogId = catalogId, Title = title };
                    foreach (var item in items.Take(previewCount))
                        shelf.Items.Add(item);
                    return shelf.Items.Count > 0 ? shelf : null;
                }

                var coreShelves = new List<ServerShelf>();
                var allMoviesShelf = CreateSnapshotShelf("All Movies", "movie", AllMoviesShelfCatalogId, snap.Item7, shelfPreviewCount);
                var allSeriesShelf = CreateSnapshotShelf("All Series", "series", AllSeriesShelfCatalogId, snap.Item8, shelfPreviewCount);
                if (allMoviesShelf != null)
                    coreShelves.Add(allMoviesShelf);
                if (allSeriesShelf != null)
                    coreShelves.Add(allSeriesShelf);

                // Do NOT post an intermediate state here — keep existing shelves visible
                // while the async per-catalog build runs. Only replace once fully complete.

                IEnumerable<ShelfCandidate> BuildCandidates(string contentType, Dictionary<string, List<ServerCatalogCatalogOption>> optionsByServer)
                {
                    var byId = new Dictionary<string, ShelfCandidate>(StringComparer.OrdinalIgnoreCase);
                    var byTitle = new Dictionary<string, ShelfCandidate>(StringComparer.OrdinalIgnoreCase);
                    foreach (var kv in optionsByServer)
                    {
                        ct.ThrowIfCancellationRequested();
                        var baseUrl = (kv.Key ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(baseUrl)) continue;
                        if (!isAll && !string.IsNullOrWhiteSpace(normalizedSelection) &&
                            !string.Equals(baseUrl.Trim().TrimEnd('/'), normalizedSelection.Trim().TrimEnd('/'), StringComparison.OrdinalIgnoreCase))
                            continue;

                        foreach (var opt in kv.Value ?? new List<ServerCatalogCatalogOption>())
                        {
                            var cid = (opt?.Value ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(cid)) continue;
                            var title = (opt?.Label ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(title)) title = cid;
                            if (IsBlockedLegacyAiSearchShelf(cid, title)) continue;
                            var req = (opt?.RequestType ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(req)) req = contentType;

                            // Deduplicate by catalogId first, then by normalised title
                            var idKey = $"{contentType}::{cid}";
                            if (!byId.TryGetValue(idKey, out var existing))
                            {
                                // Check if same display title already exists under a different catalogId
                                var titleKey = $"{contentType}::{title.ToLowerInvariant()}";
                                if (byTitle.TryGetValue(titleKey, out existing))
                                {
                                    // Merge servers into the existing same-title shelf
                                    existing.Servers.Add((baseUrl.Trim().TrimEnd('/'), req));
                                    byId[idKey] = existing;
                                    continue;
                                }

                                existing = new ShelfCandidate(contentType, cid, title, new List<(string BaseUrl, string RequestType)>());
                                byId[idKey] = existing;
                                byTitle[titleKey] = existing;
                            }
                            existing.Servers.Add((baseUrl.Trim().TrimEnd('/'), req));
                        }
                    }
                    return byId.Values.Distinct();
                }

                var candidates = new List<ShelfCandidate>();
                candidates.AddRange(BuildCandidates("movie", snap.movieOptions));
                candidates.AddRange(BuildCandidates("series", snap.seriesOptions));
                candidates.AddRange(BuildCandidates("music", snap.musicOptions));

                const int allServersPerCatalogPreviewCount = 36;
                const int allServersPerCatalogShelfLimit = 60;

                static bool IsGenericAllServersCandidate(ShelfCandidate candidate)
                {
                    var catalogId = (candidate.CatalogId ?? string.Empty).Trim().ToLowerInvariant();
                    var title = (candidate.Title ?? string.Empty).Trim().ToLowerInvariant();
                    var haystack = $"{catalogId} {title}";

                    return haystack.Contains("top") ||
                           haystack.Contains("popular") ||
                           haystack.Contains("trending") ||
                           haystack.Contains("featured") ||
                           haystack.Contains("latest") ||
                           haystack.Contains("new") ||
                           haystack.Contains("discover") ||
                           haystack.Contains("collection");
                }

                List<ShelfCandidate> SelectPerCatalogCandidates(List<ShelfCandidate> source)
                {
                    if (!isAll || source.Count <= allServersPerCatalogShelfLimit)
                        return source;

                    var ranked = source
                        .Select(candidate => new
                        {
                            candidate,
                            score = ShelfScore(candidate.CatalogId, candidate.Title),
                            hostCount = candidate.Servers
                                .Select(server => server.BaseUrl)
                                .Where(baseUrl => !string.IsNullOrWhiteSpace(baseUrl))
                                .Distinct(StringComparer.OrdinalIgnoreCase)
                                .Count()
                        })
                        .OrderByDescending(entry => entry.hostCount)
                        .ThenBy(entry => entry.score)
                        .ThenBy(entry => entry.candidate.Title, StringComparer.OrdinalIgnoreCase)
                        .ToList();

                    var prioritized = ranked
                        .Where(entry => !IsGenericAllServersCandidate(entry.candidate))
                        .Concat(ranked.Where(entry => IsGenericAllServersCandidate(entry.candidate)))
                        .Select(entry => entry.candidate)
                        .Take(allServersPerCatalogShelfLimit)
                        .ToList();

                    return prioritized;
                }

                var perCatalogCandidates = SelectPerCatalogCandidates(candidates);
                var perCatalogPreviewCount = isAll ? allServersPerCatalogPreviewCount : shelfPreviewCount;

                AtlasAI.Core.AppLogger.LogInfo($"[BuildServerShelves] snapshot: movieServers={snap.movieOptions.Count} seriesServers={snap.seriesOptions.Count} musicServers={snap.musicOptions.Count} candidates={candidates.Count}");

                var intelligentShelves = (await TryBuildMediaIntelligenceShelvesAsync(ct).ConfigureAwait(false))
                    .Where(s => !IsBlockedLegacyAiSearchShelf(s?.CatalogId, s?.Title))
                    .ToList();

                var perCatalogShelves = await BuildPerCatalogShelvesAsync(perCatalogCandidates, isAll, perCatalogPreviewCount, ct).ConfigureAwait(false);

                AtlasAI.Core.AppLogger.LogInfo($"[BuildServerShelves] result: intelligence={intelligentShelves.Count} perCatalog={perCatalogShelves.Count} candidates={candidates.Count} selectedPerCatalogCandidates={perCatalogCandidates.Count} perCatalogPreviewCount={perCatalogPreviewCount}");

                // Option A: index Phase 1 results by ContentType::CatalogId so Phase 2 named shelves and
                // Phase 3 extra shelves can be assembled from memory without any additional network calls.
                var perCatalogByKey = new Dictionary<string, List<MediaItem>>(StringComparer.OrdinalIgnoreCase);
                foreach (var pcs in perCatalogShelves)
                {
                    if (pcs?.Items.Count > 0)
                    {
                        var k = $"{pcs.ContentType}::{pcs.CatalogId}";
                        if (!perCatalogByKey.TryGetValue(k, out var existing))
                            perCatalogByKey[k] = new List<MediaItem>(pcs.Items);
                        else
                            existing.AddRange(pcs.Items);
                    }
                }

                if (intelligentShelves.Count > 0)
                {
                    // Keep stable browse-all shelves first, then append intelligence and addon shelves.
                    var combined = new List<ServerShelf>(coreShelves);
                    combined.AddRange(intelligentShelves);
                    foreach (var pcs in perCatalogShelves)
                    {
                        if (pcs?.Items.Count > 0)
                            combined.Add(pcs);
                    }

                    await _uiDispatcher.InvokeAsync(() =>
                    {
                        _serverShelves.Clear();
                        foreach (var shelf in combined)
                        {
                            _serverShelves.Add(shelf);
                        }
                        OnPropertyChanged(nameof(ServerShelves));
                    });
                    return;
                }

                if (candidates.Count == 0)
                {
                    await _uiDispatcher.InvokeAsync(() =>
                    {
                        _serverShelves.Clear();
                        foreach (var shelf in coreShelves)
                            _serverShelves.Add(shelf);
                        if (snap.Item9.Count > 0)
                        {
                            var shelf = new ServerShelf { ContentType = "music", CatalogId = "top", Title = "Music" };
                            foreach (var i in snap.Item9) shelf.Items.Add(i);
                            _serverShelves.Add(shelf);
                        }
                        OnPropertyChanged(nameof(ServerShelves));
                    });
                    return;
                }

                // Fixed shelf lineup in requested order.
                // We best-effort match addon catalogs; if a shelf has no matches/items it is skipped.
                var movieCandidates = candidates.Where(c => string.Equals((c.ContentType ?? "").Trim(), "movie", StringComparison.OrdinalIgnoreCase)).ToList();
                var seriesCandidates = candidates.Where(c => string.Equals((c.ContentType ?? "").Trim(), "series", StringComparison.OrdinalIgnoreCase)).ToList();

                static bool ContainsAny(string value, params string[] parts)
                {
                    var v = (value ?? "").Trim().ToLowerInvariant();
                    if (string.IsNullOrWhiteSpace(v)) return false;
                    foreach (var p in parts)
                    {
                        var pp = (p ?? "").Trim().ToLowerInvariant();
                        if (string.IsNullOrWhiteSpace(pp)) continue;
                        if (v.Contains(pp)) return true;
                    }
                    return false;
                }

                static bool MatchesKeyword(ShelfCandidate c, params string[] parts)
                {
                    return ContainsAny(c.CatalogId, parts) || ContainsAny(c.Title, parts);
                }

                static bool MatchesRequestType(ShelfCandidate c, params string[] reqTypes)
                {
                    foreach (var s in c.Servers)
                    {
                        if (ContainsAny(s.RequestType, reqTypes))
                            return true;
                    }
                    return false;
                }

                List<ServerCatalogPageState> BuildStatesFromCandidates(List<ShelfCandidate> match, int maxCandidates, int maxServersPerCandidate)
                {
                    var states = new List<ServerCatalogPageState>();
                    foreach (var cand in match
                        .Select(c => new
                        {
                            c,
                            score = ShelfScore(c.CatalogId, c.Title),
                            hostCount = c.Servers.Select(s => s.BaseUrl).Distinct(StringComparer.OrdinalIgnoreCase).Count()
                        })
                        .OrderBy(x => x.score)
                        .ThenByDescending(x => x.hostCount)
                        .ThenBy(x => x.c.Title, StringComparer.OrdinalIgnoreCase)
                        .Select(x => x.c)
                        .Take(maxCandidates))
                    {
                        ct.ThrowIfCancellationRequested();
                        foreach (var s in cand.Servers
                            .Where(s => !string.IsNullOrWhiteSpace(s.BaseUrl))
                            .DistinctBy(s => s.BaseUrl, StringComparer.OrdinalIgnoreCase)
                            .Take(maxServersPerCandidate))
                        {
                            var req = string.IsNullOrWhiteSpace(s.RequestType) ? cand.ContentType : s.RequestType;
                            states.Add(new ServerCatalogPageState(
                                BaseUrl: (s.BaseUrl ?? "").Trim().TrimEnd('/'),
                                ContentType: (cand.ContentType ?? "").Trim(),
                                CatalogId: (cand.CatalogId ?? "").Trim(),
                                NextSkip: 0,
                                HasMore: true,
                                RequestType: (req ?? "").Trim()));
                        }
                    }
                    return states;
                }

                async Task<ServerShelf?> BuildShelfFromCandidatesAsync(string keyType, string keyCatalogId, string title, List<ShelfCandidate> match)
                {
                    try
                    {
                        if (match.Count == 0) return null;

                        // Pick a stable primary candidate for the shelf identity.
                        // This allows "View All" to open a real paged catalog (type+catalogId must be content-protocol valid).
                        var primary = match
                            .Select(c => new
                            {
                                c,
                                score = ShelfScore(c.CatalogId, c.Title),
                                hostCount = c.Servers.Select(s => s.BaseUrl).Distinct(StringComparer.OrdinalIgnoreCase).Count()
                            })
                            .OrderBy(x => x.score)
                            .ThenByDescending(x => x.hostCount)
                            .ThenBy(x => x.c.Title, StringComparer.OrdinalIgnoreCase)
                            .Select(x => x.c)
                            .FirstOrDefault();

                        var shelfType = (primary?.ContentType ?? keyType).Trim();
                        var shelfCatalogId = (primary?.CatalogId ?? keyCatalogId).Trim();

                        var states = BuildStatesFromCandidates(match, maxCandidates: 4, maxServersPerCandidate: isAll ? 4 : 1);
                        if (states.Count == 0) return null;
                        var items = await LoadShelfItemsAsync(states, targetCount: shelfPreviewCount * 2, ct).ConfigureAwait(false);
                        if (items.Count == 0) return null;

                        items = items
                            .Where(i => i != null)
                            .Where(i =>
                            {
                                var type = (i.Type ?? "").Trim();
                                if (string.Equals(keyType, "movie", StringComparison.OrdinalIgnoreCase))
                                    return string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "movie", StringComparison.OrdinalIgnoreCase);
                                if (string.Equals(keyType, "series", StringComparison.OrdinalIgnoreCase) || string.Equals(keyType, "tv", StringComparison.OrdinalIgnoreCase))
                                    return string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "series", StringComparison.OrdinalIgnoreCase);
                                return true;
                            })
                            .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                            .ToList();

                        if (items.Count == 0) return null;

                        if (string.Equals(title, "Latest Movies", StringComparison.OrdinalIgnoreCase) ||
                            string.Equals(title, "Latest Series", StringComparison.OrdinalIgnoreCase))
                        {
                            items = items
                                .OrderByDescending(i => i.Year > 0 ? i.Year : int.MinValue)
                                .ThenByDescending(i => i.ReleaseDate ?? DateTime.MinValue)
                                .ThenByDescending(i => i.Rating)
                                .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase)
                                .ToList();
                        }

                        var shelf = new ServerShelf { ContentType = shelfType, CatalogId = shelfCatalogId, Title = title };
                        foreach (var i in items.Take(shelfPreviewCount)) shelf.Items.Add(i);
                        return shelf;
                    }
                    catch
                    {
                        return null;
                    }
                }

                // In-memory counterpart to BuildShelfFromCandidatesAsync.
                // Aggregates items from Phase 1 perCatalogShelves; no network calls.
                ServerShelf? BuildShelfFromCache(string keyType, string keyCatalogId, string title, List<ShelfCandidate> match)
                {
                    try
                    {
                        if (match.Count == 0) return null;

                        // Same primary-candidate selection as BuildShelfFromCandidatesAsync.
                        var primary = match
                            .Select(c => new
                            {
                                c,
                                score = ShelfScore(c.CatalogId, c.Title),
                                hostCount = c.Servers.Select(s => s.BaseUrl).Distinct(StringComparer.OrdinalIgnoreCase).Count()
                            })
                            .OrderBy(x => x.score)
                            .ThenByDescending(x => x.hostCount)
                            .ThenBy(x => x.c.Title, StringComparer.OrdinalIgnoreCase)
                            .Select(x => x.c)
                            .FirstOrDefault();

                        var shelfType = (primary?.ContentType ?? keyType).Trim();
                        var shelfCatalogId = (primary?.CatalogId ?? keyCatalogId).Trim();

                        // Aggregate items from all matching Phase 1 per-catalog shelves.
                        var items = new List<MediaItem>();
                        foreach (var cand in match)
                        {
                            var key = $"{cand.ContentType}::{cand.CatalogId}";
                            if (perCatalogByKey.TryGetValue(key, out var cachedItems))
                                items.AddRange(cachedItems);
                        }

                        if (items.Count == 0) return null;

                        items = items
                            .Where(i => i != null)
                            .Where(i =>
                            {
                                var type = (i.Type ?? "").Trim();
                                if (string.Equals(keyType, "movie", StringComparison.OrdinalIgnoreCase))
                                    return string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "movie", StringComparison.OrdinalIgnoreCase);
                                if (string.Equals(keyType, "series", StringComparison.OrdinalIgnoreCase) || string.Equals(keyType, "tv", StringComparison.OrdinalIgnoreCase))
                                    return string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "series", StringComparison.OrdinalIgnoreCase);
                                return true;
                            })
                            .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                            .ToList();

                        if (items.Count == 0) return null;

                        if (string.Equals(title, "Latest Movies", StringComparison.OrdinalIgnoreCase) ||
                            string.Equals(title, "Latest Series", StringComparison.OrdinalIgnoreCase))
                        {
                            items = items
                                .OrderByDescending(i => i.Year > 0 ? i.Year : int.MinValue)
                                .ThenByDescending(i => i.ReleaseDate ?? DateTime.MinValue)
                                .ThenByDescending(i => i.Rating)
                                .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase)
                                .ToList();
                        }

                        var shelf = new ServerShelf { ContentType = shelfType, CatalogId = shelfCatalogId, Title = title };
                        foreach (var i in items.Take(shelfPreviewCount)) shelf.Items.Add(i);
                        return shelf;
                    }
                    catch
                    {
                        return null;
                    }
                }

                static List<ShelfCandidate> BestFallback(List<ShelfCandidate> list)
                {
                    return list
                        .OrderBy(c => ShelfScore(c.CatalogId, c.Title))
                        .ThenBy(c => c.Title, StringComparer.OrdinalIgnoreCase)
                        .Take(1)
                        .ToList();
                }

                var specs = new List<(int order, Func<Task<ServerShelf?>> build)>
                {
                    (0, () =>
                    {
                        var match = movieCandidates
                            .Where(c => MatchesKeyword(c, "latest", "new", "new releases", "recent"))
                            .Where(c => !MatchesRequestType(c, "collections"))
                            .Where(c => !MatchesKeyword(c, "collection", "collections"))
                            .ToList();
                        if (match.Count == 0) match = movieCandidates.Where(c => string.Equals((c.CatalogId ?? "").Trim(), "top", StringComparison.OrdinalIgnoreCase)).ToList();
                        if (match.Count == 0) match = BestFallback(movieCandidates);
                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("movie", "latest", "Latest Movies", match));
                    }),
                    (1, () =>
                    {
                        var match = seriesCandidates
                            .Where(c => MatchesKeyword(c, "latest", "new", "new releases", "recent"))
                            .Where(c => !MatchesRequestType(c, "collections"))
                            .Where(c => !MatchesKeyword(c, "collection", "collections"))
                            .ToList();
                        if (match.Count == 0) match = seriesCandidates.Where(c => string.Equals((c.CatalogId ?? "").Trim(), "top", StringComparison.OrdinalIgnoreCase)).ToList();
                        if (match.Count == 0) match = BestFallback(seriesCandidates);
                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("series", "latest", "Latest Series", match));
                    }),
                    (3, () =>
                    {
                        var match = candidates.Where(c => MatchesKeyword(c, "popular", "top")).ToList();
                        if (match.Count == 0) match = candidates.Where(c => string.Equals((c.CatalogId ?? "").Trim(), "top", StringComparison.OrdinalIgnoreCase)).ToList();
                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("mixed", "popular", "Popular", match));
                    }),
                    (4, () =>
                    {
                        var match = candidates.Where(c => MatchesKeyword(c, "trending", "trend")).ToList();
                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("mixed", "trending", "Trending This Week", match));
                    }),
                    (5, () =>
                    {
                        var match = candidates.Where(c => MatchesKeyword(c, "top rated", "top-rated", "best", "all time", "imdb")).ToList();
                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("mixed", "alltime", "All Time Greats", match));
                    }),
                    (6, () =>
                    {
                        static bool IsAnimationy(ShelfCandidate c)
                        {
                            return MatchesKeyword(c, "animation", "animated", "anime", "cartoon");
                        }

                        // Prefer Marvel movie/series catalogs, avoid animation/anime by default.
                        var match = candidates
                            .Where(c =>
                                (string.Equals((c.ContentType ?? "").Trim(), "movie", StringComparison.OrdinalIgnoreCase) ||
                                 string.Equals((c.ContentType ?? "").Trim(), "series", StringComparison.OrdinalIgnoreCase)) &&
                                (MatchesRequestType(c, "marvel") || MatchesKeyword(c, "marvel")) &&
                                !IsAnimationy(c))
                            .ToList();

                        // Fallback: allow animation/anime if it's the only Marvel content available.
                        if (match.Count == 0)
                        {
                            match = candidates
                                .Where(c =>
                                    (string.Equals((c.ContentType ?? "").Trim(), "movie", StringComparison.OrdinalIgnoreCase) ||
                                     string.Equals((c.ContentType ?? "").Trim(), "series", StringComparison.OrdinalIgnoreCase)) &&
                                    (MatchesRequestType(c, "marvel") || MatchesKeyword(c, "marvel")))
                                .ToList();
                        }

                        // Final fallback: any Marvel-tagged catalog.
                        if (match.Count == 0)
                            match = candidates.Where(c => MatchesRequestType(c, "marvel") || MatchesKeyword(c, "marvel")).ToList();

                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("marvel", "marvel", "Marvel", match));
                    }),
                    (7, () =>
                    {
                        var match = candidates.Where(c => MatchesRequestType(c, "collections") || MatchesKeyword(c, "collection", "collections")).ToList();
                        return Task.FromResult<ServerShelf?>(BuildShelfFromCache("collections", "collections", "Collections", match));
                    }),
                };

                var shelfConcurrency = 3;
                using var shelfSemaphore = new SemaphoreSlim(shelfConcurrency);
                var built = new List<(int order, ServerShelf shelf)>();

                var buildTasks = specs.Select(async spec =>
                {
                    await shelfSemaphore.WaitAsync(ct).ConfigureAwait(false);
                    try
                    {
                        var shelf = await spec.build().ConfigureAwait(false);
                        if (shelf == null || shelf.Items.Count == 0) return;
                        lock (built) built.Add((spec.order, shelf));
                    }
                    catch
                    {
                    }
                    finally
                    {
                        try { shelfSemaphore.Release(); } catch { }
                    }
                }).ToList();

                await Task.WhenAll(buildTasks).ConfigureAwait(false);

                // Phase 3 eliminated: reuse Phase 1 perCatalogShelves directly instead of re-fetching from network.
                var fixedCatalogKeys = new HashSet<string>(
                    built.Select(b => $"{b.shelf.ContentType}::{b.shelf.CatalogId}"),
                    StringComparer.OrdinalIgnoreCase);
                var nextOrder = (built.Count > 0 ? built.Max(b => b.order) : 7) + 1;
                foreach (var extra in perCatalogShelves)
                {
                    if (extra?.Items.Count > 0 && !fixedCatalogKeys.Contains($"{extra.ContentType}::{extra.CatalogId}"))
                        built.Add((nextOrder++, extra));
                }

                await _uiDispatcher.InvokeAsync(() =>
                {
                    _serverShelves.Clear();
                    foreach (var shelf in coreShelves)
                    {
                        _serverShelves.Add(shelf);
                    }
                    foreach (var shelf in built.OrderBy(s => s.order).Select(s => s.shelf))
                    {
                        _serverShelves.Add(shelf);
                    }
                    OnPropertyChanged(nameof(ServerShelves));
                });
            }
            catch
            {
            }
        }

        /// <summary>
        /// Builds one shelf per addon catalog candidate.  This surfaces every catalog declared
        /// in addon manifests (e.g. "Netflix Shows – Series", "HBO Shows – Series") as its own
        /// scrollable row, matching the behaviour Stremio provides when the same addons are installed.
        /// </summary>
        private async Task<List<ServerShelf>> BuildPerCatalogShelvesAsync(
            List<ShelfCandidate> candidates,
            bool isAllServers,
            int shelfPreviewCount,
            CancellationToken ct)
        {
            var shelves = new List<ServerShelf>();
            if (candidates == null || candidates.Count == 0)
                return shelves;

            const int maxConcurrency = 4;
            using var sem = new SemaphoreSlim(maxConcurrency);

            // Sort: movies first, then series, then music, alphabetical within each type.
            var ordered = candidates
                .OrderBy(c =>
                {
                    var t = (c.ContentType ?? "").Trim().ToLowerInvariant();
                    if (t == "movie") return 0;
                    if (t == "series") return 1;
                    return 2;
                })
                .ThenBy(c => c.Title, StringComparer.OrdinalIgnoreCase)
                .ToList();

            var tasks = ordered.Select(async cand =>
            {
                await sem.WaitAsync(ct).ConfigureAwait(false);
                try
                {
                    ct.ThrowIfCancellationRequested();

                    if (IsBlockedLegacyAiSearchShelf(cand.CatalogId, cand.Title))
                        return (ServerShelf?)null;

                    // Build page states from all servers that carry this catalog.
                    var states = new List<ServerCatalogPageState>();
                    var maxServers = isAllServers ? 4 : 1;
                    foreach (var s in cand.Servers
                        .Where(s => !string.IsNullOrWhiteSpace(s.BaseUrl))
                        .DistinctBy(s => s.BaseUrl, StringComparer.OrdinalIgnoreCase)
                        .Take(maxServers))
                    {
                        var req = string.IsNullOrWhiteSpace(s.RequestType) ? cand.ContentType : s.RequestType;
                        states.Add(new ServerCatalogPageState(
                            BaseUrl: (s.BaseUrl ?? "").Trim().TrimEnd('/'),
                            ContentType: (cand.ContentType ?? "").Trim(),
                            CatalogId: (cand.CatalogId ?? "").Trim(),
                            NextSkip: 0,
                            HasMore: true,
                            RequestType: (req ?? "").Trim()));
                    }

                    if (states.Count == 0)
                        return (ServerShelf?)null;

                    var items = await LoadShelfItemsAsync(states, targetCount: shelfPreviewCount, ct).ConfigureAwait(false);
                    if (items.Count == 0)
                        return null;

                    items = items
                        .Where(i => i != null)
                        .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                        .ToList();

                    if (items.Count == 0)
                        return null;

                    // Build a descriptive shelf title: "{Catalog Name} – {ContentType}"
                    var typeLabel = (cand.ContentType ?? "").Trim().ToLowerInvariant() switch
                    {
                        "movie" => "Movie",
                        "series" => "Series",
                        "music" => "Music",
                        _ => ""
                    };
                    var shelfTitle = (cand.Title ?? cand.CatalogId ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(typeLabel) &&
                        !shelfTitle.Contains(typeLabel, StringComparison.OrdinalIgnoreCase) &&
                        !shelfTitle.Contains("movie", StringComparison.OrdinalIgnoreCase) &&
                        !shelfTitle.Contains("series", StringComparison.OrdinalIgnoreCase) &&
                        !shelfTitle.Contains("music", StringComparison.OrdinalIgnoreCase))
                    {
                        shelfTitle = $"{shelfTitle} – {typeLabel}";
                    }

                    var shelf = new ServerShelf
                    {
                        ContentType = (cand.ContentType ?? "").Trim(),
                        CatalogId = (cand.CatalogId ?? "").Trim(),
                        Title = shelfTitle
                    };
                    foreach (var i in items.Take(shelfPreviewCount))
                        shelf.Items.Add(i);

                    return shelf;
                }
                catch
                {
                    return null;
                }
                finally
                {
                    try { sem.Release(); } catch { }
                }
            }).ToList();

            var results = await Task.WhenAll(tasks).ConfigureAwait(false);
            foreach (var s in results)
            {
                if (s?.Items.Count > 0)
                    shelves.Add(s);
            }

            return shelves;
        }

        private async Task<List<ServerShelf>> TryBuildMediaIntelligenceShelvesAsync(CancellationToken ct)
        {
            try
            {
                // Return cached shelves if still fresh (5 min TTL) to avoid slow TMDB API calls
                // during rapid rebuild cycles — this eliminates the cancellation race window.
                var cached = _cachedIntelligenceShelves;
                if (cached != null && (DateTime.UtcNow - _cachedIntelligenceShelvesTime).TotalMinutes < 5)
                    return new List<ServerShelf>(cached);

                var tmdbApiKey = (AtlasAI.Core.IntegrationKeyStore.GetDecrypted("tmdb") ?? "").Trim();
                if (string.IsNullOrWhiteSpace(tmdbApiKey))
                    return new List<ServerShelf>();

                var agent = new MediaIntelligenceAgent();
                var result = await agent.BuildHomeAsync(tmdbApiKey, TraktClientId, TraktToken, "Build Atlas home shelves", 30, ct).ConfigureAwait(false);
                var shelves = (result?.Sections ?? new List<MediaSection>())
                    .Select(MapMediaSectionToServerShelf)
                    .Where(shelf => shelf != null && shelf.Items.Count > 0)
                    .Select(shelf => shelf!)
                    .ToList();

                if (shelves.Count > 0)
                {
                    _cachedIntelligenceShelves = shelves;
                    _cachedIntelligenceShelvesTime = DateTime.UtcNow;
                }

                return shelves;
            }
            catch
            {
                // On failure, return cached shelves if available (even if stale)
                return _cachedIntelligenceShelves != null ? new List<ServerShelf>(_cachedIntelligenceShelves) : new List<ServerShelf>();
            }
        }

        private ServerShelf? MapMediaSectionToServerShelf(MediaSection? section)
        {
            if (section == null)
                return null;

            if (IsBlockedLegacyAiSearchShelf(section.Key, section.Title))
                return null;

            var items = (section.Items ?? new List<EnrichedMediaObject>())
                .Where(item => item != null)
                .Select(MapEnrichedMediaObjectToMediaItem)
                .Where(item => item != null)
                .Select(item => item!)
                .ToList();

            if (items.Count == 0)
                return null;

            var contentType = items.All(item => string.Equals(item.Type, "movie", StringComparison.OrdinalIgnoreCase))
                ? "movie"
                : items.All(item => string.Equals(item.Type, "series", StringComparison.OrdinalIgnoreCase))
                    ? "series"
                    : "mixed";

            var shelf = new ServerShelf
            {
                ContentType = contentType,
                CatalogId = string.IsNullOrWhiteSpace(section.Key) ? Guid.NewGuid().ToString("N") : section.Key,
                Title = string.IsNullOrWhiteSpace(section.Title) ? "Atlas Picks" : section.Title
            };

            foreach (var item in items)
            {
                shelf.Items.Add(item);
            }

            return shelf;
        }

        private MediaItem? MapEnrichedMediaObjectToMediaItem(EnrichedMediaObject? item)
        {
            if (item == null || string.IsNullOrWhiteSpace(item.Title))
                return null;

            var ratingBreakdown = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);
            if ((item.Ratings?.Tmdb ?? 0) > 0) ratingBreakdown["tmdb"] = item.Ratings.Tmdb;
            if ((item.Ratings?.Trakt ?? 0) > 0) ratingBreakdown["trakt"] = item.Ratings.Trakt;
            if ((item.Ratings?.Critic ?? 0) > 0) ratingBreakdown["critic"] = item.Ratings.Critic;
            if ((item.Ratings?.Audience ?? 0) > 0) ratingBreakdown["audience"] = item.Ratings.Audience;
            foreach (var signal in item.Ratings?.Signals ?? new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase))
            {
                if (!ratingBreakdown.ContainsKey(signal.Key))
                    ratingBreakdown[signal.Key] = signal.Value;
            }

            var rpdbRatings = ratingBreakdown
                .Where(entry => entry.Value > 0)
                .ToDictionary(entry => entry.Key, entry => entry.Value.ToString("0.0", CultureInfo.InvariantCulture), StringComparer.OrdinalIgnoreCase);

            var metadataParts = new List<string>();
            if (item.ReleaseDate?.Year is int year && year > 0)
                metadataParts.Add(year.ToString(CultureInfo.InvariantCulture));
            if (item.Genres?.Count > 0)
                metadataParts.Add(string.Join(" • ", item.Genres.Take(3)));
            if (item.RuntimeMinutes > 0)
                metadataParts.Add($"{item.RuntimeMinutes} min");

            var metaId = !string.IsNullOrWhiteSpace(item.ImdbId)
                ? item.ImdbId.Trim()
                : item.TmdbId.HasValue && item.TmdbId.Value > 0
                    ? $"tmdb:{item.TmdbId.Value}"
                    : item.Id;

            return new MediaItem
            {
                MetaId = metaId,
                TmdbId = item.TmdbId,
                ImdbId = item.ImdbId ?? "",
                FilePath = metaId ?? item.Id ?? item.Title,
                StreamSource = item.PrimaryStreamSource ?? "Atlas Intelligence",
                Title = item.Title,
                Metadata = string.Join(" • ", metadataParts),
                Year = item.ReleaseDate?.Year ?? 0,
                Rating = Math.Max(item.Ratings?.Tmdb ?? 0, item.Ratings?.Trakt ?? 0),
                AiScore = item.AiScore,
                CriticScore = item.AiRating?.CriticScore ?? 0,
                AudienceScore = item.AiRating?.AudienceScore ?? 0,
                TrendScore = item.AiRating?.TrendScore ?? 0,
                QualityTier = item.AiRating?.QualityTier.ToString() ?? "",
                Confidence = item.Confidence,
                Genres = item.Genres?.ToList() ?? new List<string>(),
                Overview = item.Overview ?? "",
                RuntimeMinutes = item.RuntimeMinutes,
                ReleaseDate = item.ReleaseDate,
                TrailerUrl = item.Trailer ?? "",
                StreamingAvailability = new Dictionary<string, string>(item.StreamingAvailability ?? new Dictionary<string, string>(), StringComparer.OrdinalIgnoreCase),
                RatingsBreakdown = ratingBreakdown,
                Type = item.Kind == MediaKind.Series ? "series" : "movie",
                CoverUrl = item.Poster,
                BackdropUrl = item.Backdrop,
                RpdbRatings = rpdbRatings,
                OriginalLanguage = item.OriginalLanguage ?? ""
            };
        }

        private Dictionary<string, List<ServerCatalogCatalogOption>> GetServerCatalogOptionsMap(string contentType)
        {
            if (string.Equals(contentType, "series", StringComparison.OrdinalIgnoreCase))
                return _serverSeriesCatalogOptionsByServer;
            if (string.Equals(contentType, "music", StringComparison.OrdinalIgnoreCase))
                return _serverMusicCatalogOptionsByServer;
            return _serverMovieCatalogOptionsByServer;
        }

        private static string BuildServerCatalogLabel(string? catalogId, string? name)
        {
            var label = (name ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(label))
                return label;

            var raw = (catalogId ?? "").Trim();
            if (string.IsNullOrWhiteSpace(raw))
                return "Top";

            var builder = new StringBuilder(raw.Length);
            var previousWasSeparator = true;
            foreach (var ch in raw)
            {
                if (char.IsLetterOrDigit(ch))
                {
                    builder.Append(previousWasSeparator ? char.ToUpperInvariant(ch) : ch);
                    previousWasSeparator = false;
                }
                else
                {
                    if (!previousWasSeparator)
                        builder.Append(' ');
                    previousWasSeparator = true;
                }
            }

            return builder.ToString().Trim();
        }

        private static List<ServerCatalogCatalogOption> ParseServerCatalogOptions(JsonElement manifestRoot, string desiredType)
        {
            var results = new List<ServerCatalogCatalogOption>();
            desiredType = (desiredType ?? "").Trim();
            if (string.IsNullOrWhiteSpace(desiredType))
                return results;

            if (!manifestRoot.TryGetProperty("catalogs", out var catalogsEl) || catalogsEl.ValueKind != JsonValueKind.Array)
                return results;

            foreach (var catalogEl in catalogsEl.EnumerateArray())
            {
                if (catalogEl.ValueKind != JsonValueKind.Object)
                    continue;
                if (!catalogEl.TryGetProperty("type", out var typeEl) || typeEl.ValueKind != JsonValueKind.String)
                    continue;

                var type = (typeEl.GetString() ?? "").Trim();
                if (!string.Equals(type, desiredType, StringComparison.OrdinalIgnoreCase))
                    continue;

                if (!catalogEl.TryGetProperty("id", out var idEl) || idEl.ValueKind != JsonValueKind.String)
                    continue;

                var id = (idEl.GetString() ?? "").Trim();
                if (string.IsNullOrWhiteSpace(id))
                    continue;

                var name = catalogEl.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String
                    ? (nameEl.GetString() ?? "").Trim()
                    : "";

                results.Add(new ServerCatalogCatalogOption
                {
                    Label = BuildServerCatalogLabel(id, name),
                    Value = id,
                    ContentType = desiredType,
                    RequestType = type
                });
            }

            if (results.Count == 0)
            {
                var manifestTypes = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                try
                {
                    if (manifestRoot.TryGetProperty("types", out var typesEl) && typesEl.ValueKind == JsonValueKind.Array)
                    {
                        foreach (var t in typesEl.EnumerateArray())
                        {
                            if (t.ValueKind != JsonValueKind.String) continue;
                            var v = (t.GetString() ?? "").Trim();
                            if (!string.IsNullOrWhiteSpace(v))
                                manifestTypes.Add(v);
                        }
                    }
                }
                catch
                {
                }

                if (manifestTypes.Contains(desiredType))
                {
                    foreach (var catalogEl in catalogsEl.EnumerateArray())
                    {
                        if (catalogEl.ValueKind != JsonValueKind.Object)
                            continue;

                        var rawType = catalogEl.TryGetProperty("type", out var tEl) && tEl.ValueKind == JsonValueKind.String
                            ? (tEl.GetString() ?? "").Trim()
                            : "";
                        if (string.IsNullOrWhiteSpace(rawType))
                            continue;

                        var id = catalogEl.TryGetProperty("id", out var idEl) && idEl.ValueKind == JsonValueKind.String
                            ? (idEl.GetString() ?? "").Trim()
                            : "";
                        if (string.IsNullOrWhiteSpace(id))
                            continue;

                        var name = catalogEl.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String
                            ? (nameEl.GetString() ?? "").Trim()
                            : "";

                        results.Add(new ServerCatalogCatalogOption
                        {
                            Label = BuildServerCatalogLabel(id, name),
                            Value = id,
                            ContentType = desiredType,
                            RequestType = rawType
                        });
                    }
                }
            }

            return results
                .GroupBy(option => option.Value, StringComparer.OrdinalIgnoreCase)
                .Select(group => group.OrderBy(option => option.Label, StringComparer.OrdinalIgnoreCase).First())
                .OrderBy(option =>
                {
                    if (string.Equals(option.Value, "top", StringComparison.OrdinalIgnoreCase)) return 0;
                    if (string.Equals(option.Value, "popular", StringComparison.OrdinalIgnoreCase)) return 1;
                    if (string.Equals(option.Value, "featured", StringComparison.OrdinalIgnoreCase)) return 2;
                    return 10;
                })
                .ThenBy(option => option.Label, StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static ServerCatalogCatalogOption? PickDefaultCatalogOption(List<ServerCatalogCatalogOption> options, string desiredType)
        {
            if (options == null || options.Count == 0)
                return null;

            desiredType = (desiredType ?? "").Trim().ToLowerInvariant();

            int Score(ServerCatalogCatalogOption o)
            {
                var id = (o?.Value ?? "").Trim().ToLowerInvariant();
                if (string.IsNullOrWhiteSpace(id)) return 1000;

                if (id == "top") return 0;
                if (id == "popular") return 1;
                if (id == "featured") return 2;
                if (desiredType == "movie" && (id == "movies" || id.Contains("movie"))) return 3;
                if (desiredType == "series" && (id == "series" || id.Contains("series") || id.Contains("tv"))) return 3;
                if (desiredType == "music" && (id == "music" || id.Contains("music"))) return 3;
                return 10;
            }

            return options
                .OrderBy(Score)
                .ThenBy(o => o.Label ?? "", StringComparer.OrdinalIgnoreCase)
                .FirstOrDefault();
        }

        private List<ServerCatalogCatalogOption> GetAvailableServerCatalogOptions(string contentType, string selection, bool aggregateAllServers)
        {
            var map = GetServerCatalogOptionsMap(contentType);
            lock (_stateLock)
            {
                if (aggregateAllServers)
                {
                    return map.Values
                        .SelectMany(list => list ?? Enumerable.Empty<ServerCatalogCatalogOption>())
                        .GroupBy(option => option.Value, StringComparer.OrdinalIgnoreCase)
                        .Select(group => group.OrderBy(option => option.Label, StringComparer.OrdinalIgnoreCase).First())
                        .OrderBy(option =>
                        {
                            if (string.Equals(option.Value, "top", StringComparison.OrdinalIgnoreCase)) return 0;
                            if (string.Equals(option.Value, "popular", StringComparison.OrdinalIgnoreCase)) return 1;
                            if (string.Equals(option.Value, "featured", StringComparison.OrdinalIgnoreCase)) return 2;
                            return 10;
                        })
                        .ThenBy(option => option.Label, StringComparer.OrdinalIgnoreCase)
                        .ToList();
                }

                if (map.TryGetValue(selection, out var list) && list != null)
                    return list.ToList();
            }

            return new List<ServerCatalogCatalogOption>();
        }

        private bool ServerSupportsCatalog(string baseUrl, string contentType, string catalogId)
        {
            var normalizedBaseUrl = NormalizeAddonServerUrl((baseUrl ?? "").Trim());
            if (string.IsNullOrWhiteSpace(normalizedBaseUrl))
                normalizedBaseUrl = (baseUrl ?? "").Trim();

            var options = GetAvailableServerCatalogOptions(contentType, normalizedBaseUrl, aggregateAllServers: false);
            if (options.Count == 0)
                return string.Equals(catalogId, "top", StringComparison.OrdinalIgnoreCase);

            return options.Any(option => string.Equals(option.Value, catalogId, StringComparison.OrdinalIgnoreCase));
        }

        private void ApplyCatalogSelectionToStates(Dictionary<string, ServerCatalogPageState> states, string contentType, string catalogId)
        {
            static bool ContainsAny(string? value, params string[] parts)
            {
                var v = (value ?? "").Trim().ToLowerInvariant();
                if (string.IsNullOrWhiteSpace(v)) return false;
                foreach (var p in parts)
                {
                    var pp = (p ?? "").Trim().ToLowerInvariant();
                    if (string.IsNullOrWhiteSpace(pp)) continue;
                    if (v.Contains(pp)) return true;
                }
                return false;
            }

            var keys = states.Keys.ToList();
            foreach (var key in keys)
            {
                var state = states[key];

                var requestedCatalogId = (catalogId ?? "").Trim();
                string requestType = (contentType ?? "").Trim();
                string chosenCatalogId = requestedCatalogId;
                try
                {
                    var normalizedBaseUrl = NormalizeAddonServerUrl((state.BaseUrl ?? "").Trim());
                    if (string.IsNullOrWhiteSpace(normalizedBaseUrl))
                        normalizedBaseUrl = (state.BaseUrl ?? "").Trim();

                    var options = GetAvailableServerCatalogOptions(contentType, normalizedBaseUrl, aggregateAllServers: false);

                    // Exact match when possible.
                    var opt = options.FirstOrDefault(o => string.Equals(o.Value, requestedCatalogId, StringComparison.OrdinalIgnoreCase));

                    // If this server doesn't have the selected catalogId (common in All Servers),
                    // fall back to a best-effort semantic match or the server's default.
                    if (opt == null && options.Count > 0)
                    {
                        if (ContainsAny(requestedCatalogId, "latest", "new", "recent", "release"))
                        {
                            opt = options.FirstOrDefault(o =>
                                ContainsAny(o.Value, "latest", "new", "recent", "release") ||
                                ContainsAny(o.Label, "latest", "new", "recent", "release"));
                        }
                        else if (ContainsAny(requestedCatalogId, "popular"))
                        {
                            opt = options.FirstOrDefault(o =>
                                ContainsAny(o.Value, "popular") || ContainsAny(o.Label, "popular"));
                        }
                        else if (ContainsAny(requestedCatalogId, "featured"))
                        {
                            opt = options.FirstOrDefault(o =>
                                ContainsAny(o.Value, "featured") || ContainsAny(o.Label, "featured"));
                        }
                        else if (ContainsAny(requestedCatalogId, "trending"))
                        {
                            opt = options.FirstOrDefault(o =>
                                ContainsAny(o.Value, "trending") || ContainsAny(o.Label, "trending"));
                        }
                        else if (ContainsAny(requestedCatalogId, "top"))
                        {
                            opt = options.FirstOrDefault(o =>
                                string.Equals((o.Value ?? "").Trim(), "top", StringComparison.OrdinalIgnoreCase) ||
                                ContainsAny(o.Label, "top"));
                        }

                        opt ??= PickDefaultCatalogOption(options, contentType);
                    }

                    if (opt != null)
                    {
                        if (!string.IsNullOrWhiteSpace(opt.Value))
                            chosenCatalogId = opt.Value.Trim();
                        if (!string.IsNullOrWhiteSpace(opt.RequestType))
                            requestType = opt.RequestType.Trim();
                    }
                }
                catch
                {
                    requestType = (contentType ?? "").Trim();
                    chosenCatalogId = requestedCatalogId;
                }

                states[key] = state with
                {
                    CatalogId = chosenCatalogId,
                    NextSkip = 0,
                    // Never hard-stop a server just because it doesn't expose the requested catalogId.
                    // We may have mapped to a different (best-effort) catalog above.
                    HasMore = true,
                    RequestType = string.IsNullOrWhiteSpace(requestType) ? (contentType ?? "").Trim() : requestType
                };
            }
        }

