        public string SelectedAddonServer
        {
            get => _selectedAddonServer;
            set
            {
                var incomingRaw = (value ?? "").Trim();
                string incoming;
                if (string.IsNullOrWhiteSpace(incomingRaw) || string.Equals(incomingRaw, AllServersOption, StringComparison.OrdinalIgnoreCase))
                {
                    incoming = AllServersOption;
                }
                else
                {
                    incoming = NormalizeAddonServerUrl(incomingRaw);
                    if (string.IsNullOrWhiteSpace(incoming))
                        incoming = AllServersOption;
                }

                if (SetProperty(ref _selectedAddonServer, incoming))
                {
                    try
                    {
                        if (string.Equals(incoming, AllServersOption, StringComparison.OrdinalIgnoreCase))
                        {
                            IntegrationKeyStore.SetProtected(AddonServerSelectedKey, "");
                        }
                        else
                        {
                            IntegrationKeyStore.SetProtected(AddonServerSelectedKey, incoming);
                        }
                    }
                    catch (Exception ex)
                    {
                        System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error saving AddonServerSelectedKey: {ex.Message}");
                    }
                    try
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            _serverCatalogCatalogs.Clear();
                            OnPropertyChanged(nameof(IsAllServersSelected));
                            OnPropertyChanged(nameof(HasServerCatalogCatalogs));
                            OnPropertyChanged(nameof(SelectedServerCatalogCatalogId));
                        });
                    }
                    catch
                    {
                    }
                    _ = RefreshServerCatalogAsync();
                }
            }
        }

        public bool IsAllServersSelected
        {
            get
            {
                var selection = (_selectedAddonServer ?? "").Trim();
                return string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
            }
        }

        public string SelectedServerCatalogType
        {
            get => _selectedServerCatalogType;
            set
            {
                if (SetProperty(ref _selectedServerCatalogType, string.IsNullOrWhiteSpace(value) ? "movie" : value))
                {
                    IsServerStreamsPanelOpen = false;
                    IsServerSeriesPanelOpen = false;
                    _serverStreamsBackToSeries = false;
                    ClearServerSeriesState(clearRoot: true);
                    OnPropertyChanged(nameof(IsServerCatalogMoviesSelected));
                    OnPropertyChanged(nameof(IsServerCatalogTvSelected));
                    OnPropertyChanged(nameof(IsServerCatalogMusicSelected));
                    OnPropertyChanged(nameof(SelectedServerCatalogCatalogId));
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    CommandManager.InvalidateRequerySuggested();
                    try
                    {
                        RefreshServerCatalogCatalogs();
                    }
                    catch
                    {
                    }
                    try
                    {
                        RefreshServerCatalogFilterOptions();
                    }
                    catch
                    {
                    }
                    try
                    {
                        RebuildServerCatalogVisibleItems();
                    }
                    catch
                    {
                    }
                    if (_serverMovieCatalogItems.Count == 0 && _serverTvCatalogItems.Count == 0 && _serverMusicCatalogItems.Count == 0)
                    {
                        _ = RefreshServerCatalogAsync();
                    }
                    else if (IsServerCatalogMusicSelected &&
                             _serverMusicCatalogItems.Count == 0 &&
                             _serverMusicPageStates.Count > 0 &&
                             string.IsNullOrWhiteSpace((ServerCatalogSearchQuery ?? "").Trim()))
                    {
                        _ = EnsureServerMusicCatalogLoadedAsync();
                    }
                }
            }
        }

        public ObservableCollection<ServerCatalogCatalogOption> ServerCatalogCatalogs => _serverCatalogCatalogs;

        public bool HasServerCatalogCatalogs => _serverCatalogCatalogs.Count > 0;

        public string SelectedServerCatalogCatalogId
        {
            get
            {
                if (IsServerCatalogTvSelected) return _selectedServerSeriesCatalogId;
                if (IsServerCatalogMusicSelected) return _selectedServerMusicCatalogId;
                return _selectedServerMovieCatalogId;
            }
            set
            {
                var incoming = (value ?? "").Trim();
                if (string.IsNullOrWhiteSpace(incoming)) return;

                var changed = false;
                if (IsServerCatalogTvSelected)
                {
                    if (!string.Equals(_selectedServerSeriesCatalogId, incoming, StringComparison.OrdinalIgnoreCase))
                    {
                        _selectedServerSeriesCatalogId = incoming;
                        changed = true;
                    }
                }
                else if (IsServerCatalogMusicSelected)
                {
                    if (!string.Equals(_selectedServerMusicCatalogId, incoming, StringComparison.OrdinalIgnoreCase))
                    {
                        _selectedServerMusicCatalogId = incoming;
                        changed = true;
                    }
                }
                else
                {
                    if (!string.Equals(_selectedServerMovieCatalogId, incoming, StringComparison.OrdinalIgnoreCase))
                    {
                        _selectedServerMovieCatalogId = incoming;
                        changed = true;
                    }
                }

                if (!changed) return;

                ApplySelectedServerCatalogToPageStates(incoming);
                OnPropertyChanged(nameof(SelectedServerCatalogCatalogId));
                _ = ReloadServerCatalogFromStatesAsync();
            }
        }

