        public bool ServerCatalogHasMore => CanLoadMoreServerCatalog;
        public bool CanLoadMoreServerCatalog => IsServersView && IsServerCatalogPanelOpen &&
                                               (((IsServerCatalogTvSelected
                                                       ? _serverTvVisibleCount < _serverTvCatalogItems.Count
                                                       : (IsServerCatalogMusicSelected
                                                           ? _serverMusicVisibleCount < _serverMusicCatalogItems.Count
                                                           : _serverMovieVisibleCount < _serverMovieCatalogItems.Count))) ||
                                                CanLoadNextServerCatalogPage);

        public bool CanLoadNextServerCatalogPage => IsServersView && IsServerCatalogPanelOpen &&
                                                    (IsServerCatalogTvSelected
                                                        ? _serverTvPageStates.Values.Any(s => s.HasMore)
                                                        : (IsServerCatalogMusicSelected
                                                            ? _serverMusicPageStates.Values.Any(s => s.HasMore)
                                                            : _serverMoviePageStates.Values.Any(s => s.HasMore)));

