        public MediaCentreViewModel(PlaybackService playbackService)
        {
            Instance = this;
            _uiDispatcher = Dispatcher.CurrentDispatcher;
            _playbackService = playbackService;
            _streamResolverOwn = AtlasStreamResolverFactory.CreateOwnResolver();
            _streamResolverServers = AtlasStreamResolverFactory.CreateServersResolver();
            _streamResolver = AtlasStreamResolverFactory.CreateDefaultResolver();
            try
            {
                var mode = IntegrationKeyStore.GetDecrypted(StreamsModeSelectedKey);
                _selectedStreamsMode = string.Equals(mode, "servers", StringComparison.OrdinalIgnoreCase) ? StreamsMode.Servers : StreamsMode.Own;
            }
            catch
            {
            }
            try
            {
                _ = LoadHomeShelvesAsync(CancellationToken.None);
            }
            catch
            {
            }
            try
            {
                LoadMediaAgentDraftsFromDisk();
            }
            catch
            {
            }
            _playbackService.CurrentMediaChanged += (_, media) =>
            {
                _uiDispatcher.Invoke(() =>
                {
                    foreach (var t in _allItems)
                    {
                        t.IsPlaying = false;
                        t.IsSelected = false;
                    }

                    var match = _allItems.FirstOrDefault(i => string.Equals(i.PlaybackItem?.FilePath, media.FilePath, StringComparison.OrdinalIgnoreCase));
                    if (match == null)
                        match = _allItems.FirstOrDefault(i => string.Equals(i.Title, media.DisplayName, StringComparison.OrdinalIgnoreCase));
                    if (match != null)
                    {
                        match.IsPlaying = true;
                        match.IsSelected = true;
                        try
                        {
                            var pending = _pendingWatchHistory;
                            var pendingKey = (pending?.Key ?? "").Trim();
                            var usePending = !string.IsNullOrWhiteSpace(pendingKey) && LooksLikeStableMediaIdToken(pendingKey);

                            var historyKey = usePending
                                ? pendingKey
                                : ComputeWatchHistoryKey(match, media.FilePath);

                            var historyTitle = !string.IsNullOrWhiteSpace(pending?.Title)
                                ? pending!.Title
                                : (match.Title ?? media.DisplayName ?? "");

                            var historyType = !string.IsNullOrWhiteSpace(pending?.Type)
                                ? pending!.Type
                                : (match.Type ?? "");

                            var coverUrl = !string.IsNullOrWhiteSpace(pending?.CoverUrl)
                                ? pending!.CoverUrl
                                : match.CoverUrl;

                            var backdropUrl = !string.IsNullOrWhiteSpace(pending?.BackdropUrl)
                                ? pending!.BackdropUrl
                                : match.BackdropUrl;

                            AtlasAI.Core.WatchHistoryStore.AddOrUpdate(historyKey, historyTitle, historyType, coverUrl, backdropUrl);
                            _nowPlayingWatchHistoryKey = historyKey;
                            _pendingWatchHistory = null;
                            RefreshHomeContinue();
                        }
                        catch
                        {
                        }
                    }
                    else
                    {
                        try
                        {
                            var computedTitle = BuildNowPlayingTitle(media.DisplayName ?? "", "");
                            var pending = _pendingWatchHistory;
                            _pendingWatchHistory = null;

                            var historyKey = !string.IsNullOrWhiteSpace(pending?.Key)
                                ? (pending!.Key ?? "").Trim()
                                : (media.FilePath ?? "").Trim();
                            var historyTitle = !string.IsNullOrWhiteSpace(pending?.Title)
                                ? pending!.Title
                                : computedTitle;
                            var historyType = !string.IsNullOrWhiteSpace(pending?.Type)
                                ? pending!.Type
                                : (NowPlayingTypeId ?? "");

                            AtlasAI.Core.WatchHistoryStore.AddOrUpdate(
                                historyKey,
                                historyTitle,
                                historyType,
                                pending?.CoverUrl,
                                pending?.BackdropUrl);
                            _nowPlayingWatchHistoryKey = historyKey;
                            RefreshHomeContinue();
                        }
                        catch
                        {
                        }
                    }

                    NowPlayingTitle = BuildNowPlayingTitle(media.DisplayName ?? "", match?.Title ?? "");
                    NowPlayingArtist = media.Artist ?? "";
                    NowPlayingAlbum = media.Album ?? "";
                    var section = (media.SectionName ?? "").Trim();
                    if (match != null && !string.IsNullOrWhiteSpace(match.Type))
                        NowPlayingTypeId = match.Type;
                    else if (!string.IsNullOrWhiteSpace(section))
                        NowPlayingTypeId = section.Equals("Karaoke", StringComparison.OrdinalIgnoreCase) ? "karaoke" : section.ToLowerInvariant();
                    else
                        NowPlayingTypeId = "";
                    if (match != null)
                    {
                        NowPlayingCoverImage = match.CoverImage
                            ?? (string.Equals(match.Type, "music", StringComparison.OrdinalIgnoreCase)
                                ? LoadMusicCoverForTrack(match.FilePath)
                                : BuildCoverForType(match.Type, match.FilePath, match.Album ?? "", match.TrackNumber));
                    }
                    TotalSeconds = media.Duration?.TotalSeconds ?? 0;
                    ProgressSeconds = 0;
                    IsPlaying = true;
                    StatusText = "Playing";
                    OnPropertyChanged(nameof(NowPlayingTitle));
                    OnPropertyChanged(nameof(NowPlayingArtist));
                    OnPropertyChanged(nameof(NowPlayingAlbum));
                    OnPropertyChanged(nameof(NowPlayingTypeId));
                    OnPropertyChanged(nameof(IsNowPlayingMusic));
                });

                try
                {
                    FlushPendingTagWrites(media.FilePath ?? "");
                }
                catch
                {
                }

                try
                {
                    FlushPendingRemovals(media.FilePath ?? "");
                }
                catch
                {
                }
            };

            try
            {
                var orchestrator = VoiceSystemOrchestrator.Instance;
                orchestrator.ListeningStarted += (_, _) =>
                {
                    _uiDispatcher.BeginInvoke(() =>
                    {
                        try
                        {
                            IsMediaAiRecording = IsChatVisible;
                        }
                        catch
                        {
                        }
                    });
                };
                orchestrator.ListeningStopped += (_, _) =>
                {
                    _uiDispatcher.BeginInvoke(() =>
                    {
                        try
                        {
                            IsMediaAiRecording = false;
                        }
                        catch
                        {
                        }
                    });
                };
            }
            catch
            {
            }

            ToggleLibraryCommand = new RelayCommand(() => IsLibraryOpen = true);
            CloseLibraryCommand = new RelayCommand(() => IsLibraryOpen = false);
            SelectCategoryCommand = new RelayCommand<MediaCategory>(SelectCategory);
            OpenServersViewCommand = new RelayCommand(() =>
            {
                var target = Categories.FirstOrDefault(c => string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase));
                if (target != null)
                    SelectCategory(target);
            });
            BackFromServersCommand = new RelayCommand(() =>
            {
                var target = _lastNonServersCategory
                             ?? Categories.FirstOrDefault(c => string.Equals(c.Id, "movies", StringComparison.OrdinalIgnoreCase))
                             ?? Categories.FirstOrDefault();
                if (target != null)
                    SelectCategory(target);
            });
            ScanSelectedCategoryCommand = new RelayCommand(ScanSelectedCategory, () => !IsScanning);
            ScanCategoryCommand = new RelayCommand<MediaCategory>(ScanCategory, _ => !IsScanning);
            CleanRadioStationsCommand = new RelayCommand(() => _ = CleanRadioStationsAsync(), () => !IsScanning);
            TogglePlayPauseCommand = new RelayCommand(TogglePlayPause);
            StopCommand = new RelayCommand(StopPlayback);
            PreviousCommand = new RelayCommand(() => _playbackService.PlayPrevious());
            NextCommand = new RelayCommand(() => _playbackService.PlayNext());
            ToggleShuffleCommand = new RelayCommand(() => ShuffleEnabled = !ShuffleEnabled);
            ToggleRepeatCommand = new RelayCommand(() => RepeatEnabled = !RepeatEnabled);
            ToggleNowPlayingFavoriteCommand = new RelayCommand(() => NowPlayingFavorite = !NowPlayingFavorite);
            PlayItemCommand = new RelayCommand<MediaItem>(PlayItem);
            OpenItemCommand = new RelayCommand<MediaItem>(OpenItem);
            SelectPreviewItemCommand = new RelayCommand<MediaItem>(OnPreviewItemClicked);
            ClosePreviewCommand = new RelayCommand(ClosePreview, () => PreviewItem != null);
            CloseDetailsCommand = new RelayCommand(CloseDetails, () => IsDetailsOpen);
            OpenDetailsStreamsCommand = new RelayCommand(OpenDetailsStreams, () => DetailsItem != null);
            PlayDetailsTrailerCommand = new RelayCommand(OpenDetailsTrailer, () => DetailsItem != null);
            PlayPreviewTrailerCommand = new RelayCommand(() => _ = OpenPreviewTrailerAsync(), () => PreviewItem != null);
            ToggleItemFavoriteCommand = new RelayCommand<MediaItem>(ToggleItemFavorite);
            SelectAlbumCommand = new RelayCommand<AlbumEntry>(SelectAlbum);
            BackToAlbumsCommand = new RelayCommand(() => SelectedAlbum = null);
            AddToQueueCommand = new RelayCommand<MediaItem>(AddToQueue);
            QueueNextCommand = new RelayCommand<MediaItem>(QueueNext);
            OpenItemFolderCommand = new RelayCommand<MediaItem>(OpenItemFolder);
            RemoveFromLibraryCommand = new RelayCommand<MediaItem>(RemoveFromLibrary);
            ShowItemInfoCommand = new RelayCommand<MediaItem>(ShowItemInfo);
            OptimizeAlbumCommand = new RelayCommand<AlbumEntry>(OptimizeAlbum);
            OpenAlbumFolderCommand = new RelayCommand<AlbumEntry>(OpenAlbumFolder);
            EditAlbumInfoCommand = new RelayCommand<AlbumEntry>(EditAlbumInfo);
            EditTrackInfoCommand = new RelayCommand<MediaItem>(EditTrackInfo);
            SetCoverCommand = new RelayCommand<MediaItem>(SetCustomCover);
            RemoveAlbumCommand = new RelayCommand<AlbumEntry>(RemoveAlbum);
            FixMusicAlbumsCommand = new RelayCommand(FixMusicAlbums);
            PlayAllMusicCommand = new RelayCommand(PlayAllMusic);
            AutoOrganizeMusicCommand = new RelayCommand(AutoOrganizeMusic, () => !IsScanning);
            UndoLastChangeCommand = new RelayCommand(UndoLastChange, () => _undoStack.Count > 0 && !IsScanning);
            ClearCategoryCommand = new RelayCommand(ClearSelectedCategory, () => !IsScanning);
            ToggleChatCommand = new RelayCommand(() => IsChatVisible = !IsChatVisible);
            ToggleMediaAiRecordingCommand = new RelayCommand(() =>
            {
                try
                {
                    var orchestrator = VoiceSystemOrchestrator.Instance;
                    if (orchestrator.IsListening)
                        orchestrator.StopListening();
                    else
                        orchestrator.BeginListening(ListeningSource.PushToTalk);
                }
                catch
                {
                }
            });
            SearchMediaCommand = new RelayCommand(SearchMedia);
            ImportCsvMp3Command = new RelayCommand(ImportCsvMp3, () => IsDownloadsView && !IsScanning);
            SelectDownloadsFolderCommand = new RelayCommand(() => EnsureMediaDownloadsFolderSelected(forcePrompt: true), () => !IsScanning);
            OpenDownloadsFolderCommand = new RelayCommand(OpenDownloadsFolder, () => HasMediaDownloadsFolder && !IsScanning);
            AddDownloadJobCommand = new RelayCommand(AddDownloadJob, CanAddDownloadJob);
            CancelDownloadJobCommand = new RelayCommand<DownloadJob>(CancelDownloadJob, j => j != null);
            ClearCompletedDownloadJobsCommand = new RelayCommand(ClearCompletedDownloadJobs, () => DownloadJobs.Any(j => j != null && !j.IsRunning));
            ExportDownloadJobsCsvCommand = new RelayCommand(ExportDownloadJobsCsv, () => DownloadJobs.Any(j => j != null));
            AddAppsBookmarkCommand = new RelayCommand(AddAppsBookmark, CanAddAppsBookmark);
            RemoveAppsBookmarkCommand = new RelayCommand<AppsBookmarkEntry>(RemoveAppsBookmark);
            OpenAppsBookmarkCommand = new RelayCommand<AppsBookmarkEntry>(OpenAppsBookmark);
            OpenAppsServiceCommand = new RelayCommand<AppsServiceEntry>(OpenAppsService);
            SaveAppsCredentialCommand = new RelayCommand(SaveAppsCredential, CanSaveAppsCredential);
            ClearAppsCredentialCommand = new RelayCommand(ClearAppsCredential, CanClearAppsCredential);
            SaveSpotifyClientIdCommand = new RelayCommand(SaveSpotifyClientId, CanSaveSpotifyClientId);
            AuthorizeSpotifyCommand = new RelayCommand(AuthorizeSpotify, CanAuthorizeSpotify);
            SaveTraktClientIdCommand = new RelayCommand(SaveTraktClientId, CanSaveTraktClientId);
            SaveTraktTokenCommand = new RelayCommand(SaveTraktToken, CanSaveTraktToken);
            SaveTraktClientSecretCommand = new RelayCommand(SaveTraktClientSecret, CanSaveTraktClientSecret);
            SendMediaAiCommand = new RelayCommand(SendMediaAi);
            CancelMediaAiCommand = new RelayCommand(CancelMediaAi, () => _mediaAiCts != null);
            RunMediaAgentQuickActionCommand = new RelayCommand<string>(RunMediaAgentQuickAction);
            MediaResultCopyTitleCommand = new RelayCommand<MediaAgentResultItem>(item =>
            {
                if (item == null) return;
                var text = string.IsNullOrWhiteSpace(item.ArtistName) ? item.Title : item.ArtistName;
                if (!string.IsNullOrWhiteSpace(text))
                    System.Windows.Clipboard.SetText(text);
            });
            MediaResultSearchLocalCommand = new RelayCommand<MediaAgentResultItem>(item =>
            {
                if (item == null) return;
                var query = string.IsNullOrWhiteSpace(item.ArtistName) ? item.Title : item.ArtistName;
                if (!string.IsNullOrWhiteSpace(query))
