        private void OpenItem(MediaItem? item)
        {
            if (item == null) return;
            var type = item.Type ?? "";
            if (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(type, "movie", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(type, "series", StringComparison.OrdinalIgnoreCase))
            {
                // If this item is a local file, treat Open as "play" (users expect double-click to play).
                var localCandidate = (item.PlaybackItem?.FilePath ?? item.FilePath) ?? "";
                try
                {
                    if (!string.IsNullOrWhiteSpace(localCandidate) && File.Exists(localCandidate))
                    {
                        PlayVideoLibraryItem(item);
                        return;
                    }
                }
                catch
                {
                }

                try
                {
                    SetPreviewItem(item);
                }
                catch
                {
                }
                DetailsItem = item;
                DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "Loading metadata..." : item.Metadata;
                try
                {
                    _detailsMetaCts?.Cancel();
                    _detailsMetaCts?.Dispose();
                }
                catch
                {
                }
                _detailsMetaCts = new CancellationTokenSource();
                _ = LoadDetailsMetaAsync(item, _detailsMetaCts.Token);
                IsDetailsOpen = true;
                _streamsTargetItem = item;
                StreamsSearchQuery = "";
                RefreshAddonServers();
                var isLocalFile = false;
                try
                {
                    isLocalFile = !string.IsNullOrWhiteSpace(localCandidate) && File.Exists(localCandidate);
                }
                catch
                {
                    isLocalFile = false;
                }

                var desiredMode = SelectedStreamsMode;
                if (IsServersView)
                    desiredMode = StreamsMode.Servers;
                else if (string.Equals(type, "cloud", StringComparison.OrdinalIgnoreCase))
                    desiredMode = StreamsMode.Own;
                else if (HasAddonServers)
                    desiredMode = StreamsMode.Servers;
                else if (isLocalFile)
                    desiredMode = StreamsMode.Own;
                else
                    desiredMode = StreamsMode.Own;

                if (SelectedStreamsMode != desiredMode)
                    SelectedStreamsMode = desiredMode;
                RefreshStreamsForCurrentItem();
                CommandManager.InvalidateRequerySuggested();
                return;
            }

            if (IsServersView && string.Equals(type, "music", StringComparison.OrdinalIgnoreCase))
            {
                _ = PlayServersMusicAsync(item);
                return;
            }

            PlayItem(item);
        }

        private void PlayVideoLibraryItem(MediaItem item)
        {
            var playbackItem = ResolvePlaybackItem(item);

            foreach (var libraryItem in LibraryItems)
            {
                libraryItem.IsSelected = ReferenceEquals(libraryItem, item);
                libraryItem.IsPlaying = false;
            }

            item.IsSelected = true;
            item.IsPlaying = true;

            if (playbackItem != null)
            {
                NowPlayingCoverImage = item.CoverImage
                    ?? BuildCoverForType(item.Type, item.FilePath, item.Album ?? "", item.TrackNumber);
                _playbackService.PlaySingle(playbackItem);
            }

            NowPlayingTitle = item.Title;
            NowPlayingArtist = item.Artist;
            NowPlayingAlbum = item.Album;
            NowPlayingTypeId = item.Type ?? "";
            TotalSeconds = item.Duration.TotalSeconds;
            ProgressSeconds = 0;
            IsPlaying = playbackItem != null;
            StatusText = playbackItem != null ? "Playing" : "Ready";

            OnPropertyChanged(nameof(NowPlayingTitle));
            OnPropertyChanged(nameof(NowPlayingArtist));
            OnPropertyChanged(nameof(NowPlayingAlbum));
            OnPropertyChanged(nameof(NowPlayingTypeId));
            OnPropertyChanged(nameof(IsNowPlayingMusic));
            OnPropertyChanged(nameof(TrendingValue));
            OnPropertyChanged(nameof(VisibleCountText));
        }

        private ScannerMediaItem? ResolvePlaybackItem(MediaItem item)
        {
            if (item.PlaybackItem != null)
                return item.PlaybackItem;

            var sourcePath = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(sourcePath))
                return null;

            var type = (item.Type ?? "").Trim();
            if (string.Equals(type, "games", StringComparison.OrdinalIgnoreCase))
                return null;

            var isHttp = IsHttpUrl(sourcePath, out var uri);
            var isLocalFile = false;
            try
            {
                isLocalFile = !isHttp && File.Exists(sourcePath);
            }
            catch
            {
                isLocalFile = false;
            }

            if (!isLocalFile && !isHttp)
                return null;

            var extension = isHttp
                ? Path.GetExtension(uri.AbsolutePath).ToLowerInvariant()
                : Path.GetExtension(sourcePath).ToLowerInvariant();

            var mediaType = GuessMediaTypeForCategory(type, extension);
            if (mediaType == ScannerMediaType.Unknown)
            {
                if (AudioExtensions.Contains(extension)) mediaType = ScannerMediaType.Audio;
                else if (VideoExtensions.Contains(extension)) mediaType = ScannerMediaType.Video;
                else if (ImageExtensions.Contains(extension)) mediaType = ScannerMediaType.Image;
            }

            var displayName = (item.Title ?? "").Trim();
            if (string.IsNullOrWhiteSpace(displayName))
            {
                displayName = isHttp
                    ? Path.GetFileNameWithoutExtension(uri.AbsolutePath) ?? "Media"
                    : Path.GetFileNameWithoutExtension(sourcePath) ?? "Media";
            }

            return new ScannerMediaItem
            {
                FilePath = sourcePath,
                DisplayName = displayName,
                Extension = extension,
                FileSize = 0,
                LastModified = DateTime.UtcNow,
                MediaType = mediaType,
                SectionName = type,
                FolderPath = isHttp ? string.Empty : (Path.GetDirectoryName(sourcePath) ?? string.Empty),
                DateAdded = DateTime.UtcNow,
                Album = item.Album,
                Artist = item.Artist,
                TrackNumber = item.TrackNumber == 0 ? null : item.TrackNumber,
                Duration = item.Duration > TimeSpan.Zero ? item.Duration : null,
                Title = displayName,
            };
        }

        private async Task PlayServersMusicAsync(MediaItem item)
        {
            if (item == null) return;

            try
            {
                if (item.PlaybackItem != null && !string.IsNullOrWhiteSpace(item.PlaybackItem.FilePath))
                {
                    try
                    {
                        if (File.Exists(item.PlaybackItem.FilePath))
                        {
                            _uiDispatcher.Invoke(() => PlayItem(item));
                            return;
                        }
                    }
                    catch
                    {
                    }
                }
            }
            catch
            {
            }

            try
            {
                if (IsHttpUrl(item.FilePath, out var uri) &&
                    uri.Host.Contains("soundcloud.com", StringComparison.OrdinalIgnoreCase))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        var apps = Categories.FirstOrDefault(c => string.Equals(c.Id, "apps", StringComparison.OrdinalIgnoreCase));
                        if (apps != null)
                            SelectCategory(apps);
                        _appsNavigator?.Invoke(item.FilePath);
                    });
                    return;
                }
            }
            catch
            {
            }

            var query = (item.Title ?? "").Trim();
            if (string.IsNullOrWhiteSpace(query))
                query = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(query))
                return;

            _uiDispatcher.Invoke(() =>
            {
                StatusText = "Resolving music...";
                OnPropertyChanged(nameof(StatusText));
            });

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(6));
                var ct = cts.Token;

                var url = $"https://itunes.apple.com/search?term={Uri.EscapeDataString(query)}&entity=song&limit=1";
                using var resp = await ServerHttp.GetAsync(url, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode)
                    throw new Exception("iTunes lookup failed");

                await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                    !doc.RootElement.TryGetProperty("results", out var resultsEl) ||
                    resultsEl.ValueKind != JsonValueKind.Array ||
                    resultsEl.GetArrayLength() == 0)
                    throw new Exception("No music preview found");

                var first = resultsEl.EnumerateArray().FirstOrDefault();
                if (first.ValueKind != JsonValueKind.Object)
                    throw new Exception("No music preview found");

                var previewUrl = first.TryGetProperty("previewUrl", out var pEl) && pEl.ValueKind == JsonValueKind.String ? (pEl.GetString() ?? "").Trim() : "";
                if (string.IsNullOrWhiteSpace(previewUrl))
                    throw new Exception("No playable preview URL");

                var trackName = first.TryGetProperty("trackName", out var tnEl) && tnEl.ValueKind == JsonValueKind.String ? (tnEl.GetString() ?? "").Trim() : "";
                var artistName = first.TryGetProperty("artistName", out var anEl) && anEl.ValueKind == JsonValueKind.String ? (anEl.GetString() ?? "").Trim() : "";
                var albumName = first.TryGetProperty("collectionName", out var cnEl) && cnEl.ValueKind == JsonValueKind.String ? (cnEl.GetString() ?? "").Trim() : "";
                var artwork = first.TryGetProperty("artworkUrl100", out var artEl) && artEl.ValueKind == JsonValueKind.String ? (artEl.GetString() ?? "").Trim() : "";
                var ms = first.TryGetProperty("trackTimeMillis", out var msEl) && msEl.TryGetInt64(out var mv) ? mv : 0;

                var display = string.IsNullOrWhiteSpace(trackName)
                    ? (string.IsNullOrWhiteSpace(artistName) ? query : artistName)
                    : (string.IsNullOrWhiteSpace(artistName) ? trackName : $"{trackName} · {artistName}");

                _uiDispatcher.Invoke(() =>
                {
                    if (!string.IsNullOrWhiteSpace(trackName))
                        item.Title = trackName;
                    if (!string.IsNullOrWhiteSpace(artwork))
                        item.CoverUrl = artwork;
                    if (ms > 0)
                        item.Metadata = $"{TimeSpan.FromMilliseconds(ms).Minutes}:{TimeSpan.FromMilliseconds(ms).Seconds:00} preview";
                    PlayStreamUrl(previewUrl, display);
                    NowPlayingArtist = artistName;
                    NowPlayingAlbum = albumName;
                    OnPropertyChanged(nameof(NowPlayingArtist));
                    OnPropertyChanged(nameof(NowPlayingAlbum));
                });
            }
            catch (Exception ex)
            {
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = string.IsNullOrWhiteSpace(ex.Message) ? "Failed to play" : ex.Message;
                    OnPropertyChanged(nameof(StatusText));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private static string ComputeWatchHistoryKey(MediaItem item, string? currentPlaybackFilePath)
        {
            try
            {
                if (item == null) return "";

                static string ExtractMetaToken(string raw)
                {
                    var fp = (raw ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(fp)) return "";

                    // If it's a canonical media id (tt..., tmdb:..., etc.), ensure we don't include episode/extra tokens.
                    var token = fp.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries).FirstOrDefault() ?? fp;
                    token = (token ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(token)) return "";

                    if (LooksLikeStableMediaIdToken(token))
                        return token;

                    return "";
                }

                var metaId = ExtractMetaToken(item.MetaId ?? "");
                if (!string.IsNullOrWhiteSpace(metaId)) return metaId;

                var fromFilePath = ExtractMetaToken(item.FilePath ?? "");
                if (!string.IsNullOrWhiteSpace(fromFilePath)) return fromFilePath;

                var playback = (item.PlaybackItem?.FilePath ?? currentPlaybackFilePath ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(playback)) return playback;

                var fallback = (item.FilePath ?? "").Trim();
                return fallback;
            }
            catch
            {
                return (item?.FilePath ?? "").Trim();
            }
        }

        private void CloseDetails()
        {
            IsDetailsOpen = false;
            DetailsItem = null;
            DetailsOverview = "";
            try
            {
                _detailsMetaCts?.Cancel();
                _detailsMetaCts?.Dispose();
            }
            catch
            {
            }
            _detailsMetaCts = null;
            _streamsTargetItem = null;
            CommandManager.InvalidateRequerySuggested();
        }

        private void ClosePreview()
        {
            try
            {
                if (PreviewItem != null)
                    PreviewItem.IsSelected = false;
            }
            catch
            {
            }

            PreviewItem = null;
            OnPropertyChanged(nameof(HasPreviewItem));
            PreviewOverview = "";
            PreviewRuntimeText = "";
            try { _previewCast.Clear(); } catch { }

            try
            {
                _previewMetaCts?.Cancel();
                _previewMetaCts?.Dispose();
            }
            catch
            {
            }
            _previewMetaCts = null;

            CommandManager.InvalidateRequerySuggested();
        }

        private static int? TryExtractTmdbIdFromMediaItem(MediaItem item)
        {
            if (item.TmdbId.HasValue && item.TmdbId.Value > 0)
                return item.TmdbId.Value;

            var raw = ((item.MetaId ?? item.ImdbId ?? item.FilePath) ?? "").Trim();
            if (string.IsNullOrWhiteSpace(raw))
                return null;

            var match = System.Text.RegularExpressions.Regex.Match(raw, @"(?i)\btmdb:(?:movie:|tv:|series:)?(\d+)\b");
            if (!match.Success)
                return null;

            return int.TryParse(match.Groups[1].Value, out var tmdbId) && tmdbId > 0 ? tmdbId : null;
        }

        private async Task<bool> TryApplyTmdbMetadataFallbackAsync(MediaItem item, string contentType, bool forPreview, CancellationToken ct)
        {
            var tmdbKey = (IntegrationKeyStore.GetDecrypted("tmdb") ?? "").Trim();
            if (string.IsNullOrWhiteSpace(tmdbKey))
                return false;

            var tmdbId = TryExtractTmdbIdFromMediaItem(item);
            if (!tmdbId.HasValue || tmdbId.Value <= 0)
                return false;

            try
            {
                string overview = "";
                string posterUrl = "";
                string backdropUrl = "";
                string title = "";
                string runtimeText = "";
                int runtimeMinutes = 0;
                double rating = 0;
                DateTime? releaseDate = null;
                List<string> genres = new();
                List<string> cast = new();
                List<string> directors = new();

                if (string.Equals(contentType, "series", StringComparison.OrdinalIgnoreCase))
                {
                    var details = await _tmdbClient.GetTvDetailsAsync(tmdbKey, tmdbId.Value, ct).ConfigureAwait(false);
                    if (details == null)
                        return false;

                    title = (details.Name ?? "").Trim();
                    overview = (details.Overview ?? "").Trim();
                    posterUrl = TmdbClient.BuildPosterUrl(details.PosterPath);
                    backdropUrl = TmdbClient.BuildBackdropUrl(details.BackdropPath);
                    runtimeMinutes = details.EpisodeRuntimeMinutes;
                    runtimeText = runtimeMinutes > 0 ? $"{runtimeMinutes} min" : "";
                    rating = details.VoteAverage;
                    releaseDate = details.FirstAirDate;
                    genres = details.Genres.Where(g => !string.IsNullOrWhiteSpace(g)).Distinct(StringComparer.OrdinalIgnoreCase).ToList();

                    var credits = await _tmdbClient.GetTvCreditsAsync(tmdbKey, tmdbId.Value, ct).ConfigureAwait(false);
                    if (credits != null)
                    {
                        cast = credits.Cast.Where(c => !string.IsNullOrWhiteSpace(c)).Distinct(StringComparer.OrdinalIgnoreCase).Take(8).ToList();
                        directors = credits.Directors.Where(d => !string.IsNullOrWhiteSpace(d)).Distinct(StringComparer.OrdinalIgnoreCase).Take(3).ToList();
                    }
                }
                else
                {
                    var details = await _tmdbClient.GetMovieDetailsAsync(tmdbKey, tmdbId.Value, ct).ConfigureAwait(false);
                    if (details == null)
                        return false;

                    title = (details.Title ?? "").Trim();
                    overview = (details.Overview ?? "").Trim();
                    posterUrl = TmdbClient.BuildPosterUrl(details.PosterPath);
                    backdropUrl = TmdbClient.BuildBackdropUrl(details.BackdropPath);
                    runtimeMinutes = details.RuntimeMinutes;
                    runtimeText = runtimeMinutes > 0 ? $"{runtimeMinutes} min" : "";
                    rating = details.VoteAverage;
                    releaseDate = details.ReleaseDate;
                    genres = details.Genres.Where(g => !string.IsNullOrWhiteSpace(g)).Distinct(StringComparer.OrdinalIgnoreCase).ToList();

                    var credits = await _tmdbClient.GetMovieCreditsAsync(tmdbKey, tmdbId.Value, ct).ConfigureAwait(false);
                    if (credits != null)
                    {
                        cast = credits.Cast.Where(c => !string.IsNullOrWhiteSpace(c)).Distinct(StringComparer.OrdinalIgnoreCase).Take(8).ToList();
                        directors = credits.Directors.Where(d => !string.IsNullOrWhiteSpace(d)).Distinct(StringComparer.OrdinalIgnoreCase).Take(3).ToList();
                    }
                }

                var hasUsefulData = !string.IsNullOrWhiteSpace(overview) || !string.IsNullOrWhiteSpace(posterUrl) || !string.IsNullOrWhiteSpace(backdropUrl) || cast.Count > 0 || genres.Count > 0;
                if (!hasUsefulData)
                    return false;

                _uiDispatcher.Invoke(() =>
                {
                    if (ct.IsCancellationRequested)
                        return;

                    if (forPreview)
                    {
                        if (!ReferenceEquals(PreviewItem, item))
                            return;
                    }
                    else
                    {
                        if (!ReferenceEquals(DetailsItem, item))
                            return;
                    }

                    if (!string.IsNullOrWhiteSpace(title) && string.IsNullOrWhiteSpace(item.Title))
                        item.Title = title;
                    if (!string.IsNullOrWhiteSpace(overview))
                    {
                        item.Overview = overview;
                        item.Metadata = overview;
                        if (forPreview)
                            PreviewOverview = overview;
                        else
                            DetailsOverview = overview;
                    }

                    if (!string.IsNullOrWhiteSpace(posterUrl) && string.IsNullOrWhiteSpace(item.CoverUrl))
                        item.CoverUrl = posterUrl;
                    if (!string.IsNullOrWhiteSpace(backdropUrl) && string.IsNullOrWhiteSpace(item.BackdropUrl))
                        item.BackdropUrl = backdropUrl;
                    if (runtimeMinutes > 0)
                        item.RuntimeMinutes = runtimeMinutes;
                    if (rating > 0 && item.Rating <= 0)
                        item.Rating = rating;
                    if (releaseDate.HasValue && !item.ReleaseDate.HasValue)
                        item.ReleaseDate = releaseDate;
                    if ((item.Year <= 0) && releaseDate.HasValue)
                        item.Year = releaseDate.Value.Year;
                    if (genres.Count > 0)
                        item.Genres = genres;

                    if (forPreview)
                    {
                        if (!string.IsNullOrWhiteSpace(runtimeText))
                            PreviewRuntimeText = runtimeText;
                        _previewCast.Clear();
                        foreach (var castMember in cast)
                            _previewCast.Add(castMember);
                        OnPropertyChanged(nameof(PreviewItem));
                    }
                    else
                    {
                        OnPropertyChanged(nameof(DetailsItem));
                    }
                });

                if (!string.IsNullOrWhiteSpace(item.CoverUrl) && item.CoverImage == null)
                    _ = TryLoadCoverIntoItemAsync(item, CancellationToken.None);

                return true;
            }
            catch
            {
                return false;
            }
        }

        private async Task LoadDetailsMetaAsync(MediaItem item, CancellationToken ct)
        {
            try
            {
                static string NormalizePosterToken(string url)
                {
                    var s = (url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(s)) return s;
                    if (s.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || s.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                        return s;
                    if ((s.StartsWith("t", StringComparison.OrdinalIgnoreCase) || s.StartsWith("T", StringComparison.OrdinalIgnoreCase)) && s.Contains("-"))
                        return $"https://cinemeta.ratingposterdb.com/poster/{s}";
                    return s;
                }

                var type = (item.Type ?? "").Trim().ToLowerInvariant();
                    var contentType = type.Contains("tv") || type.Contains("series") ? "series" : "movie";
                    if (DisableMoviesTvExternalMeta && (type == "movies" || type == "tv" || contentType == "movie" || contentType == "series"))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (ReferenceEquals(DetailsItem, item))
                            DetailsOverview = "";
                    });
                    return;
                }

                var localPath = (item.PlaybackItem?.FilePath ?? item.FilePath ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(localPath) && LooksLikeHomeVideo(localPath))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ReferenceEquals(DetailsItem, item))
                            DetailsOverview = "";
                    });
                    return;
                }

                var rawId = ((item.MetaId ?? item.ImdbId ?? item.FilePath) ?? "").Trim();
                var imdbId = rawId;
                var contentId = rawId;

                var rawTitle = (item.Title ?? "").Trim();
                if (string.IsNullOrWhiteSpace(rawTitle))
                {
                    try
                    {
                        var fp = (item.FilePath ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(fp) && fp.Contains("\\"))
                            rawTitle = Path.GetFileNameWithoutExtension(fp) ?? "";
                    }
                    catch
                    {
                    }
                }

                var year = item.Year > 0 ? item.Year : 0;
                if (year <= 0 && !string.IsNullOrWhiteSpace(localPath) && TryExtractYearFromPath(localPath, out var yFromPath))
                    year = yFromPath;

                if (!string.IsNullOrWhiteSpace(localPath) && !LooksLikeHomeVideo(localPath))
                {
                    var cleaned = CleanVideoTitleFromFileName(localPath, out var y2);
                    if (!string.IsNullOrWhiteSpace(cleaned) && cleaned.Length >= 2)
                        rawTitle = cleaned;
                    if (year <= 0 && y2 > 0)
                        year = y2;
                }
                var lookupTitle = CleanLookupTitleForMeta(rawTitle, out var extractedYear);
                if (year <= 0)
                    year = extractedYear;

                if (!imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                {
                    if (UseTmdbResolve)
                    {
                        try
                        {
                            var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
                            if (!string.IsNullOrWhiteSpace(tmdbKey))
                            {
                                var preferTv = string.Equals(contentType, "series", StringComparison.OrdinalIgnoreCase);
                                var (resolvedImdb, resolvedType) = await _tmdbClient.TryResolveImdbIdAsync(tmdbKey, year > 0 ? $"{lookupTitle} {year}" : lookupTitle, preferTv, ct).ConfigureAwait(false);
                                if (!string.IsNullOrWhiteSpace(resolvedImdb) && resolvedImdb.StartsWith("tt", StringComparison.OrdinalIgnoreCase) &&
                                    !string.IsNullOrWhiteSpace(resolvedType))
                                {
                                    imdbId = resolvedImdb;
                                    contentType = resolvedType!;
                                }
                            }
                        }
                        catch
                        {
                        }
                    }

                    if (!imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase) && UseCinemetaFallback)
                        imdbId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false) ?? "";
                }

                if (ct.IsCancellationRequested) return;

                if (imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                    contentId = imdbId;
                else if (rawId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    contentId = rawId;
                else if (!string.IsNullOrWhiteSpace(imdbId))
                    contentId = imdbId;

                if (((item.TmdbId ?? 0) > 0 || rawId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase)) &&
                    await TryApplyTmdbMetadataFallbackAsync(item, contentType, false, ct).ConfigureAwait(false))
                    return;

                // RPDB Integration - try first; if it yields useful metadata, stop here
                var rpdbKey = IntegrationKeyStore.GetDecrypted("rpdb");
                var rpdbIsPosterTokenOnly = !string.IsNullOrWhiteSpace(rpdbKey) && rpdbKey.StartsWith("t1-", StringComparison.OrdinalIgnoreCase);
                if (!rpdbIsPosterTokenOnly && !string.IsNullOrWhiteSpace(rpdbKey) && !string.IsNullOrWhiteSpace(imdbId) && imdbId.StartsWith("tt"))
                {
                    try
                    {
                        var rpdbMeta = await _rpdbClient.LookupAsync(rpdbKey, imdbId, ct).ConfigureAwait(false);
                        if (rpdbMeta != null)
                        {
                            var rpdbUseful =
                                (!string.IsNullOrWhiteSpace(rpdbMeta.Overview)) ||
                                (!string.IsNullOrWhiteSpace(rpdbMeta.PosterUrl)) ||
                                (!string.IsNullOrWhiteSpace(rpdbMeta.BackdropUrl)) ||
                                (!string.IsNullOrWhiteSpace(rpdbMeta.LogoUrl));
                            _uiDispatcher.Invoke(() =>
                            {
                                if (ct.IsCancellationRequested) return;
                                if (!ReferenceEquals(DetailsItem, item))
                                    return;

                                if (!string.IsNullOrWhiteSpace(rpdbMeta.PosterUrl) && string.IsNullOrWhiteSpace(item.CoverUrl))
                                    item.CoverUrl = rpdbMeta.PosterUrl;

                                if (!string.IsNullOrWhiteSpace(rpdbMeta.BackdropUrl))
                                    item.BackdropUrl = rpdbMeta.BackdropUrl;

                                if (rpdbMeta.Rating.HasValue)
                                    item.Rating = rpdbMeta.Rating.Value;

                                if (rpdbMeta.AllRatings.Count > 0)
                                    item.RpdbRatings = new Dictionary<string, string>(rpdbMeta.AllRatings, StringComparer.OrdinalIgnoreCase);

                                if (!string.IsNullOrWhiteSpace(rpdbMeta.LogoUrl) && string.IsNullOrWhiteSpace(item.LogoUrl))
                                    item.LogoUrl = rpdbMeta.LogoUrl;

                                if (!string.IsNullOrWhiteSpace(rpdbMeta.Overview))
                                {
                                    if (string.IsNullOrWhiteSpace(DetailsOverview) || DetailsOverview == "Loading metadata...")
                                        DetailsOverview = rpdbMeta.Overview;
                                }

                                // Clear loading text when RPDB succeeds
                                if (DetailsOverview == "Loading metadata...")
                                    DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "No information available." : item.Metadata;

                                // Ensure cover image is actually loaded into the UI
                                if (!string.IsNullOrWhiteSpace(item.CoverUrl) && item.CoverImage == null)
                                    _ = TryLoadCoverIntoItemAsync(item, CancellationToken.None);

                                OnPropertyChanged(nameof(DetailsItem));
                            });
                            if (rpdbUseful)
                                return;
                        }
                    }
                    catch
                    {
                    }
                }

                if (!UseCinemetaFallback)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (!ReferenceEquals(DetailsItem, item))
                            return;
                        if (DetailsOverview == "Loading metadata...")
                            DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "No information available." : item.Metadata;
                    });
                    return;
                }

                try
                {
                    if (string.IsNullOrWhiteSpace(contentId))
                    {
                        ClearLoadingText(item, ct);
                        return;
                    }
                    var metaEl = await TryFetchMetadataCatalogItemAsync(contentType, contentId.ToLowerInvariant(), ct).ConfigureAwait(false);
                    var metaFound = metaEl.ValueKind == JsonValueKind.Object;

                    if (!metaFound && contentId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    {
                        try
                        {
                            var reId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false);
                            if (!string.IsNullOrWhiteSpace(reId))
                            {
                                imdbId = reId!;
                                var m3 = await TryFetchMetadataCatalogItemAsync(contentType, imdbId.ToLowerInvariant(), ct).ConfigureAwait(false);
                                if (m3.ValueKind == JsonValueKind.Object)
                                {
                                    metaEl = m3;
                                    metaFound = true;
                                }
                            }
                        }
                        catch { }
                    }

                    if (!metaFound)
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            if (ct.IsCancellationRequested) return;
                            if (!ReferenceEquals(DetailsItem, item))
                                return;
                            if (DetailsOverview == "Loading metadata...")
                                DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "No information available." : item.Metadata;
                        });
                        return;
                    }

                    var metaName0 = metaEl.TryGetProperty("name", out var nm0) && nm0.ValueKind == JsonValueKind.String ? (nm0.GetString() ?? "").Trim() :
                                    (metaEl.TryGetProperty("title", out var tt0) && tt0.ValueKind == JsonValueKind.String ? (tt0.GetString() ?? "").Trim() : "");
                    var metaYear0 = 0;
                    if (metaEl.TryGetProperty("year", out var y0))
                    {
                        if (y0.ValueKind == JsonValueKind.Number) y0.TryGetInt32(out metaYear0);
                        else if (y0.ValueKind == JsonValueKind.String) int.TryParse((y0.GetString() ?? "").Trim(), out metaYear0);
                    }
                    var itemTokens0 = TokenizeTitle(item.Title ?? "");
                    var metaTokens0 = TokenizeTitle(metaName0);
                    var inter0 = 0;
                    foreach (var t in itemTokens0) if (metaTokens0.Contains(t)) inter0++;
                    var mismatch0 = (itemTokens0.Count > 0 && inter0 == 0) || (item.Year > 0 && metaYear0 > 0 && Math.Abs(item.Year - metaYear0) > 1);
                    if (mismatch0)
                    {
                        var lookup = CleanLookupTitleForMeta(item.Title ?? "", out var yx0);
                        var ysel = item.Year > 0 ? item.Year : (yx0 > 0 ? yx0 : 0);
                        var reId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookup, ysel, ct).ConfigureAwait(false);
                        if (!string.IsNullOrWhiteSpace(reId) && !string.Equals(reId, imdbId, StringComparison.OrdinalIgnoreCase))
                        {
                            imdbId = reId!;
                            var retry = $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(imdbId.ToLowerInvariant())}.json";
                            var m2 = await TryFetchMetadataCatalogItemAsync(contentType, imdbId.ToLowerInvariant(), ct).ConfigureAwait(false);
                            if (m2.ValueKind == JsonValueKind.Object)
                                metaEl = m2;
                        }
                    }

                    var overview = "";
                    if (metaEl.TryGetProperty("description", out var descEl) && descEl.ValueKind == JsonValueKind.String)
                        overview = (descEl.GetString() ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("overview", out var ovEl) && ovEl.ValueKind == JsonValueKind.String)
                        overview = (ovEl.GetString() ?? "").Trim();
                    // de-dup second pass lines removed
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("shortDescription", out var sdEl) && sdEl.ValueKind == JsonValueKind.String)
                        overview = (sdEl.GetString() ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("plot", out var plEl) && plEl.ValueKind == JsonValueKind.String)
                        overview = (plEl.GetString() ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("synopsis", out var syEl) && syEl.ValueKind == JsonValueKind.String)
                        overview = (syEl.GetString() ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("summary", out var suEl) && suEl.ValueKind == JsonValueKind.String)
                        overview = (suEl.GetString() ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("tagline", out var tgEl) && tgEl.ValueKind == JsonValueKind.String)
                        overview = (tgEl.GetString() ?? "").Trim();

                    var backgroundUrl = "";
                    var posterUrl = "";

                    // If overview is still empty and we're using a tmdb: id, try resolving to imdb: and refetching
                    if (string.IsNullOrWhiteSpace(overview) && (contentId ?? "").StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    {
                        try
                        {
                            var reId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false);
                            if (!string.IsNullOrWhiteSpace(reId) && !string.Equals(reId, imdbId, StringComparison.OrdinalIgnoreCase))
                            {
                                imdbId = reId!;
                                var retryUrl = $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(imdbId.ToLowerInvariant())}.json";
                                using var r3 = await PreviewHttp.GetAsync(retryUrl, ct).ConfigureAwait(false);
                                if (r3.IsSuccessStatusCode)
                                {
                                    await using var s3 = await r3.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                                    using var d3 = await JsonDocument.ParseAsync(s3, cancellationToken: ct).ConfigureAwait(false);
                                    if (d3.RootElement.ValueKind == JsonValueKind.Object &&
                                        d3.RootElement.TryGetProperty("meta", out var m3) &&
                                        m3.ValueKind == JsonValueKind.Object)
                                    {
                                        if (m3.TryGetProperty("description", out var de3) && de3.ValueKind == JsonValueKind.String)
                                            overview = (de3.GetString() ?? "").Trim();
                                        if (string.IsNullOrWhiteSpace(overview) && m3.TryGetProperty("overview", out var ov3) && ov3.ValueKind == JsonValueKind.String)
                                            overview = (ov3.GetString() ?? "").Trim();
                                        if (string.IsNullOrWhiteSpace(backgroundUrl) && m3.TryGetProperty("background", out var bg3) && bg3.ValueKind == JsonValueKind.String)
                                            backgroundUrl = (bg3.GetString() ?? "").Trim();
                                        if (string.IsNullOrWhiteSpace(posterUrl) && m3.TryGetProperty("poster", out var po3) && po3.ValueKind == JsonValueKind.String)
                                            posterUrl = (po3.GetString() ?? "").Trim();
                                    }
                                }
                            }
                        }
                        catch
                        {
                        }
                    }

                    if (string.IsNullOrWhiteSpace(backgroundUrl))
                        backgroundUrl = metaEl.TryGetProperty("background", out var bgEl) && bgEl.ValueKind == JsonValueKind.String
                            ? (bgEl.GetString() ?? "").Trim()
                            : "";

                    if (string.IsNullOrWhiteSpace(posterUrl))
                        posterUrl = metaEl.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String
                            ? (posterEl.GetString() ?? "").Trim()
                            : "";

                    var logoUrlDetails = metaEl.TryGetProperty("logo", out var logoElDetails) && logoElDetails.ValueKind == JsonValueKind.String
                        ? (logoElDetails.GetString() ?? "").Trim()
                        : "";

                    if (string.IsNullOrWhiteSpace(backgroundUrl) && !string.IsNullOrWhiteSpace(posterUrl))
                        backgroundUrl = posterUrl;

                    posterUrl = NormalizePosterToken(posterUrl);
                    backgroundUrl = NormalizePosterToken(backgroundUrl);

                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (!ReferenceEquals(DetailsItem, item))
                            return;

                        if (!string.IsNullOrWhiteSpace(overview))
                            DetailsOverview = overview;
                        else if (DetailsOverview == "Loading metadata...")
                            DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "No information available." : item.Metadata;

                        if (!string.IsNullOrWhiteSpace(backgroundUrl) && string.IsNullOrWhiteSpace(item.BackdropUrl))
                            item.BackdropUrl = backgroundUrl;
                        if (!string.IsNullOrWhiteSpace(posterUrl) && string.IsNullOrWhiteSpace(item.CoverUrl))
                            item.CoverUrl = posterUrl;
                        if (!string.IsNullOrWhiteSpace(logoUrlDetails) && string.IsNullOrWhiteSpace(item.LogoUrl))
                            item.LogoUrl = logoUrlDetails;
                        if (string.IsNullOrWhiteSpace(item.MetaId) && !string.IsNullOrWhiteSpace(imdbId) && imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                            item.MetaId = imdbId.Trim();

                        OnPropertyChanged(nameof(DetailsItem));
                    });

                    if (!string.IsNullOrWhiteSpace(item.CoverUrl) && item.CoverImage == null)
                        _ = TryLoadCoverIntoItemAsync(item, CancellationToken.None);

                    if (string.IsNullOrWhiteSpace(item.CoverUrl))
                    {
                        try
                        {
                            var t = (lookupTitle ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(t)) t = (item.Title ?? "").Trim();
                            SelfHealingMonitor.Instance.ReportNullPoster(
                                t,
                                "Cinemeta",
                                () =>
                                {
                                    try { _uiDispatcher.BeginInvoke(new Action(() => RescanMetadata(item))); } catch { }
                                });
                        }
                        catch
                        {
                        }
                    }
                }
                catch
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (!ReferenceEquals(DetailsItem, item))
                            return;
                        if (DetailsOverview == "Loading metadata...")
                            DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "No information available." : item.Metadata;
                    });
                }
            }
            catch
            {
            }
        }

        private void OpenDetailsStreams()
        {
            if (DetailsItem == null) return;
            OpenStreamsForItem(DetailsItem);
        }

        private void OpenDetailsTrailer()
        {
            var item = DetailsItem;
            if (item == null) return;
            _ = OpenTrailerForItemAsync(item);
        }

        private async Task OpenPreviewTrailerAsync()
        {
            var item = PreviewItem;
            if (item == null) return;
            await OpenTrailerForItemAsync(item).ConfigureAwait(false);
        }

        private async Task OpenTrailerForItemAsync(MediaItem item)
        {
            try
            {
                var directTrailerUrl = (item.TrailerUrl ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(directTrailerUrl))
                {
                    if (directTrailerUrl.Contains("youtube.com", StringComparison.OrdinalIgnoreCase) ||
                        directTrailerUrl.Contains("youtu.be", StringComparison.OrdinalIgnoreCase))
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            try
                            {
                                var w = new YouTubeEmbedWindow(directTrailerUrl, "TRAILER");
                                w.Owner = Application.Current?.Windows?.OfType<Window>().FirstOrDefault(x => x.IsActive) ?? Application.Current?.MainWindow;
                                w.Show();
                                w.Activate();
                            }
                            catch
                            {
                            }
                        });
                        return;
                    }

                    try
                    {
                        Process.Start(new ProcessStartInfo
                        {
                            FileName = directTrailerUrl,
                            UseShellExecute = true
                        });
                        return;
                    }
                    catch
                    {
                    }
                }

                OpenStreamsForItem(item);
                StreamsSearchQuery = "";

                var start = DateTime.UtcNow;
                while (IsStreamsBusy && (DateTime.UtcNow - start) < TimeSpan.FromSeconds(5))
                    await Task.Delay(120).ConfigureAwait(false);

                AddonSource? trailerSource = null;
                string? externalLink = null;

                _uiDispatcher.Invoke(() =>
                {
                    static bool HasTrailerHint(AddonSource s)
                    {
                        var n = (s.Name ?? "").ToLowerInvariant();
                        var p = (s.ProviderName ?? "").ToLowerInvariant();
                        var q = (s.Quality ?? "").ToLowerInvariant();
                        return n.Contains("trailer") || q.Contains("trailer") || p.Contains("streailer") || n.Contains("streailer");
                    }

                    trailerSource = _streamSources
                        .Where(s => s != null && !s.IsInfoOnly && !string.IsNullOrWhiteSpace(s.UrlOrPath))
                        .Where(HasTrailerHint)
                        .OrderByDescending(s => s.Rank)
                        .FirstOrDefault();

                    if (trailerSource != null)
                        return;

                    var info = _streamSources
                        .Where(s => s != null && s.IsInfoOnly && s.Metadata != null)
                        .OrderByDescending(s => s.Rank)
                        .FirstOrDefault(HasTrailerHint);

                    if (info?.Metadata != null)
                    {
                        if (info.Metadata.TryGetValue("externalUrl", out var u) && !string.IsNullOrWhiteSpace(u))
                            externalLink = u;
                        else if (info.Metadata.TryGetValue("webUrl", out var w) && !string.IsNullOrWhiteSpace(w))
                            externalLink = w;
                    }
                });

                if (trailerSource != null)
                {
                    var url = (trailerSource.UrlOrPath ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(url) &&
                        (url.Contains("youtube.com", StringComparison.OrdinalIgnoreCase) ||
                         url.Contains("youtu.be", StringComparison.OrdinalIgnoreCase)))
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            try
                            {
                                var w = new YouTubeEmbedWindow(url, "TRAILER");
                                w.Owner = Application.Current?.Windows?.OfType<Window>().FirstOrDefault(x => x.IsActive) ?? Application.Current?.MainWindow;
                                w.Show();
                                w.Activate();
                            }
                            catch
                            {
                            }
                        });
                        return;
                    }

                    PlayStreamSource(trailerSource);
                    return;
                }

                // On-demand Cinemeta trailer lookup (embedded if YouTube)
                if (string.IsNullOrWhiteSpace(externalLink))
                {
                    try
                    {
                        var type = (item.Type ?? "").Trim().ToLowerInvariant();
                        var contentType = type.Contains("tv") || type.Contains("series") ? "series" : "movie";
                        var title = (item.Title ?? "").Trim();
                        var year = item.Year > 0 ? item.Year : 0;
                        var lookupTitle = CleanLookupTitleForMeta(title, out var extractedYear);
                        if (year <= 0) year = extractedYear;

                        var imdbId = "";
                        var rawId = ((item.MetaId ?? item.ImdbId ?? item.FilePath) ?? "").Trim();
                        if (rawId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                            imdbId = rawId;
                        if (!imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                            imdbId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, CancellationToken.None).ConfigureAwait(false) ?? "";

                        if (!string.IsNullOrWhiteSpace(imdbId) && imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                        {
                            var metaUrl = $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(imdbId.ToLowerInvariant())}.json";
                            using var resp = await PreviewHttp.GetAsync(metaUrl).ConfigureAwait(false);
                            if (resp.IsSuccessStatusCode)
                            {
                                await using var stream = await resp.Content.ReadAsStreamAsync().ConfigureAwait(false);
                                using var doc = await JsonDocument.ParseAsync(stream).ConfigureAwait(false);
                                if (doc.RootElement.ValueKind == JsonValueKind.Object &&
                                    doc.RootElement.TryGetProperty("meta", out var metaEl) &&
                                    metaEl.ValueKind == JsonValueKind.Object &&
                                    metaEl.TryGetProperty("trailer", out var trEl) &&
                                    trEl.ValueKind == JsonValueKind.String)
                                {
                                    var t = (trEl.GetString() ?? "").Trim();
                                    if (!string.IsNullOrWhiteSpace(t))
                                        externalLink = t;
                                }
                            }
                        }
                    }
                    catch
                    {
                    }
                }

                if (!string.IsNullOrWhiteSpace(externalLink))
                {
                    try
                    {
                        if (externalLink.Contains("youtube.com", StringComparison.OrdinalIgnoreCase) ||
                            externalLink.Contains("youtu.be", StringComparison.OrdinalIgnoreCase))
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                try
                                {
                                    var w = new YouTubeEmbedWindow(externalLink, "TRAILER");
                                    w.Owner = Application.Current?.Windows?.OfType<Window>().FirstOrDefault(x => x.IsActive) ?? Application.Current?.MainWindow;
                                    w.Show();
                                    w.Activate();
                                }
                                catch
                                {
                                }
                            });
                            return;
                        }

                        Process.Start(new ProcessStartInfo(externalLink) { UseShellExecute = true });
                        return;
                    }
                    catch
                    {
                    }
                }

                try
                {
                    var title = (item.Title ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(title))
                        return;

                    var yearPart = item.Year > 0 ? $" {item.Year}" : "";
                    var query = Uri.EscapeDataString($"{title}{yearPart} trailer");
                    var url = $"https://www.youtube.com/results?search_query={query}";
                    _uiDispatcher.Invoke(() =>
                    {
                        try
                        {
                            var w = new YouTubeEmbedWindow(url, "TRAILER SEARCH");
                            w.Owner = Application.Current?.Windows?.OfType<Window>().FirstOrDefault(x => x.IsActive) ?? Application.Current?.MainWindow;
                            w.Show();
                            w.Activate();
                        }
                        catch
                        {
                            try { Process.Start(new ProcessStartInfo(url) { UseShellExecute = true }); } catch { }
                        }
                    });
                }
                catch
                {
                }
            }
            catch
            {
            }
        }

        private void OnPreviewItemClicked(MediaItem? item)
        {
            if (item == null) return;
            try
            {
                if (PreviewItem != null &&
                    !string.IsNullOrWhiteSpace(PreviewItem.FilePath) &&
                    string.Equals(PreviewItem.FilePath, item.FilePath, StringComparison.OrdinalIgnoreCase))
                {
                    OpenItem(item);
                    return;
                }
            }
            catch
            {
            }
            SetPreviewItem(item);
        }

        public void SetPreviewItem(MediaItem? item)
        {
            if (item == null) return;
            if (ReferenceEquals(PreviewItem, item)) return;

            try
            {
                if (PreviewItem != null)
                    PreviewItem.IsSelected = false;
                item.IsSelected = true;
            }
            catch
            {
            }

            PreviewItem = item;
            OnPropertyChanged(nameof(HasPreviewItem));
            
            // Show known metadata immediately, then enrich asynchronously.
            PreviewOverview = !string.IsNullOrWhiteSpace(item.Overview)
                ? item.Overview
                : (string.IsNullOrWhiteSpace(item.Metadata) ? "Loading metadata..." : item.Metadata);
            PreviewRuntimeText = item.Duration.TotalMinutes > 0
                ? $"{(int)Math.Round(item.Duration.TotalMinutes)} min"
                : "";
            try
            {
                _previewCast.Clear();
            }
            catch { }

            CommandManager.InvalidateRequerySuggested();

            try
            {
                _previewMetaCts?.Cancel();
                _previewMetaCts?.Dispose();
            }
            catch { }

            _previewMetaCts = new CancellationTokenSource();
            var token = _previewMetaCts.Token;

            // Fire and forget, but the token and internal checks handle concurrency
            _ = LoadPreviewMetaAsync(item, token);
        }

        private async Task LoadPreviewMetaAsync(MediaItem item, CancellationToken ct)
        {
            try
            {
                static string NormalizePosterToken(string url)
                {
                    var s = (url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(s)) return s;
                    if (s.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || s.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                        return s;
                    if ((s.StartsWith("t", StringComparison.OrdinalIgnoreCase) || s.StartsWith("T", StringComparison.OrdinalIgnoreCase)) && s.Contains("-"))
                        return $"https://cinemeta.ratingposterdb.com/poster/{s}";
                    return s;
                }

                var type = (item.Type ?? "").Trim().ToLowerInvariant();
                var contentType = type.Contains("tv") || type.Contains("series") ? "series" : "movie";
                if (DisableMoviesTvExternalMeta && (type == "movies" || type == "tv" || contentType == "movie" || contentType == "series"))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (!ReferenceEquals(PreviewItem, item))
                            return;
                        if (PreviewOverview == "Loading metadata...")
                            PreviewOverview = "";
                    });
                    return;
                }

                var localPath = (item.PlaybackItem?.FilePath ?? item.FilePath ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(localPath) && LooksLikeHomeVideo(localPath))
                {
                    var runtimeText = "";
                    try
                    {
                        var d = item.Duration;
                        if (d != default && d.TotalMinutes > 0)
                            runtimeText = $"{(int)Math.Round(d.TotalMinutes)} min";
                    }
                    catch
                    {
                    }

                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested)
                            return;
                        if (!ReferenceEquals(PreviewItem, item))
                            return;
                        PreviewOverview = "";
                        PreviewRuntimeText = runtimeText;
                        _previewCast.Clear();
                    });
                    return;
                }

                var rawId = ((item.MetaId ?? item.ImdbId ?? item.FilePath) ?? "").Trim();
                var imdbId = rawId;
                var contentId = rawId;

                var rawTitle = (item.Title ?? "").Trim();
                if (string.IsNullOrWhiteSpace(rawTitle))
                {
                    try
                    {
                        var fp = (item.FilePath ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(fp) && fp.Contains("\\"))
                            rawTitle = Path.GetFileNameWithoutExtension(fp) ?? "";
                    }
                    catch
                    {
                    }
                }

                var year = item.Year > 0 ? item.Year : 0;
                if (year <= 0 && !string.IsNullOrWhiteSpace(localPath) && TryExtractYearFromPath(localPath, out var yFromPath))
                    year = yFromPath;

                if (!string.IsNullOrWhiteSpace(localPath) && !LooksLikeHomeVideo(localPath))
                {
                    var cleaned = CleanVideoTitleFromFileName(localPath, out var y2);
                    if (!string.IsNullOrWhiteSpace(cleaned) && cleaned.Length >= 2)
                        rawTitle = cleaned;
                    if (year <= 0 && y2 > 0)
                        year = y2;
                }
                var lookupTitle = CleanLookupTitleForMeta(rawTitle, out var extractedYear);
                if (year <= 0)
                    year = extractedYear;

                if (!imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                {
                    if (UseTmdbResolve)
                    {
                        try
                        {
                            var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
                            if (!string.IsNullOrWhiteSpace(tmdbKey))
                            {
                                var preferTv = string.Equals(contentType, "series", StringComparison.OrdinalIgnoreCase);
                                var (resolvedImdb, resolvedType) = await _tmdbClient.TryResolveImdbIdAsync(tmdbKey, year > 0 ? $"{lookupTitle} {year}" : lookupTitle, preferTv, ct).ConfigureAwait(false);
                                if (!string.IsNullOrWhiteSpace(resolvedImdb) && resolvedImdb.StartsWith("tt", StringComparison.OrdinalIgnoreCase) &&
                                    !string.IsNullOrWhiteSpace(resolvedType))
                                {
                                    imdbId = resolvedImdb;
                                    contentType = resolvedType!;
                                }
                            }
                        }
                        catch
                        {
                        }
                    }

                    if (ct.IsCancellationRequested) return;

                    if (!imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase) && UseCinemetaFallback)
                        imdbId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false) ?? "";
                }

                if (ct.IsCancellationRequested) return;

                if (imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                    contentId = imdbId;
                else if (rawId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    contentId = rawId;
                else if (!string.IsNullOrWhiteSpace(imdbId))
                    contentId = imdbId;

                if (((item.TmdbId ?? 0) > 0 || rawId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase)) &&
                    await TryApplyTmdbMetadataFallbackAsync(item, contentType, true, ct).ConfigureAwait(false))
                    return;

                // RPDB Integration disabled per request; rely on Cinemeta flow only
                if (UseRpdb)
                {
                    var rpdbKey = IntegrationKeyStore.GetDecrypted("rpdb");
                    var rpdbIsPosterTokenOnly = !string.IsNullOrWhiteSpace(rpdbKey) && rpdbKey.StartsWith("t1-", StringComparison.OrdinalIgnoreCase);
                    if (!rpdbIsPosterTokenOnly && !string.IsNullOrWhiteSpace(rpdbKey) && !string.IsNullOrWhiteSpace(imdbId) && imdbId.StartsWith("tt"))
                    {
                        try
                        {
                            var rpdbMeta = await _rpdbClient.LookupAsync(rpdbKey, imdbId, ct).ConfigureAwait(false);
                            if (rpdbMeta != null)
                            {
                                var rpdbHasOverview = !string.IsNullOrWhiteSpace(rpdbMeta.Overview);
                                _uiDispatcher.Invoke(() =>
                                {
                                    if (ct.IsCancellationRequested) return;
                                    if (!ReferenceEquals(PreviewItem, item))
                                        return;
                                    if (!string.IsNullOrWhiteSpace(rpdbMeta.Overview) && (string.IsNullOrWhiteSpace(PreviewOverview) || PreviewOverview == "Loading metadata..."))
                                        PreviewOverview = rpdbMeta.Overview;
                                    if (!string.IsNullOrWhiteSpace(rpdbMeta.PosterUrl) && string.IsNullOrWhiteSpace(item.CoverUrl))
                                        item.CoverUrl = rpdbMeta.PosterUrl;
                                    if (!string.IsNullOrWhiteSpace(rpdbMeta.BackdropUrl))
                                        item.BackdropUrl = rpdbMeta.BackdropUrl;
                                    if (!string.IsNullOrWhiteSpace(rpdbMeta.LogoUrl) && string.IsNullOrWhiteSpace(item.LogoUrl))
                                        item.LogoUrl = rpdbMeta.LogoUrl;
                                    if (rpdbMeta.Rating.HasValue)
                                        item.Rating = rpdbMeta.Rating.Value;
                                    if (!string.IsNullOrWhiteSpace(item.CoverUrl) && item.CoverImage == null)
                                        _ = TryLoadCoverIntoItemAsync(item, CancellationToken.None);

                                    OnPropertyChanged(nameof(PreviewItem));
                                });
                                if (rpdbHasOverview)
                                    return;
                            }
                        }
                        catch { }
                    }
                }

                if (!UseCinemetaFallback)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (!ReferenceEquals(PreviewItem, item))
                            return;
                        if (PreviewOverview == "Loading metadata...")
                            PreviewOverview = "";
                    });
                    return;
                }

                try
                {
                    if (string.IsNullOrWhiteSpace(contentId))
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            if (ct.IsCancellationRequested)
                                return;
                            if (!ReferenceEquals(PreviewItem, item))
                                return;
                            if (PreviewOverview == "Loading metadata...")
                                PreviewOverview = "";
                            try
                            {
                                var d = item.Duration;
                                if (d != default && d.TotalMinutes > 0)
                                    PreviewRuntimeText = $"{(int)Math.Round(d.TotalMinutes)} min";
                            }
                            catch
                            {
                            }
                        });
                        return;
                    }
                    var metaEl = await TryFetchMetadataCatalogItemAsync(contentType, contentId.ToLowerInvariant(), ct).ConfigureAwait(false);
                    var metaFound = metaEl.ValueKind == JsonValueKind.Object;

                    if (!metaFound && contentId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    {
                        try
                        {
                            var reIdPv = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false);
                            if (!string.IsNullOrWhiteSpace(reIdPv))
                            {
                                imdbId = reIdPv!;
                                var retryPvUrl = $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(imdbId.ToLowerInvariant())}.json";
                                metaEl = await TryFetchMetadataCatalogItemAsync(contentType, imdbId.ToLowerInvariant(), ct).ConfigureAwait(false);
                                metaFound = metaEl.ValueKind == JsonValueKind.Object;
                            }
                        }
                        catch { }
                    }

                    if (!metaFound)
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            if (ct.IsCancellationRequested) return;
                            if (!ReferenceEquals(PreviewItem, item))
                                return;
                            if (PreviewOverview == "Loading metadata...")
                                PreviewOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "No information available." : item.Metadata;
                        });
                        return;
                    }

                    var metaNamePv = metaEl.TryGetProperty("name", out var nmPv) && nmPv.ValueKind == JsonValueKind.String ? (nmPv.GetString() ?? "").Trim() :
                                     (metaEl.TryGetProperty("title", out var ttPv) && ttPv.ValueKind == JsonValueKind.String ? (ttPv.GetString() ?? "").Trim() : "");
                    var metaYearPv = 0;
                    if (metaEl.TryGetProperty("year", out var yPv))
                    {
                        if (yPv.ValueKind == JsonValueKind.Number) yPv.TryGetInt32(out metaYearPv);
                        else if (yPv.ValueKind == JsonValueKind.String) int.TryParse((yPv.GetString() ?? "").Trim(), out metaYearPv);
                    }
                    var itemTokensPv = TokenizeTitle(item.Title ?? "");
                    var metaTokensPv = TokenizeTitle(metaNamePv);
                    var interPv = 0;
                    foreach (var t in itemTokensPv) if (metaTokensPv.Contains(t)) interPv++;
                    var mismatchPv = (itemTokensPv.Count > 0 && interPv == 0) || (item.Year > 0 && metaYearPv > 0 && Math.Abs(item.Year - metaYearPv) > 1);
                    if (mismatchPv)
                    {
                        var lookupPv = CleanLookupTitleForMeta(item.Title ?? "", out var yxPv);
                        var ySelPv = item.Year > 0 ? item.Year : (yxPv > 0 ? yxPv : 0);
                        var reIdPv = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupPv, ySelPv, ct).ConfigureAwait(false);
                        if (!string.IsNullOrWhiteSpace(reIdPv) && !string.Equals(reIdPv, imdbId, StringComparison.OrdinalIgnoreCase))
                        {
                            imdbId = reIdPv!;
                            var m2 = await TryFetchMetadataCatalogItemAsync(contentType, imdbId.ToLowerInvariant(), ct).ConfigureAwait(false);
                            if (m2.ValueKind != JsonValueKind.Object) return;
                            metaEl = m2;
                        }
                    }

                    var overview = "";
                    if (metaEl.TryGetProperty("description", out var descEl) && descEl.ValueKind == JsonValueKind.String)
                        overview = (descEl.GetString() ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("overview", out var ovEl) && ovEl.ValueKind == JsonValueKind.String)
                        overview = (ovEl.GetString() ?? "").Trim();

                    // If overview is still empty and we're using a tmdb: id, try resolving to imdb: and refetching
                    if (string.IsNullOrWhiteSpace(overview) && (contentId ?? "").StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    {
                        try
                        {
                            var reIdPv2 = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false);
                            if (!string.IsNullOrWhiteSpace(reIdPv2) && !string.Equals(reIdPv2, imdbId, StringComparison.OrdinalIgnoreCase))
                            {
                                imdbId = reIdPv2!;
                                var m3Pv = await TryFetchMetadataCatalogItemAsync(contentType, imdbId.ToLowerInvariant(), ct).ConfigureAwait(false);
                                if (m3Pv.ValueKind == JsonValueKind.Object)
                                {
                                    if (m3Pv.TryGetProperty("description", out var de3Pv) && de3Pv.ValueKind == JsonValueKind.String)
                                        overview = (de3Pv.GetString() ?? "").Trim();
                                    if (string.IsNullOrWhiteSpace(overview) && m3Pv.TryGetProperty("overview", out var ov3Pv) && ov3Pv.ValueKind == JsonValueKind.String)
                                        overview = (ov3Pv.GetString() ?? "").Trim();
                                }
                            }
                        }
                        catch
                        {
                        }
                    }

                    var backgroundUrl = metaEl.TryGetProperty("background", out var bgEl) && bgEl.ValueKind == JsonValueKind.String
                        ? (bgEl.GetString() ?? "").Trim()
                        : "";

                    var logoUrl = metaEl.TryGetProperty("logo", out var logoEl) && logoEl.ValueKind == JsonValueKind.String
                        ? (logoEl.GetString() ?? "").Trim()
                        : "";

                    var posterUrl = metaEl.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String
                        ? (posterEl.GetString() ?? "").Trim()
                        : "";

                    if (string.IsNullOrWhiteSpace(backgroundUrl) && !string.IsNullOrWhiteSpace(posterUrl))
                        backgroundUrl = posterUrl;

                    posterUrl = NormalizePosterToken(posterUrl);
                    backgroundUrl = NormalizePosterToken(backgroundUrl);

                    var runtime = "";
                    if (metaEl.TryGetProperty("runtime", out var rtEl))
                    {
                        if (rtEl.ValueKind == JsonValueKind.Number && rtEl.TryGetInt32(out var mins) && mins > 0)
                            runtime = $"{mins} min";
                        else if (rtEl.ValueKind == JsonValueKind.String)
                            runtime = (rtEl.GetString() ?? "").Trim();
                    }

                    if (string.IsNullOrWhiteSpace(runtime))
                    {
                        try
                        {
                            var d = item.Duration;
                            if (d != default && d.TotalMinutes > 0)
                                runtime = $"{(int)Math.Round(d.TotalMinutes)} min";
                        }
                        catch
                        {
                        }
                    }

                    var cast = new List<string>();
                    if (metaEl.TryGetProperty("cast", out var castEl) && castEl.ValueKind == JsonValueKind.Array)
                    {
                        foreach (var c in castEl.EnumerateArray())
                        {
                            if (c.ValueKind != JsonValueKind.String) continue;
                            var s = (c.GetString() ?? "").Trim();
                            if (!string.IsNullOrWhiteSpace(s)) cast.Add(s);
                        }
                    }

                    cast = cast.Distinct(StringComparer.OrdinalIgnoreCase).Take(8).ToList();

                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested)
                            return;
                        if (!ReferenceEquals(PreviewItem, item))
                            return;

                        if (!string.IsNullOrWhiteSpace(overview))
                            PreviewOverview = overview;
                        else if (PreviewOverview == "Loading metadata...")
                            PreviewOverview = "";

                        if (!string.IsNullOrWhiteSpace(runtime))
                            PreviewRuntimeText = runtime;

                        if (cast.Count > 0)
                        {
                            _previewCast.Clear();
                            foreach (var c in cast)
                                _previewCast.Add(c);
                        }

                        if (!string.IsNullOrWhiteSpace(backgroundUrl) && string.IsNullOrWhiteSpace(item.BackdropUrl))
                            item.BackdropUrl = backgroundUrl;
                        if (!string.IsNullOrWhiteSpace(logoUrl) && string.IsNullOrWhiteSpace(item.LogoUrl))
                            item.LogoUrl = logoUrl;
                        if (!string.IsNullOrWhiteSpace(posterUrl) && string.IsNullOrWhiteSpace(item.CoverUrl))
                            item.CoverUrl = posterUrl;
                        if (string.IsNullOrWhiteSpace(item.MetaId) && !string.IsNullOrWhiteSpace(imdbId) && imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                            item.MetaId = imdbId.Trim();

                        if (metaEl.TryGetProperty("genres", out var genreEl) && genreEl.ValueKind == JsonValueKind.Array)
                        {
                            var gList = new List<string>();
                            foreach (var g in genreEl.EnumerateArray())
                            {
                                var s = g.GetString();
                                if (!string.IsNullOrWhiteSpace(s))
                                    gList.Add(s);
                            }
                            if (gList.Count > 0 && (item.Genres == null || item.Genres.Count == 0))
                                item.Genres = gList;
                        }

                        if (metaEl.TryGetProperty("imdbRating", out var rateEl))
                        {
                            var normalized = ReadNormalizedRating(rateEl);
                            if (normalized > 0)
                                item.Rating = item.Rating > 0 ? item.Rating : normalized;
                        }

                        if (metaEl.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String)
                        {
                            var n = nameEl.GetString();
                            if (!string.IsNullOrWhiteSpace(n) && string.IsNullOrWhiteSpace(item.Title))
                                item.Title = n;
                        }

                        if (metaEl.TryGetProperty("year", out var yrEl))
                        {
                            if (yrEl.ValueKind == JsonValueKind.Number && yrEl.TryGetInt32(out var y))
                            {
                                if (item.Year <= 0) item.Year = y;
                            }
                            else if (yrEl.ValueKind == JsonValueKind.String && int.TryParse(yrEl.GetString(), out var y2))
                            {
                                if (item.Year <= 0) item.Year = y2;
                            }
                        }

                        OnPropertyChanged(nameof(PreviewItem));
                    });

                    if (!string.IsNullOrWhiteSpace(item.CoverUrl) && item.CoverImage == null)
                        _ = TryLoadCoverIntoItemAsync(item, CancellationToken.None);
                }
                catch
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (ct.IsCancellationRequested) return;
                        if (!ReferenceEquals(PreviewItem, item))
                            return;
                        if (PreviewOverview == "Loading metadata...")
                            PreviewOverview = "";
                    });
                }
            }
            catch
            {
            }
        }

        private void ClearLoadingText(MediaItem item, CancellationToken ct)
        {
            _uiDispatcher.Invoke(() =>
            {
                if (ct.IsCancellationRequested) return;
                if (!ReferenceEquals(PreviewItem, item))
                    return;
                if (PreviewOverview == "Loading metadata...")
                    PreviewOverview = "";
            });
        }

        private static async Task<JsonElement> TryFetchMetadataCatalogItemAsync(string contentType, string contentId, CancellationToken ct)
        {
            var urls = new[]
            {
                $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(contentId)}.json",
                $"https://cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(contentId)}.json"
            };
            foreach (var u in urls)
            {
                using var resp = await PreviewHttp.GetAsync(u, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode) continue;
                await using var s = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(s, cancellationToken: ct).ConfigureAwait(false);
                if (doc.RootElement.ValueKind == JsonValueKind.Object &&
                    doc.RootElement.TryGetProperty("meta", out var meta) &&
                    meta.ValueKind == JsonValueKind.Object)
                    return meta;
            }
            return default;
        }

        private static string CleanLookupTitleForMeta(string raw, out int year)
        {
            year = 0;
            var s = (raw ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s))
                return "";

            try
            {
                var yearMatch = System.Text.RegularExpressions.Regex.Match(s, @"\b(19|20)\d{2}\b", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
                if (yearMatch.Success && int.TryParse(yearMatch.Value, out var y))
                    year = y;
            }
            catch
            {
            }

            try
            {
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\bv?\d{1,2}\.\d{1,4}(\.\d{1,4})*\b", " ");
            }
            catch
            {
            }

            s = s.Replace('.', ' ').Replace('_', ' ').Replace('-', ' ');

            try
            {
                s = System.Text.RegularExpressions.Regex.Replace(s, @"[\[\(\{][^\]\)\}]{1,120}[\]\)\}]", " ", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\bS\d{1,2}E\d{1,2}\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b\d{1,2}x\d{1,2}\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\bseason\s*\d{1,2}\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\bepisode\s*\d{1,3}\b", " ");

                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(19|20)\d{2}\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(480p|720p|1080p|2160p|4k|8k)\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(web\\-?dl|webrip|web|hdrip|bdrip|bluray|blu\\-?ray|dvdrip|hdtv|cam|ts|tc)\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(x264|x265|h264|h265|hevc|av1|10bit|8bit|hdr|dv|dolby|vision)\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(aac|ac3|eac3|dts|truehd|atmos|ddp)\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(extended|unrated|remux|proper|repack|limited)\b", " ");
                s = System.Text.RegularExpressions.Regex.Replace(s, @"\s+", " ").Trim();

                if (year > 0)
                    s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b1\b$", "").Trim();
                else
                    s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b\d{1,2}\s+\d{1,3}\b$", "").Trim();

                s = System.Text.RegularExpressions.Regex.Replace(s, @"(?i)\b(yts|yify|rarbg|evo|ettv|tgx|psa|ion10|pahe|ganool|nitro|hmax|amzn|nf|dsnp)\b$", "").Trim();
                s = System.Text.RegularExpressions.Regex.Replace(s, @"\b[A-Z]{2,6}\b$", "", System.Text.RegularExpressions.RegexOptions.None).Trim();
                s = System.Text.RegularExpressions.Regex.Replace(s, @"\s+", " ").Trim();
            }
            catch
            {
                s = (s ?? "").Trim();
            }

            return s;
        }

        private static bool TryExtractYearFromPath(string filePath, out int year)
        {
            year = 0;
            try
            {
                var name = Path.GetFileNameWithoutExtension(filePath) ?? "";
                if (string.IsNullOrWhiteSpace(name))
                    return false;

                var m = Regex.Match(name, @"\b(19|20)\d{2}\b", RegexOptions.IgnoreCase);
                if (!m.Success)
                    return false;

                if (!int.TryParse(m.Value, out var y))
                    return false;

                if (y < 1900 || y > DateTime.UtcNow.Year + 1)
                    return false;

                year = y;
                return true;
            }
            catch
            {
                year = 0;
                return false;
            }
        }

        private static bool LooksLikeHomeVideo(string filePath)
        {
            try
            {
                var fp = (filePath ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(fp))
                {
                    var lowerPath = fp.ToLowerInvariant();
                    if (lowerPath.Contains("\\dcim\\", StringComparison.OrdinalIgnoreCase) ||
                        lowerPath.Contains("\\camera\\", StringComparison.OrdinalIgnoreCase) ||
                        lowerPath.Contains("\\camera roll\\", StringComparison.OrdinalIgnoreCase) ||
                        lowerPath.Contains("\\home videos\\", StringComparison.OrdinalIgnoreCase) ||
                        lowerPath.Contains("\\home movies\\", StringComparison.OrdinalIgnoreCase) ||
                        lowerPath.Contains("\\phone\\", StringComparison.OrdinalIgnoreCase))
                        return true;
                }

                var name = Path.GetFileNameWithoutExtension(filePath) ?? "";
                name = name.Trim();
                if (string.IsNullOrWhiteSpace(name))
                    return false;

                if (Regex.IsMatch(name, @"(?i)^(img|vid|mov|pxl|dsc|gopr|gopro|dji)[\-_ ]?\d{6,}$"))
                    return true;

                if (Regex.IsMatch(name, @"\b(19|20)\d{2}[-_.](0[1-9]|1[0-2])[-_.](0[1-9]|[12]\d|3[01])\b"))
                    return true;

                if (Regex.IsMatch(name, @"\b(0[1-9]|1[0-2])[-_.](0[1-9]|[12]\d|3[01])[-_.](19|20)\d{2}\b"))
                    return true;

                if (Regex.IsMatch(name, @"(?i)\bv?\d{1,2}\.\d{1,4}(\.\d{1,4})*\b"))
                {
                    if (!Regex.IsMatch(name, @"\b(19|20)\d{2}\b"))
                        return true;
                }

                return false;
            }
            catch
            {
                return false;
            }
        }

        private static string CleanVideoTitleFromFileName(string filePath, out int year)
        {
            year = 0;
            try
            {
                var name = Path.GetFileNameWithoutExtension(filePath) ?? "";
                if (string.IsNullOrWhiteSpace(name))
                    return "";

                if (LooksLikeHomeVideo(filePath))
                    return name.Trim();

                var title = name.Trim().Replace('.', ' ').Replace('_', ' ').Replace('-', ' ');
                var yearMatch = Regex.Match(title, @"\b(19|20)\d{2}\b", RegexOptions.IgnoreCase);
                if (yearMatch.Success && int.TryParse(yearMatch.Value, out var y))
                    year = y;

                title = Regex.Replace(title, @"[\[\(\{][^\]\)\}]{1,120}[\]\)\}]", " ", RegexOptions.IgnoreCase);
                title = Regex.Replace(title, @"(?i)\bv?\d{1,2}\.\d{1,4}(\.\d{1,4})*\b", " ");
                title = Regex.Replace(title, @"(?i)\b(19|20)\d{2}\b", " ");
                title = Regex.Replace(title, @"(?i)\b(480p|720p|1080p|2160p|4k|8k)\b", " ");
                title = Regex.Replace(title, @"(?i)\b(web\-?dl|webrip|web|hdrip|bdrip|bluray|blu\-?ray|dvdrip|hdtv|cam|ts|tc)\b", " ");
                title = Regex.Replace(title, @"(?i)\b(x264|x265|h264|h265|hevc|av1|10bit|8bit|hdr|dv|dolby|vision)\b", " ");
                title = Regex.Replace(title, @"(?i)\b(aac|ac3|eac3|dts|truehd|atmos|ddp)\b", " ");
                title = Regex.Replace(title, @"(?i)\b(extended|unrated|remux|proper|repack|limited)\b", " ");
                title = Regex.Replace(title, @"(?i)\b(yts|yify|rarbg|evo|ettv|tgx|psa|ion10|pahe|ganool|nitro|hmax|amzn|nf|dsnp|panam)\b$", " ").Trim();
                title = Regex.Replace(title, @"\b[A-Z]{2,6}\b$", "", RegexOptions.None).Trim();
                title = Regex.Replace(title, @"(?i)\bironman\b", "iron man");
                title = Regex.Replace(title, @"(?i)\bspiderman\b", "spider man");
                title = Regex.Replace(title, @"(?i)\bantman\b", "ant man");
                title = Regex.Replace(title, @"\s+", " ").Trim();
                return title;
            }
            catch
            {
                year = 0;
                return "";
            }
        }

        private static string NormalizeTitleKey(string s)
        {
            var t = (s ?? "").ToLowerInvariant();
            try
            {
                t = System.Text.RegularExpressions.Regex.Replace(t, @"[^a-z0-9]+", "");
            }
            catch
            {
            }
            return t;
        }

        private static string NormalizeTitleForTokens(string s)
        {
            var t = (s ?? "").ToLowerInvariant();
            try
            {
                t = t.Replace("ironman", "iron man")
                     .Replace("spiderman", "spider man")
                     .Replace("antman", "ant man");
                t = Regex.Replace(t, @"[^a-z0-9]+", " ").Trim();
                t = Regex.Replace(t, @"\s+", " ").Trim();
            }
            catch
            {
                t = (s ?? "").ToLowerInvariant().Trim();
            }
            return t;
        }

        private static HashSet<string> TokenizeTitle(string s)
        {
            var tokens = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            try
            {
                var norm = NormalizeTitleForTokens(s);
                if (string.IsNullOrWhiteSpace(norm))
                    return tokens;

                foreach (var part in norm.Split(' ', StringSplitOptions.RemoveEmptyEntries))
                {
                    if (part.Length <= 1) continue;
                    if (part is "the" or "a" or "an" or "and" or "of" or "to" or "in" or "on" or "at") continue;
                    tokens.Add(part);
                }
            }
            catch
            {
            }
            return tokens;
        }

        private static string StripTrailingOne(string key)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(key))
                    return "";
                if (key.EndsWith("1", StringComparison.Ordinal))
                    return key.Substring(0, key.Length - 1);
                return key;
            }
            catch
            {
                return key;
            }
        }

        private static async Task<string?> ResolveImdbIdViaMetadataCatalogAsync(string contentType, string title, int year, CancellationToken ct)
        {
            try
            {
                var q = (title ?? "").Trim();
                if (string.IsNullOrWhiteSpace(q))
                    return null;

                contentType = string.Equals(contentType, "series", StringComparison.OrdinalIgnoreCase) ? "series" : "movie";

                async Task<JsonElement> FetchMetasAsync(string query)
                {
                    var urls = new[]
                    {
                        $"https://v3-cinemeta.strem.io/catalog/{Uri.EscapeDataString(contentType)}/top/search={Uri.EscapeDataString(query)}.json",
                        $"https://cinemeta.strem.io/catalog/{Uri.EscapeDataString(contentType)}/top/search={Uri.EscapeDataString(query)}.json"
                    };
                    foreach (var url in urls)
                    {
                        using var resp = await PreviewHttp.GetAsync(url, ct).ConfigureAwait(false);
                        if (!resp.IsSuccessStatusCode)
                            continue;

                        await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                        using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                        if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                            !doc.RootElement.TryGetProperty("metas", out var metasEl) ||
                            metasEl.ValueKind != JsonValueKind.Array)
                            continue;

                        return metasEl.Clone();
                    }

                    return default;
                }

                JsonElement metasEl = default;
                if (year > 0)
                {
                    metasEl = await FetchMetasAsync($"{q} {year}").ConfigureAwait(false);
                    if (metasEl.ValueKind != JsonValueKind.Array || metasEl.GetArrayLength() == 0)
                        metasEl = await FetchMetasAsync(q).ConfigureAwait(false);
                }
                else
                {
                    metasEl = await FetchMetasAsync(q).ConfigureAwait(false);
                }

                if (metasEl.ValueKind != JsonValueKind.Array || metasEl.GetArrayLength() == 0)
                    return null;

                var queryKey = NormalizeTitleKey(q);
                var queryKeyNoOne = StripTrailingOne(queryKey);
                var queryTokens = TokenizeTitle(q);

                var candidates = new List<(string id, string name, int year, int score)>();

                foreach (var m in metasEl.EnumerateArray())
                {
                    ct.ThrowIfCancellationRequested();
                    if (m.ValueKind != JsonValueKind.Object) continue;

                    if (!m.TryGetProperty("id", out var idEl) || idEl.ValueKind != JsonValueKind.String) continue;
                    var id = (idEl.GetString() ?? "").Trim();
                    if (!id.StartsWith("tt", StringComparison.OrdinalIgnoreCase)) continue;

                    var name = "";
                    if (m.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String)
                        name = (nameEl.GetString() ?? "").Trim();
                    else if (m.TryGetProperty("title", out var titleEl) && titleEl.ValueKind == JsonValueKind.String)
                        name = (titleEl.GetString() ?? "").Trim();

                    var metaYear = 0;
                    if (m.TryGetProperty("year", out var yearEl))
                    {
                        if (yearEl.ValueKind == JsonValueKind.Number)
                            yearEl.TryGetInt32(out metaYear);
                        else if (yearEl.ValueKind == JsonValueKind.String)
                            int.TryParse((yearEl.GetString() ?? "").Trim(), out metaYear);
                    }

                    var score = 0;
                    if (year > 0 && metaYear == year) score += 1000;
                    else if (year > 0 && metaYear > 0 && metaYear != year) score -= 600;

                    var nameKey = NormalizeTitleKey(name);
                    var nameKeyNoOne = StripTrailingOne(nameKey);
                    if (!string.IsNullOrWhiteSpace(queryKey) && !string.IsNullOrWhiteSpace(nameKey))
                    {
                        if (string.Equals(queryKey, nameKey, StringComparison.OrdinalIgnoreCase)) score += 600;
                        else if (nameKey.Contains(queryKey, StringComparison.OrdinalIgnoreCase) || queryKey.Contains(nameKey, StringComparison.OrdinalIgnoreCase)) score += 200;
                        else score -= 350;
                    }
                    if (!string.IsNullOrWhiteSpace(queryKeyNoOne) && !string.IsNullOrWhiteSpace(nameKeyNoOne))
                    {
                        if (string.Equals(queryKeyNoOne, nameKeyNoOne, StringComparison.OrdinalIgnoreCase)) score += 450;
                        else if (nameKeyNoOne.Contains(queryKeyNoOne, StringComparison.OrdinalIgnoreCase) || queryKeyNoOne.Contains(nameKeyNoOne, StringComparison.OrdinalIgnoreCase)) score += 150;
                        else score -= 200;
                    }

                    var candTokens = TokenizeTitle(name);
                    if (queryTokens.Count > 0 && candTokens.Count > 0)
                    {
                        var intersection = 0;
                        foreach (var t in queryTokens)
                            if (candTokens.Contains(t)) intersection++;

                        if (intersection == 0) score -= 900;
                        else score += intersection * 250;

                        if (queryTokens.Count >= 2 && intersection == queryTokens.Count) score += 600;
                    }

                    candidates.Add((id.ToLowerInvariant(), name, metaYear, score));
                }

                if (candidates.Count == 0)
                    return null;

                var ordered = candidates
                    .OrderByDescending(c => c.score)
                    .ThenByDescending(c => c.year)
                    .ToList();

                if (year <= 0)
                {
                    if (ordered[0].score < 800)
                        return null;
                }

                async Task<int> FetchMetaYearAsync(string imdbId)
                {
                    try
                    {
                        var metaUrl = $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(imdbId)}.json";
                        using var mr = await PreviewHttp.GetAsync(metaUrl, ct).ConfigureAwait(false);
                        if (!mr.IsSuccessStatusCode)
                            return 0;

                        await using var ms = await mr.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                        using var md = await JsonDocument.ParseAsync(ms, cancellationToken: ct).ConfigureAwait(false);
                        if (md.RootElement.ValueKind != JsonValueKind.Object ||
                            !md.RootElement.TryGetProperty("meta", out var metaEl) ||
                            metaEl.ValueKind != JsonValueKind.Object)
                            return 0;

                        if (!metaEl.TryGetProperty("year", out var yEl))
                            return 0;

                        if (yEl.ValueKind == JsonValueKind.Number && yEl.TryGetInt32(out var yy))
                            return yy;
                        if (yEl.ValueKind == JsonValueKind.String && int.TryParse((yEl.GetString() ?? "").Trim(), out var ys))
                            return ys;
                        return 0;
                    }
                    catch
                    {
                        return 0;
                    }
                }

                var limit = Math.Min(10, ordered.Count);
                for (var idx = 0; idx < limit; idx++)
                {
                    ct.ThrowIfCancellationRequested();
                    var c = ordered[idx];
                    if (year > 0)
                    {
                        if (c.year == year)
                            return c.id;
                        if (c.year > 0 && c.year != year)
                            continue;

                        var metaYear = await FetchMetaYearAsync(c.id).ConfigureAwait(false);
                        if (metaYear == year)
                            return c.id;
                        if (metaYear > 0 && metaYear != year)
                            continue;
                    }
                    else
                    {
                        return c.id;
                    }
                }

                return ordered[0].id;
            }
            catch
            {
                return null;
            }
        }

        private static void EnsureDefaultAddonServersSeeded()
        {
            try
            {
                try
                {
                    var seeded = (IntegrationKeyStore.GetDecrypted(AddonServersSeededKey) ?? "").Trim();
                    if (string.Equals(seeded, "1", StringComparison.OrdinalIgnoreCase))
                    {
                        return;
                    }
                }
                catch
                {
                }

                var current = LoadAddonServersFromStore();

                // If the user already has servers configured (or has removed them), do not force defaults back in.
                if (current.Count > 0)
                {
                    try { IntegrationKeyStore.SetProtected(AddonServersSeededKey, "1"); } catch { }
                    return;
                }

                try
                {
                    var cfgPath = GetAddonServersConfigPath();
                    if (!string.IsNullOrWhiteSpace(cfgPath) && File.Exists(cfgPath))
                    {
                        var items = JsonSerializer.Deserialize<List<AtlasAI.Models.AddonServerItem>>(File.ReadAllText(cfgPath)) ?? new List<AtlasAI.Models.AddonServerItem>();
                        if (items.Any(i => i != null && !string.IsNullOrWhiteSpace(i.Url) && i.Enabled))
                        {
                            try { IntegrationKeyStore.SetProtected(AddonServersSeededKey, "1"); } catch { }
                            return;
                        }
                    }
                }
                catch
                {
                }

                var defaults = new[]
                {
                    DefaultTmdbAddonManifestUrl,
                    DefaultRatingsMetadataAddonManifestUrl,
                    DefaultTrailerMetadataAddonManifestUrl
                };

                var changed = false;
                foreach (var u in defaults)
                {
                    var normalized = NormalizeAddonServerUrl(u);
                    if (string.IsNullOrWhiteSpace(normalized))
                        continue;
                    if (current.Any(x => string.Equals(x, normalized, StringComparison.OrdinalIgnoreCase)))
                        continue;
                    current.Add(normalized);
                    changed = true;
                }

                if (!changed)
                {
                    try { IntegrationKeyStore.SetProtected(AddonServersSeededKey, "1"); } catch { }
                    return;
                }

                SaveAddonServersToStore(current);

                try { IntegrationKeyStore.SetProtected(AddonServersSeededKey, "1"); } catch { }
            }
            catch
            {
            }
        }

        private static void EnsureAddonServerPresent(string normalizedBaseUrl)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(normalizedBaseUrl))
                    return;

                var current = LoadAddonServersFromStore();
                if (!current.Any(x => string.Equals(x, normalizedBaseUrl, StringComparison.OrdinalIgnoreCase)))
                {
                    current.Add(normalizedBaseUrl);
                    SaveAddonServersToStore(current);
                }

                TryAddOrEnableAddonServerInConfigFile(normalizedBaseUrl);
            }
            catch
            {
            }
        }

        private void EnsureCloudProvidersLoaded()
        {
            try
            {
                if (CloudProviderRegistry.Providers.Count == 0)
                {
                    try
                    {
                        CloudProviderRegistry.Register(new AtlasAI.Integrations.CloudProviders.RealDebridProvider(new DpapiFileSecretsStore()));
                    }
                    catch
                    {
                    }
                }

                _cloudProviders.Clear();
                foreach (var p in CloudProviderRegistry.Providers)
                    _cloudProviders.Add(p);

                var preferredId = IntegrationKeyStore.GetDecrypted("cloud_provider_selected");
                if (!string.IsNullOrWhiteSpace(preferredId))
                {
                    var match = _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, preferredId, StringComparison.OrdinalIgnoreCase));
                    if (match != null)
                        SelectedCloudProvider = match;
                }

                if (SelectedCloudProvider == null || !_cloudProviders.Contains(SelectedCloudProvider))
                    SelectedCloudProvider = _cloudProviders.FirstOrDefault();
            }
            catch
            {
            }
            finally
            {
                OnPropertyChanged(nameof(HasCloudProviders));
                CommandManager.InvalidateRequerySuggested();
            }
        }

        private async Task LoadLibraryFromDiskAsync()
        {
            string? json = null;
            try
            {
                if (!File.Exists(LibraryFilePath))
                    return;

                json = await File.ReadAllTextAsync(LibraryFilePath).ConfigureAwait(false);
            }
            catch (Exception ex)
            {
                Debug.WriteLine($"[MediaCentre] Failed to read library: {ex.Message}");
                return;
            }

            if (string.IsNullOrWhiteSpace(json))
            {
                var backupPath = LibraryFilePath + ".bak";
                if (File.Exists(backupPath))
                {
                    try
                    {
                        json = await File.ReadAllTextAsync(backupPath).ConfigureAwait(false);
                    }
                    catch
                    {
                        return;
                    }
                }
                else
                {
                    return;
                }
            }

            if (!TryDeserializeLibrary(json, out var persisted, out var legacyItems))
            {
                var backupPath = LibraryFilePath + ".bak";
                if (File.Exists(backupPath))
                {
                    try
                    {
                        var backupJson = await File.ReadAllTextAsync(backupPath).ConfigureAwait(false);
                        if (TryDeserializeLibrary(backupJson, out persisted, out legacyItems))
                            json = backupJson;
                    }
                    catch (Exception ex)
                    {
                        Debug.WriteLine($"[MediaCentre] Failed to read library backup: {ex.Message}");
                    }
                }
            }

            if ((persisted?.Items == null || persisted.Items.Count == 0) && (legacyItems == null || legacyItems.Count == 0))
            {
                var backupPath = LibraryFilePath + ".bak";
                if (File.Exists(backupPath))
                {
                    try
                    {
                        var backupJson = await File.ReadAllTextAsync(backupPath).ConfigureAwait(false);
                        if (TryDeserializeLibrary(backupJson, out persisted, out legacyItems))
                            json = backupJson;
                    }
                    catch
                    {
                        return;
                    }
                }
            }

            if ((persisted?.Items == null || persisted.Items.Count == 0) && (legacyItems == null || legacyItems.Count == 0))
                return;

            var ignoredSnapshot = (persisted?.IgnoredPaths ?? new List<string>())
                .Where(p => !string.IsNullOrWhiteSpace(p))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            List<MediaItem> rebuilt;
            try
            {
                if (legacyItems != null && legacyItems.Count > 0)
                {
                    var list = new List<MediaItem>(legacyItems.Count);
                    foreach (var i in legacyItems)
                    {
                        try
                        {
                            if (string.IsNullOrWhiteSpace(i.FilePath)) continue;

                            var type = i.SectionName ?? "";
                            var isGame = string.Equals(type, "games", StringComparison.OrdinalIgnoreCase);
                            var localPath = i.FilePath ?? "";
                            var title = i.DisplayName ?? Path.GetFileNameWithoutExtension(localPath) ?? "";
                            var year = 0;
                            if (!string.IsNullOrWhiteSpace(localPath) &&
                                (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase)) &&
                                !LooksLikeHomeVideo(localPath))
                            {
                                var cleaned = CleanVideoTitleFromFileName(localPath, out var y);
                                if (!string.IsNullOrWhiteSpace(cleaned))
                                    title = cleaned;
                                if (y > 0)
                                    year = y;
                            }

                            list.Add(new MediaItem
                            {
                                PlaybackItem = isGame ? null : i,
                                FilePath = i.FilePath,
                                Title = title,
                                Year = year,
                                Artist = i.Artist ?? "",
                                Album = i.Album ?? "",
                                TrackNumber = i.TrackNumber ?? 0,
                                DiscNumber = GetDiscNumberFromPath(i.FilePath),
                                Duration = i.Duration ?? TimeSpan.Zero,
                                Type = type,
                                AccentBrush = AccentForCategory(type),
                                IconGeometry = IconForCategory(type),
                                CoverImage = null
                            });
                        }
                        catch
                        {
                        }
                    }

                    rebuilt = list
                        .DistinctBy(x => x.FilePath, StringComparer.OrdinalIgnoreCase)
                        .ToList();
                }
                else
                {
                    var list = new List<MediaItem>(persisted!.Items.Count);
                    foreach (var i in persisted!.Items)
                    {
                        try
                        {
                            if (string.IsNullOrWhiteSpace(i.FilePath)) continue;

                            var type = i.Type ?? "";
                            var isGame = string.Equals(type, "games", StringComparison.OrdinalIgnoreCase);
                            var filePath = i.FilePath ?? "";
                            var isHttp = IsHttpUrl(filePath, out var uri);
                            var ext = isHttp
                                ? Path.GetExtension(uri.AbsolutePath).ToLowerInvariant()
                                : Path.GetExtension(filePath).ToLowerInvariant();
                            ScannerMediaType mediaType = ScannerMediaType.Unknown;
                            if (!isGame)
                            {
                                if (AudioExtensions.Contains(ext)) mediaType = ScannerMediaType.Audio;
                                else if (VideoExtensions.Contains(ext)) mediaType = ScannerMediaType.Video;
                                else if (ImageExtensions.Contains(ext)) mediaType = ScannerMediaType.Image;
                                else mediaType = GuessMediaTypeForCategory(type, ext);
                            }

                            ScannerMediaItem? playbackItem = null;
                            var yInit = 0;
                            if (!isGame)
                            {
                                var derivedYear = 0;
                                var derivedTitle = string.IsNullOrWhiteSpace(i.Title) ? Path.GetFileNameWithoutExtension(i.FilePath) : i.Title;
                                if (!string.IsNullOrWhiteSpace(filePath) &&
                                    mediaType == ScannerMediaType.Video &&
                                    (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase)) &&
                                    !LooksLikeHomeVideo(filePath))
                                {
                                    var cleaned = CleanVideoTitleFromFileName(filePath, out var y);
                                    if (!string.IsNullOrWhiteSpace(cleaned))
                                        derivedTitle = cleaned;
                                    if (y > 0)
                                        derivedYear = y;
                                }

                                yInit = derivedYear;

                                playbackItem = new ScannerMediaItem
                                {
                                    FilePath = filePath,
                                    DisplayName = derivedTitle,
                                    Extension = ext,
                                    FileSize = 0,
                                    LastModified = DateTime.UtcNow,
                                    MediaType = mediaType,
                                    SectionName = type,
                                    FolderPath = isHttp ? "" : (Path.GetDirectoryName(filePath) ?? ""),
                                    DateAdded = DateTime.UtcNow,
                                    Album = i.Album,
                                    Artist = i.Artist,
                                    TrackNumber = i.TrackNumber == 0 ? null : i.TrackNumber,
                                    Duration = i.DurationSeconds <= 0 ? null : TimeSpan.FromSeconds(i.DurationSeconds)
                                };
                            }

                            list.Add(new MediaItem
                            {
                                PlaybackItem = playbackItem,
                                FilePath = filePath,
                                MetaId = i.MetaId,
                                Title = playbackItem?.DisplayName ?? (i.Title ?? ""),
                                Metadata = i.Metadata ?? "",
                                Year = yInit,
                                Artist = i.Artist ?? "",
                                Album = i.Album ?? "",
                                TrackNumber = i.TrackNumber,
                                DiscNumber = i.DiscNumber > 0 ? i.DiscNumber : GetDiscNumberFromPath(i.FilePath),
                                Duration = i.DurationSeconds <= 0 ? TimeSpan.Zero : TimeSpan.FromSeconds(i.DurationSeconds),
                                Type = type,
                                AccentBrush = AccentForCategory(type),
                                IconGeometry = IconForCategory(type),
                                IsFavorite = i.IsFavorite,
                                LastAiOptimizedUtc = i.LastAiOptimizedUtc,
                                CoverUrl = i.CoverUrl,
                                CoverImage = null
                            });
                        }
                        catch
                        {
                        }
                    }

                    rebuilt = list
                        .DistinctBy(x => x.FilePath, StringComparer.OrdinalIgnoreCase)
                        .ToList();
                }
            }
            catch
            {
                return;
            }

            try
            {
                NormalizeKaraokeItems(rebuilt);
            }
            catch
            {
            }

            List<AlbumEntry>? albums = null;
            var musicTracks = rebuilt.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
            if (musicTracks.Count > 0)
                albums = BuildAlbumEntries(musicTracks, loadCovers: false);

            await _uiDispatcher.InvokeAsync(() =>
            {
                var defaultsAdded = false;
                lock (_stateLock)
                {
                    var existing = _allItems;
                    List<MediaItem> merged;
                    if (_libraryMutatedDuringLoad && existing.Count > 0)
                    {
                        var byPath = new Dictionary<string, MediaItem>(StringComparer.OrdinalIgnoreCase);
                        foreach (var i in rebuilt)
                        {
                            if (!string.IsNullOrWhiteSpace(i.FilePath))
                                byPath[i.FilePath] = i;
                        }
                        foreach (var i in existing)
                        {
                            if (!string.IsNullOrWhiteSpace(i.FilePath))
                                byPath[i.FilePath] = i;
                        }
                        merged = byPath.Values.ToList();
                    }
                    else
                    {
                        merged = rebuilt;
                    }

                    var existingIgnored = _ignoredPaths.ToList();
                    defaultsAdded = EnsureDefaultRadioStations(merged);
                    _allItems = merged;
                    _ignoredPaths.Clear();

                    foreach (var p in ignoredSnapshot)
                    {
                        if (!string.IsNullOrWhiteSpace(p))
                            _ignoredPaths.Add(p);
                    }
                    foreach (var p in existingIgnored)
                    {
                        if (!string.IsNullOrWhiteSpace(p))
                            _ignoredPaths.Add(p);
                    }
                    foreach (var i in merged)
                    {
                        if (!string.IsNullOrWhiteSpace(i.FilePath))
                            _ignoredPaths.Remove(i.FilePath);
                    }

                    _isLibraryLoaded = true;
                    _libraryMutatedDuringLoad = false;
                }

                if (defaultsAdded)
                {
                    try
                    {
                        List<MediaItem> snapshot;
                        lock (_stateLock) snapshot = _allItems.ToList();
                        _ = SaveLibraryToDiskAsync(snapshot);
                    }
                    catch
                    {
                    }
                }

                _musicAlbums.Clear();
                _musicAlbumRows.Clear();
                if (albums != null)
                {
                    foreach (var a in albums) _musicAlbums.Add(a);
                    RebuildAlbumRows();
                }

                foreach (var c in Categories)
                {
                    if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                        c.Count = _addonServers.Count;
                    else if (string.Equals(c.Id, "apps", StringComparison.OrdinalIgnoreCase))
                        c.Count = _appsServices.Count;
                    else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                        c.Count = _musicAlbums.Count;
                    else
                        c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
                }

                OnPropertyChanged(nameof(LibraryCountText));
                OnPropertyChanged(nameof(PlaytimeText));
                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));
                OnPropertyChanged(nameof(VisibleCountText));
                ApplyCategoryFilter();

                KickAutoEnrichVideoCovers(rebuilt);
            }, DispatcherPriority.Normal);
        }

        private static bool EnsureDefaultRadioStations(List<MediaItem> items)
        {
            try
            {
                if (items.Any(i => i != null && string.Equals(i.Type, "radio", StringComparison.OrdinalIgnoreCase)))
                    return false;

                var preset = new List<(string name, string url)>
                {
                    ("SomaFM: Groove Salad", "https://ice1.somafm.com/groovesalad-128-mp3"),
                    ("SomaFM: Drone Zone", "https://ice1.somafm.com/dronezone-128-mp3"),
                    ("SomaFM: Secret Agent", "https://ice1.somafm.com/secretagent-128-mp3"),
                    ("SomaFM: Indie Pop Rocks!", "https://ice1.somafm.com/indiepop-128-mp3"),
                    ("SomaFM: Beat Blender", "https://ice1.somafm.com/beatblender-128-mp3"),
                    ("SomaFM: DEF CON Radio", "https://ice1.somafm.com/defcon-128-mp3"),
                    ("SomaFM: Lush", "https://ice1.somafm.com/lush-128-mp3"),
                    ("SomaFM: Metal Detector", "https://ice1.somafm.com/metal-128-mp3"),
                    ("SomaFM: The Trip", "https://ice1.somafm.com/thetrip-128-mp3"),
                    ("SomaFM: SF 10-33", "https://ice1.somafm.com/sf1033-128-mp3")
                };

                var accent = AccentForCategory("radio");
                var icon = IconForCategory("radio");
                var now = DateTime.UtcNow;

                var existing = new HashSet<string>(
                    items.Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath)).Select(i => i.FilePath),
                    StringComparer.OrdinalIgnoreCase);

                var added = 0;
                foreach (var (name, url) in preset)
                {
                    var u = (url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(u)) continue;
                    if (existing.Contains(u)) continue;
                    var host = "";
                    try
                    {
                        if (Uri.TryCreate(u, UriKind.Absolute, out var uri))
                            host = (uri.Host ?? "").Trim();
                    }
                    catch
                    {
                        host = "";
                    }
                    var logoUrl = BuildStationLogoUrlFromStreamHost(host);

                    var playback = new ScannerMediaItem
                    {
                        FilePath = u,
                        DisplayName = name,
                        Extension = "",
                        FileSize = 0,
                        LastModified = now,
                        MediaType = ScannerMediaType.Audio,
                        SectionName = "radio",
                        FolderPath = "",
                        DateAdded = now,
                        Album = "Radio",
                        Artist = "",
                        TrackNumber = null,
                        Duration = null
                    };

                    items.Add(new MediaItem
                    {
                        PlaybackItem = playback,
                        FilePath = u,
                        Title = name,
                        Metadata = "",
                        Artist = "",
                        Album = "Radio",
                        TrackNumber = 0,
                        DiscNumber = 0,
                        SeasonNumber = 0,
                        EpisodeNumber = 0,
                        Duration = TimeSpan.Zero,
                        Year = 0,
                        Rating = 0,
                        Genres = Array.Empty<string>(),
                        Type = "radio",
                        AccentBrush = accent,
                        IconGeometry = icon,
                        CoverUrl = logoUrl,
                        CoverImage = null,
                        LastAiOptimizedUtc = null,
                        IsFavorite = false,
                        IsSelected = false,
                        IsPlaying = false
                    });
                    added++;
                }

                return added > 0;
            }
            catch
            {
                return false;
            }
        }

        private static void NormalizeKaraokeItems(List<MediaItem>? items)
        {
            if (items == null || items.Count == 0) return;

            for (int i = 0; i < items.Count; i++)
            {
                var item = items[i];
                if (item == null) continue;
                if (!string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase)) continue;
                if (!LooksLikeKaraokeTrack(item.FilePath, item.Album)) continue;

                var pb = item.PlaybackItem;
                if (pb != null)
                {
                    pb.SectionName = "Karaoke";
                    pb.MediaType = MediaScanner.MediaType.Video;
                }

                var next = new MediaItem
                {
                    PlaybackItem = pb,
                    FilePath = item.FilePath,
                    Title = item.Title,
                    Metadata = item.Metadata,
                    Artist = item.Artist,
                    Album = item.Album,
                    TrackNumber = item.TrackNumber,
                    DiscNumber = item.DiscNumber,
                    SeasonNumber = item.SeasonNumber,
                    EpisodeNumber = item.EpisodeNumber,
                    Duration = item.Duration,
                    Year = item.Year,
                    Rating = item.Rating,
                    Genres = item.Genres,
                    Type = "karaoke",
                    AccentBrush = AccentForCategory("karaoke"),
                    IconGeometry = IconForCategory("karaoke"),
                    CoverUrl = item.CoverUrl,
                    CoverImage = item.CoverImage,
                    LastAiOptimizedUtc = item.LastAiOptimizedUtc,
                    IsFavorite = item.IsFavorite,
                    IsSelected = item.IsSelected,
                    IsPlaying = item.IsPlaying
                };

                items[i] = next;
            }
        }

        private static bool LooksLikeKaraokeTrack(string? filePath, string? album)
        {
            var path = (filePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(path)) return false;

            try
            {
                if (Path.GetExtension(path).Equals(".cdg", StringComparison.OrdinalIgnoreCase)) return true;

                var dir = Path.GetDirectoryName(path) ?? "";
                if (!string.IsNullOrWhiteSpace(dir) &&
                    dir.Contains("karaoke", StringComparison.OrdinalIgnoreCase))
                    return true;

                var a = (album ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(a) &&
                    a.Contains("karaoke", StringComparison.OrdinalIgnoreCase))
                    return true;

                var baseName = Path.GetFileNameWithoutExtension(path);
                if (string.IsNullOrWhiteSpace(baseName)) return false;

                if (!string.IsNullOrWhiteSpace(dir))
                {
                    var cdg = Path.Combine(dir, baseName + ".cdg");
                    if (File.Exists(cdg)) return true;
                }
            }
            catch
            {
                return false;
            }

            return false;
        }

        private static bool IsCustomCoverPath(string? coverUrl)
        {
            try
            {
                var cu = (coverUrl ?? "").Trim();
                if (string.IsNullOrWhiteSpace(cu)) return false;

                if (Uri.TryCreate(cu, UriKind.Absolute, out var uri) && uri.IsFile)
                    cu = uri.LocalPath;

                if (string.IsNullOrWhiteSpace(cu) || !Path.IsPathRooted(cu)) return false;

                var customDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "CustomCovers");
                if (!cu.StartsWith(customDir, StringComparison.OrdinalIgnoreCase)) return false;
                return File.Exists(cu);
            }
            catch
            {
                return false;
            }
        }

        private Task SaveLibraryToDiskAsync(List<MediaItem> itemsSnapshot)
        {
            List<string> ignoredSnapshot;
            lock (_stateLock)
            {
                ignoredSnapshot = _ignoredPaths.ToList();
            }
            var task = SaveLibraryToDiskAfterLoadCoreAsync(itemsSnapshot, ignoredSnapshot);
            lock (_librarySaveTaskLock)
            {
                _lastLibrarySaveTask = task;
            }
            return task;
        }

        private async Task SaveLibraryToDiskAfterLoadCoreAsync(List<MediaItem> itemsSnapshot, List<string> ignoredSnapshot)
        {
            try
            {
                await _libraryLoadTask.ConfigureAwait(false);
            }
            catch
            {
            }

            if (itemsSnapshot.Count == 0 && File.Exists(LibraryFilePath))
                return;

            await _librarySaveGate.WaitAsync().ConfigureAwait(false);
            try
            {
                var directory = Path.GetDirectoryName(LibraryFilePath);
                if (!string.IsNullOrWhiteSpace(directory))
                    Directory.CreateDirectory(directory);

                var persisted = new PersistedLibrary
                {
                    Version = 2,
                    Items = itemsSnapshot.Select(i => new PersistedItem
                    {
                        FilePath = i.FilePath,
                        Type = i.Type,
                        MetaId = i.MetaId,
                        Title = i.Title,
                        Metadata = i.Metadata,
                        Artist = i.Artist,
                        Album = i.Album,
                        TrackNumber = i.TrackNumber,
                        DiscNumber = i.DiscNumber,
                        DurationSeconds = i.Duration.TotalSeconds,
                        IsFavorite = i.IsFavorite,
                        LastAiOptimizedUtc = i.LastAiOptimizedUtc,
                        CoverUrl = i.CoverUrl
                    }).ToList(),
                    IgnoredPaths = ignoredSnapshot
                };

                var json = JsonSerializer.Serialize(persisted, new JsonSerializerOptions { WriteIndented = true });
                var tmpPath = LibraryFilePath + ".tmp";
                await File.WriteAllTextAsync(tmpPath, json).ConfigureAwait(false);

                var backupPath = LibraryFilePath + ".bak";
                try
                {
                    if (File.Exists(LibraryFilePath))
                        File.Copy(LibraryFilePath, backupPath, overwrite: true);
                }
                catch
                {
                }

                File.Move(tmpPath, LibraryFilePath, overwrite: true);
            }
            catch (Exception ex)
            {
                Debug.WriteLine($"[MediaCentre] Failed to save library: {ex.Message}");
            }
            finally
            {
                _librarySaveGate.Release();
            }
        }

        public void FlushLibrarySavesBlocking()
        {
            Task task;
            lock (_librarySaveTaskLock)
            {
                task = _lastLibrarySaveTask;
            }

            try
            {
                task.GetAwaiter().GetResult();
            }
            catch
            {
            }
        }

        private static bool TryDeserializeLibrary(string json, out PersistedLibrary? persisted, out List<ScannerMediaItem>? legacyItems)
        {
            persisted = null;
            legacyItems = null;

            try
            {
                persisted = JsonSerializer.Deserialize<PersistedLibrary>(json);
            }
            catch
            {
                persisted = null;
            }

            if (persisted != null)
                return persisted.Items != null && persisted.Items.Count > 0;

            try
            {
                legacyItems = JsonSerializer.Deserialize<List<ScannerMediaItem>>(json);
            }
            catch
            {
                legacyItems = null;
            }

            return legacyItems != null && legacyItems.Count > 0;
        }

