        public void StartLibraryLoading()
        {
            if (_libraryLoadingStarted)
                return;

            _libraryLoadingStarted = true;

            // Start background initialization tasks
            Task.Run(() =>
            {
                try
                {
                    EnsureDefaultAddonServersSeeded();
                    _uiDispatcher.Invoke(RefreshAddonServers);
                    _uiDispatcher.Invoke(EnsureAddonServersConfigWatcher);
                    _uiDispatcher.Invoke(ResetMediaWatchers);
                }
                catch (Exception ex)
                {
                    Debug.WriteLine($"[MediaCentreViewModel] Background init failed: {ex.Message}");
                }
            });

            _libraryLoadTask = LoadLibraryFromDiskAsync();
        }

        private static string BuildServerCatalogDedupeKey(MediaItem? i)
        {
            try
            {
                if (i == null) return "";

                var type = (i.Type ?? "").Trim().ToLowerInvariant();
                if (string.IsNullOrWhiteSpace(type))
                    type = "unknown";
                if (type == "movie") type = "movies";
                if (type == "series") type = "tv";

                var stableId = (i.MetaId ?? "").Trim();

                if (string.IsNullOrWhiteSpace(stableId))
                    stableId = (i.ImdbId ?? "").Trim();

                if (string.IsNullOrWhiteSpace(stableId) && i.TmdbId.HasValue && i.TmdbId.Value > 0)
                    stableId = $"tmdb:{i.TmdbId.Value}";

                if (string.IsNullOrWhiteSpace(stableId))
                    stableId = (i.FilePath ?? "").Trim();

                var isMovieOrTv = type is "movies" or "tv";
                if (string.IsNullOrWhiteSpace(stableId) && isMovieOrTv)
                {
                    var titleKey = NormalizeTitleKey(i.Title ?? "");
                    if (!string.IsNullOrWhiteSpace(titleKey) && i.Year > 0)
                        stableId = $"{titleKey}|{i.Year}";
                }

                if (string.IsNullOrWhiteSpace(stableId))
                {
                    var title = (i.Title ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(title) && i.Year > 0)
                        stableId = $"{title}|{i.Year}";
                    else
                        stableId = title;
                }

                stableId = (stableId ?? "").Trim();
                if (string.IsNullOrWhiteSpace(stableId))
                    return "";

                return $"{type}|{stableId}";
            }
            catch
            {
                return "";
            }
        }

        private static bool LooksLikeLocalServerNoise(string? value, bool allowBareFileNames)
        {
            try
            {
                var text = (value ?? "").Trim();
                if (string.IsNullOrWhiteSpace(text)) return false;

                if (string.Equals(text, "downloads", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(text, "download", StringComparison.OrdinalIgnoreCase))
                    return true;

                if (text.StartsWith(@"\\", StringComparison.Ordinal) || Regex.IsMatch(text, @"^[a-zA-Z]:\\"))
                    return true;

                if (text.Contains("\\downloads\\", StringComparison.OrdinalIgnoreCase) ||
                    text.Contains("/downloads/", StringComparison.OrdinalIgnoreCase))
                    return true;

                if (allowBareFileNames)
                    return false;

                return false;
            }
            catch
            {
                return false;
            }
        }

        private static bool ShouldIncludeServerCatalogMeta(string? id, string? title)
        {
            var normalizedTitle = (title ?? "").Trim();
            if (string.IsNullOrWhiteSpace(normalizedTitle))
                return false;

            if (LooksLikeLocalServerNoise(normalizedTitle, allowBareFileNames: false))
                return false;

            var normalizedId = (id ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(normalizedId) && LooksLikeLocalServerNoise(normalizedId, allowBareFileNames: true))
                return false;

            return true;
        }

        private void SyncAppsBookmarksFromPrefs(UserPreferences prefs)
        {
            var selectedId = SelectedAppsBookmarkId ?? "";
            try
            {
                _appsBookmarks.Clear();
                var list = prefs?.AppsBookmarks ?? new List<UserPreferences.AppBookmark>();
                foreach (var b in list)
                {
                    if (b == null) continue;
                    var id = (b.Id ?? "").Trim();
                    var name = (b.Name ?? "").Trim();
                    var url = (b.Url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(url)) continue;
                    if (string.IsNullOrWhiteSpace(id)) continue;
                    var iconUrl = "";
                    try
                    {
                        if (Uri.TryCreate(url, UriKind.Absolute, out var u))
                            iconUrl = new Uri(u, "/favicon.ico").ToString();
                    }
                    catch
                    {
                        iconUrl = "";
                    }
                    _appsBookmarks.Add(new AppsBookmarkEntry { Id = id, Name = string.IsNullOrWhiteSpace(name) ? url : name, Url = url, IconUrl = iconUrl });
                }
            }
            catch
            {
                _appsBookmarks.Clear();
            }
            if (!string.IsNullOrWhiteSpace(selectedId) && _appsBookmarks.All(b => !string.Equals(b.Id, selectedId, StringComparison.OrdinalIgnoreCase)))
            {
                SelectedAppsBookmarkId = "";
                SelectedAppsBookmarkName = "";
                AppsCredentialUser = "";
                AppsCredentialSecret = "";
                AppsCredentialStatusText = "";
            }
            CommandManager.InvalidateRequerySuggested();
        }

        private static string FaviconFor(string url)
        {
            try
            {
                if (!Uri.TryCreate(url, UriKind.Absolute, out var u)) return "";
                var safe = Uri.EscapeDataString(u.GetLeftPart(UriPartial.Authority));
                return $"https://www.google.com/s2/favicons?sz=64&domain_url={safe}";
            }
            catch
            {
                return "";
            }
        }

