        private bool CanAddAppsBookmark()
        {
            var raw = (AppsBookmarkUrl ?? "").Trim();
            if (string.IsNullOrWhiteSpace(raw)) return false;
            return Uri.TryCreate(raw, UriKind.Absolute, out var u) &&
                   (string.Equals(u.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(u.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase));
        }

        private void AddAppsBookmark()
        {
            var raw = (AppsBookmarkUrl ?? "").Trim();
            if (string.IsNullOrWhiteSpace(raw)) return;
            if (!Uri.TryCreate(raw, UriKind.Absolute, out var uri)) return;
            if (!string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
                return;

            var url = uri.ToString();
            var name = (AppsBookmarkName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(name))
                name = (uri.Host ?? "").Trim();
            if (string.IsNullOrWhiteSpace(name))
                name = "Bookmark";

            PreferencesStore.Instance.Update(p =>
            {
                p.AppsBookmarks ??= new List<UserPreferences.AppBookmark>();
                p.AppsBookmarks.Add(new UserPreferences.AppBookmark { Id = Guid.NewGuid().ToString("N"), Name = name, Url = url });
            });

            AppsBookmarkName = "";
            AppsBookmarkUrl = "";
        }

        private void RemoveAppsBookmark(AppsBookmarkEntry? bookmark)
        {
            if (bookmark == null) return;
            var id = (bookmark.Id ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id)) return;

            PreferencesStore.Instance.Update(p =>
            {
                p.AppsBookmarks ??= new List<UserPreferences.AppBookmark>();
                p.AppsBookmarks.RemoveAll(b => b != null && string.Equals((b.Id ?? "").Trim(), id, StringComparison.OrdinalIgnoreCase));
            });
        }

