        private void SaveAppsCredential()
        {
            var id = (SelectedAppsBookmarkId ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id)) return;
            var userKey = $"apps_cred_{id}_user";
            var secretKey = $"apps_cred_{id}_secret";

            try
            {
                var user = (AppsCredentialUser ?? "").Trim();
                var secret = AppsCredentialSecret ?? "";
                if (string.IsNullOrWhiteSpace(user))
                    AtlasAI.Core.IntegrationKeyStore.Delete(userKey);
                else
                    AtlasAI.Core.IntegrationKeyStore.SetProtected(userKey, user);

                if (string.IsNullOrEmpty(secret))
                    AtlasAI.Core.IntegrationKeyStore.Delete(secretKey);
                else
                    AtlasAI.Core.IntegrationKeyStore.SetProtected(secretKey, secret);

                AppsCredentialStatusText = "Saved credentials";
            }
            catch (Exception ex)
            {
                AppsCredentialStatusText = ex.Message;
            }
        }

