        private static string BuildNowPlayingTitle(string displayName, string matchTitle)
        {
            var title = (matchTitle ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(title))
                return title;

            var dn = (displayName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(dn))
                return "Unknown";

            if (IsProbablyUrl(dn))
                dn = TryGetFilenameFromUrl(dn);

            try
            {
                if (dn.Contains('\\') || dn.Contains('/'))
                    dn = System.IO.Path.GetFileNameWithoutExtension(dn);
            }
            catch
            {
            }

            if (string.IsNullOrWhiteSpace(dn))
                return "Unknown";
            return dn;
        }

        private static bool IsProbablyUrl(string s)
        {
            try
            {
                return Uri.TryCreate(s, UriKind.Absolute, out var u) &&
                       (string.Equals(u.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(u.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(u.Scheme, "magnet", StringComparison.OrdinalIgnoreCase));
            }
            catch
            {
                return false;
            }
        }

        private static string TryGetFilenameFromUrl(string url)
        {
            try
            {
                if (!Uri.TryCreate(url, UriKind.Absolute, out var u))
                    return url;
                if (string.Equals(u.Scheme, "magnet", StringComparison.OrdinalIgnoreCase))
                {
                    var q = System.Web.HttpUtility.ParseQueryString(u.Query ?? "");
                    var dn = q.Get("dn");
                    if (!string.IsNullOrWhiteSpace(dn))
                        return dn;
                    return "Stream";
                }
                var path = (u.AbsolutePath ?? "").Trim();
                if (string.IsNullOrWhiteSpace(path))
                    return url;
                var seg = path.Split('/').LastOrDefault() ?? "";
                seg = Uri.UnescapeDataString(seg);
                return string.IsNullOrWhiteSpace(seg) ? url : seg;
            }
            catch
            {
                return url;
            }
        }

        private async Task LoadHomeShelvesAsync(CancellationToken ct)
        {
            try
            {
                var moviesUrl = "https://v3-cinemeta.strem.io/catalog/movie/top.json";
                var seriesUrl = "https://v3-cinemeta.strem.io/catalog/series/top.json";

                var movies = await FetchCinemetaTopAsync(moviesUrl, "movies", ct).ConfigureAwait(false);
                var series = await FetchCinemetaTopAsync(seriesUrl, "tv", ct).ConfigureAwait(false);

                _uiDispatcher.Invoke(() =>
                {
                    try
                    {
                        HomePopularMovies.Clear();
                        foreach (var m in movies.Take(20))
                        {
                            HomePopularMovies.Add(m);
                            _ = TryLoadCoverIntoItemAsync(m, CancellationToken.None);
                        }
                        HomePopularSeries.Clear();
                        foreach (var s in series.Take(20))
                        {
                            HomePopularSeries.Add(s);
                            _ = TryLoadCoverIntoItemAsync(s, CancellationToken.None);
                        }
                        RefreshHomeContinue();
                    }
                    catch
                    {
                    }
                });
            }
            catch
            {
            }
        }

        private void RefreshHomeContinue()
        {
            try
            {
                var recent = AtlasAI.Core.WatchHistoryStore.GetRecent(12);
                var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                var items = new List<MediaItem>();
                foreach (var r in recent)
                {
                    var id = AtlasAI.Core.WatchHistoryStore.NormalizeIdentity(r.filePath);
                    if (string.IsNullOrWhiteSpace(id)) continue;
                    if (!id.Contains('\\') && !id.Contains('/') && !LooksLikeStableMediaIdToken(id))
                        continue;
                    if (!seen.Add(id)) continue;
                    items.Add(new MediaItem
                    {
                        FilePath = id,
                        MetaId = id,
                        Title = r.title,
                        Type = r.type,
                        CoverUrl = r.coverUrl,
                        BackdropUrl = r.backdropUrl
                    });
                }
                _uiDispatcher.Invoke(() =>
                {
                    HomeContinueItems.Clear();
                    foreach (var i in items)
                    {
                        HomeContinueItems.Add(i);
                        _ = TryLoadCoverIntoItemAsync(i, CancellationToken.None);
                    }
                });
            }
            catch
            {
            }
        }

        private async Task<List<MediaItem>> FetchCinemetaTopAsync(string url, string type, CancellationToken ct)
        {
            var list = new List<MediaItem>();
            try
            {
                using var resp = await PreviewHttp.GetAsync(url, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode) return list;
                await using var s = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(s, cancellationToken: ct).ConfigureAwait(false);
                if (doc.RootElement.ValueKind != JsonValueKind.Object) return list;
                if (!doc.RootElement.TryGetProperty("metas", out var metas) || metas.ValueKind != JsonValueKind.Array) return list;
                foreach (var el in metas.EnumerateArray())
                {
                    if (ct.IsCancellationRequested) break;
                    if (el.ValueKind != JsonValueKind.Object) continue;
                    var id = el.TryGetProperty("id", out var idEl) && idEl.ValueKind == JsonValueKind.String ? (idEl.GetString() ?? "").Trim() : "";
                    var name = el.TryGetProperty("name", out var nmEl) && nmEl.ValueKind == JsonValueKind.String ? (nmEl.GetString() ?? "").Trim() : "";
                    var poster = el.TryGetProperty("poster", out var poEl) && poEl.ValueKind == JsonValueKind.String ? (poEl.GetString() ?? "").Trim() : "";
                    var bg = el.TryGetProperty("background", out var bgEl) && bgEl.ValueKind == JsonValueKind.String ? (bgEl.GetString() ?? "").Trim() : "";
                    if (string.IsNullOrWhiteSpace(name)) continue;
                    var m = new MediaItem
                    {
                        FilePath = id,
                        Title = name,
                        Type = type,
                        CoverUrl = poster,
                        BackdropUrl = bg
                    };
                    list.Add(m);
                }
            }
            catch
            {
            }
            return list;
        }

