        private void SelectCategory(MediaCategory? category)
        {
            if (category == null) return;

            if (!string.Equals(category.Id, "servers", StringComparison.OrdinalIgnoreCase))
                _lastNonServersCategory = category;
            else if (SelectedCategory != null && !string.Equals(SelectedCategory.Id, "servers", StringComparison.OrdinalIgnoreCase))
                _lastNonServersCategory = SelectedCategory;
            foreach (var c in Categories) c.IsActive = ReferenceEquals(c, category);
            SelectedCategory = category;
            SelectedAlbum = null;
            StatusText = "Loading...";
            IsStreamsOpen = false;
            if (!string.Equals(category.Id, "servers", StringComparison.OrdinalIgnoreCase))
            {
                IsServerStreamsPanelOpen = false;
                IsServerSeriesPanelOpen = false;
                IsWatchLaterPanelOpen = false;
                IsContinuePanelOpen = false;
                _serverStreamsBackToSeries = false;
                ClearServerSeriesState(clearRoot: true);
            }

            OnPropertyChanged(nameof(IsMusicView));
            OnPropertyChanged(nameof(IsMusicAlbumsView));
            OnPropertyChanged(nameof(IsAlbumTracksView));
            OnPropertyChanged(nameof(IsRadioView));
            OnPropertyChanged(nameof(IsAppsView));
            OnPropertyChanged(nameof(IsStandardTracksView));
            OnPropertyChanged(nameof(IsCloudView));
            OnPropertyChanged(nameof(IsServersView));
            OnPropertyChanged(nameof(IsServerCatalogPanelOpen));
            OnPropertyChanged(nameof(IsDownloadsView));
            OnPropertyChanged(nameof(IsMoviesOrTvView));
            OnPropertyChanged(nameof(HasCloudProviders));
            OnPropertyChanged(nameof(IsMoviesCoversView));
            OnPropertyChanged(nameof(IsNotMoviesCoversView));
            OnPropertyChanged(nameof(IsGamesView));
            OnPropertyChanged(nameof(LibraryHeaderText));
            OnPropertyChanged(nameof(VisibleCountText));
            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));

            // Set CurrentSection based on category
            CurrentSection = category?.Id?.ToLowerInvariant() switch
            {
                "movies" => this, // Reuse existing VM for movies
                "tv" => this, // Reuse existing VM for TV
                "music" => this, // Reuse existing VM for music
                "radio" => this, // Reuse existing VM for radio
                "games" => this, // Reuse existing VM for games
                _ => this // Default to current VM
            };

            // Offload blocking operations to background thread to prevent UI freeze
            System.Diagnostics.Debug.WriteLine($"[MediaCentre] SelectCategory: {category?.Id} - Starting async load");
            _ = Task.Run(async () =>
            {
                try
                {
                    System.Diagnostics.Debug.WriteLine($"[MediaCentre] Background thread started for {category?.Id}");
                    // Apply category filter on background thread
                    await _uiDispatcher.InvokeAsync(() => ApplyCategoryFilter());

                    // Load category-specific content
                    if (string.Equals(category.Id, "movies", StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(category.Id, "tv", StringComparison.OrdinalIgnoreCase))
                    {
                        var itemsSnapshot = await _uiDispatcher.InvokeAsync(() => LibraryItems.ToList());
                        await Task.Run(() => KickAutoEnrichVideoCovers(itemsSnapshot));
                    }
                    else if (string.Equals(category.Id, "music", StringComparison.OrdinalIgnoreCase))
                    {
                        await Task.Run(() =>
                        {
                            KickLoadMusicAlbumCovers();
                            // DISABLED: FixMusicAlbums causes UI freeze on section switch
                            // User can manually trigger via FIX ALBUMS button if needed
                            // FixMusicAlbums();
                        });
                    }
                    else if (string.Equals(category.Id, "cloud", StringComparison.OrdinalIgnoreCase))
                    {
                        await Task.Run(() => RefreshCloudLibrary());
                    }
                    else if (string.Equals(category.Id, "servers", StringComparison.OrdinalIgnoreCase))
                    {
                        await _uiDispatcher.InvokeAsync(() => RefreshAddonServers());
                        await RefreshServerCatalogAsync();
                    }

                    // Update status when done
                    System.Diagnostics.Debug.WriteLine($"[MediaCentre] Background load complete for {category?.Id}");
                    await _uiDispatcher.InvokeAsync(() =>
                    {
                        StatusText = "Ready";
                        try
                        {
                            MediaItem? candidate = null;
                            if (IsServersView)
                            {
                                if (PreviewItem == null || !_serverCatalogItems.Contains(PreviewItem))
                                    candidate = _serverCatalogItems.FirstOrDefault();
                            }
                            else
                            {
                                if (PreviewItem == null || !LibraryItems.Contains(PreviewItem))
                                    candidate = LibraryItems.FirstOrDefault();
                            }

                            if (candidate != null)
                                SetPreviewItem(candidate);
                        }
                        catch
                        {
                        }
                        OnPropertyChanged(nameof(HasPreviewItem));
                        CommandManager.InvalidateRequerySuggested();
                    });
                }
                catch (Exception ex)
                {
                    System.Diagnostics.Debug.WriteLine($"[MediaCentre] Error loading category {category?.Id}: {ex.Message}");
                    System.Diagnostics.Debug.WriteLine($"[MediaCentre] Stack trace: {ex.StackTrace}");
                    await _uiDispatcher.InvokeAsync(() =>
                    {
                        StatusText = $"Error loading {category?.Label ?? "content"}";
                    });
                }
            });

            if (string.Equals(category.Id, "games", StringComparison.OrdinalIgnoreCase) && !_gamesDiscovered)
            {
                _gamesDiscovered = true;
                DiscoverGamesAsync();
            }

            if (IsLibraryOpen)
                IsLibraryOpen = false;
        }

        private void SearchMedia()
        {
            var query = (SearchQuery ?? "").Trim();
            if (IsStreamsOpen || IsServerStreamsPanelOpen)
            {
                StreamsSearchQuery = query;
                return;
            }
            if (IsServerSeriesPanelOpen)
            {
                ServerSeriesSearchQuery = query;
                return;
            }
            if (IsServerCatalogPanelOpen)
            {
                ServerCatalogSearchQuery = query;
                return;
            }
            if (IsServersView)
            {
                ServerCatalogSearchQuery = query;
                return;
            }

            if (string.IsNullOrWhiteSpace(query))
            {
                if (IsMusicAlbumsView)
                {
                    RebuildMusicAlbums();
                }
                else
                {
                    ApplyCategoryFilter();
                }
                return;
            }

            if (IsMusicAlbumsView)
            {
                var musicTracks = _allItems.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
                var qn = NormalizeSearchText(query);
                var tokens = Regex.Split(qn, "\\s+")
                    .Select(t => (t ?? "").Trim())
                    .Where(t => !string.IsNullOrWhiteSpace(t) && t.Length >= 2)
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToArray();

                var albums = BuildAlbumEntries(musicTracks, loadCovers: false)
                    .Where(a =>
                    {
                        if (tokens.Length == 0) return true;

                        var composite = $"{a.Artist ?? ""} {a.AlbumTitle ?? ""}";
                        var tracks = a.Tracks?.Take(40).ToList() ?? new List<MediaItem>();
                        foreach (var tr in tracks)
                        {
                            var fp = (tr.FilePath ?? "").Trim();
                            var name = string.IsNullOrWhiteSpace(fp) ? "" : (Path.GetFileNameWithoutExtension(fp) ?? "");
                            composite += $" {tr.Title ?? ""} {tr.Artist ?? ""} {tr.Album ?? ""} {name} {fp}";
                        }

                        var cn = NormalizeSearchText(composite);
                        foreach (var t in tokens)
                        {
                            if (!cn.Contains(t, StringComparison.OrdinalIgnoreCase))
                                return false;
                        }
                        return true;
                    })
                    .ToList();

                _musicAlbums.Clear();
                foreach (var a in albums) _musicAlbums.Add(a);
                RebuildAlbumRows();
                KickLoadMusicAlbumCovers();

                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));
                OnPropertyChanged(nameof(VisibleCountText));
                return;
            }

            IEnumerable<MediaItem> baseItems;
            if (IsAlbumTracksView && SelectedAlbum != null)
            {
                baseItems = SelectedAlbum.Tracks;
            }
            else
            {
                var id = SelectedCategory?.Id ?? "";
                baseItems = string.IsNullOrWhiteSpace(id)
                    ? _allItems
                    : _allItems.Where(i => string.Equals(i.Type, id, StringComparison.OrdinalIgnoreCase));
            }

            var results = baseItems.Where(i =>
                (i.Title ?? "").Contains(query, StringComparison.OrdinalIgnoreCase) ||
                (i.Artist ?? "").Contains(query, StringComparison.OrdinalIgnoreCase) ||
                (i.Album ?? "").Contains(query, StringComparison.OrdinalIgnoreCase)
            ).ToList();

            if (LibraryItems is FastObservableCollection<MediaItem> fast)
                fast.ReplaceWith(results);
            else
            {
                LibraryItems.Clear();
                foreach (var item in results) LibraryItems.Add(item);
            }
        }

