        private static string CreateM3uPlaylist(string outputFolder, string csvPath, IReadOnlyList<MediaItem> items, IReadOnlyDictionary<string, string>? resolvedPaths)
        {
            outputFolder = (outputFolder ?? "").Trim();
            if (string.IsNullOrWhiteSpace(outputFolder)) throw new InvalidOperationException("No output folder");
            Directory.CreateDirectory(outputFolder);

            var baseName = "";
            try { baseName = Path.GetFileNameWithoutExtension(csvPath) ?? ""; } catch { baseName = ""; }
            baseName = SanitizeFileName(baseName);
            if (string.IsNullOrWhiteSpace(baseName)) baseName = "playlist";

            var playlistPath = BuildUniquePlaylistPath(outputFolder, baseName);
            var lines = new List<string> { "#EXTM3U" };

            foreach (var it in items ?? Array.Empty<MediaItem>())
            {
                if (it == null) continue;

                var title = (it.Title ?? "").Trim();
                if (string.IsNullOrWhiteSpace(title)) title = "Track";
                var artist = (it.Artist ?? "").Trim();
                var label = string.IsNullOrWhiteSpace(artist) ? title : $"{artist} - {title}";

                var pathOrUrl = "";
                try
                {
                    var fp = (it.FilePath ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(fp) && resolvedPaths != null && resolvedPaths.TryGetValue(fp, out var mappedAny) && !string.IsNullOrWhiteSpace(mappedAny))
                    {
                        pathOrUrl = mappedAny;
                    }
                    else if (!string.IsNullOrWhiteSpace(fp) && File.Exists(fp))
                    {
                        if (resolvedPaths != null && resolvedPaths.TryGetValue(fp, out var mapped) && !string.IsNullOrWhiteSpace(mapped))
                            pathOrUrl = mapped;
                        else
                            pathOrUrl = fp;
                    }
                    else
                        pathOrUrl = (it.DownloadUrl ?? fp).Trim();
                }
                catch
                {
                    pathOrUrl = (it.DownloadUrl ?? it.FilePath ?? "").Trim();
                }

                if (string.IsNullOrWhiteSpace(pathOrUrl)) continue;

                lines.Add($"#EXTINF:-1,{label}");
                lines.Add(pathOrUrl);
            }

            File.WriteAllLines(playlistPath, lines, new UTF8Encoding(encoderShouldEmitUTF8Identifier: false));
            return playlistPath;
        }

        private static string BuildUniquePlaylistPath(string folder, string baseName)
        {
            folder = (folder ?? "").Trim();
            baseName = (baseName ?? "").Trim();
            Directory.CreateDirectory(folder);

            var path = Path.Combine(folder, baseName + ".m3u");
            if (!File.Exists(path)) return path;

            for (var i = 2; i < 10_000; i++)
            {
                var next = Path.Combine(folder, $"{baseName} ({i}).m3u");
                if (!File.Exists(next)) return next;
            }
            throw new IOException("Too many duplicates");
        }

        private async Task<Dictionary<string, string>> TryMaterializeMp3OutputsAsync(string outputFolder, IReadOnlyList<MediaItem> items)
        {
            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

            outputFolder = (outputFolder ?? "").Trim();
            if (string.IsNullOrWhiteSpace(outputFolder)) return result;

            string ffmpegExe;
            try
            {
                ffmpegExe = ResolveFfmpegExecutable();
            }
            catch
            {
                ffmpegExe = "";
            }

            if (string.IsNullOrWhiteSpace(ffmpegExe) || !File.Exists(ffmpegExe))
            {
                try
                {
                    using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));
                    var ensured = await EnsureFfmpegAsync(cts.Token).ConfigureAwait(false);
                    if (!string.IsNullOrWhiteSpace(ensured) && File.Exists(ensured))
                        ffmpegExe = ensured!;
                }
                catch
                {
                }
                if (string.IsNullOrWhiteSpace(ffmpegExe) || !File.Exists(ffmpegExe))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        StatusText = "FFmpeg not found";
                        OnPropertyChanged(nameof(StatusText));
                    });
                    return result;
                }
            }

            var localItems = (items ?? Array.Empty<MediaItem>())
                .Where(i => i != null)
                .Select(i => i!)
                .Where(i => !string.IsNullOrWhiteSpace(i.FilePath))
                .ToList();

            var total = localItems.Count;
            var idx = 0;

            foreach (var it in localItems)
            {
                idx++;
                var src = (it.FilePath ?? "").Trim();
                if (string.IsNullOrWhiteSpace(src)) continue;
                try { if (!File.Exists(src)) continue; } catch { continue; }

                var dst = "";
                try
                {
                    dst = BuildUniqueOutputMp3Path(outputFolder, it);
                }
                catch
                {
                    continue;
                }

                _uiDispatcher.Invoke(() =>
                {
                    StatusText = $"Converting to MP3 {idx}/{total}";
                    OnPropertyChanged(nameof(StatusText));
                });

                try
                {
                    var ext = "";
                    try { ext = Path.GetExtension(src); } catch { ext = ""; }

                    if (string.Equals(ext, ".mp3", StringComparison.OrdinalIgnoreCase))
                    {
                        Directory.CreateDirectory(Path.GetDirectoryName(dst) ?? outputFolder);
                        File.Copy(src, dst, overwrite: false);
                        result[src] = dst;
                        continue;
                    }

                    Directory.CreateDirectory(Path.GetDirectoryName(dst) ?? outputFolder);
                    var args = $"-hide_banner -loglevel error -y -i \"{src}\" -vn -codec:a libmp3lame -q:a 0 \"{dst}\"";
                    using var proc = new Process
                    {
                        StartInfo = new ProcessStartInfo
                        {
                            FileName = ffmpegExe,
                            Arguments = args,
                            UseShellExecute = false,
                            CreateNoWindow = true,
                            RedirectStandardError = true,
                            RedirectStandardOutput = true
                        }
                    };

                    proc.Start();
                    await proc.WaitForExitAsync().ConfigureAwait(false);
                    if (proc.ExitCode == 0 && File.Exists(dst))
                        result[src] = dst;
                }
                catch
                {
                }
            }

            _uiDispatcher.Invoke(() =>
            {
                StatusText = result.Count > 0 ? $"MP3 ready · {result.Count} file(s)" : "MP3 convert failed";
                OnPropertyChanged(nameof(StatusText));
            });

            return result;
        }

        private static string BuildUniqueOutputMp3Path(string outputFolder, MediaItem item)
        {
            outputFolder = (outputFolder ?? "").Trim();
            Directory.CreateDirectory(outputFolder);

            var title = (item.Title ?? "").Trim();
            var artist = (item.Artist ?? "").Trim();
            var baseName = string.IsNullOrWhiteSpace(artist) ? title : $"{artist} - {title}";
            baseName = SanitizeFileName(baseName);
            if (string.IsNullOrWhiteSpace(baseName)) baseName = "track";

            var path = Path.Combine(outputFolder, baseName + ".mp3");
            if (!File.Exists(path)) return path;

            for (var i = 2; i < 10_000; i++)
            {
                var next = Path.Combine(outputFolder, $"{baseName} ({i}).mp3");
                if (!File.Exists(next)) return next;
            }
            throw new IOException("Too many duplicates");
        }

        private static string ResolveFfmpegExecutable()
        {
            var baseDir = AppContext.BaseDirectory;
            var p1 = Path.Combine(baseDir, "ffmpeg", "ffmpeg.exe");
            if (File.Exists(p1)) return p1;

            var cwd = Environment.CurrentDirectory;
            var p2 = Path.Combine(cwd, "ffmpeg", "ffmpeg.exe");
            if (File.Exists(p2)) return p2;

            try
            {
                var p3 = Path.Combine(baseDir, "ffmpeg.exe");
                if (File.Exists(p3)) return p3;
            }
            catch
            {
            }
            try
            {
                var p4 = Path.Combine(cwd, "ffmpeg.exe");
                if (File.Exists(p4)) return p4;
            }
            catch
            {
            }
            return "ffmpeg";
        }

        private async Task<string?> EnsureYtDlpAsync(CancellationToken ct)
        {
            try
            {
                var baseDir = AppContext.BaseDirectory;
                var p1 = Path.Combine(baseDir, "yt-dlp", "yt-dlp.exe");
                if (File.Exists(p1)) return p1;

                var cwd = Environment.CurrentDirectory;
                var p2 = Path.Combine(cwd, "yt-dlp", "yt-dlp.exe");
                if (File.Exists(p2)) return p2;

                Directory.CreateDirectory(Path.GetDirectoryName(p2) ?? cwd);
                var tmp = p2 + ".tmp";
                try { if (File.Exists(tmp)) File.Delete(tmp); } catch { }

                using var resp = await ServerHttp.GetAsync("https://github.com/yt-dlp/yt-dlp/releases/latest/download/yt-dlp.exe", HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                resp.EnsureSuccessStatusCode();
                await using (var src = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false))
                await using (var dst = new FileStream(tmp, FileMode.Create, FileAccess.Write, FileShare.None, 81920, useAsync: true))
                {
                    await src.CopyToAsync(dst, ct).ConfigureAwait(false);
                }
                try
                {
                    if (File.Exists(p2)) File.Delete(p2);
                }
                catch
                {
                }
                File.Move(tmp, p2);
                return p2;
            }
            catch
            {
                return null;
            }
        }

        private async Task<string?> EnsureFfmpegAsync(CancellationToken ct)
        {
            try
            {
                var baseDir = AppContext.BaseDirectory;
                var p1 = Path.Combine(baseDir, "ffmpeg", "ffmpeg.exe");
                if (File.Exists(p1)) return p1;
                var p3 = Path.Combine(baseDir, "ffmpeg.exe");
                if (File.Exists(p3)) return p3;

                var cwd = Environment.CurrentDirectory;
                var p2 = Path.Combine(cwd, "ffmpeg", "ffmpeg.exe");
                if (File.Exists(p2)) return p2;
                var p4 = Path.Combine(cwd, "ffmpeg.exe");
                if (File.Exists(p4)) return p4;

                var targetDir = Path.Combine(cwd, "ffmpeg");
                Directory.CreateDirectory(targetDir);
                var destExe = Path.Combine(targetDir, "ffmpeg.exe");
                if (File.Exists(destExe)) return destExe;

                var tmpZip = Path.Combine(targetDir, "ffmpeg.zip.tmp");
                try { if (File.Exists(tmpZip)) File.Delete(tmpZip); } catch { }

                using var resp = await ServerHttp.GetAsync("https://github.com/BtbN/FFmpeg-Builds/releases/latest/download/ffmpeg-master-latest-win64-gpl.zip", HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                resp.EnsureSuccessStatusCode();
                await using (var src = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false))
                await using (var dst = new FileStream(tmpZip, FileMode.Create, FileAccess.Write, FileShare.None, 81920, useAsync: true))
                {
                    await src.CopyToAsync(dst, ct).ConfigureAwait(false);
                }

                var extractDir = Path.Combine(targetDir, "extracted_" + Guid.NewGuid().ToString("N"));
                Directory.CreateDirectory(extractDir);
                try
                {
                    System.IO.Compression.ZipFile.ExtractToDirectory(tmpZip, extractDir);
                }
                catch
                {
                    try { Directory.Delete(extractDir, recursive: true); } catch { }
                    try { File.Delete(tmpZip); } catch { }
                    return null;
                }

                string? found = null;
                try
                {
                    found = Directory.EnumerateFiles(extractDir, "ffmpeg.exe", SearchOption.AllDirectories).FirstOrDefault();
                }
                catch
                {
                    found = null;
                }

                try
                {
                    if (!string.IsNullOrWhiteSpace(found) && File.Exists(found))
                    {
                        if (File.Exists(destExe))
                        {
                            try { File.Delete(destExe); } catch { }
                        }
                        File.Move(found, destExe);
                    }
                }
                catch
                {
                }

                try
                {
                    Directory.Delete(extractDir, recursive: true);
                    File.Delete(tmpZip);
                }
                catch
                {
                }

                return File.Exists(destExe) ? destExe : null;
            }
            catch
            {
                return null;
            }
        }

        private static bool IsYouTubeUrl(string? url)
        {
            var s = (url ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return false;
            return s.Contains("youtube.com", StringComparison.OrdinalIgnoreCase) ||
                   s.Contains("youtu.be", StringComparison.OrdinalIgnoreCase) ||
                   s.StartsWith("ytsearch", StringComparison.OrdinalIgnoreCase);
        }

        private async Task<Dictionary<string, string>> TryDownloadMissingFromYouTubeAsync(string outputFolder, IReadOnlyList<MediaItem> items)
        {
            var result = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);

            outputFolder = (outputFolder ?? "").Trim();
            if (string.IsNullOrWhiteSpace(outputFolder)) return result;
            Directory.CreateDirectory(outputFolder);

            using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(30));
            var ct = cts.Token;

            var ytdlp = await EnsureYtDlpAsync(ct).ConfigureAwait(false);
            if (string.IsNullOrWhiteSpace(ytdlp) || !File.Exists(ytdlp))
            {
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "yt-dlp missing";
                    OnPropertyChanged(nameof(StatusText));
                });
                return result;
            }

            var ffmpegDir = "";
            try
            {
                using var ffCts = new CancellationTokenSource(TimeSpan.FromMinutes(3));
                var ensuredFfmpeg = await EnsureFfmpegAsync(ffCts.Token).ConfigureAwait(false);
                var ffPath = !string.IsNullOrWhiteSpace(ensuredFfmpeg) ? ensuredFfmpeg! : ResolveFfmpegExecutable();
                ffmpegDir = Path.GetDirectoryName(ffPath) ?? "";
            }
            catch
            {
                ffmpegDir = "";
            }

            var list = (items ?? Array.Empty<MediaItem>()).Where(i => i != null).ToList();
            var total = list.Count;
            var index = 0;

            foreach (var it in list)
            {
                index++;
                var fpKey = (it.FilePath ?? "").Trim();
                if (string.IsNullOrWhiteSpace(fpKey)) continue;

                var hasLocal = false;
                try { hasLocal = File.Exists(fpKey); } catch { hasLocal = false; }
                if (hasLocal) continue;

                var dl = (it.DownloadUrl ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(dl) && !IsYouTubeUrl(dl)) continue;

                var title = (it.Title ?? "").Trim();
                var artist = (it.Artist ?? "").Trim();
                var q = string.IsNullOrWhiteSpace(artist) ? title : $"{artist} - {title}";
                q = (q ?? "").Trim();
                if (string.IsNullOrWhiteSpace(q)) continue;

                var destMp3 = "";
                try { destMp3 = BuildUniqueOutputMp3Path(outputFolder, it); } catch { destMp3 = ""; }
                if (string.IsNullOrWhiteSpace(destMp3)) continue;
                var destBase = destMp3;
                if (destBase.EndsWith(".mp3", StringComparison.OrdinalIgnoreCase))
                    destBase = destBase.Substring(0, destBase.Length - 4);

                _uiDispatcher.Invoke(() =>
                {
                    var prefs = Core.PreferencesStore.Instance.Current;
                    var variants = (prefs.CsvVariants ?? "").Trim();
                    var label = string.IsNullOrWhiteSpace(variants) ? title : $"{title} {variants}";
                    StatusText = $"[{index}/{total}] Searching: {label}";
                    OnPropertyChanged(nameof(StatusText));
                });

                try
                {
                    var prefs = Core.PreferencesStore.Instance.Current;
                    var variants = (prefs.CsvVariants ?? "").Trim();
                    var minDur = Math.Max(0, prefs.CsvMinDurationSeconds);
                    var maxDur = Math.Max(0, prefs.CsvMaxDurationSeconds);
                    var excludeInstr = prefs.CsvExcludeInstrumentals;

                    var searchQuery = string.IsNullOrWhiteSpace(variants) ? q : $"{q} {variants}";
                    var search = $"ytsearch1:{searchQuery}";

                    var matchParts = new List<string>();
                    if (minDur > 0) matchParts.Add($"duration >= {minDur}");
                    if (maxDur > 0) matchParts.Add($"duration <= {maxDur}");
                    if (excludeInstr) matchParts.Add("title !~ '(?i)instrumental'");
                    var matchFilter = matchParts.Count > 0 ? $"--match-filter \"{string.Join(" & ", matchParts)}\" " : "";
                        var embedThumb = prefs.CsvEmbedThumbnails ? "--embed-thumbnail --convert-thumbnails jpg " : "";
                        var args =
                            $"--no-playlist --no-warnings --ignore-errors --newline " +
                            $"{matchFilter}" +
                            $"-x --audio-format mp3 --audio-quality 0 " +
                            $"{embedThumb}" +
                            $"{(string.IsNullOrWhiteSpace(ffmpegDir) ? "" : $"--ffmpeg-location \"{ffmpegDir}\" ")}" +
                            $"--print after_move:filepath " +
                            $"-o \"{destBase}.%(ext)s\" " +
                            $"\"{search}\"";

                    using var proc = new Process
                    {
                        StartInfo = new ProcessStartInfo
                        {
                            FileName = ytdlp,
                            Arguments = args,
                            UseShellExecute = false,
                            CreateNoWindow = true,
                            RedirectStandardOutput = true,
                            RedirectStandardError = true
                        }
                    };

                    proc.Start();
                    var lastPrinted = "";
                    while (!proc.StandardOutput.EndOfStream)
                    {
                        var line = await proc.StandardOutput.ReadLineAsync().ConfigureAwait(false);
                        if (string.IsNullOrWhiteSpace(line)) continue;
                        lastPrinted = line.Trim();
                    }
                    await proc.WaitForExitAsync(ct).ConfigureAwait(false);

                    var final = "";
                    if (!string.IsNullOrWhiteSpace(lastPrinted) && File.Exists(lastPrinted))
                    {
                        final = lastPrinted;
                        var ext = Path.GetExtension(final) ?? "";
                        if (!ext.Equals(".mp3", StringComparison.OrdinalIgnoreCase))
                        {
                            var ffmpegExe2 = ResolveFfmpegExecutable();
                            if (!string.IsNullOrWhiteSpace(ffmpegExe2))
                            {
                                try
                                {
                                    using var conv = new Process
                                    {
                                        StartInfo = new ProcessStartInfo
                                        {
                                            FileName = ffmpegExe2,
                                            Arguments = $"-hide_banner -loglevel error -y -i \"{final}\" -vn -codec:a libmp3lame -q:a 0 \"{destMp3}\"",
                                            UseShellExecute = false,
                                            CreateNoWindow = true,
                                            RedirectStandardError = true,
                                            RedirectStandardOutput = true
                                        }
                                    };
                                    conv.Start();
                                    await conv.WaitForExitAsync(ct).ConfigureAwait(false);
                                    if (File.Exists(destMp3))
                                        final = destMp3;
                                }
                                catch
                                {
                                }
                            }
                        }
                    }
                    else if (File.Exists(destMp3))
                        final = destMp3;

                    if (!string.IsNullOrWhiteSpace(final))
                        result[fpKey] = final;
                }
                catch
                {
                }
            }

            _uiDispatcher.Invoke(() =>
            {
                StatusText = result.Count > 0 ? $"Downloaded {result.Count} from YouTube" : "No YouTube downloads";
                OnPropertyChanged(nameof(StatusText));
            });

            return result;
        }

        private static bool IsM3u8Url(string? urlOrPath)
        {
            var s = (urlOrPath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return false;
            return s.Contains(".m3u8", StringComparison.OrdinalIgnoreCase) ||
                   s.Contains("m3u8", StringComparison.OrdinalIgnoreCase);
        }

        private async Task DownloadViaFfmpegAsync(string inputUrl, string destPath, Action? indeterminate, CancellationToken ct)
        {
            var ffmpegExe = ResolveFfmpegExecutable();
            if (string.IsNullOrWhiteSpace(ffmpegExe))
                throw new InvalidOperationException("FFmpeg not found");

            Directory.CreateDirectory(Path.GetDirectoryName(destPath) ?? Environment.CurrentDirectory);

            async Task<int> RunAsync(string args)
            {
                using var proc = new Process
                {
                    StartInfo = new ProcessStartInfo
                    {
                        FileName = ffmpegExe,
                        Arguments = args,
                        UseShellExecute = false,
                        CreateNoWindow = true,
                        RedirectStandardError = true,
                        RedirectStandardOutput = true
                    }
                };

                using var reg = ct.Register(() =>
                {
                    try { if (!proc.HasExited) proc.Kill(entireProcessTree: true); } catch { }
                });

                proc.Start();
                _ = Task.Run(async () =>
                {
                    try
                    {
                        while (!proc.HasExited && !ct.IsCancellationRequested)
                        {
                            indeterminate?.Invoke();
                            await Task.Delay(350, ct).ConfigureAwait(false);
                        }
                    }
                    catch
                    {
                    }
                }, CancellationToken.None);

                await proc.WaitForExitAsync(ct).ConfigureAwait(false);
                return proc.ExitCode;
            }

            var inputEscaped = inputUrl.Replace("\"", "%22", StringComparison.Ordinal);
            var argsCopy = $"-hide_banner -loglevel error -y -protocol_whitelist file,http,https,tcp,tls,crypto -i \"{inputEscaped}\" -c copy \"{destPath}\"";
            var exit = await RunAsync(argsCopy).ConfigureAwait(false);
            if (exit == 0 && File.Exists(destPath)) return;

            var argsTranscode = $"-hide_banner -loglevel error -y -protocol_whitelist file,http,https,tcp,tls,crypto -i \"{inputEscaped}\" -c:v libx264 -preset veryfast -crf 23 -c:a aac -b:a 192k \"{destPath}\"";
            exit = await RunAsync(argsTranscode).ConfigureAwait(false);
            if (exit != 0 || !File.Exists(destPath))
                throw new InvalidOperationException("FFmpeg download failed");
        }

        public List<MediaItem> FindLibraryItems(string query, string? typeId = null, int maxResults = 250)
        {
            query = (query ?? "").Trim();
            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }

            IEnumerable<MediaItem> items = snapshot;
            if (!string.IsNullOrWhiteSpace(typeId))
                items = items.Where(i => string.Equals(i.Type, typeId, StringComparison.OrdinalIgnoreCase));

            if (string.IsNullOrWhiteSpace(query))
                return items.Take(Math.Max(1, maxResults)).ToList();

            var stopwords = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "a", "an", "and", "the", "me", "my", "all", "every", "please", "in", "on", "at", "to", "for", "of", "from"
            };

            var minTokenLen = query.Length <= 4 ? 2 : 3;
            var tokens = Regex.Split(query, "\\s+")
                .Select(t => (t ?? "").Trim())
                .Where(t => !string.IsNullOrWhiteSpace(t))
                .Select(t => t.Trim('\"', '\'', ',', '.', '!', '?', ':', ';', '(', ')', '[', ']', '{', '}'))
                .Where(t => t.Length >= minTokenLen && !stopwords.Contains(t))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToArray();

            if (tokens.Length == 0)
                return items.Take(Math.Max(1, maxResults)).ToList();

            var scored = items
                .Select(i => (Item: i, Score: ScoreSearch(i, tokens, out var matched), Matched: matched))
                .Where(x => x.Score > 0)
                .OrderByDescending(x => x.Matched)
                .ThenByDescending(x => x.Score)
                .ThenBy(x => x.Item.Title ?? "", StringComparer.OrdinalIgnoreCase)
                .Select(x => x.Item);

            var results = scored.Take(Math.Max(1, maxResults)).ToList();
            if (results.Count == 0 && tokens.Contains("marvel", StringComparer.OrdinalIgnoreCase))
            {
                var marvelResults = items
                    .Select(i => (Item: i, Score: ScoreByPhrases(i.Title ?? "", i.FilePath ?? "", GetMarvelKeywordPhrases())))
                    .Where(x => x.Score > 0)
                    .OrderByDescending(x => x.Score)
                    .ThenBy(x => x.Item.Title ?? "", StringComparer.OrdinalIgnoreCase)
                    .Select(x => x.Item)
                    .Take(Math.Max(1, maxResults))
                    .ToList();
                return marvelResults;
            }
            return results;
        }

        private static int ScoreSearch(MediaItem item, string[] tokens, out int matchedTokens)
        {
            matchedTokens = 0;
            var title = item.Title ?? "";
            var artist = item.Artist ?? "";
            var album = item.Album ?? "";
            var path = item.FilePath ?? "";
            var fileName = "";
            var folderName = "";
            try
            {
                fileName = Path.GetFileNameWithoutExtension(path) ?? "";
                folderName = Path.GetFileName(Path.GetDirectoryName(path) ?? "") ?? "";
            }
            catch
            {
            }
            var genres = item.Genres != null && item.Genres.Count > 0 ? string.Join(" ", item.Genres) : "";

            var haystack = $"{title} {artist} {album} {genres} {path}";
            var score = 0;
            foreach (var t in tokens)
            {
                var matched = false;
                if (title.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 12; matched = true; }
                if (album.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 6; matched = true; }
                if (artist.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 6; matched = true; }
                if (path.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 3; matched = true; }
                if (!string.IsNullOrWhiteSpace(fileName) && fileName.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 8; matched = true; }
                if (!string.IsNullOrWhiteSpace(folderName) && folderName.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 3; matched = true; }
                if (genres.Contains(t, StringComparison.OrdinalIgnoreCase)) { score += 1; matched = true; }
                if (matched) matchedTokens++;
            }
            if (matchedTokens <= 0) return 0;
            return score;
        }

        private static string[] GetMarvelKeywordPhrases()
        {
            return new[]
            {
                "marvel", "mcu",
                "avengers", "iron man", "captain america", "the winter soldier", "civil war",
                "thor", "guardians of the galaxy", "black panther", "doctor strange", "ant-man",
                "spider-man", "homecoming", "far from home", "no way home",
                "captain marvel", "the marvels",
                "black widow", "shang-chi", "eternals",
                "deadpool", "wolverine", "x-men", "fantastic four", "hulk"
            };
        }

        private static int ScoreByPhrases(string title, string path, IEnumerable<string> phrases)
        {
            var score = 0;
            foreach (var p in phrases)
            {
                if (string.IsNullOrWhiteSpace(p)) continue;
                var matched = false;
                if (!string.IsNullOrWhiteSpace(title) && title.Contains(p, StringComparison.OrdinalIgnoreCase))
                {
                    score += p.Length >= 6 ? 14 : 10;
                    matched = true;
                }
                if (!string.IsNullOrWhiteSpace(path) && path.Contains(p, StringComparison.OrdinalIgnoreCase))
                {
                    score += matched ? 2 : 5;
                }
            }
            return score;
        }

        private void ApplyCategoryFilter()
        {
            var id = SelectedCategory?.Id ?? "";
            if (string.Equals(id, "music", StringComparison.OrdinalIgnoreCase))
            {
                if (SelectedAlbum != null)
                {
                    if (LibraryItems is FastObservableCollection<MediaItem> fast)
                        fast.ReplaceWith(SelectedAlbum.Tracks);
                    else
                    {
                        LibraryItems.Clear();
                        foreach (var track in SelectedAlbum.Tracks)
                            LibraryItems.Add(track);
                    }
                }
                else
                {
                    if (LibraryItems is FastObservableCollection<MediaItem> fastEmpty)
                        fastEmpty.ReplaceWith(Array.Empty<MediaItem>());
                    else
                        LibraryItems.Clear();
                }
                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));
                OnPropertyChanged(nameof(IsMusicAlbumsView));
                OnPropertyChanged(nameof(IsAlbumTracksView));
                OnPropertyChanged(nameof(IsStandardTracksView));
                OnPropertyChanged(nameof(LibraryHeaderText));
                OnPropertyChanged(nameof(VisibleCountText));
                KickLoadCoversForVisibleLibraryItems();
                KickTrimCoverImagesToVisible();
                return;
            }

            IEnumerable<MediaItem> filtered = string.IsNullOrWhiteSpace(id)
                ? _allItems
                : _allItems.Where(i => string.Equals(i.Type, id, StringComparison.OrdinalIgnoreCase));

            var nowPlaying = _allItems.FirstOrDefault(i => i.IsPlaying);

            filtered = filtered
                .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                .Where(i => !string.IsNullOrWhiteSpace(BuildServerCatalogDedupeKey(i)));

            if (LibraryItems is FastObservableCollection<MediaItem> fastFiltered)
                fastFiltered.ReplaceWith(filtered);
            else
            {
                LibraryItems.Clear();
                foreach (var item in filtered) LibraryItems.Add(item);
            }

            if (string.Equals(id, "radio", StringComparison.OrdinalIgnoreCase))
            {
                try
                {
                    foreach (var it in LibraryItems.Take(250))
                    {
                        if (it == null) continue;
                        if (!string.Equals(it.Type, "radio", StringComparison.OrdinalIgnoreCase)) continue;
                        if (!string.IsNullOrWhiteSpace(it.CoverUrl)) continue;
                        var fp = (it.FilePath ?? "").Trim();
                        if (!Uri.TryCreate(fp, UriKind.Absolute, out var uri)) continue;
                        if (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps) continue;
                        it.CoverUrl = BuildStationLogoUrlFromStreamHost(uri.Host);
                    }
                }
                catch
                {
                }
            }

            if (nowPlaying != null && !string.IsNullOrWhiteSpace(nowPlaying.FilePath))
            {
                foreach (var item in LibraryItems)
                {
                    if (string.Equals(item.FilePath, nowPlaying.FilePath, StringComparison.OrdinalIgnoreCase))
                    {
                        item.IsPlaying = true;
                        break;
                    }
                }
            }

            OnPropertyChanged(nameof(LibraryHeaderText));
            OnPropertyChanged(nameof(VisibleCountText));
            KickLoadCoversForVisibleLibraryItems();
            KickTrimCoverImagesToVisible();
        }

        private int _coverTrimRunId;
        private int _musicAlbumCoverRunId;

        private void KickTrimCoverImagesToVisible()
        {
            HashSet<string> keepPaths;
            string? detailsPath;
            try
            {
                keepPaths = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                foreach (var i in LibraryItems.Take(100))
                {
                    if (!string.IsNullOrWhiteSpace(i.FilePath))
                        keepPaths.Add(i.FilePath);
                }
                detailsPath = DetailsItem?.FilePath;
                if (!string.IsNullOrWhiteSpace(detailsPath))
                    keepPaths.Add(detailsPath);
            }
            catch
            {
                return;
            }

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }

            var runId = Interlocked.Increment(ref _coverTrimRunId);
            _ = Task.Run(() =>
            {
                try
                {
                    var toClear = new List<MediaItem>();
                    foreach (var item in snapshot)
                    {
                        if (item == null) continue;
                        if (item.CoverImage == null) continue;
                        if (item.IsPlaying) continue;
                        if (!string.IsNullOrWhiteSpace(detailsPath) && string.Equals(item.FilePath, detailsPath, StringComparison.OrdinalIgnoreCase))
                            continue;
                        if (string.IsNullOrWhiteSpace(item.FilePath)) continue;
                        if (keepPaths.Contains(item.FilePath)) continue;
                        toClear.Add(item);
                    }

                    if (toClear.Count == 0) return;

                    _uiDispatcher.BeginInvoke(() =>
                    {
                        if (runId != _coverTrimRunId) return;
                        foreach (var item in toClear)
                            item.CoverImage = null;
                    }, DispatcherPriority.Background);
                }
                catch
                {
                }
            });
        }

        private void KickLoadCoversForVisibleLibraryItems()
        {
            List<MediaItem> snapshot;
            try
            {
                snapshot = LibraryItems.Take(60).ToList();
                if (IsDetailsOpen && DetailsItem != null && !snapshot.Contains(DetailsItem))
                    snapshot.Insert(0, DetailsItem);
            }
            catch
            {
                return;
            }

            if (snapshot.Count == 0)
                return;

            try
            {
                var keep = new HashSet<MediaItem>(snapshot);
                _uiDispatcher.BeginInvoke(() =>
                {
                    foreach (var item in LibraryItems)
                    {
                        if (item.CoverImage == null) continue;
                        if (item.IsPlaying) continue;
                        if (DetailsItem != null && ReferenceEquals(item, DetailsItem)) continue;
                        if (!keep.Contains(item))
                            item.CoverImage = null;
                    }
                });
            }
            catch
            {
            }

            try
            {
                _libraryCoverCts?.Cancel();
                _libraryCoverCts?.Dispose();
            }
            catch
            {
            }

            var cts = new CancellationTokenSource();
            _libraryCoverCts = cts;
            var ct = cts.Token;

            _ = Task.Run(async () =>
            {
                try
                {
                    var pending = snapshot
                        .Where(i => i != null && i.CoverImage == null)
                        .ToList();
                    if (pending.Count == 0)
                        return;

                    var semaphore = new SemaphoreSlim(12);
                    var tasks = pending.Select(async item =>
                    {
                        await semaphore.WaitAsync(ct).ConfigureAwait(false);
                        try
                        {
                            await TryLoadCoverIntoItemAsync(item, ct).ConfigureAwait(false);
                        }
                        finally
                        {
                            semaphore.Release();
                        }
                    }).ToList();

                    await Task.WhenAll(tasks).ConfigureAwait(false);
                }
                catch
                {
                }
            }, ct);
        }

        private void SelectAlbum(AlbumEntry? album)
        {
            if (album == null) return;
            foreach (var a in MusicAlbums) a.IsSelected = ReferenceEquals(a, album);
            SelectedAlbum = album;

            if (LibraryItems is FastObservableCollection<MediaItem> fast)
                fast.ReplaceWith(album.Tracks);
            else
            {
                LibraryItems.Clear();
                foreach (var track in album.Tracks)
                    LibraryItems.Add(track);
            }

            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));
            OnPropertyChanged(nameof(VisibleCountText));
            KickLoadCoversForVisibleLibraryItems();
        }

        private void ScanSelectedCategory()
        {
            if (SelectedCategory == null) return;
            ScanCategory(SelectedCategory);
        }

        private async Task CleanRadioStationsAsync()
        {
            if (IsScanning) return;

            List<MediaItem> radios;
            lock (_stateLock)
            {
                radios = _allItems
                    .Where(i => i != null && string.Equals(i.Type, "radio", StringComparison.OrdinalIgnoreCase))
                    .ToList();
            }

            if (radios.Count == 0)
            {
                StatusText = "No stations";
                OnPropertyChanged(nameof(StatusText));
                return;
            }

            _scanCts?.Cancel();
            _scanCts?.Dispose();
            _scanCts = new CancellationTokenSource();
            var ct = _scanCts.Token;

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = $"Checking {radios.Count} station(s)...";
                ScannedCount = 0;
                StatusText = "Scanning";
                CommandManager.InvalidateRequerySuggested();
            });

            var keep = new List<MediaItem>(radios.Count);
            var keepLock = new object();
            var removed = 0;
            var done = 0;
            var gate = new SemaphoreSlim(6, 6);

            try
            {
                var tasks = radios.Select(async item =>
                {
                    await gate.WaitAsync(ct).ConfigureAwait(false);
                    try
                    {
                        var ok = await ProbeRadioStreamAsync(item.FilePath, ct).ConfigureAwait(false);
                        if (ok)
                        {
                            lock (keepLock) keep.Add(item);
                        }
                        else
                        {
                            Interlocked.Increment(ref removed);
                        }
                    }
                    catch
                    {
                        Interlocked.Increment(ref removed);
                    }
                    finally
                    {
                        gate.Release();
                        var d = Interlocked.Increment(ref done);
                        if (d == 1 || d % 5 == 0 || d == radios.Count)
                        {
                            _uiDispatcher.BeginInvoke(() =>
                            {
                                ScannedCount = d;
                                ScanProgressText = $"Checking stations... {d}/{radios.Count}";
                            });
                        }
                    }
                }).ToList();

                await Task.WhenAll(tasks).ConfigureAwait(false);
            }
            catch (OperationCanceledException)
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    IsScanning = false;
                    ScanProgressText = "Cancelled";
                    StatusText = "Ready";
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }
            finally
            {
                try { gate.Dispose(); } catch { }
            }

            _uiDispatcher.Invoke(() =>
            {
                try
                {
                    MarkLibraryMutated();
                    lock (_stateLock)
                    {
                        var nonRadio = _allItems.Where(i => i != null && !string.Equals(i.Type, "radio", StringComparison.OrdinalIgnoreCase)).ToList();
                        _allItems = nonRadio.Concat(keep).ToList();
                    }

                    ApplyCategoryFilter();

                    List<MediaItem> snapshot;
                    lock (_stateLock) snapshot = _allItems.ToList();
                    _ = SaveLibraryToDiskAsync(snapshot);
                }
                catch
                {
                }

                IsScanning = false;
                ScanProgressText = removed == 0 ? "All stations OK" : $"Removed {removed} broken station(s)";
                StatusText = "Ready";
                CommandManager.InvalidateRequerySuggested();
            });
        }

        private static async Task<bool> ProbeRadioStreamAsync(string? url, CancellationToken ct)
        {
            var u = (url ?? "").Trim();
            if (string.IsNullOrWhiteSpace(u)) return false;
            if (!Uri.TryCreate(u, UriKind.Absolute, out var uri)) return false;
            if (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps) return false;

            using var req = new HttpRequestMessage(HttpMethod.Get, uri);
            try
            {
                req.Headers.TryAddWithoutValidation("Icy-MetaData", "1");
            }
            catch
            {
            }

            using var resp = await RadioProbeHttp.SendAsync(req, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
            if ((int)resp.StatusCode >= 400) return false;

            var ctHeader = (resp.Content.Headers.ContentType?.MediaType ?? "").Trim().ToLowerInvariant();
            if (ctHeader.StartsWith("text/") || ctHeader.Contains("html"))
                return false;

            try
            {
                await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                var buffer = new byte[2048];
                var read = await stream.ReadAsync(buffer.AsMemory(0, buffer.Length), ct).ConfigureAwait(false);
                if (read <= 0) return false;
            }
            catch
            {
                if (ctHeader.StartsWith("audio/")) return true;
                if (ctHeader.Contains("mpegurl")) return true;
                return false;
            }

            return true;
        }

        private async void DiscoverGamesAsync()
        {
            if (IsScanning) return;

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = "Discovering installed games...";
                ScannedCount = 0;
                StatusText = "Scanning";
                CommandManager.InvalidateRequerySuggested();
            });

            List<DiscoveredGame> discovered;
            try
            {
                try
                {
                    await InstalledAppsManager.Instance.ScanAllAppsAsync().ConfigureAwait(false);
                }
                catch
                {
                }
                discovered = await Task.Run(GameDiscoveryService.DiscoverInstalledGames).ConfigureAwait(false);
            }
            catch
            {
                discovered = new List<DiscoveredGame>();
            }

            List<MediaItem> games = new();
            var discoveredCount = discovered.Count;
            _uiDispatcher.Invoke(() =>
            {
                Dictionary<string, MediaItem> existingByPath;
                HashSet<string> ignored;
                lock (_stateLock)
                {
                    existingByPath = _allItems
                        .Where(i => string.Equals(i.Type, "games", StringComparison.OrdinalIgnoreCase))
                        .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                        .ToDictionary(g => g.Key, g => g.First(), StringComparer.OrdinalIgnoreCase);
                    ignored = new HashSet<string>(_ignoredPaths.Where(p => !string.IsNullOrWhiteSpace(p)), StringComparer.OrdinalIgnoreCase);
                }

                var keep = _allItems.Where(i => !string.Equals(i.Type, "games", StringComparison.OrdinalIgnoreCase)).ToList();
                var accent = AccentForCategory("games");
                var icon = IconForCategory("games");

                games = discovered
                    .Where(g => !string.IsNullOrWhiteSpace(g.ExecutablePath) && File.Exists(g.ExecutablePath))
                    .Where(g => !ignored.Contains(g.ExecutablePath))
                    .Select(g =>
                    {
                        existingByPath.TryGetValue(g.ExecutablePath, out var prev);

                        var title = prev != null && !string.IsNullOrWhiteSpace(prev.Title) ? prev.Title : g.Name;
                        var metadata = prev?.Metadata ?? "";
                        var album = prev != null && !string.IsNullOrWhiteSpace(prev.Album) ? prev.Album : g.Platform;
                        var coverUrl = prev?.CoverUrl;
                        var fav = prev?.IsFavorite == true;

                        ImageSource? cover = null;
                        try
                        {
                            var cu = (coverUrl ?? "").Trim();
                            if (!string.IsNullOrWhiteSpace(cu))
                            {
                                if (Uri.TryCreate(cu, UriKind.Absolute, out var uri) && uri.IsFile && File.Exists(uri.LocalPath))
                                    cover = LoadAlbumCoverFromFile(uri.LocalPath);
                                else if (File.Exists(cu))
                                    cover = LoadAlbumCoverFromFile(cu);
                            }
                        }
                        catch
                        {
                            cover = null;
                        }
                        cover ??= LoadGameCoverImage(g);

                        return new MediaItem
                        {
                            PlaybackItem = null,
                            FilePath = g.ExecutablePath,
                            Title = title,
                            Metadata = metadata,
                            Artist = "",
                            Album = album,
                            TrackNumber = g.SteamAppId ?? 0,
                            Duration = TimeSpan.Zero,
                            Type = "games",
                            AccentBrush = accent,
                            IconGeometry = icon,
                            CoverImage = cover,
                            CoverUrl = coverUrl,
                            IsFavorite = fav
                        };
                    })
                    .DistinctBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                    .OrderBy(i => i.Title, StringComparer.OrdinalIgnoreCase)
                    .ToList();

                lock (_stateLock)
                {
                    _allItems = keep.Concat(games).ToList();
                }

                foreach (var c in Categories)
                {
                    if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                        c.Count = _addonServers.Count;
                    else if (string.Equals(c.Id, "apps", StringComparison.OrdinalIgnoreCase))
                        c.Count = _appsServices.Count;
                    else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                        c.Count = _musicAlbums.Count;
                    else
                        c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
                }

                ApplyCategoryFilter();
                OnPropertyChanged(nameof(LibraryCountText));
                OnPropertyChanged(nameof(VisibleCountText));
                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));

                List<MediaItem> snapshot;
                lock (_stateLock)
                {
                    snapshot = _allItems.ToList();
                }
                _ = SaveLibraryToDiskAsync(snapshot);

                ScanProgressText = discoveredCount == 0 ? "No games found" : $"Found {games.Count} games";
                StatusText = "Ready";
                CommandManager.InvalidateRequerySuggested();
            });

            try
            {
                if (games.Count > 0 && TryGetIgdbCredentials(out var igdbId, out var igdbSecret))
                {
                    await EnrichDiscoveredGamesWithIgdbAsync(games, igdbId, igdbSecret, true).ConfigureAwait(false);
                }
            }
            catch
            {
            }

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = false;
                StatusText = "Ready";
                CommandManager.InvalidateRequerySuggested();
            });
        }

        private void ScanCategory(MediaCategory? category)
        {
            if (category == null) return;
            if (IsScanning) return;

            if (string.Equals(category.Id, "radio", StringComparison.OrdinalIgnoreCase))
            {
                var res = ShowRadioStationsModal();
                if (res.added != null && res.added.Count > 0)
                {
                    try
                    {
                        AddRadioStationsToLibrary(res.added);
                    }
                    catch
                    {
                    }
                    return;
                }

                if (!res.openFolder)
                    return;

                var folderDialog = new System.Windows.Forms.FolderBrowserDialog
                {
                    Description = "Select a folder to scan for .m3u/.pls radio playlists",
                    ShowNewFolderButton = false
                };

                if (folderDialog.ShowDialog() != System.Windows.Forms.DialogResult.OK)
                    return;

                _ = ScanFolderForRadioStationsAsync(folderDialog.SelectedPath);
                return;
            }

            var scanDialog = new System.Windows.Forms.FolderBrowserDialog
            {
                Description = $"Select folder to scan for {category.Label}",
                ShowNewFolderButton = false
            };

            if (scanDialog.ShowDialog() != System.Windows.Forms.DialogResult.OK)
                return;

            StartScan(category, scanDialog.SelectedPath);
        }

        private void AddRadioStationsToLibrary(List<(string name, string url)> added)
        {
            try
            {
                if (added == null || added.Count == 0) return;

                var accent = AccentForCategory("radio");
                var icon = IconForCategory("radio");

                var now = DateTime.UtcNow;
                var newItems = new List<MediaItem>(added.Count);
                foreach (var entry in added)
                {
                    var url = (entry.url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(url)) continue;
                    if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) || (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps))
                        continue;

                    var title = (entry.name ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(title))
                        title = (uri.Host ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(title))
                        title = url;

                    var logoUrl = BuildStationLogoUrlFromStreamHost(uri.Host);
                    var playback = new ScannerMediaItem
                    {
                        FilePath = url,
                        DisplayName = title,
                        Extension = "",
                        FileSize = 0,
                        LastModified = now,
                        MediaType = ScannerMediaType.Audio,
                        SectionName = "radio",
                        FolderPath = "",
                        DateAdded = now,
                        Album = "Radio",
                        Artist = "",
                        TrackNumber = null,
                        Duration = null
                    };

                    var uiItem = new MediaItem
                    {
                        PlaybackItem = playback,
                        FilePath = url,
                        Title = title,
                        Metadata = "",
                        Artist = "",
                        Album = "Radio",
                        TrackNumber = 0,
                        DiscNumber = 0,
                        SeasonNumber = 0,
                        EpisodeNumber = 0,
                        Duration = TimeSpan.Zero,
                        Year = 0,
                        Rating = 0,
                        Genres = Array.Empty<string>(),
                        Type = "radio",
                        AccentBrush = accent,
                        IconGeometry = icon,
                        CoverUrl = logoUrl,
                        CoverImage = null,
                        LastAiOptimizedUtc = null,
                        IsFavorite = false,
                        IsSelected = false,
                        IsPlaying = false
                    };
                    newItems.Add(uiItem);
                }

                if (newItems.Count == 0) return;

                MarkLibraryMutated();
                lock (_stateLock)
                {
                    var byPath = _allItems
                        .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                        .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                        .ToDictionary(g => g.Key, g => g.First(), StringComparer.OrdinalIgnoreCase);

                    foreach (var i in newItems)
                    {
                        if (string.IsNullOrWhiteSpace(i.FilePath)) continue;
                        byPath[i.FilePath] = i;
                    }

                    _allItems = byPath.Values.ToList();
                }

                ApplyCategoryFilter();

                List<MediaItem> snapshot;
                lock (_stateLock) snapshot = _allItems.ToList();
                _ = SaveLibraryToDiskAsync(snapshot);

                foreach (var r in newItems)
                    TryKickStationLogoLoad(r);
            }
            catch
            {
            }
        }

        private static string? BuildStationLogoUrlFromStreamHost(string? host)
        {
            try
            {
                var h = (host ?? "").Trim();
                if (string.IsNullOrWhiteSpace(h)) return null;
                return $"https://www.google.com/s2/favicons?sz=128&domain_url=https://{Uri.EscapeDataString(h)}";
            }
            catch
            {
                return null;
            }
        }

        private void TryKickStationLogoLoad(MediaItem? item)
        {
            if (item == null) return;
            if (!string.Equals(item.Type, "radio", StringComparison.OrdinalIgnoreCase)) return;
            if (item.CoverImage != null) return;
            if (string.IsNullOrWhiteSpace(item.CoverUrl)) return;

            _ = Task.Run(async () =>
            {
                try
                {
                    using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(12));
                    var img = await LoadImageFromUrlAsync(item.CoverUrl, cts.Token).ConfigureAwait(false);
                    if (img == null) return;
                    _uiDispatcher.BeginInvoke(() =>
                    {
                        try
                        {
                            if (item.CoverImage == null)
                                item.CoverImage = img;
                        }
                        catch
                        {
                        }
                    });
                }
                catch
                {
                }
            });
        }

        private async Task ScanFolderForRadioStationsAsync(string rootFolder)
        {
            if (IsScanning) return;

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = "Scanning playlists for radio stations...";
                ScannedCount = 0;
                StatusText = "Scanning";
                CommandManager.InvalidateRequerySuggested();
            });

            _scanCts?.Cancel();
            _scanCts?.Dispose();
            _scanCts = new CancellationTokenSource();
            var ct = _scanCts.Token;

            List<(string name, string url)> found;
            try
            {
                found = await Task.Run(() => ScanPlaylistsForRadioStations(rootFolder, ct), ct).ConfigureAwait(false);
            }
            catch (OperationCanceledException)
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = "Scan cancelled";
                    StatusText = "Ready";
                    IsScanning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }
            catch
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = "Scan failed";
                    StatusText = "Ready";
                    IsScanning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            _uiDispatcher.Invoke(() =>
            {
                try
                {
                    AddRadioStationsToLibrary(found);
                }
                catch
                {
                }

                ScanProgressText = found.Count == 0 ? "No stations found in playlists" : $"Found {found.Count} station(s)";
                StatusText = "Ready";
                IsScanning = false;
                CommandManager.InvalidateRequerySuggested();
            });
        }

        private List<(string name, string url)> ScanPlaylistsForRadioStations(string rootFolder, CancellationToken ct)
        {
            var results = new List<(string name, string url)>();
            if (string.IsNullOrWhiteSpace(rootFolder) || !Directory.Exists(rootFolder))
                return results;

            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            IEnumerable<string> files;
            try
            {
                files = Directory.EnumerateFiles(rootFolder, "*.*", SearchOption.AllDirectories);
            }
            catch
            {
                return results;
            }

            var playlistFiles = files.Where(f =>
            {
                var ext = Path.GetExtension(f) ?? "";
                return ext.Equals(".m3u", StringComparison.OrdinalIgnoreCase) ||
                       ext.Equals(".m3u8", StringComparison.OrdinalIgnoreCase) ||
                       ext.Equals(".pls", StringComparison.OrdinalIgnoreCase) ||
                       ext.Equals(".txt", StringComparison.OrdinalIgnoreCase);
            }).ToList();

            var processed = 0;
            foreach (var filePath in playlistFiles)
            {
                ct.ThrowIfCancellationRequested();
                processed++;

                if (processed == 1 || processed % 25 == 0)
                {
                    var p = processed;
                    var n = playlistFiles.Count;
                    var fn = Path.GetFileName(filePath);
                    _uiDispatcher.BeginInvoke(() =>
                    {
                        ScanProgressText = $"Scanning playlists... {p}/{n} · {fn}";
                    });
                }

                var ext = (Path.GetExtension(filePath) ?? "").ToLowerInvariant();
                List<(string name, string url)> parsed = new();
                try
                {
                    if (ext == ".m3u" || ext == ".m3u8")
                        parsed = ParseM3uStations(filePath);
                    else if (ext == ".pls")
                        parsed = ParsePlsStations(filePath);
                    else if (ext == ".txt")
                        parsed = ParseTextStations(filePath);
                }
                catch
                {
                    parsed = new List<(string name, string url)>();
                }

                foreach (var (name, url) in parsed)
                {
                    var u = (url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(u)) continue;
                    if (!Uri.TryCreate(u, UriKind.Absolute, out var uri) || (uri.Scheme != Uri.UriSchemeHttp && uri.Scheme != Uri.UriSchemeHttps))
                        continue;
                    if (!seen.Add(u)) continue;

                    var title = (name ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(title))
                        title = (uri.Host ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(title))
                        title = u;

                    results.Add((title, u));
                    if (results.Count >= 1000) return results;
                }
            }

            return results;
        }

        private static List<(string name, string url)> ParseM3uStations(string filePath)
        {
            var results = new List<(string name, string url)>();
            var lines = File.ReadAllLines(filePath);
            string pendingName = "";
            foreach (var raw in lines)
            {
                var line = (raw ?? "").Trim();
                if (string.IsNullOrWhiteSpace(line)) continue;
                if (line.StartsWith("#EXTINF", StringComparison.OrdinalIgnoreCase))
                {
                    var idx = line.IndexOf(',');
                    pendingName = idx >= 0 ? line[(idx + 1)..].Trim() : "";
                    continue;
                }
                if (line.StartsWith("#")) continue;

                if (line.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || line.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                {
                    results.Add((pendingName, line));
                    pendingName = "";
                }
            }
            return results;
        }

        private static List<(string name, string url)> ParsePlsStations(string filePath)
        {
            var results = new List<(string name, string url)>();
            var lines = File.ReadAllLines(filePath);
            var urls = new Dictionary<int, string>();
            var titles = new Dictionary<int, string>();

            foreach (var raw in lines)
            {
                var line = (raw ?? "").Trim();
                if (string.IsNullOrWhiteSpace(line)) continue;
                if (line.StartsWith("[", StringComparison.OrdinalIgnoreCase)) continue;
                var eq = line.IndexOf('=');
                if (eq <= 0) continue;
                var key = line[..eq].Trim();
                var value = line[(eq + 1)..].Trim();
                if (key.StartsWith("File", StringComparison.OrdinalIgnoreCase))
                {
                    if (int.TryParse(key["File".Length..], out var i))
                        urls[i] = value;
                }
                else if (key.StartsWith("Title", StringComparison.OrdinalIgnoreCase))
                {
                    if (int.TryParse(key["Title".Length..], out var i))
                        titles[i] = value;
                }
            }

            foreach (var kv in urls.OrderBy(k => k.Key))
            {
                var name = titles.TryGetValue(kv.Key, out var t) ? t : "";
                results.Add((name, kv.Value));
            }
            return results;
        }

        private static List<(string name, string url)> ParseTextStations(string filePath)
        {
            var results = new List<(string name, string url)>();
            var lines = File.ReadAllLines(filePath);
            foreach (var raw in lines)
            {
                var line = (raw ?? "").Trim();
                if (string.IsNullOrWhiteSpace(line)) continue;

                var name = "";
                var url = "";
                var parts = line.Split('|');
                if (parts.Length >= 2)
                {
                    name = (parts[0] ?? "").Trim();
                    url = (parts[1] ?? "").Trim();
                }
                else
                {
                    url = line;
                }

                results.Add((name, url));
            }
            return results;
        }

