        private void StartScan(MediaCategory category, string rootFolder)
        {
            _ = StartScanAsync(category, rootFolder);
        }

        private static MediaItem MergeExistingAndScanned(MediaItem existing, MediaItem scanned)
        {
            var type = !string.IsNullOrWhiteSpace(existing.Type) ? existing.Type : scanned.Type;

            var title = !string.IsNullOrWhiteSpace(existing.Title) ? existing.Title : scanned.Title;
            var artist = !string.IsNullOrWhiteSpace(existing.Artist) ? existing.Artist : scanned.Artist;
            var album = !string.IsNullOrWhiteSpace(existing.Album) ? existing.Album : scanned.Album;

            var track = existing.TrackNumber != 0 ? existing.TrackNumber : scanned.TrackNumber;
            var disc = existing.DiscNumber != 0 ? existing.DiscNumber : scanned.DiscNumber;

            var duration = scanned.Duration > TimeSpan.Zero ? scanned.Duration : existing.Duration;

            var next = new MediaItem
            {
                PlaybackItem = existing.PlaybackItem ?? scanned.PlaybackItem,
                FilePath = existing.FilePath,
                Title = title ?? "",
                Artist = artist ?? "",
                Album = album ?? "",
                TrackNumber = track,
                DiscNumber = disc,
                Duration = duration,
                Type = type ?? "",
                AccentBrush = AccentForCategory(type ?? ""),
                IconGeometry = IconForCategory(type ?? ""),
                LastAiOptimizedUtc = existing.LastAiOptimizedUtc,
                CoverUrl = !string.IsNullOrWhiteSpace(existing.CoverUrl) ? existing.CoverUrl : scanned.CoverUrl,
                CoverImage = existing.CoverImage ?? scanned.CoverImage
            };

            next.IsFavorite = existing.IsFavorite;
            next.IsSelected = existing.IsSelected;
            next.IsPlaying = existing.IsPlaying;
            return next;
        }

        private async Task StartScanAsync(MediaCategory category, string rootFolder)
        {
            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = "Starting scan...";
                ScannedCount = 0;
                StatusText = "Scanning";
                CommandManager.InvalidateRequerySuggested();
            });
            MarkLibraryMutated();

            _scanCts?.Cancel();
            _scanCts?.Dispose();
            _scanCts = new CancellationTokenSource();
            var ct = _scanCts.Token;

            List<MediaItem> scannedItems;
            try
            {
                scannedItems = await Task.Run(() => ScanFolder(category.Id, rootFolder, ct), ct).ConfigureAwait(false);
            }
            catch (OperationCanceledException)
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = "Scan cancelled";
                    StatusText = "Ready";
                    IsScanning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }
            catch
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = "Scan failed";
                    StatusText = "Ready";
                    IsScanning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            if (string.Equals(category.Id, "karaoke", StringComparison.OrdinalIgnoreCase))
            {
                try
                {
                    var accent = AccentForCategory(category.Id);
                    var icon = IconForCategory(category.Id);
                    var expanded = new List<MediaItem>();
                    foreach (var item in scannedItems)
                    {
                        if (item == null)
                            continue;
                        var fp = (item.FilePath ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(fp) &&
                            fp.EndsWith(".zip", StringComparison.OrdinalIgnoreCase) &&
                            !fp.Contains("|", StringComparison.Ordinal))
                        {
                            var pack = ExpandKaraokeZipPack(fp, category.Id, accent, icon);
                            if (pack.Count > 0)
                            {
                                expanded.AddRange(pack);
                                continue;
                            }
                        }
                        expanded.Add(item);
                    }
                    scannedItems = expanded;
                }
                catch
                {
                }
            }

            List<MediaItem> newAllItems;
            lock (_stateLock)
            {
                var byPath = new Dictionary<string, MediaItem>(StringComparer.OrdinalIgnoreCase);
                foreach (var existing in _allItems)
                {
                    if (!string.IsNullOrWhiteSpace(existing.FilePath))
                        byPath[existing.FilePath] = existing;
                }

                foreach (var scanned in scannedItems)
                {
                    if (!string.IsNullOrWhiteSpace(scanned.FilePath) && !_ignoredPaths.Contains(scanned.FilePath))
                    {
                        if (byPath.TryGetValue(scanned.FilePath, out var existing))
                            byPath[scanned.FilePath] = MergeExistingAndScanned(existing, scanned);
                        else
                            byPath[scanned.FilePath] = scanned;
                    }
                }

                newAllItems = byPath.Values.ToList();
            }

            List<AlbumEntry>? albums = null;
            if (string.Equals(category.Id, "music", StringComparison.OrdinalIgnoreCase))
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = $"Indexing albums... {scannedItems.Count} tracks";
                });
                var musicTracks = newAllItems.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
                albums = BuildAlbumEntries(musicTracks);
            }

            _ = SaveLibraryToDiskAsync(newAllItems.ToList());

            _uiDispatcher.BeginInvoke(() =>
            {
                lock (_stateLock)
                {
                    _allItems = newAllItems;
                }

                if (albums != null)
                {
                    _musicAlbums.Clear();
                    foreach (var a in albums) _musicAlbums.Add(a);
                    RebuildAlbumRows();
                    category.Count = _musicAlbums.Count;
                }
                else
                {
                    category.Count = scannedItems.Count;
                }

                ScanProgressText = $"Scan complete: {scannedItems.Count} items";
                StatusText = "Ready";
                IsScanning = false;
                CommandManager.InvalidateRequerySuggested();

                OnPropertyChanged(nameof(LibraryCountText));
                OnPropertyChanged(nameof(PlaytimeText));
                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));
                ApplyCategoryFilter();
            });
        }

        private List<MediaItem> ScanFolder(string categoryId, string rootFolder, CancellationToken ct)
        {
            var items = new List<MediaItem>();
            if (!Directory.Exists(rootFolder))
                return items;

            HashSet<string> ext;
            switch (categoryId.ToLowerInvariant())
            {
                case "music":
                case "radio":
                case "karaoke":
                    ext = AudioExtensions;
                    break;
                case "movies":
                case "tv":
                    ext = VideoExtensions;
                    break;
                case "images":
                    ext = ImageExtensions;
                    break;
                case "games":
                    ext = GameExtensions;
                    break;
                default:
                    ext = AudioExtensions;
                    break;
            }

            var accent = AccentForCategory(categoryId);
            var icon = IconForCategory(categoryId);

            var visited = 0;
            var matched = 0;
            var lastUiUpdateUtc = DateTime.UtcNow;

            var dirs = new Stack<string>();
            dirs.Push(rootFolder);

            while (dirs.Count > 0)
            {
                ct.ThrowIfCancellationRequested();
                var dir = dirs.Pop();

                IEnumerable<string> subDirs;
                try
                {
                    subDirs = Directory.EnumerateDirectories(dir);
                }
                catch
                {
                    continue;
                }

                foreach (var sub in subDirs)
                {
                    ct.ThrowIfCancellationRequested();
                    if (string.Equals(categoryId, "games", StringComparison.OrdinalIgnoreCase))
                    {
                        if (sub.Contains("\\_CommonRedist\\", StringComparison.OrdinalIgnoreCase) ||
                            sub.Contains("\\Redist\\", StringComparison.OrdinalIgnoreCase) ||
                            sub.Contains("\\__Installer\\", StringComparison.OrdinalIgnoreCase) ||
                            sub.Contains("\\Installer\\", StringComparison.OrdinalIgnoreCase) ||
                            sub.Contains("\\Support\\", StringComparison.OrdinalIgnoreCase) ||
                            sub.Contains("\\docs\\", StringComparison.OrdinalIgnoreCase))
                            continue;
                    }
                    dirs.Push(sub);
                }

                IEnumerable<string> files;
                try
                {
                    files = Directory.EnumerateFiles(dir, "*.*", SearchOption.TopDirectoryOnly);
                }
                catch
                {
                    continue;
                }

                foreach (var filePath in files)
                {
                    ct.ThrowIfCancellationRequested();
                    visited++;

                    var nowUtc = DateTime.UtcNow;
                    if (visited == 1 || visited % 250 == 0 || (nowUtc - lastUiUpdateUtc) > TimeSpan.FromSeconds(1))
                    {
                        lastUiUpdateUtc = nowUtc;
                        var visitedSnapshot = visited;
                        var matchedSnapshot = matched;
                        var fileSnapshot = Path.GetFileName(filePath);
                        _uiDispatcher.BeginInvoke(() =>
                        {
                            ScannedCount = matchedSnapshot;
                            ScanProgressText = $"Scanning... {matchedSnapshot} found · {visitedSnapshot} files · {fileSnapshot}";
                        });
                    }

                    if (string.Equals(categoryId, "games", StringComparison.OrdinalIgnoreCase))
                    {
                        var d = Path.GetDirectoryName(filePath) ?? "";
                        if (d.Contains("\\_CommonRedist\\", StringComparison.OrdinalIgnoreCase) ||
                            d.Contains("\\Redist\\", StringComparison.OrdinalIgnoreCase) ||
                            d.Contains("\\__Installer\\", StringComparison.OrdinalIgnoreCase) ||
                            d.Contains("\\Installer\\", StringComparison.OrdinalIgnoreCase) ||
                            d.Contains("\\Support\\", StringComparison.OrdinalIgnoreCase) ||
                            d.Contains("\\docs\\", StringComparison.OrdinalIgnoreCase))
                            continue;
                    }

                    var extension = Path.GetExtension(filePath);

                    if (string.Equals(categoryId, "karaoke", StringComparison.OrdinalIgnoreCase) &&
                        string.Equals(extension, ".zip", StringComparison.OrdinalIgnoreCase))
                    {
                        var expanded = ExpandKaraokeZipPack(filePath, categoryId, accent, icon);
                        if (expanded.Count > 0)
                        {
                            items.AddRange(expanded);
                            matched += expanded.Count;
                            continue;
                        }
                    }

                    if (!ext.Contains(extension))
                        continue;

                    if (string.Equals(categoryId, "games", StringComparison.OrdinalIgnoreCase))
                    {
                        var name = Path.GetFileName(filePath);
                        if (name.Contains("unins", StringComparison.OrdinalIgnoreCase) ||
                            name.Contains("uninstall", StringComparison.OrdinalIgnoreCase) ||
                            name.Contains("setup", StringComparison.OrdinalIgnoreCase) ||
                            name.Contains("installer", StringComparison.OrdinalIgnoreCase) ||
                            name.Contains("crash", StringComparison.OrdinalIgnoreCase) ||
                            name.Contains("vcredist", StringComparison.OrdinalIgnoreCase))
                            continue;
                    }

                    matched++;

                    var title = Path.GetFileNameWithoutExtension(filePath) ?? "";
                    var artist = "";
                    var album = Path.GetFileName(Path.GetDirectoryName(filePath) ?? "") ?? "";
                    var trackNumber = 0;
                    var duration = TimeSpan.Zero;

                    var isGame = string.Equals(categoryId, "games", StringComparison.OrdinalIgnoreCase);
                    var inferredType = categoryId;
                    if (string.Equals(categoryId, "music", StringComparison.OrdinalIgnoreCase) &&
                        LooksLikeKaraokeTrack(filePath, album))
                        inferredType = "karaoke";

                    ScannerMediaType mediaType = ScannerMediaType.Unknown;
                    if (!isGame)
                    {
                        if (AudioExtensions.Contains(extension)) mediaType = ScannerMediaType.Audio;
                        else if (VideoExtensions.Contains(extension)) mediaType = ScannerMediaType.Video;
                        else if (ImageExtensions.Contains(extension)) mediaType = ScannerMediaType.Image;
                    }

                    ScannerMediaItem? playbackItem = null;
                    if (!isGame)
                    {
                        playbackItem = new ScannerMediaItem
                        {
                            FilePath = filePath,
                            DisplayName = title,
                            Extension = extension.ToLowerInvariant(),
                            FileSize = 0,
                            LastModified = DateTime.UtcNow,
                            MediaType = string.Equals(inferredType, "karaoke", StringComparison.OrdinalIgnoreCase) ? ScannerMediaType.Video : mediaType,
                            SectionName = string.Equals(inferredType, "karaoke", StringComparison.OrdinalIgnoreCase) ? "Karaoke" : categoryId,
                            FolderPath = Path.GetDirectoryName(filePath) ?? "",
                            DateAdded = DateTime.UtcNow,
                            Album = album,
                            Artist = artist,
                            TrackNumber = trackNumber == 0 ? null : trackNumber,
                            Duration = duration == TimeSpan.Zero ? null : duration
                        };
                    }

                    items.Add(new MediaItem
                    {
                        PlaybackItem = playbackItem,
                        FilePath = filePath,
                        Title = title,
                        Artist = artist,
                        Album = album,
                        TrackNumber = trackNumber,
                        DiscNumber = GetDiscNumberFromPath(filePath),
                        Duration = duration,
                        Type = inferredType,
                        AccentBrush = AccentForCategory(inferredType),
                        IconGeometry = IconForCategory(inferredType),
                        CoverImage = null
                    });
                }
            }

            _uiDispatcher.BeginInvoke(() =>
            {
                ScannedCount = matched;
                ScanProgressText = matched == 0 ? "No matching files found" : $"Found {matched} item(s)";
            });

            if (string.Equals(categoryId, "music", StringComparison.OrdinalIgnoreCase))
            {
                return items.OrderBy(i => i.Album, StringComparer.OrdinalIgnoreCase)
                            .ThenBy(i => i.DiscNumber == 0 ? 999 : i.DiscNumber)
                            .ThenBy(i => i.TrackNumber == 0 ? 999 : i.TrackNumber)
                            .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase)
                            .ToList();
            }

            return items.OrderBy(i => i.Title, StringComparer.OrdinalIgnoreCase).ToList();
        }

        private List<MediaItem> ExpandKaraokeZipPack(string zipPath, string categoryId, Brush accent, Geometry icon)
        {
            var results = new List<MediaItem>();
            if (!File.Exists(zipPath)) return results;

            var zipBase = Path.GetFileNameWithoutExtension(zipPath) ?? "";
            var folder = Path.GetDirectoryName(zipPath) ?? "";
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            try
            {
                using var fs = new FileStream(zipPath, FileMode.Open, FileAccess.Read, FileShare.ReadWrite);
                using var archive = new ZipArchive(fs, ZipArchiveMode.Read);
                var entries = archive.Entries.Where(e => !e.FullName.EndsWith("/", StringComparison.Ordinal)).ToList();

                foreach (var entry in entries)
                {
                    var entryExt = Path.GetExtension(entry.Name);
                    if (string.IsNullOrWhiteSpace(entryExt)) continue;

                    if (string.Equals(entryExt, ".zip", StringComparison.OrdinalIgnoreCase))
                    {
                        try
                        {
                            using var nestedStream = entry.Open();
                            using var ms = new MemoryStream();
                            nestedStream.CopyTo(ms);
                            ms.Position = 0;
                            using var nested = new ZipArchive(ms, ZipArchiveMode.Read);
                            foreach (var inner in nested.Entries.Where(e => !e.FullName.EndsWith("/", StringComparison.Ordinal)))
                            {
                                var innerExt = Path.GetExtension(inner.Name);
                                if (!IsKaraokePlayableInnerExtension(innerExt)) continue;

                                var specialPath = $"{zipPath}|{entry.FullName}|{inner.FullName}";
                                if (!seen.Add(specialPath)) continue;

                                var title = (Path.GetFileNameWithoutExtension(inner.Name) ?? "").Trim();
                                if (string.IsNullOrWhiteSpace(title)) title = zipBase;

                                var playbackItem = new ScannerMediaItem
                                {
                                    FilePath = specialPath,
                                    DisplayName = title,
                                    Extension = (innerExt ?? "").ToLowerInvariant(),
                                    FileSize = inner.Length,
                                    LastModified = DateTime.UtcNow,
                                    MediaType = ScannerMediaType.Video,
                                    SectionName = categoryId,
                                    FolderPath = folder,
                                    DateAdded = DateTime.UtcNow,
                                    Album = zipBase,
                                    Artist = "",
                                    TrackNumber = null,
                                    Duration = null
                                };

                                results.Add(new MediaItem
                                {
                                    PlaybackItem = playbackItem,
                                    FilePath = specialPath,
                                    Title = title,
                                    Artist = "",
                                    Album = zipBase,
                                    TrackNumber = 0,
                                    DiscNumber = 0,
                                    Duration = TimeSpan.Zero,
                                    Type = categoryId,
                                    AccentBrush = accent,
                                    IconGeometry = icon,
                                    CoverImage = null
                                });
                            }
                        }
                        catch
                        {
                        }

                        continue;
                    }

                    if (!IsKaraokePlayableInnerExtension(entryExt)) continue;

                    var directPath = $"{zipPath}|{entry.FullName}";
                    if (!seen.Add(directPath)) continue;

                    var directTitle = (Path.GetFileNameWithoutExtension(entry.Name) ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(directTitle)) directTitle = zipBase;

                    var directPlayback = new ScannerMediaItem
                    {
                        FilePath = directPath,
                        DisplayName = directTitle,
                        Extension = (entryExt ?? "").ToLowerInvariant(),
                        FileSize = entry.Length,
                        LastModified = DateTime.UtcNow,
                        MediaType = ScannerMediaType.Video,
                        SectionName = categoryId,
                        FolderPath = folder,
                        DateAdded = DateTime.UtcNow,
                        Album = zipBase,
                        Artist = "",
                        TrackNumber = null,
                        Duration = null
                    };

                    results.Add(new MediaItem
                    {
                        PlaybackItem = directPlayback,
                        FilePath = directPath,
                        Title = directTitle,
                        Artist = "",
                        Album = zipBase,
                        TrackNumber = 0,
                        DiscNumber = 0,
                        Duration = TimeSpan.Zero,
                        Type = categoryId,
                        AccentBrush = accent,
                        IconGeometry = icon,
                        CoverImage = null
                    });
                }
            }
            catch
            {
                return new List<MediaItem>();
            }

            return results
                .OrderBy(i => i.Album ?? "", StringComparer.OrdinalIgnoreCase)
                .ThenBy(i => i.Title ?? "", StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        private static bool IsKaraokePlayableInnerExtension(string? extension)
        {
            if (string.IsNullOrWhiteSpace(extension)) return false;
            return extension.Equals(".mp3", StringComparison.OrdinalIgnoreCase) ||
                   extension.Equals(".wav", StringComparison.OrdinalIgnoreCase) ||
                   extension.Equals(".wma", StringComparison.OrdinalIgnoreCase) ||
                   extension.Equals(".m4a", StringComparison.OrdinalIgnoreCase) ||
                   extension.Equals(".mp4", StringComparison.OrdinalIgnoreCase) ||
                   extension.Equals(".avi", StringComparison.OrdinalIgnoreCase) ||
                   extension.Equals(".mkv", StringComparison.OrdinalIgnoreCase);
        }

        private async void PlayItem(MediaItem? item)
        {
            if (item == null) return;
            if (string.Equals(item.Type, "cloud", StringComparison.OrdinalIgnoreCase))
            {
                OpenStreamsForItem(item);
                return;
            }
            if (!IsServersView &&
                item.PlaybackItem == null &&
                string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
            {
                var isLocal = false;
                try { isLocal = !string.IsNullOrWhiteSpace(item.FilePath) && File.Exists(item.FilePath); } catch { isLocal = false; }
                if (!isLocal)
                {
                    if (IsHttpUrl(item.FilePath, out _))
                    {
                        PlayStreamUrl(item.FilePath, string.IsNullOrWhiteSpace(item.Title) ? "Music" : item.Title);
                        return;
                    }
                    _ = PlayServersMusicAsync(item);
                    return;
                }
            }
            if (IsServersView &&
                item.PlaybackItem == null &&
                string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
            {
                _ = PlayServersMusicAsync(item);
                return;
            }
            if (!string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(item.Type, "karaoke", StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(item.Type, "radio", StringComparison.OrdinalIgnoreCase))
            {
                var t = (item.Type ?? "").Trim();
                if (string.Equals(t, "movies", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(t, "movie", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(t, "tv", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(t, "series", StringComparison.OrdinalIgnoreCase))
                {
                    var playbackItem = ResolvePlaybackItem(item);
                    if (playbackItem != null)
                    {
                        PlayVideoLibraryItem(item);
                    }
                    else
                    {
                        _ = PlayBestStreamForItemAsync(item);
                    }
                }
                return;
            }
            foreach (var i in LibraryItems)
            {
                i.IsSelected = ReferenceEquals(i, item);
                i.IsPlaying = false;
            }

            item.IsSelected = true;
            item.IsPlaying = true;
            string? playbackNotice = null;

            if (string.Equals(item.Type, "games", StringComparison.OrdinalIgnoreCase))
            {
                item.IsPlaying = false;
                LaunchGame(item);
                NowPlayingTitle = item.Title;
                NowPlayingArtist = item.Artist;
                NowPlayingAlbum = item.Album;
                NowPlayingTypeId = item.Type ?? "";
                TotalSeconds = 0;
                ProgressSeconds = 0;
                IsPlaying = false;
                StatusText = $"Launching · {item.Title}";
                OnPropertyChanged(nameof(NowPlayingTitle));
                OnPropertyChanged(nameof(NowPlayingArtist));
                OnPropertyChanged(nameof(NowPlayingAlbum));
                OnPropertyChanged(nameof(NowPlayingTypeId));
                OnPropertyChanged(nameof(IsNowPlayingMusic));
                OnPropertyChanged(nameof(TrendingValue));
                OnPropertyChanged(nameof(VisibleCountText));
                return;
            }

            if (item.PlaybackItem != null)
            {
                if (string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
                {
                    var itemFolder = Path.GetDirectoryName(item.FilePath) ?? "";
                    NowPlayingCoverImage = item.CoverImage ?? LoadMusicCoverForTrack(item.FilePath);
                    var albumTracks = _allItems.Where(t =>
                            string.Equals(t.Type, "music", StringComparison.OrdinalIgnoreCase) &&
                            string.Equals(Path.GetDirectoryName(t.FilePath) ?? "", itemFolder, StringComparison.OrdinalIgnoreCase))
                        .Select(t => t.PlaybackItem)
                        .Where(t => t != null)
                        .Cast<ScannerMediaItem>()
                        .OrderBy(t => t.TrackNumber ?? 999)
                        .ThenBy(t => t.DisplayName)
                        .ToList();

                    if (albumTracks.Count > 1)
                    {
                        _playbackService.PlayAlbum(albumTracks, item.PlaybackItem);
                    }
                    else
                    {
                        _playbackService.PlaySingle(item.PlaybackItem);
                    }
                }
                else if (string.Equals(item.Type, "karaoke", StringComparison.OrdinalIgnoreCase))
                {
                    NowPlayingCoverImage = item.CoverImage
                        ?? BuildCoverForType(item.Type, item.FilePath, item.Album ?? "", item.TrackNumber);

                    var fp = (item.FilePath ?? "").Trim();
                    var packRoot = fp.Contains('|') ? fp.Split('|')[0] : "";
                    var packTracks = string.IsNullOrWhiteSpace(packRoot)
                        ? new List<ScannerMediaItem>()
                        : _allItems.Where(t =>
                                string.Equals(t.Type, "karaoke", StringComparison.OrdinalIgnoreCase) &&
                                !string.IsNullOrWhiteSpace(t.FilePath) &&
                                t.FilePath.StartsWith(packRoot + "|", StringComparison.OrdinalIgnoreCase))
                            .Select(t => t.PlaybackItem)
                            .Where(t => t != null)
                            .Cast<ScannerMediaItem>()
                            .OrderBy(t => t.DisplayName)
                            .ToList();

                    if (packTracks.Count > 1)
                        _playbackService.PlayAlbum(packTracks, item.PlaybackItem);
                    else
                        _playbackService.PlaySingle(item.PlaybackItem);
                }
                else
                {
                    NowPlayingCoverImage = item.CoverImage
                        ?? BuildCoverForType(item.Type, item.FilePath, item.Album ?? "", item.TrackNumber);
                    _playbackService.PlaySingle(item.PlaybackItem);
                }
            }

            NowPlayingTitle = item.Title;
            NowPlayingArtist = item.Artist;
            NowPlayingAlbum = item.Album;
            TotalSeconds = item.Duration.TotalSeconds;
            ProgressSeconds = 0;
            IsPlaying = true;
            StatusText = string.IsNullOrWhiteSpace(playbackNotice) ? "Playing" : $"Playing · {playbackNotice}";

            OnPropertyChanged(nameof(NowPlayingTitle));
            OnPropertyChanged(nameof(NowPlayingArtist));
            OnPropertyChanged(nameof(NowPlayingAlbum));
            OnPropertyChanged(nameof(TrendingValue));
            OnPropertyChanged(nameof(VisibleCountText));
        }

        private void OpenAddCloudLink()
        {
            EnsureCloudProvidersLoaded();
            CloudLinkUrl = "";
            CloudLinkTitle = "";
            CloudStatusText = "";
            if (SelectedCloudProvider == null)
                SelectedCloudProvider = _cloudProviders.FirstOrDefault();
            IsAddCloudLinkOpen = true;
        }

        private void OpenStreamsForItem(MediaItem? item)
        {
            if (item == null) return;
            EnsureCloudProvidersLoaded();
            RefreshAddonServers();

            try
            {
                if (IsServersView &&
                    string.Equals((item.Type ?? "").Trim(), "music", StringComparison.OrdinalIgnoreCase) &&
                    IsHttpUrl(item.FilePath, out var uri) &&
                    uri.Host.Contains("soundcloud.com", StringComparison.OrdinalIgnoreCase))
                {
                    var apps = Categories.FirstOrDefault(c => string.Equals(c.Id, "apps", StringComparison.OrdinalIgnoreCase));
                    if (apps != null)
                        SelectCategory(apps);
                    _appsNavigator?.Invoke(item.FilePath);
                    return;
                }
            }
            catch
            {
            }

            if (IsServersView)
            {
                SelectedStreamsMode = StreamsMode.Servers;
                IsStreamsOpen = false;
                IsWatchLaterPanelOpen = false;
                IsServerStreamsPanelOpen = !UseServersWebViewBridge;
                StreamsSearchQuery = (SearchQuery ?? "").Trim();
                _streamsTargetItem = item;
                OnPropertyChanged(nameof(StreamsHeaderText));
                _ = RefreshStreamsAsync(item);
                return;
            }

            IsWatchLaterPanelOpen = false;
            _streamsTargetItem = item;
            OnPropertyChanged(nameof(StreamsHeaderText));
            IsServerStreamsPanelOpen = false;
            IsStreamsOpen = true;
            StreamsSearchQuery = (SearchQuery ?? "").Trim();
            _ = RefreshStreamsAsync(item);
        }

        private void CloseStreamsPanels()
        {
            if (IsServerStreamsPanelOpen)
            {
                IsServerStreamsPanelOpen = false;
                if (_serverStreamsBackToSeries)
                {
                    _serverStreamsBackToSeries = false;
                    IsServerSeriesPanelOpen = true;
                }
                return;
            }

            IsStreamsOpen = false;
        }

        private void OpenServerSeries(MediaItem? item)
        {
            if (!IsServersView || item == null)
                return;

            IsServerStreamsPanelOpen = false;
            _serverStreamsBackToSeries = false;
            IsWatchLaterPanelOpen = false;

            _serverSeriesRootItem = item;
            OnPropertyChanged(nameof(ServerSeriesHeaderText));
            OnPropertyChanged(nameof(ServerSeriesRootItem));
            OnPropertyChanged(nameof(ServerSeriesBackdropImage));
            ServerSeriesStatusText = "";
            ClearServerSeriesState(clearRoot: false);
            IsServerSeriesPanelOpen = true;
            _ = RefreshServerSeriesMetaAsync();
            _ = RefreshServerSeriesAsync();
        }

        /// <summary>
        /// Load series episodes for the React bridge without opening native WPF panels.
        /// </summary>
        public void LoadServerSeriesForBridge(MediaItem? item)
        {
            if (!IsServersView || item == null)
                return;

            StopBackgroundPlaybackForBridge();

            IsServerStreamsPanelOpen = false;
            _serverStreamsBackToSeries = false;
            IsWatchLaterPanelOpen = false;

            _serverSeriesRootItem = item;
            OnPropertyChanged(nameof(ServerSeriesHeaderText));
            OnPropertyChanged(nameof(ServerSeriesRootItem));
            OnPropertyChanged(nameof(ServerSeriesBackdropImage));
            ServerSeriesStatusText = "";
            ClearServerSeriesState(clearRoot: false);
            // NOTE: Deliberately NOT setting IsServerSeriesPanelOpen = true
            // so the native panel stays hidden while React handles the UI.

            // Populate full metadata (overview, ratings, cast) from TMDB/meta endpoint.
            DetailsItem = item;
            DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "Loading metadata..." : item.Metadata;
            try { _detailsMetaCts?.Cancel(); _detailsMetaCts?.Dispose(); } catch { }
            _detailsMetaCts = new CancellationTokenSource();
            _ = LoadDetailsMetaAsync(item, _detailsMetaCts.Token);

            _ = RefreshServerSeriesMetaAsync();
            _ = RefreshServerSeriesAsync();
        }

        /// <summary>
        /// Load streams for the React bridge without opening native WPF panels.
        /// </summary>
        public void LoadStreamsForBridge(MediaItem? item)
        {
            if (item == null) return;

            StopBackgroundPlaybackForBridge();

            var incomingToken = (item.MetaId ?? item.ImdbId ?? item.FilePath ?? "").Trim();
            var currentToken = (_streamsTargetItem?.MetaId ?? _streamsTargetItem?.ImdbId ?? _streamsTargetItem?.FilePath ?? "").Trim();
            var sameTarget = !string.IsNullOrWhiteSpace(incomingToken) &&
                             string.Equals(incomingToken, currentToken, StringComparison.OrdinalIgnoreCase);

            // Ignore duplicate bridge requests for the same item while loading or after sources are present.
            if (sameTarget)
            {
                if (IsStreamsBusy)
                {
                    AtlasAI.Core.AppLogger.LogInfo($"[BridgeStreams] ignored duplicate while busy token={incomingToken}");
                    return;
                }

                if (_streamSources.Count > 0)
                {
                    AtlasAI.Core.AppLogger.LogInfo($"[BridgeStreams] ignored duplicate with cached sources token={incomingToken} count={_streamSources.Count}");
                    return;
                }
            }

            // If a different item's fetch is already running, queue it and return without
            // touching _streamsTargetItem. PostStreamsState must keep reporting the mediaId
            // of the currently running fetch; updating it now would label the old fetch's
            // sources with the new item's id (the race that caused the double-load bug).
            if (IsStreamsBusy)
            {
                _pendingStreamsTargetItem = item;
                _streamsRefreshRequested = true;
                return;
            }

            try { SetPreviewItem(item); } catch { }

            // Populate full metadata (overview, ratings, cast) from TMDB/meta endpoint.
            DetailsItem = item;
            DetailsOverview = string.IsNullOrWhiteSpace(item.Metadata) ? "Loading metadata..." : item.Metadata;
            try { _detailsMetaCts?.Cancel(); _detailsMetaCts?.Dispose(); } catch { }
            _detailsMetaCts = new CancellationTokenSource();
            _ = LoadDetailsMetaAsync(item, _detailsMetaCts.Token);

            SelectedStreamsMode = StreamsMode.Servers;
            _streamsTargetItem = item;
            StreamsSearchQuery = "";
            OnPropertyChanged(nameof(StreamsHeaderText));
            // NOTE: Deliberately NOT setting IsServerStreamsPanelOpen, IsStreamsOpen,
            // or IsDetailsOpen — React handles all of those.
            RefreshAddonServers();
            _ = RefreshStreamsAsync(item);
        }

        private void StopBackgroundPlaybackForBridge()
        {
            try
            {
                var hasActivePlayback = IsPlaying;
                try { hasActivePlayback = hasActivePlayback || _playbackService.CurrentMedia != null; } catch { }
                if (!hasActivePlayback)
                    return;

                StopPlayback();
                try { _playbackService.ClearQueue(); } catch { }
                try { AtlasAI.Core.AppLogger.LogInfo("[BridgePlay] background playback stopped before loading detail/streams"); } catch { }
            }
            catch
            {
            }
        }


        private bool CanAddToWatchLater(MediaItem? item)
        {
            if (item == null) return false;
            var id = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id)) return false;
            if (id.Contains('\\') || id.Contains('/')) return false;
            return true;
        }

        private void AddToWatchLater(MediaItem? item)
        {
            if (item == null) return;
            var id = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id)) return;
            if (id.Contains('\\') || id.Contains('/')) return;

            try
            {
                PreferencesStore.Instance.Update(prefs =>
                {
                    prefs.WatchLaterMediaIds ??= new List<string>();
                    if (!prefs.WatchLaterMediaIds.Any(x => string.Equals(x, id, StringComparison.OrdinalIgnoreCase)))
                        prefs.WatchLaterMediaIds.Add(id);
                });
            }
            catch
            {
                return;
            }

            if (IsServersView)
                ServerCatalogStatusText = "Added to Watch Later";
            else
                StatusText = "Added to Watch Later";

            if (IsWatchLaterPanelOpen)
                _ = RefreshWatchLaterAsync();
        }

        private void RemoveFromWatchLater(MediaItem? item)
        {
            if (item == null) return;
            var id = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id)) return;

            try
            {
                PreferencesStore.Instance.Update(prefs =>
                {
                    if (prefs.WatchLaterMediaIds == null || prefs.WatchLaterMediaIds.Count == 0) return;
                    prefs.WatchLaterMediaIds.RemoveAll(x => string.Equals((x ?? "").Trim(), id, StringComparison.OrdinalIgnoreCase));
                });
            }
            catch
            {
                return;
            }

            if (IsServersView)
                ServerCatalogStatusText = "Removed from Watch Later";
            else
                StatusText = "Removed from Watch Later";

            if (IsWatchLaterPanelOpen)
                _ = RefreshWatchLaterAsync();
        }

        private void RemoveFromContinue(MediaItem? item)
        {
            if (item == null) return;
            var key = (item.FilePath ?? "").Trim();
            var title = (item.Title ?? "").Trim();

            var removed = 0;
            try
            {
                if (!string.IsNullOrWhiteSpace(key))
                    removed = AtlasAI.Core.WatchHistoryStore.RemoveMatching(key);

                if (removed <= 0 && !string.IsNullOrWhiteSpace(title))
                    removed = AtlasAI.Core.WatchHistoryStore.RemoveByTitle(title);
            }
            catch
            {
            }

            ContinueStatusText = removed > 0 ? "Removed" : "Not found";
            NotifyWatchHistoryChanged();
        }

        public void NotifyWatchHistoryChanged()
        {
            try
            {
                RefreshHomeContinue();
            }
            catch
            {
            }

            try
            {
                if (IsContinuePanelOpen)
                    _ = RefreshContinueAsync();
            }
            catch
            {
            }

            try
            {
                RebuildServerShelves();
            }
            catch
            {
            }
        }

        private async Task RefreshWatchLaterAsync()
        {
            if (IsWatchLaterBusy)
                return;

            try
            {
                _watchLaterCts?.Cancel();
                _watchLaterCts?.Dispose();
            }
            catch
            {
            }
            _watchLaterCts = new CancellationTokenSource(TimeSpan.FromSeconds(18));
            var ct = _watchLaterCts.Token;

            IsWatchLaterBusy = true;
            WatchLaterStatusText = "Loading...";
            CommandManager.InvalidateRequerySuggested();

            try
            {
                var ids = (PreferencesStore.Instance.Current.WatchLaterMediaIds ?? new List<string>())
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(x => x.Trim())
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(UserPreferences.MaxWatchLaterMediaIds)
                    .ToList();

                if (ids.Count == 0)
                {
                    _uiDispatcher.Invoke(() => _watchLaterItems.Clear());
                    WatchLaterStatusText = "No items";
                    return;
                }

                var results = new List<MediaItem>();
                var semaphore = new SemaphoreSlim(6);
                var tasks = ids.Select(async id =>
                {
                    await semaphore.WaitAsync(ct).ConfigureAwait(false);
                    try
                    {
                        return await TryLoadWatchLaterItemAsync(id, ct).ConfigureAwait(false);
                    }
                    finally
                    {
                        semaphore.Release();
                    }
                }).ToList();

                var loaded = await Task.WhenAll(tasks);
                results = loaded.Where(x => x != null).Cast<MediaItem>().ToList();

                _uiDispatcher.Invoke(() =>
                {
                    _watchLaterItems.Clear();
                    foreach (var i in results)
                        _watchLaterItems.Add(i);
                });

                WatchLaterStatusText = $"{results.Count} item(s)";
                _ = QueueWatchLaterCoverLoadingAsync(ct);
            }
            catch
            {
                WatchLaterStatusText = "Failed to load";
            }
            finally
            {
                IsWatchLaterBusy = false;
                CommandManager.InvalidateRequerySuggested();
            }
        }

        private async Task RefreshContinueAsync()
        {
            if (IsContinueBusy)
                return;
            IsContinueBusy = true;
            ContinueStatusText = "Loading...";
            CancellationTokenSource? cts = null;
            try
            {
                cts = new CancellationTokenSource(TimeSpan.FromSeconds(15));
                var recent = AtlasAI.Core.WatchHistoryStore.GetRecent(24);
                var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                var items = new List<MediaItem>();
                foreach (var r in recent)
                {
                    var id = AtlasAI.Core.WatchHistoryStore.NormalizeIdentity(r.filePath);
                    if (string.IsNullOrWhiteSpace(id)) continue;
                    if (!id.Contains('\\') && !id.Contains('/') && !LooksLikeStableMediaIdToken(id))
                        continue;
                    if (!seen.Add(id)) continue;
                    items.Add(new MediaItem
                    {
                        FilePath = id,
                        MetaId = id,
                        Title = r.title,
                        Type = r.type,
                        CoverUrl = r.coverUrl,
                        BackdropUrl = r.backdropUrl
                    });
                }

                _uiDispatcher.Invoke(() =>
                {
                    _continueItems.Clear();
                    foreach (var i in items)
                    {
                        _continueItems.Add(i);
                        _ = TryLoadCoverIntoItemAsync(i, CancellationToken.None);
                    }
                    ContinueStatusText = _continueItems.Count == 0 ? "No items" : $"{_continueItems.Count} item(s)";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() => ContinueStatusText = "Failed to load");
            }
            finally
            {
                try { cts?.Cancel(); } catch { }
                try { cts?.Dispose(); } catch { }
                IsContinueBusy = false;
            }
        }

        private void DownloadItem(MediaItem? item)
        {
            if (item == null) return;
            if (IsServersView)
            {
                OpenStreamsForItem(item);
                _uiDispatcher.Invoke(() =>
                {
                    StreamsStatusText = "Right-click a source to download";
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            _ = DownloadLibraryItemAsync(item);
        }

        private bool CanDownloadItem(MediaItem? item)
        {
            if (item == null) return false;
            if (item.IsDownloading) return false;
            if (IsServersView) return true;

            try
            {
                if (!string.IsNullOrWhiteSpace(item.FilePath) && File.Exists(item.FilePath))
                    return true;
            }
            catch
            {
            }

            return IsHttpUrl(item.DownloadUrl ?? item.FilePath, out _);
        }

        private string? EnsureMediaDownloadsFolderSelected(bool forcePrompt)
        {
            try
            {
                var current = (PreferencesStore.Instance.Current.MediaDownloadsFolder ?? "").Trim();
                if (!forcePrompt)
                {
                    if (!string.IsNullOrWhiteSpace(current))
                    {
                        try { Directory.CreateDirectory(current); } catch { }
                        return current;
                    }
                    var def = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "Downloads", "AtlasAI");
                    try { Directory.CreateDirectory(def); } catch { }
                    PreferencesStore.Instance.Update(p => p.MediaDownloadsFolder = def);
                    _uiDispatcher.Invoke(() =>
                    {
                        OnPropertyChanged(nameof(HasMediaDownloadsFolder));
                        OnPropertyChanged(nameof(MediaDownloadsFolderText));
                        CommandManager.InvalidateRequerySuggested();
                    });
                    return def;
                }

                var dlg = new System.Windows.Forms.FolderBrowserDialog
                {
                    Description = "Choose download folder",
                    UseDescriptionForTitle = true,
                    ShowNewFolderButton = true,
                    SelectedPath = string.IsNullOrWhiteSpace(current)
                        ? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "Downloads", "AtlasAI")
                        : current
                };

                var result = dlg.ShowDialog();
                if (result != System.Windows.Forms.DialogResult.OK) return null;

                var chosen = (dlg.SelectedPath ?? "").Trim();
                if (string.IsNullOrWhiteSpace(chosen)) return null;
                try { Directory.CreateDirectory(chosen); } catch { }

                PreferencesStore.Instance.Update(p => p.MediaDownloadsFolder = chosen);
                _uiDispatcher.Invoke(() =>
                {
                    OnPropertyChanged(nameof(HasMediaDownloadsFolder));
                    OnPropertyChanged(nameof(MediaDownloadsFolderText));
                    CommandManager.InvalidateRequerySuggested();
                });
                return chosen;
            }
            catch
            {
                return null;
            }
        }

