                if (string.IsNullOrWhiteSpace(folder)) return;
                try { Directory.CreateDirectory(folder); } catch { }
                try { Process.Start(new ProcessStartInfo(folder) { UseShellExecute = true }); } catch { }
            }
            catch
            {
            }
        }

        private bool CanAddDownloadJob()
        {
            if (IsScanning) return false;
            return !string.IsNullOrWhiteSpace((DownloadManagerUrl ?? "").Trim());
        }

        private void AddDownloadJob()
        {
            var raw = (DownloadManagerUrl ?? "").Trim();
            if (string.IsNullOrWhiteSpace(raw)) return;

            var parts = raw
                .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .Where(p => !string.IsNullOrWhiteSpace(p))
                .ToList();
            if (parts.Count == 0) return;

            DownloadManagerUrl = "";

            foreach (var p in parts)
            {
                var url = (p ?? "").Trim();
                if (string.IsNullOrWhiteSpace(url)) continue;

                if (TryGetLocalCsvPath(url, out var csvPath))
                {
                    var csvJob = new DownloadJob
                    {
                        Url = csvPath,
                        DisplayName = Path.GetFileName(csvPath),
                        Status = "Queued in Downloader",
                        Progress = 0,
                        IsIndeterminate = false,
                        IsRunning = false
                    };
                    _uiDispatcher.Invoke(() => _downloadJobs.Insert(0, csvJob));
                    _ = AtlasAI.Modules.Downloader.DownloadManager.Instance.ImportCsvFromPathAsync(csvPath);
                    continue;
                }

                if (TryExtractSpotifyPlaylistId(url, out var playlistId))
                {
                    var playlistJob = new DownloadJob
                    {
                        Url = url,
                        DisplayName = "Spotify playlist",
                        Status = "Expanding...",
                        Progress = 0,
                        IsIndeterminate = true,
                        IsRunning = true
                    };
                    _uiDispatcher.Invoke(() => _downloadJobs.Insert(0, playlistJob));
                    _ = ExpandSpotifyPlaylistToJobsAsync(playlistId, playlistJob);
                    continue;
                }

                var job = new DownloadJob
                {
                    Url = url,
                    DisplayName = BuildDownloadDisplayName(url),
                    Status = "Queued",
                    Progress = 0,
                    IsIndeterminate = false,
                    IsRunning = false
                };

                _uiDispatcher.Invoke(() => _downloadJobs.Insert(0, job));
                _ = RunDownloadJobAsync(job);
            }

            _uiDispatcher.Invoke(() => CommandManager.InvalidateRequerySuggested());
        }

        private static bool TryGetLocalCsvPath(string input, out string csvPath)
        {
            csvPath = "";
            var s = (input ?? "").Trim().Trim('"');
            if (string.IsNullOrWhiteSpace(s)) return false;
            if (!s.EndsWith(".csv", StringComparison.OrdinalIgnoreCase)) return false;
            try
            {
                if (!File.Exists(s)) return false;
                csvPath = s;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private void CancelDownloadJob(DownloadJob? job)
        {
            if (job == null) return;
            try
            {
                if (_downloadJobCts.TryGetValue(job.Id, out var cts))
                    cts.Cancel();
            }
            catch
            {
            }
        }

        private void ClearCompletedDownloadJobs()
        {
            _uiDispatcher.Invoke(() =>
            {
                for (var i = _downloadJobs.Count - 1; i >= 0; i--)
                {
                    var j = _downloadJobs[i];
                    if (j == null) continue;
                    if (j.IsRunning) continue;
                    _downloadJobs.RemoveAt(i);
                }
                CommandManager.InvalidateRequerySuggested();
            });
        }

        private void ExportDownloadJobsCsv()
        {
            try
            {
                var jobs = DownloadJobs?.Where(j => j != null).ToList() ?? new List<DownloadJob>();
                if (jobs.Count == 0) return;

                var folder = (PreferencesStore.Instance.Current.MediaDownloadsFolder ?? "").Trim();
                if (string.IsNullOrWhiteSpace(folder))
                {
                    folder = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "Downloads");
                }
                try { Directory.CreateDirectory(folder); } catch { }

                var suggestedName = $"atlas_downloads_{DateTime.Now:yyyyMMdd_HHmm}.csv";

                var dialog = new SaveFileDialog
                {
                    Title = "Export Downloads CSV",
                    Filter = "CSV Files|*.csv|All Files|*.*",
                    FileName = suggestedName,
                    InitialDirectory = folder,
                    AddExtension = true,
                    DefaultExt = ".csv",
                    OverwritePrompt = true
                };

                if (dialog.ShowDialog() != true) return;
                var path = (dialog.FileName ?? "").Trim();
                if (string.IsNullOrWhiteSpace(path)) return;

                static string CsvEscape(string? value)
                {
                    var s = (value ?? "").Replace("\r", " ").Replace("\n", " ").Trim();
                    var needsQuotes = s.Contains(',') || s.Contains('"');
                    if (s.Contains('"'))
                        s = s.Replace("\"", "\"\"");
                    return needsQuotes ? $"\"{s}\"" : s;
                }

                using var sw = new StreamWriter(path, false, new UTF8Encoding(encoderShouldEmitUTF8Identifier: true));
                sw.WriteLine("id,displayName,url,status,progress,isRunning,isIndeterminate,destinationPath");
                foreach (var j in jobs)
                {
                    sw.Write(CsvEscape(j.Id));
                    sw.Write(",");
                    sw.Write(CsvEscape(j.DisplayName));
                    sw.Write(",");
                    sw.Write(CsvEscape(j.Url));
                    sw.Write(",");
                    sw.Write(CsvEscape(j.Status));
                    sw.Write(",");
                    sw.Write(CsvEscape(j.Progress.ToString("0.####", System.Globalization.CultureInfo.InvariantCulture)));
                    sw.Write(",");
                    sw.Write(CsvEscape(j.IsRunning ? "true" : "false"));
                    sw.Write(",");
                    sw.Write(CsvEscape(j.IsIndeterminate ? "true" : "false"));
                    sw.Write(",");
                    sw.WriteLine(CsvEscape(j.DestinationPath));
                }

                _uiDispatcher.Invoke(() =>
                {
                    StatusText = $"Exported CSV · {Path.GetFileName(path)}";
                    OnPropertyChanged(nameof(StatusText));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            catch
            {
            }
        }

        private static string BuildDownloadDisplayName(string url)
        {
            var s = (url ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return "Download";
            if (s.StartsWith("ytsearch", StringComparison.OrdinalIgnoreCase))
            {
                var idx = s.IndexOf(':');
                if (idx >= 0 && idx + 1 < s.Length)
                {
                    var q = s[(idx + 1)..].Trim();
                    if (!string.IsNullOrWhiteSpace(q)) return q;
                }
                return "YouTube";
            }
            if (s.StartsWith("magnet:", StringComparison.OrdinalIgnoreCase)) return "Magnet";
            try
            {
                if (File.Exists(s))
                {
                    var localName = Path.GetFileNameWithoutExtension(s);
                    if (!string.IsNullOrWhiteSpace(localName)) return localName;
                }
            }
            catch
            {
            }
            if (IsYouTubeUrl(s)) return "YouTube";
            if (IsM3u8Url(s)) return "Stream";
            try
            {
                if (Uri.TryCreate(s, UriKind.Absolute, out var u))
                {
                    var name = Path.GetFileName(u.AbsolutePath);
                    if (!string.IsNullOrWhiteSpace(name)) return name;
                    return u.Host;
                }
            }
            catch
            {
            }
            return "Download";
        }

        private static ICloudProvider? TryGetRealDebrid()
        {
            try
            {
                var p = CloudProviderRegistry.GetById("realdebrid");
                if (p == null)
                {
                    try
                    {
                        CloudProviderRegistry.Register(new RealDebridProvider(new DpapiFileSecretsStore()));
                    }
                    catch
                    {
                    }
                    p = CloudProviderRegistry.GetById("realdebrid");
                }

                if (p == null) return null;
                if (!p.IsConfigured) return null;
                return p;
            }
            catch
            {
                return null;
            }
        }

        private static bool TryExtractSpotifyPlaylistId(string url, out string playlistId)
        {
            playlistId = "";
            var s = (url ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return false;
            if (!s.Contains("open.spotify.com/playlist", StringComparison.OrdinalIgnoreCase)) return false;

            try
            {
                if (!Uri.TryCreate(s, UriKind.Absolute, out var u)) return false;
                var parts = (u.AbsolutePath ?? "").Split('/', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
                var idx = Array.FindIndex(parts, p => string.Equals(p, "playlist", StringComparison.OrdinalIgnoreCase));
                if (idx < 0 || idx + 1 >= parts.Length) return false;
                playlistId = parts[idx + 1].Trim();
                if (string.IsNullOrWhiteSpace(playlistId)) return false;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private async Task ExpandSpotifyPlaylistToJobsAsync(string playlistId, DownloadJob playlistJob)
        {
            try
            {
                var tracks = await SpotifyTool.GetPlaylistTrackQueriesAsync(playlistId).ConfigureAwait(false);
                if (tracks.Count == 0)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        playlistJob.IsIndeterminate = false;
                        playlistJob.IsRunning = false;
                        playlistJob.Status = "Empty playlist";
                        CommandManager.InvalidateRequerySuggested();
                    });
                    return;
                }

                _uiDispatcher.Invoke(() =>
                {
                    playlistJob.IsIndeterminate = false;
                    playlistJob.Progress = 1;
                    playlistJob.Status = $"Queued {tracks.Count}";
                    playlistJob.IsRunning = false;
                    CommandManager.InvalidateRequerySuggested();
                });

                foreach (var q in tracks)
                {
                    var job = new DownloadJob
                    {
                        Url = "ytsearch1:" + q,
                        DisplayName = q,
                        Status = "Queued",
                        Progress = 0,
                        IsIndeterminate = false,
                        IsRunning = false
                    };
                    _uiDispatcher.Invoke(() => _downloadJobs.Insert(0, job));
                    _ = RunDownloadJobAsync(job);
                }
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    playlistJob.IsIndeterminate = false;
                    playlistJob.IsRunning = false;
                    playlistJob.Status = "Playlist failed";
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private async Task RunDownloadJobAsync(DownloadJob job)
        {
            if (job == null) return;

            var folder = EnsureMediaDownloadsFolderSelected(forcePrompt: false) ?? EnsureMediaDownloadsFolderSelected(forcePrompt: true);
            if (string.IsNullOrWhiteSpace(folder))
            {
                _uiDispatcher.Invoke(() =>
                {
                    job.Status = "No folder";
                    job.IsRunning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            CancellationTokenSource cts;
            try
            {
                cts = new CancellationTokenSource();
                _downloadJobCts[job.Id] = cts;
            }
            catch
            {
                cts = new CancellationTokenSource();
            }
            var ct = cts.Token;

            await _downloadSemaphore.WaitAsync(ct).ConfigureAwait(false);
            try
            {
                _uiDispatcher.Invoke(() =>
                {
                    job.IsRunning = true;
                    job.Status = "Starting...";
                    job.Progress = 0;
                    job.IsIndeterminate = false;
                    CommandManager.InvalidateRequerySuggested();
                });

                var url = (job.Url ?? "").Trim();
                if (string.IsNullOrWhiteSpace(url))
                    throw new InvalidOperationException("No URL");

                string? suggestedName = null;
                var rd = TryGetRealDebrid();
                if (rd != null && (url.StartsWith("magnet:", StringComparison.OrdinalIgnoreCase) || IsHttpUrl(url, out _)))
                {
                    try
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            job.IsIndeterminate = true;
                            job.Status = "Real-Debrid...";
                        });

                        var un = await rd.UnrestrictAsync(url, ct).ConfigureAwait(false);
                        if (un.Success && !string.IsNullOrWhiteSpace(un.StreamUrl))
                        {
                            url = un.StreamUrl.Trim();
                            suggestedName = string.IsNullOrWhiteSpace(un.Filename) ? null : un.Filename.Trim();
                            if (!string.IsNullOrWhiteSpace(suggestedName))
                            {
                                _uiDispatcher.Invoke(() =>
                                {
                                    job.DisplayName = suggestedName!;
                                });
                            }
                        }
                        else if (url.StartsWith("magnet:", StringComparison.OrdinalIgnoreCase))
                        {
                            throw new InvalidOperationException(string.IsNullOrWhiteSpace(un.Error) ? "Real-Debrid failed" : un.Error);
                        }
                    }
                    catch (OperationCanceledException)
                    {
                        throw;
                    }
                    catch (Exception ex)
                    {
                        if (url.StartsWith("magnet:", StringComparison.OrdinalIgnoreCase))
                            throw new InvalidOperationException(ex.Message);
                    }
                    finally
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            job.IsIndeterminate = false;
                        });
                    }
                }

                if (IsYouTubeUrl(url))
                {
                    await DownloadJobFromYouTubeAsync(job, folder, ct).ConfigureAwait(false);
                }
                else if (IsM3u8Url(url))
                {
                    var dest = BuildUniqueGenericDownloadPath(folder, job.DisplayName, ".mp4");
                    job.DestinationPath = dest;
                    _uiDispatcher.Invoke(() =>
                    {
                        job.IsIndeterminate = true;
                        job.Status = "Downloading...";
                    });
                    await DownloadViaFfmpegAsync(url, dest, () => { }, ct).ConfigureAwait(false);
                }
                else if (IsHttpUrl(url, out var uri))
                {
                    var tryYtdlp = false;
                    var extRaw = "";
                    try { extRaw = Path.GetExtension(uri.AbsolutePath) ?? ""; } catch { extRaw = ""; }
                    if (string.IsNullOrWhiteSpace(extRaw) || extRaw.Equals(".html", StringComparison.OrdinalIgnoreCase))
                        tryYtdlp = true;
                    else
                    {
                        var headCt = await TryHeadContentTypeAsync(uri, ct).ConfigureAwait(false);
                        if (string.IsNullOrWhiteSpace(headCt) || headCt.Contains("text/html", StringComparison.OrdinalIgnoreCase))
                            tryYtdlp = true;
                    }

                    if (tryYtdlp)
                    {
                        var ok = await TryDownloadViaYtdlpGenericAsync(job, folder, ct).ConfigureAwait(false);
                        if (!ok)
                        {
                            var fileName = "";
                            if (!string.IsNullOrWhiteSpace(suggestedName))
                                fileName = suggestedName!;
                            else
                                try { fileName = Path.GetFileName(uri.AbsolutePath) ?? ""; } catch { fileName = ""; }
                            if (string.IsNullOrWhiteSpace(fileName))
                                fileName = job.DisplayName;
                            var dest = BuildUniqueGenericDownloadPath(folder, fileName, Path.GetExtension(uri.AbsolutePath));
                            job.DestinationPath = dest;
                            await DownloadHttpToFileAsync(uri, dest, p =>
                            {
                                _uiDispatcher.Invoke(() =>
                                {
                                    job.Progress = p;
                                    job.Status = p >= 1 ? "Finalizing..." : $"Downloading {(int)Math.Round(p * 100, MidpointRounding.AwayFromZero)}%";
                                });
                            }, ct).ConfigureAwait(false);
                        }
                    }
                    else
                    {
                        var fileName = "";
                        if (!string.IsNullOrWhiteSpace(suggestedName))
                            fileName = suggestedName!;
                        else
                            try { fileName = Path.GetFileName(uri.AbsolutePath) ?? ""; } catch { fileName = ""; }
                        if (string.IsNullOrWhiteSpace(fileName))
                            fileName = job.DisplayName;
                        var dest = BuildUniqueGenericDownloadPath(folder, fileName, Path.GetExtension(uri.AbsolutePath));
                        job.DestinationPath = dest;
                        await DownloadHttpToFileAsync(uri, dest, p =>
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                job.Progress = p;
                                job.Status = p >= 1 ? "Finalizing..." : $"Downloading {(int)Math.Round(p * 100, MidpointRounding.AwayFromZero)}%";
                            });
                        }, ct).ConfigureAwait(false);
                    }
                }
                else
                {
                    if (!string.IsNullOrWhiteSpace(url) && File.Exists(url))
                    {
                        var src = url;
                        var ext = "";
                        try { ext = Path.GetExtension(src) ?? ""; } catch { ext = ""; }
                        var transcode = CsvTranscodeToMp3;

                        var fileName = string.IsNullOrWhiteSpace(suggestedName) ? job.DisplayName : suggestedName!;
                        var dest = BuildUniqueGenericDownloadPath(folder, fileName, transcode ? ".mp3" : ext);
                        job.DestinationPath = dest;

                        if (transcode)
                        {
                            var ffmpegExe = ResolveFfmpegExecutable();
                            if (string.IsNullOrWhiteSpace(ffmpegExe) || !File.Exists(ffmpegExe))
                            {
                                using var ffCts = new CancellationTokenSource(TimeSpan.FromMinutes(3));
                                var ensured = await EnsureFfmpegAsync(ffCts.Token).ConfigureAwait(false);
                                if (!string.IsNullOrWhiteSpace(ensured) && File.Exists(ensured))
                                    ffmpegExe = ensured!;
                                else
                                    throw new InvalidOperationException("FFmpeg not found");
                            }

                            _uiDispatcher.Invoke(() =>
                            {
                                job.IsIndeterminate = true;
                                job.Status = "Converting...";
                            });

                            using var proc = new Process
                            {
                                StartInfo = new ProcessStartInfo
                                {
                                    FileName = ffmpegExe,
                                    Arguments = $"-hide_banner -loglevel error -y -i \"{src}\" -vn -codec:a libmp3lame -q:a 0 \"{dest}\"",
                                    UseShellExecute = false,
                                    CreateNoWindow = true,
                                    RedirectStandardOutput = true,
                                    RedirectStandardError = true
                                }
                            };
                            using var reg = ct.Register(() =>
                            {
                                try { if (!proc.HasExited) proc.Kill(entireProcessTree: true); } catch { }
                            });
                            proc.Start();
                            await proc.WaitForExitAsync(ct).ConfigureAwait(false);
                            if (!File.Exists(dest))
                                throw new InvalidOperationException("Convert failed");
                        }
                        else
                        {
                            await CopyFileWithProgressAsync(src, dest, p =>
                            {
                                _uiDispatcher.Invoke(() =>
                                {
                                    job.Progress = p;
                                    job.Status = p >= 1 ? "Finalizing..." : $"Copying {(int)Math.Round(p * 100, MidpointRounding.AwayFromZero)}%";
                                });
                            }, ct).ConfigureAwait(false);
                        }
                    }
                    else
                    {
                        throw new InvalidOperationException("Unsupported URL");
                    }
                }

                _uiDispatcher.Invoke(() =>
                {
                    job.Progress = 1;
                    job.IsIndeterminate = false;
                    job.Status = "Complete";
                    job.IsRunning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            catch (OperationCanceledException)
            {
                _uiDispatcher.Invoke(() =>
                {
                    job.IsIndeterminate = false;
                    job.Status = "Canceled";
                    job.IsRunning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            catch (Exception ex)
            {
                _uiDispatcher.Invoke(() =>
                {
                    var msg = (ex.Message ?? "").Replace("\r", " ").Replace("\n", " ").Trim();
                    if (msg.Length > 120) msg = msg.Substring(0, 120);
                    job.IsIndeterminate = false;
                    job.Status = string.IsNullOrWhiteSpace(msg) ? "Failed" : $"Failed · {msg}";
                    job.IsRunning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            finally
            {
                try
                {
                    _downloadJobCts.Remove(job.Id);
                }
                catch
                {
                }
                _downloadSemaphore.Release();
            }
        }

        private static string BuildUniqueGenericDownloadPath(string folder, string baseNameOrFileName, string? extension)
        {
            folder = (folder ?? "").Trim();
            Directory.CreateDirectory(folder);

            var ext = (extension ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(ext) && !ext.StartsWith(".", StringComparison.Ordinal))
                ext = "." + ext;

            var baseName = (baseNameOrFileName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(baseName)) baseName = "download";
            if (!string.IsNullOrWhiteSpace(ext) && baseName.EndsWith(ext, StringComparison.OrdinalIgnoreCase))
                baseName = baseName.Substring(0, baseName.Length - ext.Length);

            baseName = SanitizeFileName(baseName);
            if (string.IsNullOrWhiteSpace(baseName)) baseName = "download";
            if (string.IsNullOrWhiteSpace(ext)) ext = ".bin";

            var path = Path.Combine(folder, baseName + ext);
            if (!File.Exists(path)) return path;

            for (var i = 2; i < 10_000; i++)
            {
                var next = Path.Combine(folder, $"{baseName} ({i}){ext}");
                if (!File.Exists(next)) return next;
            }
            throw new IOException("Too many duplicates");
        }

        private async Task DownloadJobFromYouTubeAsync(DownloadJob job, string folder, CancellationToken ct)
        {
            var ytdlp = await EnsureYtDlpAsync(ct).ConfigureAwait(false);
            if (string.IsNullOrWhiteSpace(ytdlp) || !File.Exists(ytdlp))
                throw new InvalidOperationException("yt-dlp missing");

            var ffmpegDir = "";
            try { ffmpegDir = Path.GetDirectoryName(ResolveFfmpegExecutable()) ?? ""; } catch { ffmpegDir = ""; }

            var name = string.IsNullOrWhiteSpace(job.DisplayName) ? "youtube" : job.DisplayName;
            var destMp3 = BuildUniqueGenericDownloadPath(folder, name, ".mp3");
            var destBase = destMp3.Substring(0, destMp3.Length - 4);
            job.DestinationPath = destMp3;

            _uiDispatcher.Invoke(() =>
            {
                job.IsIndeterminate = true;
                job.Status = "Downloading...";
            });

            var url = (job.Url ?? "").Trim();
            var source = url.StartsWith("ytsearch", StringComparison.OrdinalIgnoreCase) ? url : url;

            var prefs = Core.PreferencesStore.Instance.Current;
            var embedThumb = prefs.CsvEmbedThumbnails ? "--embed-thumbnail --convert-thumbnails jpg " : "";
            var minDur = Math.Max(0, prefs.CsvMinDurationSeconds);
            var maxDur = Math.Max(0, prefs.CsvMaxDurationSeconds);
            var excludeInstr = prefs.CsvExcludeInstrumentals;
            var matchParts = new List<string>();
            if (source.StartsWith("ytsearch", StringComparison.OrdinalIgnoreCase))
            {
                if (minDur > 0) matchParts.Add($"duration >= {minDur}");
                if (maxDur > 0) matchParts.Add($"duration <= {maxDur}");
                if (excludeInstr) matchParts.Add("title !~ '(?i)instrumental'");
            }
            var matchFilter = matchParts.Count > 0 ? $"--match-filter \"{string.Join(" & ", matchParts)}\" " : "";

            var args =
                $"--no-playlist --no-warnings --ignore-errors --newline " +
                $"{matchFilter}" +
                $"-x --audio-format mp3 --audio-quality 0 " +
                $"{embedThumb}" +
                $"{(string.IsNullOrWhiteSpace(ffmpegDir) ? "" : $"--ffmpeg-location \"{ffmpegDir}\" ")}" +
                $"--print after_move:filepath " +
                $"-o \"{destBase}.%(ext)s\" " +
                $"\"{source}\"";

            using var proc = new Process
            {
                StartInfo = new ProcessStartInfo
                {
                    FileName = ytdlp,
                    Arguments = args,
                    UseShellExecute = false,
                    CreateNoWindow = true,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true
                }
            };

            using var reg = ct.Register(() =>
            {
                try { if (!proc.HasExited) proc.Kill(entireProcessTree: true); } catch { }
            });

            proc.Start();
            var lastPrinted = "";
            while (!proc.StandardOutput.EndOfStream)
            {
                var line = await proc.StandardOutput.ReadLineAsync().ConfigureAwait(false);
                if (string.IsNullOrWhiteSpace(line)) continue;
                lastPrinted = line.Trim();
            }
            await proc.WaitForExitAsync(ct).ConfigureAwait(false);

            if (!string.IsNullOrWhiteSpace(lastPrinted) && File.Exists(lastPrinted))
            {
                var ext = Path.GetExtension(lastPrinted) ?? "";
                if (!ext.Equals(".mp3", StringComparison.OrdinalIgnoreCase))
                {
                    var ffmpegExe = ResolveFfmpegExecutable();
                    if (!string.IsNullOrWhiteSpace(ffmpegExe))
                    {
                        var tmpMp3 = destMp3;
                        try
                        {
                            using var conv = new Process
                            {
                                StartInfo = new ProcessStartInfo
                                {
                                    FileName = ffmpegExe,
                                    Arguments = $"-hide_banner -loglevel error -y -i \"{lastPrinted}\" -vn -codec:a libmp3lame -q:a 0 \"{tmpMp3}\"",
                                    UseShellExecute = false,
                                    CreateNoWindow = true,
                                    RedirectStandardError = true,
                                    RedirectStandardOutput = true
                                }
                            };
                            conv.Start();
                            await conv.WaitForExitAsync(ct).ConfigureAwait(false);
                            if (File.Exists(tmpMp3))
                                lastPrinted = tmpMp3;
                        }
                        catch
                        {
                        }
                    }
                }
                job.DestinationPath = lastPrinted;
            }
            else if (!File.Exists(destMp3))
            {
                throw new InvalidOperationException("YouTube failed");
            }

            _uiDispatcher.Invoke(() =>
            {
                job.IsIndeterminate = false;
                job.Progress = 1;
            });
        }

        private async Task<bool> TryDownloadViaYtdlpGenericAsync(DownloadJob job, string folder, CancellationToken ct)
        {
            var ytdlp = await EnsureYtDlpAsync(ct).ConfigureAwait(false);
            if (string.IsNullOrWhiteSpace(ytdlp) || !File.Exists(ytdlp))
                return false;

            var ffmpegDir = "";
            try { ffmpegDir = Path.GetDirectoryName(ResolveFfmpegExecutable()) ?? ""; } catch { ffmpegDir = ""; }

            var name = string.IsNullOrWhiteSpace(job.DisplayName) ? "download" : job.DisplayName;
            var destMp4 = BuildUniqueGenericDownloadPath(folder, name, ".mp4");
            var destBase = destMp4.Substring(0, destMp4.Length - 4);
            job.DestinationPath = destMp4;

            _uiDispatcher.Invoke(() =>
            {
                job.IsIndeterminate = true;
                job.Status = "Resolving...";
            });

            var source = (job.Url ?? "").Trim();
            var prefs = Core.PreferencesStore.Instance.Current;
            var embedThumb = prefs.CsvEmbedThumbnails ? "--embed-thumbnail --convert-thumbnails jpg " : "";
            var args =
                $"--no-playlist --no-warnings --ignore-errors --newline " +
                $"{(string.IsNullOrWhiteSpace(ffmpegDir) ? "" : $"--ffmpeg-location \"{ffmpegDir}\" ")}" +
                $"{embedThumb}" +
                $"--print after_move:filepath " +
                $"-f bestvideo+bestaudio/best " +
                $"-o \"{destBase}.%(ext)s\" " +
                $"\"{source}\"";

            using var proc = new Process
            {
                StartInfo = new ProcessStartInfo
                {
                    FileName = ytdlp,
                    Arguments = args,
                    UseShellExecute = false,
                    CreateNoWindow = true,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true
                }
            };

            using var reg = ct.Register(() =>
            {
                try { if (!proc.HasExited) proc.Kill(entireProcessTree: true); } catch { }
            });

            proc.Start();
            var lastPrinted = "";
            while (!proc.StandardOutput.EndOfStream)
            {
                var line = await proc.StandardOutput.ReadLineAsync().ConfigureAwait(false);
                if (string.IsNullOrWhiteSpace(line)) continue;
                lastPrinted = line.Trim();
            }
            await proc.WaitForExitAsync(ct).ConfigureAwait(false);

            if (!string.IsNullOrWhiteSpace(lastPrinted) && File.Exists(lastPrinted))
            {
                job.DestinationPath = lastPrinted;
                _uiDispatcher.Invoke(() =>
                {
                    job.IsIndeterminate = false;
                    job.Progress = 1;
                });
                return true;
            }
            if (File.Exists(destMp4))
            {
                _uiDispatcher.Invoke(() =>
                {
                    job.IsIndeterminate = false;
                    job.Progress = 1;
                });
                return true;
            }
            _uiDispatcher.Invoke(() =>
            {
                job.IsIndeterminate = false;
            });
            return false;
        }

        private async Task<string> TryHeadContentTypeAsync(Uri uri, CancellationToken ct)
        {
            try
            {
                using var req = new HttpRequestMessage(HttpMethod.Head, uri);
                using var resp = await ServerHttp.SendAsync(req, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode) return "";
                var ctHeader = resp.Content.Headers.ContentType;
                var s = ctHeader == null ? "" : (ctHeader.MediaType ?? "").Trim();
                return s ?? "";
            }
            catch
            {
                return "";
            }
        }

        private async Task DownloadLibraryItemAsync(MediaItem item)
        {
            if (item == null) return;
            if (item.IsDownloading) return;

            var downloadUrl = (item.DownloadUrl ?? "").Trim();
            if (string.IsNullOrWhiteSpace(downloadUrl))
                downloadUrl = (item.FilePath ?? "").Trim();

            if (!IsHttpUrl(downloadUrl, out var uri))
            {
                try
                {
                    if (!string.IsNullOrWhiteSpace(downloadUrl) && File.Exists(downloadUrl))
                    {
                        uri = null;
                    }
                    else
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StatusText = "No download link";
                            OnPropertyChanged(nameof(StatusText));
                        });
                        return;
                    }
                }
                catch
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        StatusText = "No download link";
                        OnPropertyChanged(nameof(StatusText));
                    });
                    return;
                }
            }

            var folder = EnsureMediaDownloadsFolderSelected(forcePrompt: false);
            if (string.IsNullOrWhiteSpace(folder)) return;

            string destPath;
            try
            {
                destPath = BuildUniqueDownloadPath(folder, item, uri, downloadUrl, forcedExtension: IsM3u8Url(downloadUrl) ? ".mp4" : null);
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "Download path failed";
                    OnPropertyChanged(nameof(StatusText));
                });
                return;
            }

            CancellationToken ct;
            try
            {
                _downloadCts?.Cancel();
                _downloadCts?.Dispose();
            }
            catch
            {
            }
            _downloadCts = new CancellationTokenSource();
            ct = _downloadCts.Token;

            await _downloadSemaphore.WaitAsync(ct).ConfigureAwait(false);
            try
            {
                _uiDispatcher.Invoke(() =>
                {
                    item.IsDownloading = true;
                    item.DownloadProgress = 0;
                    item.DownloadStatus = "Starting...";
                    StatusText = $"Downloading · {item.Title}";
                    OnPropertyChanged(nameof(StatusText));
                });

                if (uri != null)
                {
                    if (IsM3u8Url(uri.ToString()))
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            item.DownloadProgress = 0;
                            item.DownloadStatus = "Downloading...";
                        });
                        await DownloadViaFfmpegAsync(uri.ToString(), destPath, indeterminate: () =>
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                item.DownloadStatus = "Downloading...";
                            });
                        }, ct).ConfigureAwait(false);
                    }
                    else
                    {
                        await DownloadHttpToFileAsync(uri, destPath, p =>
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                item.DownloadProgress = p;
                                item.DownloadStatus = $"Downloading {item.DownloadPercentText}";
                            });
                        }, ct).ConfigureAwait(false);
                    }
                }
                else
                {
                    await CopyFileWithProgressAsync(downloadUrl, destPath, p =>
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            item.DownloadProgress = p;
                            item.DownloadStatus = $"Copying {item.DownloadPercentText}";
                        });
                    }, ct).ConfigureAwait(false);
                }

                _uiDispatcher.Invoke(() =>
                {
                    item.DownloadProgress = 1;
                    item.DownloadStatus = "Complete";
                    StatusText = $"Downloaded · {Path.GetFileName(destPath)}";
                    OnPropertyChanged(nameof(StatusText));
                    OnPropertyChanged(nameof(TrendingValue));
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    item.DownloadStatus = "Failed";
                    StatusText = "Download failed";
                    OnPropertyChanged(nameof(StatusText));
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    item.IsDownloading = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                _downloadSemaphore.Release();
            }
        }

        private static string BuildUniqueDownloadPath(string folder, MediaItem item, Uri? uri, string fallbackSource, string? titleOverride = null, string? forcedExtension = null)
        {
            folder = (folder ?? "").Trim();
            if (string.IsNullOrWhiteSpace(folder)) throw new InvalidOperationException("No folder");
            Directory.CreateDirectory(folder);

            forcedExtension = (forcedExtension ?? "").Trim();
            var ext = "";
            try
            {
                if (uri != null)
                    ext = Path.GetExtension(uri.AbsolutePath);
            }
            catch
            {
                ext = "";
            }

            if (!string.IsNullOrWhiteSpace(forcedExtension))
                ext = forcedExtension.StartsWith(".", StringComparison.Ordinal) ? forcedExtension : "." + forcedExtension;

            if (string.IsNullOrWhiteSpace(ext))
            {
                try { ext = Path.GetExtension(fallbackSource); } catch { ext = ""; }
            }

            if (string.IsNullOrWhiteSpace(ext))
            {
                ext = string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase) ? ".mp3" : ".mp4";
            }

            var preferredTitle = (titleOverride ?? "").Trim();
            if (string.IsNullOrWhiteSpace(preferredTitle))
                preferredTitle = string.IsNullOrWhiteSpace(item.Title) ? "download" : item.Title;
            var baseName = SanitizeFileName(preferredTitle);
            if (string.IsNullOrWhiteSpace(baseName)) baseName = "download";

            var path = Path.Combine(folder, baseName + ext);
            if (!File.Exists(path)) return path;

            for (var i = 2; i < 10_000; i++)
            {
                var next = Path.Combine(folder, $"{baseName} ({i}){ext}");
                if (!File.Exists(next)) return next;
            }
            throw new IOException("Too many duplicates");
        }

        private static string SanitizeFileName(string name)
        {
            name = (name ?? "").Trim();
            if (string.IsNullOrWhiteSpace(name)) return "";
            var invalid = Path.GetInvalidFileNameChars();
            var sb = new StringBuilder(name.Length);
            foreach (var ch in name)
            {
                if (invalid.Contains(ch)) continue;
                if (ch == '\u0000') continue;
                sb.Append(ch);
            }
            var s = sb.ToString().Trim();
            while (s.EndsWith(".", StringComparison.Ordinal)) s = s.Substring(0, s.Length - 1).Trim();
            return s.Length > 160 ? s.Substring(0, 160).Trim() : s;
        }

        private async Task DownloadHttpToFileAsync(Uri uri, string destPath, Action<double> onProgress, CancellationToken ct)
        {
            using var resp = await ServerHttp.GetAsync(uri, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
            resp.EnsureSuccessStatusCode();

            var total = resp.Content.Headers.ContentLength ?? -1;
            await using var inStream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
            await using var outStream = new FileStream(destPath, FileMode.Create, FileAccess.Write, FileShare.None, 81920, useAsync: true);

            var buffer = new byte[81920];
            long readTotal = 0;
            int read;
            while ((read = await inStream.ReadAsync(buffer.AsMemory(0, buffer.Length), ct).ConfigureAwait(false)) > 0)
            {
                await outStream.WriteAsync(buffer.AsMemory(0, read), ct).ConfigureAwait(false);
                readTotal += read;
                if (total > 0)
                    onProgress(Math.Clamp((double)readTotal / total, 0, 1));
            }
            onProgress(1);
        }

        private static async Task CopyFileWithProgressAsync(string srcPath, string destPath, Action<double> onProgress, CancellationToken ct)
        {
            var total = 0L;
            try { total = new FileInfo(srcPath).Length; } catch { total = 0; }
            await using var inStream = new FileStream(srcPath, FileMode.Open, FileAccess.Read, FileShare.Read, 81920, useAsync: true);
            await using var outStream = new FileStream(destPath, FileMode.Create, FileAccess.Write, FileShare.None, 81920, useAsync: true);

            var buffer = new byte[81920];
            long readTotal = 0;
            int read;
            while ((read = await inStream.ReadAsync(buffer.AsMemory(0, buffer.Length), ct).ConfigureAwait(false)) > 0)
            {
                await outStream.WriteAsync(buffer.AsMemory(0, read), ct).ConfigureAwait(false);
                readTotal += read;
                if (total > 0)
                    onProgress(Math.Clamp((double)readTotal / total, 0, 1));
            }
            onProgress(1);
        }

        private void SaveServerItemToLibrary(MediaItem? item)
        {
            if (item == null) return;
            if (!IsServersView) return;
            if (string.IsNullOrWhiteSpace(item.FilePath)) return;

            EnsureItemSavedToLibrary(item);

            _uiDispatcher.Invoke(() =>
            {
                StatusText = "Saved to library";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
            });
        }

        private void EnsureItemSavedToLibrary(MediaItem item)
        {
            if (item == null) return;
            var path = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(path)) return;

            var metaId = (item.MetaId ?? "").Trim();

            var added = false;
            var addedType = (item.Type ?? "").Trim();
            lock (_stateLock)
            {
                if (_ignoredPaths.Contains(path))
                    _ignoredPaths.Remove(path);

                var type = string.IsNullOrWhiteSpace(addedType) ? "unknown" : addedType;
                var alreadyExists = _allItems.Any(i =>
                {
                    if (i == null) return false;
                    if (string.Equals(i.FilePath, path, StringComparison.OrdinalIgnoreCase)) return true;

                    var existingMeta = (i.MetaId ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(metaId) || string.IsNullOrWhiteSpace(existingMeta)) return false;
                    if (!string.Equals(i.Type ?? "", type, StringComparison.OrdinalIgnoreCase)) return false;
                    return string.Equals(existingMeta, metaId, StringComparison.OrdinalIgnoreCase);
                });

                if (!alreadyExists)
                {
                    var saved = new MediaItem
                    {
                        PlaybackItem = null,
                        FilePath = path,
                        MetaId = string.IsNullOrWhiteSpace(metaId) ? null : metaId,
                        Title = item.Title,
                        Metadata = item.Metadata,
                        Artist = item.Artist,
                        Album = item.Album,
                        TrackNumber = item.TrackNumber,
                        DiscNumber = item.DiscNumber,
                        Duration = item.Duration,
                        Type = type,
                        AccentBrush = AccentForCategory(type),
                        IconGeometry = IconForCategory(type),
                        LastAiOptimizedUtc = item.LastAiOptimizedUtc,
                        CoverUrl = item.CoverUrl,
                        CoverImage = item.CoverImage
                    };
                    saved.IsFavorite = item.IsFavorite;
                    _allItems.Add(saved);
                    added = true;
                }
            }

            if (!added)
            {
                List<MediaItem> snapshotExisting;
                lock (_stateLock) snapshotExisting = _allItems.ToList();
                _ = SaveLibraryToDiskAsync(snapshotExisting);
                return;
            }

            _uiDispatcher.Invoke(() =>
            {
                if (string.Equals(addedType, "music", StringComparison.OrdinalIgnoreCase))
                    RebuildMusicAlbums();
                foreach (var c in Categories)
                {
                    if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                        c.Count = _addonServers.Count;
                    else if (string.Equals(c.Id, "apps", StringComparison.OrdinalIgnoreCase))
                        c.Count = _appsServices.Count;
                    else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                        c.Count = _musicAlbums.Count;
                    else
                        c.Count = _allItems.Count(i => i != null && string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
                }

                OnPropertyChanged(nameof(LibraryCountText));
                OnPropertyChanged(nameof(VisibleCountText));
                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));
                CommandManager.InvalidateRequerySuggested();
            });

            List<MediaItem> snapshot;
            lock (_stateLock) snapshot = _allItems.ToList();
            _ = SaveLibraryToDiskAsync(snapshot);
        }

        private async Task QueueWatchLaterCoverLoadingAsync(CancellationToken ct)
        {
            List<MediaItem> items = new();
            _uiDispatcher.Invoke(() =>
            {
                items = _watchLaterItems.Take(72).ToList();
            });
            if (items.Count == 0) return;

            var semaphore = new SemaphoreSlim(8);
            var tasks = items.Select(async i =>
            {
                await semaphore.WaitAsync(ct).ConfigureAwait(false);
                try
                {
                    await TryLoadCoverIntoItemAsync(i, ct).ConfigureAwait(false);
                }
                finally
                {
                    semaphore.Release();
                }
            }).ToList();

            try
            {
                await Task.WhenAll(tasks).ConfigureAwait(false);
            }
            catch
            {
            }
        }

        private static async Task<MediaItem?> TryLoadWatchLaterItemAsync(string id, CancellationToken ct)
        {
            var imdb = (id ?? "").Trim();
            if (string.IsNullOrWhiteSpace(imdb))
                return null;

            static async Task<(bool ok, string title, string poster)> TryMetaAsync(string type, string imdb, CancellationToken ct)
            {
                var url = $"https://v3-cinemeta.strem.io/meta/{Uri.EscapeDataString(type)}/{Uri.EscapeDataString(imdb)}.json";
                using var resp = await ServerHttp.GetAsync(url, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode) return (false, "", "");

                await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                    !doc.RootElement.TryGetProperty("meta", out var metaEl) ||
                    metaEl.ValueKind != JsonValueKind.Object)
                    return (false, "", "");

                var name = metaEl.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String ? (nameEl.GetString() ?? "").Trim() : "";
                var poster = metaEl.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String ? (posterEl.GetString() ?? "").Trim() : "";
                if (string.IsNullOrWhiteSpace(name))
                    return (false, "", "");

                if (!string.IsNullOrWhiteSpace(poster) && poster.StartsWith("//", StringComparison.Ordinal))
                    poster = "https:" + poster;

                return (true, name, poster);
            }

            try
            {
                var movie = await TryMetaAsync("movie", imdb, ct).ConfigureAwait(false);
                if (movie.ok)
                {
                    return new MediaItem
                    {
                        PlaybackItem = null,
                        FilePath = imdb,
                        Title = movie.title,
                        Artist = "",
                        Album = "",
                        TrackNumber = 0,
                        DiscNumber = 0,
                        Duration = TimeSpan.Zero,
                        Type = "movies",
                        AccentBrush = AccentForCategory("movies"),
                        IconGeometry = IconForCategory("movies"),
                        CoverUrl = string.IsNullOrWhiteSpace(movie.poster) ? null : movie.poster,
                        CoverImage = null
                    };
                }

                var series = await TryMetaAsync("series", imdb, ct).ConfigureAwait(false);
                if (series.ok)
                {
                    return new MediaItem
                    {
                        PlaybackItem = null,
                        FilePath = imdb,
                        Title = series.title,
                        Artist = "",
                        Album = "",
                        TrackNumber = 0,
                        DiscNumber = 0,
                        Duration = TimeSpan.Zero,
                        Type = "tv",
                        AccentBrush = AccentForCategory("tv"),
                        IconGeometry = IconForCategory("tv"),
                        CoverUrl = string.IsNullOrWhiteSpace(series.poster) ? null : series.poster,
                        CoverImage = null
                    };
                }
            }
            catch
            {
            }

            return null;
        }

