            {
                _serverSeriesRootItem = null;
                OnPropertyChanged(nameof(ServerSeriesHeaderText));
                OnPropertyChanged(nameof(ServerSeriesRootItem));
                OnPropertyChanged(nameof(ServerSeriesBackdropImage));
            }

            _serverSeriesSeasons.Clear();
            _serverSeriesEpisodes.Clear();
