        private void ApplyServerSeriesEpisodeFilter()
        {
            _visibleServerSeriesEpisodes.Clear();
            var season = SelectedServerSeriesSeason?.SeasonNumber ?? 0;
            var q = (ServerSeriesSearchQuery ?? "").Trim();
            IEnumerable<MediaItem> src = season <= 0
                ? _serverSeriesEpisodes
                : _serverSeriesEpisodes.Where(e => e.SeasonNumber == season);

            if (!string.IsNullOrWhiteSpace(q))
            {
                src = src.Where(e =>
                    (!string.IsNullOrWhiteSpace(e.Title) && e.Title.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                    (!string.IsNullOrWhiteSpace(e.FilePath) && e.FilePath.Contains(q, StringComparison.OrdinalIgnoreCase)));
            }

            foreach (var e in src)
                _visibleServerSeriesEpisodes.Add(e);
        }

        private void OnServerCatalogSearchQueryChanged()
        {
            try
            {
                _serverCatalogSearchCts?.Cancel();
                _serverCatalogSearchCts?.Dispose();
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error cancelling search token: {ex.Message}");
            }
            _serverCatalogSearchCts = null;

            var q = (_serverCatalogSearchQuery ?? "").Trim();
            if (string.IsNullOrWhiteSpace(q))
            {
                _serverMovieSearchItems.Clear();
                _serverTvSearchItems.Clear();
                _serverMusicSearchItems.Clear();
                RebuildServerCatalogVisibleItems();
                return;
            }

            PopulateLocalServerCatalogSearchItems(q);
            RebuildServerCatalogVisibleItems();

            if (q.Length < 2)
                return;

            Dictionary<string, ServerCatalogPageState> movieStates = new(StringComparer.OrdinalIgnoreCase);
            Dictionary<string, ServerCatalogPageState> tvStates = new(StringComparer.OrdinalIgnoreCase);
            Dictionary<string, ServerCatalogPageState> musicStates = new(StringComparer.OrdinalIgnoreCase);
            try
            {
                movieStates = _serverMoviePageStates.Values
                    .Where(s => !string.IsNullOrWhiteSpace(s.BaseUrl))
                    .GroupBy(s => s.BaseUrl, StringComparer.OrdinalIgnoreCase)
                    .Select(g => g.First())
                    .ToDictionary(s => s.BaseUrl, s => s with { NextSkip = 0, HasMore = true }, StringComparer.OrdinalIgnoreCase);

                tvStates = _serverTvPageStates.Values
                    .Where(s => !string.IsNullOrWhiteSpace(s.BaseUrl))
                    .GroupBy(s => s.BaseUrl, StringComparer.OrdinalIgnoreCase)
                    .Select(g => g.First())
                    .ToDictionary(s => s.BaseUrl, s => s with { NextSkip = 0, HasMore = true }, StringComparer.OrdinalIgnoreCase);

                musicStates = _serverMusicPageStates.Values
                    .Where(s => !string.IsNullOrWhiteSpace(s.BaseUrl))
                    .GroupBy(s => s.BaseUrl, StringComparer.OrdinalIgnoreCase)
                    .Select(g => g.First())
                    .ToDictionary(s => s.BaseUrl, s => s with { NextSkip = 0, HasMore = true }, StringComparer.OrdinalIgnoreCase);
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error preparing search states: {ex.Message}");
            }

            var cts = new CancellationTokenSource(TimeSpan.FromSeconds(25));
            _serverCatalogSearchCts = cts;
            var ct = cts.Token;

            _ = Task.Run(async () =>
            {
                try
                {
                    await Task.Delay(300, ct).ConfigureAwait(false);

                    var tasks = new List<Task>();
                    if (movieStates.Count > 0)
                        tasks.Add(FillServerCatalogSearchItemsAsync(movieStates, q, "movie", ct));
                    if (tvStates.Count > 0)
                        tasks.Add(FillServerCatalogSearchItemsAsync(tvStates, q, "series", ct));
                    if (musicStates.Count > 0)
                        tasks.Add(FillServerCatalogSearchItemsAsync(musicStates, q, "music", ct));
                    if (tasks.Count > 0)
                        await Task.WhenAll(tasks).ConfigureAwait(false);
                }
                catch (OperationCanceledException)
                {
                    // Ignore
                }
                catch (Exception ex)
                {
                    System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error during search task: {ex.Message}");
                }
                finally
                {
                    try
                    {
                        _uiDispatcher.Invoke(RebuildServerCatalogVisibleItems);
                    }
                    catch (Exception ex)
                    {
                        System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Error updating UI after search: {ex.Message}");
                    }
                }
            }, ct);
        }

        private void PopulateLocalServerCatalogSearchItems(string query)
        {
            var q = (query ?? "").Trim();
            if (string.IsNullOrWhiteSpace(q))
                return;

            const int maxItems = 480;

            var movieLocal = _serverMovieCatalogItems
                .Where(i => MatchesServerCatalogQuery(i, q))
                .Take(maxItems)
                .ToList();

            var tvLocal = _serverTvCatalogItems
                .Where(i => MatchesServerCatalogQuery(i, q))
                .Take(maxItems)
                .ToList();

            IEnumerable<MediaItem> musicSrc = _serverMusicCatalogItems;
            if (_serverMusicCatalogItems.Count == 0)
            {
                musicSrc = _allItems.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase));
            }
            var musicLocal = musicSrc
                .Where(i => MatchesServerCatalogQuery(i, q))
                .Take(maxItems)
                .ToList();

            _serverMovieSearchItems.Clear();
            foreach (var i in movieLocal)
                _serverMovieSearchItems.Add(i);

            _serverTvSearchItems.Clear();
            foreach (var i in tvLocal)
                _serverTvSearchItems.Add(i);

            _serverMusicSearchItems.Clear();
            foreach (var i in musicLocal)
                _serverMusicSearchItems.Add(i);

            if (_serverMusicSearchItems.Count == 0)
            {
                var scUrl = $"https://soundcloud.com/search/sounds?q={Uri.EscapeDataString(q)}";
                _serverMusicSearchItems.Add(new MediaItem
                {
                    FilePath = scUrl,
                    Title = $"Search SoundCloud: {q}",
                    Metadata = "Open SoundCloud search",
                    Artist = "SoundCloud",
                    Album = "",
                    TrackNumber = 0,
                    DiscNumber = 0,
                    SeasonNumber = 0,
                    EpisodeNumber = 0,
                    Duration = TimeSpan.Zero,
                    Year = 0,
                    Rating = 0,
                    Genres = Array.Empty<string>(),
                    Type = "music",
                    AccentBrush = AccentForCategory("music"),
                    IconGeometry = IconForCategory("music"),
                    CoverUrl = null,
                    CoverImage = null
                });
            }
        }

        private async Task FillServerCatalogSearchItemsAsync(Dictionary<string, ServerCatalogPageState> states, string query, string kind, CancellationToken ct)
        {
            const int maxItems = 1200;
            const int maxPasses = 25;

            var q = (query ?? "").Trim();
            if (string.IsNullOrWhiteSpace(q))
                return;

            var kindKey = (kind ?? "").Trim().ToLowerInvariant();
            var isTv = string.Equals(kindKey, "series", StringComparison.OrdinalIgnoreCase) || string.Equals(kindKey, "tv", StringComparison.OrdinalIgnoreCase);
            var isMusic = string.Equals(kindKey, "music", StringComparison.OrdinalIgnoreCase);

            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var catalogSeen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            try
            {
                _uiDispatcher.Invoke(() =>
                {
                    var existing = isTv
                        ? _serverTvSearchItems.ToList()
                        : (isMusic ? _serverMusicSearchItems.ToList() : _serverMovieSearchItems.ToList());
                    foreach (var i in existing)
                    {
                        var key = (i.FilePath ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(key))
                            seen.Add(key);
                    }

                    var existingCatalog = isTv
                        ? _serverTvCatalogItems.ToList()
                        : (isMusic ? _serverMusicCatalogItems.ToList() : _serverMovieCatalogItems.ToList());
                    foreach (var i in existingCatalog)
                    {
                        var key = (i.FilePath ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(key))
                            catalogSeen.Add(key);
                    }
                });
            }
            catch
            {
            }

            var passes = 0;
            while (!ct.IsCancellationRequested &&
                   passes < maxPasses &&
                   states.Values.Any(s => s.HasMore))
            {
                var batch = await LoadNextPagesForTypeAsync(states, ct, q).ConfigureAwait(false);
                if (batch.Count == 0)
                    break;

                var toCache = new List<MediaItem>();
                var toAdd = new List<MediaItem>();
                foreach (var i in batch)
                {
                    if (i == null) continue;
                    var key = (i.FilePath ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(key)) continue;
                    if (catalogSeen.Add(key))
                        toCache.Add(i);
                    if (!MatchesServerCatalogQuery(i, q)) continue;
                    if (!seen.Add(key)) continue;
                    toAdd.Add(i);
                    if (seen.Count >= maxItems) break;
                }

                if (toCache.Count > 0 || toAdd.Count > 0)
                {
                    try
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            var cacheTarget = isTv
                                ? _serverTvCatalogItems
                                : (isMusic ? _serverMusicCatalogItems : _serverMovieCatalogItems);
                            foreach (var i in toCache)
                                cacheTarget.Add(i);

                            var target = isTv
                                ? _serverTvSearchItems
                                : (isMusic ? _serverMusicSearchItems : _serverMovieSearchItems);
                            foreach (var i in toAdd)
                            {
                                if (target.Count >= maxItems) break;
                                target.Add(i);
                            }

                            RebuildServerCatalogVisibleItems();
                        });
                    }
                    catch
                    {
                    }
                }

                if (seen.Count >= maxItems)
                    break;

                passes++;
            }
        }

        public void RequestLoadMoreFromBridge(string contentType)
        {
            AtlasAI.Core.AppLogger.LogInfo($"[BridgeLoad] RequestLoadMoreFromBridge called: type={contentType}, IsServersView={IsServersView}, IsBusy={IsServerCatalogBusy}, Category={SelectedCategory?.Id}");
            if (!IsServersView) { AtlasAI.Core.AppLogger.LogInfo("[BridgeLoad] BAIL: not servers view"); return; }
            if (IsServerCatalogBusy) { AtlasAI.Core.AppLogger.LogInfo("[BridgeLoad] BAIL: busy"); return; }
            var type = (contentType ?? "movie").Trim().ToLowerInvariant();
            SelectedServerCatalogType = string.Equals(type, "series", StringComparison.OrdinalIgnoreCase) ? "series" : "movie";
            _ = LoadBridgePageAsync();
        }

        private async Task LoadBridgePageAsync()
        {
            if (IsServerCatalogBusy) return;

            var selection = _uiDispatcher.Invoke(() => (SelectedAddonServer ?? "").Trim());
            var isAllServers = string.IsNullOrWhiteSpace(selection) ||
                               string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);

            var states = _uiDispatcher.Invoke(() =>
                IsServerCatalogTvSelected ? _serverTvPageStates : _serverMoviePageStates);

            var hasMoreCount = states.Values.Count(s => s.HasMore);
            AtlasAI.Core.AppLogger.LogInfo($"[BridgeLoad] LoadBridgePageAsync: statesCount={states.Count}, hasMoreCount={hasMoreCount}, isAllServers={isAllServers}");

            if (!states.Values.Any(s => s.HasMore))
            {
                AtlasAI.Core.AppLogger.LogInfo("[BridgeLoad] BAIL: no HasMore states — all pages exhausted");
                return;
            }

            IsServerCatalogBusy = true;
            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(90));
                var ct = cts.Token;

                var excludeKeys = _uiDispatcher.Invoke(() =>
                {
                    var target = IsServerCatalogTvSelected ? _serverTvCatalogItems : _serverMovieCatalogItems;
                    return new HashSet<string>(
                        target.Select(i => BuildServerCatalogDedupeKey(i)).Where(x => !string.IsNullOrWhiteSpace(x)),
                        StringComparer.OrdinalIgnoreCase);
                });

                var newItems = new List<MediaItem>();
                const int targetMinimum = 500;
                const int maxPasses = 20;

                for (var pass = 0; pass < maxPasses && states.Values.Any(s => s.HasMore); pass++)
                {
                    var batch = await LoadNextPagesForTypeAsync(states, ct, null, loadAllServers: isAllServers, excludeKeys: excludeKeys).ConfigureAwait(false);
                    if (batch.Count == 0) break;

                    foreach (var item in batch)
                    {
                        if (item == null) continue;
                        var key = BuildServerCatalogDedupeKey(item);
                        if (string.IsNullOrWhiteSpace(key) || !excludeKeys.Add(key)) continue;
                        newItems.Add(item);
                    }

                    if (newItems.Count >= targetMinimum) break;
                }

                AtlasAI.Core.AppLogger.LogInfo($"[BridgeLoad] Fetch complete: newItems={newItems.Count}");
                _uiDispatcher.Invoke(() =>
                {
                    var target = IsServerCatalogTvSelected ? _serverTvCatalogItems : _serverMovieCatalogItems;
                    var existing = new HashSet<string>(
                        target.Select(i => BuildServerCatalogDedupeKey(i)).Where(x => !string.IsNullOrWhiteSpace(x)),
                        StringComparer.OrdinalIgnoreCase);
                    var added = 0;
                    foreach (var i in newItems)
                    {
                        if (i == null) continue;
                        var key = BuildServerCatalogDedupeKey(i);
                        if (string.IsNullOrWhiteSpace(key) || !existing.Add(key)) continue;
                        target.Add(i);
                        added++;
                    }
                    AtlasAI.Core.AppLogger.LogInfo($"[BridgeLoad] Added {added} items to catalog, total now={target.Count}");
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsServerCatalogBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        public void TryLoadMoreServerCatalog()
        {
            Debug.WriteLine($"[MediaCentre] === TryLoadMoreServerCatalog CALLED ===");
            Debug.WriteLine($"[MediaCentre] IsServersView: {IsServersView}");
            Debug.WriteLine($"[MediaCentre] IsServerCatalogPanelOpen: {IsServerCatalogPanelOpen}");
            Debug.WriteLine($"[MediaCentre] IsServerCatalogBusy: {IsServerCatalogBusy}");
            
            if (!IsServersView) return;
            if (!IsServerCatalogPanelOpen) return;

            var now = DateTime.UtcNow;
            var timeSinceLastLoad = (now - _lastServerCatalogLoadMoreUtc).TotalMilliseconds;
            Debug.WriteLine($"[MediaCentre] Time since last load: {timeSinceLastLoad}ms");
            
            if (timeSinceLastLoad < 250)
            {
                Debug.WriteLine($"[MediaCentre] THROTTLED - too soon since last load");
                return;
            }

            var pageSize = ServerCatalogPageSize;
            if (IsServerCatalogTvSelected)
            {
                Debug.WriteLine($"[MediaCentre] TV Selected - Visible: {_serverTvVisibleCount}, Total: {_serverTvCatalogItems.Count}");
                if (_serverTvVisibleCount >= _serverTvCatalogItems.Count)
                {
                    Debug.WriteLine($"[MediaCentre] All TV items visible, checking if can load next page");
                    Debug.WriteLine($"[MediaCentre] CanLoadNextServerCatalogPage: {CanLoadNextServerCatalogPage}");
                    if (!IsServerCatalogBusy && CanLoadNextServerCatalogPage)
                    {
                        Debug.WriteLine($"[MediaCentre] Loading next TV page...");
                        _lastServerCatalogLoadMoreUtc = now;
                        _ = LoadNextServerCatalogPageAsync();
                    }
                    else
                    {
                        Debug.WriteLine($"[MediaCentre] Cannot load next page - all pages loaded");
                    }
                    return;
                }
                var newCount = Math.Min(_serverTvCatalogItems.Count, _serverTvVisibleCount + pageSize);
                Debug.WriteLine($"[MediaCentre] Increasing TV visible count from {_serverTvVisibleCount} to {newCount}");
                _serverTvVisibleCount = newCount;
            }
            else if (IsServerCatalogMusicSelected)
            {
                Debug.WriteLine($"[MediaCentre] Music Selected - Visible: {_serverMusicVisibleCount}, Total: {_serverMusicCatalogItems.Count}");
                if (_serverMusicVisibleCount >= _serverMusicCatalogItems.Count)
                {
                    Debug.WriteLine($"[MediaCentre] All Music items visible, checking if can load next page");
                    Debug.WriteLine($"[MediaCentre] CanLoadNextServerCatalogPage: {CanLoadNextServerCatalogPage}");
                    if (!IsServerCatalogBusy && CanLoadNextServerCatalogPage)
                    {
                        Debug.WriteLine($"[MediaCentre] Loading next Music page...");
                        _lastServerCatalogLoadMoreUtc = now;
                        _ = LoadNextServerCatalogPageAsync();
                    }
                    else
                    {
                        Debug.WriteLine($"[MediaCentre] Cannot load next page - all pages loaded");
                    }
                    return;
                }
                var newCount = Math.Min(_serverMusicCatalogItems.Count, _serverMusicVisibleCount + pageSize);
                Debug.WriteLine($"[MediaCentre] Increasing Music visible count from {_serverMusicVisibleCount} to {newCount}");
                _serverMusicVisibleCount = newCount;
            }
            else
            {
                Debug.WriteLine($"[MediaCentre] Movies Selected - Visible: {_serverMovieVisibleCount}, Total: {_serverMovieCatalogItems.Count}");
                if (_serverMovieVisibleCount >= _serverMovieCatalogItems.Count)
                {
                    Debug.WriteLine($"[MediaCentre] All Movie items visible, checking if can load next page");
                    Debug.WriteLine($"[MediaCentre] CanLoadNextServerCatalogPage: {CanLoadNextServerCatalogPage}");
                    if (!IsServerCatalogBusy && CanLoadNextServerCatalogPage)
                    {
                        Debug.WriteLine($"[MediaCentre] Loading next Movie page...");
                        _lastServerCatalogLoadMoreUtc = now;
                        _ = LoadNextServerCatalogPageAsync();
                    }
                    else
                    {
                        Debug.WriteLine($"[MediaCentre] Cannot load next page - all pages loaded");
                    }
                    return;
                }
                var newCount = Math.Min(_serverMovieCatalogItems.Count, _serverMovieVisibleCount + pageSize);
                Debug.WriteLine($"[MediaCentre] Increasing Movie visible count from {_serverMovieVisibleCount} to {newCount}");
                _serverMovieVisibleCount = newCount;
            }

            _lastServerCatalogLoadMoreUtc = now;
            Debug.WriteLine($"[MediaCentre] Rebuilding visible items...");
            RebuildServerCatalogVisibleItems();
            OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
            CommandManager.InvalidateRequerySuggested();
            Debug.WriteLine($"[MediaCentre] === TryLoadMoreServerCatalog COMPLETE ===");
        }

        public void EnsureServerCatalogLoaded()
        {
            try
            {
                if (!IsServersView) return;
                if (IsServerCatalogBusy) return;

                if (_serverCatalogItems.Count > 0)
                {
                    try
                    {
                        if (_serverShelves.Count == 0)
                            RebuildServerShelves();
                    }
                    catch
                    {
                    }

                    try
                    {
                        // Only auto-select preview when NOT in shelves mode
                        if (!IsServerShelvesMode && (PreviewItem == null || !_serverCatalogItems.Contains(PreviewItem)))
                        {
                            var first = _serverCatalogItems.FirstOrDefault();
                            if (first != null)
                                SetPreviewItem(first);
                        }
                    }
                    catch
                    {
                    }
                    return;
                }

                var selection = (SelectedAddonServer ?? "").Trim();
                if (string.IsNullOrWhiteSpace(selection))
                {
                    SelectedAddonServer = AllServersOption;
                    return;
                }

                _ = RefreshServerCatalogAsync();
            }
            catch
            {
            }
        }

        private void RebuildServerCatalogVisibleItems()
        {
            if (!IsServersView) return;

            var q = (ServerCatalogSearchQuery ?? "").Trim();
            IEnumerable<MediaItem> baseItems;
            int visibleCount;

            if (IsServerCatalogTvSelected)
            {
                baseItems = _serverTvCatalogItems;
                visibleCount = Math.Clamp(_serverTvVisibleCount, 0, _serverTvCatalogItems.Count);
            }
            else if (IsServerCatalogMusicSelected)
            {
                if (_serverMusicCatalogItems.Count == 0 && string.IsNullOrWhiteSpace(q))
                {
                    var fallback = new List<MediaItem>
                    {
                        new MediaItem
                        {
                            FilePath = "https://soundcloud.com/discover",
                            Title = "SoundCloud Discover",
                            Metadata = "Browse music on SoundCloud",
                            Artist = "SoundCloud",
                            Album = "",
                            TrackNumber = 0,
                            DiscNumber = 0,
                            SeasonNumber = 0,
                            EpisodeNumber = 0,
                            Duration = TimeSpan.Zero,
                            Year = 0,
                            Rating = 0,
                            Genres = Array.Empty<string>(),
                            Type = "music",
                            AccentBrush = AccentForCategory("music"),
                            IconGeometry = IconForCategory("music"),
                            CoverUrl = null,
                            CoverImage = null
                        }
                    };
                    baseItems = fallback;
                    visibleCount = fallback.Count;
                }
                else
                {
                    baseItems = _serverMusicCatalogItems;
                    visibleCount = Math.Clamp(_serverMusicVisibleCount, 0, _serverMusicCatalogItems.Count);
                }
            }
            else
            {
                baseItems = _serverMovieCatalogItems;
                visibleCount = Math.Clamp(_serverMovieVisibleCount, 0, _serverMovieCatalogItems.Count);
            }

            try
            {
                var totalCount = baseItems.Count();
                var remaining = Math.Max(0, totalCount - visibleCount);
                var prefetchThreshold = IsServerCatalogMusicSelected ? 24 : 32;
                var now = DateTime.UtcNow;
                var tooSoon = (now - _lastServerCatalogPrefetchUtc).TotalMilliseconds < 800;
                if (remaining <= prefetchThreshold && CanLoadNextServerCatalogPage && !IsServerCatalogBusy && !_isServerCatalogPrefetching && !tooSoon)
                {
                    _lastServerCatalogPrefetchUtc = now;
                    _ = PreloadNextServerCatalogPageAsync();
                }
            }
            catch
            {
            }

            const int maxSearchResults = 1200;
            if (!string.IsNullOrWhiteSpace(q))
            {
                var searchBase = IsServerCatalogTvSelected
                    ? _serverTvSearchItems
                    : (IsServerCatalogMusicSelected ? _serverMusicSearchItems : _serverMovieSearchItems);
                if (searchBase.Count > 0)
                {
                    baseItems = searchBase;
                    visibleCount = Math.Min(searchBase.Count, maxSearchResults);
                }
                else
                {
                    visibleCount = maxSearchResults;
                }
            }

            var filtered = baseItems;
            if (!string.IsNullOrWhiteSpace(q))
            {
                filtered = filtered.Where(i => MatchesServerCatalogQuery(i, q));
            }

            var genre = (SelectedServerCatalogGenre ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(genre) && !string.Equals(genre, AllGenresOption, StringComparison.OrdinalIgnoreCase))
            {
                filtered = filtered.Where(i =>
                    i != null && i.Genres.Any(g => string.Equals(g, genre, StringComparison.OrdinalIgnoreCase)));
            }

            var yearText = (SelectedServerCatalogYear ?? "").Trim();
            if (!string.IsNullOrWhiteSpace(yearText) && !string.Equals(yearText, AllYearsOption, StringComparison.OrdinalIgnoreCase) &&
                int.TryParse(yearText, out var year) && year > 0)
            {
                filtered = filtered.Where(i => i != null && i.Year == year);
            }

            var sort = (SelectedServerCatalogSort ?? "").Trim();
            if (string.Equals(sort, "popularity", StringComparison.OrdinalIgnoreCase))
            {
                filtered = filtered
                    .OrderByDescending(i => i.Rating)
                    .ThenByDescending(i => i.Year)
                    .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase);
            }
            else if (string.Equals(sort, "year_desc", StringComparison.OrdinalIgnoreCase))
            {
                filtered = filtered
                    .OrderByDescending(i => i.Year > 0 ? i.Year : int.MinValue)
                    .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase);
            }
            else if (string.Equals(sort, "year_asc", StringComparison.OrdinalIgnoreCase))
            {
                filtered = filtered
                    .OrderBy(i => i.Year > 0 ? i.Year : int.MaxValue)
                    .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase);
            }
            else if (string.Equals(sort, "title_asc", StringComparison.OrdinalIgnoreCase))
            {
                filtered = filtered.OrderBy(i => i.Title, StringComparer.OrdinalIgnoreCase);
            }

            filtered = filtered
                .Where(i => i != null)
                .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                .Where(i => !string.IsNullOrWhiteSpace(BuildServerCatalogDedupeKey(i)));

            var subset = filtered.Take(visibleCount).ToList();
            var page = (int)Math.Ceiling(Math.Max(1, subset.Count) / (double)ServerCatalogPageSize);
            void Update()
            {
                ServerCatalogCurrentPage = page;
                if (_serverCatalogItems.Count > subset.Count)
                {
                    _serverCatalogItems.Clear();
                    foreach (var i in subset)
                        _serverCatalogItems.Add(i);
                    _serverCatalogRows.Clear();
                    for (var idx = 0; idx < subset.Count; idx += 4)
                    {
                        var row = new MediaItemRow();
                        for (var j = idx; j < subset.Count && j < idx + 4; j++)
                            row.Items.Add(subset[j]);
                        _serverCatalogRows.Add(row);
                    }
                    return;
                }

                var canAppend = true;
                for (var i = 0; i < _serverCatalogItems.Count; i++)
                {
                    if (!ReferenceEquals(_serverCatalogItems[i], subset[i]))
                    {
                        canAppend = false;
                        break;
                    }
                }

                if (canAppend)
                {
                    for (var i = _serverCatalogItems.Count; i < subset.Count; i++)
                        _serverCatalogItems.Add(subset[i]);

                    var flatCount = 0;
                    for (var r = 0; r < _serverCatalogRows.Count; r++)
                        flatCount += _serverCatalogRows[r].Items.Count;

                    if (flatCount != _serverCatalogItems.Count)
                    {
                        _serverCatalogRows.Clear();
                        for (var idx = 0; idx < subset.Count; idx += 4)
                        {
                            var row = new MediaItemRow();
                            for (var j = idx; j < subset.Count && j < idx + 4; j++)
                                row.Items.Add(subset[j]);
                            _serverCatalogRows.Add(row);
                        }
                        return;
                    }

                    var remainingIndex = flatCount;
                    if (_serverCatalogRows.Count > 0)
                    {
                        var lastRow = _serverCatalogRows[_serverCatalogRows.Count - 1];
                        while (lastRow.Items.Count < 4 && remainingIndex < subset.Count)
                        {
                            lastRow.Items.Add(subset[remainingIndex]);
                            remainingIndex++;
                        }
                    }
                    while (remainingIndex < subset.Count)
                    {
                        var row = new MediaItemRow();
                        for (var j = 0; j < 4 && remainingIndex < subset.Count; j++)
                        {
                            row.Items.Add(subset[remainingIndex]);
                            remainingIndex++;
                        }
                        _serverCatalogRows.Add(row);
                    }
                }
                else
                {
                    _serverCatalogItems.Clear();
                    foreach (var i in subset)
                        _serverCatalogItems.Add(i);
                    _serverCatalogRows.Clear();
                    for (var idx = 0; idx < subset.Count; idx += 4)
                    {
                        var row = new MediaItemRow();
                        for (var j = idx; j < subset.Count && j < idx + 4; j++)
                            row.Items.Add(subset[j]);
                        _serverCatalogRows.Add(row);
                    }
                }
            }

            if (_uiDispatcher.CheckAccess())
                Update();
            else
                _uiDispatcher.Invoke(Update);

            QueueServerCatalogCoverLoadingForVisibleItems();
            QueueServerCatalogMetadataForVisibleItems();
            QueueServerMusicArtworkForVisibleItems();
        }

		private async Task PreloadNextServerCatalogPageAsync()
        {
            if (!IsServersView) return;
            if (!IsServerCatalogPanelOpen) return;
			var selection = (SelectedAddonServer ?? "").Trim();
			var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
            var states = IsServerCatalogTvSelected
                ? _serverTvPageStates
                : (IsServerCatalogMusicSelected ? _serverMusicPageStates : _serverMoviePageStates);
            if (!states.Values.Any(s => s.HasMore)) return;
            if (_isServerCatalogPrefetching) return;
            _isServerCatalogPrefetching = true;
            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(10));
                var ct = cts.Token;
				var searchQuery = IsServerCatalogMusicSelected ? (ServerCatalogSearchQuery ?? "").Trim() : null;
				var excludeKeys = _uiDispatcher.Invoke(() =>
				{
					var target = IsServerCatalogTvSelected
						? _serverTvCatalogItems
						: (IsServerCatalogMusicSelected ? _serverMusicCatalogItems : _serverMovieCatalogItems);
					return new HashSet<string>(
						target.Select(i => BuildServerCatalogDedupeKey(i)).Where(x => !string.IsNullOrWhiteSpace(x)),
						StringComparer.OrdinalIgnoreCase);
				});
				var newItems = await LoadNextPagesForTypeAsync(states, ct, searchQuery, loadAllServers: isAllServers, excludeKeys: excludeKeys).ConfigureAwait(false);
                _uiDispatcher.Invoke(() =>
                {
                    var target = IsServerCatalogTvSelected
                        ? _serverTvCatalogItems
                        : (IsServerCatalogMusicSelected ? _serverMusicCatalogItems : _serverMovieCatalogItems);
                    var existing = new HashSet<string>(
                        target.Select(i => BuildServerCatalogDedupeKey(i)).Where(x => !string.IsNullOrWhiteSpace(x)),
                        StringComparer.OrdinalIgnoreCase);
                    foreach (var i in newItems)
                    {
                        if (i == null) continue;
                        var key = BuildServerCatalogDedupeKey(i);
                        if (string.IsNullOrWhiteSpace(key)) continue;
                        if (!existing.Add(key)) continue;
                        target.Add(i);
                    }
                    RefreshServerCatalogFilterOptions();
                    RebuildServerCatalogVisibleItems();
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            catch
            {
            }
            finally
            {
                _isServerCatalogPrefetching = false;
            }
        }

        private static bool MatchesServerCatalogQuery(MediaItem? item, string query)
        {
            if (item == null) return false;

            var q = (query ?? "").Trim();
            if (string.IsNullOrWhiteSpace(q)) return true;

            var t = (item.Title ?? "").Trim();
            var i = (item.FilePath ?? "").Trim();
            var year = item.Year;
            var artist = (item.Artist ?? "").Trim();
            var album = (item.Album ?? "").Trim();
            var type = (item.Type ?? "").Trim();
            var genres = item.Genres == null || item.Genres.Count == 0 ? "" : string.Join(' ', item.Genres);

            if (q.Length < 2)
            {
                if (int.TryParse(q, out var y) && y > 0 && year == y)
                    return true;

                return (!string.IsNullOrWhiteSpace(t) && t.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(i) && i.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(artist) && artist.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(album) && album.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(genres) && genres.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(type) && type.Contains(q, StringComparison.OrdinalIgnoreCase));
            }

            var qn = NormalizeSearchText(q);
            if (string.IsNullOrWhiteSpace(qn)) return true;

            var tokens = qn.Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (tokens.Length == 0) return true;

            var cn = NormalizeSearchText($"{t} {i} {artist} {album} {genres} {type}");
            var cnCompact = cn.Replace(" ", "");
            foreach (var tok in tokens)
            {
                if (tok.Length == 0) continue;

                if (tok.Length == 4 && int.TryParse(tok, out var y) && y > 0 && year == y)
                    continue;

                if (!string.IsNullOrWhiteSpace(cn) && cn.Contains(tok, StringComparison.Ordinal))
                    continue;

                if (tok.Length >= 4 && !string.IsNullOrWhiteSpace(cnCompact) && cnCompact.Contains(tok, StringComparison.Ordinal))
                    continue;

                return false;
            }

            return true;
        }

        private static bool MatchesServerCatalogQuery(string? title, string? id, string query)
        {
            var q = (query ?? "").Trim();
            if (string.IsNullOrWhiteSpace(q)) return true;

            var t = (title ?? "").Trim();
            var i = (id ?? "").Trim();

            if (q.Length < 2)
            {
                return (!string.IsNullOrWhiteSpace(t) && t.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(i) && i.Contains(q, StringComparison.OrdinalIgnoreCase));
            }

            var qn = NormalizeSearchText(q);
            if (string.IsNullOrWhiteSpace(qn)) return true;

            var cn = NormalizeSearchText($"{t} {i}");
            if (string.IsNullOrWhiteSpace(cn)) return false;

            var tokens = qn.Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (tokens.Length == 0) return true;
            var cnCompact = cn.Replace(" ", "");
            foreach (var tok in tokens)
            {
                if (tok.Length == 0) continue;
                if (cn.Contains(tok, StringComparison.Ordinal)) continue;
                if (tok.Length >= 4 && cnCompact.Contains(tok, StringComparison.Ordinal)) continue;
                return false;
            }
            return true;
        }

        private static string NormalizeSearchText(string value)
        {
            if (string.IsNullOrWhiteSpace(value)) return "";
            var s = value.Trim().ToLowerInvariant();
            Span<char> buf = s.Length <= 512 ? stackalloc char[s.Length] : new char[s.Length];
            var n = 0;
            var lastWasSpace = true;
            for (var idx = 0; idx < s.Length; idx++)
            {
                var ch = s[idx];
                var ok = (ch >= 'a' && ch <= 'z') || (ch >= '0' && ch <= '9');
                if (ok)
                {
                    buf[n++] = ch;
                    lastWasSpace = false;
                    continue;
                }

                if (!lastWasSpace)
                {
                    buf[n++] = ' ';
                    lastWasSpace = true;
                }
            }

            if (n == 0) return "";
            if (lastWasSpace) n--;
            return new string(buf[..n]);
        }

        private void QueueServerCatalogCoverLoadingForVisibleItems()
        {
            if (!IsServersView) return;
            if (!IsServerCatalogPanelOpen) return;

            List<MediaItem> snapshot;
            if (_uiDispatcher.CheckAccess())
                snapshot = _serverCatalogItems.ToList();
            else
                snapshot = _uiDispatcher.Invoke(() => _serverCatalogItems.ToList());

            if (snapshot.Count == 0)
                return;

            CancellationToken ct;
            try
            {
                if (_serverCatalogCoverCts == null || _serverCatalogCoverCts.IsCancellationRequested)
                {
                    try { _serverCatalogCoverCts?.Dispose(); } catch { }
                    _serverCatalogCoverCts = new CancellationTokenSource();
                }
                ct = _serverCatalogCoverCts.Token;
            }
            catch
            {
                try { _serverCatalogCoverCts = new CancellationTokenSource(); } catch { }
                ct = _serverCatalogCoverCts?.Token ?? CancellationToken.None;
            }

            _ = Task.Run(async () =>
            {
                try
                {
                    var pending = snapshot
                        .Where(i => i != null && i.CoverImage == null && !string.IsNullOrWhiteSpace(i.CoverUrl))
                        .Take(IsServerCatalogMusicSelected ? 36 : 60)
                        .ToList();
                    if (pending.Count == 0)
                        return;

                    var semaphore = new SemaphoreSlim(12);
                    var tasks = pending.Select(async item =>
                    {
                        var key = (item?.CoverUrl ?? item?.FilePath ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(key)) return;
                        if (!_serverCatalogCoverInFlight.TryAdd(key, 0)) return;
                        try
                        {
                            await semaphore.WaitAsync(ct).ConfigureAwait(false);
                            try
                            {
                                await TryLoadCoverIntoItemAsync(item, ct).ConfigureAwait(false);
                            }
                            finally
                            {
                                semaphore.Release();
                            }
                        }
                        finally
                        {
                            _serverCatalogCoverInFlight.TryRemove(key, out _);
                        }
                    }).ToList();

                    await Task.WhenAll(tasks).ConfigureAwait(false);
                }
                catch
                {
                }
            }, ct);
        }

        private void QueueServerCatalogMetadataForVisibleItems()
        {
            if (!IsServersView) return;
            if (!IsServerCatalogPanelOpen) return;

            List<MediaItem> snapshot;
            if (_uiDispatcher.CheckAccess())
                snapshot = _serverCatalogItems.ToList();
            else
                snapshot = _uiDispatcher.Invoke(() => _serverCatalogItems.ToList());

            var pending = snapshot
                .Where(NeedsServerCatalogMetadataEnrichment)
                .Take(IsServerCatalogMusicSelected ? 0 : 48)
                .ToList();

            if (pending.Count == 0)
                return;

            CancellationToken ct;
            try
            {
                if (_serverCatalogMetaCts == null || _serverCatalogMetaCts.IsCancellationRequested)
                {
                    try { _serverCatalogMetaCts?.Dispose(); } catch { }
                    _serverCatalogMetaCts = new CancellationTokenSource();
                }
                ct = _serverCatalogMetaCts.Token;
            }
            catch
            {
                try { _serverCatalogMetaCts = new CancellationTokenSource(); } catch { }
                ct = _serverCatalogMetaCts?.Token ?? CancellationToken.None;
            }

            _ = Task.Run(async () =>
            {
                try
                {
                    var semaphore = new SemaphoreSlim(6);
                    var tasks = pending.Select(async item =>
                    {
                        var key = BuildServerCatalogDedupeKey(item);
                        if (string.IsNullOrWhiteSpace(key)) return;
                        if (!_serverCatalogMetaInFlight.TryAdd(key, 0)) return;

                        try
                        {
                            await semaphore.WaitAsync(ct).ConfigureAwait(false);
                            try
                            {
                                await EnrichServerCatalogItemMetadataAsync(item, ct).ConfigureAwait(false);
                            }
                            finally
                            {
                                semaphore.Release();
                            }
                        }
                        finally
                        {
                            _serverCatalogMetaInFlight.TryRemove(key, out _);
                        }
                    }).ToList();

                    await Task.WhenAll(tasks).ConfigureAwait(false);
                }
                catch
                {
                }
            }, ct);
        }

        private static bool NeedsServerCatalogMetadataEnrichment(MediaItem? item)
        {
            if (item == null) return false;
            if (string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase)) return false;

            var title = (item.Title ?? "").Trim();
            var hasCanonicalId = !string.IsNullOrWhiteSpace((item.MetaId ?? item.ImdbId ?? "").Trim()) &&
                                 ((item.MetaId ?? item.ImdbId ?? "").Trim().StartsWith("tt", StringComparison.OrdinalIgnoreCase) ||
                                  (item.MetaId ?? item.ImdbId ?? "").Trim().StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase));
            var hasMetadata = item.Year > 0 &&
                              !string.IsNullOrWhiteSpace(item.CoverUrl) &&
                              (!string.IsNullOrWhiteSpace(item.Metadata) || !string.IsNullOrWhiteSpace(item.Overview));

            if (hasCanonicalId && hasMetadata)
                return false;

            return LooksLikeRawServerCatalogTitle(title) || !hasMetadata || !hasCanonicalId;
        }

        private static bool LooksLikeRawServerCatalogTitle(string? title)
        {
            var value = (title ?? "").Trim();
            if (string.IsNullOrWhiteSpace(value)) return true;

            return Regex.IsMatch(
                value,
                @"(?i)\b(s\d{1,2}e\d{1,2}|e\d{1,2}|480p|720p|1080p|2160p|4k|8k|web\-?dl|webrip|hdrip|bluray|blu\-?ray|amzn|nf|dsnp|hmax|ddp|aac|x264|x265|hevc|h\.264|h\.265|atmos|dv|hdr)\b");
        }

        private async Task EnrichServerCatalogItemMetadataAsync(MediaItem item, CancellationToken ct)
        {
            try
            {
                var type = (item.Type ?? "").Trim().ToLowerInvariant();
                var contentType = type.Contains("tv") || type.Contains("series") ? "series" : "movie";

                var rawId = ((item.MetaId ?? item.ImdbId ?? item.FilePath) ?? "").Trim();
                var imdbId = rawId.StartsWith("tt", StringComparison.OrdinalIgnoreCase) ? rawId : "";
                var contentId = rawId;

                var year = item.Year > 0 ? item.Year : 0;
                var lookupTitle = CleanLookupTitleForMeta((item.Title ?? "").Trim(), out var extractedYear);
                if (year <= 0)
                    year = extractedYear;

                if (string.IsNullOrWhiteSpace(imdbId) && UseCinemetaFallback && !string.IsNullOrWhiteSpace(lookupTitle))
                    imdbId = await ResolveImdbIdViaMetadataCatalogAsync(contentType, lookupTitle, year, ct).ConfigureAwait(false) ?? "";

                if (!string.IsNullOrWhiteSpace(imdbId) && imdbId.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                    contentId = imdbId;
                else if (rawId.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase))
                    contentId = rawId;

                if (string.IsNullOrWhiteSpace(contentId))
                    return;

                var metaEl = await TryFetchMetadataCatalogItemAsync(contentType, contentId.ToLowerInvariant(), ct).ConfigureAwait(false);
                if (metaEl.ValueKind != JsonValueKind.Object)
                    return;

                static string NormalizeAssetUrl(string url)
                {
                    var value = (url ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(value)) return "";
                    if (value.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || value.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                        return value;
                    if ((value.StartsWith("t", StringComparison.OrdinalIgnoreCase)) && value.Contains("-"))
                        return $"https://cinemeta.ratingposterdb.com/poster/{value}";
                    return value;
                }

                var name = metaEl.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String
                    ? (nameEl.GetString() ?? "").Trim()
                    : (metaEl.TryGetProperty("title", out var titleEl) && titleEl.ValueKind == JsonValueKind.String ? (titleEl.GetString() ?? "").Trim() : "");

                var overview = metaEl.TryGetProperty("description", out var descEl) && descEl.ValueKind == JsonValueKind.String
                    ? (descEl.GetString() ?? "").Trim()
                    : "";
                if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("overview", out var overviewEl) && overviewEl.ValueKind == JsonValueKind.String)
                    overview = (overviewEl.GetString() ?? "").Trim();
                if (string.IsNullOrWhiteSpace(overview) && metaEl.TryGetProperty("plot", out var plotEl) && plotEl.ValueKind == JsonValueKind.String)
                    overview = (plotEl.GetString() ?? "").Trim();

                var poster = metaEl.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String
                    ? NormalizeAssetUrl(posterEl.GetString() ?? "")
                    : "";
                var background = metaEl.TryGetProperty("background", out var bgEl) && bgEl.ValueKind == JsonValueKind.String
                    ? NormalizeAssetUrl(bgEl.GetString() ?? "")
                    : "";
                var logo = metaEl.TryGetProperty("logo", out var logoEl) && logoEl.ValueKind == JsonValueKind.String
                    ? NormalizeAssetUrl(logoEl.GetString() ?? "")
                    : "";

                var fetchedYear = 0;
                if (metaEl.TryGetProperty("year", out var yearEl))
                {
                    if (yearEl.ValueKind == JsonValueKind.Number)
                        yearEl.TryGetInt32(out fetchedYear);
                    else if (yearEl.ValueKind == JsonValueKind.String)
                        int.TryParse((yearEl.GetString() ?? "").Trim(), out fetchedYear);
                }

                var fetchedRating = 0d;
                if (metaEl.TryGetProperty("imdbRating", out var ratingEl))
                    fetchedRating = ReadNormalizedRating(ratingEl);
                if (fetchedRating <= 0 && metaEl.TryGetProperty("rating", out var ratingEl2))
                    fetchedRating = ReadNormalizedRating(ratingEl2);

                await _uiDispatcher.InvokeAsync(() =>
                {
                    if (!string.IsNullOrWhiteSpace(name) && (LooksLikeRawServerCatalogTitle(item.Title) || string.IsNullOrWhiteSpace(item.Title)))
                        item.Title = name;
                    if (!string.IsNullOrWhiteSpace(overview))
                    {
                        if (string.IsNullOrWhiteSpace(item.Metadata))
                            item.Metadata = overview;
                        if (string.IsNullOrWhiteSpace(item.Overview))
                            item.Overview = overview;
                    }
                    if (item.Year <= 0 && fetchedYear > 0)
                        item.Year = fetchedYear;
                    if (item.Rating <= 0 && fetchedRating > 0)
                        item.Rating = fetchedRating;
                    if (string.IsNullOrWhiteSpace(item.CoverUrl) && !string.IsNullOrWhiteSpace(poster))
                        item.CoverUrl = poster;
                    if (string.IsNullOrWhiteSpace(item.BackdropUrl) && !string.IsNullOrWhiteSpace(background))
                        item.BackdropUrl = background;
                    if (string.IsNullOrWhiteSpace(item.LogoUrl) && !string.IsNullOrWhiteSpace(logo))
                        item.LogoUrl = logo;
                    if (string.IsNullOrWhiteSpace(item.MetaId) && !string.IsNullOrWhiteSpace(imdbId))
                        item.MetaId = imdbId;
                });

                if (!string.IsNullOrWhiteSpace(item.CoverUrl) && item.CoverImage == null)
                    await TryLoadCoverIntoItemAsync(item, ct).ConfigureAwait(false);
            }
            catch
            {
            }
        }

        private void QueueServerMusicArtworkForVisibleItems()
        {
            if (!IsServersView) return;
            if (!IsServerCatalogPanelOpen) return;
            if (!IsServerCatalogMusicSelected) return;

            List<MediaItem> snapshot;
            if (_uiDispatcher.CheckAccess())
                snapshot = _serverCatalogItems.ToList();
            else
                snapshot = _uiDispatcher.Invoke(() => _serverCatalogItems.ToList());

            var pending = snapshot
                .Where(i =>
                    i != null &&
                    string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase) &&
                    i.CoverImage == null &&
                    string.IsNullOrWhiteSpace(i.CoverUrl) &&
                    !string.IsNullOrWhiteSpace(i.Title))
                .Take(60)
                .ToList();

            if (pending.Count == 0) return;

            try
            {
                _serverMusicArtworkCts?.Cancel();
                _serverMusicArtworkCts?.Dispose();
            }
            catch
            {
            }

            var cts = new CancellationTokenSource();
            _serverMusicArtworkCts = cts;
            var ct = cts.Token;

            _ = Task.Run(async () =>
            {
                try
                {
                    var semaphore = new SemaphoreSlim(3);
                    var tasks = pending.Select(async item =>
                    {
                        await semaphore.WaitAsync(ct).ConfigureAwait(false);
                        try
                        {
                            if (item.CoverImage != null) return;
                            if (!string.IsNullOrWhiteSpace(item.CoverUrl)) return;

                            var q = (item.Title ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(q)) return;

                            string? cachedUrl;
                            lock (_serverMusicArtworkCache)
                            {
                                _serverMusicArtworkCache.TryGetValue(q, out cachedUrl);
                            }

                            if (!string.IsNullOrWhiteSpace(cachedUrl))
                            {
                                _uiDispatcher.Invoke(() => item.CoverUrl = cachedUrl);
                                await TryLoadCoverIntoItemAsync(item, ct).ConfigureAwait(false);
                                return;
                            }

                            var lookupUrl = $"https://itunes.apple.com/search?term={Uri.EscapeDataString(q)}&entity=song&limit=1";
                            using var resp = await ServerHttp.GetAsync(lookupUrl, ct).ConfigureAwait(false);
                            if (!resp.IsSuccessStatusCode) return;

                            await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                            using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                            if (!doc.RootElement.TryGetProperty("results", out var resultsEl) || resultsEl.ValueKind != JsonValueKind.Array)
                                return;

                            var first = resultsEl.EnumerateArray().FirstOrDefault();
                            if (first.ValueKind != JsonValueKind.Object) return;

                            var artwork = first.TryGetProperty("artworkUrl100", out var artEl) && artEl.ValueKind == JsonValueKind.String
                                ? (artEl.GetString() ?? "").Trim()
                                : "";
                            if (string.IsNullOrWhiteSpace(artwork)) return;

                            artwork = artwork.Replace("100x100bb", "600x600bb", StringComparison.OrdinalIgnoreCase);
                            lock (_serverMusicArtworkCache)
                            {
                                _serverMusicArtworkCache[q] = artwork;
                            }

                            _uiDispatcher.Invoke(() => item.CoverUrl = artwork);
                            await TryLoadCoverIntoItemAsync(item, ct).ConfigureAwait(false);
                        }
                        catch
                        {
                        }
                        finally
                        {
                            semaphore.Release();
                        }
                    }).ToList();

                    await Task.WhenAll(tasks).ConfigureAwait(false);
                }
                catch
                {
                }
            }, ct);
        }

        private async Task TryLoadCoverIntoItemAsync(MediaItem item, CancellationToken ct)
        {
            try
            {
                if (item.CoverImage != null)
                    return;

                var coverUrl = (item.CoverUrl ?? "").Trim();
                ImageSource? image = null;
                if (!string.IsNullOrWhiteSpace(coverUrl))
                {
                    if (Uri.TryCreate(coverUrl, UriKind.Absolute, out var uri))
                    {
                        if (uri.IsFile)
                        {
                            var local = uri.LocalPath;
                            if (!string.IsNullOrWhiteSpace(local))
                                image = LoadAlbumCoverFromFile(local);
                        }
                        else if (string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) ||
                                 string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
                        {
                            image = await LoadImageFromUrlAsync(coverUrl, ct).ConfigureAwait(false);
                        }
                    }

                    if (image == null && File.Exists(coverUrl))
                        image = LoadAlbumCoverFromFile(coverUrl);
                }

                if (image == null)
                {
                    var type = (item.Type ?? "").Trim();
                    if (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) ||
                        string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase))
                    {
                        image = LoadVideoPosterForFile(item.FilePath);
                    }
                    else if (string.Equals(type, "music", StringComparison.OrdinalIgnoreCase))
                    {
                        image = LoadMusicCoverForTrack(item.FilePath);
                    }
                    else if (string.Equals(type, "images", StringComparison.OrdinalIgnoreCase))
                    {
                        if (!IsHttpUrl(item.FilePath, out _))
                            image = LoadAlbumCoverFromFile(item.FilePath);
                    }
                    else if (string.Equals(type, "games", StringComparison.OrdinalIgnoreCase))
                    {
                        image = LoadGameCoverImage(item.Album ?? "", item.TrackNumber, item.FilePath);
                    }
                }

                if (image == null)
                    return;

                _uiDispatcher.BeginInvoke(new Action(() =>
                {
                    try
                    {
                        if (item.CoverImage == null)
                            item.CoverImage = image;
                        if (item.IsPlaying)
                            NowPlayingCoverImage = item.CoverImage;
                        if (ReferenceEquals(_serverSeriesRootItem, item))
                            OnPropertyChanged(nameof(ServerSeriesBackdropImage));
                    }
                    catch
                    {
                    }
                }));
            }
            catch
            {
            }
        }

        private async Task RefreshServerSeriesMetaAsync()
        {
            if (!IsServersView || _serverSeriesRootItem == null)
                return;

            var seriesId = (_serverSeriesRootItem.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(seriesId))
                return;

            var selection = (SelectedAddonServer ?? "").Trim();
            var baseUrls = new List<string>();
            if (string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase))
            {
                baseUrls = _addonServers
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(x => x.Trim())
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
            }
            else
            {
                baseUrls.Add(selection);
            }

            if (baseUrls.Count == 0)
                baseUrls.Add("https://v3-cinemeta.strem.io");
            else
                baseUrls.Add("https://v3-cinemeta.strem.io");

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(12));
                var ct = cts.Token;

                foreach (var b in baseUrls.Where(x => !string.IsNullOrWhiteSpace(x)).Distinct(StringComparer.OrdinalIgnoreCase))
                {
                    try
                    {
                        var baseUrl = (b ?? "").Trim().TrimEnd('/');
                        if (string.IsNullOrWhiteSpace(baseUrl))
                            continue;

                        var metaUrl = BuildAddonEndpointUrl(baseUrl, $"/meta/series/{Uri.EscapeDataString(seriesId)}.json");
                        if (string.IsNullOrWhiteSpace(metaUrl))
                            continue;
                        using var resp = await ServerHttp.GetAsync(metaUrl, ct).ConfigureAwait(false);
                        if (!resp.IsSuccessStatusCode)
                            continue;

                        await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                        using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                        if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                            !doc.RootElement.TryGetProperty("meta", out var metaEl) ||
                            metaEl.ValueKind != JsonValueKind.Object)
                            continue;

                        var genres = new List<string>();
                        if (metaEl.TryGetProperty("genres", out var genresEl) && genresEl.ValueKind == JsonValueKind.Array)
                        {
                            foreach (var g in genresEl.EnumerateArray())
                            {
                                if (g.ValueKind != JsonValueKind.String) continue;
                                var s = (g.GetString() ?? "").Trim();
                                if (!string.IsNullOrWhiteSpace(s)) genres.Add(s);
                            }
                        }

                        if (genres.Count == 0)
                            continue;

                        genres = genres.Distinct(StringComparer.OrdinalIgnoreCase).Take(12).ToList();
                        _uiDispatcher.Invoke(() =>
                        {
                            _serverSeriesGenres.Clear();
                            foreach (var g in genres)
                                _serverSeriesGenres.Add(g);
                        });
                        return;
                    }
                    catch
                    {
                    }
                }
            }
            catch
            {
            }
        }

        private void RefreshStreamsForCurrentItem()
        {
            if (_streamsTargetItem == null) return;
            RefreshAddonServers();
            _ = RefreshStreamsAsync(_streamsTargetItem);
        }

        private static List<string> LoadAddonServersFromStore()
        {
            try
            {
                var raw = IntegrationKeyStore.GetDecrypted(AddonServersKey);
                if (string.IsNullOrWhiteSpace(raw))
                    return new List<string>();

                return (JsonSerializer.Deserialize<List<string>>(raw) ?? new List<string>())
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(NormalizeAddonServerUrl)
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
            }
            catch
            {
                return new List<string>();
            }
        }

        private static void SaveAddonServersToStore(List<string> servers)
        {
            try
            {
                var normalized = (servers ?? new List<string>())
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(NormalizeAddonServerUrl)
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                IntegrationKeyStore.SetProtected(AddonServersKey, JsonSerializer.Serialize(normalized));
            }
            catch
            {
            }
        }

        private static string GetAddonServersConfigPath()
        {
            try
            {
                var appData = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "AtlasAI");
                return Path.Combine(appData, "addon_servers.json");
            }
            catch
            {
                return "";
            }
        }

        private static bool AddonUrlsMatch(string a, string b)
        {
            if (string.IsNullOrWhiteSpace(a) || string.IsNullOrWhiteSpace(b)) return false;
            a = a.Trim().TrimEnd('/');
            b = b.Trim().TrimEnd('/');
            if (string.Equals(a, b, StringComparison.OrdinalIgnoreCase)) return true;

            // Compare after URI-decoding to handle %7C vs | and %3A vs : mismatches.
            try
            {
                var da = Uri.UnescapeDataString(a);
                var db = Uri.UnescapeDataString(b);
                if (string.Equals(da, db, StringComparison.OrdinalIgnoreCase)) return true;
            }
            catch { }

            // Compare after full normalization.
            var na = NormalizeAddonServerUrl(a);
            var nb = NormalizeAddonServerUrl(b);
            if (!string.IsNullOrWhiteSpace(na) && string.Equals(na, nb, StringComparison.OrdinalIgnoreCase)) return true;

            return false;
        }

        private static void TryRemoveAddonServerFromConfigFile(string normalizedBaseUrl)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(normalizedBaseUrl))
                    return;

                var normalizedTarget = NormalizeAddonServerUrl(normalizedBaseUrl);
                if (string.IsNullOrWhiteSpace(normalizedTarget))
                    return;

                Uri.TryCreate(normalizedTarget, UriKind.Absolute, out var targetUri);
                var targetHost = (targetUri?.Host ?? "").Trim();
                var targetPath = (targetUri?.AbsolutePath ?? "").Trim().Trim('/');

                var cfgPath = GetAddonServersConfigPath();
                if (string.IsNullOrWhiteSpace(cfgPath) || !File.Exists(cfgPath))
                    return;

                var json = File.ReadAllText(cfgPath);
                var items = JsonSerializer.Deserialize<List<AtlasAI.Models.AddonServerItem>>(json) ?? new List<AtlasAI.Models.AddonServerItem>();
                var changed = false;

                for (var index = items.Count - 1; index >= 0; index--)
                {
                    var item = items[index];
                    var itemUrl = item?.Url ?? "";
                    var itemNormalized = NormalizeAddonServerUrl(itemUrl);
                    if (string.IsNullOrWhiteSpace(itemNormalized))
                        continue;

                    var directMatch = AddonUrlsMatch(itemNormalized, normalizedTarget);
                    var hostPathMatch = false;
                    try
                    {
                        if (targetUri != null && Uri.TryCreate(itemNormalized, UriKind.Absolute, out var itemUri))
                        {
                            var itemHost = (itemUri.Host ?? "").Trim();
                            var itemPath = (itemUri.AbsolutePath ?? "").Trim().Trim('/');
                            hostPathMatch = !string.IsNullOrWhiteSpace(targetHost)
                                && string.Equals(itemHost, targetHost, StringComparison.OrdinalIgnoreCase)
                                && (string.IsNullOrWhiteSpace(targetPath)
                                    || string.Equals(itemPath, targetPath, StringComparison.OrdinalIgnoreCase)
                                    || itemPath.StartsWith(targetPath + "/", StringComparison.OrdinalIgnoreCase)
                                    || targetPath.StartsWith(itemPath + "/", StringComparison.OrdinalIgnoreCase));
                        }
                    }
                    catch
                    {
                    }

                    if (!directMatch && !hostPathMatch)
                        continue;

                    items.RemoveAt(index);
                    changed = true;
                }

                if (changed)
                    File.WriteAllText(cfgPath, JsonSerializer.Serialize(items, new JsonSerializerOptions { WriteIndented = true }));
            }
            catch
            {
            }
        }

        private static void TryAddOrEnableAddonServerInConfigFile(string normalizedBaseUrl)
        {
            try
            {
                normalizedBaseUrl = NormalizeAddonServerUrl(normalizedBaseUrl);
                if (string.IsNullOrWhiteSpace(normalizedBaseUrl))
                    return;

                var cfgPath = GetAddonServersConfigPath();
                if (string.IsNullOrWhiteSpace(cfgPath))
                    return;

                var dir = Path.GetDirectoryName(cfgPath);
                if (!string.IsNullOrWhiteSpace(dir) && !Directory.Exists(dir))
                    Directory.CreateDirectory(dir);

                List<AtlasAI.Models.AddonServerItem> items;
                try
                {
                    items = File.Exists(cfgPath)
                        ? (JsonSerializer.Deserialize<List<AtlasAI.Models.AddonServerItem>>(File.ReadAllText(cfgPath)) ?? new List<AtlasAI.Models.AddonServerItem>())
                        : new List<AtlasAI.Models.AddonServerItem>();
                }
                catch
                {
                    items = new List<AtlasAI.Models.AddonServerItem>();
                }

                var existing = items.FirstOrDefault(i => string.Equals(NormalizeAddonServerUrl(i?.Url ?? ""), normalizedBaseUrl, StringComparison.OrdinalIgnoreCase));
                if (existing != null)
                {
                    existing.Url = normalizedBaseUrl;
                    existing.Enabled = true;
                }
                else
                {
                    items.Add(new AtlasAI.Models.AddonServerItem
                    {
                        Name = "",
                        Url = normalizedBaseUrl,
                        Enabled = true,
                        Status = AtlasAI.Models.ServerStatus.Unknown,
                        ErrorMessage = ""
                    });
                }

                File.WriteAllText(cfgPath, JsonSerializer.Serialize(items, new JsonSerializerOptions { WriteIndented = true }));
            }
            catch
            {
            }
        }

        private void AddAddonServer(string? input)
        {
            try
            {
                var normalized = NormalizeAddonServerUrl(input ?? "");
                if (string.IsNullOrWhiteSpace(normalized))
                    return;

                var current = LoadAddonServersFromStore();
                if (!current.Any(x => string.Equals(x, normalized, StringComparison.OrdinalIgnoreCase)))
                    current.Add(normalized);

                SaveAddonServersToStore(current);
                TryAddOrEnableAddonServerInConfigFile(normalized);
            }
            catch
            {
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    AddonServerUrl = "";
                    RefreshAddonServers();
                });
            }
        }

        private void RemoveAddonServer(string? input)
        {
            try
            {
                var normalized = NormalizeAddonServerUrl(input ?? "");
                if (string.IsNullOrWhiteSpace(normalized))
                    return;

                // Also try the raw input for matching (avoids encoding mismatches).
                var rawInput = (input ?? "").Trim().TrimEnd('/');

                var current = LoadAddonServersFromStore();
                current.RemoveAll(x => AddonUrlsMatch(x, normalized) || AddonUrlsMatch(x, rawInput));
                SaveAddonServersToStore(current);
                TryRemoveAddonServerFromConfigFile(normalized);
                TryRemoveAddonServerFromConfigFile(rawInput);

                // If the user cleared the list, prevent defaults from being re-seeded later.
                if (current.Count == 0)
                {
                    try { IntegrationKeyStore.SetProtected(AddonServersSeededKey, "1"); } catch { }
                }
            }
            catch
            {
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    InvalidateServerCatalogAndShelvesState();
                    RefreshAddonServers();
                    RebuildServerShelves();
                });
            }
        }

        private void InvalidateServerCatalogAndShelvesState()
        {
            try { _serverShelvesDebounCts?.Cancel(); _serverShelvesDebounCts?.Dispose(); } catch { }
            _serverShelvesDebounCts = null;
            try { _serverShelvesBuildCts?.Cancel(); _serverShelvesBuildCts?.Dispose(); } catch { }
            _serverShelvesBuildCts = null;

            _cachedIntelligenceShelves = null;
            _cachedIntelligenceShelvesTime = DateTime.MinValue;

            lock (_stateLock)
            {
                _serverMovieCatalogOptionsByServer.Clear();
                _serverSeriesCatalogOptionsByServer.Clear();
                _serverMusicCatalogOptionsByServer.Clear();
                _serverMoviePageStates.Clear();
                _serverTvPageStates.Clear();
                _serverMusicPageStates.Clear();
                _serverCatalogSupportCache.Clear();
                _serverCatalogBackoffUntil.Clear();
            }

            _serverShelves.Clear();
            ActiveServerShelf = null;
            _serverCatalogItems.Clear();
            _serverMovieCatalogItems.Clear();
            _serverTvCatalogItems.Clear();
            _serverMusicCatalogItems.Clear();
            _serverCatalogCatalogs.Clear();
            _serverMovieVisibleCount = 0;
            _serverTvVisibleCount = 0;
            _serverMusicVisibleCount = 0;
            OnPropertyChanged(nameof(ServerShelves));
            OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
            OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
        }

        private void UseOnlySelectedServer()
        {
            try
            {
                var selection = NormalizeAddonServerUrl((SelectedAddonServer ?? "").Trim());
                if (string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase))
                    return;

                SaveAddonServersToStore(new List<string> { selection });
                try
                {
                    IntegrationKeyStore.SetProtected(AddonServerSelectedKey, selection);
                }
                catch
                {
                }

                _uiDispatcher.Invoke(() =>
                {
                    RefreshAddonServers();
                    SelectedStreamsMode = StreamsMode.Servers;
                });

                _ = RefreshServerCatalogAsync();
            }
            catch
            {
            }
        }

        private void RefreshServerCatalogCatalogs()
        {
            _serverCatalogCatalogs.Clear();

            var selection = NormalizeAddonServerUrl((SelectedAddonServer ?? "").Trim());
            if (string.IsNullOrWhiteSpace(selection))
                selection = (SelectedAddonServer ?? "").Trim();

            var contentType = IsServerCatalogTvSelected ? "series" : (IsServerCatalogMusicSelected ? "music" : "movie");
            var options = GetAvailableServerCatalogOptions(contentType, selection, IsAllServersSelected);

            if (options.Count == 0)
            {
                var fallback = "top";
                try
                {
                    var state = IsServerCatalogTvSelected
                        ? _serverTvPageStates.Values.FirstOrDefault()
                        : (IsServerCatalogMusicSelected
                            ? _serverMusicPageStates.Values.FirstOrDefault()
                            : _serverMoviePageStates.Values.FirstOrDefault());
                    if (state != null && !string.IsNullOrWhiteSpace(state.CatalogId))
                        fallback = state.CatalogId;
                }
                catch
                {
                }

                options.Add(new ServerCatalogCatalogOption
                {
                    Label = BuildServerCatalogLabel(fallback, null),
                    Value = fallback,
                    ContentType = contentType
                });
            }

            foreach (var o in options)
                _serverCatalogCatalogs.Add(o);

            var desired = SelectedServerCatalogCatalogId;
            if (string.IsNullOrWhiteSpace(desired) || !_serverCatalogCatalogs.Any(o => string.Equals(o.Value, desired, StringComparison.OrdinalIgnoreCase)))
            {
                var v = _serverCatalogCatalogs.FirstOrDefault()?.Value ?? "";
                if (IsServerCatalogTvSelected)
                    _selectedServerSeriesCatalogId = v;
                else if (IsServerCatalogMusicSelected)
                    _selectedServerMusicCatalogId = v;
                else
                    _selectedServerMovieCatalogId = v;
                OnPropertyChanged(nameof(SelectedServerCatalogCatalogId));
            }

            OnPropertyChanged(nameof(HasServerCatalogCatalogs));
        }

		private void EnsureDefaultServerCatalogGenres()
		{
			try
			{
				if (ServerCatalogGenres.Count == 0)
					ServerCatalogGenres.Add(new ServerCatalogOption { Label = "All", Value = "" });

				if (string.IsNullOrWhiteSpace(SelectedServerCatalogGenre))
					SelectedServerCatalogGenre = "";
			}
			catch
			{
			}
		}

        private void RefreshServerCatalogFilterOptions()
        {
            void Update()
            {
                var items = IsServerCatalogTvSelected
                    ? _serverTvCatalogItems
                    : (IsServerCatalogMusicSelected ? _serverMusicCatalogItems : _serverMovieCatalogItems);

                var genres = items
                    .SelectMany(i => i?.Genres ?? Array.Empty<string>())
                    .Where(g => !string.IsNullOrWhiteSpace(g))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .OrderBy(g => g, StringComparer.OrdinalIgnoreCase)
                    .ToList();

                var years = items
                    .Select(i => i?.Year ?? 0)
                    .Where(y => y > 0)
                    .Distinct()
                    .OrderByDescending(y => y)
                    .ToList();

                _serverCatalogGenreOptions.Clear();
                _serverCatalogGenreOptions.Add(AllGenresOption);
                foreach (var g in genres)
                    _serverCatalogGenreOptions.Add(g);

				ServerCatalogGenres.Clear();
				ServerCatalogGenres.Add(new ServerCatalogOption { Label = "All", Value = "" });
				foreach (var g in genres)
					ServerCatalogGenres.Add(new ServerCatalogOption { Label = g, Value = g });

                _serverCatalogYearOptions.Clear();
                _serverCatalogYearOptions.Add(AllYearsOption);
                foreach (var y in years)
                    _serverCatalogYearOptions.Add(y.ToString());

				var genreSelection = (_selectedServerCatalogGenre ?? "").Trim();
				if (!string.IsNullOrWhiteSpace(genreSelection) && !_serverCatalogGenreOptions.Any(o => string.Equals(o, genreSelection, StringComparison.OrdinalIgnoreCase)))
					genreSelection = "";
				if (!string.Equals(_selectedServerCatalogGenre, genreSelection, StringComparison.OrdinalIgnoreCase))
				{
					_selectedServerCatalogGenre = genreSelection;
					OnPropertyChanged(nameof(SelectedServerCatalogGenre));
				}

                var yearSelection = string.IsNullOrWhiteSpace(_selectedServerCatalogYear) ? AllYearsOption : _selectedServerCatalogYear.Trim();
                if (!_serverCatalogYearOptions.Any(o => string.Equals(o, yearSelection, StringComparison.OrdinalIgnoreCase)))
                    yearSelection = AllYearsOption;
                if (!string.Equals(_selectedServerCatalogYear, yearSelection, StringComparison.OrdinalIgnoreCase))
                {
                    _selectedServerCatalogYear = yearSelection;
                    OnPropertyChanged(nameof(SelectedServerCatalogYear));
                }
            }

            if (_uiDispatcher.CheckAccess())
                Update();
            else
                _uiDispatcher.Invoke(Update);
        }

        private void ApplySelectedServerCatalogToPageStates(string catalogId)
        {
            catalogId = (catalogId ?? "").Trim();
            if (string.IsNullOrWhiteSpace(catalogId)) return;

            if (IsServerCatalogTvSelected)
            {
                ApplyCatalogSelectionToStates(_serverTvPageStates, "series", catalogId);
            }
            else if (IsServerCatalogMusicSelected)
            {
                ApplyCatalogSelectionToStates(_serverMusicPageStates, "music", catalogId);
            }
            else
            {
                ApplyCatalogSelectionToStates(_serverMoviePageStates, "movie", catalogId);
            }
        }

        private async Task ReloadServerCatalogFromStatesAsync()
        {
            if (!IsServersView)
                return;
            if (IsServerCatalogBusy)
                return;

            var selection = (SelectedAddonServer ?? "").Trim();
            var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
            var displayServerCount = 0;
            if (isAllServers)
                displayServerCount = _addonServers.Count;

            IsServerCatalogBusy = true;
            ServerCatalogStatusText = "Loading...";
            CommandManager.InvalidateRequerySuggested();

            try
            {
                _serverCatalogCoverCts?.Cancel();
                _serverCatalogCoverCts?.Dispose();
                _serverCatalogCoverCts = null;
                _serverCatalogMetaCts?.Cancel();
                _serverCatalogMetaCts?.Dispose();
                _serverCatalogMetaCts = null;

                _uiDispatcher.Invoke(() =>
                {
                    _serverCatalogItems.Clear();
                    _serverMovieCatalogItems.Clear();
                    _serverTvCatalogItems.Clear();
                    _serverMusicCatalogItems.Clear();
                    _serverMovieVisibleCount = 0;
                    _serverTvVisibleCount = 0;
                    _serverMusicVisibleCount = 0;
                });

                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(25));
                var ct = cts.Token;

                const int prefetchMin = 320;
                const int prefetchPasses = 6;

                var moviesRaw = new List<MediaItem>();
                var seriesRaw = new List<MediaItem>();
                for (var pass = 0; pass < prefetchPasses && !ct.IsCancellationRequested; pass++)
                {
                    if (moviesRaw.Count < prefetchMin && _serverMoviePageStates.Values.Any(s => s.HasMore))
                    {
                        try
                        {
                            var batch = await LoadNextPagesForTypeAsync(_serverMoviePageStates, ct).ConfigureAwait(false);
                            if (batch.Count > 0) moviesRaw.AddRange(batch);
                        }
                        catch
                        {
                            break;
                        }
                    }

                    if (seriesRaw.Count < prefetchMin && _serverTvPageStates.Values.Any(s => s.HasMore))
                    {
                        try
                        {
                            var batch = await LoadNextPagesForTypeAsync(_serverTvPageStates, ct).ConfigureAwait(false);
                            if (batch.Count > 0) seriesRaw.AddRange(batch);
                        }
                        catch
                        {
                            break;
                        }
                    }

                    if (moviesRaw.Count >= prefetchMin && seriesRaw.Count >= prefetchMin)
                        break;
                }

                var movies = moviesRaw
                    .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                    .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                    .ToList();

                var series = seriesRaw
                    .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                    .DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
                    .ToList();

                if (movies.Count == 0 && series.Count == 0 && !ct.IsCancellationRequested)
                {
                    try
                    {
                        var cinemetaMovies = await FetchCinemetaTopAsync("movie", ct).ConfigureAwait(false);
                        var cinemetaSeries = await FetchCinemetaTopAsync("series", ct).ConfigureAwait(false);
                        if (cinemetaMovies.Count > 0)
                            movies = cinemetaMovies;
                        if (cinemetaSeries.Count > 0)
                            series = cinemetaSeries;
                    }
                    catch
                    {
                    }
                }

                _uiDispatcher.Invoke(() =>
                {
                    _serverMovieCatalogItems.Clear();
                    foreach (var i in movies)
                        _serverMovieCatalogItems.Add(i);

                    _serverTvCatalogItems.Clear();
                    foreach (var i in series)
                        _serverTvCatalogItems.Add(i);

                    const int initialPageSize = 240;
                    _serverMovieVisibleCount = Math.Min(_serverMovieCatalogItems.Count, initialPageSize);
                    _serverTvVisibleCount = Math.Min(_serverTvCatalogItems.Count, initialPageSize);
                    _serverMusicVisibleCount = Math.Min(_serverMusicCatalogItems.Count, initialPageSize);
                    RefreshServerCatalogFilterOptions();
                    OnServerCatalogSearchQueryChanged();
                    try
                    {
                        if (PreviewItem == null)
                        {
                            var first = _serverCatalogItems.FirstOrDefault();
                            if (first != null)
                                SetPreviewItem(first);
                        }
                    }
                    catch
                    {
                    }

                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();

                    if (!isAllServers && _serverMovieCatalogItems.Count == 0 && _serverTvCatalogItems.Count == 0 && _serverMusicCatalogItems.Count == 0)
                    {
                        var normalized = NormalizeAddonServerUrl(selection);
                        if (_serverCatalogSupportCache.TryGetValue(normalized, out var supported) && supported == false)
                            ServerCatalogStatusText = "Stream-only addon (no catalogs) · use 'All servers' to browse";
                        else
                            ServerCatalogStatusText = "No catalog returned by this addon";
                        return;
                    }

                    var suffix = isAllServers
                        ? (displayServerCount <= 0 ? "Cinemeta" : $"{displayServerCount} server(s)")
                        : "1 server";
                    ServerCatalogStatusText = $"{_serverMovieCatalogItems.Count} movies · {_serverTvCatalogItems.Count} series · {_serverMusicCatalogItems.Count} music · {suffix}";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    _serverCatalogItems.Clear();
                    _serverMovieCatalogItems.Clear();
                    _serverTvCatalogItems.Clear();
                    _serverMusicCatalogItems.Clear();
                    ServerCatalogStatusText = "Failed to load catalog";
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsServerCatalogBusy = false;
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
                try
                {
                    if (IsServersView &&
                        IsServerCatalogPanelOpen &&
                        _serverMovieCatalogItems.Count == 0 &&
                        _serverTvCatalogItems.Count == 0 &&
                        _serverMusicCatalogItems.Count == 0 &&
                        CanLoadNextServerCatalogPage)
                    {
                        _ = LoadNextServerCatalogPageAsync();
                    }
                }
                catch
                {
                }
            }
        }

        private async Task RefreshServerCatalogAsync()
        {
            if (!IsServersView)
                return;

            var selection = (SelectedAddonServer ?? "").Trim();
            var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
            var baseUrls = new List<string>();
            var displayServerCount = 0;
            var normalizedSelection = NormalizeAddonServerUrl(selection);
            if (isAllServers)
            {
                List<string> servers;
                if (_uiDispatcher.CheckAccess())
                {
                    servers = _addonServers.ToList();
                }
                else
                {
                    servers = _uiDispatcher.Invoke(() => _addonServers.ToList());
                }

                var normalizedServers = servers
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Select(NormalizeAddonServerUrl)
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Select(s => s.Trim().TrimEnd('/'))
                    .ToList();

                baseUrls.Clear();
                baseUrls.Add("https://v3-cinemeta.strem.io");
                baseUrls.AddRange(normalizedServers);
                baseUrls = baseUrls
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(x => x.Trim().TrimEnd('/'))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
                displayServerCount = normalizedServers.Count + 1;
            }
            else
            {
                baseUrls.Add(selection);
                displayServerCount = 1;
            }

            if (baseUrls.Count == 0)
            {
                _uiDispatcher.Invoke(() =>
                {
                    _serverCatalogItems.Clear();
                    _serverMovieCatalogItems.Clear();
                    _serverTvCatalogItems.Clear();
                    _serverMusicCatalogItems.Clear();
                    _serverMoviePageStates.Clear();
                    _serverTvPageStates.Clear();
                    _serverMusicPageStates.Clear();
                    ServerCatalogStatusText = "Add a server";
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                });
                return;
            }

            if (IsServerCatalogBusy)
                return;

            IsServerCatalogBusy = true;
            ServerCatalogStatusText = "Loading...";
            CommandManager.InvalidateRequerySuggested();

            try
            {
                _serverCatalogCoverCts?.Cancel();
                _serverCatalogCoverCts?.Dispose();
                _serverCatalogCoverCts = null;
                _serverCatalogMetaCts?.Cancel();
                _serverCatalogMetaCts?.Dispose();
                _serverCatalogMetaCts = null;

                _uiDispatcher.Invoke(() =>
                {
                    _serverCatalogItems.Clear();
                    _serverMovieCatalogItems.Clear();
                    _serverTvCatalogItems.Clear();
                    _serverMusicCatalogItems.Clear();
                    _serverMovieVisibleCount = 0;
                    _serverTvVisibleCount = 0;
                    _serverMusicVisibleCount = 0;
                });

                _serverMoviePageStates.Clear();
                _serverTvPageStates.Clear();
                _serverMusicPageStates.Clear();
                _serverMovieCatalogOptionsByServer.Clear();
                _serverSeriesCatalogOptionsByServer.Clear();
                _serverMusicCatalogOptionsByServer.Clear();

                var timeoutSeconds = Math.Clamp(20 + (baseUrls.Count * 5), 25, 90);
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(timeoutSeconds));
                var ct = cts.Token;

                if (isAllServers)
                {
                    _ = Task.Run(async () =>
                    {
                        try
                        {
                            using var primeCts = new CancellationTokenSource(TimeSpan.FromSeconds(10));
                            var primeCt = primeCts.Token;

                            var seed = new ServerCatalogPageState("https://v3-cinemeta.strem.io", "movie", "top", NextSkip: 0, HasMore: true, RequestType: "movie");
                            _serverMoviePageStates[seed.BaseUrl] = seed;
                            _serverTvPageStates[seed.BaseUrl] = seed with { ContentType = "series", RequestType = "series" };

                            var moviesRaw = await LoadNextPagesForTypeAsync(_serverMoviePageStates, primeCt).ConfigureAwait(false);
                            var seriesRaw = await LoadNextPagesForTypeAsync(_serverTvPageStates, primeCt).ConfigureAwait(false);

							var movies = moviesRaw
								.Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
								.DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
								.ToList();

							var series = seriesRaw
								.Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
								.DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
								.ToList();

                            _uiDispatcher.Invoke(() =>
                            {
                                if (_serverMovieCatalogItems.Count == 0)
                                {
                                    foreach (var i in movies)
                                        _serverMovieCatalogItems.Add(i);
                                    _serverMovieVisibleCount = Math.Min(_serverMovieCatalogItems.Count, ServerCatalogPageSize);
                                }

                                if (_serverTvCatalogItems.Count == 0)
                                {
                                    foreach (var i in series)
                                        _serverTvCatalogItems.Add(i);
                                    _serverTvVisibleCount = Math.Min(_serverTvCatalogItems.Count, ServerCatalogPageSize);
                                }

                                RefreshServerCatalogFilterOptions();
                                RebuildServerCatalogVisibleItems();
                                // Don't rebuild shelves here — the main refresh path will call RebuildServerShelves()
                                // after all addon manifests are loaded, which avoids a race condition where this
                                // early rebuild produces intelligence-only shelves (no addon candidates yet).
                                OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                                OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                                CommandManager.InvalidateRequerySuggested();
                            });
                        }
                        catch
                        {
                        }
                    });
                }

                var initConcurrency = Math.Min(6, Math.Max(3, baseUrls.Count));
                var initSemaphore = new SemaphoreSlim(initConcurrency);
                // Include ALL servers (including cinemeta) so every addon's catalog options
                // are parsed from the manifest and available for shelf building.
                // The cinemeta prime task above handles early grid loading in parallel.
                var initUrls = baseUrls.Where(u => !string.IsNullOrWhiteSpace(u)).ToList();

                var initTasks = initUrls.Select(async url =>
                {
                    var acquired = false;
                    try
                    {
                        await initSemaphore.WaitAsync(ct).ConfigureAwait(false);
                        acquired = true;
                        return await TryInitServerCatalogStatesAsync(url, ct).ConfigureAwait(false);
                    }
                    catch
                    {
                        return (movie: (ServerCatalogPageState?)null, series: (ServerCatalogPageState?)null, music: (ServerCatalogPageState?)null);
                    }
                    finally
                    {
                        if (acquired)
                            initSemaphore.Release();
                    }
                }).ToList();

                var initResults = await Task.WhenAll(initTasks).ConfigureAwait(false);
                foreach (var r in initResults)
                {
                    if (r.movie != null)
                        _serverMoviePageStates[r.movie.BaseUrl] = r.movie;
                    if (r.series != null)
                        _serverTvPageStates[r.series.BaseUrl] = r.series;
                    if (r.music != null)
                        _serverMusicPageStates[r.music.BaseUrl] = r.music;
                }

                try
                {
                    _uiDispatcher.Invoke(RefreshServerCatalogCatalogs);
                }
                catch
                {
                }

                if (!string.IsNullOrWhiteSpace(_selectedServerMovieCatalogId))
                {
                    ApplyCatalogSelectionToStates(_serverMoviePageStates, "movie", _selectedServerMovieCatalogId);
                }
                if (!string.IsNullOrWhiteSpace(_selectedServerSeriesCatalogId))
                {
                    ApplyCatalogSelectionToStates(_serverTvPageStates, "series", _selectedServerSeriesCatalogId);
                }
                if (!string.IsNullOrWhiteSpace(_selectedServerMusicCatalogId))
                {
                    ApplyCatalogSelectionToStates(_serverMusicPageStates, "music", _selectedServerMusicCatalogId);
                }

                // F2: start shelf build immediately after manifests — catalog options are fully
                // populated by initTasks above. BuildServerShelvesAsync does not need grid items,
                // so there is no need to wait for LoadNextPagesForTypeAsync to complete first.
                try
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        AtlasAI.Core.AppLogger.LogInfo("[BuildServerShelves] early rebuild requested after manifest init");
                        RebuildServerShelves();
                    });
                }
                catch { }

                const int prefetchMin = 120;
                const int prefetchPasses = 3;

                var moviesRaw = new List<MediaItem>();
                var seriesRaw = new List<MediaItem>();
                for (var pass = 0; pass < prefetchPasses && !ct.IsCancellationRequested; pass++)
                {
						if (moviesRaw.Count < prefetchMin && _serverMoviePageStates.Values.Any(s => s.HasMore))
                    {
							var batch = await LoadNextPagesForTypeAsync(_serverMoviePageStates, ct, loadAllServers: isAllServers && pass == 0).ConfigureAwait(false);
                        if (batch.Count > 0) moviesRaw.AddRange(batch);
                    }

						if (seriesRaw.Count < prefetchMin && _serverTvPageStates.Values.Any(s => s.HasMore))
                    {
							var batch = await LoadNextPagesForTypeAsync(_serverTvPageStates, ct, loadAllServers: isAllServers && pass == 0).ConfigureAwait(false);
                        if (batch.Count > 0) seriesRaw.AddRange(batch);
                    }

                    if (moviesRaw.Count >= prefetchMin && seriesRaw.Count >= prefetchMin)
                        break;
                }

				var movies = moviesRaw
					.Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
					.DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
					.ToList();

				var series = seriesRaw
					.Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
					.DistinctBy(i => BuildServerCatalogDedupeKey(i), StringComparer.OrdinalIgnoreCase)
					.ToList();

                _uiDispatcher.Invoke(() =>
                {
                    _serverMovieCatalogItems.Clear();
                    foreach (var i in movies)
                        _serverMovieCatalogItems.Add(i);

                    _serverTvCatalogItems.Clear();
                    foreach (var i in series)
                        _serverTvCatalogItems.Add(i);

                    const int initialPageSize = 40;
                    _serverMovieVisibleCount = Math.Min(_serverMovieCatalogItems.Count, initialPageSize);
                    _serverTvVisibleCount = Math.Min(_serverTvCatalogItems.Count, initialPageSize);
                    _serverMusicVisibleCount = Math.Min(_serverMusicCatalogItems.Count, initialPageSize);
                    ServerCatalogCurrentPage = 1;
                    RefreshServerCatalogFilterOptions();
                    OnServerCatalogSearchQueryChanged();
                    try
                    {
                        // Only auto-select preview when NOT in shelves mode
                        if (!IsServerShelvesMode && (PreviewItem == null || !_serverCatalogItems.Contains(PreviewItem)))
                        {
                            var first = _serverCatalogItems.FirstOrDefault();
                            if (first != null)
                                SetPreviewItem(first);
                        }
                    }
                    catch
                    {
                    }

                    // Shelves already triggered earlier (F2 early rebuild after manifest init).

                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();

                    if (!isAllServers && _serverMovieCatalogItems.Count == 0 && _serverTvCatalogItems.Count == 0 && !_serverMusicPageStates.Values.Any())
                    {
                        var normalized = string.IsNullOrWhiteSpace(normalizedSelection) ? NormalizeAddonServerUrl(selection) : normalizedSelection;
                        if (_serverCatalogSupportCache.TryGetValue(normalized, out var supported) && supported == false)
                            ServerCatalogStatusText = "Stream-only addon (no catalogs) · use 'All servers' to browse";
                        else
                            ServerCatalogStatusText = "No catalog returned by this addon";
                        return;
                    }

                    var suffix = isAllServers
                        ? (displayServerCount <= 0 ? "Cinemeta" : $"{displayServerCount} server(s)")
                        : "1 server";
                    ServerCatalogStatusText = $"{_serverMovieCatalogItems.Count} movies · {_serverTvCatalogItems.Count} series · {_serverMusicCatalogItems.Count} music · {suffix}";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    _serverCatalogItems.Clear();
                    _serverMovieCatalogItems.Clear();
                    _serverTvCatalogItems.Clear();
                    _serverMusicCatalogItems.Clear();
                    _serverMoviePageStates.Clear();
                    _serverTvPageStates.Clear();
                    _serverMusicPageStates.Clear();
                    ServerCatalogStatusText = "Failed to load catalog";
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsServerCatalogBusy = false;
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private async Task LoadNextServerCatalogPageAsync()
        {
            if (!IsServersView) return;
            if (IsServerCatalogBusy) return;
            if (!IsServerCatalogPanelOpen) return;

            var selection = (SelectedAddonServer ?? "").Trim();
            var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
            var baseUrls = new List<string>();
            if (isAllServers)
            {
                List<string> servers;
                if (_uiDispatcher.CheckAccess())
                {
                    servers = _addonServers.ToList();
                }
                else
                {
                    servers = _uiDispatcher.Invoke(() => _addonServers.ToList());
                }

                var normalizedServers = servers
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Select(NormalizeAddonServerUrl)
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Select(s => s.Trim().TrimEnd('/'))
                    .ToList();

                baseUrls.Clear();
                baseUrls.Add("https://v3-cinemeta.strem.io");
                baseUrls.AddRange(normalizedServers);
                baseUrls = baseUrls
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(x => x.Trim().TrimEnd('/'))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
            }
            else
            {
                baseUrls.Add(selection);
            }

            var states = IsServerCatalogTvSelected
                ? _serverTvPageStates
                : (IsServerCatalogMusicSelected ? _serverMusicPageStates : _serverMoviePageStates);
            if (!states.Values.Any(s => s.HasMore))
                return;

            IsServerCatalogBusy = true;
            ServerCatalogStatusText = "Loading more...";
            CommandManager.InvalidateRequerySuggested();

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(12));
                var ct = cts.Token;

                var searchQuery = IsServerCatalogMusicSelected ? (ServerCatalogSearchQuery ?? "").Trim() : null;
                var excludeKeys = _uiDispatcher.Invoke(() =>
                {
                    var target = IsServerCatalogTvSelected
                        ? _serverTvCatalogItems
                        : (IsServerCatalogMusicSelected ? _serverMusicCatalogItems : _serverMovieCatalogItems);
                    return new HashSet<string>(
                        target.Select(i => BuildServerCatalogDedupeKey(i)).Where(x => !string.IsNullOrWhiteSpace(x)),
                        StringComparer.OrdinalIgnoreCase);
                });
                var newItems = new List<MediaItem>();
                var targetMinimum = IsServerCatalogMusicSelected ? 24 : 48;
                const int maxAdvancePasses = 4;

                for (var pass = 0; pass < maxAdvancePasses && states.Values.Any(s => s.HasMore); pass++)
                {
                    var batch = await LoadNextPagesForTypeAsync(states, ct, searchQuery, loadAllServers: isAllServers, excludeKeys: excludeKeys).ConfigureAwait(false);
                    if (batch.Count == 0)
                        continue;

                    var addedThisPass = false;
                    foreach (var item in batch)
                    {
                        if (item == null) continue;
                        var key = BuildServerCatalogDedupeKey(item);
                        if (string.IsNullOrWhiteSpace(key)) continue;
                        if (!excludeKeys.Add(key)) continue;
                        newItems.Add(item);
                        addedThisPass = true;
                    }

                    if (newItems.Count >= targetMinimum)
                        break;

                    if (!addedThisPass)
                        continue;
                }

                _uiDispatcher.Invoke(() =>
                {
                    var target = IsServerCatalogTvSelected
                        ? _serverTvCatalogItems
                        : (IsServerCatalogMusicSelected ? _serverMusicCatalogItems : _serverMovieCatalogItems);
					var existing = new HashSet<string>(
						target.Select(i => BuildServerCatalogDedupeKey(i)).Where(x => !string.IsNullOrWhiteSpace(x)),
						StringComparer.OrdinalIgnoreCase);
                    foreach (var i in newItems)
                    {
                        if (i == null) continue;
						var key = BuildServerCatalogDedupeKey(i);
						if (string.IsNullOrWhiteSpace(key)) continue;
						if (!existing.Add(key)) continue;
                        target.Add(i);
                    }

                    var pageSize = IsServerCatalogMusicSelected ? 48 : 96;
                    if (IsServerCatalogTvSelected)
                        _serverTvVisibleCount = Math.Min(_serverTvCatalogItems.Count, _serverTvVisibleCount + pageSize);
                    else if (IsServerCatalogMusicSelected)
                        _serverMusicVisibleCount = Math.Min(_serverMusicCatalogItems.Count, _serverMusicVisibleCount + pageSize);
                    else
                        _serverMovieVisibleCount = Math.Min(_serverMovieCatalogItems.Count, _serverMovieVisibleCount + pageSize);

                    RefreshServerCatalogFilterOptions();
                    RebuildServerCatalogVisibleItems();
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();

                    if (!isAllServers && _serverMovieCatalogItems.Count == 0 && _serverTvCatalogItems.Count == 0 && _serverMusicCatalogItems.Count == 0)
                    {
                        var normalized = NormalizeAddonServerUrl(selection);
                        if (_serverCatalogSupportCache.TryGetValue(normalized, out var supported) && supported == false)
                            ServerCatalogStatusText = "Stream-only addon (no catalogs) · use 'All servers' to browse";
                        else
                            ServerCatalogStatusText = "No catalog returned by this addon";
                        return;
                    }

                    var suffix = isAllServers ? $"{baseUrls.Count} server(s)" : "1 server";
                    ServerCatalogStatusText = $"{_serverMovieCatalogItems.Count} movies · {_serverTvCatalogItems.Count} series · {_serverMusicCatalogItems.Count} music · {suffix}";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    ServerCatalogStatusText = "Failed to load more";
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsServerCatalogBusy = false;
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private async Task EnsureServerMusicCatalogLoadedAsync()
        {
            if (!IsServersView) return;
            if (!IsServerCatalogPanelOpen) return;
            if (!IsServerCatalogMusicSelected) return;
            if (IsServerCatalogBusy) return;

            if (_serverMusicCatalogItems.Count > 0)
            {
                _uiDispatcher.Invoke(() =>
                {
                    const int initialPageSize = 40;
                    if (_serverMusicVisibleCount <= 0)
                        _serverMusicVisibleCount = Math.Min(_serverMusicCatalogItems.Count, initialPageSize);
                    ServerCatalogCurrentPage = 1;
                    RebuildServerCatalogVisibleItems();
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            if (!_serverMusicPageStates.Values.Any(s => s.HasMore))
            {
                _uiDispatcher.Invoke(() =>
                {
                    RebuildServerCatalogVisibleItems();
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            IsServerCatalogBusy = true;
            ServerCatalogStatusText = "Loading music...";
            CommandManager.InvalidateRequerySuggested();

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(25));
                var ct = cts.Token;

				var selection = (SelectedAddonServer ?? "").Trim();
				var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
				var raw = await LoadNextPagesForTypeAsync(_serverMusicPageStates, ct, loadAllServers: isAllServers).ConfigureAwait(false);
                var batch = raw
                    .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                    .DistinctBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                    .ToList();

                _uiDispatcher.Invoke(() =>
                {
                    foreach (var i in batch)
                        _serverMusicCatalogItems.Add(i);

                    const int initialPageSize = 40;
                    _serverMusicVisibleCount = Math.Min(_serverMusicCatalogItems.Count, initialPageSize);
                    ServerCatalogCurrentPage = 1;
                    RefreshServerCatalogFilterOptions();
                    RebuildServerCatalogVisibleItems();

                    var selection = (SelectedAddonServer ?? "").Trim();
                    var isAllServers = string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase);
                    var suffix = isAllServers ? "Cinemeta" : "1 server";
                    ServerCatalogStatusText = $"{_serverMovieCatalogItems.Count} movies · {_serverTvCatalogItems.Count} series · {_serverMusicCatalogItems.Count} music · {suffix}";

                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    RebuildServerCatalogVisibleItems();
                    ServerCatalogStatusText = "Failed to load music";
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsServerCatalogBusy = false;
                    OnPropertyChanged(nameof(CanLoadMoreServerCatalog));
                    OnPropertyChanged(nameof(CanLoadNextServerCatalogPage));
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private async Task<(ServerCatalogPageState? movie, ServerCatalogPageState? series, ServerCatalogPageState? music)> TryInitServerCatalogStatesAsync(string serverBaseUrl, CancellationToken ct)
        {
            try
            {
                var baseUrl = (serverBaseUrl ?? "").Trim().TrimEnd('/');
                if (string.IsNullOrWhiteSpace(baseUrl))
                    return (null, null, null);

                var normalizedBaseUrl = NormalizeAddonServerUrl(baseUrl);
                if (string.IsNullOrWhiteSpace(normalizedBaseUrl))
                    normalizedBaseUrl = baseUrl;

                var manifestUrl = BuildAddonEndpointUrl(baseUrl, "/manifest.json");
                if (string.IsNullOrWhiteSpace(manifestUrl))
                    return (null, null, null);
                AtlasAI.Core.AppLogger.LogInfo($"[InitServerCatalog] Fetching manifest: {manifestUrl}");
                using var manifestReqCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
                manifestReqCts.CancelAfter(TimeSpan.FromSeconds(18));
                using var manifestResp = await ServerHttp.GetAsync(manifestUrl, HttpCompletionOption.ResponseHeadersRead, manifestReqCts.Token).ConfigureAwait(false);
                if (!manifestResp.IsSuccessStatusCode)
                {
                    var movieOk = await ProbeCatalogHasMetasAsync(baseUrl, "movie", "top", ct).ConfigureAwait(false);
                    var seriesOk = await ProbeCatalogHasMetasAsync(baseUrl, "series", "top", ct).ConfigureAwait(false);
                    var musicOk = await ProbeCatalogHasMetasAsync(baseUrl, "music", "top", ct).ConfigureAwait(false);
                    _serverCatalogSupportCache[normalizedBaseUrl] = movieOk || seriesOk || musicOk ? true : null;
                    return (
                        movieOk ? new ServerCatalogPageState(baseUrl, "movie", "top", NextSkip: 0, HasMore: true, RequestType: "movie") : null,
                        seriesOk ? new ServerCatalogPageState(baseUrl, "series", "top", NextSkip: 0, HasMore: true, RequestType: "series") : null,
                        musicOk ? new ServerCatalogPageState(baseUrl, "music", "top", NextSkip: 0, HasMore: true, RequestType: "music") : null
                    );
                }

                await using var manifestStream = await manifestResp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var manifestDoc = await JsonDocument.ParseAsync(manifestStream, cancellationToken: ct).ConfigureAwait(false);
                if (manifestDoc.RootElement.ValueKind != JsonValueKind.Object)
                {
                    var movieOk = await ProbeCatalogHasMetasAsync(baseUrl, "movie", "top", ct).ConfigureAwait(false);
                    var seriesOk = await ProbeCatalogHasMetasAsync(baseUrl, "series", "top", ct).ConfigureAwait(false);
                    var musicOk = await ProbeCatalogHasMetasAsync(baseUrl, "music", "top", ct).ConfigureAwait(false);
                    _serverCatalogSupportCache[normalizedBaseUrl] = movieOk || seriesOk || musicOk ? true : null;
                    return (
                        movieOk ? new ServerCatalogPageState(baseUrl, "movie", "top", NextSkip: 0, HasMore: true, RequestType: "movie") : null,
                        seriesOk ? new ServerCatalogPageState(baseUrl, "series", "top", NextSkip: 0, HasMore: true, RequestType: "series") : null,
                        musicOk ? new ServerCatalogPageState(baseUrl, "music", "top", NextSkip: 0, HasMore: true, RequestType: "music") : null
                    );
                }

                if (IsTorrentioLikeAddon(baseUrl, manifestDoc.RootElement))
                {
                    lock (_stateLock)
                    {
                        _serverMovieCatalogOptionsByServer[normalizedBaseUrl] = new List<ServerCatalogCatalogOption>();
                        _serverSeriesCatalogOptionsByServer[normalizedBaseUrl] = new List<ServerCatalogCatalogOption>();
                        _serverMusicCatalogOptionsByServer[normalizedBaseUrl] = new List<ServerCatalogCatalogOption>();
                    }

                    _serverCatalogSupportCache[normalizedBaseUrl] = false;
                    return (null, null, null);
                }

                var movieCatalogId = ChooseBestCatalogId(manifestDoc.RootElement, "movie");
                var seriesCatalogId = ChooseBestCatalogId(manifestDoc.RootElement, "series");
                var musicCatalogId = ChooseBestCatalogId(manifestDoc.RootElement, "music");

                var movieOptions = ParseServerCatalogOptions(manifestDoc.RootElement, "movie");
                var seriesOptions = ParseServerCatalogOptions(manifestDoc.RootElement, "series");
                var musicOptions = ParseServerCatalogOptions(manifestDoc.RootElement, "music");

                // Stremio addons may use "tv" type for live TV catalogs — merge into series
                var tvCatalogId = ChooseBestCatalogId(manifestDoc.RootElement, "tv");
                var tvOptions = ParseServerCatalogOptions(manifestDoc.RootElement, "tv");
                if (tvOptions.Count > 0)
                {
                    var existingIds = new HashSet<string>(seriesOptions.Select(o => o.Value), StringComparer.OrdinalIgnoreCase);
                    foreach (var opt in tvOptions)
                    {
                        if (!existingIds.Contains(opt.Value))
                        {
                            seriesOptions.Add(new ServerCatalogCatalogOption
                            {
                                Label = opt.Label,
                                Value = opt.Value,
                                ContentType = "series",
                                RequestType = opt.RequestType
                            });
                            existingIds.Add(opt.Value);
                        }
                    }

                    if (string.IsNullOrWhiteSpace(seriesCatalogId) && !string.IsNullOrWhiteSpace(tvCatalogId))
                        seriesCatalogId = tvCatalogId;
                }

                AtlasAI.Core.AppLogger.LogInfo($"[InitServerCatalog] {normalizedBaseUrl} movieOpts={movieOptions.Count} seriesOpts={seriesOptions.Count} musicOpts={musicOptions.Count}");

                lock (_stateLock)
                {
                    _serverMovieCatalogOptionsByServer[normalizedBaseUrl] = movieOptions;
                    _serverSeriesCatalogOptionsByServer[normalizedBaseUrl] = seriesOptions;
                    _serverMusicCatalogOptionsByServer[normalizedBaseUrl] = musicOptions;
                }

                ServerCatalogPageState? movie = null;
                {
                    var option = !string.IsNullOrWhiteSpace(movieCatalogId)
                        ? movieOptions.FirstOrDefault(o => string.Equals(o.Value, movieCatalogId, StringComparison.OrdinalIgnoreCase))
                        : null;
                    option ??= PickDefaultCatalogOption(movieOptions, "movie");
                    if (option != null && !string.IsNullOrWhiteSpace(option.Value))
                        movie = new ServerCatalogPageState(baseUrl, "movie", option.Value, NextSkip: 0, HasMore: true, RequestType: string.IsNullOrWhiteSpace(option.RequestType) ? "movie" : option.RequestType);
                    else if (!string.IsNullOrWhiteSpace(movieCatalogId))
                        movie = new ServerCatalogPageState(baseUrl, "movie", movieCatalogId!, NextSkip: 0, HasMore: true, RequestType: "movie");
                }

                ServerCatalogPageState? series = null;
                {
                    var option = !string.IsNullOrWhiteSpace(seriesCatalogId)
                        ? seriesOptions.FirstOrDefault(o => string.Equals(o.Value, seriesCatalogId, StringComparison.OrdinalIgnoreCase))
                        : null;
                    option ??= PickDefaultCatalogOption(seriesOptions, "series");
                    if (option != null && !string.IsNullOrWhiteSpace(option.Value))
                        series = new ServerCatalogPageState(baseUrl, "series", option.Value, NextSkip: 0, HasMore: true, RequestType: string.IsNullOrWhiteSpace(option.RequestType) ? "series" : option.RequestType);
                    else if (!string.IsNullOrWhiteSpace(seriesCatalogId))
                        series = new ServerCatalogPageState(baseUrl, "series", seriesCatalogId!, NextSkip: 0, HasMore: true, RequestType: "series");
                }

                ServerCatalogPageState? music = null;
                {
                    var option = !string.IsNullOrWhiteSpace(musicCatalogId)
                        ? musicOptions.FirstOrDefault(o => string.Equals(o.Value, musicCatalogId, StringComparison.OrdinalIgnoreCase))
                        : null;
                    option ??= PickDefaultCatalogOption(musicOptions, "music");
                    if (option != null && !string.IsNullOrWhiteSpace(option.Value))
                        music = new ServerCatalogPageState(baseUrl, "music", option.Value, NextSkip: 0, HasMore: true, RequestType: string.IsNullOrWhiteSpace(option.RequestType) ? "music" : option.RequestType);
                    else if (!string.IsNullOrWhiteSpace(musicCatalogId))
                        music = new ServerCatalogPageState(baseUrl, "music", musicCatalogId!, NextSkip: 0, HasMore: true, RequestType: "music");
                }

                if (movie == null)
                {
                    var ok = await ProbeCatalogHasMetasAsync(baseUrl, "movie", "top", ct).ConfigureAwait(false);
                    if (ok)
                        movie = new ServerCatalogPageState(baseUrl, "movie", "top", NextSkip: 0, HasMore: true, RequestType: "movie");
                }
                if (series == null)
                {
                    var ok = await ProbeCatalogHasMetasAsync(baseUrl, "series", "top", ct).ConfigureAwait(false);
                    if (ok)
                        series = new ServerCatalogPageState(baseUrl, "series", "top", NextSkip: 0, HasMore: true, RequestType: "series");
                }
                if (music == null)
                {
                    var ok = await ProbeCatalogHasMetasAsync(baseUrl, "music", "top", ct).ConfigureAwait(false);
                    if (ok)
                        music = new ServerCatalogPageState(baseUrl, "music", "top", NextSkip: 0, HasMore: true, RequestType: "music");
                }

                _serverCatalogSupportCache[normalizedBaseUrl] = (movie != null || series != null || music != null) ? true : false;
                return (movie, series, music);
            }
            catch (Exception ex)
            {
                AtlasAI.Core.AppLogger.LogInfo($"[InitServerCatalog] FAILED for {serverBaseUrl}: {ex.GetType().Name}: {ex.Message}");
                return (null, null, null);
            }
        }

        private static bool IsTorrentioLikeAddon(string? baseUrl, JsonElement manifestRoot)
        {
            try
            {
                var haystacks = new List<string>();

                var normalizedBaseUrl = (baseUrl ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(normalizedBaseUrl))
                    haystacks.Add(normalizedBaseUrl);

                foreach (var propertyName in new[] { "id", "name", "description", "version" })
                {
                    if (manifestRoot.TryGetProperty(propertyName, out var el) && el.ValueKind == JsonValueKind.String)
                    {
                        var text = (el.GetString() ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(text))
                            haystacks.Add(text);
                    }
                }

                return haystacks.Any(text =>
                    text.Contains("torrentio", StringComparison.OrdinalIgnoreCase) ||
                    text.Contains("torrent io", StringComparison.OrdinalIgnoreCase));
            }
            catch
            {
                return false;
            }
        }

        private async Task<bool> ProbeCatalogHasMetasAsync(string baseUrl, string contentType, string catalogId, CancellationToken ct)
        {
            try
            {
                baseUrl = (baseUrl ?? "").Trim().TrimEnd('/');
                if (string.IsNullOrWhiteSpace(baseUrl))
                    return false;

                contentType = (contentType ?? "").Trim();
                if (string.IsNullOrWhiteSpace(contentType))
                    return false;
                catalogId = (catalogId ?? "").Trim();
                if (string.IsNullOrWhiteSpace(catalogId))
                    return false;

                var url = BuildAddonEndpointUrl(baseUrl, $"/catalog/{Uri.EscapeDataString(contentType)}/{Uri.EscapeDataString(catalogId)}.json");
                if (string.IsNullOrWhiteSpace(url))
                    return false;
                        using var reqCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
                        reqCts.CancelAfter(TimeSpan.FromSeconds(4));
                using var resp = await ServerHttp.GetAsync(url, HttpCompletionOption.ResponseHeadersRead, reqCts.Token).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode)
                    return false;

                await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                return doc.RootElement.ValueKind == JsonValueKind.Object &&
                       doc.RootElement.TryGetProperty("metas", out var metasEl) &&
                       metasEl.ValueKind == JsonValueKind.Array &&
                       metasEl.GetArrayLength() > 0;
            }
            catch
            {
                return false;
            }
        }

        private static string? ChooseBestCatalogId(JsonElement manifestRoot, string desiredType)
        {
            desiredType = (desiredType ?? "").Trim();
            if (string.IsNullOrWhiteSpace(desiredType))
                return null;
            if (!manifestRoot.TryGetProperty("catalogs", out var catalogsEl) || catalogsEl.ValueKind != JsonValueKind.Array)
                return null;

            var ids = new List<string>();
            foreach (var c in catalogsEl.EnumerateArray())
            {
                if (c.ValueKind != JsonValueKind.Object) continue;
                if (!c.TryGetProperty("type", out var tEl) || tEl.ValueKind != JsonValueKind.String) continue;
                var t = (tEl.GetString() ?? "").Trim();
                if (!string.Equals(t, desiredType, StringComparison.OrdinalIgnoreCase)) continue;
                if (!c.TryGetProperty("id", out var idEl) || idEl.ValueKind != JsonValueKind.String) continue;
                var id = (idEl.GetString() ?? "").Trim();
                if (string.IsNullOrWhiteSpace(id)) continue;
                ids.Add(id);
            }

            var distinct = ids
                .Where(x => !string.IsNullOrWhiteSpace(x))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (distinct.Count == 0)
                return null;

            var ordered = distinct
                .OrderBy(x =>
                {
                    if (string.Equals(x, "top", StringComparison.OrdinalIgnoreCase)) return 0;
                    if (string.Equals(x, "popular", StringComparison.OrdinalIgnoreCase)) return 1;
                    if (string.Equals(x, "featured", StringComparison.OrdinalIgnoreCase)) return 2;
                    return 10;
                })
                .ThenBy(x => x, StringComparer.OrdinalIgnoreCase)
                .ToList();

            return ordered.FirstOrDefault();
        }

        private async Task<List<MediaItem>> LoadNextPagesForTypeAsync(
            Dictionary<string, ServerCatalogPageState> states,
            CancellationToken ct,
            string? searchQuery = null,
            bool loadAllServers = false,
            ISet<string>? excludeKeys = null)
        {
            System.Diagnostics.Debug.WriteLine($"[Search] LoadNextPagesForTypeAsync called. Query: '{searchQuery ?? "null"}', States: {states.Count}");

            if (states.Count == 0)
                return new List<MediaItem>();

            var start = DateTime.UtcNow;
            var softDeadlineMs = 4500;
            var minTarget = loadAllServers ? 96 : 48;
            var exclude = excludeKeys == null
                ? null
                : new HashSet<string>(excludeKeys.Where(x => !string.IsNullOrWhiteSpace(x)), StringComparer.OrdinalIgnoreCase);

			CancellationTokenSource? linkedCts = null;
			CancellationToken loadToken;
			try
			{
				if (loadAllServers)
				{
					loadToken = ct;
				}
				else
				{
					linkedCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
					linkedCts.CancelAfter(TimeSpan.FromMilliseconds(softDeadlineMs));
					loadToken = linkedCts.Token;
				}

            var now = DateTime.UtcNow;
			var candidatesQuery = states.Values
                .Where(s => s.HasMore && !string.IsNullOrWhiteSpace(s.BaseUrl) && !string.IsNullOrWhiteSpace(s.CatalogId))
                .Where(s =>
                {
                    if (_serverCatalogBackoffUntil.TryGetValue((s.BaseUrl ?? "").Trim(), out var until))
                        return until <= now;
                    return true;
                })
                .OrderByDescending(s => (s.BaseUrl ?? "").Contains("v3-cinemeta.strem.io", StringComparison.OrdinalIgnoreCase))
				.ThenBy(s => s.NextSkip);

            var candidates = (loadAllServers
                    ? candidatesQuery
                    : candidatesQuery.Take(Math.Clamp(states.Count, 1, 3)))
                .ToList();

            var maxParallel = 3;
            const int PerServerTimeoutSeconds = 6;

            if (candidates.Count == 0)
            {
                System.Diagnostics.Debug.WriteLine("[Search] No valid states to load from.");
					linkedCts?.Dispose();
                return new List<MediaItem>();
            }

            var all = new List<MediaItem>();
			try
			{
                var seen = exclude != null
                    ? new HashSet<string>(exclude, StringComparer.OrdinalIgnoreCase)
                    : new HashSet<string>(StringComparer.OrdinalIgnoreCase);

                // Worker-pool over candidates: keeps sampling servers until we hit target or deadline.
                var pending = new Queue<ServerCatalogPageState>(candidates);
                var inFlight = new List<Task<(List<MediaItem> items, ServerCatalogPageState updated)>>();

                Task<(List<MediaItem> items, ServerCatalogPageState updated)> Start(ServerCatalogPageState s)
                {
                    return Task.Run(async () =>
                    {
                        using var serverCts = CancellationTokenSource.CreateLinkedTokenSource(loadToken);
                        serverCts.CancelAfter(TimeSpan.FromSeconds(PerServerTimeoutSeconds));
                        System.Diagnostics.Debug.WriteLine($"[Search] Requesting page from {s.BaseUrl} (Catalog: {s.CatalogId})");
                        try
                        {
                            return await TryLoadServerCatalogPageAsync(s, serverCts.Token, searchQuery).ConfigureAwait(false);
                        }
                        catch (OperationCanceledException)
                        {
                            return (items: new List<MediaItem>(), updated: s);
                        }
                        catch
                        {
                            return (items: new List<MediaItem>(), updated: s);
                        }
                    });
                }

                while (inFlight.Count < maxParallel && pending.Count > 0 && !loadToken.IsCancellationRequested)
                    inFlight.Add(Start(pending.Dequeue()));

                while (inFlight.Count > 0 && !loadToken.IsCancellationRequested)
                {
                    var finished = await Task.WhenAny(inFlight).ConfigureAwait(false);
                    inFlight.Remove(finished);
                    var elapsed = (DateTime.UtcNow - start).TotalMilliseconds;

                    try
                    {
                        var r = await finished.ConfigureAwait(false);
                        if (!string.IsNullOrWhiteSpace(r.updated.BaseUrl))
                            states[r.updated.BaseUrl] = r.updated;
                        if (r.items.Count > 0)
                        {
                            foreach (var item in r.items)
                            {
                                if (item == null) continue;
                                var k = BuildServerCatalogDedupeKey(item);
                                if (string.IsNullOrWhiteSpace(k) || k.EndsWith("|", StringComparison.Ordinal))
                                    continue;
                                if (seen.Add(k))
                                    all.Add(item);
                            }
                        }
                    }
                    catch
                    {
                    }

                    if (all.Count >= minTarget || elapsed >= softDeadlineMs)
                        break;

                    while (inFlight.Count < maxParallel && pending.Count > 0 && !loadToken.IsCancellationRequested)
                        inFlight.Add(Start(pending.Dequeue()));
                }

                if (!loadAllServers && inFlight.Count > 0)
                {
                    try { linkedCts?.Cancel(); } catch { }
                    try { await Task.WhenAll(inFlight).ConfigureAwait(false); } catch { }
                }
			}
			finally
			{
				linkedCts?.Dispose();
			}

			System.Diagnostics.Debug.WriteLine($"[Search] LoadNextPagesForTypeAsync finished. Found {all.Count} items.");
			return all;
			}
			catch
			{
				linkedCts?.Dispose();
				return new List<MediaItem>();
			}
        }

        private async Task<(List<MediaItem> items, ServerCatalogPageState updated)> TryLoadServerCatalogPageAsync(ServerCatalogPageState state, CancellationToken ct, string? searchQuery)
        {
            try
            {
                var baseUrl = (state.BaseUrl ?? "").Trim().TrimEnd('/');
                var contentType = (state.ContentType ?? "").Trim().ToLowerInvariant();
                if (string.IsNullOrWhiteSpace(contentType))
                    contentType = "movie";

                var requestType = (state.RequestType ?? "").Trim();
                if (string.IsNullOrWhiteSpace(requestType))
                    requestType = contentType;
                var catalogId = (state.CatalogId ?? "").Trim();
                var skip = Math.Max(0, state.NextSkip);

                if (string.IsNullOrWhiteSpace(baseUrl) || string.IsNullOrWhiteSpace(catalogId))
                    return (new List<MediaItem>(), state with { HasMore = false });

                var q = (searchQuery ?? "").Trim();
                List<string> BuildCatalogUrls()
                {
                    var list = new List<string>();
                    if (skip > 0)
                    {
                        var alt = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}/skip={skip}.json");
                        if (!string.IsNullOrWhiteSpace(alt))
                            list.Add(alt);

                        var altQuery = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}.json",
                            $"skip={skip}");
                        if (!string.IsNullOrWhiteSpace(altQuery))
                            list.Add(altQuery);

						// IMPORTANT:
						// When paging (skip > 0), do not fall back to the unpaged base URL.
						// Many add-ons will still return page 1 for the base URL, which causes
						// duplicates and makes the catalog appear to "stall" around the first page.
						return list;
                    }
                    var baseCatalogUrl = BuildAddonEndpointUrl(
                        baseUrl,
                        $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}.json");
                    if (!string.IsNullOrWhiteSpace(baseCatalogUrl))
                        list.Add(baseCatalogUrl);
                    return list;
                }

                List<string> BuildSearchUrls()
                {
                    var list = new List<string>();
                    var sq = Uri.EscapeDataString(q);

                    static void AddExtraSegmentUrls(List<string> target, string baseUrl, string requestType, string catalogId, string name, string sq, int skip)
                    {
                        var extra = $"{Uri.EscapeDataString(name)}={sq}";
                        if (skip > 0)
                            extra += $"&skip={skip}";

                        var u = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}/{extra}.json");
                        if (!string.IsNullOrWhiteSpace(u))
                            target.Add(u);
                    }

                    static void AddQueryStringUrls(List<string> target, string baseUrl, string requestType, string catalogId, string name, string sq, int skip)
                    {
                        var queryParts = new List<string> { $"{Uri.EscapeDataString(name)}={sq}" };
                        if (skip > 0) queryParts.Add($"skip={skip}");
                        var u = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}.json",
                            string.Join("&", queryParts));
                        if (!string.IsNullOrWhiteSpace(u))
                            target.Add(u);
                    }

                    static void AddLegacyExtraJsonUrls(List<string> target, string baseUrl, string requestType, string catalogId, string name, string sq, int skip)
                    {
                        var u = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}/{Uri.EscapeDataString(name)}={sq}.json",
                            skip > 0 ? $"skip={skip}" : null);
                        if (!string.IsNullOrWhiteSpace(u))
                            target.Add(u);

                        if (skip > 0)
                        {
                            var u2 = BuildAddonEndpointUrl(
                                baseUrl,
                                $"/catalog/{Uri.EscapeDataString(requestType)}/{Uri.EscapeDataString(catalogId)}/{Uri.EscapeDataString(name)}={sq}/skip={skip}.json");
                            if (!string.IsNullOrWhiteSpace(u2))
                                target.Add(u2);
                        }
                    }

                    AddExtraSegmentUrls(list, baseUrl, requestType, catalogId, "search", sq, skip);
                    AddExtraSegmentUrls(list, baseUrl, requestType, catalogId, "query", sq, skip);
                    AddExtraSegmentUrls(list, baseUrl, requestType, catalogId, "q", sq, skip);

                    AddQueryStringUrls(list, baseUrl, requestType, catalogId, "search", sq, skip);
                    AddQueryStringUrls(list, baseUrl, requestType, catalogId, "query", sq, skip);
                    AddQueryStringUrls(list, baseUrl, requestType, catalogId, "q", sq, skip);

                    AddLegacyExtraJsonUrls(list, baseUrl, requestType, catalogId, "search", sq, skip);
                    AddLegacyExtraJsonUrls(list, baseUrl, requestType, catalogId, "query", sq, skip);
                    AddLegacyExtraJsonUrls(list, baseUrl, requestType, catalogId, "q", sq, skip);

                    return list;
                }

                async Task<(bool ok, int pageCount, List<MediaItem> items)> TryParseAsync(HttpResponseMessage resp)
                {
                    await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                    using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                    if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                        !doc.RootElement.TryGetProperty("metas", out var metasEl) ||
                        metasEl.ValueKind != JsonValueKind.Array)
                    {
                        return (false, 0, new List<MediaItem>());
                    }

                    var items = new List<MediaItem>();
                    foreach (var m in metasEl.EnumerateArray())
                    {
                        ct.ThrowIfCancellationRequested();
                        if (m.ValueKind != JsonValueKind.Object) continue;

                        var id = m.TryGetProperty("id", out var idEl) && idEl.ValueKind == JsonValueKind.String ? (idEl.GetString() ?? "").Trim() : "";
                        if (string.IsNullOrWhiteSpace(id) && m.TryGetProperty("id", out var idAny) && idAny.ValueKind != JsonValueKind.Null && idAny.ValueKind != JsonValueKind.Undefined)
                            id = (idAny.ToString() ?? "").Trim();

                        var name = m.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String ? (nameEl.GetString() ?? "").Trim() : "";
                        if (string.IsNullOrWhiteSpace(name) && m.TryGetProperty("title", out var titleEl) && titleEl.ValueKind == JsonValueKind.String)
                            name = (titleEl.GetString() ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(id) || string.IsNullOrWhiteSpace(name)) continue;
                        if (!ShouldIncludeServerCatalogMeta(id, name)) continue;

                        // Derive IMDb ID: prefer explicit imdb_id field, fall back to id if it looks like a tt-ID
                        var imdbId = "";
                        try
                        {
                            if (m.TryGetProperty("imdb_id", out var imdbEl) && imdbEl.ValueKind == JsonValueKind.String)
                                imdbId = (imdbEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(imdbId) && id.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                                imdbId = id;
                        }
                        catch { }

                        var poster = m.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String ? (posterEl.GetString() ?? "").Trim() : "";
                        if (!string.IsNullOrWhiteSpace(poster))
                        {
                            if (poster.StartsWith("//", StringComparison.Ordinal))
                                poster = "https:" + poster;
                            else if (!poster.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
                                     !poster.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                            {
                                var abs = BuildAddonEndpointUrl(baseUrl, poster);
                                if (!string.IsNullOrWhiteSpace(abs))
                                    poster = abs;
                            }
                        }

                        var background = m.TryGetProperty("background", out var bgEl) && bgEl.ValueKind == JsonValueKind.String ? (bgEl.GetString() ?? "").Trim() : "";
                        if (string.IsNullOrWhiteSpace(background) && m.TryGetProperty("backdrop", out var bdEl) && bdEl.ValueKind == JsonValueKind.String)
                            background = (bdEl.GetString() ?? "").Trim();
                        if (!string.IsNullOrWhiteSpace(background))
                        {
                            if (background.StartsWith("//", StringComparison.Ordinal))
                                background = "https:" + background;
                            else if (!background.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
                                     !background.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                            {
                                var abs = BuildAddonEndpointUrl(baseUrl, background);
                                if (!string.IsNullOrWhiteSpace(abs))
                                    background = abs;
                            }
                        }

                        var logo = m.TryGetProperty("logo", out var logoEl) && logoEl.ValueKind == JsonValueKind.String ? (logoEl.GetString() ?? "").Trim() : "";
                        if (!string.IsNullOrWhiteSpace(logo))
                        {
                            if (logo.StartsWith("//", StringComparison.Ordinal))
                                logo = "https:" + logo;
                            else if (!logo.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
                                     !logo.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                            {
                                var abs = BuildAddonEndpointUrl(baseUrl, logo);
                                if (!string.IsNullOrWhiteSpace(abs))
                                    logo = abs;
                            }
                        }

                        var description = m.TryGetProperty("description", out var descEl) && descEl.ValueKind == JsonValueKind.String ? (descEl.GetString() ?? "").Trim() : "";
                        if (string.IsNullOrWhiteSpace(description) && m.TryGetProperty("overview", out var ovEl) && ovEl.ValueKind == JsonValueKind.String)
                            description = (ovEl.GetString() ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(description) && m.TryGetProperty("plot", out var plEl) && plEl.ValueKind == JsonValueKind.String)
                            description = (plEl.GetString() ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(description) && m.TryGetProperty("synopsis", out var syEl) && syEl.ValueKind == JsonValueKind.String)
                            description = (syEl.GetString() ?? "").Trim();

                        var year = 0;
                        try
                        {
                            if (m.TryGetProperty("year", out var yearEl))
                            {
                                if (yearEl.ValueKind == JsonValueKind.Number && yearEl.TryGetInt32(out var y))
                                    year = y;
                                else if (yearEl.ValueKind == JsonValueKind.String && int.TryParse((yearEl.GetString() ?? "").Trim(), out var ys))
                                    year = ys;
                            }
                            if (year <= 0 && m.TryGetProperty("releaseInfo", out var relEl) && relEl.ValueKind == JsonValueKind.String)
                            {
                                var rel = (relEl.GetString() ?? "").Trim();
                                if (rel.Length >= 4 && int.TryParse(rel.Substring(0, 4), out var ry))
                                    year = ry;
                            }
                        }
                        catch
                        {
                            year = 0;
                        }

                        // Read full release date from addon catalog: `released`, `releaseDate`, `firstAired`
                        DateTime? releaseDate = null;
                        try
                        {
                            static bool TryParseReleaseDateString(string? raw, out DateTime result)
                            {
                                result = default;
                                if (string.IsNullOrWhiteSpace(raw)) return false;
                                return DateTime.TryParse(raw.Trim(),
                                    System.Globalization.CultureInfo.InvariantCulture,
                                    System.Globalization.DateTimeStyles.RoundtripKind | System.Globalization.DateTimeStyles.AllowWhiteSpaces,
                                    out result);
                            }

                            string? rdRaw = null;
                            if (m.TryGetProperty("released", out var rdEl) && rdEl.ValueKind == JsonValueKind.String)
                                rdRaw = rdEl.GetString();
                            if (rdRaw == null && m.TryGetProperty("releaseDate", out var rd2El) && rd2El.ValueKind == JsonValueKind.String)
                                rdRaw = rd2El.GetString();
                            if (rdRaw == null && m.TryGetProperty("firstAired", out var faEl) && faEl.ValueKind == JsonValueKind.String)
                                rdRaw = faEl.GetString();

                            if (TryParseReleaseDateString(rdRaw, out var parsedDate))
                            {
                                releaseDate = parsedDate.ToUniversalTime();
                                if (year <= 0)
                                    year = parsedDate.Year;
                            }
                        }
                        catch { }

                        double rating = 0;
                        try
                        {
                            if (m.TryGetProperty("imdbRating", out var rEl))
                                rating = ReadNormalizedRating(rEl);
                            if (rating <= 0 && m.TryGetProperty("rating", out var r2El))
                                rating = ReadNormalizedRating(r2El);
                        }
                        catch
                        {
                            rating = 0;
                        }

                        List<string> genres = new();
                        try
                        {
                            static void AddGenreStrings(List<string> target, JsonElement el)
                            {
                                if (el.ValueKind == JsonValueKind.Array)
                                {
                                    foreach (var g in el.EnumerateArray())
                                    {
                                        if (g.ValueKind != JsonValueKind.String) continue;
                                        var s = (g.GetString() ?? "").Trim();
                                        if (!string.IsNullOrWhiteSpace(s))
                                            target.Add(s);
                                    }
                                }
                                else if (el.ValueKind == JsonValueKind.String)
                                {
                                    var raw = (el.GetString() ?? "").Trim();
                                    if (!string.IsNullOrWhiteSpace(raw))
                                    {
                                        foreach (var part in raw.Split(new[] { ',', ';', '|' }, StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
                                        {
                                            if (!string.IsNullOrWhiteSpace(part))
                                                target.Add(part.Trim());
                                        }
                                    }
                                }
                            }

                            if (m.TryGetProperty("genres", out var genresEl))
                                AddGenreStrings(genres, genresEl);
                            else if (m.TryGetProperty("genre", out var genreEl))
                                AddGenreStrings(genres, genreEl);

                            if (genres.Count > 0)
                                genres = genres.Distinct(StringComparer.OrdinalIgnoreCase).ToList();
                        }
                        catch
                        {
                            genres.Clear();
                        }

                        var atlasType =
                            string.Equals(contentType, "series", StringComparison.OrdinalIgnoreCase) ? "tv" :
                            (string.Equals(contentType, "music", StringComparison.OrdinalIgnoreCase) ? "music" : "movies");

                        try
                        {
                            if (m.TryGetProperty("type", out var mtEl) && mtEl.ValueKind == JsonValueKind.String)
                            {
                                var mt = (mtEl.GetString() ?? "").Trim();
                                if (string.Equals(mt, "series", StringComparison.OrdinalIgnoreCase) || string.Equals(mt, "tv", StringComparison.OrdinalIgnoreCase))
                                    atlasType = "tv";
                                else if (string.Equals(mt, "movie", StringComparison.OrdinalIgnoreCase) || string.Equals(mt, "movies", StringComparison.OrdinalIgnoreCase))
                                    atlasType = "movies";
                                else if (string.Equals(mt, "music", StringComparison.OrdinalIgnoreCase))
                                    atlasType = "music";
                            }
                        }
                        catch
                        {
                        }
                        var origLang = "";
                        try
                        {
                            if (m.TryGetProperty("original_language", out var olEl2) && olEl2.ValueKind == JsonValueKind.String)
                                origLang = (olEl2.GetString() ?? "").Trim();
                            else if (m.TryGetProperty("language", out var langEl2) && langEl2.ValueKind == JsonValueKind.String)
                                origLang = (langEl2.GetString() ?? "").Trim();
                            else if (m.TryGetProperty("country", out var ctryEl) && ctryEl.ValueKind == JsonValueKind.String)
                            {
                                var ctry = (ctryEl.GetString() ?? "").Trim().ToLowerInvariant();
                                if (ctry.Length == 2) origLang = ctry;
                            }
                        }
                        catch { }

                        items.Add(new MediaItem
                        {
                            PlaybackItem = null,
							MetaId = id,
                            FilePath = id,
                            ImdbId = imdbId,
                            Title = name,
                            Metadata = description ?? "",
                            Artist = "",
                            Album = "",
                            TrackNumber = 0,
                            DiscNumber = 0,
                            Duration = TimeSpan.Zero,
                            Year = year,
                            ReleaseDate = releaseDate,
                            Rating = rating,
                            Genres = genres.Count == 0 ? Array.Empty<string>() : genres,
                            Type = atlasType,
                            OriginalLanguage = origLang,
                            AccentBrush = AccentForCategory(atlasType),
                            IconGeometry = IconForCategory(atlasType),
                            CoverUrl = string.IsNullOrWhiteSpace(poster) ? null : poster,
                            BackdropUrl = string.IsNullOrWhiteSpace(background) ? null : background,
                            LogoUrl = string.IsNullOrWhiteSpace(logo) ? null : logo,
                            CoverImage = null
                        });
                    }

                    return (true, metasEl.GetArrayLength(), items);
                }

                async Task<(List<MediaItem> items, ServerCatalogPageState updated)> TryUrlsAsync(IEnumerable<string> urls, bool filterByQuery)
                {
                    foreach (var u in urls.Distinct(StringComparer.OrdinalIgnoreCase))
                    {
                        HttpResponseMessage? resp = null;
                        try
                        {
                            using var reqCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
                            reqCts.CancelAfter(TimeSpan.FromSeconds(8));
                            resp = await ServerHttp.GetAsync(u, HttpCompletionOption.ResponseHeadersRead, reqCts.Token).ConfigureAwait(false);
                            if (!resp.IsSuccessStatusCode) continue;
                            var parsed = await TryParseAsync(resp).ConfigureAwait(false);
                        if (!parsed.ok) return (new List<MediaItem>(), state with { HasMore = false });

                        var pageCount = Math.Max(0, parsed.pageCount);
                        var nextSkip = state.NextSkip + pageCount;
                        var hasMore = pageCount > 0 && nextSkip <= 8000;
                        var items = parsed.items;
                        if (filterByQuery && !string.IsNullOrWhiteSpace(q))
                        {
                            items = items.Where(i => MatchesServerCatalogQuery(i, q)).ToList();
                            if (items.Count == 0 && parsed.items.Count > 0 && urls is ICollection<string> && ((ICollection<string>)urls).Count > 1)
                                continue;
                        }
                            _serverCatalogBackoffUntil.TryRemove(baseUrl, out _);
                        return (items, state with { NextSkip = nextSkip, HasMore = hasMore });
                        }
                        catch (OperationCanceledException)
                        {
                            var until = DateTime.UtcNow.AddSeconds(2);
                            _serverCatalogBackoffUntil[baseUrl] = until;
                            return (new List<MediaItem>(), state);
                        }
                        catch
                        {
                            var until = DateTime.UtcNow.AddSeconds(8);
                            _serverCatalogBackoffUntil[baseUrl] = until;
                            continue;
                        }
                        finally
                        {
                            resp?.Dispose();
                        }
                    }
                    return (new List<MediaItem>(), state with { HasMore = false });
                }

                if (!string.IsNullOrWhiteSpace(q))
                {
                    var searchUrls = BuildSearchUrls();
                    if (searchUrls.Count > 0)
                    {
                        var r = await TryUrlsAsync(searchUrls, filterByQuery: true).ConfigureAwait(false);
                        if (r.updated.HasMore || r.items.Count > 0)
                            return r;
                    }

                    var fallbackUrls = BuildCatalogUrls();
                    if (fallbackUrls.Count == 0)
                        return (new List<MediaItem>(), state with { HasMore = false });
                    return await TryUrlsAsync(fallbackUrls, filterByQuery: true).ConfigureAwait(false);
                }

                var catalogUrls = BuildCatalogUrls();
                if (catalogUrls.Count == 0)
                    return (new List<MediaItem>(), state with { HasMore = false });
                return await TryUrlsAsync(catalogUrls, filterByQuery: false).ConfigureAwait(false);
            }
            catch (OperationCanceledException)
            {
                return (new List<MediaItem>(), state);
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[Search] Error in TryLoadServerCatalogPageAsync for {state.BaseUrl}: {ex.Message}");
                return (new List<MediaItem>(), state with { HasMore = false });
            }
        }

        private async Task RefreshServerSeriesAsync()
        {
            if (!IsServersView || _serverSeriesRootItem == null)
                return;

            var seriesId = (_serverSeriesRootItem.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(seriesId))
                return;

            var selection = (SelectedAddonServer ?? "").Trim();
            var baseUrls = new List<string>();
            if (string.IsNullOrWhiteSpace(selection) || string.Equals(selection, AllServersOption, StringComparison.OrdinalIgnoreCase))
            {
                baseUrls = _addonServers
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Select(x => x.Trim())
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
            }
            else
            {
                baseUrls.Add(selection);
            }

            if (baseUrls.Count == 0)
            {
                _uiDispatcher.Invoke(() =>
                {
                    ClearServerSeriesState(clearRoot: false);
                    ServerSeriesStatusText = "Add a server";
                });
                return;
            }

            if (IsServerSeriesBusy)
                return;

            IsServerSeriesBusy = true;
            ServerSeriesStatusText = "Loading episodes...";
            CommandManager.InvalidateRequerySuggested();

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(25));
                var ct = cts.Token;
                var seriesCover = _serverSeriesRootItem.CoverImage;

                var semaphore = new SemaphoreSlim(3);
                var tasks = baseUrls.Select(async url =>
                {
                    await semaphore.WaitAsync(ct).ConfigureAwait(false);
                    try
                    {
                        return await TryLoadServerSeriesEpisodesFromServerAsync(url, seriesId, seriesCover, ct).ConfigureAwait(false);
                    }
                    finally
                    {
                        semaphore.Release();
                    }
                }).ToList();

                var results = await Task.WhenAll(tasks).ConfigureAwait(false);
                var all = results.SelectMany(x => x).ToList();

                List<MediaItem> deduped = all
                    .Where(e => e != null && e.DiscNumber > 0 && e.TrackNumber >= 0 && !string.IsNullOrWhiteSpace(e.FilePath))
                    .GroupBy(e => $"{e.TrackNumber}:{e.DiscNumber}", StringComparer.OrdinalIgnoreCase)
                    .Select(g => g.First())
                    .OrderBy(e => e.TrackNumber)
                    .ThenBy(e => e.DiscNumber)
                    .ToList();

                if (deduped.Count == 0)
                {
                    var fallback = await FetchCinemetaSeriesEpisodesAsync(seriesId, seriesCover, ct).ConfigureAwait(false);
                    deduped = fallback
                        .Where(e => e != null && e.DiscNumber > 0 && e.TrackNumber >= 0 && !string.IsNullOrWhiteSpace(e.FilePath))
                        .GroupBy(e => $"{e.TrackNumber}:{e.DiscNumber}", StringComparer.OrdinalIgnoreCase)
                        .Select(g => g.First())
                        .OrderBy(e => e.TrackNumber)
                        .ThenBy(e => e.DiscNumber)
                        .ToList();
                }

                var seasons = deduped
                    .Select(e => e.TrackNumber)
                    .Where(s => s >= 0)
                    .Distinct()
                    .OrderBy(s => s)
                    .ToList();

                _uiDispatcher.Invoke(() =>
                {
                    _serverSeriesEpisodes.Clear();
                    foreach (var e in deduped)
                        _serverSeriesEpisodes.Add(e);

                    _serverSeriesSeasons.Clear();
                    _serverSeriesSeasons.Add(new SeasonEntry { SeasonNumber = 0, Label = "All" });
                    foreach (var s in seasons.Where(s => s > 0))
                        _serverSeriesSeasons.Add(new SeasonEntry { SeasonNumber = s, Label = $"Season {s}" });

                    SelectedServerSeriesSeason = _serverSeriesSeasons.FirstOrDefault();

                    var seasonCount = _serverSeriesSeasons.Count > 0 ? _serverSeriesSeasons.Count - 1 : 0;
                    ServerSeriesStatusText = $"{_serverSeriesEpisodes.Count} episode(s) · {seasonCount} season(s) · {baseUrls.Count} server(s)";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    ClearServerSeriesState(clearRoot: false);
                    ServerSeriesStatusText = "Failed to load episodes";
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsServerSeriesBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private async Task<List<MediaItem>> TryLoadServerSeriesEpisodesFromServerAsync(string serverBaseUrl, string seriesId, ImageSource? seriesCover, CancellationToken ct)
        {
            try
            {
                var baseUrl = (serverBaseUrl ?? "").Trim().TrimEnd('/');
                if (string.IsNullOrWhiteSpace(baseUrl))
                    return new List<MediaItem>();

                var metaUrl = $"{baseUrl}/meta/series/{Uri.EscapeDataString(seriesId)}.json";
                using var resp = await ServerHttp.GetAsync(metaUrl, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode)
                    return new List<MediaItem>();

                await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                    !doc.RootElement.TryGetProperty("meta", out var metaEl) ||
                    metaEl.ValueKind != JsonValueKind.Object)
                {
                    return new List<MediaItem>();
                }

                if (!metaEl.TryGetProperty("videos", out var videosEl) || videosEl.ValueKind != JsonValueKind.Array)
                    return new List<MediaItem>();

                var items = new List<MediaItem>();
                var idx = 0;
                foreach (var v in videosEl.EnumerateArray())
                {
                    ct.ThrowIfCancellationRequested();
                    if (v.ValueKind != JsonValueKind.Object) continue;

                    idx++;

                    var videoId = "";
                    try
                    {
                        if (v.TryGetProperty("id", out var idEl))
                        {
                            if (idEl.ValueKind == JsonValueKind.String)
                                videoId = (idEl.GetString() ?? "").Trim();
                            else if (idEl.ValueKind != JsonValueKind.Null && idEl.ValueKind != JsonValueKind.Undefined)
                                videoId = (idEl.ToString() ?? "").Trim();
                        }
                    }
                    catch
                    {
                        videoId = "";
                    }

                    if (string.IsNullOrWhiteSpace(videoId))
                        continue;

                    var season = v.TryGetProperty("season", out var sEl) && sEl.TryGetInt32(out var sv) ? sv : 0;
                    var episode = v.TryGetProperty("episode", out var eEl) && eEl.TryGetInt32(out var ev) ? ev : 0;

                    // If the addon doesn't include explicit season/episode, try to parse from id like `tt1234567:1:2`.
                    if (episode <= 0 || season <= 0)
                    {
                        try
                        {
                            var parts = videoId.Split(':', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
                            if (parts.Length >= 3 &&
                                int.TryParse(parts[^2], out var ps) &&
                                int.TryParse(parts[^1], out var pe))
                            {
                                if (season <= 0) season = ps;
                                if (episode <= 0) episode = pe;
                            }
                        }
                        catch
                        {
                        }
                    }

                    // Final fallback for collection-style lists.
                    if (episode <= 0)
                        episode = idx;
                    if (season <= 0)
                        season = 1;

                    var name = v.TryGetProperty("title", out var tEl) && tEl.ValueKind == JsonValueKind.String ? (tEl.GetString() ?? "").Trim() : "";
                    if (string.IsNullOrWhiteSpace(name) && v.TryGetProperty("name", out var nEl) && nEl.ValueKind == JsonValueKind.String)
                        name = (nEl.GetString() ?? "").Trim();

                    var isTvEpisodeId = videoId.Contains(':');
                    var itemType = isTvEpisodeId ? "tv" : "movies";

                    string displayTitle;
                    if (isTvEpisodeId)
                    {
                        var se = $"S{Math.Max(0, season):00}E{episode:00}";
                        displayTitle = string.IsNullOrWhiteSpace(name) ? se : $"{se} · {name}";
                    }
                    else
                    {
                        displayTitle = string.IsNullOrWhiteSpace(name) ? $"{episode}." : $"{episode}. {name}";
                    }

                    items.Add(new MediaItem
                    {
                        PlaybackItem = null,
                        MetaId = videoId,
                        FilePath = videoId,
                        Title = displayTitle,
                        Artist = "",
                        Album = "",
                        TrackNumber = Math.Max(0, season),
                        DiscNumber = episode,
                        SeasonNumber = Math.Max(0, season),
                        EpisodeNumber = episode,
                        Duration = TimeSpan.Zero,
                        Type = itemType,
                        AccentBrush = AccentForCategory(itemType),
                        IconGeometry = IconForCategory(itemType),
                        CoverImage = seriesCover
                    });
                }

                return items;
            }
            catch
            {
                return new List<MediaItem>();
            }
        }

        private async Task<(List<MediaItem> movies, List<MediaItem> series)> TryLoadServerCatalogFromServerAsync(string serverBaseUrl, CancellationToken ct)
        {
            try
            {
                var baseUrl = (serverBaseUrl ?? "").Trim().TrimEnd('/');
                if (string.IsNullOrWhiteSpace(baseUrl))
                    return (new List<MediaItem>(), new List<MediaItem>());

                var manifestUrl = $"{baseUrl}/manifest.json";
                using var manifestResp = await ServerHttp.GetAsync(manifestUrl, ct).ConfigureAwait(false);
                if (!manifestResp.IsSuccessStatusCode)
                    return (new List<MediaItem>(), new List<MediaItem>());

                await using var manifestStream = await manifestResp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var manifestDoc = await JsonDocument.ParseAsync(manifestStream, cancellationToken: ct).ConfigureAwait(false);
                if (manifestDoc.RootElement.ValueKind != JsonValueKind.Object)
                    return (new List<MediaItem>(), new List<MediaItem>());

                var movieTask = LoadServerCatalogItemsAsync(baseUrl, manifestDoc.RootElement, "movie", ct);
                var seriesTask = LoadServerCatalogItemsAsync(baseUrl, manifestDoc.RootElement, "series", ct);
                await Task.WhenAll(movieTask, seriesTask).ConfigureAwait(false);

                return (movieTask.Result, seriesTask.Result);
            }
            catch
            {
                return (new List<MediaItem>(), new List<MediaItem>());
            }
        }

        private async Task<List<MediaItem>> LoadServerCatalogItemsAsync(string baseUrl, JsonElement manifestRoot, string desiredType, CancellationToken ct)
        {
            desiredType = string.Equals(desiredType, "series", StringComparison.OrdinalIgnoreCase) ? "series" : "movie";

            if (!manifestRoot.TryGetProperty("catalogs", out var catalogsEl) || catalogsEl.ValueKind != JsonValueKind.Array)
            {
                if (baseUrl.Contains("v3-cinemeta.strem.io", StringComparison.OrdinalIgnoreCase))
                    return await FetchCinemetaTopAsync(desiredType, ct).ConfigureAwait(false);
                return new List<MediaItem>();
            }

            var catalogs = new List<(string id, List<string> genreOptions)>();
            foreach (var c in catalogsEl.EnumerateArray())
            {
                if (c.ValueKind != JsonValueKind.Object) continue;
                if (!c.TryGetProperty("type", out var tEl) || tEl.ValueKind != JsonValueKind.String) continue;
                var t = (tEl.GetString() ?? "").Trim();
                if (!string.Equals(t, desiredType, StringComparison.OrdinalIgnoreCase)) continue;

                if (!c.TryGetProperty("id", out var idEl) || idEl.ValueKind != JsonValueKind.String) continue;
                var id = (idEl.GetString() ?? "").Trim();
                if (string.IsNullOrWhiteSpace(id)) continue;

                var genreOptions = new List<string>();
                if (c.TryGetProperty("extra", out var extraEl) && extraEl.ValueKind == JsonValueKind.Array)
                {
                    foreach (var ex in extraEl.EnumerateArray())
                    {
                        if (ex.ValueKind != JsonValueKind.Object) continue;
                        if (!ex.TryGetProperty("name", out var nEl) || nEl.ValueKind != JsonValueKind.String) continue;
                        var name = (nEl.GetString() ?? "").Trim();
                        if (!string.Equals(name, "genre", StringComparison.OrdinalIgnoreCase)) continue;

                        if (!ex.TryGetProperty("options", out var optEl) || optEl.ValueKind != JsonValueKind.Array) continue;
                        foreach (var o in optEl.EnumerateArray())
                        {
                            if (o.ValueKind != JsonValueKind.String) continue;
                            var opt = (o.GetString() ?? "").Trim();
                            if (!string.IsNullOrWhiteSpace(opt))
                                genreOptions.Add(opt);
                        }
                    }
                }

                catalogs.Add((id, genreOptions));
            }

            var orderedCatalogs = catalogs
                .Where(x => !string.IsNullOrWhiteSpace(x.id))
                .GroupBy(x => x.id, StringComparer.OrdinalIgnoreCase)
                .Select(g => (id: g.Key, genreOptions: g.SelectMany(x => x.genreOptions).Where(o => !string.IsNullOrWhiteSpace(o)).Distinct(StringComparer.OrdinalIgnoreCase).ToList()))
                .OrderBy(x =>
                {
                    if (string.Equals(x.id, "top", StringComparison.OrdinalIgnoreCase)) return 0;
                    if (string.Equals(x.id, "popular", StringComparison.OrdinalIgnoreCase)) return 1;
                    if (string.Equals(x.id, "featured", StringComparison.OrdinalIgnoreCase)) return 2;
                    return 10;
                })
                .ThenBy(x => x.id, StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (orderedCatalogs.Count == 0)
            {
                if (baseUrl.Contains("v3-cinemeta.strem.io", StringComparison.OrdinalIgnoreCase))
                    return await FetchCinemetaTopAsync(desiredType, ct).ConfigureAwait(false);
                return new List<MediaItem>();
            }

            const int maxItems = 600;
            var items = new List<MediaItem>();
            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            async Task<bool> TryFetchCatalogAsync(string catalogId, string? extraName, string? extraValue)
            {
                var skip = 0;
                var pagesFetched = 0;
                const int maxPagesPerCatalog = 3;
                while (skip <= 8000 && items.Count < maxItems && pagesFetched < maxPagesPerCatalog)
                {
                    var tryUrls = new List<string>();
                    if (!string.IsNullOrWhiteSpace(extraName) && !string.IsNullOrWhiteSpace(extraValue))
                    {
                        var extraSegment = $"{Uri.EscapeDataString(extraName)}={Uri.EscapeDataString(extraValue)}";
                        if (skip > 0)
                            extraSegment += $"&skip={skip}";

                        var extraUrl = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(desiredType)}/{Uri.EscapeDataString(catalogId)}/{extraSegment}.json");
                        if (!string.IsNullOrWhiteSpace(extraUrl))
                            tryUrls.Add(extraUrl);
                    }
                    else if (skip > 0)
                    {
                        var skipUrl = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(desiredType)}/{Uri.EscapeDataString(catalogId)}/skip={skip}.json");
                        if (!string.IsNullOrWhiteSpace(skipUrl))
                            tryUrls.Add(skipUrl);
                    }

                    var baseCatalogUrl = BuildAddonEndpointUrl(
                        baseUrl,
                        $"/catalog/{Uri.EscapeDataString(desiredType)}/{Uri.EscapeDataString(catalogId)}.json",
                        skip > 0 ? $"skip={skip}" : null);
                    if (!string.IsNullOrWhiteSpace(baseCatalogUrl))
                        tryUrls.Add(baseCatalogUrl);

                    if (!string.IsNullOrWhiteSpace(extraName) && !string.IsNullOrWhiteSpace(extraValue))
                    {
                        var extraPathBase = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(desiredType)}/{Uri.EscapeDataString(catalogId)}/{Uri.EscapeDataString(extraName)}={Uri.EscapeDataString(extraValue)}.json",
                            skip > 0 ? $"skip={skip}" : null);
                        if (!string.IsNullOrWhiteSpace(extraPathBase))
                            tryUrls.Add(extraPathBase);
                    }

                    if (skip > 0)
                    {
                        var skipUrl = BuildAddonEndpointUrl(
                            baseUrl,
                            $"/catalog/{Uri.EscapeDataString(desiredType)}/{Uri.EscapeDataString(catalogId)}/skip={skip}.json");
                        if (!string.IsNullOrWhiteSpace(skipUrl))
                            tryUrls.Add(skipUrl);
                    }

                    HttpResponseMessage? resp = null;
                    foreach (var u in tryUrls.Distinct(StringComparer.OrdinalIgnoreCase))
                    {
                        resp?.Dispose();
                        using var reqCts = CancellationTokenSource.CreateLinkedTokenSource(ct);
                        reqCts.CancelAfter(TimeSpan.FromSeconds(8));
                        resp = await ServerHttp.GetAsync(u, reqCts.Token).ConfigureAwait(false);
                        if (resp.IsSuccessStatusCode)
                            break;
                    }

                    if (resp == null || !resp.IsSuccessStatusCode)
                        break;

                    try
                    {
                        await using var catalogStream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                        using var catalogDoc = await JsonDocument.ParseAsync(catalogStream, cancellationToken: ct).ConfigureAwait(false);
                        if (catalogDoc.RootElement.ValueKind != JsonValueKind.Object ||
                            !catalogDoc.RootElement.TryGetProperty("metas", out var metasEl) ||
                            metasEl.ValueKind != JsonValueKind.Array)
                            break;

                        var pageCount = 0;
                        var addedThisPage = 0;
                        foreach (var m in metasEl.EnumerateArray())
                        {
                            ct.ThrowIfCancellationRequested();
                            if (m.ValueKind != JsonValueKind.Object) continue;

                            var id = m.TryGetProperty("id", out var idEl) && idEl.ValueKind == JsonValueKind.String ? (idEl.GetString() ?? "").Trim() : "";
                            if (string.IsNullOrWhiteSpace(id) && m.TryGetProperty("id", out var idAny) && idAny.ValueKind != JsonValueKind.Null && idAny.ValueKind != JsonValueKind.Undefined)
                                id = (idAny.ToString() ?? "").Trim();

                            var name = m.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String ? (nameEl.GetString() ?? "").Trim() : "";
                            if (string.IsNullOrWhiteSpace(name) && m.TryGetProperty("title", out var titleEl) && titleEl.ValueKind == JsonValueKind.String)
                                name = (titleEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(id) || string.IsNullOrWhiteSpace(name)) continue;
                            if (!ShouldIncludeServerCatalogMeta(id, name)) continue;
                            if (!seen.Add(id))
                            {
                                pageCount++;
                                continue;
                            }

                            var type = m.TryGetProperty("type", out var typeEl) && typeEl.ValueKind == JsonValueKind.String ? (typeEl.GetString() ?? "").Trim() : desiredType;
                            var poster = m.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String ? (posterEl.GetString() ?? "").Trim() : "";
                            if (!string.IsNullOrWhiteSpace(poster))
                            {
                                if (poster.StartsWith("//", StringComparison.Ordinal))
                                    poster = "https:" + poster;
                                else if (!poster.StartsWith("http://", StringComparison.OrdinalIgnoreCase) &&
                                         !poster.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                                {
                                    var abs = BuildAddonEndpointUrl(baseUrl, poster);
                                    if (!string.IsNullOrWhiteSpace(abs))
                                        poster = abs;
                                }
                            }

                            var atlasType = string.Equals(type, "series", StringComparison.OrdinalIgnoreCase) ? "tv" : "movies";

                            items.Add(new MediaItem
                            {
                                PlaybackItem = null,
								MetaId = id,
                                FilePath = id,
                                Title = name,
                                Artist = "",
                                Album = "",
                                TrackNumber = 0,
                                DiscNumber = 0,
                                Duration = TimeSpan.Zero,
                                Type = atlasType,
                                AccentBrush = AccentForCategory(atlasType),
                                IconGeometry = IconForCategory(atlasType),
                                CoverUrl = string.IsNullOrWhiteSpace(poster) ? null : poster,
                                CoverImage = null
                            });

                            pageCount++;
                            addedThisPage++;
                            if (items.Count >= maxItems)
                                break;
                        }

                        if (pageCount <= 0)
                            break;

                        skip += pageCount;
                        pagesFetched++;
                    }
                    finally
                    {
                        resp.Dispose();
                    }
                }

                return items.Count > 0;
            }

            foreach (var catalog in orderedCatalogs)
            {
                await TryFetchCatalogAsync(catalog.id, null, null).ConfigureAwait(false);

                if (items.Count < maxItems && catalog.genreOptions.Count > 0)
                {
                    foreach (var g in catalog.genreOptions.Take(12))
                    {
                        if (items.Count >= maxItems) break;
                        await TryFetchCatalogAsync(catalog.id, "genre", g).ConfigureAwait(false);
                    }
                }

                if (items.Count >= maxItems)
                    break;
            }

            if (items.Count == 0)
                return await FetchCinemetaTopAsync(desiredType, ct).ConfigureAwait(false);

            return items;
        }

        private async Task<List<MediaItem>> FetchCinemetaTopAsync(string desiredType, CancellationToken ct)
        {
            var contentType = string.Equals(desiredType, "series", StringComparison.OrdinalIgnoreCase) ? "series" : "movie";
            const int maxItems = 1000;

            try
            {
                using var manifestResp = await ServerHttp.GetAsync("https://v3-cinemeta.strem.io/manifest.json", ct).ConfigureAwait(false);
                if (manifestResp.IsSuccessStatusCode)
                {
                    await using var manifestStream = await manifestResp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                    using var manifestDoc = await JsonDocument.ParseAsync(manifestStream, cancellationToken: ct).ConfigureAwait(false);
                    if (manifestDoc.RootElement.ValueKind == JsonValueKind.Object &&
                        manifestDoc.RootElement.TryGetProperty("catalogs", out var catalogsEl) &&
                        catalogsEl.ValueKind == JsonValueKind.Array)
                    {
                        var loaded = await LoadServerCatalogItemsAsync("https://v3-cinemeta.strem.io", manifestDoc.RootElement, contentType, ct).ConfigureAwait(false);
                        if (loaded.Count > 0)
                            return loaded.Take(maxItems).ToList();
                    }
                }
            }
            catch
            {
            }

            try
            {
                var items = new List<MediaItem>();
                var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                var skip = 0;
                var pagesFetched = 0;
                const int maxPages = 3;
                while (skip <= 8000 && items.Count < maxItems && pagesFetched < maxPages)
                {
                    var url = $"https://v3-cinemeta.strem.io/catalog/{Uri.EscapeDataString(contentType)}/top.json?skip={skip}";
                    using var resp = await ServerHttp.GetAsync(url, ct).ConfigureAwait(false);
                    if (!resp.IsSuccessStatusCode)
                        break;

                    await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                    using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                    if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                        !doc.RootElement.TryGetProperty("metas", out var metasEl) ||
                        metasEl.ValueKind != JsonValueKind.Array)
                        break;

                    var pageSize = metasEl.GetArrayLength();
                    if (pageSize <= 0)
                        break;

                    var addedThisPage = 0;
                    foreach (var m in metasEl.EnumerateArray())
                    {
                        ct.ThrowIfCancellationRequested();
                        if (m.ValueKind != JsonValueKind.Object) continue;

                        var id = m.TryGetProperty("id", out var idEl) && idEl.ValueKind == JsonValueKind.String ? (idEl.GetString() ?? "").Trim() : "";
                        if (string.IsNullOrWhiteSpace(id) && m.TryGetProperty("id", out var idAny) && idAny.ValueKind != JsonValueKind.Null && idAny.ValueKind != JsonValueKind.Undefined)
                            id = (idAny.ToString() ?? "").Trim();

                        var name = m.TryGetProperty("name", out var nameEl) && nameEl.ValueKind == JsonValueKind.String ? (nameEl.GetString() ?? "").Trim() : "";
                        if (string.IsNullOrWhiteSpace(name) && m.TryGetProperty("title", out var titleEl) && titleEl.ValueKind == JsonValueKind.String)
                            name = (titleEl.GetString() ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(id) || string.IsNullOrWhiteSpace(name)) continue;
                        if (!ShouldIncludeServerCatalogMeta(id, name)) continue;
                        if (!seen.Add(id)) continue;

                        var type = m.TryGetProperty("type", out var typeEl) && typeEl.ValueKind == JsonValueKind.String ? (typeEl.GetString() ?? "").Trim() : contentType;
                        var poster = m.TryGetProperty("poster", out var posterEl) && posterEl.ValueKind == JsonValueKind.String ? (posterEl.GetString() ?? "").Trim() : "";
                        if (!string.IsNullOrWhiteSpace(poster) && poster.StartsWith("/", StringComparison.Ordinal))
                            poster = "https://v3-cinemeta.strem.io" + poster;

                        var atlasType = string.Equals(type, "series", StringComparison.OrdinalIgnoreCase) ? "tv" : "movies";
                        items.Add(new MediaItem
                        {
                            PlaybackItem = null,
							MetaId = id,
                            FilePath = id,
                            Title = name,
                            Artist = "",
                            Album = "",
                            TrackNumber = 0,
                            DiscNumber = 0,
                            Duration = TimeSpan.Zero,
                            Type = atlasType,
                            AccentBrush = AccentForCategory(atlasType),
                            IconGeometry = IconForCategory(atlasType),
                            CoverUrl = string.IsNullOrWhiteSpace(poster) ? null : poster,
                            CoverImage = null
                        });

                        addedThisPage++;
                        if (items.Count >= maxItems)
                            break;
                    }

                    if (addedThisPage <= 0)
                        break;

                    skip += pageSize;
                    pagesFetched++;
                    if (pageSize < 50)
                        break;
                }

                return items;
            }
            catch
            {
                return new List<MediaItem>();
            }
        }

        private async Task<List<MediaItem>> FetchCinemetaSeriesEpisodesAsync(string seriesId, ImageSource? seriesCover, CancellationToken ct)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(seriesId))
                    return new List<MediaItem>();

                var url = $"https://v3-cinemeta.strem.io/meta/series/{Uri.EscapeDataString(seriesId.Trim())}.json";
                using var resp = await ServerHttp.GetAsync(url, ct).ConfigureAwait(false);
                if (!resp.IsSuccessStatusCode)
                    return new List<MediaItem>();

                await using var stream = await resp.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                using var doc = await JsonDocument.ParseAsync(stream, cancellationToken: ct).ConfigureAwait(false);
                if (doc.RootElement.ValueKind != JsonValueKind.Object ||
                    !doc.RootElement.TryGetProperty("meta", out var metaEl) ||
                    metaEl.ValueKind != JsonValueKind.Object)
                {
                    return new List<MediaItem>();
                }

                if (!metaEl.TryGetProperty("videos", out var videosEl) || videosEl.ValueKind != JsonValueKind.Array)
                    return new List<MediaItem>();

                var items = new List<MediaItem>();
                foreach (var v in videosEl.EnumerateArray())
                {
                    ct.ThrowIfCancellationRequested();
                    if (v.ValueKind != JsonValueKind.Object) continue;

                    var season = v.TryGetProperty("season", out var sEl) && sEl.TryGetInt32(out var sv) ? sv : 0;
                    var episode = v.TryGetProperty("episode", out var eEl) && eEl.TryGetInt32(out var ev) ? ev : 0;
                    if (episode <= 0) continue;

                    var name = v.TryGetProperty("title", out var tEl) && tEl.ValueKind == JsonValueKind.String ? (tEl.GetString() ?? "").Trim() : "";
                    if (string.IsNullOrWhiteSpace(name) && v.TryGetProperty("name", out var nEl) && nEl.ValueKind == JsonValueKind.String)
                        name = (nEl.GetString() ?? "").Trim();

                    var se = $"S{Math.Max(0, season):00}E{episode:00}";
                    var displayTitle = string.IsNullOrWhiteSpace(name) ? se : $"{se} · {name}";
                    var primary = $"{seriesId} {se}";

                    items.Add(new MediaItem
                    {
                        PlaybackItem = null,
                        FilePath = primary,
                        Title = displayTitle,
                        Artist = "",
                        Album = "",
                        TrackNumber = Math.Max(0, season),
                        DiscNumber = episode,
                        SeasonNumber = Math.Max(0, season),
                        EpisodeNumber = episode,
                        Duration = TimeSpan.Zero,
                        Type = "tv",
                        AccentBrush = AccentForCategory("tv"),
                        IconGeometry = IconForCategory("tv"),
                        CoverImage = seriesCover
                    });
                }

                return items;
            }
            catch
            {
                return new List<MediaItem>();
            }
        }

        private async Task RefreshStreamsAsync(MediaItem item)
        {
            if (IsStreamsBusy) return;

            // Pin the target for this fetch. Everything from here until finally is
            // guaranteed to correspond to `item`, so PostStreamsState will always
            // send the correct mediaId while these streams are loading.
            _streamsTargetItem = item;
            IsStreamsBusy = true;
            StreamsStatusText = "Finding sources...";
            CommandManager.InvalidateRequerySuggested();

            _streamSources.Clear();

            try
            {
                _uiDispatcher.Invoke(RefreshAddonServers);
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(10));
                var request = BuildStreamRequest(item);
                var resolver = _streamResolver;
                var sources = await resolver.GetSourcesAsync(request, cts.Token).ConfigureAwait(false);

                _uiDispatcher.Invoke(() =>
                {
                    foreach (var s in sources)
                        _streamSources.Add(s);

                    ApplyStreamSourcesFilter();

                    var playableCount = _streamSources.Count(s => s != null && !s.IsInfoOnly && !string.IsNullOrWhiteSpace(s.UrlOrPath));
                    var infoOnlyCount = _streamSources.Count(s => s != null && (s.IsInfoOnly || string.IsNullOrWhiteSpace(s.UrlOrPath)));

                    if (playableCount == 0 && infoOnlyCount == 0)
                    {
                        StreamsStatusText = "No sources found";
                    }
                    else if (playableCount == 0)
                    {
                        StreamsStatusText = $"{infoOnlyCount} addon detail(s), no playable streams";
                    }
                    else if (infoOnlyCount == 0)
                    {
                        StreamsStatusText = $"{playableCount} playable source(s)";
                    }
                    else
                    {
                        StreamsStatusText = $"{playableCount} playable source(s), {infoOnlyCount} addon detail(s)";
                    }
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() => StreamsStatusText = "Failed to load sources");
            }
            finally
            {
                MediaItem? rerunItem = null;
                _uiDispatcher.Invoke(() =>
                {
                    IsStreamsBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                    if (_streamsRefreshRequested)
                    {
                        _streamsRefreshRequested = false;
                        if (_pendingStreamsTargetItem != null)
                        {
                            // A new item was requested while this fetch was running.
                            // Run its metadata now (we're on the UI thread) then start
                            // its fetch. _streamsTargetItem is set at the top of
                            // RefreshStreamsAsync so PostStreamsState stays correct.
                            rerunItem = _pendingStreamsTargetItem;
                            _pendingStreamsTargetItem = null;
                            try { SetPreviewItem(rerunItem); } catch { }
                            DetailsItem = rerunItem;
                            DetailsOverview = string.IsNullOrWhiteSpace(rerunItem!.Metadata) ? "Loading metadata..." : rerunItem.Metadata;
                            try { _detailsMetaCts?.Cancel(); _detailsMetaCts?.Dispose(); } catch { }
                            _detailsMetaCts = new CancellationTokenSource();
                            _ = LoadDetailsMetaAsync(rerunItem, _detailsMetaCts.Token);
                        }
                        else
                        {
                            // Legacy path: mode-change rerun with no pending item.
                            rerunItem = _streamsTargetItem;
                        }
                    }
                });
                if (rerunItem != null)
                    _ = RefreshStreamsAsync(rerunItem);
            }
        }

        private void ApplyStreamSourcesFilter()
        {
            var view = _streamSourcesView ?? CollectionViewSource.GetDefaultView(_streamSources);
            _streamSourcesView = view;
            view.Filter = StreamSourceFilter;
            try { view.Refresh(); } catch { }
            OnPropertyChanged(nameof(StreamSourcesView));
        }

        private bool StreamSourceFilter(object obj)
        {
            if (obj is not AddonSource s) return false;

            var url = (s.UrlOrPath ?? "").Trim();
            var provider = (s.ProviderName ?? "").Trim();
            var name = (s.Name ?? "").Trim();
            var quality = (s.Quality ?? "").Trim();

            var q = (StreamsSearchQuery ?? "").Trim();
            if (string.IsNullOrWhiteSpace(q)) return true;

            if (q.Length < 2)
            {
                return (!string.IsNullOrWhiteSpace(name) && name.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(provider) && provider.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(quality) && quality.Contains(q, StringComparison.OrdinalIgnoreCase)) ||
                       (!string.IsNullOrWhiteSpace(url) && url.Contains(q, StringComparison.OrdinalIgnoreCase));
            }

            var qn = NormalizeSearchText(q);
            if (string.IsNullOrWhiteSpace(qn)) return true;

            var cn = NormalizeSearchText($"{name} {provider} {quality} {url}");
            if (string.IsNullOrWhiteSpace(cn)) return false;

            var tokens = qn.Split(' ', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
            if (tokens.Length == 0) return true;

            var cnCompact = cn.Replace(" ", "");
            foreach (var tok in tokens)
            {
                if (tok.Length == 0) continue;
                if (cn.Contains(tok, StringComparison.Ordinal)) continue;
                if (tok.Length >= 4 && cnCompact.Contains(tok, StringComparison.Ordinal)) continue;
                return false;
            }

            return true;
        }

        private void RefreshAddonServers()
        {
            try
            {
                var raw = IntegrationKeyStore.GetDecrypted(AddonServersKey);
                List<string> servers;
                if (string.IsNullOrWhiteSpace(raw))
                {
                    servers = new List<string>();
                }
                else
                {
                    servers = JsonSerializer.Deserialize<List<string>>(raw) ?? new List<string>();
                }

                var normalized = servers
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Select(NormalizeAddonServerUrl)
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();
                var initialSnapshot = string.Join("|", normalized.OrderBy(s => s, StringComparer.OrdinalIgnoreCase));

                // Do not auto-merge enabled addons from addon_servers.json back into secure store.
                // User deletion must stay authoritative and should not be undone by config drift.

                // Clean the config file without stripping enabled entries that exist only in config.
                // This keeps poster/rating/source addons available even when the secure store lags.
                try
                {
                    var cfgPath = GetAddonServersConfigPath();
                    if (!string.IsNullOrWhiteSpace(cfgPath) && File.Exists(cfgPath))
                    {
                        var json = File.ReadAllText(cfgPath);
                        var items = JsonSerializer.Deserialize<List<AtlasAI.Models.AddonServerItem>>(json) ?? new List<AtlasAI.Models.AddonServerItem>();
                        var cleaned = new List<AtlasAI.Models.AddonServerItem>();
                        var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
                        foreach (var cfgItem in items)
                        {
                            var cfgUrl = (cfgItem?.Url ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(cfgUrl))
                                continue;

                            var normalizedUrl = NormalizeAddonServerUrl(cfgUrl);
                            if (string.IsNullOrWhiteSpace(normalizedUrl))
                                continue;

                            if (!seen.Add(normalizedUrl))
                                continue;

                            cfgItem.Url = normalizedUrl;
                            cleaned.Add(cfgItem);
                        }

                        var configChanged = cleaned.Count != items.Count;
                        if (!configChanged)
                        {
                            for (var index = 0; index < cleaned.Count; index++)
                            {
                                if (string.Equals(cleaned[index].Url, items[index].Url, StringComparison.OrdinalIgnoreCase))
                                    continue;
                                configChanged = true;
                                break;
                            }
                        }

                        if (configChanged)
                            File.WriteAllText(cfgPath, JsonSerializer.Serialize(cleaned, new JsonSerializerOptions { WriteIndented = true }));
                    }
                }
                catch
                {
                }

                // Keep Atlas addon server state authoritative to avoid re-adding removed addons
                // from external app storage.

                var finalSnapshot = string.Join("|", normalized.OrderBy(s => s, StringComparer.OrdinalIgnoreCase));
                if (!string.Equals(initialSnapshot, finalSnapshot, StringComparison.Ordinal))
                    SaveAddonServersToStore(normalized);

                _addonServers.Clear();
                foreach (var s in normalized)
                    _addonServers.Add(s);

                _addonServerOptions.Clear();
                _addonServerOptions.Add(AllServersOption);
                foreach (var s in _addonServers)
                    _addonServerOptions.Add(s);

                var selection = AllServersOption;
                try
                {
                    IntegrationKeyStore.SetProtected(AddonServerSelectedKey, "");
                }
                catch
                {
                }

                if (SetProperty(ref _selectedAddonServer, selection, nameof(SelectedAddonServer)))
                    CommandManager.InvalidateRequerySuggested();
            }
            catch
            {
                _addonServers.Clear();
                _addonServerOptions.Clear();
                _addonServerOptions.Add(AllServersOption);
                _addonServerOptions.Add(CinemetaServerUrl);
                if (SetProperty(ref _selectedAddonServer, AllServersOption, nameof(SelectedAddonServer)))
                    CommandManager.InvalidateRequerySuggested();
            }
            finally
            {
                OnPropertyChanged(nameof(HasAddonServers));
                var serversCategory = Categories.FirstOrDefault(c => string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase));
                if (serversCategory != null)
                    serversCategory.Count = _addonServers.Count;
            }
        }

        private string BuildAddonServersSnapshotKey()
        {
            try
            {
                var selection = (SelectedAddonServer ?? "").Trim();
                var servers = _addonServers
                    .Where(s => !string.IsNullOrWhiteSpace(s))
                    .Select(s => s.Trim())
                    .OrderBy(s => s, StringComparer.OrdinalIgnoreCase);

                return $"{selection}::{string.Join("|", servers)}";
            }
            catch
            {
                return "";
            }
        }

        private void QueueAddonServersConfigReload()
        {
            try
            {
                if (Interlocked.Exchange(ref _addonServersReloadQueued, 1) == 1)
                    return;

                _ = Task.Run(async () =>
                {
                    try
                    {
                        await Task.Delay(800).ConfigureAwait(false);
                    }
                    catch
                    {
                    }
                    finally
                    {
                        Interlocked.Exchange(ref _addonServersReloadQueued, 0);
                    }

                    try
                    {
                        _uiDispatcher.BeginInvoke(new Action(() =>
                        {
                            var before = BuildAddonServersSnapshotKey();
                            RefreshAddonServers();
                            var after = BuildAddonServersSnapshotKey();

                            if (!string.Equals(before, after, StringComparison.Ordinal))
                                _ = RefreshServerCatalogAsync();
                        }));
                    }
                    catch
                    {
                    }
                });
            }
            catch
            {
            }
        }

        private void EnsureAddonServersConfigWatcher()
        {
            try
            {
                if (_addonServersConfigWatcher != null)
                    return;

                var cfgPath = GetAddonServersConfigPath();
                if (string.IsNullOrWhiteSpace(cfgPath))
                    return;

                var dir = Path.GetDirectoryName(cfgPath);
                var file = Path.GetFileName(cfgPath);
                if (string.IsNullOrWhiteSpace(dir) || string.IsNullOrWhiteSpace(file))
                    return;

                if (!Directory.Exists(dir))
                    Directory.CreateDirectory(dir);

                var watcher = new FileSystemWatcher(dir)
                {
                    Filter = file,
                    IncludeSubdirectories = false,
                    NotifyFilter = NotifyFilters.FileName | NotifyFilters.LastWrite | NotifyFilters.CreationTime | NotifyFilters.Size,
                    EnableRaisingEvents = true
                };

                FileSystemEventHandler changed = (_, _) => QueueAddonServersConfigReload();
                RenamedEventHandler renamed = (_, _) => QueueAddonServersConfigReload();

                watcher.Changed += changed;
                watcher.Created += changed;
                watcher.Deleted += changed;
                watcher.Renamed += renamed;

                _addonServersConfigWatcher = watcher;
            }
            catch
            {
            }
        }

        public void ReloadAddonServersFromStore()
        {
            try
            {
                var before = BuildAddonServersSnapshotKey();
                RefreshAddonServers();
                var after = BuildAddonServersSnapshotKey();

                if (!string.Equals(before, after, StringComparison.Ordinal))
                {
                    _ = RefreshServerCatalogAsync();
                }
            }
            catch
            {
            }
        }

        private static IEnumerable<string> ExtractStremioManifestUrls()
        {
            var ldbDir = Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                @"Programs\Stremio\stremio-shell-ng.exe.WebView2\EBWebView\Default\Local Storage\leveldb");
            if (!Directory.Exists(ldbDir))
                yield break;

            var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            var files = Directory.EnumerateFiles(ldbDir, "*.ldb")
                .Concat(Directory.EnumerateFiles(ldbDir, "*.log"));

            foreach (var file in files)
            {
                byte[] bytes;
                try { bytes = File.ReadAllBytes(file); } catch { continue; }
                var text = System.Text.Encoding.UTF8.GetString(bytes);
                foreach (Match m in Regex.Matches(text, @"https://[^\x00-\x1F\s""'<>\\]{10,}/manifest\.json"))
                {
                    var baseUrl = m.Value.Substring(0, m.Value.Length - "/manifest.json".Length);
                    if (seen.Add(baseUrl))
                        yield return baseUrl;
                }
            }
        }

        private static string NormalizeAddonServerUrl(string input)
        {
            var s = (input ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s))
                return "";

            s = s.Trim();
            while (s.Length >= 2)
            {
                var first = s[0];
                var last = s[^1];
                if ((first == '"' && last == '"') || (first == '\'' && last == '\'') || (first == '`' && last == '`') || (first == '<' && last == '>'))
                {
                    s = s.Substring(1, s.Length - 2).Trim();
                    continue;
                }
                break;
            }

            s = s.TrimEnd('/');

            if (!Uri.TryCreate(s, UriKind.Absolute, out var uri))
            {
                if (!Uri.TryCreate("http://" + s, UriKind.Absolute, out uri))
                    return "";
            }

            if (!string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
                return "";

            var rawPath = (uri.AbsolutePath ?? "").Trim();
            if (Regex.IsMatch(rawPath, @"(?i)\.(png|jpe?g|webp|gif|svg)$") ||
                rawPath.Contains("/poster/", StringComparison.OrdinalIgnoreCase))
                return "";

            var builder = new UriBuilder(uri) { Fragment = "" };
            if (builder.Path.EndsWith("/manifest.json", StringComparison.OrdinalIgnoreCase))
                builder.Path = builder.Path.Substring(0, builder.Path.Length - "/manifest.json".Length).TrimEnd('/');

            return builder.Uri.ToString().TrimEnd('/');
        }

        private static string BuildAddonEndpointUrl(string baseUrl, string endpointPath, string? extraQuery = null)
        {
            try
            {
                baseUrl = (baseUrl ?? "").Trim();
                endpointPath = (endpointPath ?? "").Trim();
                extraQuery = (extraQuery ?? "").Trim().TrimStart('?');

                if (string.IsNullOrWhiteSpace(baseUrl) || string.IsNullOrWhiteSpace(endpointPath))
                    return "";

                var normalized = NormalizeAddonServerUrl(baseUrl);
                if (!Uri.TryCreate(normalized, UriKind.Absolute, out var uri))
                    return "";

                var builder = new UriBuilder(uri) { Fragment = "" };

                var basePath = (builder.Path ?? "").Trim();
                if (basePath.EndsWith("/manifest.json", StringComparison.OrdinalIgnoreCase))
                    basePath = basePath.Substring(0, basePath.Length - "/manifest.json".Length);
                basePath = basePath.TrimEnd('/');
                if (string.Equals(basePath, "/", StringComparison.Ordinal))
                    basePath = "";

                if (!endpointPath.StartsWith("/", StringComparison.Ordinal))
                    endpointPath = "/" + endpointPath;

                builder.Path = string.IsNullOrWhiteSpace(basePath) ? endpointPath : basePath + endpointPath;

                var existingQuery = (builder.Query ?? "").TrimStart('?').Trim();
                var combinedQuery = string.IsNullOrWhiteSpace(existingQuery)
                    ? extraQuery
                    : (string.IsNullOrWhiteSpace(extraQuery) ? existingQuery : existingQuery + "&" + extraQuery);

                builder.Query = combinedQuery ?? "";
                return builder.Uri.ToString();
            }
            catch
            {
                return "";
            }
        }

        private void PlayStreamSource(AddonSource? source)
        {
            if (_streamsTargetItem == null) return;
            if (source == null) return;
            if (IsStreamsBusy) return;

            if (string.Equals(_streamsTargetItem.Type, "tv", StringComparison.OrdinalIgnoreCase))
                _lastPlayedSeriesEpisode = _streamsTargetItem;
            _ = PlayStreamSourceAsync(_streamsTargetItem, source);
        }

        /// <summary>
        /// Bridge-initiated playback — bypasses the IsStreamsBusy guard so the user
        /// can play a stream immediately even while additional sources are still loading.
        /// </summary>
        public void PlayStreamSourceFromBridge(AddonSource? source)
        {
            if (source == null || source.IsInfoOnly || string.IsNullOrWhiteSpace(source.UrlOrPath))
            {
                AtlasAI.Core.AppLogger.LogInfo($"[BridgePlay] skipped: source={source?.SourceId ?? "null"} isInfoOnly={source?.IsInfoOnly} url={source?.UrlOrPath ?? "null"}");
                return;
            }
            var item = _streamsTargetItem;
            if (item == null)
            {
                AtlasAI.Core.AppLogger.LogInfo("[BridgePlay] skipped: _streamsTargetItem is null");
                return;
            }
            AtlasAI.Core.AppLogger.LogInfo($"[BridgePlay] starting: source={source.SourceId} item={item.Title}");
            if (string.Equals(item.Type, "tv", StringComparison.OrdinalIgnoreCase))
                _lastPlayedSeriesEpisode = item;
            _ = PlayStreamSourceAsync(item, source);
        }

        private void DownloadStreamSource(AddonSource? source)
        {
            if (_streamsTargetItem == null) return;
            if (source == null) return;
            if (IsStreamsBusy) return;

            _ = DownloadStreamSourceAsync(_streamsTargetItem, source);
        }

        private async Task DownloadStreamSourceAsync(MediaItem item, AddonSource source)
        {
            EnsureCloudProvidersLoaded();

            _uiDispatcher.Invoke(() =>
            {
                IsStreamsBusy = true;
                StreamsStatusText = "Resolving download...";
                IsStreamsDownloading = false;
                StreamsDownloadProgress = 0;
                CommandManager.InvalidateRequerySuggested();
            });

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45));
                var request = BuildStreamRequest(item);
                ICloudProvider? provider = null;
                Func<string, CancellationToken, Task<UnrestrictResult>>? unrestrict = null;

                if (source.RequiresDebrid)
                {
                    provider = _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                               ?? SelectedCloudProvider
                               ?? _cloudProviders.FirstOrDefault();

                    if (provider == null || !provider.IsConfigured)
                        throw new InvalidOperationException("Real-Debrid is not configured");

                    unrestrict = async (url, ct) =>
                    {
                        var r = await provider.UnrestrictAsync(url, ct).ConfigureAwait(false);
                        return new UnrestrictResult(r.Success, r.Success ? r.StreamUrl : null, r.Error);
                    };
                }

                var plan = await _streamResolver.ResolveAsync(request, source, unrestrict, cts.Token).ConfigureAwait(false);
                var urlOrPath = plan.PlayUrlOrPath;

                if (!source.RequiresDebrid && IsMagnetUrl(urlOrPath))
                {
                    provider ??= _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                                 ?? SelectedCloudProvider
                                 ?? _cloudProviders.FirstOrDefault();
                    if (provider == null || !provider.IsConfigured)
                        throw new InvalidOperationException("Real-Debrid is not configured");

                    var r = await provider.UnrestrictAsync(urlOrPath, cts.Token).ConfigureAwait(false);
                    if (!r.Success || string.IsNullOrWhiteSpace(r.StreamUrl))
                        throw new InvalidOperationException(string.IsNullOrWhiteSpace(r.Error) ? "Unrestrict failed" : r.Error);
                    urlOrPath = r.StreamUrl;
                }
                else if (!source.RequiresDebrid && plan.IsHttp)
                {
                    provider ??= _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                                 ?? SelectedCloudProvider
                                 ?? _cloudProviders.FirstOrDefault();

                    if (provider != null && provider.IsConfigured)
                    {
                        try
                        {
                            var r = await provider.UnrestrictAsync(urlOrPath, cts.Token).ConfigureAwait(false);
                            if (r.Success && !string.IsNullOrWhiteSpace(r.StreamUrl))
                                urlOrPath = r.StreamUrl;
                        }
                        catch
                        {
                        }
                    }
                }

                if (IsLikelyAddonNavigationUrl(urlOrPath))
                    throw new InvalidOperationException("No playable download stream returned by addon");

                var folder = EnsureMediaDownloadsFolderSelected(forcePrompt: false);
                if (string.IsNullOrWhiteSpace(folder))
                {
                    _uiDispatcher.Invoke(() => StreamsStatusText = "Choose a download folder first");
                    return;
                }

                if (!IsHttpUrl(urlOrPath, out var uri))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        try { System.Windows.Clipboard.SetText(urlOrPath); } catch { }
                        try { Process.Start(new ProcessStartInfo(urlOrPath) { UseShellExecute = true }); } catch { }
                        StreamsStatusText = "Opened download link";
                    });
                    return;
                }

                var title = $"{item.Title} {source.ProviderName} {source.Quality}".Trim();
                var destPath = BuildUniqueDownloadPath(folder, item, uri, urlOrPath, title, IsM3u8Url(urlOrPath) ? ".mp4" : null);

                _uiDispatcher.Invoke(() =>
                {
                    IsStreamsDownloading = true;
                    IsStreamsDownloadIndeterminate = IsM3u8Url(urlOrPath);
                    StreamsDownloadProgress = 0;
                    item.IsDownloading = true;
                    item.DownloadProgress = 0;
                    item.DownloadStatus = "Downloading...";
                    StreamsStatusText = "Downloading...";
                    CommandManager.InvalidateRequerySuggested();
                });

                if (IsM3u8Url(urlOrPath))
                {
                    await DownloadViaFfmpegAsync(urlOrPath, destPath, indeterminate: () =>
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StreamsStatusText = "Downloading...";
                            item.DownloadStatus = "Downloading...";
                        });
                    }, cts.Token).ConfigureAwait(false);
                }
                else
                {
                    await DownloadHttpToFileAsync(uri, destPath, p =>
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StreamsDownloadProgress = p;
                            item.DownloadProgress = p;
                            StreamsStatusText = $"Downloading {StreamsDownloadPercentText}";
                            item.DownloadStatus = $"Downloading {item.DownloadPercentText}";
                        });
                    }, cts.Token).ConfigureAwait(false);
                }

                _uiDispatcher.Invoke(() =>
                {
                    StreamsDownloadProgress = 1;
                    IsStreamsDownloadIndeterminate = false;
                    item.DownloadProgress = 1;
                    item.DownloadStatus = "Complete";
                    StreamsStatusText = $"Downloaded · {Path.GetFileName(destPath)}";
                    OnPropertyChanged(nameof(TrendingValue));
                });
            }
            catch (Exception ex)
            {
                _uiDispatcher.Invoke(() => StreamsStatusText = string.IsNullOrWhiteSpace(ex.Message) ? "Resolve failed" : ex.Message);
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsStreamsDownloading = false;
                    IsStreamsDownloadIndeterminate = false;
                    IsStreamsBusy = false;
                    try
                    {
                        if (item != null) item.IsDownloading = false;
                    }
                    catch
                    {
                    }
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private void CopyStreamSourceLink(AddonSource? source)
        {
            if (source == null) return;
            var url = (source.UrlOrPath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(url)) return;
            try { System.Windows.Clipboard.SetText(url); } catch { }
            StreamsStatusText = "Copied link";
            OnPropertyChanged(nameof(TrendingValue));
        }

        private async Task PlayStreamSourceAsync(MediaItem item, AddonSource source)
        {
            EnsureCloudProvidersLoaded();

            _uiDispatcher.Invoke(() =>
            {
                IsStreamsBusy = true;
                StreamsStatusText = "Resolving...";
                CommandManager.InvalidateRequerySuggested();
            });

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45));
                var request = BuildStreamRequest(item);
                ICloudProvider? provider = null;
                Func<string, CancellationToken, Task<UnrestrictResult>>? unrestrict = null;

                if (source.RequiresDebrid)
                {
                    provider = _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                               ?? SelectedCloudProvider
                               ?? _cloudProviders.FirstOrDefault();

                    if (provider != null && provider.IsConfigured)
                    {
                        unrestrict = async (url, ct) =>
                        {
                            var r = await provider.UnrestrictAsync(url, ct).ConfigureAwait(false);
                            return new UnrestrictResult(r.Success, r.Success ? r.StreamUrl : null, r.Error);
                        };
                    }
                    // If no Atlas debrid provider configured, ResolveAsync will handle the fallback
                }

                AtlasAI.Core.AppLogger.LogInfo($"[BridgePlay] pre-resolve sourceUrl={source.UrlOrPath?.Substring(0, Math.Min(80, source.UrlOrPath?.Length ?? 0))} requiresDebrid={source.RequiresDebrid}");
                var plan = await _streamResolver.ResolveAsync(request, source, unrestrict, cts.Token).ConfigureAwait(false);
                var playUrlOrPath = plan.PlayUrlOrPath;
                AtlasAI.Core.AppLogger.LogInfo($"[BridgePlay] post-resolve url={playUrlOrPath?.Substring(0, Math.Min(120, playUrlOrPath?.Length ?? 0))} isHttp={plan.IsHttp}");

                if (!source.RequiresDebrid && IsMagnetUrl(playUrlOrPath))
                {
                    provider ??= _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                                 ?? SelectedCloudProvider
                                 ?? _cloudProviders.FirstOrDefault();
                    if (provider == null || !provider.IsConfigured)
                        throw new InvalidOperationException("Real-Debrid is not configured");

                    var r = await provider.UnrestrictAsync(playUrlOrPath, cts.Token).ConfigureAwait(false);
                    if (!r.Success || string.IsNullOrWhiteSpace(r.StreamUrl))
                        throw new InvalidOperationException(string.IsNullOrWhiteSpace(r.Error) ? "Unrestrict failed" : r.Error);

                    playUrlOrPath = r.StreamUrl;
                }
                else if (!source.RequiresDebrid && plan.IsHttp)
                {
                    provider ??= _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                                 ?? SelectedCloudProvider
                                 ?? _cloudProviders.FirstOrDefault();

                    if (provider != null && provider.IsConfigured)
                    {
                        try
                        {
                            var r = await provider.UnrestrictAsync(playUrlOrPath, cts.Token).ConfigureAwait(false);
                            if (r.Success && !string.IsNullOrWhiteSpace(r.StreamUrl))
                                playUrlOrPath = r.StreamUrl;
                        }
                        catch (Exception ex)
                        {
                            System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] PlayStreamSourceAsync provider.UnrestrictAsync catch: {ex.Message}\n{ex.StackTrace}");
                        }
                    }
                }

                AtlasAI.Core.AppLogger.LogInfo($"[BridgePlay] pre-navcheck url={playUrlOrPath?.Substring(0, Math.Min(120, playUrlOrPath?.Length ?? 0))}");
                System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] after pre-navcheck url={playUrlOrPath}");
                if (IsLikelyAddonNavigationUrl(playUrlOrPath))
                    throw new InvalidOperationException("No playable stream returned by addon - url was: " + (playUrlOrPath?.Substring(0, Math.Min(120, playUrlOrPath?.Length ?? 0))));

                var displayName = string.IsNullOrWhiteSpace(source.Name) ? item.Title : source.Name;
                System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] before _uiDispatcher.Invoke playUrlOrPath={playUrlOrPath} displayName={displayName}");
                _uiDispatcher.Invoke(() =>
                {
                    System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] inside _uiDispatcher.Invoke start playUrlOrPath={playUrlOrPath}");
                    // Close streams panel first so it doesn't appear behind the player
                    if (IsStreamsOpen)
                        IsStreamsOpen = false;
                    EnsureVideoPlayerWindow();
                    SetPendingWatchHistoryForStream(item);
                    System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] before PlayStreamUrl url={playUrlOrPath} title={displayName}");
                    PlayStreamUrl(playUrlOrPath, displayName);
                    System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] after PlayStreamUrl url={playUrlOrPath} title={displayName}");
                    if (string.Equals(item.Type, "tv", StringComparison.OrdinalIgnoreCase))
                        _lastPlayedSeriesEpisode = item;
                    StreamsStatusText = "Playing";
                });
            }
            catch (Exception ex)
            {
                AtlasAI.Core.AppLogger.LogError($"[BridgePlay] FAILED: {ex.GetType().Name}: {ex.Message}");
                System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] PlayStreamSourceAsync catch: {ex.Message}\n{ex.StackTrace}");
                System.Diagnostics.Debug.WriteLine("[BridgePlayTrace] before _uiDispatcher.Invoke in PlayStreamSourceAsync catch");
                _uiDispatcher.Invoke(() =>
                {
                    System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] inside _uiDispatcher.Invoke catch setting status: {ex.Message}");
                    StreamsStatusText = string.IsNullOrWhiteSpace(ex.Message) ? "Resolve failed" : ex.Message;
                });
            }
            finally
            {
                System.Diagnostics.Debug.WriteLine("[BridgePlayTrace] before _uiDispatcher.Invoke in PlayStreamSourceAsync finally");
                _uiDispatcher.Invoke(() =>
                {
                    IsStreamsBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        public void AutoPlayNextEpisode()
        {
            try
            {
                var current = _lastPlayedSeriesEpisode;
                if (current == null) return;
                var seriesToken = (current.FilePath ?? "").Trim();
                if (string.IsNullOrWhiteSpace(seriesToken)) return;
                var parts = seriesToken.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries);
                if (parts.Length == 0) return;
                var seriesId = parts[0];
                var season = current.SeasonNumber > 0 ? current.SeasonNumber : Math.Max(0, current.TrackNumber);
                var episode = current.EpisodeNumber > 0 ? current.EpisodeNumber : Math.Max(0, current.DiscNumber);
                if (episode <= 0) return;
                List<MediaItem> episodes;
                lock (_stateLock)
                {
                    episodes = _serverSeriesEpisodes
                        .Where(e => e != null &&
                                    !string.IsNullOrWhiteSpace(e.FilePath) &&
                                    e.FilePath!.StartsWith(seriesId, StringComparison.OrdinalIgnoreCase))
                        .Where(e => !e.IsWatched)
                        .OrderBy(e => e.TrackNumber)
                        .ThenBy(e => e.DiscNumber)
                        .ToList();
                }
                if (episodes.Count == 0) return;
                var idx = episodes.FindIndex(e => Math.Max(0, e.TrackNumber) == Math.Max(0, season) &&
                                                  Math.Max(0, e.DiscNumber) == Math.Max(0, episode));
                var nextIdx = idx >= 0 ? idx + 1 : -1;
                if (nextIdx < 0 || nextIdx >= episodes.Count) return;
                var next = episodes[nextIdx];
                _ = PlayBestStreamForItemAsync(next);
            }
            catch
            {
            }
        }

        public void MarkLastEpisodeWatched()
        {
            try
            {
                var current = _lastPlayedSeriesEpisode;
                if (current == null) return;
                current.IsWatched = true;
            }
            catch
            {
            }
        }

        private async Task PlayBestStreamForItemAsync(MediaItem item)
        {
            EnsureCloudProvidersLoaded();
            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45));
                var request = BuildStreamRequest(item);
                var resolver = _streamResolver;
                var sources = await resolver.GetSourcesAsync(request, cts.Token).ConfigureAwait(false);
                var best = sources.FirstOrDefault(s => s != null && !s.IsInfoOnly && !string.IsNullOrWhiteSpace(s.UrlOrPath));
                if (best == null) return;
                ICloudProvider? provider = null;
                Func<string, CancellationToken, Task<UnrestrictResult>>? unrestrict = null;
                if (best.RequiresDebrid)
                {
                    provider = _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                               ?? SelectedCloudProvider
                               ?? _cloudProviders.FirstOrDefault();
                    if (provider == null || !provider.IsConfigured) return;
                    unrestrict = async (url, ct) =>
                    {
                        var r = await provider.UnrestrictAsync(url, ct).ConfigureAwait(false);
                        return new UnrestrictResult(r.Success, r.Success ? r.StreamUrl : null, r.Error);
                    };
                }
                var plan = await resolver.ResolveAsync(request, best, unrestrict, cts.Token).ConfigureAwait(false);
                var playUrlOrPath = plan.PlayUrlOrPath;
                if (!best.RequiresDebrid && IsMagnetUrl(playUrlOrPath))
                {
                    provider ??= _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                                 ?? SelectedCloudProvider
                                 ?? _cloudProviders.FirstOrDefault();
                    if (provider == null || !provider.IsConfigured) return;
                    var r = await provider.UnrestrictAsync(playUrlOrPath, cts.Token).ConfigureAwait(false);
                    if (!r.Success || string.IsNullOrWhiteSpace(r.StreamUrl)) return;
                    playUrlOrPath = r.StreamUrl;
                }
                else if (!best.RequiresDebrid && plan.IsHttp)
                {
                    provider ??= _cloudProviders.FirstOrDefault(p => string.Equals(p.Id, "realdebrid", StringComparison.OrdinalIgnoreCase))
                                 ?? SelectedCloudProvider
                                 ?? _cloudProviders.FirstOrDefault();
                    if (provider != null && provider.IsConfigured)
                    {
                        try
                        {
                            var r = await provider.UnrestrictAsync(playUrlOrPath, cts.Token).ConfigureAwait(false);
                            if (r.Success && !string.IsNullOrWhiteSpace(r.StreamUrl))
                                playUrlOrPath = r.StreamUrl;
                        }
                        catch
                        {
                        }
                    }
                }
                _uiDispatcher.Invoke(() =>
                {
                    SetPendingWatchHistoryForStream(item);
                    PlayStreamUrl(playUrlOrPath, string.IsNullOrWhiteSpace(item.Title) ? "Episode" : item.Title);
                    _lastPlayedSeriesEpisode = item;
                });
            }
            catch
            {
            }
        }

        private void SetPendingWatchHistoryForStream(MediaItem item)
        {
            try
            {
                if (item == null) return;

                var key = (item.MetaId ?? "").Trim();
                if (string.IsNullOrWhiteSpace(key))
                {
                    var fp = (item.FilePath ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(fp))
                    {
                        var token = fp.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries).FirstOrDefault() ?? fp;
                        token = token.Trim();
                        if (LooksLikeStableMediaIdToken(token))
                            key = token;
                    }
                }

                if (string.IsNullOrWhiteSpace(key)) return;
                _pendingWatchHistory = new PendingWatchHistory(
                    key,
                    (item.Title ?? "").Trim(),
                    (item.Type ?? "").Trim(),
                    string.IsNullOrWhiteSpace(item.CoverUrl) ? null : item.CoverUrl,
                    string.IsNullOrWhiteSpace(item.BackdropUrl) ? null : item.BackdropUrl);
            }
            catch
            {
            }
        }

        private static bool LooksLikeStableMediaIdToken(string token)
        {
            try
            {
                var t = (token ?? "").Trim();
                if (string.IsNullOrWhiteSpace(t)) return false;
                if (t.Contains('\\') || t.Contains('/')) return false;

                if (t.StartsWith("tt", StringComparison.OrdinalIgnoreCase))
                {
                    if (t.Length >= 3 && char.IsDigit(t[2])) return true;
                    return false;
                }

                if (t.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase)) return true;
                if (t.StartsWith("imdb:", StringComparison.OrdinalIgnoreCase)) return true;
                if (t.StartsWith("tvdb:", StringComparison.OrdinalIgnoreCase)) return true;

                return false;
            }
            catch
            {
                return false;
            }
        }
        private static string ExtractStableMediaIdToken(string raw)
        {
            try
            {
                var value = (raw ?? "").Trim();
                if (string.IsNullOrWhiteSpace(value)) return "";

                var token = value.Split(new[] { ' ' }, StringSplitOptions.RemoveEmptyEntries).FirstOrDefault() ?? value;
                token = (token ?? "").Trim();
                if (string.IsNullOrWhiteSpace(token)) return "";

                return LooksLikeStableMediaIdToken(token) ? token : "";
            }
            catch
            {
                return "";
            }
        }

        private static List<string> BuildSeriesLookupIds(MediaItem item)
        {
            var ids = new List<string>();

            void Add(string? value)
            {
                var candidate = (value ?? "").Trim();
                if (string.IsNullOrWhiteSpace(candidate)) return;
                if (ids.Contains(candidate, StringComparer.OrdinalIgnoreCase)) return;
                ids.Add(candidate);
            }

            var stableMetaId = ExtractStableMediaIdToken(item.MetaId ?? "");
            var stableImdbId = ExtractStableMediaIdToken(item.ImdbId ?? "");
            var stableFilePath = ExtractStableMediaIdToken(item.FilePath ?? "");

            Add(stableMetaId);
            Add(stableImdbId);
            Add(stableFilePath);

            if (item.TmdbId.HasValue && item.TmdbId.Value > 0)
            {
                Add($"tmdb:tv:{item.TmdbId.Value}");
                Add($"tmdb:series:{item.TmdbId.Value}");
                Add($"tmdb:{item.TmdbId.Value}");
            }

            Add(item.MetaId);
            Add(item.ImdbId);
            Add(item.FilePath);

            return ids;
        }

        private static MediaRequest BuildStreamRequest(MediaItem item)
        {
            var title = (item.Title ?? "").Trim();
            if (string.IsNullOrWhiteSpace(title) || string.Equals(title, "Unknown", StringComparison.OrdinalIgnoreCase))
            {
                title = CleanVideoTitleFromFileName(item.FilePath ?? "", out _);
            }
            else if (LooksLikeRawServerCatalogTitle(title))
            {
                var cleanedTitle = CleanLookupTitleForMeta(title, out _);
                if (!string.IsNullOrWhiteSpace(cleanedTitle))
                    title = cleanedTitle;
            }

            if (string.IsNullOrWhiteSpace(title))
                title = "Unknown";

            var rawCategory = string.IsNullOrWhiteSpace(item.Type) ? "unknown" : item.Type;
            var category = rawCategory;
            if (string.Equals(rawCategory, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(rawCategory, "movie", StringComparison.OrdinalIgnoreCase))
                category = "movie";
            else if (string.Equals(rawCategory, "tv", StringComparison.OrdinalIgnoreCase) || string.Equals(rawCategory, "series", StringComparison.OrdinalIgnoreCase))
                category = "tv";

            var id = (item.MetaId ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id))
                id = (item.ImdbId ?? "").Trim();
            if (string.IsNullOrWhiteSpace(id))
            {
                var fp = (item.FilePath ?? "").Trim();
                if (!string.IsNullOrWhiteSpace(fp) &&
                    (fp.StartsWith("tt", StringComparison.OrdinalIgnoreCase) || fp.StartsWith("tmdb:", StringComparison.OrdinalIgnoreCase)) &&
                    !fp.Contains('\\') && !fp.Contains('/'))
                    id = fp;
            }

            string? primary;
            if (!string.IsNullOrWhiteSpace(id))
            {
                primary = id;
            }
            else
            {
                var fp = (item.FilePath ?? "").Trim();
                if (string.IsNullOrWhiteSpace(fp))
                {
                    primary = null;
                }
                else if (File.Exists(fp) || fp.StartsWith("http://", StringComparison.OrdinalIgnoreCase) || fp.StartsWith("https://", StringComparison.OrdinalIgnoreCase))
                {
                    primary = fp;
                }
                else
                {
                    primary = null;
                }
            }

            return new MediaRequest(title, category, primary);
        }

        private async void TestCloudProvider()
        {
            if (IsCloudBusy) return;
            var provider = SelectedCloudProvider ?? _cloudProviders.FirstOrDefault();
            if (provider == null)
            {
                CloudStatusText = "No providers installed";
                return;
            }

            IsCloudBusy = true;
            CommandManager.InvalidateRequerySuggested();
            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(20));
                var ok = await provider.ValidateAsync(cts.Token).ConfigureAwait(false);
                _uiDispatcher.Invoke(() =>
                {
                    CloudStatusText = ok ? "Provider validated" : "Provider not configured or invalid";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() => CloudStatusText = "Validation failed");
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsCloudBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private async void AddAndStreamCloudLink()
        {
            if (IsCloudBusy) return;
            var url = (CloudLinkUrl ?? "").Trim();
            if (string.IsNullOrWhiteSpace(url))
            {
                CloudStatusText = "URL is required";
                return;
            }

            var provider = SelectedCloudProvider ?? _cloudProviders.FirstOrDefault();
            if (provider == null)
            {
                CloudStatusText = "No providers installed";
                return;
            }

            IsCloudBusy = true;
            CloudStatusText = "Unrestricting...";
            CommandManager.InvalidateRequerySuggested();
            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45));
                var result = await provider.UnrestrictAsync(url, cts.Token).ConfigureAwait(false);
                if (!result.Success || string.IsNullOrWhiteSpace(result.StreamUrl))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        CloudStatusText = string.IsNullOrWhiteSpace(result.Error) ? "Unrestrict failed" : result.Error!;
                    });
                    return;
                }

                var title = (CloudLinkTitle ?? "").Trim();
                if (string.IsNullOrWhiteSpace(title))
                    title = string.IsNullOrWhiteSpace(result.Filename) ? "Cloud Link" : result.Filename!;

                MediaItem newItem = new()
                {
                    PlaybackItem = null,
                    FilePath = url,
                    Title = title,
                    Artist = provider.DisplayName,
                    Album = "",
                    TrackNumber = 0,
                    DiscNumber = 0,
                    Duration = TimeSpan.Zero,
                    Type = "cloud",
                    AccentBrush = AccentForCategory("cloud"),
                    IconGeometry = IconForCategory("cloud"),
                    CoverImage = null
                };

                _uiDispatcher.Invoke(() =>
                {
                    var existingIdx = _allItems.FindIndex(i => string.Equals(i.Type, "cloud", StringComparison.OrdinalIgnoreCase) &&
                                                              string.Equals(i.FilePath, url, StringComparison.OrdinalIgnoreCase));
                    if (existingIdx >= 0)
                        _allItems[existingIdx] = newItem;
                    else
                        _allItems.Add(newItem);

                    if (IsCloudView)
                    {
                        ApplyCategoryFilter();
                        OnPropertyChanged(nameof(HasLibraryItems));
                        OnPropertyChanged(nameof(HasNoLibraryItems));
                    }

                    List<MediaItem> snapshot;
                    lock (_stateLock)
                    {
                        snapshot = _allItems.ToList();
                    }
                    _ = SaveLibraryToDiskAsync(snapshot);
                });

                PlayStreamUrl(result.StreamUrl, title);
                _uiDispatcher.Invoke(() =>
                {
                    CloudStatusText = "Streaming";
                    IsAddCloudLinkOpen = false;
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() => CloudStatusText = "Unrestrict failed");
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsCloudBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private void StreamCloudLink(MediaItem? item)
        {
            if (item == null) return;
            if (IsCloudBusy) return;

            var url = (item.FilePath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(url))
            {
                StatusText = "URL is required";
                OnPropertyChanged(nameof(StatusText));
                return;
            }

            _ = StreamCloudLinkAsync(item);
        }

        private async Task StreamCloudLinkAsync(MediaItem item)
        {
            var provider = SelectedCloudProvider ?? _cloudProviders.FirstOrDefault();
            if (provider == null)
            {
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "No providers installed";
                    OnPropertyChanged(nameof(StatusText));
                });
                return;
            }

            _uiDispatcher.Invoke(() =>
            {
                IsCloudBusy = true;
                StatusText = "Unrestricting...";
                OnPropertyChanged(nameof(StatusText));
                CommandManager.InvalidateRequerySuggested();
            });

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45));
                var result = await provider.UnrestrictAsync(item.FilePath, cts.Token).ConfigureAwait(false);
                if (!result.Success || string.IsNullOrWhiteSpace(result.StreamUrl))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        StatusText = string.IsNullOrWhiteSpace(result.Error) ? "Unrestrict failed" : result.Error!;
                        OnPropertyChanged(nameof(StatusText));
                    });
                    return;
                }

                PlayStreamUrl(result.StreamUrl, string.IsNullOrWhiteSpace(item.Title) ? "Cloud Link" : item.Title);
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "Playing";
                    OnPropertyChanged(nameof(StatusText));
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "Unrestrict failed";
                    OnPropertyChanged(nameof(StatusText));
                });
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsCloudBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private string? TryExtractRdKeyFromAddonServers()
        {
            try
            {
                foreach (var server in _addonServers)
                {
                    if (string.IsNullOrWhiteSpace(server)) continue;
                    var m = System.Text.RegularExpressions.Regex.Match(server, @"[|/]realdebrid=([A-Za-z0-9]+)", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
                    if (m.Success && m.Groups[1].Length >= 10)
                        return m.Groups[1].Value;
                }
            }
            catch { }
            return null;
        }

        private void EnsureVideoPlayerWindow()
        {
            AtlasAI.Core.AppLogger.LogInfo("[BridgePlay] EnsureVideoPlayerWindow called");
            // Use != null check only — IsVisible may still be false right after Show(), causing double-create
            if (_videoPlayerWindow != null)
            {
                AtlasAI.Core.AppLogger.LogInfo("[BridgePlay] player window already exists");
                if (!_videoPlayerWindow.IsVisible)
                    _videoPlayerWindow.Show();
                // Minimized WPF windows still have IsVisible=true, so Show() above is skipped.
                // Activate()/Focus() do not restore a minimized window — WindowState must be reset first.
                if (_videoPlayerWindow.WindowState == WindowState.Minimized)
                    _videoPlayerWindow.WindowState = WindowState.Maximized;
                _videoPlayerWindow.Topmost = true;
                _videoPlayerWindow.Topmost = false;
                _videoPlayerWindow.Activate();
                _videoPlayerWindow.Focus();
                return;
            }
            try
            {
                _videoPlayerWindow = new FullscreenPlayerWindow(_playbackService);
                _videoPlayerWindow.Closed += (_, __) => _videoPlayerWindow = null;
                _videoPlayerWindow.Show();
                _videoPlayerWindow.Topmost = true;
                _videoPlayerWindow.Topmost = false;
                _videoPlayerWindow.Activate();
                _videoPlayerWindow.Focus();
                _videoPlayerWindow.Dispatcher.BeginInvoke(
                    System.Windows.Threading.DispatcherPriority.ApplicationIdle,
                    new Action(() =>
                    {
                        if (_videoPlayerWindow != null)
                        {
                            _videoPlayerWindow.Activate();
                            _videoPlayerWindow.Focus();
                        }
                    }));
                AtlasAI.Core.AppLogger.LogInfo("[BridgePlay] player window shown OK");
            }
            catch (Exception ex)
            {
                AtlasAI.Core.AppLogger.LogError($"[BridgePlay] player window FAILED: {ex.GetType().Name}: {ex.Message}");
            }
        }

        /// <summary>
        /// Restores an existing minimized/hidden FullscreenPlayerWindow without starting or restarting playback.
        /// </summary>
        public void RestoreVideoPlayerWindow()
        {
            if (_videoPlayerWindow == null)
                return;

            if (!_videoPlayerWindow.IsVisible)
                _videoPlayerWindow.Show();

            if (_videoPlayerWindow.WindowState == WindowState.Minimized)
                _videoPlayerWindow.WindowState = WindowState.Maximized;

            _videoPlayerWindow.Topmost = true;
            _videoPlayerWindow.Topmost = false;
            _videoPlayerWindow.Activate();
            _videoPlayerWindow.Focus();
        }

