        private void PlayStreamUrl(string streamUrl, string title)
        {
            System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] PlayStreamUrl entry url={streamUrl} title={title}");
            if (string.IsNullOrWhiteSpace(streamUrl)) return;

            var ext = "";
            if (IsHttpUrl(streamUrl, out var uri))
                ext = Path.GetExtension(uri.AbsolutePath).ToLowerInvariant();
            else
                ext = Path.GetExtension(streamUrl).ToLowerInvariant();

            var isAudioOnly = AudioExtensions.Contains(ext);

            // Only open YouTube in browser — everything else (including no-extension stream URLs) goes to VLC
            if (IsHttpUrl(streamUrl, out var httpUri))
            {
                var host = (httpUri.Host ?? "").ToLowerInvariant();
                var isYouTube = host.Contains("youtube.") || host.Contains("youtu.be");
                if (isYouTube)
                {
                    try
                    {
                        Process.Start(new ProcessStartInfo(streamUrl) { UseShellExecute = true });
                        StatusText = "Opened in browser";
                        OnPropertyChanged(nameof(StatusText));
                        return;
                    }
                    catch
                    {
                        StatusText = "Failed to open link";
                        OnPropertyChanged(nameof(StatusText));
                        return;
                    }
                }
            }

            var playbackItem = new ScannerMediaItem
            {
                FilePath = streamUrl,
                Title = title,
                Extension = ext,
                MediaType = isAudioOnly ? AtlasAI.MediaScanner.MediaType.Audio : AtlasAI.MediaScanner.MediaType.Video,
                SectionName = "cloud",
                DateAdded = DateTime.UtcNow
            };

            System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] before _playbackService.PlaySingle path={playbackItem.FilePath} title={playbackItem.Title}");
            _playbackService.PlaySingle(playbackItem);
            System.Diagnostics.Debug.WriteLine($"[BridgePlayTrace] after _playbackService.PlaySingle path={playbackItem.FilePath} title={playbackItem.Title}");

            NowPlayingTitle = title;
            NowPlayingArtist = "";
            NowPlayingAlbum = "";
            NowPlayingCoverImage = null;

            OnPropertyChanged(nameof(NowPlayingTitle));
            OnPropertyChanged(nameof(NowPlayingArtist));
            OnPropertyChanged(nameof(NowPlayingAlbum));
            OnPropertyChanged(nameof(TrendingValue));
        }

        private void RefreshCloudLibrary()
        {
            if (IsCloudBusy) return;
            _ = RefreshCloudLibraryAsync();
        }

        private async Task RefreshCloudLibraryAsync()
        {
            var provider = SelectedCloudProvider ?? _cloudProviders.FirstOrDefault();
            if (provider == null)
            {
                _uiDispatcher.Invoke(() =>
                {
                    _cloudLibraryItems.Clear();
                    OnPropertyChanged(nameof(CloudLibraryItems));
                    CloudStatusText = "No providers installed";
                });
                return;
            }

            _uiDispatcher.Invoke(() =>
            {
                IsCloudBusy = true;
                CloudStatusText = "Loading cloud library...";
                CommandManager.InvalidateRequerySuggested();
            });

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(30));
                var items = await provider.GetCloudItemsAsync(cts.Token).ConfigureAwait(false);
                _uiDispatcher.Invoke(() =>
                {
                    _cloudLibraryItems.Clear();
                    foreach (var i in items) _cloudLibraryItems.Add(i);
                    CloudStatusText = items.Count == 0 ? "No cloud items" : "Cloud library loaded";
                });
            }
            catch
            {
                _uiDispatcher.Invoke(() => CloudStatusText = "Cloud library load failed");
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsCloudBusy = false;
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

