        public void UpdatePlaybackDuration(double seconds)
        {
            if (seconds <= 0) return;
            TotalSeconds = seconds;
            OnPropertyChanged(nameof(TotalText));
            OnPropertyChanged(nameof(ProgressRatio));
            TryPersistNowPlayingProgress();
        }

        public void UpdatePlaybackPosition(double seconds)
        {
            if (seconds < 0) return;
            if (_isUserSeeking) return;
            ProgressSeconds = seconds;
            OnPropertyChanged(nameof(ProgressText));
            OnPropertyChanged(nameof(ProgressRatio));
            TryPersistNowPlayingProgress();
        }

        private void TryPersistNowPlayingProgress()
        {
            try
            {
                var key = (_nowPlayingWatchHistoryKey ?? "").Trim();
                if (string.IsNullOrWhiteSpace(key)) return;
                if (ProgressSeconds < 0) return;

                var percent = Math.Clamp(ProgressSeconds / TotalSeconds, 0d, 1d);
                var now = DateTime.UtcNow;

                if ((now - _lastWatchProgressPersistUtc).TotalSeconds < 5 &&
                    _lastWatchProgressPersistPercent >= 0 &&
                    Math.Abs(percent - _lastWatchProgressPersistPercent) < 0.01)
                    return;

                _lastWatchProgressPersistUtc = now;
                _lastWatchProgressPersistPercent = percent;

                AtlasAI.Core.WatchHistoryStore.UpdateProgress(key, ProgressSeconds, TotalSeconds);

                var progressPercent = percent * 100d;
                foreach (var shelf in ServerShelves)
                {
                    if (shelf == null) continue;
                    if (!string.Equals((shelf.ContentType ?? "").Trim(), "continue", StringComparison.OrdinalIgnoreCase)) continue;
                    foreach (var item in shelf.Items)
                    {
                        if (item == null) continue;
                        var id = (item.MetaId ?? item.FilePath ?? "").Trim();
                        if (!string.Equals(id, key, StringComparison.OrdinalIgnoreCase)) continue;
                        item.ProgressPercent = progressPercent;
                        return;
                    }
                }
            }
            catch
            {
            }
        }

        public void BeginUserSeek()
        {
            _isUserSeeking = true;
        }

        public void EndUserSeek(double seconds)
        {
            _isUserSeeking = false;
            if (seconds < 0) return;
            _seekToSeconds?.Invoke(seconds);
        }

