        private async void OptimizeAlbum(AlbumEntry? album)
        {
            if (album == null) return;
            if (album.Tracks == null || album.Tracks.Count == 0)
            {
                StatusText = "No tracks in album";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                return;
            }

            var tracks = album.Tracks.ToList();
            var provider = AIManager.GetActiveProviderInstance();
            if (provider == null || !provider.IsConfigured)
            {
                // Free/basic path: organize using local folder/filename rules and fetch MusicBrainz metadata + covers.
                try
                {
                    var localUpdates = BuildLocalMusicOrganizeUpdates(tracks);
                    if (localUpdates.Count > 0)
                        ApplyOptimizedMetadata(localUpdates, true, true, true);

                    // Build an enhancement list that always includes Artist/Album so cover fetch can run even if there were no tag updates.
                    var enhanceItems = new List<AiOptimizedMetadata>();
                    foreach (var t in tracks)
                    {
                        if (t == null || string.IsNullOrWhiteSpace(t.FilePath)) continue;
                        enhanceItems.Add(new AiOptimizedMetadata
                        {
                            FilePath = t.FilePath,
                            Title = t.Title,
                            Artist = t.Artist,
                            Album = t.Album,
                            TrackNumber = t.TrackNumber == 0 ? null : t.TrackNumber,
                            DiscNumber = t.DiscNumber == 0 ? null : t.DiscNumber
                        });
                    }

                    // Apply any derived local updates into the enhancement list.
                    if (localUpdates.Count > 0)
                    {
                        var byPath = enhanceItems
                            .Where(i => !string.IsNullOrWhiteSpace(i.FilePath))
                            .ToDictionary(i => i.FilePath, StringComparer.OrdinalIgnoreCase);

                        foreach (var u in localUpdates)
                        {
                            if (u == null || string.IsNullOrWhiteSpace(u.FilePath)) continue;
                            if (!byPath.TryGetValue(u.FilePath, out var it)) continue;
                            if (!string.IsNullOrWhiteSpace(u.Title)) it.Title = u.Title;
                            if (!string.IsNullOrWhiteSpace(u.Artist)) it.Artist = u.Artist;
                            if (!string.IsNullOrWhiteSpace(u.Album)) it.Album = u.Album;
                            if (u.TrackNumber != null) it.TrackNumber = u.TrackNumber;
                            if (u.DiscNumber != null) it.DiscNumber = u.DiscNumber;
                        }
                    }

                    using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(45));
                    await EnhanceWithMusicBrainz(enhanceItems, true, true, cts.Token);
                }
                catch
                {
                    // Fall back to cover-only when possible.
                    if (HasArtworkProvidersConfigured())
                        await OptimizeArtworkOnlyAsync(tracks, $"Optimizing covers · {album.Artist} · {album.AlbumTitle}");
                    else
                    {
                        StatusText = "AI not configured";
                        OnPropertyChanged(nameof(StatusText));
                        OnPropertyChanged(nameof(TrendingValue));
                    }
                }
                return;
            }

            await OptimizeMediaMetadataAsync(tracks, $"AI optimizing · {album.Artist} · {album.AlbumTitle}", true);
        }

