        private void RemoveAlbum(AlbumEntry? album)
        {
            if (album == null) return;
            if (album.Tracks == null || album.Tracks.Count == 0) return;

            PushUndoSnapshot();

            var paths = album.Tracks
                .Where(t => t != null && !string.IsNullOrWhiteSpace(t.FilePath))
                .Select(t => t.FilePath)
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (paths.Count == 0) return;

            lock (_stateLock)
            {
                _allItems = _allItems.Where(i => !paths.Contains(i.FilePath, StringComparer.OrdinalIgnoreCase)).ToList();
                foreach (var p in paths) _ignoredPaths.Add(p);
            }

            RebuildMusicAlbums();
            ApplyCategoryFilter();
            OnPropertyChanged(nameof(LibraryCountText));
            OnPropertyChanged(nameof(VisibleCountText));
            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }
            _ = SaveLibraryToDiskAsync(snapshot);
        }

        private async void FixMusicAlbums()
        {
            if (IsScanning) return;

            PushUndoSnapshot();

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = "Fixing albums...";
                StatusText = "Fixing albums";
                ScannedCount = 0;
                CommandManager.InvalidateRequerySuggested();
            });

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }

            try
            {
                var result = await Task.Run(() =>
                {
                    var rebuilt = new List<MediaItem>(snapshot.Count);
                    foreach (var item in snapshot)
                    {
                        if (!string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
                        {
                            rebuilt.Add(item);
                            continue;
                        }

                        var albumRoot = GetAlbumRootFolder(item.FilePath);
                        var folderName = Path.GetFileName(albumRoot) ?? "";
                        var (folderArtist, folderAlbum) = DeriveArtistAlbumFromFolderName(folderName);
                        var disc = GetDiscNumberFromPath(item.FilePath);

                        var nextArtist = !string.IsNullOrWhiteSpace(folderArtist) ? folderArtist : item.Artist;
                        var nextAlbum = NormalizeAlbumTitle(!string.IsNullOrWhiteSpace(folderAlbum) ? folderAlbum : item.Album);

                        var nextTrack = item.TrackNumber;
                        if (nextTrack == 0 && TryParseTrackNumberFromFileName(item.FilePath, out var parsed))
                            nextTrack = parsed;

                        var next = new MediaItem
                        {
                            PlaybackItem = item.PlaybackItem,
                            FilePath = item.FilePath,
                            Title = item.Title,
                            Artist = nextArtist ?? "",
                            Album = nextAlbum ?? "",
                            TrackNumber = nextTrack,
                            DiscNumber = disc <= 0 ? 0 : disc,
                            Duration = item.Duration,
                            Type = item.Type,
                            AccentBrush = item.AccentBrush,
                            IconGeometry = item.IconGeometry,
                            LastAiOptimizedUtc = item.LastAiOptimizedUtc,
                            CoverImage = item.CoverImage
                        };
                        next.IsFavorite = item.IsFavorite;
                        next.IsSelected = item.IsSelected;
                        next.IsPlaying = item.IsPlaying;
                        rebuilt.Add(next);
                    }

                    var musicTracks = rebuilt.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
                    var albums = BuildAlbumEntries(musicTracks);
                    return (rebuilt, albums);
                }).ConfigureAwait(false);

                _uiDispatcher.Invoke(() =>
                {
                    lock (_stateLock)
                    {
                        _allItems = result.rebuilt;
                    }

                    _musicAlbums.Clear();
                    foreach (var a in result.albums) _musicAlbums.Add(a);
                    RebuildAlbumRows();

                    foreach (var c in Categories)
                    {
                        if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                            c.Count = _addonServers.Count;
                        else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                            c.Count = _musicAlbums.Count;
                        else
                            c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
                    }

                    ApplyCategoryFilter();
                    OnPropertyChanged(nameof(LibraryCountText));
                    OnPropertyChanged(nameof(VisibleCountText));
                    OnPropertyChanged(nameof(HasLibraryItems));
                    OnPropertyChanged(nameof(HasNoLibraryItems));

                    List<MediaItem> snapshot2;
                    lock (_stateLock)
                    {
                        snapshot2 = _allItems.ToList();
                    }
                    _ = SaveLibraryToDiskAsync(snapshot2);
                });
            }
            catch
            {
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsScanning = false;
                    ScanProgressText = "Ready";
                    StatusText = "Ready";
                    CommandManager.InvalidateRequerySuggested();
                });
            }
        }

        private void PlayAllMusic()
        {
            try
            {
                List<MediaItem> tracks;
                lock (_stateLock)
                {
                    tracks = _allItems
                        .Where(i => i != null &&
                                    string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase) &&
                                    !string.IsNullOrWhiteSpace(i.FilePath))
                        .ToList();
                }

                if (tracks.Count == 0) return;

                var ordered = tracks
                    .OrderBy(t => (t.Artist ?? "").Trim(), StringComparer.OrdinalIgnoreCase)
                    .ThenBy(t => (t.Album ?? "").Trim(), StringComparer.OrdinalIgnoreCase)
                    .ThenBy(t => t.DiscNumber)
                    .ThenBy(t => t.TrackNumber)
                    .ThenBy(t => (t.Title ?? "").Trim(), StringComparer.OrdinalIgnoreCase)
                    .ToList();

                var queue = ordered
                    .Select(t => t.PlaybackItem)
                    .Where(t => t != null)
                    .ToList();
                if (queue.Count == 0) return;

                _playbackService.PlayQueue(queue, 0);
                StatusText = $"Playing {queue.Count} tracks";
                OnPropertyChanged(nameof(StatusText));
            }
            catch
            {
            }
        }

        private void ResetMediaWatchers()
        {
            try
            {
                foreach (var w in _mediaWatchers)
                {
                    try
                    {
                        w.EnableRaisingEvents = false;
                        w.Dispose();
                    }
                    catch
                    {
                    }
                }
                _mediaWatchers.Clear();
            }
            catch
            {
            }

            try
            {
                var prefs = PreferencesStore.Instance.Current;
                if (!prefs.EnableAutoMediaScan) return;

                AddWatchersForFolders("music", prefs.MusicFolders);
                AddWatchersForFolders("movies", prefs.MoviesFolders);
                AddWatchersForFolders("tv", prefs.TVShowsFolders);
                AddWatchersForFolders("images", prefs.ImagesFolders);
                AddWatchersForFolders("games", prefs.GamesFolders);
            }
            catch
            {
            }
        }

        private void AddWatchersForFolders(string categoryId, string folders)
        {
            if (string.IsNullOrWhiteSpace(folders)) return;
            var list = folders.Split(';', StringSplitOptions.RemoveEmptyEntries).Select(s => s.Trim()).Distinct(StringComparer.OrdinalIgnoreCase).ToList();
            foreach (var folder in list)
            {
                if (string.IsNullOrWhiteSpace(folder)) continue;
                if (!Directory.Exists(folder)) continue;

                try
                {
                    if (string.Equals(categoryId, "games", StringComparison.OrdinalIgnoreCase))
                    {
                        var win = Environment.GetFolderPath(Environment.SpecialFolder.Windows) ?? "";
                        var pf = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles) ?? "";
                        var pf86 = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFilesX86) ?? "";
                        if (!string.IsNullOrWhiteSpace(win) && folder.StartsWith(win, StringComparison.OrdinalIgnoreCase)) continue;
                        if (!string.IsNullOrWhiteSpace(pf) && folder.StartsWith(pf, StringComparison.OrdinalIgnoreCase)) continue;
                        if (!string.IsNullOrWhiteSpace(pf86) && folder.StartsWith(pf86, StringComparison.OrdinalIgnoreCase)) continue;
                    }
                }
                catch
                {
                }

                try
                {
                    var w = new FileSystemWatcher(folder)
                    {
                        IncludeSubdirectories = true,
                        EnableRaisingEvents = true,
                        NotifyFilter = NotifyFilters.FileName | NotifyFilters.DirectoryName
                    };

                    FileSystemEventHandler handler = (_, e) => QueueAutoRescan(categoryId, e.FullPath);
                    RenamedEventHandler renamed = (_, e) => QueueAutoRescan(categoryId, e.FullPath);

                    w.Created += handler;
                    w.Deleted += handler;
                    w.Renamed += renamed;

                    _mediaWatchers.Add(w);
                }
                catch
                {
                }
            }
        }

        private void QueueAutoRescan(string categoryId, string path)
        {
            try
            {
                var now = DateTime.UtcNow;
                if (now < _autoRescanSuppressedUntilUtc) return;

                if (_autoRescanWindowStartUtc == DateTime.MinValue || (now - _autoRescanWindowStartUtc) > TimeSpan.FromSeconds(30))
                {
                    _autoRescanWindowStartUtc = now;
                    _autoRescanEventsInWindow = 0;
                }
                _autoRescanEventsInWindow++;

                if (_autoRescanEventsInWindow > 25)
                {
                    _autoRescanSuppressedUntilUtc = now.AddMinutes(15);
                    try
                    {
                        PreferencesStore.Instance.Update(p => p.EnableAutoMediaScan = false);
                    }
                    catch
                    {
                    }
                    try
                    {
                        _uiDispatcher.BeginInvoke(() =>
                        {
                            ScanProgressText = "Auto scan disabled";
                            StatusText = "Ready";
                            IsScanning = false;
                            CommandManager.InvalidateRequerySuggested();
                        });
                    }
                    catch
                    {
                    }
                    try
                    {
                        _uiDispatcher.BeginInvoke(ResetMediaWatchers);
                    }
                    catch
                    {
                    }
                    return;
                }
            }
            catch
            {
            }

            if (!IsRelevantFileForCategory(categoryId, path)) return;
            _autoRescanCategories.Add(categoryId);
            if (!_autoRescanTimer.IsEnabled)
                _autoRescanTimer.Start();
        }

        private void ProcessAutoRescanQueue()
        {
            if (_autoRescanTimer.IsEnabled) _autoRescanTimer.Stop();
            if (IsScanning)
            {
                _autoRescanTimer.Start();
                return;
            }

            if (_autoRescanCategories.Count == 0) return;
            var categories = _autoRescanCategories.ToList();
            _autoRescanCategories.Clear();

            foreach (var id in categories)
            {
                try
                {
                    var now = DateTime.UtcNow;
                    if (_lastAutoScanUtc.TryGetValue(id, out var last) && (now - last) < TimeSpan.FromMinutes(10))
                        continue;
                    _lastAutoScanUtc[id] = now;
                }
                catch
                {
                }

                _ = StartConfiguredScanAsync(id);
            }
        }

        private static bool IsRelevantFileForCategory(string categoryId, string path)
        {
            try
            {
                var ext = Path.GetExtension(path) ?? "";
                if (string.IsNullOrWhiteSpace(ext)) return false;

                if (string.Equals(categoryId, "music", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(categoryId, "radio", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(categoryId, "karaoke", StringComparison.OrdinalIgnoreCase))
                {
                    return AudioExtensions.Contains(ext);
                }

                if (string.Equals(categoryId, "movies", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(categoryId, "tv", StringComparison.OrdinalIgnoreCase))
                {
                    return VideoExtensions.Contains(ext);
                }

                if (string.Equals(categoryId, "images", StringComparison.OrdinalIgnoreCase))
                {
                    return ImageExtensions.Contains(ext);
                }

                if (string.Equals(categoryId, "games", StringComparison.OrdinalIgnoreCase))
                {
                    return GameExtensions.Contains(ext);
                }

                return false;
            }
            catch
            {
                return false;
            }
        }

        private Task StartConfiguredScanAsync(string categoryId)
        {
            try
            {
                var cat = Categories.FirstOrDefault(c => string.Equals(c.Id, categoryId, StringComparison.OrdinalIgnoreCase))
                          ?? new MediaCategory { Id = categoryId, Label = categoryId };

                var prefs = PreferencesStore.Instance.Current;
                var folders = categoryId.ToLowerInvariant() switch
                {
                    "movies" => prefs.MoviesFolders,
                    "tv" => prefs.TVShowsFolders,
                    "music" => prefs.MusicFolders,
                    "karaoke" => prefs.KaraokeFolders, // Add explicit mapping for Karaoke
                    "games" => prefs.GamesFolders,
                    "images" => prefs.ImagesFolders,
                    _ => ""
                };

                var list = (folders ?? "").Split(';', StringSplitOptions.RemoveEmptyEntries).Select(s => s.Trim()).Where(Directory.Exists).Distinct(StringComparer.OrdinalIgnoreCase).ToList();
                if (list.Count == 0) return Task.CompletedTask;

                return StartConfiguredScanAsync(cat, list);
            }
            catch
            {
                return Task.CompletedTask;
            }
        }

        private async Task StartConfiguredScanAsync(MediaCategory category, List<string> roots)
        {
            if (IsScanning) return;

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = "Auto scanning...";
                ScannedCount = 0;
                StatusText = "Auto scanning";
                CommandManager.InvalidateRequerySuggested();
            });

            _scanCts?.Cancel();
            _scanCts?.Dispose();
            _scanCts = new CancellationTokenSource();
            var ct = _scanCts.Token;

            List<MediaItem> scannedItems;
            try
            {
                scannedItems = await Task.Run(() =>
                {
                    var all = new List<MediaItem>();
                    var processed = 0;
                    foreach (var root in roots)
                    {
                        ct.ThrowIfCancellationRequested();
                        var part = ScanFolder(category.Id, root, ct);
                        all.AddRange(part);
                        processed += part.Count;
                        _uiDispatcher.BeginInvoke(() =>
                        {
                            ScannedCount = processed;
                            ScanProgressText = $"Auto scanning... {processed} files";
                        });
                    }

                    return all
                        .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                        .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                        .Select(g => g.First())
                        .ToList();
                }, ct).ConfigureAwait(false);
            }
            catch (OperationCanceledException)
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = "Auto scan cancelled";
                    StatusText = "Ready";
                    IsScanning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }
            catch
            {
                _uiDispatcher.BeginInvoke(() =>
                {
                    ScanProgressText = "Auto scan failed";
                    StatusText = "Ready";
                    IsScanning = false;
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            List<MediaItem> newAllItems;
            lock (_stateLock)
            {
                var byPath = new Dictionary<string, MediaItem>(StringComparer.OrdinalIgnoreCase);
                foreach (var existing in _allItems)
                {
                    if (!string.IsNullOrWhiteSpace(existing.FilePath))
                        byPath[existing.FilePath] = existing;
                }
                foreach (var scanned in scannedItems)
                {
                    if (!string.IsNullOrWhiteSpace(scanned.FilePath) && !_ignoredPaths.Contains(scanned.FilePath))
                    {
                        if (byPath.TryGetValue(scanned.FilePath, out var existing))
                            byPath[scanned.FilePath] = MergeExistingAndScanned(existing, scanned);
                        else
                            byPath[scanned.FilePath] = scanned;
                    }
                }
                newAllItems = byPath.Values.ToList();
            }

            List<AlbumEntry>? albums = null;
            if (string.Equals(category.Id, "music", StringComparison.OrdinalIgnoreCase))
            {
                var musicTracks = newAllItems.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
                albums = BuildAlbumEntries(musicTracks);
            }

            _uiDispatcher.BeginInvoke(() =>
            {
                lock (_stateLock)
                {
                    _allItems = newAllItems;
                }

                if (albums != null)
                {
                    _musicAlbums.Clear();
                    foreach (var a in albums) _musicAlbums.Add(a);
                    RebuildAlbumRows();
                    category.Count = _musicAlbums.Count;
                }
                else
                {
                    category.Count = _allItems.Count(i => string.Equals(i.Type, category.Id, StringComparison.OrdinalIgnoreCase));
                }

                ScanProgressText = $"Auto scan complete: {scannedItems.Count} items";
                StatusText = "Ready";
                IsScanning = false;
                CommandManager.InvalidateRequerySuggested();

                OnPropertyChanged(nameof(LibraryCountText));
                OnPropertyChanged(nameof(PlaytimeText));
                OnPropertyChanged(nameof(HasLibraryItems));
                OnPropertyChanged(nameof(HasNoLibraryItems));
                ApplyCategoryFilter();

                List<MediaItem> snapshot;
                lock (_stateLock)
                {
                    snapshot = _allItems.ToList();
                }
                _ = SaveLibraryToDiskAsync(snapshot);
            });
        }

        private async void AutoOrganizeMusic()
        {
            if (IsScanning) return;

            PushUndoSnapshot();

            _mediaAiCts?.Dispose();
            _mediaAiCts = new CancellationTokenSource();
            CommandManager.InvalidateRequerySuggested();
            var token = _mediaAiCts.Token;

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = "Auto organizing music...";
                StatusText = "Auto organizing";
                ScannedCount = 0;
                CommandManager.InvalidateRequerySuggested();
            });

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }

            try
            {
                var result = await Task.Run(() =>
                {
                    var rebuilt = new List<MediaItem>(snapshot.Count);
                    foreach (var item in snapshot)
                    {
                        token.ThrowIfCancellationRequested();

                        if (!string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
                        {
                            rebuilt.Add(item);
                            continue;
                        }

                        var albumRoot = GetAlbumRootFolder(item.FilePath);
                        var folderName = Path.GetFileName(albumRoot) ?? "";
                        var (folderArtist, folderAlbum) = DeriveArtistAlbumFromFolderName(folderName);
                        var disc = GetDiscNumberFromPath(item.FilePath);

                        var nextArtist = !string.IsNullOrWhiteSpace(folderArtist) ? folderArtist : item.Artist;
                        var nextAlbum = NormalizeAlbumTitle(!string.IsNullOrWhiteSpace(folderAlbum) ? folderAlbum : item.Album);

                        var nextTrack = item.TrackNumber;
                        if (nextTrack == 0 && TryParseTrackNumberFromFileName(item.FilePath, out var parsed))
                            nextTrack = parsed;

                        var nextTitle = item.Title;
                        if (LooksLikeFileNameTitle(item))
                        {
                            var cleaned = CleanTitleFromFileName(item.FilePath);
                            if (!string.IsNullOrWhiteSpace(cleaned))
                                nextTitle = cleaned;
                        }

                        var next = new MediaItem
                        {
                            PlaybackItem = item.PlaybackItem,
                            FilePath = item.FilePath,
                            Title = nextTitle ?? "",
                            Artist = nextArtist ?? "",
                            Album = nextAlbum ?? "",
                            TrackNumber = nextTrack,
                            DiscNumber = disc <= 0 ? 0 : disc,
                            Duration = item.Duration,
                            Type = item.Type,
                            AccentBrush = item.AccentBrush,
                            IconGeometry = item.IconGeometry,
                            LastAiOptimizedUtc = item.LastAiOptimizedUtc,
                            CoverImage = item.CoverImage
                        };
                        next.IsFavorite = item.IsFavorite;
                        next.IsSelected = item.IsSelected;
                        next.IsPlaying = item.IsPlaying;
                        rebuilt.Add(next);
                    }

                    var musicTracks = rebuilt.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
                    var albums = BuildAlbumEntries(musicTracks);
                    var needsAi = musicTracks.Where(NeedsAiMetadata).ToList();
                    return (rebuilt, albums, needsAi);
                }, token).ConfigureAwait(false);

                _uiDispatcher.Invoke(() =>
                {
                    lock (_stateLock)
                    {
                        _allItems = result.rebuilt;
                    }

                    _musicAlbums.Clear();
                    foreach (var a in result.albums) _musicAlbums.Add(a);
                    RebuildAlbumRows();

                    foreach (var c in Categories)
                    {
                        if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                            c.Count = _musicAlbums.Count;
                        else
                            c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
                    }

                    ApplyCategoryFilter();
                    OnPropertyChanged(nameof(LibraryCountText));
                    OnPropertyChanged(nameof(VisibleCountText));
                    OnPropertyChanged(nameof(HasLibraryItems));
                    OnPropertyChanged(nameof(HasNoLibraryItems));
                });

                var provider = AIManager.GetActiveProviderInstance();
                if (provider != null && provider.IsConfigured)
                {
                    var aiTargets = result.needsAi
                        .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                        .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                        .Select(g => g.First())
                        .ToList();

                    if (aiTargets.Count > 0)
                    {
                        MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = "Auto organize: put tracks back into albums, fix missing titles/artists/albums, merge multi-disc, keep existing good metadata." });

                        var updates = new List<AiOptimizedMetadata>();
                        const int batchSize = 20;
                        for (var i = 0; i < aiTargets.Count; i += batchSize)
                        {
                            token.ThrowIfCancellationRequested();
                            var batch = aiTargets.Skip(i).Take(batchSize).ToList();
                            _uiDispatcher.Invoke(() =>
                            {
                                ScannedCount = Math.Min(aiTargets.Count, i + batch.Count);
                                ScanProgressText = $"AI organizing... {ScannedCount}/{aiTargets.Count}";
                            });

                            var prompt = BuildMediaAiCommandPrompt(batch, "Put tracks back into albums. If album/artist/title is missing or wrong, infer it from folder/path and filename. Merge CD1/CD2 into one album name, set discNumber. Fix trackNumber and remove leading track numbers from titles. Never set fields to empty strings. If unsure, omit the field.");
                            AIResponse response;
                            try
                            {
                                response = await AIManager.SendMessageAsync(prompt, 900, _mediaAiCts?.Token ?? default);
                            }
                            catch
                            {
                                continue;
                            }

                            if (!response.Success || string.IsNullOrWhiteSpace(response.Content))
                                continue;

                            MediaAiLastResponse = response.Content;
                            if (TryParseOptimizedMetadata(response.Content, out var parsed))
                                updates.AddRange(parsed);
                        }

                        if (updates.Count > 0)
                        {
                            _uiDispatcher.Invoke(() => ApplyOptimizedMetadata(updates, true, true));
                            MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = $"Auto organize applied {updates.Count} updates" });
                        }
                    }
                }

                List<MediaItem> snapshot2;
                lock (_stateLock)
                {
                    snapshot2 = _allItems.ToList();
                }
                _ = SaveLibraryToDiskAsync(snapshot2);
            }
            catch (OperationCanceledException)
            {
                StatusText = "CANCELLED · OPERATION STOPPED";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
            }
            catch
            {
            }
            finally
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsScanning = false;
                    ScanProgressText = "Ready";
                    StatusText = "Ready";
                    CommandManager.InvalidateRequerySuggested();
                });

                _mediaAiCts?.Dispose();
                _mediaAiCts = null;
                CommandManager.InvalidateRequerySuggested();
            }
        }

        private static bool NeedsAiMetadata(MediaItem item)
        {
            if (item == null) return false;
            if (!string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase)) return false;
            if (string.IsNullOrWhiteSpace(item.Artist)) return true;
            if (string.IsNullOrWhiteSpace(item.Album)) return true;
            if (LooksLikeFileNameTitle(item)) return true;
            return false;
        }

        private static bool LooksLikeFileNameTitle(MediaItem item)
        {
            try
            {
                if (item == null) return false;
                if (string.IsNullOrWhiteSpace(item.FilePath)) return false;
                var fileTitle = Path.GetFileNameWithoutExtension(item.FilePath) ?? "";
                if (string.IsNullOrWhiteSpace(fileTitle)) return false;
                if (string.IsNullOrWhiteSpace(item.Title)) return true;
                return string.Equals(fileTitle, item.Title, StringComparison.OrdinalIgnoreCase);
            }
            catch
            {
                return false;
            }
        }

        private static string CleanTitleFromFileName(string filePath)
        {
            try
            {
                var name = Path.GetFileNameWithoutExtension(filePath) ?? "";
                name = name.Trim();
                if (string.IsNullOrWhiteSpace(name)) return "";

                name = Regex.Replace(name, "^(\\d{1,3})\\s*[\\-\\._\\)]\\s*", "", RegexOptions.IgnoreCase).Trim();
                name = Regex.Replace(name, "^(track)\\s*(\\d{1,3})\\s*[\\-\\._\\)]\\s*", "", RegexOptions.IgnoreCase).Trim();
                name = Regex.Replace(name, "\\s+", " ").Trim();
                return name;
            }
            catch
            {
                return "";
            }
        }

        private void UndoLastChange()
        {
            if (IsScanning) return;

            List<MediaItem>? snapshot = null;
            lock (_stateLock)
            {
                if (_undoStack.Count > 0)
                    snapshot = _undoStack.Pop();
            }

            if (snapshot == null) return;

            lock (_stateLock)
            {
                _allItems = snapshot;
            }

            RebuildMusicAlbums();

            foreach (var c in Categories)
            {
                if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                    c.Count = _addonServers.Count;
                else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                    c.Count = _musicAlbums.Count;
                else
                    c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
            }

            ApplyCategoryFilter();
            OnPropertyChanged(nameof(LibraryCountText));
            OnPropertyChanged(nameof(PlaytimeText));
            OnPropertyChanged(nameof(VisibleCountText));
            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));

            List<MediaItem> snapshot2;
            lock (_stateLock)
            {
                snapshot2 = _allItems.ToList();
            }
            _ = SaveLibraryToDiskAsync(snapshot2);

            StatusText = "Undone";
            OnPropertyChanged(nameof(StatusText));
            OnPropertyChanged(nameof(TrendingValue));
            CommandManager.InvalidateRequerySuggested();
        }

        private void ClearSelectedCategory()
        {
            if (IsScanning) return;

            var id = SelectedCategory?.Id ?? "";
            if (string.IsNullOrWhiteSpace(id)) return;

            PushUndoSnapshot();

            lock (_stateLock)
            {
                _allItems = _allItems.Where(i => !string.Equals(i.Type, id, StringComparison.OrdinalIgnoreCase)).ToList();
            }

            if (string.Equals(id, "music", StringComparison.OrdinalIgnoreCase))
            {
                SelectedAlbum = null;
                _musicAlbums.Clear();
                _musicAlbumRows.Clear();
            }
            else
