                if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                    c.Count = _addonServers.Count;
                else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                    c.Count = _musicAlbums.Count;
                else
                    c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
            }

            ApplyCategoryFilter();
            OnPropertyChanged(nameof(LibraryCountText));
            OnPropertyChanged(nameof(VisibleCountText));
            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));

            List<MediaItem> snapshot2;
            lock (_stateLock)
            {
                snapshot2 = _allItems.ToList();
            }
            _ = SaveLibraryToDiskAsync(snapshot2);

            StatusText = "Cleared";
            OnPropertyChanged(nameof(StatusText));
            OnPropertyChanged(nameof(TrendingValue));
            CommandManager.InvalidateRequerySuggested();
        }

        private async void SendMediaAi()
        {
            var instruction = (MediaAiCommandText ?? "").Trim();
            if (string.IsNullOrWhiteSpace(instruction)) return;
            if (IsScanning)
            {
                SetMediaAgentState("Media scanner busy", false, "Media scanner is active. Try again after scan completes.");
                return;
            }
            if (_mediaAiCts != null) return;

            SetMediaAgentState("Running command...", true);

            var routed = await TryHandleMediaAgentIntentAsync(instruction, CancellationToken.None).ConfigureAwait(false);
            if (routed.handled)
            {
                _uiDispatcher.Invoke(() =>
                {
                    MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = instruction });
                    MediaAiCommandText = "";
                    if (!string.IsNullOrWhiteSpace(routed.reply))
                    {
                        MediaAiLastResponse = routed.reply;
                        MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = routed.reply });
                    }
                    SetMediaAgentState("Completed", false);
                });
                return;
            }

            if (TryRunMediaAgentInsightCommand(instruction, out var insightReply))
            {
                MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = instruction });
                MediaAiCommandText = "";
                if (!string.IsNullOrWhiteSpace(insightReply))
                {
                    MediaAiLastResponse = insightReply;
                    MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = insightReply });
                }
                SetMediaAgentState("Completed", false);
                return;
            }

            if (TryApplyLocalMediaCommand(instruction, out var localReply))
            {
                MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = instruction });
                MediaAiCommandText = "";
                if (!string.IsNullOrWhiteSpace(localReply))
                {
                    MediaAiLastResponse = localReply;
                    MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = localReply });
                }
                SetMediaAgentState("Completed", false);
                return;
            }

            var scope = ResolveMediaAiScopeItems();
            if (TryBuildMediaApprovalPreview(instruction, scope.Count, out var approvalPreview))
            {
                MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = instruction });
                MediaAiCommandText = "";
                MediaAiLastResponse = approvalPreview;
                MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = approvalPreview });
                SetMediaAgentState("Approval required", false);
                return;
            }

            var provider = AIManager.GetActiveProviderInstance();
            if (provider == null || !provider.IsConfigured)
            {
                StatusText = "AI not configured";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                SetMediaAgentState("AI unavailable", false, "AI provider is not configured.");
                return;
            }

            _mediaAiCts = new CancellationTokenSource();
            var token = _mediaAiCts.Token;
            CommandManager.InvalidateRequerySuggested();

            if (scope.Count == 0)
            {
                MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = instruction });
                MediaAiCommandText = "";

                IsScanning = true;
                ScanProgressText = "AI working...";
                StatusText = "AI working";
                CommandManager.InvalidateRequerySuggested();

                try
                {
                    var messages = new List<object>
                    {
                        new { role = "system", content = "You are Atlas AI Assistant inside a media app. Help the user with questions and short suggestions. Be concise and practical." },
                        new { role = "user", content = instruction }
                    };

                    var response = await AIManager.SendMessageAsync("MediaCentreChat", messages, 700, _mediaAiCts?.Token ?? default).ConfigureAwait(false);
                    _uiDispatcher.Invoke(() =>
                    {
                        MediaAiLastResponse = response.Content ?? response.Error ?? "";
                        MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = MediaAiLastResponse });
                        SetMediaAgentState("Completed", false);
                    });
                }
                catch
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = "AI error" });
                        SetMediaAgentState("Failed", false, "AI provider returned an error.");
                    });
                }
                finally
                {
                    IsScanning = false;
                    ScanProgressText = "";
                    StatusText = "Ready";
                    try
                    {
                        _mediaAiCts?.Dispose();
                    }
                    catch
                    {
                    }
                    _mediaAiCts = null;
                    CommandManager.InvalidateRequerySuggested();
                }

                return;
            }

            MediaAiChat.Add(new MediaAiChatMessage { Role = "user", Content = instruction });
            MediaAiCommandText = "";

            PushUndoSnapshot();

            IsScanning = true;
            ScanProgressText = "AI working...";
            StatusText = "AI working";
            ScannedCount = 0;
            CommandManager.InvalidateRequerySuggested();

            var targets = scope
                .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                .Select(g => g.First())
                .ToList();

            if (targets.Count > MaxAiItemsPerRun)
            {
                var originalCount = targets.Count;
                targets = targets.Take(MaxAiItemsPerRun).ToList();
                MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = $"Limited to {MaxAiItemsPerRun} items to save credits (out of {originalCount})." });
            }

            // Run heavy lifting in background task to keep UI responsive
            await Task.Run(async () =>
            {
                var pending = new List<AiOptimizedMetadata>();
                var parsedCount = 0;
                var appliedCount = 0;
                const int applyChunkSize = 220;

                var wantsAlbumRebuild = instruction.IndexOf("album", StringComparison.OrdinalIgnoreCase) >= 0 &&
                                        (instruction.IndexOf("single", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                         instruction.IndexOf("back", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                         instruction.IndexOf("into", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                         instruction.IndexOf("group", StringComparison.OrdinalIgnoreCase) >= 0);

                var localAppliedCount = 0;
                if (wantsAlbumRebuild)
                {
                    try
                    {
                        var localUpdates = BuildLocalMusicOrganizeUpdates(targets);
                        if (localUpdates.Count > 0)
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                ApplyOptimizedMetadata(localUpdates, false, false, true);
                                MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = $"Organized {localUpdates.Count} tracks using folder + filename rules" });
                            });
                            await EnhanceWithMusicBrainz(localUpdates, true, true, token);
                            localAppliedCount = localUpdates.Count;
                        }
                    }
                    catch
                    {
                    }
                }

                const int batchSize = 20;
                try
                {
                    for (var i = 0; i < targets.Count; i += batchSize)
                    {
                        if (token.IsCancellationRequested)
                            break;

                        var batch = targets.Skip(i).Take(batchSize).ToList();
                        _uiDispatcher.Invoke(() =>
                        {
                            ScannedCount = Math.Min(targets.Count, i + batch.Count);
                            ScanProgressText = $"AI working... {ScannedCount}/{targets.Count} · applied {appliedCount}";
                        });

                        var prompt = BuildMediaAiCommandPrompt(batch, instruction);
                        var response = await AIManager.SendMessageAsync(prompt, 900, token);
                        
                        if (response.Success && !string.IsNullOrWhiteSpace(response.Content))
                             _uiDispatcher.Invoke(() => MediaAiLastResponse = response.Content);

                        bool parsedSuccess = false;
                        List<AiOptimizedMetadata> parsed = null;

                        if (response.Success && !string.IsNullOrWhiteSpace(response.Content))
                        {
                            parsedSuccess = TryParseOptimizedMetadata(response.Content, out parsed);
                        }

                        // Fallback: If AI returned nothing/invalid JSON, but user likely wants metadata/covers
                        if (!parsedSuccess)
                        {
                            var wantsMetadata = instruction.IndexOf("cover", StringComparison.OrdinalIgnoreCase) >= 0 || 
                                                instruction.IndexOf("art", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                                instruction.IndexOf("metadata", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                                instruction.IndexOf("find", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                                instruction.IndexOf("search", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                                instruction.IndexOf("fix", StringComparison.OrdinalIgnoreCase) >= 0 ||
                                                instruction.IndexOf("optimize", StringComparison.OrdinalIgnoreCase) >= 0;

                            if (wantsMetadata)
                            {
                                parsed = batch.Select(i => new AiOptimizedMetadata 
                                { 
                                    FilePath = i.FilePath,
                                    Artist = i.Artist,
                                    Album = i.Album,
                                    Title = i.Title,
                                    TrackNumber = i.TrackNumber,
                                    DiscNumber = i.DiscNumber
                                }).ToList();
                                parsedSuccess = true;
                            }
                        }

                        if (parsedSuccess && parsed != null && parsed.Count > 0)
                        {
                            _uiDispatcher.Invoke(() => MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = $"Found {parsed.Count} items to enhance. Searching metadata..." }));
                            
                            // Check each item for success
                            int enhancedCount = 0;
                            foreach (var p in parsed)
                            {
                                if (token.IsCancellationRequested) break;
                                
                                bool success = await EnhanceWithMusicBrainz(new List<AiOptimizedMetadata> { p }, true, true, token);
                                if (success) enhancedCount++;
                                
                                // Update status every few items
                                if (enhancedCount % 5 == 0)
                                {
                                    _uiDispatcher.Invoke(() => ScanProgressText = $"Enhanced {enhancedCount}/{parsed.Count}...");
                                }
                            }

                            parsedCount += parsed.Count;
                            pending.AddRange(parsed);
                        }

                        if (pending.Count >= applyChunkSize)
                        {
                            var chunk = pending.ToList();
                            pending.Clear();
                            _uiDispatcher.Invoke(() => ApplyOptimizedMetadata(chunk, false, false, true));
                            appliedCount += chunk.Count;
                        }
                    }
                }
                catch
                {
                }

                _uiDispatcher.Invoke(() =>
                {
                    IsScanning = false;
                    ScanProgressText = "Ready";
                    StatusText = "Ready";
                    CommandManager.InvalidateRequerySuggested();
                });

                if (token.IsCancellationRequested)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        StatusText = "CANCELLED · OPERATION STOPPED";
                        OnPropertyChanged(nameof(StatusText));
                        OnPropertyChanged(nameof(TrendingValue));
                    });
                }
                else
                {
                    if (pending.Count > 0)
                    {
                        var chunk = pending.ToList();
                        pending.Clear();
                        _uiDispatcher.Invoke(() => ApplyOptimizedMetadata(chunk, false, false, true));
                        appliedCount += chunk.Count;
                    }

                    _uiDispatcher.Invoke(() =>
                    {
                        if (appliedCount > 0 || localAppliedCount > 0)
                        {
                            var totalApplied = appliedCount + localAppliedCount;
                            MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = $"Applied {totalApplied} updates" });
                            StatusText = $"Applied {totalApplied} updates";
                            SetMediaAgentState("Applied updates", false);
                        }
                        else
                        {
                            MediaAiChat.Add(new MediaAiChatMessage { Role = "assistant", Content = $"No changes returned (parsed {parsedCount})" });
                            StatusText = "No changes returned";
                            SetMediaAgentState("No updates", false);
                        }

                        OnPropertyChanged(nameof(StatusText));
                        OnPropertyChanged(nameof(TrendingValue));

                        if (appliedCount > 0 || localAppliedCount > 0)
                        {
                            List<MediaItem> snapshot;
                            lock (_stateLock)
                            {
                                snapshot = _allItems.ToList();
                            }
                            _ = SaveLibraryToDiskAsync(snapshot);
                        }
                    });
                }

                _mediaAiCts?.Dispose();
                _mediaAiCts = null;
                _uiDispatcher.Invoke(() => CommandManager.InvalidateRequerySuggested());
            });
        }

        private List<MediaItem> ResolveMediaAiScopeItems()
        {
            switch (SelectedMediaAiScope)
            {
                case MediaAiScope.SelectedAlbum:
                    return SelectedAlbum?.Tracks.ToList() ?? new List<MediaItem>();
                case MediaAiScope.CurrentList:
                    return LibraryItems.ToList();
                case MediaAiScope.AllLibrary:
                    lock (_stateLock)
                    {
                        return _allItems.ToList();
                    }
                case MediaAiScope.Category:
                default:
                    var id = SelectedCategory?.Id ?? "";
                    lock (_stateLock)
                    {
                        if (string.IsNullOrWhiteSpace(id))
                            return _allItems.ToList();

                        return _allItems
                            .Where(i => string.Equals(i.Type, id, StringComparison.OrdinalIgnoreCase))
                            .ToList();
                    }
            }
        }

        private void SetMediaAgentState(string stateText, bool isBusy, string? errorText = null)
        {
            IsMediaAgentBusy = isBusy;
            MediaAgentStateText = stateText;
            MediaAgentLastError = errorText ?? "";
            OnPropertyChanged(nameof(MediaAgentContextSnapshot));
        }

        private void SetMediaAgentResultState(string stateText, string summary, IEnumerable<string>? lines = null)
        {
            MediaAgentResultStateText = stateText;
            MediaAgentResultSummary = summary;
            _mediaAgentResultItems.Clear();
            OnPropertyChanged(nameof(HasMediaAgentResultItems));
            _mediaAgentResultLines.Clear();
            if (lines != null)
            {
                foreach (var line in lines)
                {
                    var trimmed = (line ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(trimmed))
                        _mediaAgentResultLines.Add(trimmed);
                }
            }
        }

        private void SetMediaAgentResultItems(string stateText, string summary, IEnumerable<MediaAgentResultItem> items)
        {
            var list = (items ?? Enumerable.Empty<MediaAgentResultItem>())
                .Select(item => EnrichMediaAgentResultItem(item, summary))
                .ToList();
            SetMediaAgentResultState(stateText, summary, list.Select(i => i.ToFallbackLine()));
            _mediaAgentResultItems.Clear();
            foreach (var item in list)
                _mediaAgentResultItems.Add(item);
            OnPropertyChanged(nameof(HasMediaAgentResultItems));
        }

        private static string GetMediaDraftKey(MediaAgentResultItem item)
        {
            if (item == null)
                return "";

            var title = (item.Title ?? "").Trim();
            var provider = (item.Provider ?? "").Trim();
            var artist = (item.ArtistName ?? "").Trim();
            var path = (item.LocalPath ?? "").Trim();
            return $"{title}|{artist}|{provider}|{path}".ToLowerInvariant();
        }

        private static MediaAgentResultItem CloneMediaResultItem(MediaAgentResultItem item)
        {
            return new MediaAgentResultItem
            {
                Kind = item.Kind,
                Title = item.Title,
                Subtitle = item.Subtitle,
                MediaTypeId = item.MediaTypeId,
                Year = item.Year,
                Rating = item.Rating,
                Votes = item.Votes,
                Provider = item.Provider,
                Overview = item.Overview,
                Source = item.Source,
                LocalPath = item.LocalPath,
                ExternalQuery = item.ExternalQuery,
                Tags = item.Tags?.ToList() ?? new List<string>(),
                LibraryStatusText = item.LibraryStatusText,
                DraftCategory = item.DraftCategory,
                CanPlay = item.CanPlay,
                CanOpenLocation = item.CanOpenLocation,
                SimilarReason = item.SimilarReason,
                ArtistName = item.ArtistName,
                TmdbId = item.TmdbId
            };
        }

        private sealed class PersistedMediaDrafts
        {
            public List<PersistedMediaDraftItem> Watchlist { get; set; } = new();
            public List<PersistedMediaDraftItem> Playlist { get; set; } = new();
        }

        private sealed class PersistedMediaDraftItem
        {
            public string Kind { get; set; } = "";
            public string Title { get; set; } = "";
            public string Subtitle { get; set; } = "";
            public string MediaTypeId { get; set; } = "";
            public int? Year { get; set; }
            public double? Rating { get; set; }
            public int? Votes { get; set; }
            public string Provider { get; set; } = "";
            public string Overview { get; set; } = "";
            public string Source { get; set; } = "";
            public string LocalPath { get; set; } = "";
            public string ExternalQuery { get; set; } = "";
            public List<string> Tags { get; set; } = new();
            public string LibraryStatusText { get; set; } = "";
            public string DraftCategory { get; set; } = "";
            public bool CanPlay { get; set; }
            public bool CanOpenLocation { get; set; }
            public string SimilarReason { get; set; } = "";
            public string ArtistName { get; set; } = "";
            public int? TmdbId { get; set; }
        }

        private static PersistedMediaDraftItem ToPersistedMediaDraftItem(MediaAgentResultItem item)
        {
            return new PersistedMediaDraftItem
            {
                Kind = item.Kind.ToString(),
                Title = item.Title,
                Subtitle = item.Subtitle,
                MediaTypeId = item.MediaTypeId,
                Year = item.Year,
                Rating = item.Rating,
                Votes = item.Votes,
                Provider = item.Provider,
                Overview = item.Overview,
                Source = item.Source,
                LocalPath = item.LocalPath,
                ExternalQuery = item.ExternalQuery,
                Tags = item.Tags?.ToList() ?? new List<string>(),
                LibraryStatusText = item.LibraryStatusText,
                DraftCategory = item.DraftCategory,
                CanPlay = item.CanPlay,
                CanOpenLocation = item.CanOpenLocation,
                SimilarReason = item.SimilarReason,
                ArtistName = item.ArtistName,
                TmdbId = item.TmdbId
            };
        }

        private static MediaAgentResultItem FromPersistedMediaDraftItem(PersistedMediaDraftItem item)
        {
            Enum.TryParse<MediaAgentResultItem.ResultKind>(item.Kind, true, out var kind);
            return new MediaAgentResultItem
            {
                Kind = kind,
                Title = item.Title,
                Subtitle = item.Subtitle,
                MediaTypeId = item.MediaTypeId,
                Year = item.Year,
                Rating = item.Rating,
                Votes = item.Votes,
                Provider = item.Provider,
                Overview = item.Overview,
                Source = item.Source,
                LocalPath = item.LocalPath,
                ExternalQuery = item.ExternalQuery,
                Tags = item.Tags ?? new List<string>(),
                LibraryStatusText = item.LibraryStatusText,
                DraftCategory = item.DraftCategory,
                CanPlay = item.CanPlay,
                CanOpenLocation = item.CanOpenLocation,
                SimilarReason = item.SimilarReason,
                ArtistName = item.ArtistName,
                TmdbId = item.TmdbId
            };
        }

        private static string DetermineWatchlistCategory(MediaAgentResultItem item, string? summary = null)
        {
            var tags = item.Tags ?? Array.Empty<string>();
            if (tags.Any(tag => string.Equals(tag, "horror", StringComparison.OrdinalIgnoreCase)))
                return "Horror";
            if (tags.Any(tag => string.Equals(tag, "action", StringComparison.OrdinalIgnoreCase)))
                return "Action";
            if ((summary ?? "").IndexOf("new releases", StringComparison.OrdinalIgnoreCase) >= 0 ||
                (item.Subtitle ?? "").IndexOf("Release date", StringComparison.OrdinalIgnoreCase) >= 0)
                return "New Releases";
            return "To Watch Soon";
        }

        private static string NormalizeLibraryText(string value)
        {
            value = (value ?? "").Trim().ToLowerInvariant();
            value = Regex.Replace(value, @"[^a-z0-9]+", " ");
            return Regex.Replace(value, @"\s+", " ").Trim();
        }

        private string ResolveLibraryStatusText(MediaAgentResultItem item)
        {
            List<MediaItem> snapshot;
            lock (_stateLock)
                snapshot = _allItems.ToList();

            if (item.Kind == MediaAgentResultItem.ResultKind.Local)
                return "Already in your library";

            var title = NormalizeLibraryText(item.Title);
            if (string.IsNullOrWhiteSpace(title) || snapshot.Count == 0)
                return "";

            IEnumerable<MediaItem> candidates = snapshot;
            if (item.Kind == MediaAgentResultItem.ResultKind.Movie)
                candidates = candidates.Where(i => string.Equals(i.Type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(i.Type, "movie", StringComparison.OrdinalIgnoreCase));
            else if (item.Kind == MediaAgentResultItem.ResultKind.Music || string.Equals(item.MediaTypeId, "music", StringComparison.OrdinalIgnoreCase))
                candidates = candidates.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase));

            var matches = candidates.Where(i =>
            {
                var localTitle = NormalizeLibraryText(string.IsNullOrWhiteSpace(i.Title) ? Path.GetFileNameWithoutExtension(i.FilePath) ?? "" : i.Title);
                if (!string.Equals(localTitle, title, StringComparison.OrdinalIgnoreCase))
                    return false;

                if (item.Year.HasValue && i.Year > 0 && Math.Abs(i.Year - item.Year.Value) > 1)
                    return false;

                if (!string.IsNullOrWhiteSpace(item.ArtistName))
                {
                    var artist = NormalizeLibraryText(item.ArtistName);
                    var localArtist = NormalizeLibraryText(i.Artist ?? "");
                    if (!string.IsNullOrWhiteSpace(localArtist) && !string.Equals(localArtist, artist, StringComparison.OrdinalIgnoreCase))
                        return false;
                }

                return true;
            }).Take(3).ToList();

            return matches.Count > 0 ? $"Already in your library ({matches.Count})" : "";
        }

        private MediaAgentResultItem EnrichMediaAgentResultItem(MediaAgentResultItem item, string? summary)
        {
            var category = string.IsNullOrWhiteSpace(item.DraftCategory) && item.Kind == MediaAgentResultItem.ResultKind.Movie
                ? DetermineWatchlistCategory(item, summary)
                : item.DraftCategory;

            return new MediaAgentResultItem
            {
                Kind = item.Kind,
                Title = item.Title,
                Subtitle = item.Subtitle,
                MediaTypeId = item.MediaTypeId,
                Year = item.Year,
                Rating = item.Rating,
                Votes = item.Votes,
                Provider = item.Provider,
                Overview = item.Overview,
                Source = item.Source,
                LocalPath = item.LocalPath,
                ExternalQuery = item.ExternalQuery,
                Tags = item.Tags?.ToList() ?? new List<string>(),
                LibraryStatusText = string.IsNullOrWhiteSpace(item.LibraryStatusText) ? ResolveLibraryStatusText(item) : item.LibraryStatusText,
                DraftCategory = category,
                CanPlay = item.CanPlay,
                CanOpenLocation = item.CanOpenLocation,
                SimilarReason = item.SimilarReason,
                ArtistName = item.ArtistName,
                TmdbId = item.TmdbId
            };
        }

        private void SaveMediaAgentDraftsToDisk()
        {
            try
            {
                var directory = Path.GetDirectoryName(MediaAgentDraftsFilePath);
                if (!string.IsNullOrWhiteSpace(directory))
                    Directory.CreateDirectory(directory);

                var payload = new PersistedMediaDrafts
                {
                    Watchlist = _mediaWatchlistDraftItems.Select(ToPersistedMediaDraftItem).ToList(),
                    Playlist = _mediaPlaylistDraftItems.Select(ToPersistedMediaDraftItem).ToList()
                };

                var json = JsonSerializer.Serialize(payload, new JsonSerializerOptions { WriteIndented = true });
                var tmpPath = MediaAgentDraftsFilePath + ".tmp";
                File.WriteAllText(tmpPath, json, Encoding.UTF8);
                File.Move(tmpPath, MediaAgentDraftsFilePath, overwrite: true);
            }
            catch
            {
            }
        }

        private void LoadMediaAgentDraftsFromDisk()
        {
            try
            {
                if (!File.Exists(MediaAgentDraftsFilePath))
                    return;

                var json = File.ReadAllText(MediaAgentDraftsFilePath, Encoding.UTF8);
                var payload = JsonSerializer.Deserialize<PersistedMediaDrafts>(json);
                if (payload == null)
                    return;

                _mediaWatchlistDraftItems.Clear();
                foreach (var item in payload.Watchlist.Select(FromPersistedMediaDraftItem))
                    _mediaWatchlistDraftItems.Add(item);

                _mediaPlaylistDraftItems.Clear();
                foreach (var item in payload.Playlist.Select(FromPersistedMediaDraftItem))
                    _mediaPlaylistDraftItems.Add(item);

                NotifyMediaDraftPropertiesChanged();
            }
            catch
            {
            }
        }

        private void QueueMediaAgentAppsNavigation(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
                return;

            MediaAgentPendingAppsUrl = url.Trim();
            TryNavigateMediaAgentPendingAppsUrl();
        }

        public void NavigateToAppsBrowserUrl(string url)
        {
            try
            {
                _uiDispatcher.Invoke(() =>
                {
                    var apps = Categories.FirstOrDefault(c => string.Equals(c.Id, "apps", StringComparison.OrdinalIgnoreCase));
                    if (apps != null && !ReferenceEquals(SelectedCategory, apps))
                        SelectCategory(apps);
                });
            }
            catch
            {
            }

            QueueMediaAgentAppsNavigation(url);
        }

        public void TryNavigateMediaAgentPendingAppsUrl()
        {
            var url = (MediaAgentPendingAppsUrl ?? "").Trim();
            if (string.IsNullOrWhiteSpace(url) || _appsNavigator == null)
                return;

            try
            {
                _appsNavigator.Invoke(url);
                MediaAgentPendingAppsUrl = "";
            }
            catch
            {
            }
        }

        private void NotifyMediaDraftPropertiesChanged()
        {
            OnPropertyChanged(nameof(MediaWatchlistDraftItems));
            OnPropertyChanged(nameof(MediaPlaylistDraftItems));
            OnPropertyChanged(nameof(MediaWatchlistDraftCount));
            OnPropertyChanged(nameof(MediaPlaylistDraftCount));
            OnPropertyChanged(nameof(HasMediaWatchlistDraftItems));
            OnPropertyChanged(nameof(HasMediaPlaylistDraftItems));
            OnPropertyChanged(nameof(MediaWatchlistDraftHorrorItems));
            OnPropertyChanged(nameof(MediaWatchlistDraftActionItems));
            OnPropertyChanged(nameof(MediaWatchlistDraftNewReleaseItems));
            OnPropertyChanged(nameof(MediaWatchlistDraftToWatchSoonItems));
            CommandManager.InvalidateRequerySuggested();
        }

        private void AddMediaDraftItem(ObservableCollection<MediaAgentResultItem> draft, MediaAgentResultItem item, string draftName)
        {
            var key = GetMediaDraftKey(item);
            if (draft.Any(existing => string.Equals(GetMediaDraftKey(existing), key, StringComparison.OrdinalIgnoreCase)))
            {
                SetMediaAgentState($"{draftName} draft unchanged", false);
                MediaAiLastResponse = $"{draftName.ToUpperInvariant()} DRAFT\nItem already present: {item.DraftDisplayName}";
                return;
            }

            var clone = CloneMediaResultItem(item);
            if (string.Equals(draftName, "watchlist", StringComparison.OrdinalIgnoreCase) && string.IsNullOrWhiteSpace(clone.DraftCategory))
                clone = EnrichMediaAgentResultItem(clone, MediaAgentResultSummary);
            draft.Add(clone);
            SaveMediaAgentDraftsToDisk();
            NotifyMediaDraftPropertiesChanged();
            SetMediaAgentState($"Added to {draftName} draft", false);
            MediaAiLastResponse = $"{draftName.ToUpperInvariant()} DRAFT\nAdded: {item.DraftDisplayName}\nCount: {draft.Count}";
        }

        private void RemoveMediaDraftItem(ObservableCollection<MediaAgentResultItem> draft, MediaAgentResultItem? item, string draftName)
        {
            if (item == null)
                return;

            var existing = draft.FirstOrDefault(entry => string.Equals(GetMediaDraftKey(entry), GetMediaDraftKey(item), StringComparison.OrdinalIgnoreCase));
            if (existing == null)
                return;

            draft.Remove(existing);
            SaveMediaAgentDraftsToDisk();
            NotifyMediaDraftPropertiesChanged();
            SetMediaAgentState($"Removed from {draftName} draft", false);
            MediaAiLastResponse = $"{draftName.ToUpperInvariant()} DRAFT\nRemoved: {existing.DraftDisplayName}\nCount: {draft.Count}";
        }

        private void ClearMediaDraft(ObservableCollection<MediaAgentResultItem> draft, string draftName)
        {
            if (draft.Count == 0)
                return;

            draft.Clear();
            SaveMediaAgentDraftsToDisk();
            NotifyMediaDraftPropertiesChanged();
            SetMediaAgentState($"Cleared {draftName} draft", false);
            MediaAiLastResponse = $"{draftName.ToUpperInvariant()} DRAFT\nCleared.";
        }

        private void CopyMediaDraftNames(ObservableCollection<MediaAgentResultItem> draft, string draftName)
        {
            var content = string.Join(Environment.NewLine, draft.Select(item => item.DraftDisplayName).Where(name => !string.IsNullOrWhiteSpace(name)));
            if (string.IsNullOrWhiteSpace(content))
                return;

            System.Windows.Clipboard.SetText(content);
            SetMediaAgentState($"Copied {draftName} draft", false);
            MediaAiLastResponse = $"{draftName.ToUpperInvariant()} DRAFT\nCopied {draft.Count} item name(s) to clipboard.";
        }

        private void ExportMediaDraft(ObservableCollection<MediaAgentResultItem> draft, string draftName, bool preferM3u)
        {
            if (draft.Count == 0)
                return;

            var hasPaths = preferM3u && draft.Any(item => !string.IsNullOrWhiteSpace(item.LocalPath));
            var dialog = new Microsoft.Win32.SaveFileDialog
            {
                Title = $"Export {draftName} draft",
                Filter = hasPaths ? "Playlist (*.m3u)|*.m3u|Text file (*.txt)|*.txt" : "Text file (*.txt)|*.txt",
                DefaultExt = hasPaths ? ".m3u" : ".txt",
                FileName = $"atlas-{draftName}-draft-{DateTime.Now:yyyyMMdd-HHmmss}{(hasPaths ? ".m3u" : ".txt")}"
            };

            if (dialog.ShowDialog() != true)
                return;

            var lines = hasPaths && string.Equals(Path.GetExtension(dialog.FileName), ".m3u", StringComparison.OrdinalIgnoreCase)
                ? draft.Where(item => !string.IsNullOrWhiteSpace(item.LocalPath)).Select(item => item.LocalPath)
                : draft.Select(item => item.DraftDisplayName);

            File.WriteAllLines(dialog.FileName, lines, Encoding.UTF8);
            SetMediaAgentState($"Exported {draftName} draft", false);
            MediaAiLastResponse = $"{draftName.ToUpperInvariant()} DRAFT\nExported to {dialog.FileName}";
        }

        private void SetMediaAgentRouteChips(string modeChip, string providerChip)
        {
            MediaAgentModeChip = modeChip;
            MediaAgentProviderChip = providerChip;

            var scope = ResolveMediaAiScopeItems();
            var hasPlayable = scope.Any(i => i != null && (i.PlaybackItem != null || IsHttpUrl(i.FilePath, out _)));
            MediaAgentPlaybackChip = hasPlayable ? "Playback ready" : "Playback unavailable";
            MediaAgentQueueChip = hasPlayable ? "Queue ready" : "Queue unavailable";
        }

        private (bool handled, string reply) TryHandleMediaControlIntent(string instruction)
        {
            var lower = (instruction ?? "").Trim().ToLowerInvariant();
            if (string.IsNullOrWhiteSpace(lower))
                return (false, "");

            var isNavigationIntent =
                lower.StartsWith("open ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("go to ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("switch to ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("show ", StringComparison.OrdinalIgnoreCase) ||
                lower.Contains(" tab", StringComparison.OrdinalIgnoreCase) ||
                lower.Contains(" section", StringComparison.OrdinalIgnoreCase);

            if (!isNavigationIntent)
                return (false, "");

            string categoryId;
            string label;

            if (lower.Contains("discover", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "discovery";
                label = "Discovery";
            }
            else if (lower.Contains("movie", StringComparison.OrdinalIgnoreCase) || lower.Contains("film", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "movies";
                label = "Movies";
            }
            else if (lower.Contains("tv", StringComparison.OrdinalIgnoreCase) || lower.Contains("series", StringComparison.OrdinalIgnoreCase) || lower.Contains("show", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "tv";
                label = "TV";
            }
            else if (lower.Contains("music", StringComparison.OrdinalIgnoreCase) || lower.Contains("song", StringComparison.OrdinalIgnoreCase) || lower.Contains("album", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "music";
                label = "Music";
            }
            else if (lower.Contains("game", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "games";
                label = "Games";
            }
            else if (lower.Contains("stream", StringComparison.OrdinalIgnoreCase) || lower.Contains("server", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "servers";
                label = "Streams";
            }
            else if (lower.Contains("app", StringComparison.OrdinalIgnoreCase))
            {
                categoryId = "apps";
                label = "Apps";
            }
            else
            {
                return (false, "");
            }

            MediaCategory? target = null;
            _uiDispatcher.Invoke(() =>
            {
                target = Categories.FirstOrDefault(c => string.Equals(c.Id, categoryId, StringComparison.OrdinalIgnoreCase));
                if (target != null && !ReferenceEquals(SelectedCategory, target))
                    SelectCategory(target);
            });

            if (target == null)
                return (false, "");

            SetMediaAgentRouteChips("Media Control", "MediaHub UI");
            SetMediaAgentResultState("Loaded", $"Switched to {label}.", new[]
            {
                $"Action: switch section",
                $"Target: {label}",
                "MediaHub context updated for follow-up commands."
            });

            return (true, $"MEDIA CONTROL\nSwitched to {label}.");
        }

        private async Task<(bool handled, string reply)> TryHandleMediaAgentIntentAsync(string instruction, CancellationToken ct)
        {
            var lower = (instruction ?? "").Trim().ToLowerInvariant();
            if (string.IsNullOrWhiteSpace(lower))
                return (false, "");

            var mediaControl = TryHandleMediaControlIntent(instruction);
            if (mediaControl.handled)
                return mediaControl;

            var artworkIntent =
                lower.Contains("album art") ||
                lower.Contains("cover art") ||
                lower.Contains("album cover") ||
                lower.Contains("artwork");

            if (artworkIntent)
            {
                var localSourceItems = ResolveMediaAgentLocalSourceItems(lower, out var usesVisibleScope);
                var sourceLabel = usesVisibleScope ? "Local library · current visible scope" : "Local library · full index";
                var query = ExtractLocalSearchQuery(instruction);

                var musicSource = localSourceItems
                    .Where(i => i != null && string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase))
                    .ToList();

                var targets = string.Equals(query, "all items", StringComparison.OrdinalIgnoreCase)
                    ? musicSource.Take(80).ToList()
                    : SearchLibraryItems(musicSource, query, "music", 80);

                if (targets.Count == 0)
                {
                    SetMediaAgentRouteChips("Album Art", sourceLabel);
                    SetMediaAgentResultState("Empty", "No matching music items found for album-art fetch.", new[]
                    {
                        $"Searched: {query}",
                        $"Source: {sourceLabel}",
                        "Next step: try artist + album keywords, or scan your music library first."
                    });
                    return (true, "ALBUM ART\nNo matching music items found.");
                }

                SetMediaAgentRouteChips("Album Art", "MusicBrainz / ReccoBeats / iTunes");
                SetMediaAgentResultState("Loading", $"Fetching album art for {targets.Count} item(s)...");
                await OptimizeArtworkOnlyAsync(targets, $"Fetching album art · {targets.Count} item(s)").ConfigureAwait(false);

                var cards = targets.Take(20).Select(i => BuildLocalResultCard(
                    i,
                    sourceLabel,
                    "Artwork refresh",
                    string.IsNullOrWhiteSpace(i.Artist) ? (i.Type ?? "music") : $"{i.Artist} — {i.Album ?? i.Type ?? "music"}",
                    "Album-art refresh requested by Media Agent.",
                    i.Genres)).ToList();

                SetMediaAgentResultItems("Loaded", $"Album-art refresh completed for {targets.Count} track(s).", cards);
                return (true, $"ALBUM ART\nSource: {sourceLabel}\nProcessed: {targets.Count}");
            }

            var isLocalIntent =
                lower.StartsWith("local:", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("play ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("find ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("show ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("search ", StringComparison.OrdinalIgnoreCase) ||
                lower.Contains("playlist") ||
                lower.Contains("album art") ||
                lower.Contains("cover art") ||
                lower.Contains("artwork") ||
                lower.Contains("missing metadata") ||
                lower.Contains("duplicate") ||
                lower.Contains("recent") ||
                lower.Contains("cleanup") ||
                lower.Contains("my library") ||
                lower.Contains("local library") ||
                lower.Contains("downloads") ||
                lower.Contains("large media") ||
                lower.Contains("large file");

            var prefersLocalRouting =
                lower.StartsWith("local:", StringComparison.OrdinalIgnoreCase) ||
                lower.Contains("my library") ||
                lower.Contains("local library") ||
                lower.Contains("playlist") ||
                lower.Contains("album art") ||
                lower.Contains("cover art") ||
                lower.Contains("artwork") ||
                lower.Contains("missing metadata") ||
                lower.Contains("duplicate") ||
                lower.Contains("recently added") ||
                lower.Contains("newest downloads") ||
                lower.Contains("latest downloads") ||
                lower.Contains("large media") ||
                lower.Contains("large file");

            if (isLocalIntent && prefersLocalRouting)
                return HandleLocalMediaIntent(instruction);

            var isOnlineIntent =
                lower.StartsWith("online:", StringComparison.OrdinalIgnoreCase) ||
                lower.Contains("discover") ||
                lower.Contains("trending") ||
                lower.Contains("new release") ||
                Regex.IsMatch(lower, @"\bnew\b.*\breleases?\b", RegexOptions.IgnoreCase) ||
                lower.Contains("similar") ||
                lower.Contains(" like ") ||
                lower.Contains("where to watch") ||
                lower.Contains("genre") ||
                lower.Contains("movie") ||
                lower.Contains("movies") ||
                lower.Contains("film") ||
                lower.Contains("films") ||
                ResolveTmdbGenresFromInstruction(lower).Count > 0 ||
                lower.Contains("year") ||
                Regex.IsMatch(lower, @"\b(19|20)\d{2}\b");

            if (isOnlineIntent)
                return await HandleOnlineMediaIntentAsync(instruction, ct).ConfigureAwait(false);

            if (!isLocalIntent)
                return (false, "");

            return HandleLocalMediaIntent(instruction);
        }

        private (bool handled, string reply) HandleLocalMediaIntent(string instruction)
        {
            var lower = (instruction ?? "").Trim().ToLowerInvariant();
            var localSourceItems = ResolveMediaAgentLocalSourceItems(lower, out var usesVisibleScope);
            var sourceLabel = usesVisibleScope ? "Local library · current visible scope" : "Local library · full index";
            SetMediaAgentRouteChips("Local Library", sourceLabel);

            if (localSourceItems.Count == 0)
            {
                SetMediaAgentResultState("Empty", "No media library items are indexed yet. Add or scan folders first.", new[]
                {
                    $"Searched: {(instruction ?? "").Trim()}",
                    $"Source: {sourceLabel}",
                    "Why empty: media index has no items.",
                    "Next step: add folders and run a media scan, then retry this command."
                });
                return (true, "No media library items are indexed yet. Add or scan folders first.");
            }

            if ((lower.Contains("horror") && (lower.Contains("movie") || lower.Contains("movies"))) ||
                (lower.Contains("horror") && lower.Contains("library")))
            {
                var horrorTerms = new[] { "horror", "slasher", "haunted", "supernatural", "possession", "zombie", "vampire", "monster", "paranormal", "ghost" };
                var movieItems = localSourceItems
                    .Where(i => i != null && string.Equals(i.Type, "movies", StringComparison.OrdinalIgnoreCase))
                    .ToList();

                var matches = movieItems
                    .Select(i => new
                    {
                        Item = i,
                        StrongGenre = (i.Genres?.Any(g => horrorTerms.Any(t => g.Contains(t, StringComparison.OrdinalIgnoreCase))) ?? false),
                        WeakText = horrorTerms.Any(t =>
                            (i.Title ?? "").Contains(t, StringComparison.OrdinalIgnoreCase) ||
                            (i.FilePath ?? "").Contains(t, StringComparison.OrdinalIgnoreCase) ||
                            (i.Overview ?? "").Contains(t, StringComparison.OrdinalIgnoreCase))
                    })
                    .Where(x => x.StrongGenre || x.WeakText)
                    .OrderByDescending(x => x.StrongGenre)
                    .ThenByDescending(x => x.Item.Rating)
                    .ThenByDescending(x => x.Item.Year)
                    .Select(x => x.Item)
                    .Take(20)
                    .ToList();

                if (matches.Count == 0)
                {
                    SetMediaAgentResultState("Empty", "No local horror movies found.", new[]
                    {
                        "Searched: horror movies in my library",
                        $"Source: {sourceLabel}",
                        "Why empty: no indexed movie items matched horror genres or horror-style title/path terms.",
                        "Next step: Add/scan media folders first, improve movie genre metadata, or search online horror movies instead."
                    });
                    return (true, "No local horror movies found. Search online horror movies instead.");
                }

                var localHorrorItems = matches.Select(i => new MediaAgentResultItem
                {
                    Kind = MediaAgentResultItem.ResultKind.Local,
                    MediaTypeId = i.Type ?? "",
                    Title = string.IsNullOrWhiteSpace(i.Title) ? System.IO.Path.GetFileNameWithoutExtension(i.FilePath) ?? "Untitled" : i.Title,
                    Subtitle = i.Type ?? "",
                    Year = i.Year > 0 ? (int?)i.Year : null,
                    Rating = i.Rating > 0 ? (double?)i.Rating : null,
                    Overview = (i.Overview ?? "").Length > 180 ? i.Overview!.Substring(0, 180) + "…" : (i.Overview ?? ""),
                    Source = sourceLabel,
                    Provider = "Local",
                    LocalPath = i.FilePath ?? "",
                    Tags = i.Genres ?? new List<string>(),
                    CanPlay = !string.IsNullOrWhiteSpace(i.FilePath),
                    CanOpenLocation = !string.IsNullOrWhiteSpace(i.FilePath) && System.IO.File.Exists(i.FilePath)
                }).ToList();
                SetMediaAgentResultItems("Loaded", $"Found {matches.Count} horror-like movie item(s) in local library.", localHorrorItems);
                return (true, $"LOCAL HORROR\nSource: {sourceLabel}\nResults: {matches.Count}");
            }

            if ((lower.Contains("local-search") || lower.StartsWith("find ", StringComparison.OrdinalIgnoreCase) || lower.StartsWith("show ", StringComparison.OrdinalIgnoreCase) || lower.StartsWith("search ", StringComparison.OrdinalIgnoreCase))
                && !lower.Contains("missing metadata") && !lower.Contains("missing-metadata")
                && !lower.Contains("duplicate") && !lower.Contains("cleanup")
                && !lower.Contains("recently added") && !lower.Contains("recent added") && !lower.Contains("show recent")
                && !lower.Contains("large media") && !lower.Contains("large files") && !lower.Contains("newest downloads"))
            {
                var searchTypeId = ResolveMediaTypeFromInstruction(lower);
                var searchQuery = ExtractLocalSearchQuery(instruction);
                var results = SearchLibraryItems(localSourceItems, searchQuery, searchTypeId, 40);

                if (results.Count == 0)
                {
                    SetMediaAgentResultState("Empty", $"No local matches for '{searchQuery}'.", new[]
                    {
                        $"Searched: {searchQuery}",
                        $"Source: {sourceLabel}",
                        $"Why empty: no indexed items matched the query tokens{(string.IsNullOrWhiteSpace(searchTypeId) ? "." : $" in type '{searchTypeId}'.")}",
                        "Next step: try a broader keyword, remove strict genre words, or rescan folders to improve metadata coverage."
                    });
                    return (true, $"No local matches for '{searchQuery}'.");
                }

                var localSearchItems = results.Take(20).Select(i => new MediaAgentResultItem
                {
                    Kind = MediaAgentResultItem.ResultKind.Local,
                    MediaTypeId = i.Type ?? "",
                    Title = string.IsNullOrWhiteSpace(i.Title) ? System.IO.Path.GetFileNameWithoutExtension(i.FilePath) ?? "Untitled" : i.Title,
                    ArtistName = i.Artist ?? "",
                    Subtitle = string.IsNullOrWhiteSpace(i.Artist) ? (i.Type ?? "") : $"{i.Artist} — {i.Album ?? i.Type ?? ""}",
                    Year = i.Year > 0 ? (int?)i.Year : null,
                    Rating = i.Rating > 0 ? (double?)i.Rating : null,
                    Source = sourceLabel,
                    Provider = "Local",
                    LocalPath = i.FilePath ?? "",
                    Tags = i.Genres ?? new List<string>(),
                    CanPlay = !string.IsNullOrWhiteSpace(i.FilePath),
                    CanOpenLocation = !string.IsNullOrWhiteSpace(i.FilePath) && System.IO.File.Exists(i.FilePath)
                }).ToList();
                SetMediaAgentResultItems("Loaded", $"Local search returned {results.Count} item(s).", localSearchItems);
                return (true, $"LOCAL SEARCH\nSource: {sourceLabel}\nResults: {results.Count}");
            }

            if (lower.StartsWith("play ", StringComparison.OrdinalIgnoreCase) || lower.Contains("play-local"))
            {
                var query = Regex.Replace(instruction, "^(play|local:\\s*play)\\s+", "", RegexOptions.IgnoreCase).Trim();
                if (string.IsNullOrWhiteSpace(query))
                    return (true, "PLAY LOCAL requires a title or keyword.");

                if (lower.Contains("newest download") || lower.Contains("latest download"))
                {
                    var playable = localSourceItems
                        .Where(i => i != null && (i.PlaybackItem != null || IsHttpUrl(i.FilePath, out _)))
                        .ToList();

                    var fromDownloads = playable
                        .Where(i => (i.FilePath ?? "").IndexOf("download", StringComparison.OrdinalIgnoreCase) >= 0)
                        .ToList();

                    var candidatePool = fromDownloads.Count > 0 ? fromDownloads : playable;
                    var newest = candidatePool
                        .Select(i => new { Item = i, Stamp = GetBestLocalTimestampUtc(i) })
                        .OrderByDescending(x => x.Stamp ?? DateTime.MinValue)
                        .FirstOrDefault();

                    if (newest?.Item == null)
                    {
                        var downloadsConfigured = HasMediaDownloadsFolder;
                        SetMediaAgentResultState("Empty", downloadsConfigured ? "Downloads are configured but no indexed download items were found." : "Downloads folder is not indexed yet.", new[]
                        {
                            "Searched: newest downloads",
                            $"Source: {sourceLabel}",
                            downloadsConfigured ? "Why empty: no playable indexed items were found under download paths." : "Why empty: Atlas media downloads folder is not configured/scanned into the library index.",
                            "Next step: Add/scan media folders first. If using Downloads, ensure the Downloads folder is included in your library scan."
                        });
                        return (true, downloadsConfigured ? "No indexed download items were found." : "Downloads not indexed. Add/scan media folders first.");
                    }

                    var newestTitle = string.IsNullOrWhiteSpace(newest.Item.Title) ? Path.GetFileNameWithoutExtension(newest.Item.FilePath) ?? "Untitled" : newest.Item.Title;
                    SetMediaAgentResultState("Approval required", $"Newest downloaded item identified: {newestTitle}.", new[]
                    {
                        $"Source: {sourceLabel}",
                        $"Selected: {newestTitle}",
                        $"Timestamp: {(newest.Stamp.HasValue ? newest.Stamp.Value.ToString("yyyy-MM-dd HH:mm", CultureInfo.InvariantCulture) : "unknown")}",
                        "Approval required: playback command exists. Confirm before starting playback or adding to queue."
                    });
                    return (true, $"NEWEST DOWNLOADS\nCandidate: {newestTitle}\nApproval required before playback.");
                }

                var items = SearchLibraryItems(localSourceItems, query, null, 20);
                var target = items.FirstOrDefault(i => i != null && (i.PlaybackItem != null || IsHttpUrl(i.FilePath, out _)));
                if (target == null)
                {
                    SetMediaAgentResultState("Empty", $"No playable local match for '{query}'.", new[]
                    {
                        $"Searched: {query}",
                        $"Source: {sourceLabel}",
                        "Why empty: matching items exist but none appear playable, or no item matched this query.",
                        "Next step: try a broader title keyword or confirm local files are playable and indexed."
                    });
                    return (true, $"No playable local match for '{query}'.");
                }

                var title = string.IsNullOrWhiteSpace(target.Title) ? Path.GetFileNameWithoutExtension(target.FilePath) ?? "Untitled" : target.Title;
                SetMediaAgentResultState("Approval required", $"Playable local item found: {title}.", new[]
                {
                    $"Source: {sourceLabel}",
                    $"Selected: {title}",
                    "Approval required: playback command exists. Confirm before starting playback."
                });
                return (true, $"PLAY LOCAL\nCandidate: {title}\nApproval required before playback.");
            }

            if (lower.Contains("playlist-build") || lower.Contains("build playlist") || lower.Contains("playlist"))
            {
                if (lower.Contains("save") || lower.Contains("write") || lower.Contains("export"))
                {
                    SetMediaAgentResultState("Approval required", "Playlist save/export blocked pending approval.");
                    return (true, "APPROVAL REQUIRED - playlist save/export is preview-only in Media Agent.");
                }

                var scope = localSourceItems
                    .Where(i => i != null && string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase))
                    .ToList();

                var gymKeywords = new[] { "gym", "workout", "run", "cardio", "training", "energy", "power", "pump", "rock", "metal", "edm", "dance", "hip hop", "hip-hop", "electronic", "upbeat", "remix" };
                var gymGenres = new[] { "rock", "metal", "hip hop", "hip-hop", "rap", "electronic", "dance", "edm", "workout", "industrial", "punk" };
                var ranked = scope
                    .Select(i => new
                    {
                        Item = i,
                        Score = gymKeywords.Count(k =>
                            (i.Title ?? "").Contains(k, StringComparison.OrdinalIgnoreCase) ||
                            (i.Artist ?? "").Contains(k, StringComparison.OrdinalIgnoreCase) ||
                            (i.Album ?? "").Contains(k, StringComparison.OrdinalIgnoreCase)) +
                            (i.Genres?.Count(g => gymGenres.Any(tag => g.Contains(tag, StringComparison.OrdinalIgnoreCase))) ?? 0)
                    })
                    .OrderByDescending(x => x.Score)
                    .ThenByDescending(x => x.Item.Rating)
                    .ThenBy(x => x.Item.Title ?? "", StringComparer.OrdinalIgnoreCase)
                    .Select(x => x.Item)
                    .Take(20)
                    .ToList();

                if (ranked.Count == 0)
                {
                    SetMediaAgentResultState("Empty", "No music tracks available for playlist build.", new[]
                    {
                        "Searched: gym playlist from local music",
                        $"Source: {sourceLabel}",
                        "Why empty: no music items are currently indexed in this local source.",
                        "Next step: add a music folder and run scan, then retry the playlist command."
                    });
                    return (true, "No music tracks available for playlist build.");
                }

                var previewLines = ranked.Select(BuildMediaItemLabel).ToList();
                previewLines.Insert(0, $"Source: {sourceLabel}");
                previewLines.Add("Approval required: queue command exists. Confirm before adding this draft to queue.");
                previewLines.Add("Copy playlist names: available from this draft list.");
                var playlistDraftItems = ranked.Select(i => BuildLocalResultCard(
                    i,
                    sourceLabel,
                    "Local",
                    string.IsNullOrWhiteSpace(i.Artist) ? (i.Type ?? "music") : $"{i.Artist} — {i.Album ?? i.Type ?? "music"}",
                    "Drafted from local library for gym playlist.",
                    i.Genres)).ToList();

                _mediaPlaylistDraftItems.Clear();
                foreach (var draftItem in playlistDraftItems)
                    _mediaPlaylistDraftItems.Add(draftItem);
                SaveMediaAgentDraftsToDisk();
                NotifyMediaDraftPropertiesChanged();

                SetMediaAgentResultItems("Loaded", $"Gym playlist draft prepared: {ranked.Count} item(s).", playlistDraftItems);
                return (true, $"PLAYLIST BUILD\nSource: {sourceLabel}\nDraft items: {ranked.Count}");
            }

            if (lower.Contains("missing-metadata") || lower.Contains("missing metadata"))
            {
                var titleMissingItems = localSourceItems.Where(i => i != null && string.IsNullOrWhiteSpace(i.Title)).Take(8).ToList();
                var artistMissingItems = localSourceItems.Where(i => i != null && string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase) && string.IsNullOrWhiteSpace(i.Artist)).Take(8).ToList();
                var albumMissingItems = localSourceItems.Where(i => i != null && string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase) && string.IsNullOrWhiteSpace(i.Album)).Take(8).ToList();
                var yearMissingItems = localSourceItems.Where(i => i != null && i.Year <= 0).Take(8).ToList();
                var durationMissingItems = localSourceItems.Where(i => i != null && i.Duration <= TimeSpan.Zero).Take(8).ToList();
                var genreMissingItems = localSourceItems.Where(i => i != null && (i.Genres == null || i.Genres.Count == 0)).Take(8).ToList();

                var totalMissing = titleMissingItems.Count + artistMissingItems.Count + albumMissingItems.Count + yearMissingItems.Count + durationMissingItems.Count + genreMissingItems.Count;
                if (totalMissing == 0)
                {
                    SetMediaAgentResultState("Empty", "No obvious missing metadata candidates found.", new[]
                    {
                        "Searched: missing metadata",
                        $"Source: {sourceLabel}",
                        "Why empty: indexed items already have basic title/artist/album metadata coverage.",
                        "Next step: run a full rescan or request detailed metadata enrichment for stricter checks."
                    });
                    return (true, "No obvious missing metadata candidates found.");
                }

                var issueMap = new Dictionary<string, (MediaItem Item, HashSet<string> Issues)>(StringComparer.OrdinalIgnoreCase);

                void AddMissingIssue(IEnumerable<MediaItem> items, string issue)
                {
                    foreach (var item in items.Where(i => i != null))
                    {
                        var key = string.IsNullOrWhiteSpace(item.FilePath)
                            ? $"{item.Type}|{item.Title}|{item.Artist}|{item.Album}"
                            : item.FilePath;

                        if (!issueMap.TryGetValue(key, out var entry))
                            entry = (item, new HashSet<string>(StringComparer.OrdinalIgnoreCase));

                        entry.Issues.Add(issue);
                        issueMap[key] = entry;
                    }
                }

                AddMissingIssue(titleMissingItems, "title");
                AddMissingIssue(artistMissingItems, "artist");
                AddMissingIssue(albumMissingItems, "album");
                AddMissingIssue(yearMissingItems, "year");
                AddMissingIssue(durationMissingItems, "duration");
                AddMissingIssue(genreMissingItems, "genre");

                var missingCards = issueMap.Values
                    .Select(entry =>
                    {
                        var issues = entry.Issues.OrderBy(x => x, StringComparer.OrdinalIgnoreCase).ToList();
                        return BuildLocalResultCard(
                            entry.Item,
                            sourceLabel,
                            "Local",
                            $"Metadata issue · {entry.Item.Type}",
                            $"Missing: {string.Join(", ", issues)}",
                            issues);
                    })
                    .OrderByDescending(item => item.Tags.Count)
                    .ThenBy(item => item.Title, StringComparer.OrdinalIgnoreCase)
                    .ToList();

                SetMediaAgentResultItems("Loaded", $"Missing metadata groups found in local library. Items: {missingCards.Count}", missingCards);
                return (true, $"MISSING METADATA\nGroups reported.");
            }

            if (lower.Contains("duplicate-media") || lower.Contains("duplicate"))
            {
                var groups = localSourceItems
                    .GroupBy(i => $"{NormalizeForDuplicateGroup(i)}|{(i.Type ?? "").ToLowerInvariant()}")
                    .Where(g => !string.IsNullOrWhiteSpace(g.Key) && g.Count() > 1)
                    .OrderByDescending(g => g.Count())
                    .ToList();

                if (groups.Count == 0)
                {
                    SetMediaAgentResultState("Empty", "No duplicate-looking local media groups found.", new[]
                    {
                        "Searched: duplicates",
                        $"Source: {sourceLabel}",
                        "Why empty: no normalized title/type groups had more than one item.",
                        "Next step: rescan folders if you expect duplicates not present in the current index."
                    });
                    return (true, "No duplicate-looking local media groups found.");
                }

                var duplicateCards = groups
                    .Take(20)
                    .Select(group =>
                    {
                        var sample = group.First();
                        var sampleNames = group
                            .Select(item => Path.GetFileName(item.FilePath))
                            .Where(name => !string.IsNullOrWhiteSpace(name))
                            .Distinct(StringComparer.OrdinalIgnoreCase)
                            .Take(3)
                            .ToList();

                        return BuildLocalResultCard(
                            sample,
                            sourceLabel,
                            "Local",
                            $"Duplicate-looking group · {group.Count()} copies",
                            sampleNames.Count > 0
                                ? $"Review duplicates. Sample files: {string.Join(", ", sampleNames)}"
                                : $"Review duplicates. Group contains {group.Count()} local items.",
                            new[] { "duplicate", group.Count() + " copies" });
                    })
                    .ToList();

                SetMediaAgentResultItems("Loaded", $"Duplicate-looking groups: {duplicateCards.Count}", duplicateCards);
                return (true, $"DUPLICATE MEDIA\nGroups: {groups.Count}");
            }

            if (lower.Contains("large media") || lower.Contains("large file") || lower.Contains("large files"))
            {
                const long thresholdBytes = 1024L * 1024L * 1024L;
                var large = localSourceItems
                    .Select(i => new { Item = i, Size = GetMediaFileSizeBytes(i) })
                    .Where(x => x.Size >= thresholdBytes)
                    .OrderByDescending(x => x.Size)
                    .Take(20)
                    .ToList();

                if (large.Count == 0)
                {
                    SetMediaAgentResultState("Empty", "No large indexed media files found over 1 GB.", new[]
                    {
                        "Searched: large media files",
                        $"Source: {sourceLabel}",
                        "Why empty: no indexed files exceeded the 1 GB review threshold.",
                        "Next step: lower the threshold in a future command if you want a broader storage review."
                    });
                    return (true, "No large indexed media files found over 1 GB.");
                }

                var lines = new List<string> { $"Source: {sourceLabel}" };
                lines.AddRange(large.Select(x => $"{BuildMediaItemLabel(x.Item)} · {FormatBytes(x.Size)} · review for cleanup"));
                SetMediaAgentResultState("Loaded", $"Large media files over 1 GB: {large.Count}", lines);
                return (true, $"LARGE MEDIA\nFiles: {large.Count}");
            }

            if (lower.Contains("recent-local") || lower.Contains("recent") || lower.Contains("recently added"))
            {
                var recent = localSourceItems
                    .Select(i => new { Item = i, Stamp = GetBestLocalTimestampUtc(i) })
                    .Where(x => x.Stamp.HasValue)
                    .OrderByDescending(x => x.Stamp!.Value)
                    .ToList();

                if (recent.Count == 0)
                {
                    SetMediaAgentResultState("Empty", "No local timestamps available for recent additions.", new[]
                    {
                        "Searched: recent local items",
                        $"Source: {sourceLabel}",
                        "Why empty: indexed items do not expose usable file timestamps.",
                        "Next step: verify files exist on disk and rerun scan to refresh timestamp metadata."
                    });
                    return (true, "No local timestamps available for recent additions.");
                }

                var recentCards = recent
                    .Take(20)
                    .Select(x => BuildLocalResultCard(
                        x.Item,
                        sourceLabel,
                        "Local",
                        $"Recent addition · {x.Stamp!.Value.ToLocalTime():yyyy-MM-dd HH:mm}",
                        "Best effort based on local file or playback timestamp.",
                        x.Item.Genres))
                    .ToList();

                SetMediaAgentResultItems("Loaded", "Recent local additions (best effort by file timestamp).", recentCards);
                return (true, "RECENT LOCAL\nShowing recent additions from local file timestamps.");
            }

            if (lower.Contains("library-cleanup") || lower.Contains("cleanup"))
            {
                var duplicates = localSourceItems
                    .GroupBy(i => $"{NormalizeForDuplicateCheck(i.Title)}|{(i.Type ?? "").ToLowerInvariant()}")
                    .Count(g => !string.IsNullOrWhiteSpace(g.Key) && g.Count() > 1);
                var missingFiles = localSourceItems.Count(i => IsLikelyMissingLocalFile(i.FilePath));

                var lines = new List<string>
                {
                    $"Source: {sourceLabel}",
                    $"Scope size: {localSourceItems.Count}",
                    $"Duplicate-looking groups: {duplicates}",
                    $"Missing local files: {missingFiles}",
                    "Preview only. Destructive cleanup remains approval-gated."
                };
                SetMediaAgentResultState("Loaded", "Local library cleanup plan generated.", lines);
                return (true, "LOCAL LIBRARY CLEANUP\nPreview generated. Approval required for destructive actions.");
            }

            return (false, "");
        }

        private async Task<(bool handled, string reply)> HandleOnlineMediaIntentAsync(string instruction, CancellationToken ct)
        {
            var lower = (instruction ?? "").Trim().ToLowerInvariant();
            var tmdbKey = (IntegrationKeyStore.GetDecrypted("tmdb") ?? "").Trim();
            var hasTmdb = !string.IsNullOrWhiteSpace(tmdbKey);
            var hasTrakt = !string.IsNullOrWhiteSpace((TraktClientId ?? "").Trim());
            var hasSpotify = !string.IsNullOrWhiteSpace((IntegrationKeyStore.GetDecrypted("spotify_client_id") ?? "").Trim()) &&
                             !string.IsNullOrWhiteSpace((IntegrationKeyStore.GetDecrypted("spotify_client_secret") ?? "").Trim());
            var hasLastFm = !string.IsNullOrWhiteSpace((IntegrationKeyStore.GetDecrypted("lastfm_key") ?? "").Trim());

            SetMediaAgentRouteChips("Online Discovery", "Provider: checking...");
            SetMediaAgentResultState("Loading", "Resolving online discovery providers...");

            var newReleasesIntent =
                Regex.IsMatch(lower, @"\bnew\b.*\breleases?\b", RegexOptions.IgnoreCase) ||
                Regex.IsMatch(lower, @"\breleases?\b.*\blast\b.*\bmonths?\b", RegexOptions.IgnoreCase) ||
                lower.Contains("new release") ||
                lower.Contains("last 2 months") ||
                lower.Contains("last two months");
            var musicLikeIntent = lower.Contains("music like") || Regex.IsMatch(lower, @"\blike\s+", RegexOptions.IgnoreCase);
            var movieWordsPresent = lower.Contains("movie") || lower.Contains("movies") || lower.Contains("film") || lower.Contains("films");
            var detectedGenres = ResolveTmdbGenresFromInstruction(lower);
            var hasGenreHint = detectedGenres.Count > 0;
            var hasDiscoveryCue =
                lower.Contains("best") ||
                lower.Contains("top") ||
                lower.Contains("discover") ||
                lower.Contains("find") ||
                lower.Contains("recommend") ||
                lower.Contains("trending") ||
                Regex.IsMatch(lower, @"\b(19|20)\d{2}\b") ||
                Regex.IsMatch(lower, @"\b(19|20)\d0s\b") ||
                lower.Contains("last") && lower.Contains("years");
            var movieDiscoveryIntent = (movieWordsPresent || hasGenreHint) && hasDiscoveryCue;

            if (musicLikeIntent)
            {
                var seedArtist = ExtractMusicLikeArtist(instruction);

                if (hasSpotify)
                {
                    var spotify = await TryGetSpotifyRelatedArtistsAsync(seedArtist, ct).ConfigureAwait(false);
                    if (spotify.relatedArtists.Count > 0)
                    {
                        SetMediaAgentRouteChips("Online Discovery", "Provider: Spotify");
                        var spotifyItems = spotify.relatedArtists.Select(line =>
                        {
                            var parts = line.Split(new[] { " · " }, StringSplitOptions.None);
                            return new MediaAgentResultItem
                            {
                                Kind = MediaAgentResultItem.ResultKind.Music,
                                MediaTypeId = "music",
                                Title = parts.Length > 0 ? parts[0] : line,
                                Subtitle = parts.Length > 1 ? string.Join(" · ", parts.Skip(1)) : "",
                                Provider = "Spotify",
                                Source = "Spotify",
                                SimilarReason = $"Related to {spotify.seedArtist}",
                                ExternalQuery = parts.Length > 0 ? parts[0].Trim() : line
                            };
                        }).ToList();
                        SetMediaAgentResultItems("Loaded", $"Spotify related artists for '{spotify.seedArtist}': {spotify.relatedArtists.Count}", spotifyItems);
                        return (true, $"ONLINE DISCOVERY · MUSIC\nProvider: Spotify\nResults: {spotify.relatedArtists.Count}");
                    }
                }

                var musicBrainz = await TryGetMusicBrainzSimilarArtistsAsync(seedArtist, ct).ConfigureAwait(false);
                if (musicBrainz.Count > 0)
                {
                    SetMediaAgentRouteChips("Online Discovery", "Provider: MusicBrainz");
                    var mbItems = musicBrainz.Select(line =>
                    {
                        var parts = line.Split(new[] { " · " }, StringSplitOptions.None);
                        return new MediaAgentResultItem
                        {
                            Kind = MediaAgentResultItem.ResultKind.Music,
                            MediaTypeId = "music",
                            Title = parts.Length > 0 ? parts[0] : line,
                            Subtitle = parts.Length > 1 ? string.Join(" · ", parts.Skip(1)) : "",
                            Provider = "MusicBrainz",
                            Source = "MusicBrainz",
                            SimilarReason = $"Similar to {seedArtist}",
                            ExternalQuery = parts.Length > 0 ? parts[0].Trim() : line
                        };
                    }).ToList();
                    SetMediaAgentResultItems("Loaded", $"MusicBrainz similar artists for '{seedArtist}': {musicBrainz.Count}", mbItems);
                    return (true, $"ONLINE DISCOVERY · MUSIC\nProvider: MusicBrainz\nResults: {musicBrainz.Count}");
                }

                if (hasLastFm)
                {
                    var lastFm = await TryGetLastFmSimilarArtistsAsync(seedArtist, ct).ConfigureAwait(false);
                    if (lastFm.Count > 0)
                    {
                        SetMediaAgentRouteChips("Online Discovery", "Provider: Last.fm");
                        var lfmItems = lastFm.Select(line =>
                        {
                            var parts = line.Split(new[] { " · " }, StringSplitOptions.None);
                            return new MediaAgentResultItem
                            {
                                Kind = MediaAgentResultItem.ResultKind.Music,
                                MediaTypeId = "music",
                                Title = parts.Length > 0 ? parts[0] : line,
                                Subtitle = parts.Length > 1 ? string.Join(" · ", parts.Skip(1)) : "",
                                Provider = "Last.fm",
                                Source = "Last.fm",
                                SimilarReason = $"Similar to {seedArtist}",
                                ExternalQuery = parts.Length > 0 ? parts[0].Trim() : line
                            };
                        }).ToList();
                        SetMediaAgentResultItems("Loaded", $"Last.fm similar artists for '{seedArtist}': {lastFm.Count}", lfmItems);
                        return (true, $"ONLINE DISCOVERY · MUSIC\nProvider: Last.fm\nResults: {lastFm.Count}");
                    }
                }

                var aiFallback = await BuildAiMusicFallbackAsync(seedArtist, ct).ConfigureAwait(false);
                if (aiFallback.Count >= 5)
                {
                    SetMediaAgentRouteChips("Online Discovery", "Provider: AI fallback (not live provider data)");
                    SetMediaAgentResultState("Loaded", "AI recommendation, not live provider data.", aiFallback);
                    return (true, "ONLINE DISCOVERY · MUSIC\nProvider: AI fallback (not live provider data)");
                }

                SetMediaAgentRouteChips("Online Discovery", "Provider: AI fallback (not live provider data)");
                SetMediaAgentResultState("Error", "Spotify returned no results and AI fallback failed.", new[]
                {
                    $"Searched: music like {seedArtist}",
                    "Source: AI fallback (not live provider data)",
                    "Why empty: Spotify/MusicBrainz/Last.fm returned no similar rows and AI fallback produced fewer than 5 recommendations.",
                    "Next step: verify provider keys and AI availability, then retry."
                });
                return (true, "ONLINE DISCOVERY · MUSIC\nSpotify returned no results and AI fallback failed.");
            }

            if (lower.Contains("music"))
            {
                if (hasSpotify || hasLastFm)
                {
                    SetMediaAgentRouteChips("Online Discovery", hasSpotify ? "Provider: Spotify" : "Provider: Last.fm");
                    SetMediaAgentResultState("Loaded", "Music discovery provider configured.", new[]
                    {
                        hasSpotify ? "Spotify is configured for live album search." : "Last.fm is configured for live album metadata.",
                        "Tip: include artist + album for best live lookup precision."
                    });
                    return (true, "ONLINE DISCOVERY · MUSIC\nConfigured provider found. Use artist+album for precise results.");
                }

                SetMediaAgentRouteChips("Online Discovery", "Provider: AI fallback (not live DB)");
                SetMediaAgentResultState("Empty", "No live music discovery provider configured.", new[]
                {
                    "AI fallback available for recommendations only.",
                    "This is not a live database result."
                });
                return (true, "ONLINE DISCOVERY · MUSIC\nNo live provider configured. AI recommendation mode only (not live database).");
            }

            if (lower.Contains("where to watch"))
            {
                SetMediaAgentRouteChips("Online Discovery", "Provider: unavailable for watch availability");
                SetMediaAgentResultState("Empty", "Where-to-watch provider is not configured in Media Agent.", new[]
                {
                    "TMDB/Trakt credentials do not provide watch-provider lookup here.",
                    "No live where-to-watch results returned."
                });
                return (true, "WHERE TO WATCH\nUnavailable: no configured watch-availability provider in this module.");
            }

            if ((movieDiscoveryIntent || newReleasesIntent) && !hasTmdb)
            {
                SetMediaAgentRouteChips("Online Discovery", "Provider: unavailable");
                SetMediaAgentResultState("Error", "TMDB provider is required for this movie discovery request.", new[]
                {
                    $"Searched: {(movieDiscoveryIntent ? "movie discovery" : "new releases")}",
                    "Source: TMDB discover/movie",
                    "Why unavailable: TMDB key is not configured.",
                    "Next step: configure TMDB API key, then retry the same command."
                });
                return (true, "ONLINE DISCOVERY\nUnavailable: TMDB provider is not configured.");
            }

            if ((movieDiscoveryIntent || newReleasesIntent) && hasTmdb)
            {
                var discovery = new TmdbDiscoveryProvider();
                var today = DateTime.UtcNow.Date;
                var genreCsv = detectedGenres.Count > 0
                    ? string.Join(",", detectedGenres.Select(g => g.id.ToString(CultureInfo.InvariantCulture)))
                    : "";
                var genreNameLabel = detectedGenres.Count > 0
                    ? string.Join(", ", detectedGenres.Select(g => g.name))
                    : "general";
                var genreParam = string.IsNullOrWhiteSpace(genreCsv) ? "" : $"&with_genres={genreCsv}";

                if (movieDiscoveryIntent && !newReleasesIntent)
                {
                    var (startYear, requestedEndYear) = ParseRequestedYearRange(lower, today.Year, 1980, today.Year);
                    var safeEndYear = Math.Min(requestedEndYear, today.Year);
                    var endDate = new DateTime(safeEndYear, 12, 31);
                    if (endDate > today) endDate = today;
                    var longRange = (requestedEndYear - startYear) >= 15;

                    var endpointPrimary =
                        $"discover/movie?primary_release_date.gte={startYear:0000}-01-01&primary_release_date.lte={endDate:yyyy-MM-dd}&sort_by=popularity.desc&vote_count.gte=250&without_genres=99,10402&with_runtime.gte=80&include_adult=false{genreParam}";
                    var endpointFallback =
                        $"discover/movie?primary_release_date.gte={startYear:0000}-01-01&primary_release_date.lte={endDate:yyyy-MM-dd}&sort_by=vote_average.desc&vote_count.gte=100&without_genres=99,10402&with_runtime.gte=75&include_adult=false{genreParam}";

                    var tmdbItems = await discovery.FetchListPagesAsync(tmdbKey, endpointPrimary, MediaKind.Movie, 5, ct).ConfigureAwait(false);
                    if (tmdbItems.Count == 0)
                        tmdbItems = await discovery.FetchListPagesAsync(tmdbKey, endpointFallback, MediaKind.Movie, 5, ct).ConfigureAwait(false);

                    SetMediaAgentRouteChips("Online Discovery", "Provider: TMDB");
                    if (tmdbItems.Count > 0)
                    {
                        double WeightedScore(EnrichedMediaObject item)
                        {
                            var r = item.Ratings?.Tmdb ?? 0d;
                            var v = Math.Max(0, item.VoteCount);
                            const double m = 350d;
                            const double c = 6.8d;
                            var weighted = ((v / (v + m)) * r) + ((m / (v + m)) * c);
                            var popBoost = Math.Min(1.2d, (item.Ratings?.PopularityRaw ?? 0d) / 100d);
                            return weighted + popBoost;
                        }

                        var ranked = tmdbItems
                            .Where(i => i.ReleaseDate.HasValue && i.ReleaseDate.Value.Year >= startYear && i.ReleaseDate.Value.Date <= endDate)
                            .Where(i => i.VoteCount >= 80)
                            .Where(i => (i.Ratings?.Tmdb ?? 0d) >= 5.5d)
                            .GroupBy(i => $"{i.Title.Trim().ToLowerInvariant()}|{i.ReleaseDate!.Value.Year}")
                            .Select(g => g.OrderByDescending(WeightedScore).First())
                            .OrderByDescending(WeightedScore)
                            .ThenByDescending(i => i.VoteCount)
                            .ToList();

                        var groupedByDecade = ranked
                            .GroupBy(i => (i.ReleaseDate!.Value.Year / 10) * 10)
                            .OrderBy(g => g.Key)
                            .ToList();

                        var movieResultItems = new List<MediaAgentResultItem>();
                        foreach (var decadeGroup in groupedByDecade)
                        {
                            foreach (var i in decadeGroup.Take(10))
                            {
                                movieResultItems.Add(new MediaAgentResultItem
                                {
                                    Kind = MediaAgentResultItem.ResultKind.Movie,
                                    MediaTypeId = "movie",
                                    Title = i.Title ?? "",
                                    Year = i.ReleaseDate?.Year,
                                    Rating = (i.Ratings?.Tmdb ?? 0) > 0 ? (double?)i.Ratings!.Tmdb : null,
                                    Votes = i.VoteCount > 0 ? (int?)i.VoteCount : null,
                                    Overview = (i.Overview ?? "").Length > 180 ? i.Overview!.Substring(0, 180) + "…" : (i.Overview ?? ""),
                                    Provider = "TMDB",
                                    Source = "TMDB",
                                    Tags = i.Genres ?? new List<string>(),
                                    TmdbId = i.TmdbId,
                                    ExternalQuery = $"{i.Title} {i.ReleaseDate?.Year}"
                                });
                            }
                        }

                        if (movieResultItems.Count > 0)
                        {
                            var summary = longRange
                                ? $"TMDB discover ({genreNameLabel}) {startYear}-01-01 to {endDate:yyyy-MM-dd}, grouped by decade."
                                : $"TMDB discover ({genreNameLabel}) {startYear}-01-01 to {endDate:yyyy-MM-dd}, ranked by quality/popularity.";
                            SetMediaAgentResultItems("Loaded", summary, movieResultItems);
                            return (true, $"ONLINE DISCOVERY\nProvider: TMDB\nGenres: {genreNameLabel}\nResults: {ranked.Count}");
                        }

                        SetMediaAgentResultState("Empty", "TMDB returned rows but none passed quality filters for movie ranking.", new[]
                        {
                            $"Searched: best {genreNameLabel} movies from {startYear} to {requestedEndYear}",
                            "Source: TMDB discover/movie",
                            "Why empty: rows did not meet vote/rating/runtime quality thresholds.",
                            "Next step: lower vote thresholds or widen date range."
                        });
                        return (true, $"ONLINE DISCOVERY\nProvider: TMDB\nResults: {tmdbItems.Count}");
                    }

                    SetMediaAgentResultState("Empty", "TMDB returned no movie results for the requested range.", new[]
                    {
                        $"Searched: best {genreNameLabel} movies from {startYear} to {requestedEndYear}",
                        "Source: TMDB discover/movie",
                        $"Why empty: TMDB returned no rows for filters {(string.IsNullOrWhiteSpace(genreCsv) ? "(no with_genres)" : $"with_genres={genreCsv}")}, primary_release_date {startYear:0000}-01-01..{endDate:yyyy-MM-dd}.",
                        "Next step: try a shorter year range or popularity sorting without strict vote thresholds."
                    });
                    return (true, "ONLINE DISCOVERY\nProvider: TMDB\nNo matching results.");
                }

                if (newReleasesIntent)
                {
                    var months = ParseLastXMonths(lower, 2);
                    var fromDate = today.AddDays(-Math.Max(1, months) * 30);
                    var endpoint =
                        $"discover/movie?primary_release_date.gte={fromDate:yyyy-MM-dd}&primary_release_date.lte={today:yyyy-MM-dd}&sort_by=popularity.desc&include_adult=false&without_genres=10402{genreParam}";

                    var tmdbItems = await discovery.FetchListPagesAsync(tmdbKey, endpoint, MediaKind.Movie, 3, ct).ConfigureAwait(false);
                    SetMediaAgentRouteChips("Online Discovery", "Provider: TMDB");

                    if (tmdbItems.Count > 0)
                    {
                        var releaseCards = tmdbItems
                            .Where(i => i.ReleaseDate.HasValue)
                            .Where(i => i.ReleaseDate.Value.Date >= fromDate && i.ReleaseDate.Value.Date <= today)
                            .OrderByDescending(i => i.ReleaseDate)
                            .ThenByDescending(i => i.Ratings?.PopularityRaw ?? 0)
                            .ThenByDescending(i => i.VoteCount)
                            .GroupBy(i => i.TmdbId ?? 0)
                            .Select(g => g.First())
                            .Take(20)
                            .Select(i => new MediaAgentResultItem
                            {
                                Kind = MediaAgentResultItem.ResultKind.Movie,
                                MediaTypeId = "movie",
                                Title = i.Title ?? "",
                                Year = i.ReleaseDate?.Year,
                                Rating = (i.Ratings?.Tmdb ?? 0) > 0 ? (double?)i.Ratings!.Tmdb : null,
                                Votes = i.VoteCount > 0 ? (int?)i.VoteCount : null,
                                Overview = (i.Overview ?? "").Length > 180 ? i.Overview!.Substring(0, 180) + "…" : (i.Overview ?? ""),
                                Provider = "TMDB",
                                Source = "TMDB",
                                Subtitle = i.ReleaseDate.HasValue ? $"Release date · {i.ReleaseDate.Value:yyyy-MM-dd}" : "Recent release",
                                Tags = i.Genres ?? new List<string>(),
                                TmdbId = i.TmdbId,
                                ExternalQuery = $"{i.Title} trailer"
                            })
                            .ToList();

                        var grouped = tmdbItems
                            .Where(i => i.ReleaseDate.HasValue)
                            .Where(i => i.ReleaseDate.Value.Date >= fromDate && i.ReleaseDate.Value.Date <= today)
                            .Where(i => i.VoteCount >= 10)
                            .OrderByDescending(i => i.Ratings?.PopularityRaw ?? 0)
                            .ThenByDescending(i => i.VoteCount)
                            .OrderByDescending(i => i.ReleaseDate)
                            .GroupBy(i => i.ReleaseDate!.Value.ToString("yyyy-MM", CultureInfo.InvariantCulture))
                            .Take(3)
                            .SelectMany(g => g.Take(4).Select(i =>
                            {
                                var rating = (i.Ratings?.Tmdb ?? 0) > 0 ? (i.Ratings?.Tmdb ?? 0).ToString("0.0", CultureInfo.InvariantCulture) : "n/a";
                                var votes = i.VoteCount > 0 ? i.VoteCount.ToString(CultureInfo.InvariantCulture) : "n/a";
                                return $"{i.ReleaseDate:yyyy-MM-dd} · {i.Title} · TMDB {rating}/10 · votes {votes} · source TMDB";
                            }))
                            .ToList();

                        if (grouped.Count > 0)
                        {
                            grouped.Insert(0, $"Detected genre(s): {genreNameLabel}");
                            grouped.Insert(1, $"TMDB genre ID(s): {(string.IsNullOrWhiteSpace(genreCsv) ? "none" : genreCsv)}");
                        }

                        if (grouped.Count == 0)
                        {
                            grouped = tmdbItems.Take(12).Select(i =>
                            {
                                var rd = i.ReleaseDate.HasValue ? i.ReleaseDate.Value.ToString("yyyy-MM-dd", CultureInfo.InvariantCulture) : "n/a";
                                var rating = (i.Ratings?.Tmdb ?? 0) > 0 ? (i.Ratings?.Tmdb ?? 0).ToString("0.0", CultureInfo.InvariantCulture) : "n/a";
                                return $"{rd} · {i.Title} · TMDB {rating}/10";
                            }).ToList();
                        }

                        if (releaseCards.Count > 0)
                        {
                            SetMediaAgentResultItems("Loaded", $"TMDB new releases for {fromDate:yyyy-MM-dd} to {today:yyyy-MM-dd}: {tmdbItems.Count}", releaseCards);
                        }
                        else
                        {
                            SetMediaAgentResultState("Loaded", $"TMDB new releases for {fromDate:yyyy-MM-dd} to {today:yyyy-MM-dd}: {tmdbItems.Count}", grouped);
                        }
                        return (true, $"ONLINE DISCOVERY\nProvider: TMDB\nDate range: {fromDate:yyyy-MM-dd}..{today:yyyy-MM-dd}\nResults: {tmdbItems.Count}");
                    }

                    SetMediaAgentResultState("Empty", $"TMDB returned no results for date range {fromDate:yyyy-MM-dd} to {today:yyyy-MM-dd}.", new[]
                    {
                        "Searched: new releases from the last 2 months",
                        $"Detected genre(s): {genreNameLabel}",
                        $"TMDB genre ID(s): {(string.IsNullOrWhiteSpace(genreCsv) ? "none" : genreCsv)}",
                        "Source: TMDB discover/movie",
                        $"Why empty: no titles matched primary_release_date.gte={fromDate:yyyy-MM-dd} and primary_release_date.lte={today:yyyy-MM-dd}{(string.IsNullOrWhiteSpace(genreCsv) ? "" : $" with_genres={genreCsv}")}",
                        "Next step: widen date range or remove genre constraints."
                    });
                    return (true, "ONLINE DISCOVERY\nProvider: TMDB\nNo matching results.");
                }
            }

            var query = Regex.Replace(instruction, "\\b(online:|discover|trending|new releases?|similar|genre|year|movies?|shows?|tv)\\b", "", RegexOptions.IgnoreCase).Trim();
            var lines = new List<string>();

            if (lower.Contains("trending") && hasTrakt)
            {
                try
                {
                    var trakt = new TraktClient();
                    var movies = await trakt.GetTrendingMoviesAsync(TraktClientId, ct).ConfigureAwait(false);
                    lines.AddRange(movies.Take(12).Select(m => $"{m.Title} {(m.Year.HasValue ? "(" + m.Year.Value.ToString(CultureInfo.InvariantCulture) + ")" : "")}".Trim()));
                    SetMediaAgentRouteChips("Online Discovery", "Provider: Trakt");
                    if (lines.Count > 0)
                    {
                        SetMediaAgentResultState("Loaded", $"Live trending results from Trakt: {lines.Count}", lines);
                        return (true, $"ONLINE TRENDING\nProvider: Trakt\nResults: {lines.Count}");
                    }
                }
                catch
                {
                }
            }

            if (hasTmdb)
            {
                var movieResults = string.IsNullOrWhiteSpace(query)
                    ? new List<TmdbClient.TmdbMovieResult>()
                    : await _tmdbClient.SearchMovieAsync(tmdbKey, query, ct).ConfigureAwait(false);
                var tvResults = string.IsNullOrWhiteSpace(query)
                    ? new List<TmdbClient.TmdbTvResult>()
                    : await _tmdbClient.SearchTvAsync(tmdbKey, query, ct).ConfigureAwait(false);

                lines.AddRange(movieResults.Take(8).Select(r => $"Movie: {r.Title} {(r.ReleaseDate.HasValue ? "(" + r.ReleaseDate.Value.Year.ToString(CultureInfo.InvariantCulture) + ")" : "")}".Trim()));
                lines.AddRange(tvResults.Take(8).Select(r => $"TV: {r.Name} {(r.FirstAirDate.HasValue ? "(" + r.FirstAirDate.Value.Year.ToString(CultureInfo.InvariantCulture) + ")" : "")}".Trim()));
                SetMediaAgentRouteChips("Online Discovery", "Provider: TMDB");

                if (lines.Count > 0)
                {
                    SetMediaAgentResultState("Loaded", $"Live online discovery results from TMDB: {lines.Count}", lines);
                    return (true, $"ONLINE DISCOVERY\nProvider: TMDB\nResults: {lines.Count}");
                }

                SetMediaAgentResultState("Empty", "TMDB configured but no matching online discovery results.");
                return (true, "ONLINE DISCOVERY\nProvider: TMDB\nNo matching results.");
            }

            SetMediaAgentRouteChips("Online Discovery", "Provider: unavailable");
            SetMediaAgentResultState("Empty", "No live online provider configured for this discovery request.", new[]
            {
                "Configure TMDB for movie/TV live discovery.",
                "Configure Trakt for live trending feeds."
            });
            return (true, "ONLINE DISCOVERY\nUnavailable: no live provider configured.");
        }

        private List<MediaItem> ResolveMediaAgentLocalSourceItems(string lowerInstruction, out bool usesVisibleScope)
        {
            usesVisibleScope =
                lowerInstruction.Contains("current", StringComparison.OrdinalIgnoreCase) ||
                lowerInstruction.Contains("visible", StringComparison.OrdinalIgnoreCase) ||
                lowerInstruction.Contains("this list", StringComparison.OrdinalIgnoreCase) ||
                lowerInstruction.Contains("current scope", StringComparison.OrdinalIgnoreCase);

            if (usesVisibleScope)
                return ResolveMediaAiScopeItems();

            lock (_stateLock)
            {
                return _allItems.ToList();
            }
        }

        private static string ResolveMediaTypeFromInstruction(string lowerInstruction)
        {
            if (lowerInstruction.Contains(" movie") || lowerInstruction.Contains(" movies")) return "movies";
            if (lowerInstruction.Contains(" tv") || lowerInstruction.Contains(" series") || lowerInstruction.Contains(" shows")) return "tv";
            if (lowerInstruction.Contains(" music") || lowerInstruction.Contains(" songs") || lowerInstruction.Contains(" albums")) return "music";
            if (lowerInstruction.Contains(" games")) return "games";
            if (lowerInstruction.Contains(" images") || lowerInstruction.Contains(" photos")) return "images";
            return "";
        }

        private static string ExtractLocalSearchQuery(string instruction)
        {
            var query = (instruction ?? "").Trim();
            query = Regex.Replace(query, "^local[:\\-]?\\s*", "", RegexOptions.IgnoreCase).Trim();
            query = Regex.Replace(query, "^(local-search|find|show|search)\\s+(me\\s+)?(all\\s+)?", "", RegexOptions.IgnoreCase).Trim();
            query = Regex.Replace(query, "\\b(movies?|tv|series|shows?|music|songs?|albums?|games?|images?|photos?)\\b", "", RegexOptions.IgnoreCase).Trim();
            query = Regex.Replace(query, "\\b(me|the|a|an|all|every|in|my|library)\\b", "", RegexOptions.IgnoreCase).Trim();
            query = Regex.Replace(query, "\\s+", " ").Trim();
            return string.IsNullOrWhiteSpace(query) ? "all items" : query;
        }

        private static List<MediaItem> SearchLibraryItems(List<MediaItem> source, string query, string? typeId, int maxResults)
        {
            query = (query ?? "").Trim();
            IEnumerable<MediaItem> items = source.Where(i => i != null);

            if (!string.IsNullOrWhiteSpace(typeId))
                items = items.Where(i => string.Equals(i.Type, typeId, StringComparison.OrdinalIgnoreCase));

            if (string.IsNullOrWhiteSpace(query) || string.Equals(query, "all items", StringComparison.OrdinalIgnoreCase))
                return items.Take(Math.Max(1, maxResults)).ToList();

            var stopwords = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "a", "an", "and", "the", "me", "my", "all", "every", "please", "in", "on", "at", "to", "for", "of", "from"
            };

            var minTokenLen = query.Length <= 4 ? 2 : 3;
            var tokens = Regex.Split(query, "\\s+")
                .Select(t => (t ?? "").Trim())
                .Where(t => !string.IsNullOrWhiteSpace(t))
                .Select(t => t.Trim('"', '\'', ',', '.', '!', '?', ':', ';', '(', ')', '[', ']', '{', '}'))
                .Where(t => t.Length >= minTokenLen && !stopwords.Contains(t))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToArray();

            if (tokens.Length == 0)
                return items.Take(Math.Max(1, maxResults)).ToList();

            var scored = items
                .Select(i => (Item: i, Score: ScoreSearch(i, tokens, out var matched), Matched: matched))
                .Where(x => x.Score > 0)
                .OrderByDescending(x => x.Matched)
                .ThenByDescending(x => x.Score)
                .ThenBy(x => x.Item.Title ?? "", StringComparer.OrdinalIgnoreCase)
                .Select(x => x.Item)
                .Take(Math.Max(1, maxResults))
                .ToList();

            return scored;
        }

        private static List<(int id, string name)> ResolveTmdbGenresFromInstruction(string lowerInstruction)
            => TmdbDiscoveryProvider.ResolveMovieGenresFromText(lowerInstruction);

        private static (int startYear, int endYear) ParseRequestedYearRange(string lowerInstruction, int currentYear, int defaultStart, int defaultEnd)
        {
            var explicitYears = Regex.Matches(lowerInstruction, @"\b(19|20)\d{2}\b")
                .Select(m => int.TryParse(m.Value, out var y) ? y : 0)
                .Where(y => y >= 1900 && y <= currentYear + 2)
                .ToList();

            if (explicitYears.Count >= 2)
                return (explicitYears.Min(), explicitYears.Max());
            if (explicitYears.Count == 1)
                return (explicitYears[0], Math.Min(currentYear, defaultEnd));

            var decadeMatch = Regex.Match(lowerInstruction, @"\b(?<dec>(19|20)\d)0s\b", RegexOptions.IgnoreCase);
            if (decadeMatch.Success && int.TryParse(decadeMatch.Groups["dec"].Value, out var decadePrefix))
            {
                var start = decadePrefix * 10;
                var end = Math.Min(start + 9, currentYear);
                return (start, end);
            }

            var yearsBackMatch = Regex.Match(lowerInstruction, @"last\s+(?<n>\d+)\s+years?", RegexOptions.IgnoreCase);
            if (yearsBackMatch.Success && int.TryParse(yearsBackMatch.Groups["n"].Value, out var yearsBack) && yearsBack > 0)
            {
                var start = Math.Max(1900, currentYear - yearsBack);
                return (start, currentYear);
            }

            return (defaultStart, Math.Min(currentYear, defaultEnd));
        }

        private static int ParseLastXMonths(string lowerInstruction, int defaultMonths)
        {
            var numericMatch = Regex.Match(lowerInstruction, @"last\s+(?<n>\d+)\s+months?", RegexOptions.IgnoreCase);
            if (numericMatch.Success && int.TryParse(numericMatch.Groups["n"].Value, out var n) && n > 0)
                return n;

            if (Regex.IsMatch(lowerInstruction, @"last\s+two\s+months?", RegexOptions.IgnoreCase)) return 2;
            if (Regex.IsMatch(lowerInstruction, @"last\s+three\s+months?", RegexOptions.IgnoreCase)) return 3;
            if (Regex.IsMatch(lowerInstruction, @"last\s+six\s+months?", RegexOptions.IgnoreCase)) return 6;
            if (Regex.IsMatch(lowerInstruction, @"last\s+year", RegexOptions.IgnoreCase)) return 12;

            return defaultMonths;
        }

        private static string ExtractMusicLikeArtist(string instruction)
        {
            var text = (instruction ?? "").Trim();
            var match = Regex.Match(text, @"\blike\s+(?<artist>.+)$", RegexOptions.IgnoreCase);
            if (match.Success)
            {
                var artist = match.Groups["artist"].Value.Trim();
                artist = Regex.Replace(artist, "\\b(please|songs?|tracks?)\\b", "", RegexOptions.IgnoreCase).Trim();
                return string.IsNullOrWhiteSpace(artist) ? "unknown artist" : artist;
            }

            return "unknown artist";
        }

        private async Task<(string seedArtist, List<string> relatedArtists)> TryGetSpotifyRelatedArtistsAsync(string artistName, CancellationToken ct)
        {
            var clientId = (IntegrationKeyStore.GetDecrypted("spotify_client_id") ?? "").Trim();
            var clientSecret = (IntegrationKeyStore.GetDecrypted("spotify_client_secret") ?? "").Trim();
            if (string.IsNullOrWhiteSpace(clientId) || string.IsNullOrWhiteSpace(clientSecret))
                return (artistName, new List<string>());

            if (string.IsNullOrWhiteSpace(artistName) || string.Equals(artistName, "unknown artist", StringComparison.OrdinalIgnoreCase))
                return (artistName, new List<string>());

            try
            {
                using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(20) };

                using var tokenRequest = new HttpRequestMessage(HttpMethod.Post, "https://accounts.spotify.com/api/token")
                {
                    Content = new FormUrlEncodedContent(new[] { new KeyValuePair<string, string>("grant_type", "client_credentials") })
                };
                var basic = Convert.ToBase64String(Encoding.UTF8.GetBytes($"{clientId}:{clientSecret}"));
                tokenRequest.Headers.TryAddWithoutValidation("Authorization", $"Basic {basic}");

                using var tokenResponse = await http.SendAsync(tokenRequest, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!tokenResponse.IsSuccessStatusCode)
                    return (artistName, new List<string>());

                var tokenJson = await tokenResponse.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                using var tokenDoc = JsonDocument.Parse(tokenJson);
                var accessToken = tokenDoc.RootElement.TryGetProperty("access_token", out var atEl) ? (atEl.GetString() ?? "") : "";
                if (string.IsNullOrWhiteSpace(accessToken))
                    return (artistName, new List<string>());

                using var searchRequest = new HttpRequestMessage(HttpMethod.Get,
                    $"https://api.spotify.com/v1/search?q={Uri.EscapeDataString(artistName)}&type=artist&limit=1");
                searchRequest.Headers.TryAddWithoutValidation("Authorization", $"Bearer {accessToken}");
                using var searchResponse = await http.SendAsync(searchRequest, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!searchResponse.IsSuccessStatusCode)
                    return (artistName, new List<string>());

                var searchJson = await searchResponse.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                using var searchDoc = JsonDocument.Parse(searchJson);
                if (!searchDoc.RootElement.TryGetProperty("artists", out var artistsEl) ||
                    !artistsEl.TryGetProperty("items", out var itemsEl) ||
                    itemsEl.ValueKind != JsonValueKind.Array ||
                    itemsEl.GetArrayLength() == 0)
                {
                    return (artistName, new List<string>());
                }

                var firstArtist = itemsEl[0];
                var seedName = firstArtist.TryGetProperty("name", out var nEl) ? (nEl.GetString() ?? artistName) : artistName;
                var artistId = firstArtist.TryGetProperty("id", out var idEl) ? (idEl.GetString() ?? "") : "";
                if (string.IsNullOrWhiteSpace(artistId))
                    return (seedName, new List<string>());

                List<string> BuildRows(JsonElement artistsArray)
                {
                    return artistsArray.EnumerateArray()
                    .Where(a => a.ValueKind == JsonValueKind.Object)
                    .Select(a =>
                    {
                        var name = a.TryGetProperty("name", out var rnEl) ? (rnEl.GetString() ?? "") : "";
                        var popularity = a.TryGetProperty("popularity", out var popEl) && popEl.ValueKind == JsonValueKind.Number && popEl.TryGetInt32(out var pop)
                            ? pop.ToString(CultureInfo.InvariantCulture)
                            : "n/a";
                        var genres = a.TryGetProperty("genres", out var gEl) && gEl.ValueKind == JsonValueKind.Array
                            ? string.Join(", ", gEl.EnumerateArray().Where(x => x.ValueKind == JsonValueKind.String).Select(x => x.GetString()).Where(x => !string.IsNullOrWhiteSpace(x)).Take(2))
                            : "";
                        if (string.IsNullOrWhiteSpace(name)) return "";
                        return string.IsNullOrWhiteSpace(genres)
                            ? $"{name} · Spotify popularity {popularity}"
                            : $"{name} · {genres} · Spotify popularity {popularity}";
                    })
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(12)
                    .ToList();
                }

                var related = new List<string>();
                using (var relatedRequest = new HttpRequestMessage(HttpMethod.Get, $"https://api.spotify.com/v1/artists/{Uri.EscapeDataString(artistId)}/related-artists"))
                {
                    relatedRequest.Headers.TryAddWithoutValidation("Authorization", $"Bearer {accessToken}");
                    using var relatedResponse = await http.SendAsync(relatedRequest, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                    if (relatedResponse.IsSuccessStatusCode)
                    {
                        var relatedJson = await relatedResponse.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                        using var relatedDoc = JsonDocument.Parse(relatedJson);
                        if (relatedDoc.RootElement.TryGetProperty("artists", out var relatedArtistsEl) && relatedArtistsEl.ValueKind == JsonValueKind.Array)
                            related = BuildRows(relatedArtistsEl);
                    }
                }

                if (related.Count == 0)
                {
                    using var recRequest = new HttpRequestMessage(HttpMethod.Get,
                        $"https://api.spotify.com/v1/recommendations?seed_artists={Uri.EscapeDataString(artistId)}&limit=15&market=US");
                    recRequest.Headers.TryAddWithoutValidation("Authorization", $"Bearer {accessToken}");
                    using var recResponse = await http.SendAsync(recRequest, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                    if (recResponse.IsSuccessStatusCode)
                    {
                        var recJson = await recResponse.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                        using var recDoc = JsonDocument.Parse(recJson);
                        if (recDoc.RootElement.TryGetProperty("tracks", out var tracksEl) && tracksEl.ValueKind == JsonValueKind.Array)
                        {
                            related = tracksEl.EnumerateArray()
                                .Where(t => t.ValueKind == JsonValueKind.Object)
                                .Select(t =>
                                {
                                    var trackName = t.TryGetProperty("name", out var tnEl) ? (tnEl.GetString() ?? "") : "";
                                    var artists = t.TryGetProperty("artists", out var taEl) && taEl.ValueKind == JsonValueKind.Array
                                        ? string.Join(", ", taEl.EnumerateArray().Where(a => a.ValueKind == JsonValueKind.Object).Select(a => a.TryGetProperty("name", out var anEl) ? anEl.GetString() ?? "" : "").Where(a => !string.IsNullOrWhiteSpace(a)).Take(2))
                                        : "";
                                    if (string.IsNullOrWhiteSpace(trackName) || string.IsNullOrWhiteSpace(artists)) return "";
                                    return $"{artists} · Recommended track: {trackName} · Spotify recommendations";
                                })
                                .Where(x => !string.IsNullOrWhiteSpace(x))
                                .Distinct(StringComparer.OrdinalIgnoreCase)
                                .Take(12)
                                .ToList();
                        }
                    }
                }

                if (related.Count == 0)
                {
                    using var topTracksRequest = new HttpRequestMessage(HttpMethod.Get,
                        $"https://api.spotify.com/v1/artists/{Uri.EscapeDataString(artistId)}/top-tracks?market=US");
                    topTracksRequest.Headers.TryAddWithoutValidation("Authorization", $"Bearer {accessToken}");
                    using var topTracksResponse = await http.SendAsync(topTracksRequest, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                    if (topTracksResponse.IsSuccessStatusCode)
                    {
                        var topTracksJson = await topTracksResponse.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                        using var topDoc = JsonDocument.Parse(topTracksJson);
                        if (topDoc.RootElement.TryGetProperty("tracks", out var topTracksEl) && topTracksEl.ValueKind == JsonValueKind.Array)
                        {
                            related = topTracksEl.EnumerateArray()
                                .Where(t => t.ValueKind == JsonValueKind.Object)
                                .Select(t =>
                                {
                                    var trackName = t.TryGetProperty("name", out var tnEl) ? (tnEl.GetString() ?? "") : "";
                                    if (string.IsNullOrWhiteSpace(trackName)) return "";
                                    return $"{seedName} · Top track: {trackName} · Spotify artist catalog";
                                })
                                .Where(x => !string.IsNullOrWhiteSpace(x))
                                .Distinct(StringComparer.OrdinalIgnoreCase)
                                .Take(10)
                                .ToList();
                        }
                    }
                }

                return (seedName, related);
            }
            catch
            {
                return (artistName, new List<string>());
            }
        }

        private async Task<List<string>> TryGetMusicBrainzSimilarArtistsAsync(string artistName, CancellationToken ct)
        {
            artistName = (artistName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(artistName) || string.Equals(artistName, "unknown artist", StringComparison.OrdinalIgnoreCase))
                return new List<string>();

            try
            {
                using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(20) };
                var contact = (IntegrationKeyStore.GetDecrypted("musicbrainz_contact") ?? "").Trim();
                var userAgent = string.IsNullOrWhiteSpace(contact)
                    ? "AtlasAI/1.0 (https://atlas.os; contact@atlas.local)"
                    : $"AtlasAI/1.0 (https://atlas.os; {contact})";

                using var searchReq = new HttpRequestMessage(HttpMethod.Get,
                    $"https://musicbrainz.org/ws/2/artist?query={Uri.EscapeDataString($"artist:\"{artistName}\"")}&fmt=json&limit=1");
                searchReq.Headers.TryAddWithoutValidation("User-Agent", userAgent);
                searchReq.Headers.TryAddWithoutValidation("Accept", "application/json");
                using var searchRes = await http.SendAsync(searchReq, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!searchRes.IsSuccessStatusCode)
                    return new List<string>();

                var searchJson = await searchRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                using var searchDoc = JsonDocument.Parse(searchJson);
                if (!searchDoc.RootElement.TryGetProperty("artists", out var artistsEl) || artistsEl.ValueKind != JsonValueKind.Array || artistsEl.GetArrayLength() == 0)
                    return new List<string>();

                var first = artistsEl[0];
                var mbid = first.TryGetProperty("id", out var idEl) ? (idEl.GetString() ?? "") : "";
                var canonicalName = first.TryGetProperty("name", out var nameEl) ? (nameEl.GetString() ?? artistName) : artistName;
                if (string.IsNullOrWhiteSpace(mbid))
                    return new List<string>();

                using var detailsReq = new HttpRequestMessage(HttpMethod.Get,
                    $"https://musicbrainz.org/ws/2/artist/{Uri.EscapeDataString(mbid)}?inc=tags&fmt=json");
                detailsReq.Headers.TryAddWithoutValidation("User-Agent", userAgent);
                detailsReq.Headers.TryAddWithoutValidation("Accept", "application/json");
                using var detailsRes = await http.SendAsync(detailsReq, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!detailsRes.IsSuccessStatusCode)
                    return new List<string>();

                var detailsJson = await detailsRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                using var detailsDoc = JsonDocument.Parse(detailsJson);
                if (!detailsDoc.RootElement.TryGetProperty("tags", out var tagsEl) || tagsEl.ValueKind != JsonValueKind.Array)
                    return new List<string>();

                var tags = tagsEl.EnumerateArray()
                    .Where(t => t.ValueKind == JsonValueKind.Object)
                    .Select(t => new
                    {
                        Name = t.TryGetProperty("name", out var nEl) && nEl.ValueKind == JsonValueKind.String ? (nEl.GetString() ?? "") : "",
                        Count = t.TryGetProperty("count", out var cEl) && cEl.ValueKind == JsonValueKind.Number && cEl.TryGetInt32(out var c) ? c : 0
                    })
                    .Where(x => !string.IsNullOrWhiteSpace(x.Name))
                    .OrderByDescending(x => x.Count)
                    .ThenByDescending(x => x.Name.Length)
                    .Take(3)
                    .ToList();

                var rows = new List<string>();
                foreach (var tag in tags)
                {
                    using var tagReq = new HttpRequestMessage(HttpMethod.Get,
                        $"https://musicbrainz.org/ws/2/artist?query={Uri.EscapeDataString($"tag:\"{tag.Name}\"")}&fmt=json&limit=20");
                    tagReq.Headers.TryAddWithoutValidation("User-Agent", userAgent);
                    tagReq.Headers.TryAddWithoutValidation("Accept", "application/json");
                    using var tagRes = await http.SendAsync(tagReq, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                    if (!tagRes.IsSuccessStatusCode)
                        continue;

                    var tagJson = await tagRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                    using var tagDoc = JsonDocument.Parse(tagJson);
                    if (!tagDoc.RootElement.TryGetProperty("artists", out var tagArtistsEl) || tagArtistsEl.ValueKind != JsonValueKind.Array)
                        continue;

                    foreach (var a in tagArtistsEl.EnumerateArray())
                    {
                        if (a.ValueKind != JsonValueKind.Object) continue;
                        var name = a.TryGetProperty("name", out var nEl) && nEl.ValueKind == JsonValueKind.String ? (nEl.GetString() ?? "") : "";
                        if (string.IsNullOrWhiteSpace(name)) continue;
                        if (name.Equals(canonicalName, StringComparison.OrdinalIgnoreCase)) continue;
                        rows.Add($"{name} · Shared MusicBrainz tag: {tag.Name}");
                        if (rows.Count >= 12) break;
                    }

                    if (rows.Count >= 12) break;
                }

                return rows
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(12)
                    .ToList();
            }
            catch
            {
                return new List<string>();
            }
        }

        private async Task<List<string>> TryGetLastFmSimilarArtistsAsync(string artistName, CancellationToken ct)
        {
            var lastFmKey = (IntegrationKeyStore.GetDecrypted("lastfm_key") ?? "").Trim();
            artistName = (artistName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(lastFmKey) || string.IsNullOrWhiteSpace(artistName) || string.Equals(artistName, "unknown artist", StringComparison.OrdinalIgnoreCase))
                return new List<string>();

            try
            {
                using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(20) };
                var url =
                    $"https://ws.audioscrobbler.com/2.0/?method=artist.getsimilar&artist={Uri.EscapeDataString(artistName)}&api_key={Uri.EscapeDataString(lastFmKey)}&limit=12&format=json";

                using var req = new HttpRequestMessage(HttpMethod.Get, url);
                req.Headers.TryAddWithoutValidation("Accept", "application/json");
                using var res = await http.SendAsync(req, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!res.IsSuccessStatusCode)
                    return new List<string>();

                var json = await res.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                using var doc = JsonDocument.Parse(json);
                if (!doc.RootElement.TryGetProperty("similarartists", out var similarEl) || similarEl.ValueKind != JsonValueKind.Object)
                    return new List<string>();
                if (!similarEl.TryGetProperty("artist", out var artistsEl) || artistsEl.ValueKind != JsonValueKind.Array)
                    return new List<string>();

                return artistsEl.EnumerateArray()
                    .Where(a => a.ValueKind == JsonValueKind.Object)
                    .Select(a =>
                    {
                        var name = a.TryGetProperty("name", out var rnEl) && rnEl.ValueKind == JsonValueKind.String ? (rnEl.GetString() ?? "") : "";
                        var matchPct = a.TryGetProperty("match", out var mEl) && mEl.ValueKind == JsonValueKind.String ? (mEl.GetString() ?? "") : "";
                        if (string.IsNullOrWhiteSpace(name)) return "";
                        return string.IsNullOrWhiteSpace(matchPct)
                            ? $"{name} · Similar artist from Last.fm"
                            : $"{name} · Last.fm similarity {matchPct}";
                    })
                    .Where(x => !string.IsNullOrWhiteSpace(x))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(12)
                    .ToList();
            }
            catch
            {
                return new List<string>();
            }
        }

        private async Task<List<string>> BuildAiMusicFallbackAsync(string seedArtist, CancellationToken ct)
        {
            List<string> ParseRecommendations(string content)
            {
                var rows = new List<string>();
                var raw = (content ?? "").Trim();
                if (string.IsNullOrWhiteSpace(raw))
                    return rows;

                try
                {
                    using var doc = JsonDocument.Parse(raw);
                    JsonElement arrayEl;
                    if (doc.RootElement.ValueKind == JsonValueKind.Array)
                    {
                        arrayEl = doc.RootElement;
                    }
                    else if (doc.RootElement.ValueKind == JsonValueKind.Object &&
                             doc.RootElement.TryGetProperty("recommendations", out var recEl) &&
                             recEl.ValueKind == JsonValueKind.Array)
                    {
                        arrayEl = recEl;
                    }
                    else
                    {
                        arrayEl = default;
                    }

                    if (arrayEl.ValueKind == JsonValueKind.Array)
                    {
                        foreach (var item in arrayEl.EnumerateArray())
                        {
                            if (item.ValueKind == JsonValueKind.String)
                            {
                                var v = (item.GetString() ?? "").Trim();
                                if (!string.IsNullOrWhiteSpace(v))
                                    rows.Add($"{v} · AI recommendation, not live provider data.");
                                continue;
                            }

                            if (item.ValueKind != JsonValueKind.Object)
                                continue;

                            var name = "";
                            if (item.TryGetProperty("artist", out var aEl) && aEl.ValueKind == JsonValueKind.String)
                                name = (aEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(name) && item.TryGetProperty("name", out var nEl) && nEl.ValueKind == JsonValueKind.String)
                                name = (nEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(name) && item.TryGetProperty("title", out var tEl) && tEl.ValueKind == JsonValueKind.String)
                                name = (tEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(name) && item.TryGetProperty("song", out var sEl) && sEl.ValueKind == JsonValueKind.String)
                                name = (sEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(name) && item.TryGetProperty("album", out var alEl) && alEl.ValueKind == JsonValueKind.String)
                                name = (alEl.GetString() ?? "").Trim();

                            var why = "";
                            if (item.TryGetProperty("why", out var wEl) && wEl.ValueKind == JsonValueKind.String)
                                why = (wEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(why) && item.TryGetProperty("reason", out var rEl) && rEl.ValueKind == JsonValueKind.String)
                                why = (rEl.GetString() ?? "").Trim();
                            if (string.IsNullOrWhiteSpace(why) && item.TryGetProperty("similarity", out var simEl) && simEl.ValueKind == JsonValueKind.String)
                                why = (simEl.GetString() ?? "").Trim();

                            if (string.IsNullOrWhiteSpace(name))
                                continue;

                            if (string.IsNullOrWhiteSpace(why))
                                rows.Add($"{name} · Similar style and energy to {seedArtist} · AI recommendation, not live provider data.");
                            else
                                rows.Add($"{name} · {why} · AI recommendation, not live provider data.");
                        }
                    }
                }
                catch
                {
                }

                if (rows.Count == 0)
                {
                    rows = raw
                        .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
                        .Select(s => (s ?? "").Trim())
                        .Where(s => !string.IsNullOrWhiteSpace(s))
                        .Select(s => Regex.Replace(s, @"^\s*[-*•\d\.)\s]+", "").Trim())
                        .Where(s => !string.IsNullOrWhiteSpace(s))
                        .Select(s => s.Contains("AI recommendation, not live provider data.", StringComparison.OrdinalIgnoreCase)
                            ? s
                            : $"{s} · AI recommendation, not live provider data.")
                        .ToList();
                }

                return rows
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Take(10)
                    .ToList();
            }

            try
            {
                var prompts = new[]
                {
                    "Return JSON only with this shape: {\"recommendations\":[{\"artist\":\"name\",\"why\":\"short reason\"}]}. " +
                    "Give exactly 10 recommendations similar to the seed artist. Do not claim live or latest provider data.",
                    "Return exactly 10 plain-text lines: <artist or song> - <short why similar>. No numbering, no markdown. " +
                    "Do not claim live/provider/latest data."
                };

                var best = new List<string>();
                foreach (var promptTemplate in prompts)
                {
                    var prompt = $"{promptTemplate} Seed artist: {seedArtist}.";
                    var response = await AIManager.SendMessageAsync(new List<object> { prompt }, 700, ct).ConfigureAwait(false);
                    if (!response.Success || string.IsNullOrWhiteSpace(response.Content))
                        continue;

                    var parsed = ParseRecommendations(response.Content);
                    if (parsed.Count > best.Count)
                        best = parsed;

                    if (parsed.Count >= 5)
                        return parsed;
                }

                return best;
            }
            catch
            {
                return new List<string>();
            }
        }

        private string BuildMediaAgentContextSnapshot()
        {
            var selected = PreviewItem
                ?? DetailsItem
                ?? LibraryItems.FirstOrDefault(i => i != null && i.IsPlaying)
                ?? LibraryItems.FirstOrDefault();

            var selectedTitle = selected != null
                ? (string.IsNullOrWhiteSpace(selected.Title) ? Path.GetFileNameWithoutExtension(selected.FilePath) ?? "Untitled" : selected.Title)
                : "None";
            var selectedType = selected?.Type ?? "n/a";

            int totalItems;
            lock (_stateLock)
            {
                totalItems = _allItems.Count;
            }

            var scopeItems = ResolveMediaAiScopeItems().Count;
            var nowPlaying = IsPlaying ? $"{NowPlayingTitle}" : "Idle";
            var albumLabel = SelectedAlbum != null
                ? $"{SelectedAlbum.Artist} / {SelectedAlbum.AlbumTitle}"
                : "None";

            return string.Join("\n", new[]
            {
                $"Category: {(SelectedCategory?.Label ?? "All")}",
                $"Scope: {SelectedMediaAiScope} ({scopeItems} items)",
                $"Selected: {selectedTitle} [{selectedType}]",
                $"Album: {albumLabel}",
                $"Visible/Total: {LibraryItems.Count}/{totalItems}",
                $"Now Playing: {nowPlaying}"
            });
        }

        private static string NormalizeForDuplicateCheck(string text)
        {
            var lower = (text ?? "").ToLowerInvariant();
            return Regex.Replace(lower, "[^a-z0-9]", "");
        }

        private static string NormalizeForDuplicateGroup(MediaItem item)
        {
            var title = NormalizeForDuplicateCheck(item?.Title ?? "");
            var artist = NormalizeForDuplicateCheck(item?.Artist ?? "");
            var album = NormalizeForDuplicateCheck(item?.Album ?? "");

            if (string.Equals(item?.Type, "music", StringComparison.OrdinalIgnoreCase))
                return $"{title}|{artist}|{album}";

            return string.IsNullOrWhiteSpace(title)
                ? NormalizeForDuplicateCheck(item?.FilePath ?? "")
                : title;
        }

        private static string BuildMediaItemLabel(MediaItem item)
        {
            var title = string.IsNullOrWhiteSpace(item.Title)
                ? Path.GetFileNameWithoutExtension(item.FilePath) ?? "Untitled"
                : item.Title;
            return $"{title} [{item.Type}]";
        }

        private static MediaAgentResultItem BuildLocalResultCard(
            MediaItem item,
            string source,
            string provider,
            string subtitle,
            string overview,
            IReadOnlyCollection<string>? tags = null)
        {
            var resolvedTags = (tags ?? item?.Genres ?? new List<string>())
                .Where(tag => !string.IsNullOrWhiteSpace(tag))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .Take(3)
                .ToList();

            return new MediaAgentResultItem
            {
                Kind = MediaAgentResultItem.ResultKind.Local,
                MediaTypeId = item?.Type ?? "",
                Title = string.IsNullOrWhiteSpace(item?.Title) ? Path.GetFileNameWithoutExtension(item?.FilePath) ?? "Untitled" : item.Title,
                ArtistName = item?.Artist ?? "",
                Subtitle = subtitle,
                Year = item != null && item.Year > 0 ? (int?)item.Year : null,
                Rating = item != null && item.Rating > 0 ? (double?)item.Rating : null,
                Provider = provider,
                Source = source,
                Overview = overview,
                LocalPath = item?.FilePath ?? "",
                Tags = resolvedTags,
                CanPlay = item != null && !string.IsNullOrWhiteSpace(item.FilePath),
                CanOpenLocation = item != null && !string.IsNullOrWhiteSpace(item.FilePath) && File.Exists(item.FilePath)
            };
        }

        private static void AppendMetadataGroup(List<string> lines, string label, IReadOnlyCollection<string> items)
        {
            if (items == null || items.Count == 0)
                return;

            lines.Add($"{label}: {items.Count}");
            foreach (var item in items)
                lines.Add(item);
        }

        private static DateTime? GetBestLocalTimestampUtc(MediaItem item)
        {
            try
            {
                if (item?.PlaybackItem != null)
                {
                    if (item.PlaybackItem.DateAdded > DateTime.MinValue)
                        return item.PlaybackItem.DateAdded.Kind == DateTimeKind.Utc
                            ? item.PlaybackItem.DateAdded
                            : item.PlaybackItem.DateAdded.ToUniversalTime();

                    if (item.PlaybackItem.LastModified > DateTime.MinValue)
                        return item.PlaybackItem.LastModified.Kind == DateTimeKind.Utc
                            ? item.PlaybackItem.LastModified
                            : item.PlaybackItem.LastModified.ToUniversalTime();
                }

                return GetMediaFileTimestampUtc(item?.FilePath ?? "");
            }
            catch
            {
                return GetMediaFileTimestampUtc(item?.FilePath ?? "");
            }
        }

        private static long GetMediaFileSizeBytes(MediaItem item)
        {
            try
            {
                if (item?.PlaybackItem != null && item.PlaybackItem.FileSize > 0)
                    return item.PlaybackItem.FileSize;

                var path = item?.FilePath ?? "";
                if (string.IsNullOrWhiteSpace(path) || !File.Exists(path))
                    return 0;

                return new FileInfo(path).Length;
            }
            catch
            {
                return 0;
            }
        }

        private static string FormatBytes(long bytes)
        {
            if (bytes <= 0) return "0 B";

            string[] units = { "B", "KB", "MB", "GB", "TB" };
            var size = (double)bytes;
            var unitIndex = 0;
            while (size >= 1024 && unitIndex < units.Length - 1)
            {
                size /= 1024;
                unitIndex++;
            }

            return size >= 100 || unitIndex == 0
                ? $"{size:0} {units[unitIndex]}"
                : $"{size:0.0} {units[unitIndex]}";
        }

        private bool TryRunMediaAgentInsightCommand(string instruction, out string reply)
        {
            reply = "";
            var raw = (instruction ?? "").Trim();
            if (!raw.StartsWith("agent:", StringComparison.OrdinalIgnoreCase))
                return false;

            var actionId = raw.Substring("agent:".Length).Trim().ToLowerInvariant();
            var scope = ResolveMediaAiScopeItems();

            if (actionId == "explain-selected")
            {
                var selected = PreviewItem
                    ?? DetailsItem
                    ?? LibraryItems.FirstOrDefault(i => i != null && i.IsPlaying)
                    ?? LibraryItems.FirstOrDefault();

                if (selected == null)
                {
                    reply = "No selected media item. Select an item and run Explain Selected again.";
                    return true;
                }

                var title = string.IsNullOrWhiteSpace(selected.Title)
                    ? Path.GetFileNameWithoutExtension(selected.FilePath) ?? "Untitled"
                    : selected.Title;

                reply =
                    "EXPLAIN SELECTED\n" +
                    $"Title: {title}\n" +
                    $"Type: {selected.Type}\n" +
                    $"Artist: {(string.IsNullOrWhiteSpace(selected.Artist) ? "n/a" : selected.Artist)}\n" +
                    $"Album: {(string.IsNullOrWhiteSpace(selected.Album) ? "n/a" : selected.Album)}\n" +
                    $"Year: {(selected.Year <= 0 ? "n/a" : selected.Year.ToString(CultureInfo.InvariantCulture))}\n" +
                    $"Rating: {(selected.Rating <= 0 ? "n/a" : selected.Rating.ToString("0.0", CultureInfo.InvariantCulture))}\n" +
                    $"Duration: {selected.DurationText}\n" +
                    "Recommendation: Keep this item as a reference point while cleaning nearby metadata.";
                return true;
            }

            if (actionId == "build-playlist-idea")
            {
                var tracks = scope
                    .Where(i => i != null && string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase))
                    .Take(60)
                    .ToList();

                if (tracks.Count == 0)
                {
                    reply = "No music tracks found in current scope to build a playlist idea.";
                    return true;
                }

                var groups = tracks
                    .GroupBy(i => string.IsNullOrWhiteSpace(i.Artist) ? "Unknown Artist" : i.Artist)
                    .OrderByDescending(g => g.Count())
                    .Take(5)
                    .ToList();

                var lines = new List<string> { "PLAYLIST IDEA (preview)", $"Scope tracks sampled: {tracks.Count}" };
                foreach (var group in groups)
                    lines.Add($"- {group.Key}: {group.Count()} tracks");
                lines.Add("Suggested flow: start high-energy, transition to melodic, finish with recent favorites.");
                reply = string.Join("\n", lines);
                return true;
            }

            if (actionId == "find-duplicate-looking")
            {
                var duplicates = scope
                    .Where(i => i != null)
                    .GroupBy(i => $"{NormalizeForDuplicateCheck(i.Title)}|{(i.Type ?? "").ToLowerInvariant()}")
                    .Where(g => !string.IsNullOrWhiteSpace(g.Key) && g.Count() > 1)
                    .OrderByDescending(g => g.Count())
                    .Take(20)
                    .ToList();

                if (duplicates.Count == 0)
                {
                    reply = "No duplicate-looking titles found in the current scope.";
                    return true;
                }

                var lines = new List<string> { $"DUPLICATE-LOOKING GROUPS: {duplicates.Count}" };
                foreach (var group in duplicates)
                {
                    var sample = group.First();
                    lines.Add($"- {BuildMediaItemLabel(sample)} x{group.Count()}");
                }
                lines.Add("Preview only - apply action not wired yet.");
                reply = string.Join("\n", lines);
                return true;
            }

            if (actionId == "find-missing-metadata")
            {
                var missing = scope
                    .Where(i => i != null)
                    .Where(i =>
                        string.IsNullOrWhiteSpace(i.Title) ||
                        (string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase) &&
                         (string.IsNullOrWhiteSpace(i.Artist) || string.IsNullOrWhiteSpace(i.Album))) ||
                        ((string.Equals(i.Type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(i.Type, "tv", StringComparison.OrdinalIgnoreCase)) && i.Year <= 0))
                    .Take(30)
                    .ToList();

                if (missing.Count == 0)
                {
                    reply = "No obvious missing metadata found in the current scope.";
                    return true;
                }

                var lines = new List<string> { $"MISSING METADATA CANDIDATES: {missing.Count}" };
                foreach (var item in missing)
                    lines.Add($"- {BuildMediaItemLabel(item)}");
                lines.Add("Preview only - apply action not wired yet.");
                reply = string.Join("\n", lines);
                return true;
            }

            if (actionId == "recent-additions")
            {
                var ranked = scope
                    .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                    .Select(i => new
                    {
                        Item = i,
                        TimestampUtc = GetMediaFileTimestampUtc(i.FilePath)
                    })
                    .Where(x => x.TimestampUtc.HasValue)
                    .OrderByDescending(x => x.TimestampUtc.Value)
                    .Take(20)
                    .ToList();

                if (ranked.Count == 0)
                {
                    reply = "No local-file timestamps available for recent additions in this scope.";
                    return true;
                }

                var lines = new List<string> { "RECENT ADDITIONS (best-effort by file timestamp)" };
                foreach (var entry in ranked)
                    lines.Add($"- {BuildMediaItemLabel(entry.Item)} · {entry.TimestampUtc:yyyy-MM-dd HH:mm}");
                reply = string.Join("\n", lines);
                return true;
            }

            if (actionId == "cleanup-plan")
            {
                var duplicates = scope
                    .GroupBy(i => $"{NormalizeForDuplicateCheck(i.Title)}|{(i.Type ?? "").ToLowerInvariant()}")
                    .Count(g => !string.IsNullOrWhiteSpace(g.Key) && g.Count() > 1);

                var missingMeta = scope.Count(i =>
                    string.IsNullOrWhiteSpace(i.Title) ||
                    (string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase) &&
                     (string.IsNullOrWhiteSpace(i.Artist) || string.IsNullOrWhiteSpace(i.Album))));

                var missingFiles = scope.Count(i => IsLikelyMissingLocalFile(i.FilePath));

                reply =
                    "CLEANUP PLAN (preview)\n" +
                    $"Scope size: {scope.Count}\n" +
                    $"1) Duplicate-looking groups: {duplicates}\n" +
                    $"2) Missing metadata items: {missingMeta}\n" +
                    $"3) Missing local files: {missingFiles}\n" +
                    "4) Run fixes in small batches and verify each batch.\n" +
                    "Preview only - apply action not wired yet.";
                return true;
            }

            return false;
        }

        private static DateTime? GetMediaFileTimestampUtc(string path)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(path)) return null;
                if (Uri.TryCreate(path, UriKind.Absolute, out var uri) &&
                    (uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) || uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)))
                    return null;

                if (!File.Exists(path)) return null;
                return File.GetLastWriteTimeUtc(path);
            }
            catch
            {
                return null;
            }
        }

        private static bool IsLikelyMissingLocalFile(string path)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(path)) return false;
                if (Uri.TryCreate(path, UriKind.Absolute, out var uri) &&
                    (uri.Scheme.Equals("http", StringComparison.OrdinalIgnoreCase) || uri.Scheme.Equals("https", StringComparison.OrdinalIgnoreCase)))
                    return false;
                return !File.Exists(path);
            }
            catch
            {
                return false;
            }
        }

        private bool TryBuildMediaApprovalPreview(string instruction, int scopedItems, out string preview)
        {
            preview = "";
            var lower = (instruction ?? "").Trim().ToLowerInvariant();
            if (string.IsNullOrWhiteSpace(lower)) return false;

            var isRisky =
                lower.Contains("delete") ||
                lower.Contains("remove") ||
                lower.Contains("clear library") ||
                lower.Contains("rename") ||
                lower.Contains("organize") ||
                lower.Contains("optimiz") ||
                lower.Contains("retag") ||
                lower.Contains("metadata") ||
                lower.Contains("bulk") ||
                lower.Contains("apply") ||
                lower.Contains("write tags") ||
                lower.Contains("change ");

            if (!isRisky)
                return false;

            var steps = new List<string>();
            if (lower.Contains("delete") || lower.Contains("remove") || lower.Contains("clear"))
                steps.Add("Identify the exact items that would be removed from library records.");
            if (lower.Contains("rename") || lower.Contains("title"))
                steps.Add("Generate a proposed rename list for review before any file/library updates.");
            if (lower.Contains("metadata") || lower.Contains("retag") || lower.Contains("optimiz") || lower.Contains("organize"))
                steps.Add("Create a metadata diff preview showing current vs proposed values.");
            if (steps.Count == 0)
                steps.Add("Generate a non-destructive preview report for all intended changes.");

            var builder = new StringBuilder();
            builder.AppendLine("APPROVAL REQUIRED - Atlas Media Agent");
            builder.AppendLine($"Request: {instruction}");
            builder.AppendLine($"Scope: {scopedItems} item(s)");
            builder.AppendLine("Proposed preview steps:");
            for (var i = 0; i < steps.Count; i++)
                builder.AppendLine($"{i + 1}. {steps[i]}");
            builder.Append("Preview only - apply action not wired yet.");

            preview = builder.ToString();
            return true;
        }

        private void RunMediaAgentQuickAction(string? actionId)
        {
            if (string.IsNullOrWhiteSpace(actionId)) return;
            if (_mediaAiCts != null) return;

            var action = MediaAgentQuickActions.FirstOrDefault(a => string.Equals(a.Id, actionId, StringComparison.OrdinalIgnoreCase));
            if (action == null) return;

            if (!TryMapQuickActionToPrompt(action.Id, out var prompt))
                prompt = $"agent:{action.Id}";

            MediaAiCommandText = prompt;
            SendMediaAi();
        }

