        private bool TryApplyLocalMediaCommand(string instruction, out string reply)
        {
            reply = "";
            instruction = (instruction ?? "").Trim();
            if (string.IsNullOrWhiteSpace(instruction)) return false;

            var lower = instruction.ToLowerInvariant();
            if (lower.Contains("clear chat") || lower.Contains("reset chat") || lower == "clear ai")
            {
                try
                {
                    MediaAiChat.Clear();
                    EnsureMediaAiGreeting();
                }
                catch
                {
                }
                reply = "Cleared assistant chat";
                return true;
            }
            if (lower.Contains("clear search") || lower.Contains("reset search") || lower == "clear" || lower == "reset")
            {
                SearchQuery = "";
                reply = "Cleared search";
                return true;
            }

            var isFind =
                lower.StartsWith("find ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("show ", StringComparison.OrdinalIgnoreCase) ||
                lower.StartsWith("search ", StringComparison.OrdinalIgnoreCase);

            if (!isFind)
            {
                var wordCount = Regex.Matches(instruction, "\\S+").Count;
                var looksLikeQuestion =
                    lower.Contains("?") ||
                    lower.StartsWith("how ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("what ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("why ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("tell ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("explain ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("who ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("when ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("where ", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("can you", StringComparison.OrdinalIgnoreCase) ||
                    lower.StartsWith("could you", StringComparison.OrdinalIgnoreCase);
                var looksLikeAction =
                    lower.Contains("optimiz") ||
                    lower.Contains("organize") ||
                    lower.Contains("rename") ||
                    lower.Contains("update") ||
                    lower.Contains("delete") ||
                    lower.Contains("remove") ||
                    lower.Contains("add ") ||
                    lower.Contains("scan") ||
                    lower.Contains("play ");

                if (!looksLikeQuestion && !looksLikeAction && wordCount > 0 && wordCount <= 6)
                    isFind = true;
                else
                    return false;
            }

            var categoryId = "";
            if (lower.Contains(" movie") || lower.Contains(" movies")) categoryId = "movies";
            else if (lower.Contains(" tv") || lower.Contains(" series") || lower.Contains(" shows")) categoryId = "tv";
            else if (lower.Contains(" music") || lower.Contains(" songs") || lower.Contains(" albums")) categoryId = "music";
            else if (lower.Contains(" games")) categoryId = "games";
            else if (lower.Contains(" images") || lower.Contains(" photos")) categoryId = "images";

            var q = isFind && (lower.StartsWith("find ", StringComparison.OrdinalIgnoreCase) ||
                               lower.StartsWith("show ", StringComparison.OrdinalIgnoreCase) ||
                               lower.StartsWith("search ", StringComparison.OrdinalIgnoreCase))
                ? Regex.Replace(instruction, "^(find|show|search)\\s+(me\\s+)?(all\\s+)?", "", RegexOptions.IgnoreCase).Trim()
                : instruction;
            q = Regex.Replace(q, "\\b(movies?|tv|series|shows?|music|songs?|albums?|games?|images?|photos?)\\b", "", RegexOptions.IgnoreCase).Trim();
            q = Regex.Replace(q, "\\b(me|the|a|an|all|every)\\b", "", RegexOptions.IgnoreCase).Trim();
            q = Regex.Replace(q, "\\s+", " ").Trim();
            if (string.IsNullOrWhiteSpace(q)) return false;
            if (IsLibraryOpen) IsLibraryOpen = false;

            if (!string.IsNullOrWhiteSpace(categoryId))
            {
                var target = Categories.FirstOrDefault(c => string.Equals(c.Id, categoryId, StringComparison.OrdinalIgnoreCase));
                if (target != null && !ReferenceEquals(SelectedCategory, target))
                    SelectCategory(target);
            }

            List<MediaItem> results;
            if (string.Equals(q, "marvel", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(q, "mcu", StringComparison.OrdinalIgnoreCase) ||
                q.Contains("marvel", StringComparison.OrdinalIgnoreCase) ||
                q.Contains("mcu", StringComparison.OrdinalIgnoreCase))
            {
                var wantsServers = lower.Contains("server", StringComparison.OrdinalIgnoreCase) ||
                                   lower.Contains("servers", StringComparison.OrdinalIgnoreCase) ||
                                   HasAddonServers;

                var localTokens = new[]
                {
                    "avengers", "iron man", "ironman", "captain america", "thor", "spider-man", "spiderman",
                    "guardians", "black panther", "doctor strange", "ant-man", "hulk", "shang-chi",
                    "eternals", "deadpool", "wolverine", "fantastic four", "x-men", "loki", "wanda",
                    "black widow", "hawkeye"
                };

                var localBase = _allItems.Where(i => string.Equals(i.Type, "movies", StringComparison.OrdinalIgnoreCase));
                var localResults = localBase
                    .Where(i =>
                    {
                        var t = (i.Title ?? "").ToLowerInvariant();
                        if (string.IsNullOrWhiteSpace(t)) return false;
                        foreach (var token in localTokens)
                        {
                            if (t.Contains(token, StringComparison.OrdinalIgnoreCase))
                                return true;
                        }
                        return false;
                    })
                    .Take(250)
                    .ToList();

                if (wantsServers)
                {
                    var serversCategory = Categories.FirstOrDefault(c => string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase));
                    if (serversCategory != null && !ReferenceEquals(SelectedCategory, serversCategory))
                        SelectCategory(serversCategory);

                    SelectedServerCatalogType = "movie";
                    ServerCatalogSearchQuery = "marvel";
                    _ = RefreshServerCatalogAsync();

                    reply = $"SEARCHING SERVERS · MOVIES · marvel\nLocal matches: {localResults.Count}";
                    return true;
                }

                if (string.IsNullOrWhiteSpace(categoryId))
                {
                    var target = Categories.FirstOrDefault(c => string.Equals(c.Id, "movies", StringComparison.OrdinalIgnoreCase));
                    if (target != null && !ReferenceEquals(SelectedCategory, target))
                        SelectCategory(target);
                }

                results = localResults;
                SearchQuery = "marvel";
            }
            else
            {
                SearchQuery = q;
                results = FindLibraryItems(q, string.IsNullOrWhiteSpace(categoryId) ? null : categoryId, 250);
            }

            var titles = results
                .Select(r =>
                {
                    var t = (r.Title ?? "").Trim();
                    if (!string.IsNullOrWhiteSpace(t)) return t;
                    var p = (r.FilePath ?? "").Trim();
                    if (string.IsNullOrWhiteSpace(p)) return "";
                    var n = Path.GetFileNameWithoutExtension(p) ?? "";
                    return (n ?? "").Trim();
                })
                .Where(t => !string.IsNullOrWhiteSpace(t))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (titles.Count == 0)
            {
                // Only return "No matches" if the user EXPLICITLY asked for a search.
                // If it was just an implicit search (short keyword), let it fall through to the AI provider.
                var explicitSearch = lower.StartsWith("find ", StringComparison.OrdinalIgnoreCase) ||
                                     lower.StartsWith("show ", StringComparison.OrdinalIgnoreCase) ||
                                     lower.StartsWith("search ", StringComparison.OrdinalIgnoreCase);

                if (explicitSearch)
                {
                    var label = string.IsNullOrWhiteSpace(categoryId) ? "ITEMS" : categoryId.ToUpperInvariant();
                    reply = $"NO MATCHES · {label} · {q}\nTry: avengers, iron man, captain america, spider-man";
                    return true;
                }
                
                return false;
            }

            var take = Math.Min(40, titles.Count);
            reply = $"FOUND {titles.Count} · {(string.IsNullOrWhiteSpace(categoryId) ? "ITEMS" : categoryId.ToUpperInvariant())} · {q}\n" +
                    string.Join("\n", titles.Take(take).Select(t => $"• {t}"));
            if (titles.Count > take)
                reply += $"\n… +{titles.Count - take} more";
            return true;
        }

        private static List<AiOptimizedMetadata> BuildLocalMusicOrganizeUpdates(List<MediaItem> items)
        {
            var updates = new List<AiOptimizedMetadata>();
            foreach (var t in items)
            {
                if (t == null) continue;
                if (!string.Equals(t.Type, "music", StringComparison.OrdinalIgnoreCase)) continue;
                if (string.IsNullOrWhiteSpace(t.FilePath)) continue;

                var albumRoot = GetAlbumRootFolder(t.FilePath);
                var folderName = Path.GetFileName(albumRoot) ?? "";
                var (folderArtist, folderAlbum) = DeriveArtistAlbumFromFolderName(folderName);

                var next = new AiOptimizedMetadata { FilePath = t.FilePath };

                if (string.IsNullOrWhiteSpace(t.Artist) && !string.IsNullOrWhiteSpace(folderArtist))
                    next.Artist = folderArtist;

                if ((string.IsNullOrWhiteSpace(t.Album) || IsDiscToken(t.Album)) && !string.IsNullOrWhiteSpace(folderAlbum))
                    next.Album = NormalizeAlbumTitle(folderAlbum);

                if (t.TrackNumber == 0 && TryParseTrackNumberFromFileName(t.FilePath, out var tn))
                    next.TrackNumber = tn;

                if (t.DiscNumber == 0)
                {
                    var disc = GetDiscNumberFromPath(t.FilePath);
                    if (disc > 0) next.DiscNumber = disc;
                }

                if (LooksLikeFileNameTitle(t))
                {
                    var cleaned = CleanTitleFromFileName(t.FilePath);
                    if (!string.IsNullOrWhiteSpace(cleaned))
                        next.Title = cleaned;
                }

                if (next.Title != null || next.Artist != null || next.Album != null || next.TrackNumber != null || next.DiscNumber != null)
                    updates.Add(next);
            }

            return updates;
        }

        private void CancelMediaAi()
        {
            try
            {
                _mediaAiCts?.Cancel();
            }
            catch
            {
            }
            CommandManager.InvalidateRequerySuggested();
        }

        private async Task<bool> EnhanceWithMusicBrainz(List<AiOptimizedMetadata> items, bool fetchMetadata, bool fetchCovers, CancellationToken ct)
        {
            bool anySuccess = false;

            // 1. Try to find albums for single tracks (missing album)
            if (fetchMetadata)
            {
                var singles = items.Where(i => !string.IsNullOrWhiteSpace(i.Artist) && 
                                               !string.IsNullOrWhiteSpace(i.Title) && 
                                               string.IsNullOrWhiteSpace(i.Album)).ToList();
                
                foreach (var single in singles)
                {
                    if (ct.IsCancellationRequested) break;
                    
                    // Search by recording
                    var results = await _mbClient.SearchRecordingMetadataAsync("AtlasAI", single.Artist, single.Title, ct);
                    if (results.Count > 0)
                    {
                        var best = results[0];
                        // Update the metadata
                        if (!string.IsNullOrWhiteSpace(best.Artist)) single.Artist = best.Artist;
                        if (!string.IsNullOrWhiteSpace(best.Album)) single.Album = best.Album;
                        if (!string.IsNullOrWhiteSpace(best.Title)) single.Title = best.Title;
                        if (best.TrackNumber > 0) single.TrackNumber = best.TrackNumber;
                        if (best.DiscNumber > 0) single.DiscNumber = best.DiscNumber;
                        anySuccess = true;
                    }
                }
            }

            // 2. Try to fetch covers
            if (fetchCovers)
            {
                foreach (var item in items)
                {
                    if (ct.IsCancellationRequested) break;
                    if (string.IsNullOrWhiteSpace(item.Artist) || string.IsNullOrWhiteSpace(item.Album)) continue;

                    var dir = Path.GetDirectoryName(item.FilePath);
                    if (string.IsNullOrWhiteSpace(dir)) continue;

                    var coverPath = Path.Combine(dir, "folder.jpg");
                    if (File.Exists(coverPath)) continue;

                    // Try MusicBrainz
                    var mbSuccess = await _mbClient.TryDownloadAlbumArtAsync("AtlasAI", item.Artist, item.Album, coverPath, ct);
                    if (mbSuccess)
                    {
                        anySuccess = true;
                        continue;
                    }
                    
                    // Try ReccoBeats Fallback
                    var rbSuccess = await _reccoClient.TryDownloadCoverAsync(item.Artist, item.Album, coverPath, ct);
                    if (rbSuccess)
                    {
                         anySuccess = true;
                         continue;
                    }

                    // Try iTunes Fallback
                    var itSuccess = await _itunesClient.TryDownloadCoverAsync(item.Artist, item.Album, coverPath, ct);
                    if (itSuccess)
                    {
                        anySuccess = true;
                    }
                }
            }
            
            return anySuccess;
        }

        private static List<object> BuildMediaAiCommandPrompt(List<MediaItem> batch, string instruction)
        {
            var allowed = "music,movies,tv,images,games,radio,karaoke";
            var payload = batch.Select(i => new
            {
                filePath = i.FilePath,
                folder = Path.GetDirectoryName(i.FilePath) ?? "",
                albumRootFolder = GetAlbumRootFolder(i.FilePath),
                type = i.Type,
                title = i.Title,
                artist = i.Artist,
                album = i.Album,
                trackNumber = i.TrackNumber == 0 ? (int?)null : i.TrackNumber,
                discNumber = i.DiscNumber == 0 ? (int?)null : i.DiscNumber
            }).ToList();

            var userPayload = new
            {
                instruction,
                items = payload
            };

            return new List<object>
            {
                new
                {
                    role = "system",
                    content =
                        "You are Atlas Media Centre Agent. " +
                        "Apply the user's instruction to the provided items only. " +
                        $"Allowed type values: {allowed}. " +
                        "Return ONLY valid JSON (no markdown) as an array of objects. " +
                        "Each object must include: filePath. " +
                        "Optional: title, artist, album, type, trackNumber, discNumber. " +
                        "Never set fields to empty strings. " +
                        "If unsure, omit the field."
                },
                new
                {
                    role = "user",
                    content = JsonSerializer.Serialize(userPayload)
                }
            };
        }

        private static bool TryParseTrackNumberFromFileName(string filePath, out int trackNumber)
        {
            trackNumber = 0;
            try
            {
                var name = Path.GetFileNameWithoutExtension(filePath) ?? "";
                name = name.Trim();
                if (name.Length < 2) return false;

                var m = Regex.Match(name, "^(\\d{1,3})\\s*[\\-\\._\\)]\\s+");
                if (!m.Success)
                    m = Regex.Match(name, "^(\\d{1,3})\\s+");
                if (!m.Success) return false;

                if (!int.TryParse(m.Groups[1].Value, out var v)) return false;
                if (v <= 0 || v > 999) return false;
                trackNumber = v;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private void EditAlbumInfo(AlbumEntry? album)
        {
            if (album == null) return;
            if (album.Tracks == null || album.Tracks.Count == 0) return;

            var result = ShowAlbumEditModal(album);
            if (result == null) return;

            var nextArtist = result.Value.artist;
            var nextAlbum = NormalizeAlbumTitle(result.Value.album);

            var updates = album.Tracks
                .Where(t => t != null && !string.IsNullOrWhiteSpace(t.FilePath))
                .Select(t => new AiOptimizedMetadata
                {
                    FilePath = t.FilePath,
                    Artist = nextArtist,
                    Album = nextAlbum
                })
                .ToList();

            ApplyOptimizedMetadata(updates, true, true, true);
        }

        public void LoadAlbumDetails(AlbumEntry album)
        {
            if (album == null) return;
            _ = Task.Run(() => LoadAlbumDetailsAsync(album));
        }

        public void ForceReloadAlbumDetails(AlbumEntry album)
        {
            if (album == null) return;
            var key = (album.SourceFolderPath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(key)) return;

            try
            {
                lock (_albumDetailsLock)
                {
                    _albumDetailsLoaded.Remove(key);
                }
            }
            catch
            {
            }

            LoadAlbumDetails(album);
        }

        private async Task LoadAlbumDetailsAsync(AlbumEntry album)
        {
            var key = (album.SourceFolderPath ?? "").Trim();
            if (string.IsNullOrWhiteSpace(key)) return;

            lock (_albumDetailsLock)
            {
                if (_albumDetailsLoaded.Contains(key)) return;
                _albumDetailsLoaded.Add(key);
            }

            try
            {
                _uiDispatcher.Invoke(() =>
                {
                    album.DetailTracks.Clear();
                    try
                    {
                        var local = album.Tracks
                            .Where(t => t != null)
                            .Select(t => new AlbumDetailTrack
                            {
                                DiscNumber = 1,
                                TrackNumber = t.TrackNumber,
                                Title = (string.IsNullOrWhiteSpace(t.Title) ? System.IO.Path.GetFileNameWithoutExtension(t.FilePath) : t.Title).Trim(),
                                Artist = (string.IsNullOrWhiteSpace(t.Artist) ? (album.Artist ?? "") : t.Artist).Trim()
                            })
                            .Where(t => !string.IsNullOrWhiteSpace(t.Title))
                            .OrderBy(t => t.TrackNumber <= 0 ? int.MaxValue : t.TrackNumber)
                            .ToList();

                        foreach (var t in local) album.DetailTracks.Add(t);
                    }
                    catch
                    {
                    }

                    album.DetailsStatusText = album.DetailTracks.Count > 0 ? $"Local · {album.DetailTracks.Count} tracks" : "Local metadata missing";
                });

                var mbContact = (IntegrationKeyStore.GetDecrypted("musicbrainz_contact") ?? "").Trim();
                var effectiveContact = string.IsNullOrWhiteSpace(mbContact) ? "AtlasAI" : mbContact;
                if (string.IsNullOrWhiteSpace(mbContact))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        // Continue anyway with a fallback User-Agent so MusicBrainz metadata still works.
                        album.DetailsStatusText = album.DetailTracks.Count > 0
                            ? $"Local · {album.DetailTracks.Count} tracks · MusicBrainz (fallback contact)"
                            : "MusicBrainz (fallback contact)";
                    });
                }

                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(35));
                var ct = cts.Token;

                var tracks = await _mbClient.SearchReleaseMetadataAsync(effectiveContact, album.Artist, album.AlbumTitle, ct).ConfigureAwait(false);
                if (tracks.Count == 0)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        if (album.DetailTracks.Count > 0)
                            album.DetailsStatusText = $"Local · {album.DetailTracks.Count} tracks";
                        else
                            album.DetailsStatusText = "No MusicBrainz match";
                    });
                    return;
                }

                var mbMeta = tracks.FirstOrDefault();

                var mapped = tracks
                    .Where(t => t != null && t.TrackNumber > 0)
                    .OrderBy(t => t.DiscNumber)
                    .ThenBy(t => t.TrackNumber)
                    .Select(t => new AlbumDetailTrack
                    {
                        DiscNumber = t.DiscNumber <= 0 ? 1 : t.DiscNumber,
                        TrackNumber = t.TrackNumber,
                        Title = (t.Title ?? "").Trim(),
                        Artist = (t.Artist ?? "").Trim()
                    })
                    .Where(t => !string.IsNullOrWhiteSpace(t.Title))
                    .ToList();

                _uiDispatcher.Invoke(() =>
                {
                    album.DetailTracks.Clear();
                    foreach (var t in mapped) album.DetailTracks.Add(t);
                    album.DetailsStatusText = album.DetailTracks.Count > 0 ? $"MusicBrainz · {album.DetailTracks.Count} tracks" : "MusicBrainz loaded";

                    try
                    {
                        album.MusicBrainzReleaseId = (mbMeta?.ReleaseId ?? "").Trim();
                        album.MusicBrainzReleaseDate = (mbMeta?.ReleaseDate ?? "").Trim();
                        album.MusicBrainzCountry = (mbMeta?.Country ?? "").Trim();
                        album.MusicBrainzLabel = (mbMeta?.Label ?? "").Trim();
                        album.MusicBrainzBarcode = (mbMeta?.Barcode ?? "").Trim();
                        album.MusicBrainzStatus = (mbMeta?.Status ?? "").Trim();
                        album.MusicBrainzPackaging = (mbMeta?.Packaging ?? "").Trim();
                    }
                    catch
                    {
                    }
                });

                try
                {
                    var dest = MediaArtworkCache.GetMusicFolderCoverCachePath(key);
                    var ok = await _mbClient.TryDownloadAlbumArtAsync(effectiveContact, album.Artist, album.AlbumTitle, dest, ct).ConfigureAwait(false);
                    if (ok)
                    {
                        var img = LoadMusicFolderCover(key);
                        if (img != null)
                            _uiDispatcher.Invoke(() => album.CoverImage = img);
                    }
                }
                catch
                {
                }
            }
            catch
            {
                try { _uiDispatcher.Invoke(() => album.DetailsStatusText = "MusicBrainz error"); } catch { }
            }
        }

        private void EditTrackInfo(MediaItem? item)
        {
            if (item == null) return;
            if (string.IsNullOrWhiteSpace(item.FilePath)) return;
            if (IsServersView) EnsureItemSavedToLibrary(item);

            if (string.Equals(item.Type, "games", StringComparison.OrdinalIgnoreCase))
            {
                var gameResult = ShowGameEditModal(item);
                if (gameResult == null) return;

                var update = new AiOptimizedMetadata
                {
                    FilePath = item.FilePath,
                    Title = gameResult.Value.title,
                    Album = gameResult.Value.platform,
                    Type = "games"
                };

                ApplyOptimizedMetadata(new List<AiOptimizedMetadata> { update }, true, true, true);
                return;
            }

            if (string.Equals(item.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(item.Type, "tv", StringComparison.OrdinalIgnoreCase))
            {
                var titleResult = ShowVideoEditModal(item);
                if (titleResult == null) return;

                ApplyVideoTitleEdit(item.FilePath, titleResult);
                return;
            }

            var trackResult = ShowTrackEditModal(item);
            if (trackResult == null) return;

            var updateTrack = new AiOptimizedMetadata
            {
                FilePath = item.FilePath,
                Title = trackResult.Value.title,
                Artist = trackResult.Value.artist,
                Album = NormalizeAlbumTitle(trackResult.Value.album),
                TrackNumber = trackResult.Value.trackNumber,
                DiscNumber = trackResult.Value.discNumber
            };

            ApplyOptimizedMetadata(new List<AiOptimizedMetadata> { updateTrack }, true, true, true);
        }

