        private void ChangeCover(MediaItem? item)
        {
            if (item == null) return;
            try
            {
                var dialog = new OpenFileDialog
                {
                    Title = $"Select cover image for {item.Title}",
                    Filter = "Image Files|*.png;*.jpg;*.jpeg;*.webp;*.bmp|All Files|*.*",
                    FilterIndex = 1,
                    CheckFileExists = true
                };

                if (dialog.ShowDialog() != true)
                    return;

                var selectedPath = dialog.FileName;
                if (string.IsNullOrWhiteSpace(selectedPath) || !File.Exists(selectedPath))
                    return;

                // Create covers directory if it doesn't exist
                var appDataPath = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "AtlasAI", "covers");
                Directory.CreateDirectory(appDataPath);

                // Generate unique filename for this item
                var itemId = Path.GetFileNameWithoutExtension(item.FilePath ?? "unknown");
                itemId = string.Join("_", itemId.Split(Path.GetInvalidFileNameChars()));
                var extension = Path.GetExtension(selectedPath);
                var destPath = Path.Combine(appDataPath, $"{itemId}_{Guid.NewGuid():N}{extension}");

                // Copy the selected image to our covers directory
                File.Copy(selectedPath, destPath, overwrite: true);

                // Update the item's cover URL to point to the local file
                item.CoverUrl = destPath;

                // Load the image into the UI
                _uiDispatcher.Invoke(() =>
                {
                    try
                    {
                        var bitmap = new BitmapImage();
                        bitmap.BeginInit();
                        bitmap.CacheOption = BitmapCacheOption.OnLoad;
                        bitmap.CreateOptions = BitmapCreateOptions.IgnoreImageCache;
                        bitmap.UriSource = new Uri(destPath, UriKind.Absolute);
                        bitmap.EndInit();
                        bitmap.Freeze();
                        item.CoverImage = bitmap;

                        StatusText = $"Cover updated for {item.Title}";
                        System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Cover changed for: {item.Title} -> {destPath}");

                        // Mark library as mutated so it gets saved
                        MarkLibraryMutated();
                    }
                    catch (Exception ex)
                    {
                        System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Failed to load cover image: {ex.Message}");
                        StatusText = "Failed to load cover image";
                    }
                });
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] ChangeCover error: {ex.Message}");
                StatusText = $"Error changing cover: {ex.Message}";
            }
        }

        private void RescanMetadata(MediaItem? item)
        {
            if (item == null) return;
            if (IsScanning) return;

            try
            {
                System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] Rescan metadata requested for: {item.Title} ({item.FilePath})");

                _uiDispatcher.Invoke(() =>
                {
                    StatusText = $"Rescanning metadata for {item.Title}...";
                });

                // Queue a rescan for this item
                _ = Task.Run(async () =>
                {
                    try
                    {
                        if (string.IsNullOrWhiteSpace(item.FilePath) || !File.Exists(item.FilePath))
                            return;

                        // For music, rescan tags
                        if (string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
                        {
                            var tags = _taggingService.ReadTags(item.FilePath);
                            _uiDispatcher.Invoke(() =>
                            {
                                item.Title = tags.title ?? Path.GetFileNameWithoutExtension(item.FilePath);
                                StatusText = $"Metadata rescanned for {item.Title}";
                                MarkLibraryMutated();
                            });
                        }
                        // For movies/TV, re-fetch external metadata  
                        else if (string.Equals(item.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                 string.Equals(item.Type, "tv", StringComparison.OrdinalIgnoreCase))
                        {
                            // Clear existing metadata
                            _uiDispatcher.Invoke(() =>
                            {
                                item.CoverUrl = null;
                                item.BackdropUrl = null;
                                item.Rating = 0;
                                StatusText = $"Metadata cleared for {item.Title}. Re-scan library to fetch new metadata.";
                                MarkLibraryMutated();
                            });
                        }
                    }
                    catch (Exception ex)
                    {
                        System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] RescanMetadata task error: {ex.Message}");
                        _uiDispatcher.Invoke(() =>
                        {
                            StatusText = $"Rescan failed: {ex.Message}";
                        });
                    }
                });
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"[MediaCentreViewModel] RescanMetadata error: {ex.Message}");
                StatusText = $"Error rescanning metadata: {ex.Message}";
            }
        }

