                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                save.Click += (_, _) =>
                {
                    var id = ExtractLeadingToken((idBox.Text ?? "").Trim(), 16, 64);
                    var secret = ExtractLeadingToken((secretBox.Password ?? "").Trim(), 16, 128);
                    if (string.IsNullOrWhiteSpace(id) || string.IsNullOrWhiteSpace(secret))
                        return;
                    result = (id, secret);
                    dialog.Close();
                };

                footer.Children.Add(cancel);
                footer.Children.Add(save);
                System.Windows.Controls.Grid.SetRow(footer, 2);
                root.Children.Add(footer);

                dialog.Content = root;
                dialog.ShowDialog();
                return result;
            }
            catch
            {
                return null;
            }
        }

        private void SetCustomCover(MediaItem? item)
        {
            if (item == null) return;
            if (string.IsNullOrWhiteSpace(item.FilePath)) return;
            if (IsServersView) EnsureItemSavedToLibrary(item);

            try
            {
                var dialog = new OpenFileDialog
                {
                    Title = "Select cover image",
                    Filter = "Image Files|*.png;*.jpg;*.jpeg;*.webp;*.bmp|All Files|*.*",
                    Multiselect = false
                };

                if (dialog.ShowDialog() != true) return;

                var src = dialog.FileName ?? "";
                if (string.IsNullOrWhiteSpace(src) || !File.Exists(src)) return;

                var ext = Path.GetExtension(src);
                if (string.IsNullOrWhiteSpace(ext)) ext = ".jpg";

                var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "CustomCovers");
                Directory.CreateDirectory(cacheDir);

                var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(item.FilePath));
                var hash = Convert.ToHexString(hashBytes);
                var dest = Path.Combine(cacheDir, $"{hash}{ext}");

                File.Copy(src, dest, true);

                ImageSource? bmp = null;
                try
                {
                    bmp = LoadAlbumCoverFromFile(dest);
                }
                catch
                {
                    bmp = null;
                }

                _uiDispatcher.Invoke(() =>
                {
                    item.CoverUrl = dest;
                    if (bmp != null) item.CoverImage = bmp;
                    StatusText = "Cover updated";
                    ScanProgressText = "Cover updated";
                    OnPropertyChanged(nameof(StatusText));
                });

                List<MediaItem> snapshot;
                lock (_stateLock)
                {
                    snapshot = _allItems.ToList();
                }
                _ = SaveLibraryToDiskAsync(snapshot);
            }
            catch
            {
            }
        }

        private void ApplyVideoTitleEdit(string filePath, string nextTitle)
        {
            if (string.IsNullOrWhiteSpace(filePath)) return;
            nextTitle = (nextTitle ?? "").Trim();
            if (string.IsNullOrWhiteSpace(nextTitle)) return;

            MediaItem? next = null;
            lock (_stateLock)
            {
                for (var i = 0; i < _allItems.Count; i++)
                {
                    var existing = _allItems[i];
                    if (existing == null) continue;
                    if (!string.Equals(existing.FilePath, filePath, StringComparison.OrdinalIgnoreCase)) continue;

                    try
                    {
                        if (existing.PlaybackItem != null)
                            existing.PlaybackItem.DisplayName = nextTitle;
                    }
                    catch
                    {
                    }

                    next = new MediaItem
                    {
                        PlaybackItem = existing.PlaybackItem,
                        FilePath = existing.FilePath,
                        Title = nextTitle,
                        Artist = existing.Artist,
                        Album = existing.Album,
                        TrackNumber = existing.TrackNumber,
                        DiscNumber = existing.DiscNumber,
                        Duration = existing.Duration,
                        Type = existing.Type,
                        AccentBrush = existing.AccentBrush,
                        IconGeometry = existing.IconGeometry,
                        LastAiOptimizedUtc = existing.LastAiOptimizedUtc,
                        CoverUrl = existing.CoverUrl,
                        CoverImage = existing.CoverImage
                    };
                    next.IsFavorite = existing.IsFavorite;
                    next.IsSelected = existing.IsSelected;
                    next.IsPlaying = existing.IsPlaying;
                    _allItems[i] = next;
                    break;
                }
            }

            if (next == null) return;

            try
            {
                for (var i = 0; i < LibraryItems.Count; i++)
                {
                    var li = LibraryItems[i];
                    if (li == null) continue;
                    if (!string.Equals(li.FilePath, next.FilePath, StringComparison.OrdinalIgnoreCase)) continue;
                    LibraryItems[i] = next;
                    break;
                }
            }
            catch
            {
            }

            try
            {
                if (DetailsItem != null && string.Equals(DetailsItem.FilePath, next.FilePath, StringComparison.OrdinalIgnoreCase))
                    DetailsItem = next;
            }
            catch
            {
            }

            _ = Task.Run(() =>
            {
                try
                {
                    List<MediaItem> snapshot;
                    lock (_stateLock)
                    {
                        snapshot = _allItems.ToList();
                    }
                    _ = SaveLibraryToDiskAsync(snapshot);
                }
                catch
                {
                }
            });
        }

        private static System.Windows.Window? GetDialogOwner()
        {
            try
            {
                var app = System.Windows.Application.Current;
                if (app == null) return null;

                foreach (System.Windows.Window w in app.Windows)
                {
                    if (w != null && w.IsActive) return w;
                }

                return app.MainWindow;
            }
            catch
            {
                return System.Windows.Application.Current?.MainWindow;
            }
        }

