                System.Windows.Controls.Grid.SetColumn(artistBox, 1);
                form.Children.Add(artistBox);

                var albumLabel = new System.Windows.Controls.TextBlock { Text = "Album", Foreground = labelBrush, Margin = new System.Windows.Thickness(0, 6, 12, 6) };
                System.Windows.Controls.Grid.SetRow(albumLabel, 1);
                System.Windows.Controls.Grid.SetColumn(albumLabel, 0);
                form.Children.Add(albumLabel);

