                {
                    Text = album.AlbumTitle ?? "",
                    Background = inputBg,
                    Foreground = inputFg,
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1),
                    Padding = new System.Windows.Thickness(10, 6, 10, 6),
                    Margin = new System.Windows.Thickness(0, 2, 0, 8)
                };
                System.Windows.Controls.Grid.SetRow(albumBox, 1);
                System.Windows.Controls.Grid.SetColumn(albumBox, 1);
                form.Children.Add(albumBox);

                dialog.Loaded += (_, _) =>
                {
                    try
                    {
                        dialog.Activate();
                        artistBox.Focus();
                        artistBox.SelectAll();
                        Keyboard.Focus(artistBox);
                    }
                    catch
                    {
                    }
                };

                // --- Buttons Row ---
                form.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = System.Windows.GridLength.Auto });
                
                var actionsPanel = new System.Windows.Controls.StackPanel
                {
                    Orientation = System.Windows.Controls.Orientation.Horizontal,
                    Margin = new System.Windows.Thickness(0, 8, 0, 8)
                };
                System.Windows.Controls.Grid.SetRow(actionsPanel, 2);
                System.Windows.Controls.Grid.SetColumn(actionsPanel, 1);

                var searchBtn = new System.Windows.Controls.Button
                {
                    Content = "Search Metadata",
                    Background = new SolidColorBrush(Color.FromArgb(0x20, 0x22, 0xD3, 0xEE)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderThickness = new System.Windows.Thickness(0),
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 8, 0),
                    Cursor = System.Windows.Input.Cursors.Hand
                };
                
                searchBtn.Click += async (s, e) =>
                {
                    var a = artistBox.Text.Trim();
                    var t = albumBox.Text.Trim();
                    if (string.IsNullOrEmpty(a) && string.IsNullOrEmpty(t)) return;

                    searchBtn.Content = "Searching...";
                    searchBtn.IsEnabled = false;

                    try
                    {
                        var res = await _mbClient.SearchReleaseMetadataAsync("AtlasAI", a, t, CancellationToken.None);
                        if (res.Count > 0)
                        {
                            var best = res[0];
                            artistBox.Text = best.Artist;
                            albumBox.Text = best.Album;
                            searchBtn.Content = "Found & Applied";
                        }
                        else
                        {
                            searchBtn.Content = "Check Recco...";
                            var reccoRes = await _reccoClient.SearchAlbumAsync($"{a} {t}", CancellationToken.None);
                            if (reccoRes.Count > 0)
                            {
                                var best = reccoRes[0];
                                if (!string.IsNullOrEmpty(best.Artist)) artistBox.Text = best.Artist;
                                if (!string.IsNullOrEmpty(best.Title)) albumBox.Text = best.Title;
                                
                                if (!string.IsNullOrEmpty(best.CoverUrl) && !string.IsNullOrEmpty(album.SourceFolderPath))
                                {
                                    var dest = System.IO.Path.Combine(album.SourceFolderPath, "folder.jpg");
                                    var ok = await _reccoClient.TryDownloadCoverAsync(best.CoverUrl, dest, CancellationToken.None);
                                    if (!ok)
                                    {
                                        var cacheDest = MediaArtworkCache.GetMusicFolderCoverCachePath(album.SourceFolderPath);
                                        ok = await _reccoClient.TryDownloadCoverAsync(best.CoverUrl, cacheDest, CancellationToken.None);
                                    }
                                    if (ok)
                                    {
                                        try
                                        {
                                            if (File.Exists(dest))
                                            {
                                                var cacheDest = MediaArtworkCache.GetMusicFolderCoverCachePath(album.SourceFolderPath);
                                                var cacheDir = Path.GetDirectoryName(cacheDest);
                                                if (!string.IsNullOrWhiteSpace(cacheDir))
                                                    Directory.CreateDirectory(cacheDir);
                                                System.IO.File.Copy(dest, cacheDest, true);
                                            }
                                        }
                                        catch
                                        {
                                        }
                                    }
                                    if (ok) searchBtn.Content = "Found & Cover Saved";
                                    else searchBtn.Content = "Found (Recco)";
                                }
                                else
                                {
                                    searchBtn.Content = "Found (Recco)";
                                }
                            }
                            else
                            {
                                searchBtn.Content = "No Results";
                            }
                        }
                    }
                    catch
                    {
                        searchBtn.Content = "Error";
                    }
                    
                    await Task.Delay(2000);
                    if (dialog.IsLoaded)
                    {
                        searchBtn.Content = "Search Metadata";
                        searchBtn.IsEnabled = true;
                    }
                };
                actionsPanel.Children.Add(searchBtn);

                var coverBtn = new System.Windows.Controls.Button
                {
                    Content = "Change Cover",
                    Background = new SolidColorBrush(Color.FromArgb(0x20, 0x22, 0xD3, 0xEE)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderThickness = new System.Windows.Thickness(0),
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Cursor = System.Windows.Input.Cursors.Hand
                };

                coverBtn.Click += (s, e) =>
                {
                    var dlg = new Microsoft.Win32.OpenFileDialog
                    {
                        Filter = "Image Files|*.jpg;*.jpeg;*.png"
                    };

                    if (dlg.ShowDialog(dialog) == true)
                    {
                        try
                        {
                            if (!string.IsNullOrWhiteSpace(album.SourceFolderPath))
                            {
                                var ext = (System.IO.Path.GetExtension(dlg.FileName) ?? "").Trim().ToLowerInvariant();
                                var fileName = string.Equals(ext, ".png", StringComparison.OrdinalIgnoreCase) ? "folder.png" : "folder.jpg";
                                var dest = System.IO.Path.Combine(album.SourceFolderPath, fileName);
                                var saved = false;
                                var wroteToFolder = false;
                                try
                                {
                                    System.IO.File.Copy(dlg.FileName, dest, true);
                                    TouchFileUtc(dest);
                                    saved = true;
                                    wroteToFolder = true;
                                    coverBtn.Content = "Cover Updated";
                                }
                                catch
                                {
                                    var cacheDest = MediaArtworkCache.GetCustomMusicFolderCoverCachePath(album.SourceFolderPath);
                                    var cacheDir = Path.GetDirectoryName(cacheDest);
                                    if (!string.IsNullOrWhiteSpace(cacheDir))
                                        Directory.CreateDirectory(cacheDir);
                                    System.IO.File.Copy(dlg.FileName, cacheDest, true);
                                    TouchFileUtc(cacheDest);
                                    saved = true;
                                    coverBtn.Content = "Cover Updated";
                                }
                                if (!saved) return;
                                if (wroteToFolder)
                                {
                                    try
                                    {
                                        var cacheDest = MediaArtworkCache.GetCustomMusicFolderCoverCachePath(album.SourceFolderPath);
                                        var cacheDir = Path.GetDirectoryName(cacheDest);
                                        if (!string.IsNullOrWhiteSpace(cacheDir))
                                            Directory.CreateDirectory(cacheDir);
                                        System.IO.File.Copy(dlg.FileName, cacheDest, true);
                                        TouchFileUtc(cacheDest);
                                    }
                                    catch
                                    {
                                    }
                                }
                                var paths = album.Tracks
                                    .Where(t => t != null && !string.IsNullOrWhiteSpace(t.FilePath))
                                    .Select(t => t.FilePath)
                                    .Distinct(StringComparer.OrdinalIgnoreCase)
                                    .ToList();
                                RefreshCoversForPaths(paths);
                            }
                            else
                            {
                                coverBtn.Content = "No Folder Path";
                            }
                        }
                        catch
                        {
                            coverBtn.Content = "Error";
                        }
                    }
                };
                actionsPanel.Children.Add(coverBtn);

                form.Children.Add(actionsPanel);
                // -------------------

                System.Windows.Controls.Grid.SetRow(form, 1);
                root.Children.Add(form);

                (string artist, string album)? result = null;

                var footer = new System.Windows.Controls.StackPanel
                {
                    Orientation = System.Windows.Controls.Orientation.Horizontal,
                    HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
                    Margin = new System.Windows.Thickness(0, 12, 0, 0)
                };

                var cancel = new System.Windows.Controls.Button
                {
                    Content = "Cancel",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 10, 0),
                    Background = new SolidColorBrush(Color.FromRgb(0x10, 0x16, 0x20)),
                    Foreground = inputFg,
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                cancel.Click += (_, _) => dialog.Close();

                var save = new System.Windows.Controls.Button
                {
                    Content = "Save",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Background = new SolidColorBrush(Color.FromRgb(0x0F, 0x2A, 0x32)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                save.Click += (_, _) =>
                {
                    var a = (artistBox.Text ?? "").Trim();
                    var al = (albumBox.Text ?? "").Trim();
                    result = (a, al);
                    dialog.Close();
                };

                footer.Children.Add(cancel);
                footer.Children.Add(save);
                System.Windows.Controls.Grid.SetRow(footer, 2);
                root.Children.Add(footer);

                dialog.Content = root;
                dialog.ShowDialog();
                return result;
            }
            catch
            {
                try
                {
                    StatusText = "Edit window failed";
                    OnPropertyChanged(nameof(StatusText));
                }
                catch
                {
                }
                return null;
            }
        }

