                        {
                            searchBtn.Content = "Add IGDB keys";
                            searchBtn.IsEnabled = false;
                            await Task.Delay(2000);
                            if (dialog.IsLoaded)
                            {
                                searchBtn.Content = "IGDB Lookup";
                                searchBtn.IsEnabled = true;
                            }
                            return;
                        }
                    }

                    searchBtn.Content = string.Equals(type, "games", StringComparison.OrdinalIgnoreCase) ? "Looking up..." : "Searching...";
                    searchBtn.IsEnabled = false;

                    try
                    {
                        if (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) ||
                            string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase))
                        {
                            var res = await _tmdbClient.SearchMovieAsync("AtlasAI", t, CancellationToken.None);
                            if (res != null && res.Count > 0)
                            {
                                var best = res[0];
                                if (!string.IsNullOrEmpty(best.Title)) titleBox.Text = best.Title;
                                if (!string.IsNullOrEmpty(best.Overview)) 
                                {
                                     // Description/Overview update if we had a box for it
                                }
                                if (best.ReleaseDate.HasValue) 
                                {
                                     // Year update if we had a box for it
                                }
                                
                                searchBtn.Content = "Found & Applied";
                            }
                            else
                            {
                                searchBtn.Content = "No Results";
                            }
                        }
                        else if (string.Equals(type, "games", StringComparison.OrdinalIgnoreCase))
                        {
                            await OptimizeGameWithIgdbAsync(item, igdbId, igdbSecret);
                            searchBtn.Content = "IGDB Applied";
                        }
                        else
                        {
                            // Use the new SearchRecordingMetadataAsync for tracks
                            var res = await _mbClient.SearchRecordingMetadataAsync("AtlasAI", a, t, CancellationToken.None);
                            if (res.Count > 0)
                            {
                                var best = res[0];
                                if (!string.IsNullOrEmpty(best.Title)) titleBox.Text = best.Title;
                                if (!string.IsNullOrEmpty(best.Artist)) artistBox.Text = best.Artist;
                                if (!string.IsNullOrEmpty(best.Album)) albumBox.Text = best.Album;
                                if (best.TrackNumber > 0) trackBox.Text = best.TrackNumber.ToString();
                                if (best.DiscNumber > 0) discBox.Text = best.DiscNumber.ToString();
                                
                                searchBtn.Content = "Found & Applied";
                            }
                            else
                            {
                                searchBtn.Content = "No Results";
                            }
                        }
                    }
                    catch
                    {
                        searchBtn.Content = "Error";
                    }

                    await Task.Delay(2000);
                    if (dialog.IsLoaded)
                    {
                        searchBtn.Content = string.Equals(type, "games", StringComparison.OrdinalIgnoreCase) ? "IGDB Lookup" : "Search Metadata";
                        searchBtn.IsEnabled = true;
                    }
                };
                actionsPanel.Children.Add(searchBtn);

                var coverBtn = new System.Windows.Controls.Button
                {
                    Content = "Change Cover",
                    Padding = new System.Windows.Thickness(10, 5, 10, 5),
                    Background = new SolidColorBrush(Color.FromRgb(0x1E, 0x29, 0x3B)),
                    Foreground = inputFg,
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };

                coverBtn.Click += (s, e) =>
                {
                    var dlg = new Microsoft.Win32.OpenFileDialog
                    {
                        Filter = "Image Files|*.jpg;*.jpeg;*.png"
                    };

                    if (dlg.ShowDialog(dialog) == true)
                    {
                        try
                        {
                            var type = item.Type ?? "";
                            if (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase))
                            {
                                var customSaved = false;
                                try
                                {
                                    var customDest = MediaArtworkCache.GetCustomMoviePosterCachePath(item.FilePath);
                                    var dir = System.IO.Path.GetDirectoryName(customDest);
                                    if (!string.IsNullOrWhiteSpace(dir))
                                        Directory.CreateDirectory(dir);
                                    customSaved = TryWriteImageAsPng(dlg.FileName, customDest);
                                }
                                catch
                                {
                                    customSaved = false;
                                }

                                try
                                {
                                    var folder = GetVideoFolderPath(item.FilePath);
                                    if (!string.IsNullOrWhiteSpace(folder) && Directory.Exists(folder))
                                    {
                                        var baseName = Path.GetFileNameWithoutExtension(item.FilePath) ?? "poster";
                                        var localDest = Path.Combine(folder, $"{baseName}.png");
                                        TryWriteImageAsPng(dlg.FileName, localDest);
                                    }
                                }
                                catch
                                {
                                }
                                coverBtn.Content = customSaved ? "Cover Updated" : "Unsupported image";
                                RefreshCoversForPaths(new List<string> { item.FilePath });
                            }
                            else if (string.Equals(type, "music", StringComparison.OrdinalIgnoreCase))
                            {
                                var destDir = GetAlbumRootFolder(item.FilePath);
                                if (!string.IsNullOrWhiteSpace(destDir))
                                {
                                    var ext = (System.IO.Path.GetExtension(dlg.FileName) ?? "").Trim().ToLowerInvariant();
                                    var isPng = string.Equals(ext, ".png", StringComparison.OrdinalIgnoreCase);
                                    var dest = System.IO.Path.Combine(destDir, isPng ? "folder.png" : "folder.jpg");
                                    var wroteToFolder = false;
                                    try
                                    {
                                        System.IO.File.Copy(dlg.FileName, dest, true);
                                        TouchFileUtc(dest);
                                        wroteToFolder = true;
                                    }
                                    catch
                                    {
                                        var cacheDest = MediaArtworkCache.GetCustomMusicFolderCoverCachePath(destDir);
                                        var cacheDir = Path.GetDirectoryName(cacheDest);
                                        if (!string.IsNullOrWhiteSpace(cacheDir))
                                            Directory.CreateDirectory(cacheDir);
                                        System.IO.File.Copy(dlg.FileName, cacheDest, true);
                                        TouchFileUtc(cacheDest);
                                    }
                                    if (wroteToFolder)
                                    {
                                        try
                                        {
                                            var cacheDest = MediaArtworkCache.GetCustomMusicFolderCoverCachePath(destDir);
                                            var cacheDir = Path.GetDirectoryName(cacheDest);
                                            if (!string.IsNullOrWhiteSpace(cacheDir))
                                                Directory.CreateDirectory(cacheDir);
                                            System.IO.File.Copy(dlg.FileName, cacheDest, true);
                                            TouchFileUtc(cacheDest);
                                        }
                                        catch
                                        {
                                        }
                                    }
                                    coverBtn.Content = "Cover Updated";
                                    RefreshCoversForPaths(new List<string> { item.FilePath });
                                }
                                else
                                {
                                    coverBtn.Content = "No File Path";
                                }
                            }
                            else if (string.Equals(type, "games", StringComparison.OrdinalIgnoreCase))
                            {
                                var ext = (System.IO.Path.GetExtension(dlg.FileName) ?? "").Trim();
                                if (string.IsNullOrWhiteSpace(ext)) ext = ".jpg";

                                var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "CustomCovers");
                                Directory.CreateDirectory(cacheDir);
                                var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(item.FilePath));
                                var hash = Convert.ToHexString(hashBytes);
                                var dest = Path.Combine(cacheDir, $"{hash}{ext}");

                                try
                                {
                                    File.Copy(dlg.FileName, dest, true);
                                }
                                catch
                                {
                                    coverBtn.Content = "Error";
                                    return;
                                }

                                try
                                {
                                    item.CoverUrl = dest;
                                    item.CoverImage = LoadAlbumCoverFromFile(dest);
                                }
                                catch
                                {
                                }

                                coverBtn.Content = "Cover Updated";
                                RefreshCoversForPaths(new List<string> { item.FilePath });

                                List<MediaItem> snapshot;
                                lock (_stateLock)
                                {
                                    snapshot = _allItems.ToList();
                                }
                                _ = SaveLibraryToDiskAsync(snapshot);
                            }
                            else
                            {
                                coverBtn.Content = "Not Supported";
                            }
                        }
                        catch
                        {
                            coverBtn.Content = "Error";
                        }
                    }
                };
                actionsPanel.Children.Add(coverBtn);

                System.Windows.Controls.Grid.SetRow(form, 1);
                root.Children.Add(form);

                (string title, string artist, string album, int? trackNumber, int? discNumber)? result = null;

                var footer = new System.Windows.Controls.StackPanel
                {
                    Orientation = System.Windows.Controls.Orientation.Horizontal,
                    HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
                    Margin = new System.Windows.Thickness(0, 12, 0, 0)
                };

                var cancel = new System.Windows.Controls.Button
                {
                    Content = "Cancel",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 10, 0),
                    Background = new SolidColorBrush(Color.FromRgb(0x10, 0x16, 0x20)),
                    Foreground = inputFg,
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                cancel.Click += (_, _) => dialog.Close();

                var save = new System.Windows.Controls.Button
                {
                    Content = "Save",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Background = new SolidColorBrush(Color.FromRgb(0x0F, 0x2A, 0x32)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                save.Click += (_, _) =>
                {
                    int? trackNum = null;
                    int? discNum = null;
                    var trackText = (trackBox.Text ?? "").Trim();
                    var discText = (discBox.Text ?? "").Trim();
                    if (int.TryParse(trackText, out var tn) && tn >= 0) trackNum = tn;
                    if (int.TryParse(discText, out var dn) && dn >= 0) discNum = dn;

                    result = ((titleBox.Text ?? "").Trim(),
                              (artistBox.Text ?? "").Trim(),
                              (albumBox.Text ?? "").Trim(),
                              trackNum,
                              discNum);
                    dialog.Close();
                };

                footer.Children.Add(cancel);
                footer.Children.Add(save);
                System.Windows.Controls.Grid.SetRow(footer, 2);
                root.Children.Add(footer);

                dialog.Content = root;
                dialog.ShowDialog();
                return result;
            }
            catch
            {
                try
                {
                    StatusText = "Edit window failed";
                    OnPropertyChanged(nameof(StatusText));
                }
                catch
                {
                }
                return null;
            }
        }

        private string? ShowVideoEditModal(MediaItem item)
