                form.ColumnDefinitions.Add(new System.Windows.Controls.ColumnDefinition { Width = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });

                var labelBrush = new SolidColorBrush(Color.FromRgb(0x94, 0xA3, 0xB8));
                var inputBg = new SolidColorBrush(Color.FromRgb(0x08, 0x0A, 0x10));
                var inputBorder = new SolidColorBrush(Color.FromArgb(0x40, 0x22, 0xD3, 0xEE));
