                var titleLabel = new System.Windows.Controls.TextBlock { Text = "Title", Foreground = labelBrush, Margin = new System.Windows.Thickness(0, 6, 12, 6) };
                System.Windows.Controls.Grid.SetRow(titleLabel, 0);
                System.Windows.Controls.Grid.SetColumn(titleLabel, 0);
                form.Children.Add(titleLabel);

                var titleBox = new System.Windows.Controls.TextBox
                {
