                    Background = inputBg,
                    Foreground = inputFg,
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1),
                    Padding = new System.Windows.Thickness(10, 6, 10, 6),
                    Margin = new System.Windows.Thickness(0, 2, 0, 8)
                };
                System.Windows.Controls.Grid.SetRow(titleBox, 0);
                System.Windows.Controls.Grid.SetColumn(titleBox, 1);
                form.Children.Add(titleBox);

                dialog.Loaded += (_, _) =>
                {
                    try
                    {
                        dialog.Activate();
                        titleBox.Focus();
                        titleBox.SelectAll();
                        Keyboard.Focus(titleBox);
                    }
                    catch
                    {
                    }
                };

                var actionsPanel = new System.Windows.Controls.StackPanel
                {
                    Orientation = System.Windows.Controls.Orientation.Horizontal,
                    Margin = new System.Windows.Thickness(0, 8, 0, 8)
                };
                System.Windows.Controls.Grid.SetRow(actionsPanel, 1);
                System.Windows.Controls.Grid.SetColumn(actionsPanel, 1);
                form.Children.Add(actionsPanel);

                var fetchBtn = new System.Windows.Controls.Button
                {
                    Content = "Fetch TMDb Poster",
                    Background = new SolidColorBrush(Color.FromArgb(0x20, 0x22, 0xD3, 0xEE)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderThickness = new System.Windows.Thickness(0),
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 8, 0),
                    Cursor = System.Windows.Input.Cursors.Hand
                };

                fetchBtn.Click += async (_, _) =>
                {
                    void SetFetchState(string text, bool? enabled = null)
                    {
                        try
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                if (!dialog.IsLoaded) return;
                                fetchBtn.Content = text;
                                if (enabled.HasValue) fetchBtn.IsEnabled = enabled.Value;
                            });
                        }
                        catch
                        {
                        }
                    }

                    var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
                    if (string.IsNullOrWhiteSpace(tmdbKey))
                    {
                        SetFetchState("TMDb key missing");
                        await Task.Delay(2000).ConfigureAwait(false);
                        SetFetchState("Fetch TMDb Poster", true);
                        return;
                    }

                    SetFetchState("Fetching...", false);
                    try
                    {
                        using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(30));
                        var title = (titleBox.Text ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(title)) title = BuildTmdbSearchTitle(item);
                        var cacheDest = MediaArtworkCache.GetMoviePosterCachePath(item.FilePath);
                        var folder = GetVideoFolderPath(item.FilePath);
                        var localDest = string.IsNullOrWhiteSpace(folder) ? "" : Path.Combine(folder, "poster.jpg");
                        var tmdb = new TmdbClient();
                        var ok = false;
                        if (!string.IsNullOrWhiteSpace(localDest))
                        {
                            ok = await tmdb.TryDownloadPosterAsync(tmdbKey, title, localDest, cts.Token).ConfigureAwait(false);
                            if (ok)
                            {
                                try
                                {
                                    var dir = Path.GetDirectoryName(cacheDest);
                                    if (!string.IsNullOrWhiteSpace(dir))
                                        Directory.CreateDirectory(dir);
                                    File.Copy(localDest, cacheDest, true);
                                }
                                catch
                                {
                                }
                            }
                        }
                        if (!ok)
                        {
                            ok = await tmdb.TryDownloadPosterAsync(tmdbKey, title, cacheDest, cts.Token).ConfigureAwait(false);
                            if (ok && !string.IsNullOrWhiteSpace(localDest) && !File.Exists(localDest))
                            {
                                try
                                {
                                    var dir = Path.GetDirectoryName(localDest);
                                    if (!string.IsNullOrWhiteSpace(dir))
                                        Directory.CreateDirectory(dir);
                                    File.Copy(cacheDest, localDest, true);
                                }
                                catch
                                {
                                }
                            }
                        }
                        _uiDispatcher.Invoke(() => RefreshCoversForPaths(new List<string> { item.FilePath }));
                        SetFetchState(ok ? "Poster Updated" : "No Result");
                    }
                    catch
                    {
                        SetFetchState("Error");
                    }

                    await Task.Delay(2000).ConfigureAwait(false);
                    SetFetchState("Fetch TMDb Poster", true);
                };
                actionsPanel.Children.Add(fetchBtn);

                var mdbFetchBtn = new System.Windows.Controls.Button
                {
                    Content = "Fetch MDBList Poster",
                    Background = new SolidColorBrush(Color.FromArgb(0x20, 0xA8, 0x55, 0xF7)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0xA8, 0x55, 0xF7)),
                    BorderThickness = new System.Windows.Thickness(0),
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 8, 0),
                    Cursor = System.Windows.Input.Cursors.Hand
                };

                mdbFetchBtn.Click += async (_, _) =>
                {
                    void SetMdbState(string text, bool? enabled = null)
                    {
                        try
                        {
                            _uiDispatcher.Invoke(() =>
                            {
                                if (!dialog.IsLoaded) return;
                                mdbFetchBtn.Content = text;
                                if (enabled.HasValue) mdbFetchBtn.IsEnabled = enabled.Value;
                            });
                        }
                        catch
                        {
                        }
                    }

                    var mdbKey = IntegrationKeyStore.GetDecrypted("mdblist");
                    if (string.IsNullOrWhiteSpace(mdbKey))
                    {
                        SetMdbState("MDBList key missing");
                        await Task.Delay(2000).ConfigureAwait(false);
                        SetMdbState("Fetch MDBList Poster", true);
                        return;
                    }

                    SetMdbState("Fetching...", false);
                    try
                    {
                        using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(30));
                        var title = (titleBox.Text ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(title)) title = BuildTmdbSearchTitle(item);
                        var cacheDest = MediaArtworkCache.GetMoviePosterCachePath(item.FilePath);
                        var folder = GetVideoFolderPath(item.FilePath);
                        var localDest = string.IsNullOrWhiteSpace(folder) ? "" : Path.Combine(folder, "poster.jpg");

                        using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(20) };
                        var url = $"https://mdblist.com/api/?apikey={Uri.EscapeDataString(mdbKey.Trim())}&t={Uri.EscapeDataString(title)}";
                        using var res = await http.GetAsync(url, cts.Token).ConfigureAwait(false);
                        if (!res.IsSuccessStatusCode)
                        {
                            SetMdbState("No Result");
                        }
                        else
                        {
                            var json = await res.Content.ReadAsStringAsync(cts.Token).ConfigureAwait(false);
                            using var doc = JsonDocument.Parse(json);
                            var root = doc.RootElement;

                            string? posterUrl = null;
                            if (root.ValueKind == JsonValueKind.Object)
                            {
                                foreach (var prop in root.EnumerateObject())
                                {
                                    if (!prop.Name.Equals("poster", StringComparison.OrdinalIgnoreCase) &&
                                        !prop.Name.Equals("posterurl", StringComparison.OrdinalIgnoreCase) &&
                                        !prop.Name.Equals("image", StringComparison.OrdinalIgnoreCase))
                                        continue;

                                    if (prop.Value.ValueKind != JsonValueKind.String)
                                        continue;

                                    var candidate = (prop.Value.GetString() ?? "").Trim();
                                    if (string.IsNullOrWhiteSpace(candidate) || string.Equals(candidate, "N/A", StringComparison.OrdinalIgnoreCase))
                                        continue;

                                    posterUrl = candidate;
                                    break;
                                }
                            }

                            if (string.IsNullOrWhiteSpace(posterUrl) || !Uri.TryCreate(posterUrl, UriKind.Absolute, out var posterUri))
                            {
                                SetMdbState("No Result");
                            }
                            else
                            {
                                using var imgRes = await http.GetAsync(posterUri, HttpCompletionOption.ResponseHeadersRead, cts.Token).ConfigureAwait(false);
                                if (!imgRes.IsSuccessStatusCode)
                                {
                                    SetMdbState("No Result");
                                }
                                else
                                {
                                    var bytes = await imgRes.Content.ReadAsByteArrayAsync(cts.Token).ConfigureAwait(false);
                                    var wrote = false;
                                    if (bytes.Length > 0 && !string.IsNullOrWhiteSpace(localDest))
                                    {
                                        try
                                        {
                                            var dir = Path.GetDirectoryName(localDest);
                                            if (!string.IsNullOrWhiteSpace(dir))
                                                Directory.CreateDirectory(dir);
                                            await File.WriteAllBytesAsync(localDest, bytes, cts.Token).ConfigureAwait(false);
                                            wrote = File.Exists(localDest);
                                            if (wrote)
                                            {
                                                try
                                                {
                                                    var dir2 = Path.GetDirectoryName(cacheDest);
                                                    if (!string.IsNullOrWhiteSpace(dir2))
                                                        Directory.CreateDirectory(dir2);
                                                    File.Copy(localDest, cacheDest, true);
                                                }
                                                catch
                                                {
                                                }
                                            }
                                        }
                                        catch
                                        {
                                            wrote = false;
                                        }
                                    }

                                    if (bytes.Length > 0 && !wrote)
                                    {
                                        var dir = Path.GetDirectoryName(cacheDest);
                                        if (!string.IsNullOrWhiteSpace(dir))
                                            Directory.CreateDirectory(dir);
                                        await File.WriteAllBytesAsync(cacheDest, bytes, cts.Token).ConfigureAwait(false);
                                    }

                                    _uiDispatcher.Invoke(() => RefreshCoversForPaths(new List<string> { item.FilePath }));
                                    SetMdbState("Poster Updated");
                                }
                            }
                        }
                    }
                    catch
                    {
                        SetMdbState("Error");
                    }

                    await Task.Delay(2000).ConfigureAwait(false);
                    SetMdbState("Fetch MDBList Poster", true);
                };
                actionsPanel.Children.Add(mdbFetchBtn);

                var coverBtn = new System.Windows.Controls.Button
                {
                    Content = "Change Cover",
                    Background = new SolidColorBrush(Color.FromArgb(0x20, 0x22, 0xD3, 0xEE)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderThickness = new System.Windows.Thickness(0),
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Cursor = System.Windows.Input.Cursors.Hand
                };

                coverBtn.Click += (_, _) =>
                {
                    var dlg = new Microsoft.Win32.OpenFileDialog
                    {
                        Filter = "Image Files|*.jpg;*.jpeg;*.png"
                    };

                    if (dlg.ShowDialog(dialog) == true)
                    {
                        try
                        {
                            var saved = TryCopyVideoPosterToFolder(item.FilePath, dlg.FileName, out _);
                            var customSaved = false;
                            try
                            {
                                var customDest = MediaArtworkCache.GetCustomMoviePosterCachePath(item.FilePath);
                                var dir = System.IO.Path.GetDirectoryName(customDest);
                                if (!string.IsNullOrWhiteSpace(dir))
                                    Directory.CreateDirectory(dir);
                                customSaved = TryWriteImageAsPng(dlg.FileName, customDest);
                            }
                            catch
                            {
                                customSaved = false;
                            }

                            try
                            {
                                var folder = GetVideoFolderPath(item.FilePath);
                                if (!string.IsNullOrWhiteSpace(folder) && Directory.Exists(folder))
                                {
                                    var baseName = Path.GetFileNameWithoutExtension(item.FilePath) ?? "poster";
                                    var localDest = Path.Combine(folder, $"{baseName}.png");
                                    TryWriteImageAsPng(dlg.FileName, localDest);
                                }
                            }
                            catch
                            {
                            }
                            if (customSaved)
                            {
                                coverBtn.Content = "Cover Updated";
                            }
                            else
                            {
                                coverBtn.Content = "Unsupported image";
                            }
                            RefreshCoversForPaths(new List<string> { item.FilePath });
                        }
                        catch
                        {
                            coverBtn.Content = "Error";
                        }
                    }
                };
                actionsPanel.Children.Add(coverBtn);

                System.Windows.Controls.Grid.SetRow(form, 1);
                root.Children.Add(form);

                string? result = null;

                var footer = new System.Windows.Controls.StackPanel
                {
                    Orientation = System.Windows.Controls.Orientation.Horizontal,
                    HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
                    Margin = new System.Windows.Thickness(0, 12, 0, 0)
                };

                var cancel = new System.Windows.Controls.Button
                {
                    Content = "Cancel",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 10, 0),
                    Background = new SolidColorBrush(Color.FromRgb(0x10, 0x16, 0x20)),
                    Foreground = inputFg,
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                cancel.Click += (_, _) => dialog.Close();

                var save = new System.Windows.Controls.Button
                {
                    Content = "Save",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Background = new SolidColorBrush(Color.FromRgb(0x0F, 0x2A, 0x32)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    BorderBrush = inputBorder,
                    BorderThickness = new System.Windows.Thickness(1)
                };
                save.Click += (_, _) =>
                {
                    var t = (titleBox.Text ?? "").Trim();
                    result = t;
                    dialog.Close();
                };

                footer.Children.Add(cancel);
                footer.Children.Add(save);
                System.Windows.Controls.Grid.SetRow(footer, 2);
                root.Children.Add(footer);

                dialog.Content = root;
                dialog.ShowDialog();
                return result;
            }
            catch
            {
                try
                {
                    StatusText = "Edit window failed";
                    OnPropertyChanged(nameof(StatusText));
                }
                catch
                {
                }
                return null;
            }
        }

        private async void OptimizeItem(MediaItem? item)
        {
            if (item == null) return;
            if (IsServersView) EnsureItemSavedToLibrary(item);

            // Check for IGDB keys first for games
            if (string.Equals(item.Type, "games", StringComparison.OrdinalIgnoreCase))
            {
                if (!TryGetIgdbCredentials(out var igdbId, out var igdbSecret))
                {
                    var configured = ShowIgdbKeysModal();
                    if (configured == null)
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StatusText = "IGDB keys missing";
                            ScanProgressText = "Open any game → Edit info → IGDB Keys";
                            OnPropertyChanged(nameof(StatusText));
                        });
                        return;
                    }

                    try
                    {
                        IntegrationKeyStore.SetProtected("igdb_client_id", configured.Value.clientId);
                        IntegrationKeyStore.SetProtected("igdb_client_secret", configured.Value.clientSecret);
                    }
                    catch
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StatusText = "IGDB save failed";
                            OnPropertyChanged(nameof(StatusText));
                        });
                        return;
                    }

                    igdbId = configured.Value.clientId;
                    igdbSecret = configured.Value.clientSecret;
                }

                await OptimizeGameWithIgdbAsync(item, igdbId, igdbSecret);
                return;
                
                // If no keys, fall through to AI metadata optimization (NOT performance plan)
                // We intentionally removed the block that forced OptimizeGamePerformanceAsync
            }

            var provider = AIManager.GetActiveProviderInstance();

            if (HasArtworkProvidersConfigured())
                await OptimizeArtworkOnlyAsync(new List<MediaItem> { item }, $"Optimizing covers · {item.Title}");

            if (provider == null || !provider.IsConfigured)
            {
                StatusText = "Covers updated";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                return;
            }

            await OptimizeMediaMetadataAsync(new List<MediaItem> { item }, $"AI optimizing · {item.Title}");
        }

        private async Task OptimizeGameWithIgdbAsync(MediaItem item, string clientId, string clientSecret)
        {
            _uiDispatcher.Invoke(() =>
            {
                StatusText = $"IGDB Searching · {item.Title}";
                OnPropertyChanged(nameof(StatusText));
            });

            try
            {
                using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(25));
                var ct = cts.Token;

                using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(25) };

                var tokenUrl = $"https://id.twitch.tv/oauth2/token?client_id={Uri.EscapeDataString((clientId ?? "").Trim())}&client_secret={Uri.EscapeDataString((clientSecret ?? "").Trim())}&grant_type=client_credentials";
                using var tokenRes = await http.PostAsync(tokenUrl, null, ct).ConfigureAwait(false);
                if (!tokenRes.IsSuccessStatusCode) throw new Exception("IGDB Auth Failed");
                
                var tokenJson = await tokenRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                var tokenDoc = JsonDocument.Parse(tokenJson);
                var accessToken = tokenDoc.RootElement.GetProperty("access_token").GetString();

                var searchUrl = "https://api.igdb.com/v4/games";
                var title = (item.Title ?? "").Trim();
                title = title.Replace("\"", "\\\"");
                var query = $"search \"{title}\"; fields name, cover.url, summary, first_release_date, genres.name, rating; limit 1;";
                
                var request = new HttpRequestMessage(HttpMethod.Post, searchUrl);
                request.Headers.Add("Client-ID", clientId);
                request.Headers.Add("Authorization", $"Bearer {accessToken}");
                request.Headers.TryAddWithoutValidation("Accept", "application/json");
                request.Content = new StringContent(query, Encoding.UTF8, "text/plain");

                using var searchRes = await http.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!searchRes.IsSuccessStatusCode) throw new Exception("IGDB Search Failed");

                var searchJson = await searchRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                var searchDoc = JsonDocument.Parse(searchJson);
                
                if (searchDoc.RootElement.GetArrayLength() == 0)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        StatusText = "IGDB No match";
                        OnPropertyChanged(nameof(StatusText));
                    });
                    return;
                }

                var game = searchDoc.RootElement[0];
                
                var name = game.TryGetProperty("name", out var n) ? n.GetString() : item.Title;
                var summary = game.TryGetProperty("summary", out var s) ? s.GetString() : "";
                var coverUrl = "";
                if (game.TryGetProperty("cover", out var c) && c.TryGetProperty("url", out var u))
                {
                    coverUrl = "https:" + u.GetString()?.Replace("t_thumb", "t_cover_big");
                }
                
                if (!IsCustomCoverPath(item.CoverUrl) && !string.IsNullOrWhiteSpace(coverUrl))
                {
                    byte[]? coverData = null;
                    try
                    {
                        coverData = await http.GetByteArrayAsync(coverUrl, ct).ConfigureAwait(false);
                    }
                    catch
                    {
                        coverData = null;
                    }

                    if (coverData != null && coverData.Length > 0)
                    {
                        var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "GameCovers");
                        Directory.CreateDirectory(cacheDir);
                        var hashInput = $"{item.FilePath}|{coverUrl}";
                        var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(hashInput));
                        var hash = Convert.ToHexString(hashBytes);
                        var coverPath = Path.Combine(cacheDir, $"{hash}.jpg");
                        try
                        {
                            if (!File.Exists(coverPath))
                                await File.WriteAllBytesAsync(coverPath, coverData, ct).ConfigureAwait(false);
                        }
                        catch
                        {
                        }

                        ImageSource? bmp = null;
                        try
                        {
                            await using var ms = new MemoryStream(coverData);
                            var bi = new BitmapImage();
                            bi.BeginInit();
                            bi.CacheOption = BitmapCacheOption.OnLoad;
                            bi.StreamSource = ms;
                            bi.DecodePixelWidth = 320;
                            bi.CreateOptions = BitmapCreateOptions.IgnoreColorProfile;
                            bi.EndInit();
                            bi.Freeze();
                            bmp = bi;
                        }
                        catch
                        {
                            bmp = null;
                        }

                        _uiDispatcher.Invoke(() =>
                        {
                            item.CoverUrl = coverPath;
                            if (bmp != null) item.CoverImage = bmp;
                        });
                    }
                }

                _uiDispatcher.Invoke(() =>
                {
                    if (!string.IsNullOrWhiteSpace(name)) item.Title = name;
                    if (!string.IsNullOrWhiteSpace(summary)) item.Metadata = summary;
                });

                List<MediaItem> snapshot;
                lock (_stateLock)
                {
                    snapshot = _allItems.ToList();
                }
                _ = SaveLibraryToDiskAsync(snapshot);
                
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "IGDB Updated";
                    OnPropertyChanged(nameof(StatusText));
                });
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"IGDB Error: {ex.Message}");
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "IGDB Error";
                    OnPropertyChanged(nameof(StatusText));
                });
            }
        }

        private async Task EnrichDiscoveredGamesWithIgdbAsync(List<MediaItem> games, string clientId, string clientSecret, bool force = false)
        {
            if (games == null || games.Count == 0) return;

            var candidates = games
                .Where(g => g != null && !string.IsNullOrWhiteSpace(g.Title) && !string.IsNullOrWhiteSpace(g.FilePath))
                .ToList();

            var targets = force
                ? candidates.Take(120).ToList()
                : candidates
                    .Where(g => string.IsNullOrWhiteSpace(g.Metadata) || string.IsNullOrWhiteSpace(g.CoverUrl))
                    .Take(120)
                    .ToList();

            if (targets.Count == 0) return;

            using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(6));
            var ct = cts.Token;

            using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(25) };

            string accessToken;
            try
            {
                accessToken = await GetIgdbAccessTokenAsync(http, clientId, clientSecret, ct).ConfigureAwait(false);
                if (string.IsNullOrWhiteSpace(accessToken))
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        StatusText = "IGDB auth failed";
                        ScanProgressText = "IGDB auth failed";
                        OnPropertyChanged(nameof(StatusText));
                    });
                    return;
                }
            }
            catch
            {
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = "IGDB auth failed";
                    ScanProgressText = "IGDB auth failed";
                    OnPropertyChanged(nameof(StatusText));
                });
                return;
            }

            var updated = 0;
            for (var i = 0; i < targets.Count; i++)
            {
                ct.ThrowIfCancellationRequested();

                var item = targets[i];
                var label = $"{i + 1}/{targets.Count}";
                _uiDispatcher.Invoke(() =>
                {
                    StatusText = $"IGDB {label} · {item.Title}";
                    ScanProgressText = $"IGDB updating · {label}";
                    OnPropertyChanged(nameof(StatusText));
                });

                try
                {
                    var r = await TryGetIgdbGameAsync(http, clientId, accessToken, item.Title, ct).ConfigureAwait(false);
                    if (r == null) continue;

                    if (!string.IsNullOrWhiteSpace(r.Value.name))
                    {
                        _uiDispatcher.Invoke(() => item.Title = r.Value.name);
                    }

                    if (!string.IsNullOrWhiteSpace(r.Value.summary))
                    {
                        _uiDispatcher.Invoke(() => item.Metadata = r.Value.summary);
                    }

                    if (!IsCustomCoverPath(item.CoverUrl) && !string.IsNullOrWhiteSpace(r.Value.coverUrl))
                    {
                        var coverPath = await TryCacheIgdbCoverAsync(http, item.FilePath, r.Value.coverUrl, ct).ConfigureAwait(false);
                        if (!string.IsNullOrWhiteSpace(coverPath))
                        {
                            ImageSource? bmp = null;
                            try
                            {
                                bmp = LoadAlbumCoverFromFile(coverPath);
                            }
                            catch
                            {
                                bmp = null;
                            }

                            _uiDispatcher.Invoke(() =>
                            {
                                item.CoverUrl = coverPath;
                                if (bmp != null) item.CoverImage = bmp;
                            });
                        }
                    }

                    updated++;
                }
                catch
                {
                }
            }

            if (updated > 0)
            {
                List<MediaItem> snapshot;
                lock (_stateLock)
                {
                    snapshot = _allItems.ToList();
                }
                _ = SaveLibraryToDiskAsync(snapshot);
            }

            _uiDispatcher.Invoke(() =>
            {
                ScanProgressText = $"IGDB updated · {updated}/{targets.Count}";
                StatusText = updated > 0 ? "IGDB Updated" : "IGDB No matches";
                OnPropertyChanged(nameof(StatusText));
            });
        }

        private static async Task<string> GetIgdbAccessTokenAsync(HttpClient http, string clientId, string clientSecret, CancellationToken ct)
        {
            var tokenUrl =
                $"https://id.twitch.tv/oauth2/token?client_id={Uri.EscapeDataString((clientId ?? "").Trim())}&client_secret={Uri.EscapeDataString((clientSecret ?? "").Trim())}&grant_type=client_credentials";
            using var tokenRes = await http.PostAsync(tokenUrl, null, ct).ConfigureAwait(false);
            var tokenJson = await tokenRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
            if (!tokenRes.IsSuccessStatusCode) return "";

            using var tokenDoc = JsonDocument.Parse(tokenJson);
            return tokenDoc.RootElement.TryGetProperty("access_token", out var at) ? (at.GetString() ?? "") : "";
        }

        private static async Task<(string? name, string? summary, string? coverUrl)?> TryGetIgdbGameAsync(
            HttpClient http,
            string clientId,
            string accessToken,
            string title,
            CancellationToken ct)
        {
            var searchUrl = "https://api.igdb.com/v4/games";
            var q = (title ?? "").Trim();
            q = q.Replace("\"", "\\\"");
            if (string.IsNullOrWhiteSpace(q)) return null;

            var query = $"search \"{q}\"; fields name, cover.url, summary, first_release_date, genres.name, rating; limit 1;";
            using var request = new HttpRequestMessage(HttpMethod.Post, searchUrl);
            request.Headers.Add("Client-ID", clientId);
            request.Headers.Add("Authorization", $"Bearer {accessToken}");
            request.Headers.TryAddWithoutValidation("Accept", "application/json");
            request.Content = new StringContent(query, Encoding.UTF8, "text/plain");

            using var searchRes = await http.SendAsync(request, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
            var searchJson = await searchRes.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
            if (!searchRes.IsSuccessStatusCode) return null;

            using var searchDoc = JsonDocument.Parse(searchJson);
            if (searchDoc.RootElement.ValueKind != JsonValueKind.Array) return null;
            if (searchDoc.RootElement.GetArrayLength() == 0) return null;

            var game = searchDoc.RootElement[0];
            var name = game.TryGetProperty("name", out var n) ? n.GetString() : null;
            var summary = game.TryGetProperty("summary", out var s) ? s.GetString() : null;
            var coverUrl = "";
            if (game.TryGetProperty("cover", out var c) && c.TryGetProperty("url", out var u))
            {
                coverUrl = "https:" + (u.GetString() ?? "");
                coverUrl = coverUrl.Replace("t_thumb", "t_cover_big", StringComparison.OrdinalIgnoreCase);
            }

            return (name, summary, string.IsNullOrWhiteSpace(coverUrl) ? null : coverUrl);
        }

        private static async Task<string?> TryCacheIgdbCoverAsync(HttpClient http, string filePath, string coverUrl, CancellationToken ct)
        {
            if (string.IsNullOrWhiteSpace(filePath) || string.IsNullOrWhiteSpace(coverUrl)) return null;

            byte[] bytes;
            try
            {
                bytes = await http.GetByteArrayAsync(coverUrl, ct).ConfigureAwait(false);
            }
            catch
            {
                return null;
            }

            if (bytes.Length == 0) return null;

            var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "GameCovers");
            Directory.CreateDirectory(cacheDir);
            var hashInput = $"{filePath}|{coverUrl}";
            var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(hashInput));
            var hash = Convert.ToHexString(hashBytes);
            var coverPath = Path.Combine(cacheDir, $"{hash}.jpg");
            try
            {
                if (!File.Exists(coverPath))
                    await File.WriteAllBytesAsync(coverPath, bytes, ct).ConfigureAwait(false);
            }
            catch
            {
                return null;
            }
            return coverPath;
        }

        private async void OptimizeLibrary()
        {
            if (IsScanning) return;

            var scopeItems = GetSelectedOptimizationItems();
            if (scopeItems.Count == 0)
            {
                StatusText = "No items to optimize";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                return;
            }

            var games = scopeItems
                .Where(i => i != null && string.Equals(i.Type, "games", StringComparison.OrdinalIgnoreCase))
                .ToList();
            var nonGames = scopeItems
                .Where(i => i != null && !string.Equals(i.Type, "games", StringComparison.OrdinalIgnoreCase))
                .ToList();

            if (games.Count > 0)
            {
                var haveIgdb = TryGetIgdbCredentials(out var igdbId, out var igdbSecret);
                if (nonGames.Count == 0 && !haveIgdb)
                {
                    var configured = ShowIgdbKeysModal();
                    if (configured == null)
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StatusText = "IGDB keys missing";
                            ScanProgressText = "Open any game → Edit info → IGDB Keys";
                            OnPropertyChanged(nameof(StatusText));
                            OnPropertyChanged(nameof(TrendingValue));
                        });
                        return;
                    }

                    try
                    {
                        IntegrationKeyStore.SetProtected("igdb_client_id", configured.Value.clientId);
                        IntegrationKeyStore.SetProtected("igdb_client_secret", configured.Value.clientSecret);
                        igdbId = configured.Value.clientId;
                        igdbSecret = configured.Value.clientSecret;
                        haveIgdb = true;
                    }
                    catch
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            StatusText = "IGDB save failed";
                            OnPropertyChanged(nameof(StatusText));
                            OnPropertyChanged(nameof(TrendingValue));
                        });
                        return;
                    }
                }

                if (nonGames.Count == 0 && haveIgdb)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        IsScanning = true;
                        ScanProgressText = $"IGDB optimizing · {games.Count} games";
                        ScannedCount = 0;
                        StatusText = "Scanning";
                        CommandManager.InvalidateRequerySuggested();
                    });

                    try
                    {
                        await EnrichDiscoveredGamesWithIgdbAsync(games, igdbId, igdbSecret, true).ConfigureAwait(false);
                        var paths = games
                            .Where(g => !string.IsNullOrWhiteSpace(g.FilePath))
                            .Select(g => g.FilePath)
                            .Distinct(StringComparer.OrdinalIgnoreCase)
                            .ToList();
                        _uiDispatcher.Invoke(() => RefreshCoversForPaths(paths));
                    }
                    catch
                    {
                    }
                    finally
                    {
                        _uiDispatcher.Invoke(() =>
                        {
                            IsScanning = false;
                            CommandManager.InvalidateRequerySuggested();
                        });
                    }
                    return;
                }
            }

            var provider = AIManager.GetActiveProviderInstance();
            if (HasArtworkProvidersConfigured() && nonGames.Count > 0)
                await OptimizeArtworkOnlyAsync(nonGames, $"Optimizing covers · {nonGames.Count} items");

            if (provider == null || !provider.IsConfigured)
            {
                StatusText = "Covers updated";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                return;
            }

            if (nonGames.Count > MaxAiItemsPerRun)
            {
                StatusText = $"AI skipped to save credits · {nonGames.Count} items";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                return;
            }

            if (nonGames.Count > 0)
                await OptimizeMediaMetadataAsync(nonGames, $"AI optimizing · {nonGames.Count} items", true);
        }

        private static string ExtractLeadingToken(string value, int minLen, int maxLen)
        {
            var v = (value ?? "").Trim();
            if (string.IsNullOrWhiteSpace(v)) return "";
            var m = Regex.Match(v, $"^[A-Za-z0-9]{{{minLen},{maxLen}}}");
            return m.Success ? m.Value : "";
        }

        private static bool TryGetIgdbCredentials(out string clientId, out string clientSecret)
        {
            clientId = "";
            clientSecret = "";

            string FirstToken(int minLen, int maxLen, params string[] keys)
            {
                foreach (var k in keys)
                {
                    var v = IntegrationKeyStore.GetDecrypted(k);
                    var t = ExtractLeadingToken(v, minLen, maxLen);
                    if (!string.IsNullOrWhiteSpace(t)) return t;
                }
                return "";
            }

            clientId = FirstToken(16, 64,
                "IgdbClientId",
                "igdb_client_id",
                "igdbClientId",
                "IGDB_CLIENT_ID",
                "TwitchClientId",
                "twitch_client_id",
                "twitchClientId",
                "TWITCH_CLIENT_ID");

            clientSecret = FirstToken(16, 128,
                "IgdbClientSecret",
                "igdb_client_secret",
                "igdbClientSecret",
                "IGDB_CLIENT_SECRET",
                "TwitchClientSecret",
                "twitch_client_secret",
                "twitchClientSecret",
                "TWITCH_CLIENT_SECRET");

            return !string.IsNullOrWhiteSpace(clientId) && !string.IsNullOrWhiteSpace(clientSecret);
        }

        private List<MediaItem> GetSelectedOptimizationItems()
        {
            var id = SelectedCategory?.Id ?? "";

            if (string.Equals(id, "music", StringComparison.OrdinalIgnoreCase))
            {
                if (SelectedAlbum != null)
                    return SelectedAlbum.Tracks.ToList();

                lock (_stateLock)
                {
                    return _allItems.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
                }
            }

            var current = LibraryItems.ToList();
            if (current.Count > 0) return current;

            if (!string.IsNullOrWhiteSpace(id))
            {
                lock (_stateLock)
                {
                    return _allItems.Where(i => string.Equals(i.Type, id, StringComparison.OrdinalIgnoreCase)).ToList();
                }
            }

            lock (_stateLock)
            {
                return _allItems.ToList();
            }
        }

        private async Task OptimizeGamePerformanceAsync(MediaItem item, CancellationToken ct = default)
        {
            StatusText = $"AI optimizing · {item.Title}";
            OnPropertyChanged(nameof(StatusText));
            OnPropertyChanged(nameof(TrendingValue));

            var specs = GetSystemSpecsBrief();
            var messages = new List<object>
            {
                new
                {
                    role = "system",
                    content =
                        "You are Atlas Game Optimizer. " +
                        "Return a practical optimization plan for the specified PC + game. " +
                        "Prioritize FPS stability, input latency, and crash reduction. " +
                        "Give: (1) Windows optimizations, (2) GPU driver/control-panel settings, (3) in-game settings recommendations, (4) troubleshooting steps if stutter/crashes. " +
                        "Use short bullet points and clear headings."
                },
                new
                {
                    role = "user",
                    content =
                        $"Game: {item.Title}\n" +
                        $"Platform: {item.Album}\n" +
                        $"Exe: {item.FilePath}\n\n" +
                        $"PC Specs:\n{specs}\n"
                }
            };

            AIResponse response;
            try
            {
                response = await AIManager.SendMessageAsync(messages, 900, ct);
            }
            catch (OperationCanceledException)
            {
                StatusText = "Cancelled";
                OnPropertyChanged(nameof(StatusText));
                return;
            }
            catch
            {
                response = new AIResponse { Success = false, Error = "AI request failed" };
            }

            if (!response.Success || string.IsNullOrWhiteSpace(response.Content))
            {
                StatusText = response.Error ?? "AI optimization failed";
                OnPropertyChanged(nameof(StatusText));
                OnPropertyChanged(nameof(TrendingValue));
                return;
            }

            ShowTextModal($"AI Optimize · {item.Title}", response.Content);
            StatusText = "Ready";
            OnPropertyChanged(nameof(StatusText));
            OnPropertyChanged(nameof(TrendingValue));
        }

        private sealed class AiOptimizedMetadata
        {
            public string FilePath { get; set; } = "";
            public string? Title { get; set; }
            public string? Artist { get; set; }
            public string? Album { get; set; }
            public string? Type { get; set; }
            public int? TrackNumber { get; set; }
            public int? DiscNumber { get; set; }
        }

        private async Task OptimizeMediaMetadataAsync(List<MediaItem> items, string status, bool skipRecentlyOptimized = false, CancellationToken ct = default)
        {
            if (items.Count == 0) return;

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = status;
                ScannedCount = 0;
                StatusText = "Scanning";
                CommandManager.InvalidateRequerySuggested();
            });

            var targets = items
                .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                .Select(g => g.First())
                .ToList();

            if (skipRecentlyOptimized)
            {
                var cutoff = DateTime.UtcNow.AddDays(-7);
                targets = targets
                    .Where(i => !i.LastAiOptimizedUtc.HasValue || i.LastAiOptimizedUtc.Value < cutoff)
                    .ToList();

                if (targets.Count == 0)
                {
                    _uiDispatcher.Invoke(() =>
                    {
                        IsScanning = false;
                        ScanProgressText = "Skipped · optimized recently";
                        StatusText = "Ready";
                        CommandManager.InvalidateRequerySuggested();
                    });
                    return;
                }
            }

            if (targets.Count > MaxAiItemsPerRun)
            {
                targets = targets.Take(MaxAiItemsPerRun).ToList();
                _uiDispatcher.Invoke(() =>
                {
                    ScanProgressText = $"{status} · limited to {targets.Count}";
                });
            }

            var results = new List<AiOptimizedMetadata>();

            const int batchSize = 20;
            for (var i = 0; i < targets.Count; i += batchSize)
            {
                if (ct.IsCancellationRequested) break;

                var batch = targets.Skip(i).Take(batchSize).ToList();
                _uiDispatcher.Invoke(() =>
                {
                    ScannedCount = Math.Min(targets.Count, i + batch.Count);
                    ScanProgressText = $"{status} · {ScannedCount}/{targets.Count}";
                });

                var prompt = BuildOptimizePrompt(batch);
                var response = await AIManager.SendMessageAsync(prompt, 900, ct);
                if (!response.Success || string.IsNullOrWhiteSpace(response.Content))
                    continue;

                if (TryParseOptimizedMetadata(response.Content, out var parsed))
                    results.AddRange(parsed);
            }

            if (ct.IsCancellationRequested)
            {
                _uiDispatcher.Invoke(() =>
                {
                    IsScanning = false;
                    ScanProgressText = "Cancelled";
                    StatusText = "Ready";
                    CommandManager.InvalidateRequerySuggested();
                });
                return;
            }

            _uiDispatcher.Invoke(() => ApplyOptimizedMetadata(results, false, true));

            var processedPaths = targets
                .Where(t => !string.IsNullOrWhiteSpace(t.FilePath))
                .Select(t => t.FilePath)
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (processedPaths.Count > 0 && HasArtworkProvidersConfigured())
            {
                _uiDispatcher.Invoke(() => ScanProgressText = $"{status} · fetching covers");
                await EnrichArtworkForPathsAsync(processedPaths, false, false, false).ConfigureAwait(false);
                _uiDispatcher.Invoke(() => RefreshCoversForPaths(processedPaths));
            }

            _uiDispatcher.Invoke(() =>
            {
                var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
                var tmdbMissing = targets.Any(t => string.Equals(t.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                                   string.Equals(t.Type, "tv", StringComparison.OrdinalIgnoreCase)) &&
                                  string.IsNullOrWhiteSpace(tmdbKey);
                IsScanning = false;
                ScanProgressText = tmdbMissing ? "TMDb key missing · add it in Settings" : "Ready";
                StatusText = tmdbMissing ? "TMDb key missing" : "Ready";
                CommandManager.InvalidateRequerySuggested();
            });
        }

        private static bool HasArtworkProvidersConfigured()
        {
            // iTunes is always available as a fallback, so we can always attempt artwork retrieval
            return true;
        }

        private async Task OptimizeArtworkOnlyAsync(List<MediaItem> items, string status)
        {
            if (items.Count == 0) return;
            var containsVideo = items.Any(i => i != null &&
                                               (string.Equals(i.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                                string.Equals(i.Type, "tv", StringComparison.OrdinalIgnoreCase)));

            _uiDispatcher.Invoke(() =>
            {
                IsScanning = true;
                ScanProgressText = status;
                ScannedCount = 0;
                StatusText = "Scanning";
                CommandManager.InvalidateRequerySuggested();
            });

            var paths = items
                .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                .Select(i => i.FilePath)
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            _uiDispatcher.Invoke(() =>
            {
                ScannedCount = paths.Count;
                ScanProgressText = $"{status} · fetching covers";
            });

            await EnrichArtworkForPathsAsync(paths, true, false, false).ConfigureAwait(false);
            _uiDispatcher.Invoke(() => RefreshCoversForPaths(paths));

            _uiDispatcher.Invoke(() =>
            {
                var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
                var tmdbMissing = containsVideo && string.IsNullOrWhiteSpace(tmdbKey);
                IsScanning = false;
                ScanProgressText = tmdbMissing ? "TMDb key missing · add it in Settings" : "Ready";
                StatusText = tmdbMissing ? "TMDb key missing" : "Ready";
                CommandManager.InvalidateRequerySuggested();
            });
        }

        private async Task EnrichArtworkForPathsAsync(List<string> filePaths, bool force, bool saveVideoToCustom, bool saveMusicToCustom)
        {
            if (filePaths.Count == 0) return;

            var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
            var mdbListKey = IntegrationKeyStore.GetDecrypted("mdblist");
            var mbContact = IntegrationKeyStore.GetDecrypted("musicbrainz_contact");

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems
                    .Where(i => !string.IsNullOrWhiteSpace(i.FilePath))
                    .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                    .Select(g => g.First())
                    .ToList();
            }

            var byPath = snapshot.ToDictionary(i => i.FilePath, i => i, StringComparer.OrdinalIgnoreCase);

            using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));
            var ct = cts.Token;

            void TryCopyVideoPosterToLocal(MediaItem item, string downloadedPath)
            {
                try
                {
                    if (item == null) return;
                    if (string.IsNullOrWhiteSpace(downloadedPath) || !File.Exists(downloadedPath)) return;

                    var folder = GetVideoFolderPath(item.FilePath);
                    if (string.IsNullOrWhiteSpace(folder) || !Directory.Exists(folder)) return;

                    var baseName = Path.GetFileNameWithoutExtension(item.FilePath) ?? "";
                    if (string.IsNullOrWhiteSpace(baseName)) return;

                    var pngPath = Path.Combine(folder, baseName + ".png");
                    if (File.Exists(pngPath)) return;

                    var jpgPath = Path.Combine(folder, baseName + ".jpg");
                    if (File.Exists(jpgPath) && !force) return;

                    File.Copy(downloadedPath, jpgPath, true);
                    TouchFileUtc(jpgPath);
                }
                catch
                {
                }
            }

            if (string.IsNullOrWhiteSpace(tmdbKey))
            {
                var needsTmdb = filePaths
                    .Select(p => byPath.TryGetValue(p, out var item) ? item : null)
                    .Where(i => i != null)
                    .Any(i => string.Equals(i!.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                              string.Equals(i.Type, "tv", StringComparison.OrdinalIgnoreCase));
                if (needsTmdb)
                {
                    if (string.IsNullOrWhiteSpace(mdbListKey))
                        _uiDispatcher.Invoke(() => ScanProgressText = "TMDb key missing · add it in Settings");
                    else
                        _uiDispatcher.Invoke(() => ScanProgressText = "TMDb key missing · using MDBList posters");
                }
            }

            if (!string.IsNullOrWhiteSpace(tmdbKey))
            {
                var tmdb = new TmdbClient();
                var tmdbCandidates = filePaths
                    .Select(p => byPath.TryGetValue(p, out var item) ? item : null)
                    .Where(i => i != null)
                    .Where(i => string.Equals(i!.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                string.Equals(i.Type, "tv", StringComparison.OrdinalIgnoreCase))
                    .Select(i => i!)
                    .Where(i => force || FindVideoCoverFile(i.FilePath) == null)
                    .Take(40)
                    .ToList();

                var idx = 0;
                foreach (var item in tmdbCandidates)
                {
                    idx++;
                    _uiDispatcher.Invoke(() => ScanProgressText = $"Fetching TMDb posters · {idx}/{tmdbCandidates.Count}");
                    var title = BuildTmdbSearchTitle(item);
                    var dest = saveVideoToCustom
                        ? MediaArtworkCache.GetCustomMoviePosterCachePath(item.FilePath)
                        : MediaArtworkCache.GetMoviePosterCachePath(item.FilePath);
                    var ok = await tmdb.TryDownloadPosterAsync(tmdbKey, title, dest, ct).ConfigureAwait(false);
                    if (!ok && !string.IsNullOrWhiteSpace(mdbListKey))
                        ok = await TryDownloadMdbListPosterAsync(mdbListKey, title, dest, ct).ConfigureAwait(false);
                    if (ok) TryCopyVideoPosterToLocal(item, dest);
                }
            }
            else if (!string.IsNullOrWhiteSpace(mdbListKey))
            {
                var mdbCandidates = filePaths
                    .Select(p => byPath.TryGetValue(p, out var item) ? item : null)
                    .Where(i => i != null)
                    .Where(i => string.Equals(i!.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                string.Equals(i.Type, "tv", StringComparison.OrdinalIgnoreCase))
                    .Select(i => i!)
                    .Where(i => force || FindVideoCoverFile(i.FilePath) == null)
                    .Take(40)
                    .ToList();

                var idx = 0;
                foreach (var item in mdbCandidates)
                {
                    idx++;
                    _uiDispatcher.Invoke(() => ScanProgressText = $"Fetching MDBList posters · {idx}/{mdbCandidates.Count}");
                    var title = BuildTmdbSearchTitle(item);
                    var dest = saveVideoToCustom
                        ? MediaArtworkCache.GetCustomMoviePosterCachePath(item.FilePath)
                        : MediaArtworkCache.GetMoviePosterCachePath(item.FilePath);
                    var ok = await TryDownloadMdbListPosterAsync(mdbListKey, title, dest, ct).ConfigureAwait(false);
                    if (ok) TryCopyVideoPosterToLocal(item, dest);
                }
            }

            static bool HasMusicCachedCover(string folder)
            {
                try
                {
                    if (string.IsNullOrWhiteSpace(folder)) return false;
                    if (MediaArtworkCache.TryGetCustomMusicFolderCoverCachePath(folder, out var custom) && File.Exists(custom))
                        return true;
                    if (MediaArtworkCache.TryGetMusicFolderCoverCachePath(folder, out var cached) && File.Exists(cached))
                        return true;
                }
                catch
                {
                }
                return false;
            }

            var musicCandidates = filePaths
                .Select(p => byPath.TryGetValue(p, out var item) ? item : null)
                .Where(i => i != null)
                .Where(i => string.Equals(i!.Type, "music", StringComparison.OrdinalIgnoreCase))
                .Select(i => i!)
                .Where(i => !string.IsNullOrWhiteSpace(i.Artist) && !string.IsNullOrWhiteSpace(i.Album))
                .GroupBy(i => GetAlbumRootFolder(i.FilePath), StringComparer.OrdinalIgnoreCase)
                .Where(g => !string.IsNullOrWhiteSpace(g.Key))
                .Select(g => g.First())
                .Where(i => force || !HasMusicCachedCover(GetAlbumRootFolder(i.FilePath)))
                .Take(24)
                .ToList();

            if (musicCandidates.Count > 0)
            {
                MusicBrainzClient? mb = null;
                if (!string.IsNullOrWhiteSpace(mbContact))
                    mb = new MusicBrainzClient();

                var idx = 0;
                foreach (var item in musicCandidates)
                {
                    idx++;
                    var folder = GetAlbumRootFolder(item.FilePath);
                    var dest = saveMusicToCustom
                        ? MediaArtworkCache.GetCustomMusicFolderCoverCachePath(folder)
                        : MediaArtworkCache.GetMusicFolderCoverCachePath(folder);

                    var success = false;
                    if (mb != null)
                    {
                        _uiDispatcher.Invoke(() => ScanProgressText = $"Fetching MusicBrainz covers · {idx}/{musicCandidates.Count}");
                        success = await mb.TryDownloadAlbumArtAsync(mbContact, item.Artist, item.Album, dest, ct).ConfigureAwait(false);
                    }

                    if (!success)
                    {
                        _uiDispatcher.Invoke(() => ScanProgressText = $"Checking ReccoBeats · {idx}/{musicCandidates.Count}");
                        success = await _reccoClient.TryDownloadCoverAsync(item.Artist, item.Album, dest, ct).ConfigureAwait(false);
                    }

                    if (!success)
                    {
                        _uiDispatcher.Invoke(() => ScanProgressText = $"Checking iTunes · {idx}/{musicCandidates.Count}");
                        _ = await _itunesClient.TryDownloadCoverAsync(item.Artist, item.Album, dest, ct).ConfigureAwait(false);
                    }
                }
            }
        }

        private int _autoCoverEnrichRunId;
        private bool _autoCoverEnrichEnabled = false;

        private void KickAutoEnrichVideoCovers(IReadOnlyList<MediaItem> items)
        {
            try
            {
                if (!_autoCoverEnrichEnabled) return;
                if (items == null || items.Count == 0) return;

                var tmdbKey = IntegrationKeyStore.GetDecrypted("tmdb");
                var mdbListKey = IntegrationKeyStore.GetDecrypted("mdblist");
                if (string.IsNullOrWhiteSpace(tmdbKey) && string.IsNullOrWhiteSpace(mdbListKey))
                    return;

                var paths = items
                    .Where(i => i != null && !string.IsNullOrWhiteSpace(i.FilePath))
                    .Where(i => string.Equals(i.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                                string.Equals(i.Type, "tv", StringComparison.OrdinalIgnoreCase))
                    .Select(i => i.FilePath)
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .Where(p => !IsHttpUrl(p, out _) && !IsMagnetUrl(p))
                    .Where(p => FindVideoCoverFile(p) == null)
                    .Take(40)
                    .ToList();

                if (paths.Count == 0) return;

                var runId = Interlocked.Increment(ref _autoCoverEnrichRunId);
                _ = Task.Run(async () =>
                {
                    try
                    {
                        var beforeCount = 0;
                        foreach (var p in paths)
                        {
                            var cache = MediaArtworkCache.GetMoviePosterCachePath(p);
                            if (File.Exists(cache)) beforeCount++;
                        }

                        await EnrichArtworkForPathsAsync(paths, false, false, false).ConfigureAwait(false);
                        if (runId != _autoCoverEnrichRunId) return;
                        _uiDispatcher.Invoke(() =>
                        {
                            RefreshCoversForPaths(paths);

                            var afterCount = 0;
                            foreach (var p in paths)
                            {
                                var cache = MediaArtworkCache.GetMoviePosterCachePath(p);
                                if (File.Exists(cache)) afterCount++;
                            }

                            var newCount = Math.Max(0, afterCount - beforeCount);
                            if (newCount == 0)
                            {
                                ScanProgressText = "No posters found";
                            }
                            else
                            {
                                ScanProgressText = $"Posters fetched · {newCount}/{paths.Count}";
                            }
                            OnPropertyChanged(nameof(ScanProgressText));
                        });
                    }
                    catch
                    {
                    }
                });
            }
            catch
            {
            }
        }

        private static string BuildTmdbSearchTitle(MediaItem item)
        {
            var raw = item.Title;
            if (string.IsNullOrWhiteSpace(raw))
                raw = Path.GetFileNameWithoutExtension(item.FilePath) ?? "";

            raw = raw.Replace('_', ' ').Replace('.', ' ').Trim();
            raw = Regex.Replace(raw, "\\b(19\\d{2}|20\\d{2})\\b", " ", RegexOptions.IgnoreCase);
            raw = Regex.Replace(raw, "\\b(480p|720p|1080p|1440p|2160p|4k|8k)\\b", " ", RegexOptions.IgnoreCase);
            raw = Regex.Replace(raw, "\\b(x264|x265|h264|h265|hevc|hdr|dv|dts|aac|ac3|web\\-dl|webrip|bluray|brrip|hdrip|remux)\\b", " ", RegexOptions.IgnoreCase);
            raw = Regex.Replace(raw, "\\s+", " ").Trim();
            return string.IsNullOrWhiteSpace(raw) ? (item.Title ?? "") : raw;
        }

        private static async Task<bool> TryDownloadMdbListPosterAsync(string apiKey, string title, string destPath, CancellationToken ct)
        {
            try
            {
                var key = (apiKey ?? "").Trim();
                if (string.IsNullOrWhiteSpace(key)) return false;
                var q = (title ?? "").Trim();
                if (string.IsNullOrWhiteSpace(q)) return false;
                if (string.IsNullOrWhiteSpace(destPath)) return false;

                using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(20) };
                var url = $"https://mdblist.com/api/?apikey={Uri.EscapeDataString(key)}&t={Uri.EscapeDataString(q)}";
                using var res = await http.GetAsync(url, ct).ConfigureAwait(false);
                if (!res.IsSuccessStatusCode) return false;

                var json = await res.Content.ReadAsStringAsync(ct).ConfigureAwait(false);
                using var doc = JsonDocument.Parse(json);
                var root = doc.RootElement;

                string? posterUrl = null;
                if (root.ValueKind == JsonValueKind.Object)
                {
                    foreach (var prop in root.EnumerateObject())
                    {
                        if (!prop.Name.Equals("poster", StringComparison.OrdinalIgnoreCase) &&
                            !prop.Name.Equals("posterurl", StringComparison.OrdinalIgnoreCase) &&
                            !prop.Name.Equals("image", StringComparison.OrdinalIgnoreCase))
                            continue;

                        if (prop.Value.ValueKind != JsonValueKind.String)
                            continue;

                        var candidate = (prop.Value.GetString() ?? "").Trim();
                        if (string.IsNullOrWhiteSpace(candidate) || string.Equals(candidate, "N/A", StringComparison.OrdinalIgnoreCase))
                            continue;

                        posterUrl = candidate;
                        break;
                    }
                }

                if (string.IsNullOrWhiteSpace(posterUrl) || !Uri.TryCreate(posterUrl, UriKind.Absolute, out var posterUri))
                    return false;

                using var imgRes = await http.GetAsync(posterUri, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                if (!imgRes.IsSuccessStatusCode) return false;

                var contentType = (imgRes.Content.Headers.ContentType?.MediaType ?? "").Trim();
                if (contentType.Contains("image/webp", StringComparison.OrdinalIgnoreCase))
                    return false;

                var dir = Path.GetDirectoryName(destPath);
                if (!string.IsNullOrWhiteSpace(dir))
                    Directory.CreateDirectory(dir);

                await using var input = await imgRes.Content.ReadAsStreamAsync(ct).ConfigureAwait(false);
                await using var output = new FileStream(destPath, FileMode.Create, FileAccess.Write, FileShare.Read);
                await input.CopyToAsync(output, ct).ConfigureAwait(false);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private void RefreshCoversForPaths(List<string> filePaths)
        {
            if (filePaths.Count == 0) return;

            var changed = new HashSet<string>(filePaths, StringComparer.OrdinalIgnoreCase);
            var visiblePaths = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            try
            {
                foreach (var i in LibraryItems.Take(80))
                {
                    if (!string.IsNullOrWhiteSpace(i.FilePath))
                        visiblePaths.Add(i.FilePath);
                }
                if (DetailsItem != null && !string.IsNullOrWhiteSpace(DetailsItem.FilePath))
                    visiblePaths.Add(DetailsItem.FilePath);
            }
            catch
            {
            }

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }

            var any = false;
            var musicAlbumFoldersToUpdate = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var item in snapshot)
            {
                if (string.IsNullOrWhiteSpace(item.FilePath)) continue;
                if (!changed.Contains(item.FilePath)) continue;

                var shouldShowCoverNow = item.IsPlaying || visiblePaths.Contains(item.FilePath);

                if (string.Equals(item.Type, "movies", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(item.Type, "tv", StringComparison.OrdinalIgnoreCase))
                {
                    InvalidateMoviePosterCaches(item.FilePath);
                    item.CoverImage = shouldShowCoverNow ? LoadVideoPosterForFile(item.FilePath) : null;
                }
                else if (string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
                {
                    var folder = GetAlbumRootFolder(item.FilePath);
                    if (!string.IsNullOrWhiteSpace(folder))
                        InvalidateMusicFolderCoverCaches(folder);

                    item.CoverImage = shouldShowCoverNow ? BuildCoverForType(item.Type, item.FilePath, item.Album ?? "", item.TrackNumber) : null;
                }
                else if (string.Equals(item.Type, "images", StringComparison.OrdinalIgnoreCase))
                {
                    InvalidateCachedFileImages(item.FilePath);
                    item.CoverImage = shouldShowCoverNow ? BuildCoverForType(item.Type, item.FilePath, item.Album ?? "", item.TrackNumber) : null;
                }
                any = true;

                if (string.Equals(item.Type, "music", StringComparison.OrdinalIgnoreCase))
                {
                    var folder = GetAlbumRootFolder(item.FilePath);
                    if (!string.IsNullOrWhiteSpace(folder))
                        musicAlbumFoldersToUpdate.Add(folder);
                }
            }

            if (!any) return;

            if (musicAlbumFoldersToUpdate.Count > 0)
            {
                foreach (var album in _musicAlbums)
                {
                    if (string.IsNullOrWhiteSpace(album.SourceFolderPath)) continue;
                    if (!musicAlbumFoldersToUpdate.Contains(album.SourceFolderPath)) continue;

                    InvalidateMusicFolderCoverCaches(album.SourceFolderPath);
                    var cover = LoadMusicFolderCover(album.SourceFolderPath);
                    cover ??= album.Tracks.FirstOrDefault()?.FilePath is string trackPath && !string.IsNullOrWhiteSpace(trackPath)
                        ? LoadEmbeddedAlbumArtFromFile(trackPath)
                        : null;
                    album.CoverImage = cover;
                }
            }

            if (changed.Count > 0)
            {
                var playing = snapshot.FirstOrDefault(i => i.IsPlaying);
                if (playing != null && changed.Contains(playing.FilePath))
                    NowPlayingCoverImage = playing.CoverImage;
            }

            ApplyCategoryFilter();
            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));
        }

        private static List<object> BuildOptimizePrompt(List<MediaItem> batch)
        {
            var allowed = "music,movies,tv,images,games,radio,karaoke";
            var payload = batch.Select(i => new
            {
                filePath = i.FilePath,
                folder = Path.GetDirectoryName(i.FilePath) ?? "",
                albumRootFolder = GetAlbumRootFolder(i.FilePath),
                type = i.Type,
                title = i.Title,
                artist = i.Artist,
                album = i.Album,
                trackNumber = i.TrackNumber == 0 ? (int?)null : i.TrackNumber,
                discNumber = i.DiscNumber == 0 ? (int?)null : i.DiscNumber
            }).ToList();

            return new List<object>
            {
                new
                {
                    role = "system",
                    content =
                        "You are Atlas Media Centre Optimizer. " +
                        "Clean up media library metadata using file paths and existing fields. " +
                        $"Allowed type values: {allowed}. " +
                        "Return ONLY valid JSON (no markdown) as an array of objects. " +
                        "Each object must include: filePath. " +
                        "Optional: title, artist, album, type, trackNumber, discNumber. " +
                        "If you detect multi-disc albums (CD1/CD2 or Disc 1/Disc 2), set album to the shared album title and set discNumber."
                },
                new
                {
                    role = "user",
                    content = JsonSerializer.Serialize(payload)
                }
            };
        }

        private static bool TryParseOptimizedMetadata(string text, out List<AiOptimizedMetadata> items)
        {
            items = new List<AiOptimizedMetadata>();
            if (string.IsNullOrWhiteSpace(text)) return false;

            var candidate = ExtractJson(text);
            if (string.IsNullOrWhiteSpace(candidate)) return false;

            try
            {
                using var doc = JsonDocument.Parse(candidate);
                if (doc.RootElement.ValueKind == JsonValueKind.Array)
                {
                    foreach (var el in doc.RootElement.EnumerateArray())
                    {
                        var item = ParseMetadataElement(el);
                        if (item != null) items.Add(item);
                    }
                    return items.Count > 0;
                }

                if (doc.RootElement.ValueKind == JsonValueKind.Object && doc.RootElement.TryGetProperty("items", out var arr) && arr.ValueKind == JsonValueKind.Array)
                {
                    foreach (var el in arr.EnumerateArray())
                    {
                        var item = ParseMetadataElement(el);
                        if (item != null) items.Add(item);
                    }
                    return items.Count > 0;
                }

                return false;
            }
            catch
            {
                return false;
            }
        }

        private static AiOptimizedMetadata? ParseMetadataElement(JsonElement el)
        {
            if (el.ValueKind != JsonValueKind.Object) return null;
            if (!el.TryGetProperty("filePath", out var fp)) return null;
            var path = fp.GetString() ?? "";
            if (string.IsNullOrWhiteSpace(path)) return null;

            var item = new AiOptimizedMetadata { FilePath = path };

            if (el.TryGetProperty("title", out var t)) item.Title = t.GetString();
            if (el.TryGetProperty("artist", out var ar)) item.Artist = ar.GetString();
            if (el.TryGetProperty("album", out var al)) item.Album = al.GetString();
            if (el.TryGetProperty("type", out var ty)) item.Type = ty.GetString();
            if (el.TryGetProperty("trackNumber", out var tn) && tn.ValueKind == JsonValueKind.Number && tn.TryGetInt32(out var v)) item.TrackNumber = v;
            if (el.TryGetProperty("discNumber", out var dn) && dn.ValueKind == JsonValueKind.Number && dn.TryGetInt32(out var d)) item.DiscNumber = d;

            return item;
        }

        private static string ExtractJson(string text)
        {
            var startArray = text.IndexOf('[');
            var endArray = text.LastIndexOf(']');
            if (startArray >= 0 && endArray > startArray)
                return text.Substring(startArray, endArray - startArray + 1);

            var startObj = text.IndexOf('{');
            var endObj = text.LastIndexOf('}');
            if (startObj >= 0 && endObj > startObj)
                return text.Substring(startObj, endObj - startObj + 1);

            return "";
        }

        private static MediaItem CloneMediaItem(MediaItem item)
        {
            var next = new MediaItem
            {
                PlaybackItem = item.PlaybackItem,
                FilePath = item.FilePath,
                Title = item.Title,
                Metadata = item.Metadata,
                Artist = item.Artist,
                Album = item.Album,
                TrackNumber = item.TrackNumber,
                DiscNumber = item.DiscNumber,
                Duration = item.Duration,
                Type = item.Type,
                AccentBrush = item.AccentBrush,
                IconGeometry = item.IconGeometry,
                LastAiOptimizedUtc = item.LastAiOptimizedUtc,
                CoverUrl = item.CoverUrl,
                CoverImage = null
            };
            next.IsFavorite = item.IsFavorite;
            next.IsSelected = item.IsSelected;
            next.IsPlaying = item.IsPlaying;
            return next;
        }

        private void PushUndoSnapshot()
        {
            lock (_stateLock)
            {
                var snap = _allItems.Select(CloneMediaItem).ToList();
                _undoStack.Push(snap);
                while (_undoStack.Count > 10)
                {
                    _ = _undoStack.Pop();
                }
            }
            CommandManager.InvalidateRequerySuggested();
        }

        private void ApplyOptimizedMetadata(List<AiOptimizedMetadata> updates, bool pushUndoSnapshot, bool saveToDisk, bool writeTags = false)
        {
            if (updates.Count == 0) return;

            if (pushUndoSnapshot)
                PushUndoSnapshot();

            var allowedTypes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "music", "movies", "tv", "images", "games", "radio", "karaoke"
            };

            Dictionary<string, MediaItem> byPath;
            lock (_stateLock)
            {
                byPath = _allItems
                    .Where(i => !string.IsNullOrWhiteSpace(i.FilePath))
                    .GroupBy(i => i.FilePath, StringComparer.OrdinalIgnoreCase)
                    .ToDictionary(g => g.Key, g => g.First(), StringComparer.OrdinalIgnoreCase);
            }

            var currentPlayingPath = "";
            try
            {
                currentPlayingPath = _playbackService.CurrentMedia?.FilePath ?? "";
            }
            catch
            {
            }

            var filesToWrite = new List<(string path, string title, string artist, string album, int track, int disc)>();
            var shouldRebuildMusicAlbums = false;

            foreach (var u in updates)
            {
                if (string.IsNullOrWhiteSpace(u.FilePath)) continue;
                if (!byPath.TryGetValue(u.FilePath, out var existing)) continue;

                var nextType = existing.Type;
                if (!string.IsNullOrWhiteSpace(u.Type) && allowedTypes.Contains(u.Type))
                    nextType = u.Type;

                var nextTitle = string.IsNullOrWhiteSpace(u.Title) ? existing.Title : u.Title!;
                var nextArtist = string.IsNullOrWhiteSpace(u.Artist) ? existing.Artist : u.Artist!;
                var nextAlbum = string.IsNullOrWhiteSpace(u.Album) ? existing.Album : u.Album!;
                var nextTrack = u.TrackNumber ?? existing.TrackNumber;
                var nextDisc = u.DiscNumber ?? existing.DiscNumber;

                if (string.Equals(existing.Type, "music", StringComparison.OrdinalIgnoreCase) ||
                    string.Equals(nextType, "music", StringComparison.OrdinalIgnoreCase))
                {
                    shouldRebuildMusicAlbums = true;
                }

                if (string.Equals(nextType, "music", StringComparison.OrdinalIgnoreCase))
                {
                    nextAlbum = NormalizeAlbumTitle(nextAlbum ?? "");
                    if (nextDisc <= 0)
                        nextDisc = GetDiscNumberFromPath(existing.FilePath);
                    
                    var shouldWriteTagsForThis = false;
                    if (writeTags)
                    {
                        try { shouldWriteTagsForThis = File.Exists(existing.FilePath); } catch { shouldWriteTagsForThis = false; }
                    }

                    if (shouldWriteTagsForThis)
                    {
                        if (!string.IsNullOrWhiteSpace(currentPlayingPath) &&
                            string.Equals(existing.FilePath, currentPlayingPath, StringComparison.OrdinalIgnoreCase))
                        {
                            lock (_pendingTagLock)
                            {
                                _pendingTagWrites[existing.FilePath] = (nextTitle, nextArtist, nextAlbum, nextTrack, nextDisc <= 0 ? 0 : nextDisc);
                            }
                        }
                        else
                        {
                            filesToWrite.Add((existing.FilePath, nextTitle, nextArtist, nextAlbum, nextTrack, nextDisc <= 0 ? 0 : nextDisc));
                        }
                    }

                    if (existing.PlaybackItem != null)
                    {
                        existing.PlaybackItem.Artist = nextArtist;
                        existing.PlaybackItem.Album = nextAlbum;
                        if (nextTrack > 0) existing.PlaybackItem.TrackNumber = nextTrack;
                        existing.PlaybackItem.DisplayName = nextTitle;
                    }
                }
                else
                {
                    if (!string.Equals(nextType, "games", StringComparison.OrdinalIgnoreCase) && existing.PlaybackItem != null)
                    {
                        existing.PlaybackItem.Artist = nextArtist;
                        existing.PlaybackItem.Album = nextAlbum;
                        if (nextTrack > 0) existing.PlaybackItem.TrackNumber = nextTrack;
                        existing.PlaybackItem.DisplayName = nextTitle;
                    }
                }

                var next = new MediaItem
                {
                    PlaybackItem = string.Equals(nextType, "games", StringComparison.OrdinalIgnoreCase) ? null : existing.PlaybackItem,
                    FilePath = existing.FilePath,
                    Title = nextTitle,
                    Metadata = existing.Metadata,
                    Artist = nextArtist,
                    Album = nextAlbum,
                    TrackNumber = nextTrack,
                    DiscNumber = nextDisc <= 0 ? 0 : nextDisc,
                    Duration = existing.Duration,
                    Type = nextType,
                    AccentBrush = AccentForCategory(nextType),
                    IconGeometry = IconForCategory(nextType),
                    LastAiOptimizedUtc = DateTime.UtcNow,
                    CoverUrl = string.Equals(nextType, existing.Type, StringComparison.OrdinalIgnoreCase) ? existing.CoverUrl : null,
                    CoverImage = string.Equals(nextType, existing.Type, StringComparison.OrdinalIgnoreCase)
                        ? existing.CoverImage
                        : BuildCoverForType(nextType, existing.FilePath, nextAlbum, nextTrack)
                };

                next.IsFavorite = existing.IsFavorite;
                next.IsSelected = existing.IsSelected;
                next.IsPlaying = existing.IsPlaying;
                byPath[existing.FilePath] = next;
            }

            if (filesToWrite.Count > 0)
            {
                Task.Run(() =>
                {
                    foreach (var f in filesToWrite)
                    {
                        try
                        {
                            _taggingService.WriteTags(f.path, f.title, f.artist, f.album, f.track, f.disc);
                        }
                        catch
                        {
                        }
                    }
                });
            }

            var rebuilt = byPath.Values
                .OrderBy(i => i.Type, StringComparer.OrdinalIgnoreCase)
                .ThenBy(i => i.Title, StringComparer.OrdinalIgnoreCase)
                .ToList();

            lock (_stateLock)
            {
                _allItems = rebuilt;
            }

            if (shouldRebuildMusicAlbums)
                RebuildMusicAlbums();

            foreach (var c in Categories)
            {
                if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                    c.Count = _addonServers.Count;
                else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                    c.Count = _musicAlbums.Count;
                else
                    c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
            }

            ApplyCategoryFilter();
            OnPropertyChanged(nameof(LibraryCountText));
            OnPropertyChanged(nameof(VisibleCountText));
            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));

            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }
            if (saveToDisk)
                _ = SaveLibraryToDiskAsync(snapshot);
        }

        private void FlushPendingTagWrites(string currentPlayingPath)
        {
            List<(string path, string title, string artist, string album, int track, int disc)> work;
            lock (_pendingTagLock)
            {
                work = _pendingTagWrites
                    .Where(kvp =>
                        !string.IsNullOrWhiteSpace(kvp.Key) &&
                        (string.IsNullOrWhiteSpace(currentPlayingPath) ||
                         !string.Equals(kvp.Key, currentPlayingPath, StringComparison.OrdinalIgnoreCase)))
                    .Select(kvp => (kvp.Key, kvp.Value.title ?? "", kvp.Value.artist ?? "", kvp.Value.album ?? "", kvp.Value.track ?? 0, kvp.Value.disc ?? 0))
                    .ToList();
            }

            if (work.Count == 0) return;

            Task.Run(() =>
            {
                foreach (var f in work)
                {
                    try
                    {
                        var ok = _taggingService.WriteTags(f.path, f.title, f.artist, f.album, f.track, f.disc);
                        if (!ok) continue;
                        lock (_pendingTagLock)
                        {
                            _pendingTagWrites.Remove(f.path);
                        }
                    }
                    catch
                    {
                    }
                }
            });
        }

        private void FlushPendingRemovals(string currentPlayingPath)
        {
            List<string> paths;
            lock (_pendingRemovalLock)
            {
                paths = _pendingRemovals
                    .Where(p =>
                        !string.IsNullOrWhiteSpace(p) &&
                        (string.IsNullOrWhiteSpace(currentPlayingPath) ||
                         !string.Equals(p, currentPlayingPath, StringComparison.OrdinalIgnoreCase)))
                    .ToList();
            }

            if (paths.Count == 0) return;

            _uiDispatcher.BeginInvoke(() =>
            {
                try
                {
                    RemoveFromLibraryByPaths(paths);
                    lock (_pendingRemovalLock)
                    {
                        foreach (var p in paths)
                            _pendingRemovals.Remove(p);
                    }
                }
                catch
                {
                }
            });
        }

        private void RemoveFromLibraryByPaths(IReadOnlyList<string> paths)
        {
            if (paths == null || paths.Count == 0) return;

            var selectedCategoryId = SelectedCategory?.Id ?? "";
            var selectedAlbumFolder = SelectedAlbum?.SourceFolderPath;

            var removedMusic = false;
            lock (_stateLock)
            {
                for (var i = _allItems.Count - 1; i >= 0; i--)
                {
                    var it = _allItems[i];
                    if (it == null) continue;
                    if (!paths.Contains(it.FilePath, StringComparer.OrdinalIgnoreCase)) continue;
                    if (string.Equals(it.Type, "music", StringComparison.OrdinalIgnoreCase))
                        removedMusic = true;
                    _allItems.RemoveAt(i);
                }

                foreach (var p in paths)
                    _ignoredPaths.Add(p);
            }

            try
            {
                if (DetailsItem != null && paths.Contains(DetailsItem.FilePath, StringComparer.OrdinalIgnoreCase))
                {
                    DetailsItem = null;
                    IsDetailsOpen = false;
                }
            }
            catch
            {
            }

            if (removedMusic)
            {
                RebuildMusicAlbums();
                if (string.Equals(selectedCategoryId, "music", StringComparison.OrdinalIgnoreCase) &&
                    !string.IsNullOrWhiteSpace(selectedAlbumFolder))
                {
                    var album = _musicAlbums.FirstOrDefault(a =>
                        string.Equals(a.SourceFolderPath, selectedAlbumFolder, StringComparison.OrdinalIgnoreCase));
                    if (album != null)
                        SelectAlbum(album);
                    else
                        SelectedAlbum = null;
                }
            }

            foreach (var c in Categories)
            {
                if (string.Equals(c.Id, "servers", StringComparison.OrdinalIgnoreCase))
                    c.Count = _addonServers.Count;
                else if (string.Equals(c.Id, "music", StringComparison.OrdinalIgnoreCase))
                    c.Count = _musicAlbums.Count;
                else
                    c.Count = _allItems.Count(i => string.Equals(i.Type, c.Id, StringComparison.OrdinalIgnoreCase));
            }

            ApplyCategoryFilter();
            List<MediaItem> snapshot;
            lock (_stateLock)
            {
                snapshot = _allItems.ToList();
            }
            _ = SaveLibraryToDiskAsync(snapshot);
        }

        private static ImageSource? BuildCoverForType(string type, string filePath, string album, int trackNumber)
        {
            if (string.Equals(type, "movies", StringComparison.OrdinalIgnoreCase) || string.Equals(type, "tv", StringComparison.OrdinalIgnoreCase))
            {
                return LoadVideoPosterForFile(filePath);
            }

            if (string.Equals(type, "music", StringComparison.OrdinalIgnoreCase))
            {
                return LoadMusicCoverForTrack(filePath);
            }

            if (string.Equals(type, "images", StringComparison.OrdinalIgnoreCase))
            {
                if (IsHttpUrl(filePath, out _))
                    return null;
                return LoadAlbumCoverFromFile(filePath);
            }

            if (string.Equals(type, "games", StringComparison.OrdinalIgnoreCase))
            {
                return LoadGameCoverImage(album ?? "", trackNumber, filePath);
            }

            return null;
        }

        private static bool IsHttpUrl(string? value, out Uri uri)
        {
            uri = null!;
            if (string.IsNullOrWhiteSpace(value)) return false;
            if (!Uri.TryCreate(value, UriKind.Absolute, out uri)) return false;
            if (string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase)) return true;
            if (string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase)) return true;
            return false;
        }

        internal static bool IsLikelyAddonNavigationUrl(string? value)
        {
            if (!IsHttpUrl(value, out var uri)) return false;

            var path = Uri.UnescapeDataString(uri.AbsolutePath ?? "").Trim().ToLowerInvariant();
            if (string.IsNullOrWhiteSpace(path)) return false;

            if (path.EndsWith("/manifest.json", StringComparison.OrdinalIgnoreCase) || path.EndsWith("manifest.json", StringComparison.OrdinalIgnoreCase))
                return true;

            if (path.Contains("/configure", StringComparison.OrdinalIgnoreCase)
                || path.Contains("/configuration", StringComparison.OrdinalIgnoreCase)
                || path.Contains("/addon", StringComparison.OrdinalIgnoreCase)
                || path.Contains("/addons", StringComparison.OrdinalIgnoreCase)
                || path.Contains("/detail", StringComparison.OrdinalIgnoreCase)
                || path.Contains("/details", StringComparison.OrdinalIgnoreCase))
                return true;

            return false;
        }

        private static bool IsMagnetUrl(string? value)
        {
            var v = (value ?? "").Trim();
            return v.StartsWith("magnet:", StringComparison.OrdinalIgnoreCase);
        }

        private static ScannerMediaType GuessMediaTypeForCategory(string categoryId, string extension)
        {
            if (string.Equals(categoryId, "images", StringComparison.OrdinalIgnoreCase))
                return ScannerMediaType.Image;
            if (string.Equals(categoryId, "music", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(categoryId, "radio", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(categoryId, "karaoke", StringComparison.OrdinalIgnoreCase))
                return ScannerMediaType.Audio;
            if (string.Equals(categoryId, "movies", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(categoryId, "tv", StringComparison.OrdinalIgnoreCase))
                return ScannerMediaType.Video;

            if (AudioExtensions.Contains(extension)) return ScannerMediaType.Audio;
            if (VideoExtensions.Contains(extension)) return ScannerMediaType.Video;
            if (ImageExtensions.Contains(extension)) return ScannerMediaType.Image;
            return ScannerMediaType.Unknown;
        }

        private static string GetSystemSpecsBrief()
        {
            try
            {
                var cpu = "";
                var gpu = "";
                var ramGb = 0.0;

                try
                {
                    using var searcher = new System.Management.ManagementObjectSearcher("SELECT Name FROM Win32_Processor");
                    foreach (var o in searcher.Get())
                    {
                        cpu = o?["Name"]?.ToString() ?? "";
                        break;
                    }
                }
                catch
                {
                }

                try
                {
                    using var searcher = new System.Management.ManagementObjectSearcher("SELECT Name FROM Win32_VideoController");
                    foreach (var o in searcher.Get())
                    {
                        gpu = o?["Name"]?.ToString() ?? "";
                        if (!string.IsNullOrWhiteSpace(gpu)) break;
                    }
                }
                catch
                {
                }

                try
                {
                    using var searcher = new System.Management.ManagementObjectSearcher("SELECT TotalPhysicalMemory FROM Win32_ComputerSystem");
                    foreach (var o in searcher.Get())
                    {
                        if (o?["TotalPhysicalMemory"] is ulong memBytes)
                            ramGb = memBytes / 1024.0 / 1024.0 / 1024.0;
                        break;
                    }
                }
                catch
                {
                }

                return
                    $"OS: {Environment.OSVersion}\n" +
                    $"CPU: {(string.IsNullOrWhiteSpace(cpu) ? "Unknown" : cpu)}\n" +
                    $"GPU: {(string.IsNullOrWhiteSpace(gpu) ? "Unknown" : gpu)}\n" +
                    $"RAM: {(ramGb <= 0 ? "Unknown" : $"{ramGb:F0} GB")}";
            }
            catch
            {
                return $"OS: {Environment.OSVersion}";
            }
        }

        private void ShowTextModal(string title, string content)
        {
            _uiDispatcher.Invoke(() =>
            {
                var dialog = new System.Windows.Window
                {
                    Title = title,
                    Width = 720,
                    Height = 560,
                    WindowStartupLocation = System.Windows.WindowStartupLocation.CenterScreen,
                    Background = new SolidColorBrush(Color.FromRgb(0x0A, 0x0E, 0x12))
                };
                var owner = GetDialogOwner();
                if (owner != null)
                {
                    dialog.Owner = owner;
                    dialog.WindowStartupLocation = System.Windows.WindowStartupLocation.CenterOwner;
                }

                var root = new System.Windows.Controls.Grid { Margin = new System.Windows.Thickness(18) };
                root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = System.Windows.GridLength.Auto });
                root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = new System.Windows.GridLength(1, System.Windows.GridUnitType.Star) });
                root.RowDefinitions.Add(new System.Windows.Controls.RowDefinition { Height = System.Windows.GridLength.Auto });

                var header = new System.Windows.Controls.TextBlock
                {
                    Text = title,
                    Foreground = new SolidColorBrush(Color.FromRgb(0x22, 0xD3, 0xEE)),
                    FontSize = 16,
                    FontWeight = System.Windows.FontWeights.SemiBold,
                    Margin = new System.Windows.Thickness(0, 0, 0, 12)
                };
                System.Windows.Controls.Grid.SetRow(header, 0);
                root.Children.Add(header);

                var scroll = new System.Windows.Controls.ScrollViewer
                {
                    VerticalScrollBarVisibility = System.Windows.Controls.ScrollBarVisibility.Auto
                };
                var text = new System.Windows.Controls.TextBox
                {
                    Text = content ?? "",
                    TextWrapping = System.Windows.TextWrapping.Wrap,
                    IsReadOnly = true,
                    Background = new SolidColorBrush(Color.FromRgb(0x08, 0x0A, 0x10)),
                    Foreground = new SolidColorBrush(Color.FromRgb(0xE6, 0xED, 0xF3)),
                    BorderBrush = new SolidColorBrush(Color.FromArgb(0x40, 0x22, 0xD3, 0xEE)),
                    BorderThickness = new System.Windows.Thickness(1),
                    Padding = new System.Windows.Thickness(12)
                };
                scroll.Content = text;
                System.Windows.Controls.Grid.SetRow(scroll, 1);
                root.Children.Add(scroll);

                var footer = new System.Windows.Controls.StackPanel
                {
                    Orientation = System.Windows.Controls.Orientation.Horizontal,
                    HorizontalAlignment = System.Windows.HorizontalAlignment.Right,
                    Margin = new System.Windows.Thickness(0, 12, 0, 0)
                };

                var copy = new System.Windows.Controls.Button
                {
                    Content = "Copy",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6),
                    Margin = new System.Windows.Thickness(0, 0, 10, 0)
                };
                copy.Click += (_, _) =>
                {
                    try
                    {
                        System.Windows.Clipboard.SetText(content ?? "");
                    }
                    catch
                    {
                    }
                };

                var close = new System.Windows.Controls.Button
                {
                    Content = "Close",
                    Padding = new System.Windows.Thickness(12, 6, 12, 6)
                };
                close.Click += (_, _) => dialog.Close();

                footer.Children.Add(copy);
                footer.Children.Add(close);
                System.Windows.Controls.Grid.SetRow(footer, 2);
                root.Children.Add(footer);

                dialog.Content = root;
                dialog.ShowDialog();
            });
        }

        private void RemoveFromLibrary(MediaItem? item)
        {
            if (item == null) return;
            var path = item.FilePath;
            if (string.IsNullOrWhiteSpace(path)) return;

            try
            {
                var currentPlayingPath = _playbackService.CurrentMedia?.FilePath ?? "";
                if (!string.IsNullOrWhiteSpace(currentPlayingPath) &&
                    string.Equals(currentPlayingPath, path, StringComparison.OrdinalIgnoreCase))
                {
                    lock (_pendingRemovalLock)
                    {
                        _pendingRemovals.Add(path);
                    }
                    StatusText = "Will remove after playback finishes";
                    OnPropertyChanged(nameof(StatusText));
                    return;
                }
            }
            catch
            {
            }

            _uiDispatcher.BeginInvoke(() =>
            {
                var selectedCategoryId = SelectedCategory?.Id ?? "";
                var selectedAlbumFolder = SelectedAlbum?.SourceFolderPath;
                var removedType = item.Type ?? "";
                var removed = false;

                lock (_stateLock)
                {
                    for (var i = 0; i < _allItems.Count; i++)
                    {
                        var it = _allItems[i];
                        if (it == null) continue;
                        if (!string.Equals(it.FilePath, path, StringComparison.OrdinalIgnoreCase)) continue;
                        _allItems.RemoveAt(i);
                        removed = true;
                        break;
                    }

                    if (removed)
                    {
                        var isLocal = false;
                        try { isLocal = File.Exists(path); } catch { isLocal = false; }
                        if (isLocal)
                            _ignoredPaths.Add(path);
                    }
                }

                if (!removed) return;

                try
                {
                    if (DetailsItem != null && string.Equals(DetailsItem.FilePath, path, StringComparison.OrdinalIgnoreCase))
                    {
                        DetailsItem = null;
                        IsDetailsOpen = false;
                    }
                }
                catch
                {
                }

                try
                {
                    for (var i = 0; i < LibraryItems.Count; i++)
                    {
                        var li = LibraryItems[i];
                        if (li == null) continue;
                        if (!string.Equals(li.FilePath, path, StringComparison.OrdinalIgnoreCase)) continue;
                        LibraryItems.RemoveAt(i);
                        break;
                    }
                }
                catch
                {
                }

                if (string.Equals(removedType, "music", StringComparison.OrdinalIgnoreCase))
                {
                    RebuildMusicAlbums();

                    if (string.Equals(selectedCategoryId, "music", StringComparison.OrdinalIgnoreCase) &&
                        !string.IsNullOrWhiteSpace(selectedAlbumFolder))
                    {
                        var album = _musicAlbums.FirstOrDefault(a =>
                            string.Equals(a.SourceFolderPath, selectedAlbumFolder, StringComparison.OrdinalIgnoreCase));

                        if (album != null)
                            SelectAlbum(album);
                        else
                            SelectedAlbum = null;
                    }
                }
                else
                {
                    var cat = Categories.FirstOrDefault(c => string.Equals(c.Id, removedType, StringComparison.OrdinalIgnoreCase));
                    if (cat != null)
                        cat.Count = Math.Max(0, cat.Count - 1);
                }

                if (!string.Equals(selectedCategoryId, "music", StringComparison.OrdinalIgnoreCase) || SelectedAlbum == null)
                {
                    if (LibraryItems.Count == 0)
                        ApplyCategoryFilter();
                }

                OnPropertyChanged(nameof(LibraryCountText));
                OnPropertyChanged(nameof(PlaytimeText));
                OnPropertyChanged(nameof(VisibleCountText));

                _ = Task.Run(() =>
                {
                    try
                    {
                        List<MediaItem> snapshot;
                        lock (_stateLock)
                        {
                            snapshot = _allItems.ToList();
                        }
                        _ = SaveLibraryToDiskAsync(snapshot);
                    }
                    catch
                    {
                    }
                });
            });
        }

        private void Previous()
        {
            _playbackService.PlayPrevious();
        }

        private void Next()
        {
            _playbackService.PlayNext();
        }

        private void TogglePlayPause()
        {
            _togglePlayerPlayPause?.Invoke();
            IsPlaying = !IsPlaying;
        }

        private void StopPlayback()
        {
            try
            {
                _stopPlayer?.Invoke();
            }
            catch
            {
            }

            try
            {
                if (_videoPlayerWindow != null)
                {
                    try { _videoPlayerWindow.Close(); } catch { }
                    _videoPlayerWindow = null;
                }
            }
            catch
            {
            }

            try
            {
                foreach (var window in Application.Current.Windows.OfType<AtlasAI.FullscreenPlayerWindow>().ToList())
                {
                    try { window.Close(); } catch { }
                }
            }
            catch
            {
            }

            try
            {
                _playbackService.ClearQueue();
            }
            catch
            {
            }

            try
            {
                foreach (var i in LibraryItems)
                {
                    i.IsPlaying = false;
                    i.IsSelected = false;
                }
            }
            catch
            {
            }

            NowPlayingTitle = "No media selected";
            NowPlayingArtist = "";
            NowPlayingAlbum = "";
            NowPlayingTypeId = "";
            NowPlayingCoverImage = null;
            TotalSeconds = 0;
            ProgressSeconds = 0;
            IsPlaying = false;
            StatusText = "Ready";
            OnPropertyChanged(nameof(NowPlayingTitle));
            OnPropertyChanged(nameof(NowPlayingArtist));
            OnPropertyChanged(nameof(NowPlayingAlbum));
            OnPropertyChanged(nameof(NowPlayingTypeId));
            OnPropertyChanged(nameof(IsNowPlayingMusic));
            OnPropertyChanged(nameof(TrendingValue));
            OnPropertyChanged(nameof(VisibleCountText));
            OnPropertyChanged(nameof(StatusText));
        }

        private void RebuildMusicAlbums()
        {
            var selectedKey = SelectedAlbum?.SourceFolderPath;
            Dictionary<string, ImageSource> coverByFolder;
            try
            {
                coverByFolder = _musicAlbums
                    .Where(a => a.CoverImage != null && !string.IsNullOrWhiteSpace(a.SourceFolderPath))
                    .GroupBy(a => a.SourceFolderPath, StringComparer.OrdinalIgnoreCase)
                    .ToDictionary(g => g.Key, g => g.First().CoverImage!, StringComparer.OrdinalIgnoreCase);
            }
            catch
            {
                coverByFolder = new Dictionary<string, ImageSource>(StringComparer.OrdinalIgnoreCase);
            }
            var musicTracks = _allItems.Where(i => string.Equals(i.Type, "music", StringComparison.OrdinalIgnoreCase)).ToList();
            var albums = BuildAlbumEntries(musicTracks, loadCovers: false);

            _musicAlbums.Clear();
            foreach (var a in albums)
            {
                try
                {
                    if (a.CoverImage == null && !string.IsNullOrWhiteSpace(a.SourceFolderPath) && coverByFolder.TryGetValue(a.SourceFolderPath, out var cover))
                        a.CoverImage = cover;
                }
                catch
                {
                }
                _musicAlbums.Add(a);
            }
            RebuildAlbumRows();
            KickLoadMusicAlbumCovers();

            if (!string.IsNullOrWhiteSpace(selectedKey))
            {
                var match = _musicAlbums.FirstOrDefault(a => string.Equals(a.SourceFolderPath, selectedKey, StringComparison.OrdinalIgnoreCase));
                if (match != null)
                {
                    foreach (var a in _musicAlbums) a.IsSelected = ReferenceEquals(a, match);
                    SelectedAlbum = match;
                }
                else
                {
                    foreach (var a in _musicAlbums) a.IsSelected = false;
                    SelectedAlbum = null;
                }
            }

            OnPropertyChanged(nameof(HasLibraryItems));
            OnPropertyChanged(nameof(HasNoLibraryItems));
            OnPropertyChanged(nameof(VisibleCountText));
        }

        private void RebuildAlbumRows()
        {
            _musicAlbumRows.Clear();
            for (var i = 0; i < _musicAlbums.Count; i += 4)
            {
                var row = new AlbumRow();
                for (var j = 0; j < 4; j++)
                {
                    var idx = i + j;
                    if (idx >= _musicAlbums.Count) break;
                    row.Albums.Add(_musicAlbums[idx]);
                }
                _musicAlbumRows.Add(row);
            }
        }

        private void KickLoadMusicAlbumCovers(int maxAlbums = 48)
        {
            var runId = Interlocked.Increment(ref _musicAlbumCoverRunId);

            List<AlbumEntry> targets;
            try
            {
                targets = _musicAlbums
                    .Where(a => a.CoverImage == null && !string.IsNullOrWhiteSpace(a.SourceFolderPath))
                    .Take(Math.Max(1, maxAlbums))
                    .ToList();
            }
            catch
            {
                return;
            }

            if (targets.Count == 0) return;

            Task.Run(() =>
            {
                try
                {
                    var covers = new Dictionary<string, ImageSource>(StringComparer.OrdinalIgnoreCase);
                    foreach (var a in targets)
                    {
                        if (runId != _musicAlbumCoverRunId) return;

                        var folder = a.SourceFolderPath ?? "";
                        if (string.IsNullOrWhiteSpace(folder)) continue;

                        ImageSource? cover = LoadMusicFolderCover(folder);
                        if (cover == null)
                        {
                            var first = a.Tracks.FirstOrDefault()?.FilePath ?? "";
                            if (!string.IsNullOrWhiteSpace(first))
                                cover = LoadEmbeddedAlbumArtFromFile(first);
                        }

                        if (cover != null)
                            covers[folder] = cover;
                    }

                    if (covers.Count == 0) return;

                    _uiDispatcher.BeginInvoke(() =>
                    {
                        try
                        {
                            foreach (var a in _musicAlbums)
                            {
                                if (a.CoverImage != null) continue;
                                var folder = a.SourceFolderPath ?? "";
                                if (string.IsNullOrWhiteSpace(folder)) continue;
                                if (covers.TryGetValue(folder, out var cover))
                                    a.CoverImage = cover;
                            }
                        }
                        catch
                        {
                        }
                    });
                }
                catch
                {
                }
            });
        }

        private static List<AlbumEntry> BuildAlbumEntries(List<MediaItem> musicTracks, bool loadCovers = true)
        {
            static string KeyFor(MediaItem t)
            {
                var albumRoot = GetAlbumRootFolder(t.FilePath);
                var folderAlbum = Path.GetFileName(albumRoot) ?? "";
                var (folderArtist, folderAlbumTitle) = DeriveArtistAlbumFromFolderName(folderAlbum);

                var artist = string.IsNullOrWhiteSpace(t.Artist) ? folderArtist : t.Artist;
                var album = string.IsNullOrWhiteSpace(t.Album) || IsDiscToken(t.Album) ? folderAlbumTitle : t.Album;
                album = NormalizeAlbumTitle(string.IsNullOrWhiteSpace(album) ? folderAlbumTitle : album);

                if (!string.IsNullOrWhiteSpace(artist) && !string.IsNullOrWhiteSpace(album))
                    return $"{artist}|{album}";

                return albumRoot;
            }

            var groups = musicTracks
                .GroupBy(KeyFor, StringComparer.OrdinalIgnoreCase)
                .OrderBy(g => g.Key, StringComparer.OrdinalIgnoreCase)
                .ToList();

            var result = new List<AlbumEntry>();
            foreach (var g in groups)
            {
                var first = g.FirstOrDefault();
                if (first == null) continue;

                var folder = GetAlbumRootFolder(first.FilePath);
                ImageSource? cover = null;
                if (loadCovers)
                {
                    cover = LoadMusicFolderCover(folder);
                    if (cover == null)
                    {
                        var trackFolder = Path.GetDirectoryName(first.FilePath) ?? "";
                        if (!string.IsNullOrWhiteSpace(trackFolder) &&
                            !string.Equals(trackFolder, folder, StringComparison.OrdinalIgnoreCase))
                        {
                            cover = LoadMusicFolderCover(trackFolder);
                        }
                    }
                    cover ??= LoadEmbeddedAlbumArtFromFile(first.FilePath);
                }

                var folderName = Path.GetFileName(folder) ?? "";
                var (folderArtist, folderAlbumTitle) = DeriveArtistAlbumFromFolderName(folderName);
                var resolvedArtist = string.IsNullOrWhiteSpace(first.Artist) ? folderArtist : first.Artist;
                var resolvedAlbum = string.IsNullOrWhiteSpace(first.Album) || IsDiscToken(first.Album) ? folderAlbumTitle : first.Album;
                resolvedAlbum = NormalizeAlbumTitle(string.IsNullOrWhiteSpace(resolvedAlbum) ? folderAlbumTitle : resolvedAlbum);

                var album = new AlbumEntry
                {
                    Artist = string.IsNullOrWhiteSpace(resolvedArtist) ? "Unknown Artist" : resolvedArtist,
                    AlbumTitle = string.IsNullOrWhiteSpace(resolvedAlbum) ? (Path.GetFileName(folder) ?? "Unknown Album") : resolvedAlbum,
                    SourceFolderPath = folder,
                    CoverImage = cover,
                    TrackCount = g.Count(),
                    AccentBrush = first.AccentBrush
                };

                foreach (var t in g.OrderBy(t => t.DiscNumber == 0 ? 999 : t.DiscNumber)
                                   .ThenBy(t => t.TrackNumber == 0 ? 999 : t.TrackNumber)
                                   .ThenBy(t => t.Title, StringComparer.OrdinalIgnoreCase))
                {
                    album.Tracks.Add(t);
                }

                result.Add(album);
            }

            return result;
        }

        private static string GetAlbumRootFolder(string filePath)
        {
            try
            {
                var folder = Path.GetDirectoryName(filePath) ?? "";
                if (string.IsNullOrWhiteSpace(folder)) return folder;
                var name = Path.GetFileName(folder) ?? "";
                if (!string.IsNullOrWhiteSpace(name) && IsDiscToken(name))
                {
                    var parent = Path.GetDirectoryName(folder) ?? "";
                    return string.IsNullOrWhiteSpace(parent) ? folder : parent;
                }
                return folder;
            }
            catch
            {
                return Path.GetDirectoryName(filePath) ?? "";
            }
        }

        private static int GetDiscNumberFromPath(string filePath)
        {
            try
            {
                var folder = Path.GetDirectoryName(filePath) ?? "";
                if (string.IsNullOrWhiteSpace(folder)) return 0;
                var name = Path.GetFileName(folder) ?? "";
                return TryParseDiscToken(name, out var disc) ? disc : 0;
            }
            catch
            {
                return 0;
            }
        }

        private static (string artist, string album) DeriveArtistAlbumFromFolderName(string folderName)
        {
            var name = (folderName ?? "").Trim();
            if (string.IsNullOrWhiteSpace(name)) return ("", "");

            var idx = name.IndexOf(" - ", StringComparison.Ordinal);
            if (idx > 0 && idx < name.Length - 3)
            {
                var a = name.Substring(0, idx).Trim();
                var al = name.Substring(idx + 3).Trim();
                if (!string.IsNullOrWhiteSpace(a) && !string.IsNullOrWhiteSpace(al))
                    return (a, al);
            }

            return ("", name);
        }

        private static bool IsDiscToken(string text)
        {
            return TryParseDiscToken(text, out _);
        }

        private static bool TryParseDiscToken(string text, out int disc)
        {
            disc = 0;
            var s = (text ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return false;

            var m = Regex.Match(s, "^(cd|disc|disk)\\s*0*(\\d+)$", RegexOptions.IgnoreCase);
            if (!m.Success) return false;
            if (!int.TryParse(m.Groups[2].Value, out var v)) return false;
            if (v <= 0 || v > 50) return false;
            disc = v;
            return true;
        }

        private static string NormalizeAlbumTitle(string album)
        {
            var s = (album ?? "").Trim();
            if (string.IsNullOrWhiteSpace(s)) return s;

            for (var i = 0; i < 4; i++)
            {
                var before = s;
                s = Regex.Replace(s, "\\s*[\\(\\[]\\s*(cd|disc|disk)\\s*0*\\d+\\s*[\\)\\]]\\s*$", "", RegexOptions.IgnoreCase).Trim();
                s = Regex.Replace(s, "\\s*[-–—]?\\s*(cd|disc|disk)\\s*0*\\d+\\s*$", "", RegexOptions.IgnoreCase).Trim();
                if (string.Equals(before, s, StringComparison.Ordinal)) break;
            }

            return s;
        }

        private static string? FindAlbumCoverFile(string folderPath)
        {
            try
            {
                foreach (var name in AlbumCoverNames)
                {
                    var p = Path.Combine(folderPath, name);
                    if (File.Exists(p)) return p;
                }

                if (MediaArtworkCache.TryGetCustomMusicFolderCoverCachePath(folderPath, out var custom) && File.Exists(custom))
                    return custom;

                if (MediaArtworkCache.TryGetMusicFolderCoverCachePath(folderPath, out var cached) && File.Exists(cached))
                    return cached;
            }
            catch
            {
            }

            return null;
        }

        private static readonly string[] AlbumCoverNames =
        {
            "cover.jpg", "folder.jpg", "album.jpg", "front.jpg", "poster.jpg", "AlbumArtSmall.jpg",
            "cover.jpeg", "folder.jpeg", "album.jpeg", "front.jpeg", "poster.jpeg",
            "cover.png", "folder.png", "album.png", "front.png", "poster.png"
        };

        private static ImageSource? LoadMusicFolderCover(string folderPath)
        {
            if (string.IsNullOrWhiteSpace(folderPath)) return null;
            try
            {
                foreach (var name in AlbumCoverNames)
                {
                    var p = Path.Combine(folderPath, name);
                    var img = LoadAlbumCoverFromFile(p);
                    if (img != null) return img;
                }

                if (MediaArtworkCache.TryGetCustomMusicFolderCoverCachePath(folderPath, out var custom) && File.Exists(custom))
                {
                    var customImg = LoadAlbumCoverFromFile(custom);
                    if (customImg != null) return customImg;
                }

                if (MediaArtworkCache.TryGetMusicFolderCoverCachePath(folderPath, out var cached) && File.Exists(cached))
                {
                    var cachedImg = LoadAlbumCoverFromFile(cached);
                    if (cachedImg != null) return cachedImg;
                }
            }
            catch
            {
            }

            return null;
        }

        private static ImageSource? LoadMusicCoverForTrack(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath)) return null;
            if (IsHttpUrl(filePath, out _)) return null;

            var albumRootFolder = GetAlbumRootFolder(filePath);
            var cover = LoadMusicFolderCover(albumRootFolder);
            if (cover != null) return cover;

            var trackFolder = Path.GetDirectoryName(filePath) ?? "";
            if (!string.IsNullOrWhiteSpace(trackFolder) &&
                !string.Equals(trackFolder, albumRootFolder, StringComparison.OrdinalIgnoreCase))
            {
                cover = LoadMusicFolderCover(trackFolder);
                if (cover != null) return cover;
            }

            return LoadEmbeddedAlbumArtFromFile(filePath);
        }

        private static string? FindVideoCoverFile(string mediaFilePath)
        {
            try
            {
                var folder = Directory.Exists(mediaFilePath)
                    ? mediaFilePath
                    : (Path.GetDirectoryName(mediaFilePath) ?? "");
                if (string.IsNullOrWhiteSpace(folder)) return null;

                if (MediaArtworkCache.TryGetCustomMoviePosterCachePath(mediaFilePath, out var custom) && File.Exists(custom))
                    return custom;

                var baseName = Directory.Exists(mediaFilePath)
                    ? (Path.GetFileName(folder) ?? "")
                    : (Path.GetFileNameWithoutExtension(mediaFilePath) ?? "");
                var coverNames = new[]
                {
                    $"{baseName}.png", $"{baseName}.jpg", $"{baseName}.jpeg",
                    "poster.png", "poster.jpg", "poster.jpeg",
                    "folder.png", "folder.jpg", "folder.jpeg",
                    "cover.png", "cover.jpg", "cover.jpeg",
                    "movie.png", "movie.jpg", "movie.jpeg",
                    "fanart.png", "fanart.jpg", "fanart.jpeg"
                };

                foreach (var name in coverNames)
                {
                    var p = Path.Combine(folder, name);
                    if (File.Exists(p)) return p;
                }

                var parent = Path.GetDirectoryName(folder) ?? "";
                if (!string.IsNullOrWhiteSpace(parent) && !string.Equals(parent, folder, StringComparison.OrdinalIgnoreCase))
                {
                    foreach (var name in coverNames)
                    {
                        var p = Path.Combine(parent, name);
                        if (File.Exists(p)) return p;
                    }
                }

                if (MediaArtworkCache.TryGetMoviePosterCachePath(mediaFilePath, out var cached) && File.Exists(cached))
                {
                    var ext = Path.GetExtension(cached).ToLowerInvariant();
                    if (!string.Equals(ext, ".webp", StringComparison.OrdinalIgnoreCase))
                        return cached;
                }
            }
            catch
            {
            }

            return null;
        }

        private static string GetVideoFolderPath(string mediaFilePath)
        {
            try
            {
                if (Directory.Exists(mediaFilePath))
                    return mediaFilePath;
                return Path.GetDirectoryName(mediaFilePath) ?? "";
            }
            catch
            {
                return "";
            }
        }

        private static bool IsWebpFile(string filePath)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(filePath) || !File.Exists(filePath)) return false;
                using var fs = new FileStream(filePath, FileMode.Open, FileAccess.Read, FileShare.ReadWrite);
                if (fs.Length < 12) return false;
                var buf = new byte[12];
                var read = fs.Read(buf, 0, buf.Length);
                if (read < 12) return false;

                return buf[0] == (byte)'R' &&
                       buf[1] == (byte)'I' &&
                       buf[2] == (byte)'F' &&
                       buf[3] == (byte)'F' &&
                       buf[8] == (byte)'W' &&
                       buf[9] == (byte)'E' &&
                       buf[10] == (byte)'B' &&
                       buf[11] == (byte)'P';
            }
            catch
            {
                return false;
            }
        }

        private static string GetFfmpegExePath()
        {
            try
            {
                var baseDir = AppContext.BaseDirectory ?? "";
                if (!string.IsNullOrWhiteSpace(baseDir))
                {
                    var p1 = Path.Combine(baseDir, "ffmpeg", "ffmpeg.exe");
                    if (File.Exists(p1)) return p1;
                    var p2 = Path.Combine(baseDir, "ffmpeg.exe");
                    if (File.Exists(p2)) return p2;
                }

                var cwd = Environment.CurrentDirectory ?? "";
                if (!string.IsNullOrWhiteSpace(cwd))
                {
                    var p3 = Path.Combine(cwd, "ffmpeg", "ffmpeg.exe");
                    if (File.Exists(p3)) return p3;
                    var p4 = Path.Combine(cwd, "ffmpeg.exe");
                    if (File.Exists(p4)) return p4;
                }
            }
            catch
            {
            }

            return "ffmpeg.exe";
        }

        private static bool TryConvertToPngWithFfmpeg(string sourcePath, string destinationPath)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(sourcePath) || string.IsNullOrWhiteSpace(destinationPath)) return false;
                if (!File.Exists(sourcePath)) return false;

                var dir = Path.GetDirectoryName(destinationPath);
                if (!string.IsNullOrWhiteSpace(dir))
                    Directory.CreateDirectory(dir);

                try
                {
                    if (File.Exists(destinationPath))
                        File.Delete(destinationPath);
                }
                catch
                {
                }

                var ffmpegExe = GetFfmpegExePath();
                var psi = new ProcessStartInfo
                {
                    FileName = ffmpegExe,
                    Arguments = $"-y -hide_banner -loglevel error -i \"{sourcePath}\" -frames:v 1 \"{destinationPath}\"",
                    UseShellExecute = false,
                    CreateNoWindow = true,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true
                };

                using var proc = Process.Start(psi);
                if (proc == null) return false;
                proc.WaitForExit(8000);
                if (!proc.HasExited) return false;
                if (proc.ExitCode != 0) return false;
                if (!File.Exists(destinationPath)) return false;
                if (IsWebpFile(destinationPath)) return false;
                TouchFileUtc(destinationPath);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool TryExtractVideoPosterWithFfmpeg(string mediaFilePath, string destinationJpgPath)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(mediaFilePath) || string.IsNullOrWhiteSpace(destinationJpgPath)) return false;
                if (!File.Exists(mediaFilePath)) return false;

                var dir = Path.GetDirectoryName(destinationJpgPath);
                if (!string.IsNullOrWhiteSpace(dir))
                    Directory.CreateDirectory(dir);

                try
                {
                    if (File.Exists(destinationJpgPath))
                        File.Delete(destinationJpgPath);
                }
                catch
                {
                }

                var ffmpegExe = GetFfmpegExePath();
                var psi = new ProcessStartInfo
                {
                    FileName = ffmpegExe,
                    Arguments = $"-y -hide_banner -loglevel error -ss 00:00:12 -i \"{mediaFilePath}\" -frames:v 1 -vf \"scale=640:-1\" \"{destinationJpgPath}\"",
                    UseShellExecute = false,
                    CreateNoWindow = true,
                    RedirectStandardOutput = true,
                    RedirectStandardError = true
                };

                using var proc = Process.Start(psi);
                if (proc == null) return false;
                proc.WaitForExit(12000);
                if (!proc.HasExited) return false;
                if (proc.ExitCode != 0) return false;
                if (!File.Exists(destinationJpgPath)) return false;
                if (IsWebpFile(destinationJpgPath)) return false;
                TouchFileUtc(destinationJpgPath);
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool TryEnsurePngFromWebp(string sourcePath, out string? pngPath)
        {
            pngPath = null;
            try
            {
                if (string.IsNullOrWhiteSpace(sourcePath) || !File.Exists(sourcePath)) return false;
                if (!IsWebpFile(sourcePath)) return false;

                var target = Path.ChangeExtension(sourcePath, ".png");
                if (string.IsNullOrWhiteSpace(target)) return false;

                try
                {
                    if (File.Exists(target))
                    {
                        var srcTime = File.GetLastWriteTimeUtc(sourcePath);
                        var dstTime = File.GetLastWriteTimeUtc(target);
                        if (dstTime >= srcTime && !IsWebpFile(target))
                        {
                            pngPath = target;
                            return true;
                        }
                    }
                }
                catch
                {
                }

                if (!TryConvertToPngWithFfmpeg(sourcePath, target))
                    return false;

                pngPath = target;
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool TryWriteImageAsPng(string sourceImagePath, string destinationPath)
        {
            try
            {
                if (string.IsNullOrWhiteSpace(sourceImagePath) || string.IsNullOrWhiteSpace(destinationPath)) return false;
                if (!File.Exists(sourceImagePath)) return false;

                var dir = Path.GetDirectoryName(destinationPath);
                if (!string.IsNullOrWhiteSpace(dir))
                    Directory.CreateDirectory(dir);

                if (IsWebpFile(sourceImagePath))
                {
                    return TryConvertToPngWithFfmpeg(sourceImagePath, destinationPath);
                }

                using var input = new FileStream(sourceImagePath, FileMode.Open, FileAccess.Read, FileShare.ReadWrite);
                BitmapDecoder decoder;
                try
                {
                    decoder = BitmapDecoder.Create(input, BitmapCreateOptions.PreservePixelFormat, BitmapCacheOption.OnLoad);
                }
                catch
                {
                    return TryConvertToPngWithFfmpeg(sourceImagePath, destinationPath);
                }

                var frame = decoder.Frames.FirstOrDefault();
                if (frame == null) return false;
                frame.Freeze();

                var encoder = new PngBitmapEncoder();
                encoder.Frames.Add(frame);

                using var output = new FileStream(destinationPath, FileMode.Create, FileAccess.Write, FileShare.Read);
                encoder.Save(output);
                TouchFileUtc(destinationPath);
                return File.Exists(destinationPath);
            }
            catch
            {
                try
                {
                    return TryConvertToPngWithFfmpeg(sourceImagePath, destinationPath);
                }
                catch
                {
                    return false;
                }
            }
        }

        private static bool TryCopyVideoPosterToFolder(string mediaFilePath, string sourceImagePath, out string? destinationPath)
        {
            destinationPath = null;
            try
            {
                var folder = GetVideoFolderPath(mediaFilePath);
                if (string.IsNullOrWhiteSpace(folder) || !Directory.Exists(folder))
                    return false;
                string? existingCover = null;

                var baseName = Directory.Exists(mediaFilePath)
                    ? (Path.GetFileName(folder) ?? "")
                    : (Path.GetFileNameWithoutExtension(mediaFilePath) ?? "");

                var candidates = new[]
                {
                    $"{baseName}.png", $"{baseName}.jpg", $"{baseName}.jpeg",
                    "poster.png", "poster.jpg", "poster.jpeg",
                    "folder.png", "folder.jpg", "folder.jpeg",
                    "cover.png", "cover.jpg", "cover.jpeg",
                    "movie.png", "movie.jpg", "movie.jpeg",
                    "fanart.png", "fanart.jpg", "fanart.jpeg"
                };

                foreach (var name in candidates)
                {
                    var p = Path.Combine(folder, name);
                    if (File.Exists(p))
                    {
                        existingCover = p;
                        break;
                    }
                }

                static void TryClearReadOnly(string path)
                {
                    try
                    {
                        var attr = File.GetAttributes(path);
                        if ((attr & FileAttributes.ReadOnly) == FileAttributes.ReadOnly)
                            File.SetAttributes(path, attr & ~FileAttributes.ReadOnly);
                    }
                    catch
                    {
                    }
                }

                static void TryDeleteOrMoveAway(string path)
                {
                    try
                    {
                        TryClearReadOnly(path);
                    }
                    catch
                    {
                    }

                    try
                    {
                        var tempPath = path + ".old_" + Guid.NewGuid().ToString("N");
                        File.Move(path, tempPath);
                        try { File.Delete(tempPath); } catch { }
                    }
                    catch
                    {
                        try { File.Delete(path); } catch { }
                    }
                }

                var existingName = existingCover != null ? Path.GetFileNameWithoutExtension(existingCover) : "poster";
                var targetPath = Path.Combine(folder, existingName + ".png");

                if (existingCover != null && !string.Equals(existingCover, targetPath, StringComparison.OrdinalIgnoreCase) && File.Exists(existingCover))
                    TryDeleteOrMoveAway(existingCover);

                if (File.Exists(targetPath))
                    TryDeleteOrMoveAway(targetPath);

                if (!TryWriteImageAsPng(sourceImagePath, targetPath))
                {
                    destinationPath = null;
                    return false;
                }

                destinationPath = targetPath;
                InvalidateCachedFileImages(destinationPath);
                return true;
            }
            catch
            {
                destinationPath = null;
                return false;
            }
        }

        private static ImageSource? LoadVideoPosterForFile(string mediaFilePath)
        {
            if (string.IsNullOrWhiteSpace(mediaFilePath)) return null;

            try
            {
                var folder = Directory.Exists(mediaFilePath)
                    ? mediaFilePath
                    : (Path.GetDirectoryName(mediaFilePath) ?? "");

                var baseName = Directory.Exists(mediaFilePath)
                    ? (Path.GetFileName(folder) ?? "")
                    : (Path.GetFileNameWithoutExtension(mediaFilePath) ?? "");

                var candidates = new[]
                {
                    $"{baseName}.png", $"{baseName}.jpg", $"{baseName}.jpeg",
                    "poster.png", "poster.jpg", "poster.jpeg",
                    "folder.png", "folder.jpg", "folder.jpeg",
                    "cover.png", "cover.jpg", "cover.jpeg",
                    "movie.png", "movie.jpg", "movie.jpeg",
                    "fanart.png", "fanart.jpg", "fanart.jpeg"
                };

                var localCandidates = new List<(string path, DateTime time)>();
                var seen = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

                void AddFrom(string dir)
                {
                    foreach (var name in candidates)
                    {
                        var p = Path.Combine(dir, name);
                        if (!File.Exists(p)) continue;
                        if (!seen.Add(p)) continue;
                        if (IsWebpFile(p))
                        {
                            if (TryEnsurePngFromWebp(p, out var png) && !string.IsNullOrWhiteSpace(png) && File.Exists(png) && seen.Add(png))
                            {
                                try { localCandidates.Add((png, File.GetLastWriteTimeUtc(png))); } catch { }
                            }
                            continue;
                        }
                        try { localCandidates.Add((p, File.GetLastWriteTimeUtc(p))); } catch { }
                    }
                }

                if (!string.IsNullOrWhiteSpace(folder))
                {
                    AddFrom(folder);
                    if (localCandidates.Count == 0)
                    {
                        var parent = Path.GetDirectoryName(folder) ?? "";
                        if (!string.IsNullOrWhiteSpace(parent) && !string.Equals(parent, folder, StringComparison.OrdinalIgnoreCase))
                            AddFrom(parent);
                    }
                }

                var localMaxTime = DateTime.MinValue;
                foreach (var c in localCandidates)
                    if (c.time > localMaxTime) localMaxTime = c.time;

                string? customPath = null;
                DateTime customTime = DateTime.MinValue;
                if (MediaArtworkCache.TryGetCustomMoviePosterCachePath(mediaFilePath, out var custom) && File.Exists(custom))
                {
                    try
                    {
                        customPath = custom;
                        customTime = File.GetLastWriteTimeUtc(custom);
                    }
                    catch
                    {
                        customPath = null;
                        customTime = DateTime.MinValue;
                    }
                }

                if (customPath != null)
                {
                    var img = LoadAlbumCoverFromFile(customPath);
                    if (img != null) return img;
                }

                var triedCustomFirst = false;
                if (customPath != null && customTime > localMaxTime)
                {
                    triedCustomFirst = true;
                    var img = LoadAlbumCoverFromFile(customPath);
                    if (img != null) return img;
                }

                foreach (var c in localCandidates)
                {
                    var img = LoadAlbumCoverFromFile(c.path);
                    if (img != null) return img;
                }

                if (customPath != null && !triedCustomFirst)
                {
                    var img = LoadAlbumCoverFromFile(customPath);
                    if (img != null) return img;
                }

                if (MediaArtworkCache.TryGetMoviePosterCachePath(mediaFilePath, out var cachedFile) && File.Exists(cachedFile))
                {
                    var ext = Path.GetExtension(cachedFile).ToLowerInvariant();
                    if (!string.Equals(ext, ".webp", StringComparison.OrdinalIgnoreCase))
                    {
                        var cachedImg = LoadAlbumCoverFromFile(cachedFile);
                        if (cachedImg != null) return cachedImg;
                    }
                }

                try
                {
                    if (File.Exists(mediaFilePath))
                    {
                        var ext = Path.GetExtension(mediaFilePath).ToLowerInvariant();
                        var isVideo =
                            ext is ".mp4" or ".mkv" or ".avi" or ".mov" or ".wmv" or ".webm" or ".m4v" or ".flv" or ".mpg" or ".mpeg" or ".ts";
                        if (isVideo)
                        {
                            var poster = MediaArtworkCache.GetMoviePosterCachePath(mediaFilePath);
                            if (!string.IsNullOrWhiteSpace(poster) && TryExtractVideoPosterWithFfmpeg(mediaFilePath, poster))
                            {
                                var img = LoadAlbumCoverFromFile(poster);
                                if (img != null) return img;
                            }
                        }
                    }
                }
                catch
                {
                }
            }
            catch
            {
            }

            return null;
        }

        private static ImageSource? LoadGameCoverImage(DiscoveredGame game)
        {
            if (string.Equals(game.Platform, "Steam", StringComparison.OrdinalIgnoreCase) && game.SteamAppId.HasValue)
            {
                var steamCover = GameDiscoveryService.TryGetSteamCoverPath(game.SteamAppId.Value);
                var img = LoadAlbumCoverFromFile(steamCover);
                if (img != null) return img;
            }

            return LoadExeIconFromFile(game.ExecutablePath);
        }

        private static ImageSource? LoadGameCoverImage(string platform, int trackNumber, string exePath)
        {
            if (string.Equals(platform, "Steam", StringComparison.OrdinalIgnoreCase) && trackNumber > 0)
            {
                var steamCover = GameDiscoveryService.TryGetSteamCoverPath(trackNumber);
                var img = LoadAlbumCoverFromFile(steamCover);
                if (img != null) return img;
            }

            return LoadExeIconFromFile(exePath);
        }

        private static ImageSource? LoadExeIconFromFile(string exePath)
        {
            if (string.IsNullOrWhiteSpace(exePath)) return null;
            if (!File.Exists(exePath)) return null;

            try
            {
                using var icon = System.Drawing.Icon.ExtractAssociatedIcon(exePath);
                if (icon == null) return null;

                var bmp = Imaging.CreateBitmapSourceFromHIcon(
                    icon.Handle,
                    System.Windows.Int32Rect.Empty,
                    BitmapSizeOptions.FromWidthAndHeight(256, 256));
                bmp.Freeze();
                return bmp;
            }
            catch
            {
                return null;
            }
        }

        private static async Task<ImageSource?> LoadImageFromUrlAsync(string? url, CancellationToken ct)
        {
            if (string.IsNullOrWhiteSpace(url)) return null;
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)) return null;
            if (!string.Equals(uri.Scheme, Uri.UriSchemeHttp, StringComparison.OrdinalIgnoreCase) &&
                !string.Equals(uri.Scheme, Uri.UriSchemeHttps, StringComparison.OrdinalIgnoreCase))
                return null;

            try
            {
                var urlKey = $"url|{url.Trim()}";
                if (TryGetCachedImage(urlKey, out var cached))
                    return cached;

                string? TryGetCachedDiskPath(string key, string extension)
                {
                    try
                    {
                        var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "ImageCache");
                        Directory.CreateDirectory(cacheDir);
                        var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(key));
                        var hex = Convert.ToHexString(hashBytes);
                        var path = Path.Combine(cacheDir, $"{hex}{extension}");
                        if (!File.Exists(path)) return null;
                        var fi = new FileInfo(path);
                        if (fi.Length <= 0) return null;
                        if (fi.LastWriteTimeUtc < DateTime.UtcNow.AddDays(-10)) return null;
                        return path;
                    }
                    catch
                    {
                        return null;
                    }
                }

                ImageSource? TryLoadBitmapFromDisk(string fullPath)
                {
                    try
                    {
                        var bmp = new BitmapImage();
                        bmp.BeginInit();
                        bmp.CacheOption = BitmapCacheOption.OnLoad;
                        bmp.DecodePixelWidth = 320;
                        bmp.UriSource = new Uri(fullPath, UriKind.Absolute);
                        bmp.CreateOptions = BitmapCreateOptions.IgnoreColorProfile;
                        bmp.EndInit();
                        bmp.Freeze();
                        return bmp;
                    }
                    catch
                    {
                        return null;
                    }
                }

                try
                {
                    var cachedPng = TryGetCachedDiskPath(urlKey, ".png");
                    if (!string.IsNullOrWhiteSpace(cachedPng))
                    {
                        var img = TryLoadBitmapFromDisk(cachedPng);
                        if (img != null)
                        {
                            AddCachedImage(urlKey, img);
                            return img;
                        }
                    }

                    var cachedJpg = TryGetCachedDiskPath(urlKey, ".jpg") ?? TryGetCachedDiskPath(urlKey, ".jpeg");
                    if (!string.IsNullOrWhiteSpace(cachedJpg))
                    {
                        var img = TryLoadBitmapFromDisk(cachedJpg);
                        if (img != null)
                        {
                            AddCachedImage(urlKey, img);
                            return img;
                        }
                    }
                }
                catch
                {
                }

                byte[] bytes;
                try
                {
                    using var req = new HttpRequestMessage(HttpMethod.Get, uri);
                    req.Headers.TryAddWithoutValidation("Accept", "image/jpeg,image/png,image/*;q=0.8,*/*;q=0.6");
                    var host = (uri.Host ?? "").ToLowerInvariant();
                    if (host.Contains("cinemeta.ratingposterdb.com"))
                    {
                        try
                        {
                            req.Headers.Referrer = new Uri("https://cinemeta.ratingposterdb.com/");
                            req.Headers.TryAddWithoutValidation("Origin", "https://cinemeta.ratingposterdb.com");
                        }
                        catch { }
                    }
                    using var resp = await ServerImageHttp.SendAsync(req, HttpCompletionOption.ResponseHeadersRead, ct).ConfigureAwait(false);
                    if (!resp.IsSuccessStatusCode) return null;
                    bytes = await resp.Content.ReadAsByteArrayAsync(ct).ConfigureAwait(false);
                }
                catch
                {
                    bytes = await ServerImageHttp.GetByteArrayAsync(uri, ct).ConfigureAwait(false);
                }
                if (bytes == null || bytes.Length == 0) return null;

                bool IsWebpBytes(byte[] b)
                {
                    if (b.Length < 12) return false;
                    return b[0] == (byte)'R' &&
                           b[1] == (byte)'I' &&
                           b[2] == (byte)'F' &&
                           b[3] == (byte)'F' &&
                           b[8] == (byte)'W' &&
                           b[9] == (byte)'E' &&
                           b[10] == (byte)'B' &&
                           b[11] == (byte)'P';
                }

                var ext = "";
                try { ext = Path.GetExtension(uri.AbsolutePath ?? "").ToLowerInvariant(); } catch { ext = ""; }
                if (string.Equals(ext, ".webp", StringComparison.OrdinalIgnoreCase) || IsWebpBytes(bytes))
                {
                    try
                    {
                        var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "ImageCache");
                        Directory.CreateDirectory(cacheDir);
                        var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(urlKey));
                        var hex = Convert.ToHexString(hashBytes);
                        var webpPath = Path.Combine(cacheDir, $"{hex}.webp");

                        var shouldWrite = true;
                        try
                        {
                            if (File.Exists(webpPath))
                            {
                                var fi = new FileInfo(webpPath);
                                if (fi.Length == bytes.Length && fi.LastWriteTimeUtc > DateTime.UtcNow.AddHours(-6))
                                    shouldWrite = false;
                            }
                        }
                        catch
                        {
                            shouldWrite = true;
                        }

                        if (shouldWrite)
                        {
                            await File.WriteAllBytesAsync(webpPath, bytes, ct).ConfigureAwait(false);
                        }

                        if (TryEnsurePngFromWebp(webpPath, out var pngPath) && !string.IsNullOrWhiteSpace(pngPath) && File.Exists(pngPath))
                        {
                            var pngBmp = TryLoadBitmapFromDisk(pngPath);
                            if (pngBmp != null)
                            {
                                AddCachedImage(urlKey, pngBmp);
                                return pngBmp;
                            }
                        }

                        return null;
                    }
                    catch
                    {
                        return null;
                    }
                }

                try
                {
                    var cacheDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "AtlasAI", "ImageCache");
                    Directory.CreateDirectory(cacheDir);
                    var hashBytes = System.Security.Cryptography.SHA256.HashData(Encoding.UTF8.GetBytes(urlKey));
                    var hex = Convert.ToHexString(hashBytes);
                    var fileExt = ext;
                    if (fileExt != ".jpg" && fileExt != ".jpeg" && fileExt != ".png")
                        fileExt = ".jpg";
                    var outPath = Path.Combine(cacheDir, $"{hex}{fileExt}");
                    if (!File.Exists(outPath))
                        await File.WriteAllBytesAsync(outPath, bytes, ct).ConfigureAwait(false);
                    var diskBmp = TryLoadBitmapFromDisk(outPath);
                    if (diskBmp != null)
                    {
                        AddCachedImage(urlKey, diskBmp);
                        return diskBmp;
                    }
                }
                catch
                {
                }

                await using var ms = new MemoryStream(bytes);
                var bmp = new BitmapImage();
                bmp.BeginInit();
                bmp.CacheOption = BitmapCacheOption.OnLoad;
                bmp.DecodePixelWidth = 320;
                bmp.StreamSource = ms;
                bmp.EndInit();
                bmp.Freeze();
                AddCachedImage(urlKey, bmp);
                return bmp;
            }
            catch
            {
                return null;
            }
        }

        private static readonly object ImageCacheLock = new();
        private static readonly Dictionary<string, LinkedListNode<(string key, ImageSource image)>> ImageCacheMap = new(StringComparer.OrdinalIgnoreCase);
        private static readonly LinkedList<(string key, ImageSource image)> ImageCacheLru = new();
        private const int ImageCacheMaxEntries = 120;

        private static bool TryGetCachedImage(string key, out ImageSource image)
        {
            lock (ImageCacheLock)
            {
                if (ImageCacheMap.TryGetValue(key, out var node))
                {
                    ImageCacheLru.Remove(node);
                    ImageCacheLru.AddFirst(node);
                    image = node.Value.image;
                    return true;
                }
            }

            image = null!;
            return false;
        }

        private static void RemoveCachedImage(string key)
        {
            lock (ImageCacheLock)
            {
                if (ImageCacheMap.TryGetValue(key, out var node))
                {
                    ImageCacheLru.Remove(node);
                    ImageCacheMap.Remove(key);
                }
            }
        }

        private static void AddCachedImage(string key, ImageSource image)
        {
            lock (ImageCacheLock)
            {
                if (ImageCacheMap.TryGetValue(key, out var existing))
                {
                    ImageCacheLru.Remove(existing);
                    ImageCacheMap.Remove(key);
                }

                var node = new LinkedListNode<(string key, ImageSource image)>((key, image));
                ImageCacheLru.AddFirst(node);
                ImageCacheMap[key] = node;

                while (ImageCacheMap.Count > ImageCacheMaxEntries && ImageCacheLru.Last != null)
                {
                    var last = ImageCacheLru.Last;
                    ImageCacheLru.RemoveLast();
                    ImageCacheMap.Remove(last.Value.key);
                }
            }
        }

        private static void InvalidateCachedFileImages(string filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath)) return;
            lock (ImageCacheLock)
            {
                if (ImageCacheMap.Count == 0) return;
                var marker = $"|{filePath}|";
                var toRemove = new List<string>();
                foreach (var key in ImageCacheMap.Keys)
                {
                    if (key.IndexOf(marker, StringComparison.OrdinalIgnoreCase) >= 0)
                        toRemove.Add(key);
                }

                foreach (var k in toRemove)
                {
                    if (!ImageCacheMap.TryGetValue(k, out var node)) continue;
                    ImageCacheLru.Remove(node);
                    ImageCacheMap.Remove(k);
                }
            }
        }

        private static void InvalidateMoviePosterCaches(string mediaFilePath)
        {
            if (string.IsNullOrWhiteSpace(mediaFilePath)) return;
            try
            {
                var folder = GetVideoFolderPath(mediaFilePath);
                if (!string.IsNullOrWhiteSpace(folder))
                {
                    var baseName = Directory.Exists(mediaFilePath)
                        ? (Path.GetFileName(folder) ?? "")
                        : (Path.GetFileNameWithoutExtension(mediaFilePath) ?? "");
                    var candidates = new[]
                    {
                        "poster.jpg", "poster.jpeg", "folder.jpg", "folder.jpeg", "cover.jpg", "cover.jpeg", "movie.jpg", "movie.jpeg", "fanart.jpg", "fanart.jpeg",
                        "poster.png", "folder.png", "cover.png", "movie.png", "fanart.png",
                        $"{baseName}.jpg", $"{baseName}.jpeg", $"{baseName}.png"
                    };
                    foreach (var name in candidates)
                    {
                        var p = Path.Combine(folder, name);
                        if (File.Exists(p)) InvalidateCachedFileImages(p);
                    }

                    var parent = Path.GetDirectoryName(folder) ?? "";
                    if (!string.IsNullOrWhiteSpace(parent) && !string.Equals(parent, folder, StringComparison.OrdinalIgnoreCase))
                    {
                        foreach (var name in candidates)
                        {
                            var p = Path.Combine(parent, name);
                            if (File.Exists(p)) InvalidateCachedFileImages(p);
                        }
                    }
                }
            }
            catch
            {
            }

            try
            {
                InvalidateCachedFileImages(MediaArtworkCache.GetCustomMoviePosterCachePath(mediaFilePath));
                if (MediaArtworkCache.TryGetCustomMoviePosterCachePath(mediaFilePath, out var existingCustom) && !string.IsNullOrWhiteSpace(existingCustom))
                    InvalidateCachedFileImages(existingCustom);

                InvalidateCachedFileImages(MediaArtworkCache.GetMoviePosterCachePath(mediaFilePath));
                if (MediaArtworkCache.TryGetMoviePosterCachePath(mediaFilePath, out var existing) && !string.IsNullOrWhiteSpace(existing))
                    InvalidateCachedFileImages(existing);
            }
            catch
            {
            }
        }

        private static void InvalidateMusicFolderCoverCaches(string albumFolderPath)
        {
            if (string.IsNullOrWhiteSpace(albumFolderPath)) return;
            try
            {
                foreach (var name in AlbumCoverNames)
                {
                    var p = Path.Combine(albumFolderPath, name);
                    if (File.Exists(p)) InvalidateCachedFileImages(p);
                }
            }
            catch
            {
            }

            try
            {
                InvalidateCachedFileImages(MediaArtworkCache.GetCustomMusicFolderCoverCachePath(albumFolderPath));
                if (MediaArtworkCache.TryGetCustomMusicFolderCoverCachePath(albumFolderPath, out var existingCustom) && !string.IsNullOrWhiteSpace(existingCustom))
                    InvalidateCachedFileImages(existingCustom);

                InvalidateCachedFileImages(MediaArtworkCache.GetMusicFolderCoverCachePath(albumFolderPath));
                if (MediaArtworkCache.TryGetMusicFolderCoverCachePath(albumFolderPath, out var existing) && !string.IsNullOrWhiteSpace(existing))
                    InvalidateCachedFileImages(existing);
            }
            catch
            {
            }
        }

        private static ImageSource? LoadAlbumCoverFromFile(string? coverPath)
        {
            if (string.IsNullOrWhiteSpace(coverPath)) return null;
            try
            {
                if (!File.Exists(coverPath)) return null;
                if (IsWebpFile(coverPath))
                {
                    if (TryEnsurePngFromWebp(coverPath, out var png) && !string.IsNullOrWhiteSpace(png) && File.Exists(png))
                        coverPath = png;
                    else
                        return null;
                }
                var info = new FileInfo(coverPath);
                var stamp = info.LastWriteTimeUtc.Ticks;
                var len = info.Length;
                var key = $"file|{coverPath}|{stamp}|{len}";
                if (TryGetCachedImage(key, out var cached))
                {
                    try
                    {
                        if (File.GetLastWriteTimeUtc(coverPath).Ticks == stamp)
                            return cached;
                        RemoveCachedImage(key);
                    }
                    catch
                    {
                        return cached;
                    }
                }
                using var fs = new FileStream(coverPath, FileMode.Open, FileAccess.Read, FileShare.ReadWrite);
                var bmp = new BitmapImage();
                bmp.BeginInit();
                bmp.CacheOption = BitmapCacheOption.OnLoad;
                bmp.CreateOptions = BitmapCreateOptions.IgnoreImageCache;
                bmp.DecodePixelWidth = 320;
                bmp.StreamSource = fs;
                bmp.EndInit();
                bmp.Freeze();
                AddCachedImage(key, bmp);
                return bmp;
            }
            catch
            {
                try
                {
                    if (!File.Exists(coverPath)) return null;
                    if (IsWebpFile(coverPath))
                    {
                        if (TryEnsurePngFromWebp(coverPath, out var png) && !string.IsNullOrWhiteSpace(png) && File.Exists(png))
                            coverPath = png;
                        else
                            return null;
                    }
                    var bytes = File.ReadAllBytes(coverPath);
                    if (bytes.Length == 0) return null;

                    using var input = new MemoryStream(bytes);
                    using var img = System.Drawing.Image.FromStream(input, true, true);
                    using var output = new MemoryStream();
                    img.Save(output, System.Drawing.Imaging.ImageFormat.Png);
                    output.Position = 0;

                    var bmp = new BitmapImage();
                    bmp.BeginInit();
                    bmp.CacheOption = BitmapCacheOption.OnLoad;
                    bmp.DecodePixelWidth = 320;
                    bmp.StreamSource = output;
                    bmp.EndInit();
                    bmp.Freeze();

                    var info = new FileInfo(coverPath);
                    var stamp = info.LastWriteTimeUtc.Ticks;
                    var len = info.Length;
                    var key = $"file|gdi|{coverPath}|{stamp}|{len}";
                    AddCachedImage(key, bmp);
                    return bmp;
                }
                catch
                {
                    return null;
                }
            }
        }

        private static void TouchFileUtc(string? filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath)) return;
            try
            {
                if (File.Exists(filePath))
                    File.SetLastWriteTimeUtc(filePath, DateTime.UtcNow);
            }
            catch
            {
            }
        }

        private static ImageSource? LoadEmbeddedAlbumArtFromFile(string? filePath)
        {
            if (string.IsNullOrWhiteSpace(filePath)) return null;
            if (!File.Exists(filePath)) return null;

            try
            {
                using var tagFile = TagLib.File.Create(filePath);
                var pic = tagFile?.Tag?.Pictures?.FirstOrDefault();
                if (pic?.Data?.Data == null || pic.Data.Data.Length == 0) return null;

                using var ms = new MemoryStream(pic.Data.Data);
                var bmp = new BitmapImage();
                bmp.BeginInit();
                bmp.CacheOption = BitmapCacheOption.OnLoad;
                bmp.DecodePixelWidth = 320;
                bmp.StreamSource = ms;
                bmp.EndInit();
                bmp.Freeze();
                return bmp;
            }
            catch
            {
                return null;
            }
        }

        private void UpdateTimerState()
        {
            if (_progressTimer.IsEnabled) _progressTimer.Stop();
        }

        private static string FormatTime(TimeSpan t)
        {
            if (t.TotalHours >= 1)
                return $"{(int)t.TotalHours}:{t.Minutes:00}:{t.Seconds:00}";
            return $"{t.Minutes}:{t.Seconds:00}";
        }

        public event PropertyChangedEventHandler? PropertyChanged;

        private void OnPropertyChanged([CallerMemberName] string? propertyName = null)
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }

        private bool SetProperty<T>(ref T field, T value, [CallerMemberName] string? propertyName = null)
        {
            if (Equals(field, value)) return false;
            field = value;
            OnPropertyChanged(propertyName);
            return true;
        }
    }
}
